public enum ManualOrderValidationError: Error, Sendable, Equatable {
    case emptySymbol
    case invalidOptionSymbol
    case invalidQuantity
    case unsupportedOrderType
    case unsupportedOptionTimeInForce
    case limitPriceRequired
    case invalidLimitPrice
    case optionBracketNotSupported
    case invalidOrderID
    case replaceRequiresChanges
    case invalidReplaceQuantity
    case invalidReplaceLimitPrice
    case invalidBracketTakeProfit
    case invalidBracketStopLoss
    case invalidBracketStopLimitPrice
    case invalidBracketRelation
    case shortNotAllowedByAccount
    case symbolNotShortable
    case liveTradingNotArmed
    case tradingDisabledByKillSwitch
    case staleArmingSession
    case localUserPresenceCanceled
    case localUserPresenceFailed
    case localUserPresenceUnavailable
    case localUserPresenceSystemError
    case replayTradingNotEnabled
}

extension ManualOrderValidationError: LocalizedError {
    public var errorDescription: String? {
        switch self {
        case .emptySymbol:
            return "Symbol is required."
        case .invalidOptionSymbol:
            return "Option symbol must use OCC format (example: AAPL240119C00190000)."
        case .invalidQuantity:
            return "Quantity must be greater than zero."
        case .unsupportedOrderType:
            return "Only market and limit orders are supported."
        case .unsupportedOptionTimeInForce:
            return "Options currently support DAY or GTC time-in-force."
        case .limitPriceRequired:
            return "Limit price is required for limit orders."
        case .invalidLimitPrice:
            return "Limit price must be greater than zero."
        case .optionBracketNotSupported:
            return "Bracket orders are currently disabled for options."
        case .invalidOrderID:
            return "Order ID is required."
        case .replaceRequiresChanges:
            return "Provide qty and/or limit price to replace an order."
        case .invalidReplaceQuantity:
            return "Replacement quantity must be greater than zero."
        case .invalidReplaceLimitPrice:
            return "Replacement limit price must be greater than zero."
        case .invalidBracketTakeProfit:
            return "Take-profit limit price must be greater than zero."
        case .invalidBracketStopLoss:
            return "Stop-loss stop price must be greater than zero."
        case .invalidBracketStopLimitPrice:
            return "Stop-loss limit price must be greater than zero."
        case .invalidBracketRelation:
            return "Bracket prices are not consistent with side and entry price."
        case .shortNotAllowedByAccount:
            return "This account is not currently eligible to open equity short positions."
        case .symbolNotShortable:
            return "This symbol is not shortable."
        case .liveTradingNotArmed:
            return "Live trading is disarmed. Arm live trading before submitting new or replacement orders."
        case .tradingDisabledByKillSwitch:
            return "Trading is disabled by kill switch."
        case .staleArmingSession:
            return "Trading request was created under a stale arming session. Refresh and retry."
        case .localUserPresenceCanceled:
            return "Live order submission was canceled at the local macOS authentication prompt."
        case .localUserPresenceFailed:
            return "Live order submission requires successful local macOS authentication."
        case .localUserPresenceUnavailable:
            return "Live order submission is blocked because local macOS authentication is unavailable."
        case .localUserPresenceSystemError:
            return "Live order submission is blocked because local macOS authentication returned a system error."
        case .replayTradingNotEnabled:
            return "Replay mode is bars-only and does not submit orders in this slice."
        }
    }
}

