    var displayTitle: String {
        switch self {
        case .informationalNoAction:
            return "Informational only; no action required"
        case .worthMonitoring:
            return "Worth monitoring"
        case .followUpAnalystWorkWarranted:
            return "Follow-up analyst work warranted"
        case .ownerAttentionRecommended:
            return "Owner attention recommended"
        case .candidateIdeasWorthConsidering:
            return "Candidate ideas worth considering"
