    private static let telegramMissingBotTokenRetryInterval: TimeInterval = 300
    private static let ownerSurfaceJobSnapshotCompletedLimit = 100
    private static let indefiniteMonitorProgressMinimumIntervalSec: TimeInterval = 300

    deinit {
        tradeUpdatesEventTask?.cancel()
        marketDataEventTask?.cancel()
        marketDataNoFirstDataMonitorTask?.cancel()
        pendingPaperExecutionRetryTask?.cancel()
        strategyRunMonitorTask?.cancel()

        let hadTradeUpdatesTask = tradeUpdatesEventTask != nil
        let hadMarketDataTask = marketDataEventTask != nil
        let hadMarketDataNoFirstDataMonitorTask = marketDataNoFirstDataMonitorTask != nil
        let hadPendingPaperRetryTask = pendingPaperExecutionRetryTask != nil
        let hadStrategyMonitorTask = strategyRunMonitorTask != nil
        let shouldScheduleAsyncCleanup = isStarted
            || hadTradeUpdatesTask
            || hadMarketDataTask
            || hadMarketDataNoFirstDataMonitorTask
            || hadPendingPaperRetryTask
            || hadStrategyMonitorTask
        guard shouldScheduleAsyncCleanup else {
            return
        }

        let positionsRefresher = positionsRefresher
        let openOrdersRefresher = openOrdersRefresher
        let paperRunPersistenceRefresher = paperRunPersistenceRefresher
        let scheduler = scheduler
        let jobRunner = jobRunner

        Task {
            await positionsRefresher.cancel()
            await openOrdersRefresher.cancel()
            await paperRunPersistenceRefresher.cancel()
            await scheduler.stop()
            await jobRunner.handleEngineStop()
        }
    }

