    public func getLiveExecutionProtectionSettings() async -> LiveExecutionProtectionSettings {
        if let liveExecutionProtectionSettingsCache {
            return liveExecutionProtectionSettingsCache
        }
        let settings = await liveExecutionProtectionSettingsStore.loadOrDefault()
        liveExecutionProtectionSettingsCache = settings
        return settings
    }

    public func setLiveExecutionProtectionRequired(
        _ required: Bool,
        source: AuditEventSource = .ui
    ) async -> LiveExecutionProtectionUpdateResult {
        let existing = await getLiveExecutionProtectionSettings()
        if required == existing.localUserPresenceRequiredForLiveOrders {
            return LiveExecutionProtectionUpdateResult(
                settings: existing,
                authorizationResult: nil,
                applied: true,
                summary: required
                    ? "Live execution local-auth protection is already enabled."
                    : "Live execution local-auth protection is already disabled."
            )
        }

        if required == false {
            let challenge = disableLiveExecutionProtectionChallenge()
            let authorization = await localUserPresenceAuthorizer.authorize(challenge: challenge)
            lastLocalUserPresenceAuthorizationResult = authorization
            guard authorization.authorized else {
                await store.publishDiagnostic(
                    "live execution protection disable blocked status=\(authorization.status.rawValue)",
                    source: source,
                    level: .warning,
                    action: "live_execution_protection_disable",
                    errorCode: "local_user_presence_required"
                )
                return LiveExecutionProtectionUpdateResult(
                    settings: existing,
                    authorizationResult: authorization,
                    applied: false,
                    summary: "Protection remains enabled because local macOS authentication did not authorize disabling it."
                )
            }

            let updated = existing.updating(
                required: false,
                updatedBy: "owner",
                updateSource: source,
                now: nowDate()
            )
            do {
                let saved = try await liveExecutionProtectionSettingsStore.upsert(updated)
                liveExecutionProtectionSettingsCache = saved
                await store.publishDiagnostic(
                    "live execution protection disabled after local macOS authentication",
                    source: source,
                    action: "live_execution_protection_disable"
                )
                return LiveExecutionProtectionUpdateResult(
                    settings: saved,
                    authorizationResult: authorization,
                    applied: true,
                    summary: "Live execution local-auth protection is disabled."
                )
            } catch {
                await store.publishDiagnostic(
                    "live execution protection disable persistence failed reason=\(error.localizedDescription)",
                    source: source,
                    level: .error,
                    action: "live_execution_protection_disable",
                    errorCode: "settings_persist_failed"
                )
                return LiveExecutionProtectionUpdateResult(
                    settings: existing,
                    authorizationResult: authorization,
                    applied: false,
                    summary: "Protection remains enabled because the setting could not be saved."
                )
            }
        }

        let updated = existing.updating(
            required: true,
            updatedBy: "owner",
            updateSource: source,
            now: nowDate()
        )
        do {
            let saved = try await liveExecutionProtectionSettingsStore.upsert(updated)
            liveExecutionProtectionSettingsCache = saved
            await store.publishDiagnostic(
                "live execution protection enabled for Live NEW/REPLACE submissions",
                source: source,
                action: "live_execution_protection_enable"
            )
            return LiveExecutionProtectionUpdateResult(
                settings: saved,
                authorizationResult: nil,
                applied: true,
                summary: "Live execution local-auth protection is enabled."
            )
        } catch {
            await store.publishDiagnostic(
                "live execution protection enable persistence failed reason=\(error.localizedDescription)",
                source: source,
                level: .error,
                action: "live_execution_protection_enable",
                errorCode: "settings_persist_failed"
            )
            return LiveExecutionProtectionUpdateResult(
                settings: existing,
                authorizationResult: nil,
                applied: false,
                summary: "Protection could not be enabled because the setting could not be saved."
            )
        }
    }

    public func testLiveExecutionLocalAuthentication(
        source: AuditEventSource = .ui
    ) async -> LocalUserPresenceAuthorizationResult {
        let result = await localUserPresenceAuthorizer.authorize(
            challenge: testLiveExecutionProtectionChallenge()
        )
        lastLocalUserPresenceAuthorizationResult = result
        await store.publishDiagnostic(
            "live execution protection local-auth test status=\(result.status.rawValue)",
            source: source,
            level: result.authorized ? .info : .warning,
            action: "live_execution_protection_test",
            errorCode: result.authorized ? nil : "local_user_presence_test_not_authorized"
        )
        return result
    }

