            proposalID: nil,
            proposalConstraints: nil
        )
        return status
    }

    @discardableResult
    public func startStrategyFromProposal(
        proposalID: String,
        source: AuditEventSource = .ui
    ) async throws -> StrategyStatusSnapshot {
        let normalizedID = proposalID.trimmingCharacters(in: .whitespacesAndNewlines)
        guard let proposal = try await proposalStore.getProposal(id: normalizedID) else {
            throw ProposalStoreError.proposalNotFound(id: normalizedID)
        }
        guard configuration.environment == .paper else {
            throw StrategyProposalExecutionError.proposalRequiresPaperEnvironment(
                proposalId: proposal.proposalId
            )
        }
        guard proposal.intendedEnvironmentPaperOnly else {
            throw StrategyProposalExecutionError.proposalNotPaperOnly(
                proposalId: proposal.proposalId
            )
        }
        guard proposal.approval.status == .approvedPaper else {
            await throttledBlockedProposalStartAudit(
                proposalID: proposal.proposalId,
                source: source
            )
            throw StrategyProposalExecutionError.strategyNotApprovedForPaper(
                proposalId: proposal.proposalId
            )
        }

        let startingEquity = await currentAccountEquity()
        let runID = UUID().uuidString
        let runStartedAt = nowDate()
        let runRecord = PaperRunRecord(
            runId: runID,
            proposalId: proposal.proposalId,
            strategyId: proposal.strategyId,
            startedAt: runStartedAt,
            endedAt: nil,
            status: .running,
            stopReason: nil,
            environment: .paper,
            parametersSnapshot: proposal.parameters,
            constraintsSnapshot: proposal.constraints,
            metrics: PaperRunMetrics(
                lastUpdatedAt: runStartedAt,
                startingEquity: startingEquity
            )
        )

        let status = try await startStrategyInternal(
            id: proposal.strategyId,
            params: proposal.parameters,
            source: source,
            proposalID: proposal.proposalId,
            proposalConstraints: proposal.constraints
        )
        _ = try await paperRunStore.createRun(runRecord)
        activePaperRunsByRunID[runID] = runRecord
        activeRunIDByStrategyID[proposal.strategyId] = runID
        activeReplayRunIDByStrategyID[proposal.strategyId] = nil
        replaySimBrokerByStrategyID[proposal.strategyId] = nil
        replayCurrentTimeByStrategyID[proposal.strategyId] = nil
        dirtyRunIDs.remove(runID)
        _ = try? await proposalStore.recordPaperRunResult(
            proposalID: proposal.proposalId,
            status: "started"
        )
        await refreshProposalsSnapshot()
        await refreshProposalRunsSnapshot(proposalID: proposal.proposalId)
        await store.publishDiagnostic(
            "paper run started proposal_id=\(proposal.proposalId) run_id=\(shortOrderID(runID)) strategy_id=\(proposal.strategyId)",
            source: source,
            strategyID: proposal.strategyId,
            action: "paper_run_started"
        )
        return status
    }

    @discardableResult
    public func stopStrategy(
        id: String,
        source: AuditEventSource = .ui
    ) async throws -> StrategyStatusSnapshot {
        let previousStatus = await strategyRunner.statuses().first(where: { $0.id == id })
        let status = try await strategyRunner.stop(id: id)
        strategyRunConstraintStateByID[id] = nil
        replaySimBrokerByStrategyID[id] = nil
        replayCurrentTimeByStrategyID[id] = nil
        if let proposalID = previousStatus?.proposalId {
            await finalizePaperRunIfActive(
                strategyID: id,
                status: .stopped,
                stopReason: "user_stop",
                source: source
            )
            _ = try? await proposalStore.recordPaperRunResult(
                proposalID: proposalID,
                status: "stopped"
            )
            await refreshProposalsSnapshot()
            await refreshProposalRunsSnapshot(proposalID: proposalID)
        }
        await store.publishDiagnostic(
            "strategy stopped id=\(id)",
            source: source,
            strategyID: id,
            action: "strategy_stop"
        )
        return status
    }

