        let run = try await paperRunStore.getRun(runId: runID)
        await publishRunPersistenceDiagnostics()
        return run
    }

    public func exportRunJSON(runID: String) async throws -> String {
        if let active = activePaperRunsByRunID[runID] {
            let encoder = JSONEncoder()
            encoder.outputFormatting = [.prettyPrinted, .sortedKeys]
            encoder.dateEncodingStrategy = .iso8601
            let data = try encoder.encode(active)
            return String(data: data, encoding: .utf8) ?? "{}"
        }
        let json = try await paperRunStore.exportRunJSON(runId: runID)
        await publishRunPersistenceDiagnostics()
        return json
    }

