    @discardableResult
    public func runScheduleNow(
        id: String,
        source: AuditEventSource = .ipc
    ) async throws -> ScheduledJobSummary {
        await configureJobRunnerIfNeeded()
        await store.publishDiagnostic(
            "schedule_run_now_requested scheduleId=\(id)",
            source: source,
            action: "schedule_run_now"
        )
        do {
            let summary = try await scheduler.runScheduleNow(id: id)
            await publishSchedulePersistenceDiagnostics()
            let jobID = summary.runningJobId ?? ""
            await store.publishDiagnostic(
                "schedule_run_now_dispatched scheduleId=\(id) jobId=\(jobID)",
                source: source,
                action: "schedule_run_now"
            )
            return summary
        } catch {
            await publishSchedulePersistenceDiagnostics()
            let errorCode = (error as? any AgentControlError)?.code ?? "unknown_error"
            await store.publishDiagnostic(
                "schedule_run_now_failed scheduleId=\(id) errorCode=\(errorCode)",
                source: source,
                level: .error,
                action: "schedule_run_now"
            )
            throw error
        }
    }

