    public func runMaintenanceRetention(
        dryRun: Bool,
        jobTelemetryCleanupBefore: Date? = nil,
        source: AuditEventSource = .ipc
    ) async throws -> JobRecord {
        var parameters: [String: JSONValue] = ["dryRun": .bool(dryRun)]
        if let jobTelemetryCleanupBefore {
            parameters["jobTelemetryCleanupBefore"] = .string(
                DateCodec.formatISO8601(jobTelemetryCleanupBefore)
            )
        }
        let job = try await submitJob(
            type: .maintenanceRetention,
            parameters: parameters,
            source: source
        )
        await store.publishDiagnostic(
            "maintenance retention queued id=\(shortOrderID(job.jobId)) dry_run=\(dryRun)",
            source: source,
            action: "maintenance_retention_queue"
        )
        return job
    }

    public func lastMaintenanceJobSummary() async throws -> JobSummary? {
        let jobs = try await listJobs()
        return jobs
            .filter { $0.type == .maintenanceRetention }
            .sorted { lhs, rhs in
                if lhs.updatedAt == rhs.updatedAt {
                    return lhs.jobId < rhs.jobId
                }
                return lhs.updatedAt > rhs.updatedAt
            }
            .first
    }

