    @discardableResult
    public func updateRSSFeed(_ feed: RSSFeed) async throws -> RSSFeed {
        guard let existingFeed = try await rssFeedStore.get(id: feed.id) else {
            throw RSSFeedStoreError.feedNotFound(id: feed.id)
        }
        let updated = try await rssFeedStore.upsert(feed)
        await refreshRSSFeedsSnapshot()
        if normalizedRSSSourceName(for: existingFeed) != normalizedRSSSourceName(for: updated) {
            await reconcilePersistedRSSNewsSources(
                changedFeedName: existingFeed.name,
                trigger: "feed_updated",
                force: true
            )
            await refreshNewsSnapshot()
        }
        await publishRSSFeedPersistenceDiagnostics()
        await store.publishDiagnostic(
            "rss feed updated id=\(shortOrderID(updated.id)) name=\(updated.name) enabled=\(updated.enabled)",
            source: .ui,
            action: "rss_feed_update"
        )
        return updated
    }

