        await refreshNewsSnapshot()
        await publishRSSFeedPersistenceDiagnostics()
        await store.publishDiagnostic(
            "rss feed removed id=\(shortOrderID(id))",
            source: .ui,
            action: "rss_feed_remove"
        )
    }

