    private let pmOperatingGuideInstructionID = "pm-instruction-operating-charter"
    private let pmOperatingGuideInstructionCategory = "pm_operating_guide"

    @discardableResult
    private func ensurePMOperatingGuideInstruction(
        pmId: String,
        source: AuditEventSource = .system
    ) async throws -> PMInstruction {
        if let existing = try await pmInstructionStore.get(id: pmOperatingGuideInstructionID) {
            if let repaired = repairedPMOperatingGuideInstructionIfNeeded(existing) {
                let stored = try await pmInstructionStore.upsert(repaired)
                await publishPMPersistenceDiagnostics()
                await store.publishDiagnostic(
                    "pm operating guide source-policy balance backfilled id=\(shortOrderID(stored.instructionId))",
                    source: source,
                    action: "pm_operating_guide_source_policy_backfill"
                )
                return stored
            }
            await publishPMPersistenceDiagnostics()
            return existing
        }

        let now = nowDate()
        let seeded = try await pmInstructionStore.upsert(
            PMInstruction(
                instructionId: pmOperatingGuideInstructionID,
                pmId: pmId,
                title: "PM Operating Charter",
                body: defaultPMOperatingGuideBody(),
                category: pmOperatingGuideInstructionCategory,
                status: .active,
                effectiveAt: now,
                createdAt: now,
                updatedAt: now
            )
        )
        await publishPMPersistenceDiagnostics()
        await store.publishDiagnostic(
            "pm operating guide seeded id=\(shortOrderID(seeded.instructionId))",
            source: source,
            action: "pm_operating_guide_seed"
        )
        return seeded
    }

    private func repairedPMOperatingGuideInstructionIfNeeded(_ existing: PMInstruction) -> PMInstruction? {
        let body = existing.body
        let lowered = body.lowercased()
        let staleSignals = [
            "dedicated filings/ad hoc charter",
            "source policy " + "permits official filings",
            "valid analyst/charter and source-policy route",
            "compatible source policy"
        ]
        guard staleSignals.contains(where: { lowered.contains($0) }) else {
            return nil
        }

        var repaired = existing
        repaired.body = defaultPMOperatingGuideBody()
        repaired.category = pmOperatingGuideInstructionCategory
        repaired.status = .active
        repaired.updatedAt = nowDate()
        return repaired
    }

    private func defaultPMOperatingGuideBody() -> String {
        """
        The PM coordinates owner conversation, app-owned truth, analyst work, and governed execution. The PM may reason, recommend, and delegate, but the app controls persistence, approvals, and execution gates.

        Use standing analysts when a request maps to their lane: sector analysts for sector or company work, Macro and International for macro/cross-asset/international framing, Portfolio Risk for portfolio-level exposure and risk posture, and Recent News for app-owned news or material source-event review.

        If at least one standing analyst broadly fits the domain, choose the closest valid standing analyst rather than asking for a bespoke route. Ask the owner which existing analyst or charter to use only when several plausible targets are materially ambiguous or no standing/ad hoc charter fits at all. Do not claim research has launched until the hidden action resolves to an actual app-owned analyst/charter id, and do not invent a non-existent analyst identity.

        Analyst research capability is governed by the selected analyst charter's restrictions, not by hidden topical routes or bespoke source workflows. Once a valid analyst/charter target is selected, the PM should not further narrow the analyst's research activity except to honor that charter/source policy, the owner's current task instructions, and hard app governance. The analyst should use ordinary domain-relevant public sources for discovery, corroboration, context, and primary-source pursuit unless the charter/source policy, owner/task wording, or hard app governance expressly restricts that source set. Primary and official sources are preferred but not exclusive unless the owner explicitly asks for official-only or primary-only work.

        For SEC filer identification, 13F research, asset-manager holdings extraction, or similar public research, choose the closest valid analyst lane rather than requiring a bespoke 13F route. Financials Analyst is normally appropriate for asset-manager / official-filings work when available, but the broader rule is to route to the analyst whose charter best covers the domain and let that charter's source restrictions govern the research. If the app cannot resolve the selected analyst/charter id from the action payload, say no analyst is tasked, no work item has launched, and ask which existing analyst or charter should handle the work.

        Agent Skills are reusable methodology guidance. They can be requested for analyst tasks, but they do not grant tool access, source access, approval authority, or trading authority.

        Analyst confidence scores and low-confidence findings are PM context, not deterministic app blockers by themselves. Use them to frame uncertainty, follow-up needs, and owner-facing caveats; do not suppress PM reasoning solely because a finding is low confidence.

        If the PM says work has launched, there must be a corresponding app-owned delegation/task/job or a precise blocker in the same conversation.
        """
    }

    private func resolvedConversationPMID(
        requestedPMID: String?,
        source: AuditEventSource
    ) async throws -> String? {
        let trimmedRequestedPMID = requestedPMID?.trimmingCharacters(in: .whitespacesAndNewlines)
        if let trimmedRequestedPMID,
           trimmedRequestedPMID.isEmpty == false,
           isOperationalExercisePMID(trimmedRequestedPMID) == false {
            return trimmedRequestedPMID
        }
        return try await ensurePrimaryPMProfile(source: source).pmId
    }

