    public func assemblePMContextPack(
        pmId: String? = nil
    ) async throws -> PMContextPack {
        try await ensureStandingAnalystBenchSeeded()
        let profiles = try await pmProfileStore.loadAll()
        let mandates = try await pmMandateStore.loadAll()
        let instructions = try await pmInstructionStore.loadAll()
        let notebookEntries = try await pmNotebookStore.loadAll()
        let interactionMemories = try await pmInteractionMemoryStore.loadAll()
        let strategyBrief = try await portfolioStrategyBriefStore.loadOrDefault()
        let approvalRequests = try await pmApprovalRequestStore.loadAll()
        let decisions = try await pmDecisionStore.loadAll()
        let communicationSessions = try await pmCommunicationSessionStore.loadAll()
        let communicationMessages = try await pmCommunicationMessageStore.loadAll()
        let delegations = try await pmDelegationStore.loadAll()
        let analystMemos = try await analystMemoStore.loadAll()
        let analystCharters = try await analystCharterStore.loadAll()
        let schedules = try await scheduler.listSummaries()
        let standingReports = try await analystStandingReportStore.loadAll()
        let snapshot = await store.snapshot()
        let portfolioWatchChartWallConfiguration = await portfolioWatchChartWallConfigurationStore.load()
        await publishPMPersistenceDiagnostics()
        await publishAnalystPersistenceDiagnostics()

        return makePMContextPack(
            requestedPMId: pmId,
            profiles: profiles,
            mandates: mandates,
            instructions: instructions,
            notebookEntries: notebookEntries,
            interactionMemories: interactionMemories,
            strategyBrief: strategyBrief,
            positions: snapshot.positions,
            openOrders: snapshot.openOrders,
            watchlistSymbols: snapshot.watchlistSymbols,
            storeSnapshot: snapshot,
            portfolioWatchSelectedSymbols: portfolioWatchChartWallConfiguration?.selectedSymbols ?? [],
            approvalRequests: approvalRequests,
            decisions: decisions,
            delegations: delegations,
            analystMemos: analystMemos,
            analystCharters: analystCharters,
            schedules: schedules,
            standingReports: standingReports,
            systemReadiness: snapshot.alwaysOnReadiness,
            communicationSessions: communicationSessions,
            communicationMessages: communicationMessages,
            assembledAt: nowDate()
        )
    }

    @discardableResult
    func triggerPMStandingReviewWakeIfNeeded(
        trigger: PMStandingReviewWakeTrigger,
        source: AuditEventSource = .engine
    ) async throws -> PMCommunicationMessage? {
        let contextPack = try await assemblePMContextPack()
        let queue = contextPack.operatingContext.standingReviewQueue
        let currentReportIDs = Set(queue.items.map(\.reportId))

        guard currentReportIDs.isEmpty == false else {
            knownPendingStandingReviewReportIDs.removeAll()
            lastPMStandingReviewWakeFingerprint = nil
            return nil
        }

        let fingerprint = pmStandingReviewWakeFingerprint(for: queue)
        let newReportIDs = currentReportIDs.subtracting(knownPendingStandingReviewReportIDs)
        let shouldWake: Bool
        switch trigger {
        case .engineReady:
            shouldWake = true
        case .queueChanged:
            shouldWake = newReportIDs.isEmpty == false
        }

        guard shouldWake else {
            knownPendingStandingReviewReportIDs = currentReportIDs
            return nil
        }
        guard lastPMStandingReviewWakeFingerprint != fingerprint,
              inFlightPMStandingReviewWakeFingerprint != fingerprint else {
            knownPendingStandingReviewReportIDs = currentReportIDs
            return nil
        }

        inFlightPMStandingReviewWakeFingerprint = fingerprint
        defer {
            if inFlightPMStandingReviewWakeFingerprint == fingerprint {
                inFlightPMStandingReviewWakeFingerprint = nil
            }
        }

        let pendingReports = try await pendingStandingReportsForPMReview(reportIDs: currentReportIDs)
        guard pendingReports.isEmpty == false else {
            knownPendingStandingReviewReportIDs = currentReportIDs
            lastPMStandingReviewWakeFingerprint = fingerprint
            await store.publishDiagnostic(
                "pm standing review wake triggered without loadable pending reports trigger=\(trigger.rawValue) pending=\(queue.pendingCount)",
                source: source,
                action: "pm_standing_review_wake_degraded"
            )
            return nil
        }
        let analysis = analyzePMStandingReviewCycle(
            contextPack: contextPack,
            reports: pendingReports
        )
        lastPMStandingReviewWakeFingerprint = fingerprint
        knownPendingStandingReviewReportIDs = currentReportIDs
        await store.publishDiagnostic(
            "pm standing review wake triggered trigger=\(trigger.rawValue) pending=\(queue.pendingCount) analysts=\(queue.analystsAwaitingReview.joined(separator: ","))",
            source: source,
            action: "pm_standing_review_wake"
        )
        await store.publishDiagnostic(
            "pm standing review queue updated trigger=\(trigger.rawValue) pending=\(pendingReports.count) disposition=\(analysis.disposition.rawValue)",
            source: source,
            action: "pm_standing_review_queue_updated"
        )
        await store.publish(StoreEvent(name: "pm_standing_review_queue_changed"))
        return nil
    }

    @discardableResult
    public func completePendingStandingReviewCycle(
        source: AuditEventSource = .ui
    ) async throws -> PMNotebookEntry? {
        let cleanupOnlySummary = try await closeLingeringBackgroundStandingReviewArtifacts(
            source: source
        )
        let contextPack = try await assemblePMContextPack()
        let queue = contextPack.operatingContext.standingReviewQueue
        let currentReportIDs = Set(queue.items.map(\.reportId))
        guard currentReportIDs.isEmpty == false else {
            knownPendingStandingReviewReportIDs.removeAll()
            lastPMStandingReviewWakeFingerprint = nil
            if cleanupOnlySummary.didChange {
                await store.publishDiagnostic(
                    "pm standing review cleanup closed stale background artifacts requests=\(cleanupOnlySummary.withdrawnApprovalRequests) decisions=\(cleanupOnlySummary.withdrawnDecisions)",
                    source: source,
                    action: "pm_standing_review_cleanup"
                )
                await store.publish(StoreEvent(name: "pm_standing_review_cycle_closed"))
            }
            return nil
        }

        let allPendingReports = try await pendingStandingReportsForPMReview(reportIDs: currentReportIDs)
        guard allPendingReports.isEmpty == false else {
            knownPendingStandingReviewReportIDs = currentReportIDs
            if cleanupOnlySummary.didChange {
                await store.publishDiagnostic(
                    "pm standing review cleanup closed stale background artifacts requests=\(cleanupOnlySummary.withdrawnApprovalRequests) decisions=\(cleanupOnlySummary.withdrawnDecisions)",
                    source: source,
                    action: "pm_standing_review_cleanup"
                )
                await store.publish(StoreEvent(name: "pm_standing_review_cycle_closed"))
            }
            return nil
        }
        let pendingReports = Array(allPendingReports.prefix(1))

        var analysis = analyzePMStandingReviewCycle(
            contextPack: contextPack,
            reports: pendingReports
        )
        let reasoning = try await synthesizePMStandingReviewIfPossible(
            baseAnalysis: analysis,
            contextPack: contextPack,
            reports: pendingReports
        )
        analysis = reasoning.analysis
        _ = try await markStandingReportsReviewedByPM(pendingReports)
        let outcomeArtifacts = try await recordPMStandingReviewOutcomeArtifacts(
            contextPack: contextPack,
            reports: pendingReports,
            analysis: analysis,
            reasoning: reasoning,
            source: source
        )
        let cleanupSummary = try await closeLingeringBackgroundStandingReviewArtifacts(
            source: source
        )

        knownPendingStandingReviewReportIDs.subtract(currentReportIDs)
        lastPMStandingReviewWakeFingerprint = nil
        await store.publishDiagnostic(
            "pm standing review completed reviewed=\(pendingReports.count) disposition=\(analysis.disposition.rawValue) quiet_summary=\(shortOrderID(outcomeArtifacts.backgroundSummary.entryId)) decision=\(outcomeArtifacts.decision != nil) approval=\(outcomeArtifacts.approvalRequest != nil) cleaned_requests=\(cleanupSummary.withdrawnApprovalRequests) cleaned_decisions=\(cleanupSummary.withdrawnDecisions)",
            source: source,
            action: "pm_standing_review_complete"
        )
        await store.publish(StoreEvent(name: "pm_standing_review_cycle_closed"))
        return outcomeArtifacts.backgroundSummary
    }

    private func pmStandingReviewWakeFingerprint(
        for queue: PMStandingReviewQueueSummary
    ) -> String {
        queue.items
            .map(\.reportId)
            .sorted()
            .joined(separator: "|")
    }

    private func pendingStandingReportsForPMReview(
        reportIDs: Set<String>
    ) async throws -> [AnalystStandingReport] {
        let reports = try await analystStandingReportStore.loadAll()
        return reports
            .filter {
                reportIDs.contains($0.reportId)
                    && $0.deliveryStatus == .pendingPMReview
            }
            .sorted { lhs, rhs in
                if lhs.deliveredToPMInboxAt == rhs.deliveredToPMInboxAt {
                    return lhs.reportId < rhs.reportId
                }
                return lhs.deliveredToPMInboxAt > rhs.deliveredToPMInboxAt
            }
    }

    private func markStandingReportsReviewedByPM(
        _ reports: [AnalystStandingReport]
    ) async throws -> [AnalystStandingReport] {
        guard reports.isEmpty == false else { return [] }

        let reviewedAt = nowDate()
        var updatedReports: [AnalystStandingReport] = []
        for report in reports where report.deliveryStatus == .pendingPMReview {
            var updated = report
            updated.deliveryStatus = .reviewedByPM
            updated.updatedAt = reviewedAt
            updatedReports.append(try await analystStandingReportStore.upsert(updated))
        }
        await publishAnalystPersistenceDiagnostics()
        return updatedReports
    }

    private func recordPMStandingReviewOutcomeArtifacts(
        contextPack: PMContextPack,
        reports: [AnalystStandingReport],
        analysis: PMStandingReviewCycleAnalysis,
        reasoning: PMStandingReviewReasoningResult,
        source: AuditEventSource
    ) async throws -> PMStandingReviewOutcomeArtifacts {
        let summary = try await upsertPMNotebookEntry(
            makePMStandingReviewBackgroundSummaryEntry(
                contextPack: contextPack,
                reports: reports,
                analysis: analysis
            ),
            source: source
        )

        guard analysis.disposition == .ownerAttentionRecommended else {
            return PMStandingReviewOutcomeArtifacts(
                backgroundSummary: summary,
                decision: try await upsertPMDecision(
                    makePMStandingReviewClosureDecision(
                        contextPack: contextPack,
                        reports: reports,
                        analysis: analysis,
                        reasoning: reasoning,
                        sourceSummaryEntry: summary
                    ),
                    source: source
                ),
                approvalRequest: nil
            )
        }

        let decision = try await upsertPMDecision(
            makePMStandingReviewEscalationDecision(
                contextPack: contextPack,
                reports: reports,
                analysis: analysis,
                reasoning: reasoning,
                sourceSummaryEntry: summary
            ),
            source: source
        )
        let approvalRequest = try await createPMApprovalRequestFromDecision(
            decisionId: decision.decisionId,
            subject: "Review standing analyst synthesis: \(analysis.analystTitles.joined(separator: ", "))",
            rationale: makePMStandingReviewEscalationRationale(
                reports: reports,
                analysis: analysis
            ),
            requestedActionSummary: "Review the PM synthesis from this standing-review cycle and decide whether it should remain background-only or advance into a separate governed next step.",
            approvedNextStepSummary: "I will keep the standing-review conclusion visible as an owner-reviewed PM item and, if needed, shape any next step through the normal governed path.",
            rejectedNextStepSummary: "I will keep this standing-review outcome in background PM work and will not advance it into a governed next step.",
            reviewedNextStepSummary: "I will keep monitoring the standing bench output or request bounded follow-up work without creating an execution request.",
            requestType: .other,
            source: source
        )
        return PMStandingReviewOutcomeArtifacts(
            backgroundSummary: summary,
            decision: decision,
            approvalRequest: approvalRequest
        )
    }

    private func makePMStandingReviewClosureDecision(
        contextPack: PMContextPack,
        reports: [AnalystStandingReport],
        analysis: PMStandingReviewCycleAnalysis,
        reasoning: PMStandingReviewReasoningResult,
        sourceSummaryEntry: PMNotebookEntry
    ) -> PMDecisionRecord {
        let resolvedPMID = contextPack.pmId ?? PMProfile.primaryPMID
        let now = nowDate()
        let analystLead = analysis.analystTitles.joined(separator: ", ")
        let linkedStandingReportIDs = orderedStandingReviewResultIDs(reports)

        let summaryText = reasoning.summaryOverride ?? makeDeterministicPMStandingReviewSummary(
            reports: reports,
            analysis: analysis,
            analystLead: analystLead
        )
        let recommendedAction = reasoning.recommendedActionOverride
            ?? makeDeterministicPMStandingReviewRecommendedAction(disposition: analysis.disposition)

        return PMDecisionRecord(
            decisionId: "pm-decision-\(UUID().uuidString.lowercased())",
            pmId: resolvedPMID,
            title: "Standing review conclusion: \(analystLead)",
            summary: summaryText,
            recommendedAction: recommendedAction,
            evidenceSummary: "Standing review cycle covered \(reports.count) report\(reports.count == 1 ? "" : "s"). Background summary: \(sourceSummaryEntry.title).",
            decisionType: .recommendation,
            status: .active,
            charterId: reports.count == 1 ? reports.first?.charterId : nil,
            primaryStandingReportId: linkedStandingReportIDs.first,
            standingReportIds: linkedStandingReportIDs,
            standingReviewDisposition: analysis.disposition.rawValue,
            standingReviewAnalystTitles: analysis.analystTitles,
            standingReviewAttentionItems: analysis.attentionItems,
            standingReviewCandidateLongs: analysis.candidateLongs,
            standingReviewCandidateShorts: analysis.candidateShorts,
            standingReviewCandidateThemes: analysis.candidateThemes,
            standingReviewFollowUpItems: analysis.followUpItems,
            runtimeProvenance: reasoning.runtimeProvenance,
            createdAt: now,
            updatedAt: now
        )
    }

    private func closeLingeringBackgroundStandingReviewArtifacts(
        source: AuditEventSource
    ) async throws -> PMStandingReviewArtifactCleanupSummary {
        let now = nowDate()
        let decisions = try await pmDecisionStore.loadAll()
        let requests = try await pmApprovalRequestStore.loadAll()
        let decisionsByID = Dictionary(uniqueKeysWithValues: decisions.map { ($0.decisionId, $0) })
        var requestsByDecisionID: [String: PMApprovalRequest] = [:]
        for request in requests {
            guard let decisionId = request.decisionId,
                  requestsByDecisionID[decisionId] == nil else {
                continue
            }
            requestsByDecisionID[decisionId] = request
        }

        var withdrawnApprovalRequests = 0
        for request in requests where request.status == .pending {
            let linkedDecision = request.decisionId.flatMap { decisionsByID[$0] }
            guard standingReviewBackgroundByDefault(
                request: request,
                linkedDecision: linkedDecision
            ) else {
                continue
            }
            var updated = request
            updated.status = .withdrawn
            updated.updatedAt = now
            _ = try await upsertPMApprovalRequest(updated, source: source)
            withdrawnApprovalRequests += 1
        }

        var withdrawnDecisions = 0
        for decision in decisions where decision.status == .active {
            let linkedRequest = requestsByDecisionID[decision.decisionId]
            guard standingReviewBackgroundByDefault(
                decision: decision,
                linkedApprovalRequest: linkedRequest
            ) else {
                continue
            }
            var updated = decision
            updated.status = .withdrawn
            updated.updatedAt = now
            _ = try await upsertPMDecision(updated, source: source)
            withdrawnDecisions += 1
        }

        return PMStandingReviewArtifactCleanupSummary(
            withdrawnApprovalRequests: withdrawnApprovalRequests,
            withdrawnDecisions: withdrawnDecisions
        )
    }

    private func makePMStandingReviewBackgroundSummaryEntry(
        contextPack: PMContextPack,
        reports: [AnalystStandingReport],
        analysis: PMStandingReviewCycleAnalysis
    ) -> PMNotebookEntry {
        let resolvedPMID = contextPack.pmId ?? PMProfile.primaryPMID
        let noPortfolio = contextPack.sharedPortfolioTruth.positionCount == 0
        let reviewedAnalysts = analysis.analystTitles.joined(separator: ", ")
        let now = nowDate()

        var lines: [String] = [
            "Closed one PM standing-review cycle across \(reports.count) standing analyst report\(reports.count == 1 ? "" : "s") from \(reviewedAnalysts).",
            "Disposition: \(analysis.disposition.displayTitle)."
        ]

        if noPortfolio {
            lines.append("No live portfolio is attached, so this review stayed in candidate and portfolio-construction synthesis mode rather than existing-holdings maintenance.")
        }

        if analysis.attentionItems.isEmpty == false {
            lines.append("What matters most now: \(analysis.attentionItems.prefix(3).joined(separator: " | "))")
        }

        let candidateSummary = makePMStandingReviewCandidateSummary(analysis: analysis)
        if candidateSummary.isEmpty == false {
            if noPortfolio {
                lines.append("Candidate directions worth considering: \(candidateSummary)")
            } else {
                lines.append("Ideas or expressions worth monitoring after review: \(candidateSummary)")
            }
        }

        if analysis.followUpItems.isEmpty == false {
            lines.append("Possible PM follow-up: \(analysis.followUpItems.prefix(3).joined(separator: " | "))")
        }

        if analysis.disposition == .informationalNoAction {
            lines.append("No governed next step is being escalated from this review cycle.")
        }

        if analysis.disposition == .ownerAttentionRecommended {
            lines.append("This cycle crossed the owner-attention threshold, so the next step was routed into the owner decision path instead of direct PM chat.")
        } else {
            lines.append("This cycle stays as quiet background PM work. No proposal, approval, or execution action is being initiated from it.")
        }

        return PMNotebookEntry(
            entryId: "pm-note-\(UUID().uuidString.lowercased())",
            pmId: resolvedPMID,
            title: "Standing review closed: \(reviewedAnalysts)",
            body: lines.joined(separator: "\n\n"),
            tags: [
                pmStandingReviewBackgroundNotebookTag,
                pmStandingReviewNotebookTag,
                analysis.disposition.rawValue
            ],
            sourceSummary: makePMStandingReviewBackgroundSourceSummary(
                analysis: analysis,
                reports: reports
            ),
            createdAt: now,
            updatedAt: now
        )
    }

    private func makePMStandingReviewBackgroundSourceSummary(
        analysis: PMStandingReviewCycleAnalysis,
        reports: [AnalystStandingReport]
    ) -> String {
        let analystLead = analysis.analystTitles.joined(separator: ", ")
        return "Closed \(reports.count) reviewed standing report\(reports.count == 1 ? "" : "s") from \(analystLead) as \(analysis.disposition.displayTitle.lowercased())."
    }

    private func makePMStandingReviewEscalationDecision(
        contextPack: PMContextPack,
        reports: [AnalystStandingReport],
        analysis: PMStandingReviewCycleAnalysis,
        reasoning: PMStandingReviewReasoningResult,
        sourceSummaryEntry: PMNotebookEntry
    ) -> PMDecisionRecord {
        let resolvedPMID = contextPack.pmId ?? PMProfile.primaryPMID
        let now = nowDate()
        let title = "Standing review escalation: \(analysis.analystTitles.joined(separator: ", "))"
        let summaryText = reasoning.summaryOverride ?? makeDeterministicPMStandingReviewEscalationSummary(analysis: analysis)
        let linkedStandingReportIDs = orderedStandingReviewResultIDs(reports)

        return PMDecisionRecord(
            decisionId: "pm-decision-\(UUID().uuidString.lowercased())",
            pmId: resolvedPMID,
            title: title,
            summary: summaryText,
            recommendedAction: reasoning.recommendedActionOverride
                ?? analysis.attentionItems.first
                ?? analysis.followUpItems.first
                ?? makePMStandingReviewCandidateSummary(analysis: analysis),
            evidenceSummary: "Standing review cycle covered \(reports.count) report\(reports.count == 1 ? "" : "s") from \(analysis.analystTitles.joined(separator: ", ")). Background summary: \(sourceSummaryEntry.title).",
            ownerAsk: "Review this standing-review synthesis and decide whether you want it to remain monitor-only or have me prepare a separate governed next step.",
            approvedNextStepSummary: "I will keep the reviewed analyst synthesis active as an owner-reviewed PM item and, if needed, prepare the next governed step separately.",
            decisionType: .escalation,
            status: .active,
            charterId: reports.count == 1 ? reports.first?.charterId : nil,
            primaryStandingReportId: linkedStandingReportIDs.first,
            standingReportIds: linkedStandingReportIDs,
            standingReviewDisposition: analysis.disposition.rawValue,
            standingReviewAnalystTitles: analysis.analystTitles,
            standingReviewAttentionItems: analysis.attentionItems,
            standingReviewCandidateLongs: analysis.candidateLongs,
            standingReviewCandidateShorts: analysis.candidateShorts,
            standingReviewCandidateThemes: analysis.candidateThemes,
            standingReviewFollowUpItems: analysis.followUpItems,
            runtimeProvenance: reasoning.runtimeProvenance,
            createdAt: now,
            updatedAt: now
        )
    }

    private func orderedStandingReviewResultIDs(
        _ reports: [AnalystStandingReport]
    ) -> [String] {
        reports
            .sorted { lhs, rhs in
                let lhsTimestamp = max(lhs.updatedAt, lhs.deliveredToPMInboxAt)
                let rhsTimestamp = max(rhs.updatedAt, rhs.deliveredToPMInboxAt)
                if lhsTimestamp == rhsTimestamp {
                    return lhs.reportId < rhs.reportId
                }
                return lhsTimestamp > rhsTimestamp
            }
            .map(\.reportId)
    }

    private func makePMStandingReviewEscalationRationale(
        reports: [AnalystStandingReport],
        analysis: PMStandingReviewCycleAnalysis
    ) -> String {
        var segments: [String] = [
            "Standing analyst review surfaced an owner-relevant issue across \(reports.count) reviewed report\(reports.count == 1 ? "" : "s")."
        ]
        if analysis.attentionItems.isEmpty == false {
            segments.append("Most important: \(analysis.attentionItems.prefix(3).joined(separator: " | "))")
        }
        if analysis.followUpItems.isEmpty == false {
            segments.append("Potential follow-up: \(analysis.followUpItems.prefix(2).joined(separator: " | "))")
        }
        return segments.joined(separator: " ")
    }

    private func analyzePMStandingReviewCycle(
        contextPack: PMContextPack,
        reports: [AnalystStandingReport]
    ) -> PMStandingReviewCycleAnalysis {
        let analystTitles = orderedUniqueStrings(
            reports.compactMap { report in
                report.title.replacingOccurrences(of: " Standing Report", with: "")
            }
        )
        let attentionItems = orderedUniqueStrings(
            standingReviewAttentionSummaries(in: reports, limit: 4)
        )
        let candidateLongs = orderedUniqueStrings(
            standingReviewSectionSummaries(
                in: reports,
                kinds: [.longIdeas],
                limit: 4
            )
        )
        let candidateShorts = orderedUniqueStrings(
            standingReviewSectionSummaries(
                in: reports,
                kinds: [.shortIdeas, .etfIdeas],
                limit: 4
            )
        )
        let candidateThemes = orderedUniqueStrings(
            standingReviewSectionSummaries(
                in: reports,
                kinds: [.macroViews, .portfolioRelevance],
                limit: 4
            )
        )
        let followUpItems = orderedUniqueStrings(
            standingReviewFollowUpSummaries(in: reports, limit: 4)
        )

        let noPortfolio = contextPack.sharedPortfolioTruth.positionCount == 0
        let hasCandidateIdeas = candidateLongs.isEmpty == false
            || candidateShorts.isEmpty == false
            || candidateThemes.isEmpty == false
        let hasConcreteOwnerAction = attentionItems.contains(where: isStandingReviewConcreteOwnerActionCandidate(_:))
        let disposition: PMStandingReviewDisposition
        if noPortfolio && hasCandidateIdeas {
            disposition = .candidateIdeasWorthConsidering
        } else if hasConcreteOwnerAction {
            disposition = .ownerAttentionRecommended
        } else if attentionItems.isEmpty == false || followUpItems.isEmpty == false {
            disposition = .followUpAnalystWorkWarranted
        } else if hasCandidateIdeas {
            disposition = .worthMonitoring
        } else {
            disposition = .informationalNoAction
        }

        return PMStandingReviewCycleAnalysis(
            disposition: disposition,
            analystTitles: analystTitles,
            attentionItems: attentionItems,
            candidateLongs: candidateLongs,
            candidateShorts: candidateShorts,
            candidateThemes: candidateThemes,
            followUpItems: followUpItems
        )
    }

    private func makePMStandingReviewCandidateSummary(
        analysis: PMStandingReviewCycleAnalysis
    ) -> String {
        var segments: [String] = []
        if analysis.candidateLongs.isEmpty == false {
            segments.append("long candidates: \(analysis.candidateLongs.prefix(3).joined(separator: ", "))")
        }
        if analysis.candidateShorts.isEmpty == false {
            segments.append("short or hedge ideas: \(analysis.candidateShorts.prefix(3).joined(separator: ", "))")
        }
        if analysis.candidateThemes.isEmpty == false {
            segments.append("themes or expressions: \(analysis.candidateThemes.prefix(3).joined(separator: ", "))")
        }
        return segments.joined(separator: " • ")
    }

    private func synthesizePMStandingReviewIfPossible(
        baseAnalysis: PMStandingReviewCycleAnalysis,
        contextPack: PMContextPack,
        reports: [AnalystStandingReport]
    ) async throws -> PMStandingReviewReasoningResult {
        let launchedAt = nowDate()
        let (_, runtimeSelection) = try await resolvedPMRuntimeSettingsForExecution(now: launchedAt)
        let credentialResolution = openAICredentialResolution(for: runtimeSelection)
        let fallbackProvenance = pmFallbackRuntimeProvenance(
            runtimeSelection: runtimeSelection,
            status: credentialResolution.fallbackStatus,
            issueSummary: credentialResolution.synthesisIssueSummary,
            launchedAt: launchedAt
        )
        guard let apiKey = credentialResolution.apiKey else {
            return PMStandingReviewReasoningResult(
                analysis: baseAnalysis,
                summaryOverride: nil,
                recommendedActionOverride: nil,
                runtimeProvenance: fallbackProvenance
            )
        }

        let strategyBrief = try await getPortfolioStrategyBrief()
        let request = PMStandingReviewOpenAISynthesisRequest(
            runtimeIdentifier: runtimeSelection.effectiveRuntimeIdentifier,
            reasoningMode: runtimeSelection.effectiveReasoningMode,
            strategyObjective: emptyToNil(strategyBrief.objectiveSummary),
            currentRiskPosture: emptyToNil(strategyBrief.currentRiskPosture),
            reviewEscalationPosture: emptyToNil(strategyBrief.reviewEscalationPosture),
            noPortfolio: contextPack.sharedPortfolioTruth.positionCount == 0,
            analystTitles: baseAnalysis.analystTitles,
            attentionItems: baseAnalysis.attentionItems,
            candidateLongs: baseAnalysis.candidateLongs,
            candidateShorts: baseAnalysis.candidateShorts,
            candidateThemes: baseAnalysis.candidateThemes,
            followUpItems: baseAnalysis.followUpItems,
            reports: reports.prefix(4).map { report in
                PMStandingReviewOpenAISynthesisRequest.ReportContext(
                    title: report.title,
                    summary: report.summary,
                    headlineView: report.headlineView,
                    portfolioRelevanceSummary: report.portfolioRelevanceSummary,
                    openQuestions: Array(report.openQuestions.prefix(4)),
                    sections: report.sections.prefix(5).flatMap { section in
                        section.items.prefix(2).map { item in
                            "\(section.kind.displayTitle): \(item.headline)"
                        }
                    }
                )
            }
        )

        do {
            let output = try await pmOpenAISynthesisProvider.synthesizeStandingReview(
                request: request,
                apiKey: apiKey
            )
            var analysis = baseAnalysis
            analysis.disposition = pmStandingReviewDisposition(from: output.disposition) ?? baseAnalysis.disposition
            return PMStandingReviewReasoningResult(
                analysis: analysis,
                summaryOverride: output.summary,
                recommendedActionOverride: output.recommendedAction,
                runtimeProvenance: PMRuntimeProvenance(
                    configuredProviderKind: runtimeSelection.configuredProviderKind,
                    configuredCredentialProfileId: runtimeSelection.configuredCredentialProfileId,
                    configuredRuntimeIdentifier: runtimeSelection.configuredRuntimeIdentifier,
                    configuredReasoningMode: runtimeSelection.configuredReasoningMode,
                    actualProviderKind: runtimeSelection.effectiveProviderKind,
                    actualCredentialProfileId: runtimeSelection.effectiveCredentialProfileId,
                    actualRuntimeIdentifier: "openai_responses[\(runtimeSelection.effectiveRuntimeIdentifier)]",
                    actualReasoningMode: runtimeSelection.effectiveReasoningMode,
                    usedOpenAI: true,
                    synthesisStatus: "openai_responses",
                    launchedAt: launchedAt
                )
            )
        } catch let error as PMOpenAISynthesisError {
            return PMStandingReviewReasoningResult(
                analysis: baseAnalysis,
                summaryOverride: nil,
                recommendedActionOverride: nil,
                runtimeProvenance: pmFallbackRuntimeProvenance(
                    runtimeSelection: runtimeSelection,
                    status: "fallback_openai_error",
                    issueSummary: error.boundedSummary,
                    launchedAt: launchedAt
                )
            )
        } catch {
            return PMStandingReviewReasoningResult(
                analysis: baseAnalysis,
                summaryOverride: nil,
                recommendedActionOverride: nil,
                runtimeProvenance: pmFallbackRuntimeProvenance(
                    runtimeSelection: runtimeSelection,
                    status: "fallback_openai_error",
                    issueSummary: "openai_unexpected_error",
                    launchedAt: launchedAt
                )
            )
        }
    }

    private func pmStandingReviewDisposition(from rawValue: String) -> PMStandingReviewDisposition? {
        PMStandingReviewDisposition(rawValue: rawValue)
    }

    private func makeDeterministicPMStandingReviewSummary(
        reports: [AnalystStandingReport],
        analysis: PMStandingReviewCycleAnalysis,
        analystLead: String
    ) -> String {
        var summarySegments: [String] = [
            "Closed standing-review cycle across \(reports.count) reviewed report\(reports.count == 1 ? "" : "s") from \(analystLead).",
            "Disposition: \(analysis.disposition.displayTitle)."
        ]
        if analysis.attentionItems.isEmpty == false {
            summarySegments.append("What mattered most: \(analysis.attentionItems.prefix(3).joined(separator: " | "))")
        }
        let candidateSummary = makePMStandingReviewCandidateSummary(analysis: analysis)
        if candidateSummary.isEmpty == false {
            summarySegments.append("Candidate directions: \(candidateSummary)")
        }
        if analysis.followUpItems.isEmpty == false {
            summarySegments.append("Possible follow-up: \(analysis.followUpItems.prefix(3).joined(separator: " | "))")
        }
        summarySegments.append("This remains PM-layer conclusion truth only. No owner approval request, proposal approval, trade authorization, or safety-state change is being created from this review cycle.")
        return summarySegments.joined(separator: " ")
    }

    private func makeDeterministicPMStandingReviewEscalationSummary(
        analysis: PMStandingReviewCycleAnalysis
    ) -> String {
        let candidateSummary = makePMStandingReviewCandidateSummary(analysis: analysis)
        var summarySegments: [String] = []
        if analysis.attentionItems.isEmpty == false {
            summarySegments.append("Key issues: \(analysis.attentionItems.prefix(3).joined(separator: " | "))")
        }
        if candidateSummary.isEmpty == false {
            summarySegments.append("Supporting ideas: \(candidateSummary)")
        }
        if analysis.followUpItems.isEmpty == false {
            summarySegments.append("Follow-up worth weighing: \(analysis.followUpItems.prefix(2).joined(separator: " | "))")
        }
        summarySegments.append("This recommendation came out of quiet PM standing-review work and is now routed through the owner decision path instead of PM conversation chatter.")
        return summarySegments.joined(separator: " ")
    }

    private func makeDeterministicPMStandingReviewRecommendedAction(
        disposition: PMStandingReviewDisposition
    ) -> String {
        switch disposition {
        case .informationalNoAction:
            return "No action is warranted from this standing-review cycle right now."
        case .worthMonitoring:
            return "Keep this cycle monitor-only in PM background review with no owner escalation right now."
        case .followUpAnalystWorkWarranted:
            return "Keep this cycle in PM background review and decide whether bounded analyst follow-up is warranted before any owner-facing ask."
        case .candidateIdeasWorthConsidering:
            return "Keep these candidate ideas in PM background review for watchlist or portfolio-construction follow-up; no owner escalation is warranted right now."
        case .ownerAttentionRecommended:
            return "Owner attention is recommended through the separate governed review path."
        }
    }

    private func standingReviewAttentionSummaries(
        in reports: [AnalystStandingReport],
        limit: Int
    ) -> [String] {
        var summaries: [String] = []
        let attentionKinds: Set<AnalystStandingReportSectionKind> = [.riskIssues, .importantItems, .materialDevelopments]

        for report in reports {
            for section in report.sections where attentionKinds.contains(section.kind) {
                for item in section.items {
                    let priority = item.priority ?? item.conviction ?? 0
                    guard priority >= standingReviewOwnerAttentionPriorityThreshold else {
                        continue
                    }
                    let summary = standingReviewItemSummary(item)
                    guard isStandingReviewMaterialAttentionSummary(summary) else {
                        continue
                    }
                    summaries.append(summary)
                    if summaries.count >= limit {
                        return summaries
                    }
                }
            }
        }

        return summaries
    }

    private func standingReviewSectionSummaries(
        in reports: [AnalystStandingReport],
        kinds: Set<AnalystStandingReportSectionKind>,
        limit: Int
    ) -> [String] {
        var summaries: [String] = []
        for report in reports {
            for section in report.sections where kinds.contains(section.kind) {
                for item in section.items {
                    let summary = standingReviewItemSummary(item)
                    guard summary.isEmpty == false else { continue }
                    summaries.append(summary)
                    if summaries.count >= limit {
                        return summaries
                    }
                }
            }
        }
        return summaries
    }

    private func standingReviewFollowUpSummaries(
        in reports: [AnalystStandingReport],
        limit: Int
    ) -> [String] {
        var summaries: [String] = []
        for report in reports {
            for question in report.openQuestions {
                let trimmed = question.trimmingCharacters(in: .whitespacesAndNewlines)
                guard trimmed.isEmpty == false else { continue }
                summaries.append(trimmed)
                if summaries.count >= limit {
                    return summaries
                }
            }
            for section in report.sections where section.kind == .followUp {
                for item in section.items {
                    let summary = standingReviewItemSummary(item)
                    guard summary.isEmpty == false else { continue }
                    summaries.append(summary)
                    if summaries.count >= limit {
                        return summaries
                    }
                }
            }
        }
        return summaries
    }

    private func isStandingReviewMaterialAttentionSummary(
        _ summary: String
    ) -> Bool {
        let normalized = summary
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .lowercased()
        guard normalized.isEmpty == false else {
            return false
        }

        let lowSignalPhrases = [
            "no fresh",
            "no material",
            "no meaningful",
            "no current action",
            "no governed next step",
            "no action",
            "nothing material",
            "non-material",
            "not material",
            "remain quiet",
            "stay quiet",
            "monitor-only",
            "background-only",
            "worth monitoring",
            "candidate worth considering",
            "did not displace"
        ]
        return lowSignalPhrases.contains(where: { normalized.contains($0) }) == false
    }

    private func isStandingReviewConcreteOwnerActionCandidate(
        _ summary: String
    ) -> Bool {
        guard isStandingReviewMaterialAttentionSummary(summary) else {
            return false
        }

        let normalized = summary
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .lowercased()
        let actionPhrases = [
            "reduce",
            "trim",
            "hedge",
            "rebalance",
            "rotate",
            "exit",
            "de-risk",
            "change posture",
            "change exposure",
            "adjust sizing",
            "raise cash",
            "cut exposure",
            "increase exposure",
            "prepare a follow-up now",
            "owner decision"
        ]
        return actionPhrases.contains(where: { normalized.contains($0) })
    }

    private func standingReviewItemSummary(
        _ item: AnalystStandingReportItem
    ) -> String {
        let headline = item.headline.trimmingCharacters(in: .whitespacesAndNewlines)
        let detail = item.detail.trimmingCharacters(in: .whitespacesAndNewlines)
        if let symbol = item.symbol?.trimmingCharacters(in: .whitespacesAndNewlines),
           symbol.isEmpty == false,
           headline.isEmpty == false,
           headline.caseInsensitiveCompare(symbol) != .orderedSame {
            return "\(symbol): \(headline)"
        }
        if headline.isEmpty == false {
            return headline
        }
        return detail
    }

    private func orderedUniqueStrings(
        _ values: [String]
    ) -> [String] {
        var seen: Set<String> = []
        var ordered: [String] = []
        for value in values {
            let trimmed = value.trimmingCharacters(in: .whitespacesAndNewlines)
            guard trimmed.isEmpty == false else { continue }
            if seen.insert(trimmed).inserted {
                ordered.append(trimmed)
            }
        }
        return ordered
    }

