    public func resolvePMRuntimeSelectionForExecution() async throws -> ResolvedRuntimeSelection {
        let now = nowDate()
        let settings = try await getPMRuntimeSettings()
        let resolution = resolveRuntimeSelection(
            configuredRuntimeIdentifier: settings.runtimeIdentifier,
            configuredReasoningMode: settings.reasoningMode,
            configuredProviderKind: settings.providerKind,
            configuredCredentialProfileId: settings.credentialProfileId,
            lastKnownGoodRuntime: settings.lastKnownGoodRuntime,
            checkedBy: settings.updatedBy,
            now: now,
            anthropicExecutionSupported: true
        )
        let updated = applyingRuntimeResolution(
            resolution,
            to: settings,
            updateSource: settings.updateSource,
            updatedBy: settings.updatedBy,
            now: now
        )
        if updated != settings {
            _ = try await pmRuntimeSettingsStore.upsert(updated)
            await publishPMPersistenceDiagnostics()
        }
        return resolution
    }

    private func resolvedPMRuntimeSettingsForExecution(
        now: Date
    ) async throws -> (PMRuntimeSettings, ResolvedRuntimeSelection) {
        let settings = try await getPMRuntimeSettings()
        let resolution = resolveRuntimeSelection(
            configuredRuntimeIdentifier: settings.runtimeIdentifier,
            configuredReasoningMode: settings.reasoningMode,
            configuredProviderKind: settings.providerKind,
            configuredCredentialProfileId: settings.credentialProfileId,
            lastKnownGoodRuntime: settings.lastKnownGoodRuntime,
            checkedBy: settings.updatedBy,
            now: now,
            anthropicExecutionSupported: true
        )
        let updated = applyingRuntimeResolution(
            resolution,
            to: settings,
            updateSource: settings.updateSource,
            updatedBy: settings.updatedBy,
            now: now
        )
        if updated != settings {
            _ = try await pmRuntimeSettingsStore.upsert(updated)
            await publishPMPersistenceDiagnostics()
            await store.publishDiagnostic(
                "pm runtime selection resolved configured=\(settings.runtimeIdentifier) effective=\(resolution.effectiveRuntimeIdentifier) fallback=\(resolution.fallbackApplied)",
                source: .engine,
                action: "pm_runtime_resolution"
            )
        }
        if resolution.validation.status == .invalid,
           resolution.validation.category != .unavailable,
           resolution.fallbackApplied == false {
            throw RuntimeSelectionResolutionError.configuredRuntimeInvalid(
                summary: "PM runtime is invalid and no last-known-good fallback is available. \(resolution.validation.summary)"
            )
        }
        return (updated, resolution)
    }

    private func pmExecutionStatusRecord(
        category: RuntimeValidationCategory,
        summary: String,
        checkedBy: String,
        now: Date
    ) -> RuntimeValidationRecord {
        RuntimeValidationRecord(
            status: category == .accepted ? .valid : .invalid,
            category: category,
            summary: summary,
            checkedAt: now,
            checkedBy: checkedBy
        )
    }

    private func pmExecutionStatusRecord(
        for error: PMOpenAISynthesisError,
        runtimeSelection: ResolvedRuntimeSelection,
        checkedBy: String,
        now: Date
    ) -> RuntimeValidationRecord {
        let runtimeLabel = runtimeSelection.effectiveRuntimeIdentifier
        let summary = error.boundedSummary
        let category: RuntimeValidationCategory
        switch pmConversationFallbackTrigger(degradedReason: "fallback_openai_error", issueSummary: summary) {
        case .invalidSchema:
            category = .invalidSchema
        case .authFailure:
            category = .authFailure
        case .networkFailure, .timeout:
            category = .networkFailure
        case .rateLimitOrQuota:
            category = .rateLimitOrQuota
        case .invalidRuntime:
            category = .unavailable
        case .requestTooLarge:
            category = .requestTooLarge
        case .providerUnavailable:
            category = .providerFailure
        case .refusal:
            category = .refusal
        case .malformedResponse:
            category = .malformedResponse
        case .credentialUnavailable, .credentialEmpty:
            category = .unavailable
        case .internalFailure:
            category = .internalFailure
        }
        return pmExecutionStatusRecord(
            category: category,
            summary: "Latest PM conversation execution for \(runtimeLabel) failed: \(summary).",
            checkedBy: checkedBy,
            now: now
        )
    }

    private func recordPMConversationExecutionStatus(
        _ executionStatus: RuntimeValidationRecord,
        runtimeSelection: ResolvedRuntimeSelection,
        now: Date
    ) async throws {
        let current = try await pmRuntimeSettingsStore.loadOrDefault()
        let normalizedRuntime = normalizedRuntimeIdentifier(current.runtimeIdentifier)
        guard normalizedRuntime == runtimeSelection.configuredRuntimeIdentifier else {
            return
        }

        var updated = current
        updated.settingsId = PMRuntimeSettings.singletonID
        updated.validationStatus = current.validationStatus
        updated.executionStatus = executionStatus
        if executionStatus.category == .accepted {
            updated.lastKnownGoodRuntime = LastKnownGoodRuntimeRecord(
                providerKind: runtimeSelection.effectiveProviderKind,
                credentialProfileId: runtimeSelection.effectiveCredentialProfileId,
                runtimeIdentifier: runtimeSelection.effectiveRuntimeIdentifier,
                reasoningMode: runtimeSelection.effectiveReasoningMode,
                verifiedAt: now,
                summary: "Verified by successful PM conversation execution."
            )
            if runtimeSelection.fallbackApplied == false {
                updated.lastFallback = nil
            }
        }

        if updated != current {
            _ = try await pmRuntimeSettingsStore.upsert(updated)
            await publishPMPersistenceDiagnostics()
        }
    }

    @discardableResult
    public func revisePortfolioStrategyBriefFromCommunicationMessage(
        messageId: String,
        title: String,
        documentBody: String,
        updatedBy: String,
        revisionSummary: String,
        source: AuditEventSource = .system
    ) async throws -> PortfolioStrategyBrief {
        let message = try await requirePromotableCommunicationMessage(id: messageId)
        let existing = try await portfolioStrategyBriefStore.loadOrDefault()
        let validatedTitle = try validatedPMCommunicationPromotionTitle(title)
        let validatedDocumentBody = try validatedPMCommunicationPromotionBody(documentBody)
        let validatedRevisionSummary = try validatedPMCommunicationPromotionBody(revisionSummary)
        let trimmedUpdatedBy = updatedBy.trimmingCharacters(in: .whitespacesAndNewlines)
        let now = nowDate()

        let revised = PortfolioStrategyBrief(
            briefId: PortfolioStrategyBrief.singletonID,
            title: validatedTitle,
            documentBody: validatedDocumentBody,
            objectiveSummary: existing.objectiveSummary,
            keyThemes: existing.keyThemes,
            currentRiskPosture: existing.currentRiskPosture,
            materialDevelopments: existing.materialDevelopments,
            nonMaterialDevelopments: existing.nonMaterialDevelopments,
            reviewEscalationPosture: existing.reviewEscalationPosture,
            revisionSummary: validatedRevisionSummary,
            sourceCommunicationMessageId: message.messageId,
            updatedBy: trimmedUpdatedBy.isEmpty ? "pm" : trimmedUpdatedBy,
            updateSource: .conversationDerived,
            createdAt: existing.createdAt,
            updatedAt: now
        )
        let stored = try await upsertPortfolioStrategyBrief(revised, source: source)
        _ = try await upsertPMCommunicationPromotion(
            message: message,
            targetType: .strategyBrief,
            targetId: stored.briefId,
            source: source
        )
        return stored
    }

