    @discardableResult
    public func upsertStandingBenchAnalystRuntimeSettings(
        _ settings: StandingBenchAnalystRuntimeSettings,
        source: AuditEventSource = .system
    ) async throws -> StandingBenchAnalystRuntimeSettings {
        let existing = await standingBenchAnalystRuntimeSettingsStore.loadOrDefault()
        let normalized = protectedStandingBenchAnalystRuntimeSettings(
            normalizedStandingBenchAnalystRuntimeSettings(
                settings,
                previous: existing,
                now: nowDate()
            ),
            existing: existing
        )
        let updated = try await standingBenchAnalystRuntimeSettingsStore.upsert(normalized)
        await publishAnalystPersistenceDiagnostics()
        await store.publishDiagnostic(
            "standing bench analyst runtime settings upserted id=\(shortOrderID(updated.settingsId)) runtime=\(updated.runtimeIdentifier) validation=\(updated.validationStatus?.status.rawValue ?? "unknown")",
            source: source,
            action: "standing_bench_runtime_settings_upsert"
        )
        return updated
    }

    private func protectedStandingBenchAnalystRuntimeSettings(
        _ incoming: StandingBenchAnalystRuntimeSettings,
        existing: StandingBenchAnalystRuntimeSettings?
    ) -> StandingBenchAnalystRuntimeSettings {
        guard let existing else {
            return incoming
        }

        let incomingSelection = standingBenchRuntimeSelectionFingerprint(incoming)
        let existingSelection = standingBenchRuntimeSelectionFingerprint(existing)
        guard incomingSelection != existingSelection else {
            return incoming
        }

        let incomingIsOwnerEdit = incoming.updateSource == .userEdited
        let existingIsOwnerEdit = existing.updateSource == .userEdited
        if existingIsOwnerEdit && incomingIsOwnerEdit == false && incoming.updatedAt <= existing.updatedAt {
            return existing
        }

        if incoming.updateSource == .systemDefault && incoming.updatedAt <= existing.updatedAt {
            return existing
        }

        return incoming
    }

    private func standingBenchRuntimeSelectionFingerprint(
        _ settings: StandingBenchAnalystRuntimeSettings
    ) -> String {
        let reasoning = settings.reasoningMode?.rawValue ?? "default"
        return "\(settings.providerKind.rawValue)|\(settings.credentialProfileId)|\(settings.runtimeIdentifier.lowercased())|\(reasoning)"
    }

