    @discardableResult
    public func routeAnalystStrategyFollowUpCandidateToOwnerApproval(
        candidateId: String,
        source: AuditEventSource = .system
    ) async throws -> PMApprovalRequest {
        let candidate = try await getAnalystStrategyFollowUpCandidate(id: candidateId)
        guard candidate.status.isActive else {
            throw AnalystStrategyFollowUpCandidateActionValidationError.candidateNotActive(id: candidateId)
        }
        guard candidate.followUpKind == .strategyBriefRevision else {
            throw AnalystStrategyFollowUpCandidateActionValidationError.routeRequiresStrategyBriefRevision(id: candidateId)
        }

        let existingRequests = try await listPMApprovalRequests()
        if let pending = existingRequests.first(where: {
            $0.requestType == .strategyChange
                && $0.status == .pending
                && $0.sourceAnalystStrategyFollowUpCandidateId == candidateId
        }) {
            return pending
        }

        let implication = try await getAnalystStrategyImplication(id: candidate.implicationId)
        let now = nowDate()
        let portfolioContext = await makeStrategyChangePortfolioContextSnapshot(now: now)
        let request = PMApprovalRequest(
            approvalRequestId: "pm-approval-\(UUID().uuidString.lowercased())",
            pmId: candidate.pmId,
            subject: "Review PM-proposed strategy change: \(candidate.candidateSummary)",
            rationale: implication.whyItMatters,
            requestedActionSummary: "Decide whether to approve this bounded change to the saved Portfolio Strategy Brief.",
            approvedNextStepSummary: "If approved, the app updates the saved Portfolio Strategy Brief through the explicit owner-approved strategy-change path. This does not approve trading, authorize execution, or change safety posture.",
            rejectedNextStepSummary: "If declined, the saved Portfolio Strategy Brief stays unchanged and this bounded strategy-change request closes without applying the proposed revision.",
            reviewedNextStepSummary: "If you ask for more work, the saved Portfolio Strategy Brief stays unchanged while the PM keeps the candidate open for bounded follow-up.",
            requestType: .strategyChange,
            status: .pending,
            delegationId: candidate.delegationId,
            findingId: candidate.findingId,
            sourceAnalystStrategyFollowUpCandidateId: candidate.candidateId,
            sourceAnalystStrategyImplicationId: implication.implicationId,
            sourceAnalystMemoId: candidate.memoId,
            sourceAnalystEvidenceBundleId: candidate.evidenceBundleId,
            strategyChangePortfolioContext: portfolioContext,
            createdAt: now,
            updatedAt: now
        )
        let stored = try await upsertPMApprovalRequest(request, source: source)
        await store.publishDiagnostic(
            "analyst strategy follow-up candidate routed for owner strategy approval id=\(shortOrderID(candidate.candidateId)) approval=\(shortOrderID(stored.approvalRequestId))",
            source: source,
            action: "analyst_strategy_follow_up_candidate_route_owner_approval"
        )
        return stored
    }

