    @discardableResult
    public func respondToPMApprovalRequest(
        requestId: String,
        response: PMApprovalRequestOwnerResponse,
        source: AuditEventSource = .system
    ) async throws -> PMApprovalRequest {
        var request = try await getPMApprovalRequest(id: requestId)
        let now = nowDate()

        if request.requestType == .strategyChange {
            guard let candidateId = request.sourceAnalystStrategyFollowUpCandidateId else {
                throw AnalystStrategyFollowUpCandidateActionValidationError.strategyChangeRequestMissingCandidateLink(
                    requestId: requestId
                )
            }

            switch response {
            case .approved:
                let appliedCandidate = try await applyAnalystStrategyFollowUpCandidateToStrategyBrief(
                    candidateId: candidateId,
                    updatedBy: ownerApprovedStrategyChangeUpdatedBy(for: request),
                    source: source
                )
                request.resultingStrategyBriefId = appliedCandidate.appliedStrategyBriefId
            case .rejected:
                _ = try await dismissAnalystStrategyFollowUpCandidate(
                    candidateId: candidateId,
                    source: source
                )
                request.resultingStrategyBriefId = nil
            case .reviewed:
                request.resultingStrategyBriefId = nil
            }
        }

        request.ownerResponse = response
        request.ownerRespondedAt = now
        request.status = .resolved
        request.updatedAt = now
        let stored = try await upsertPMApprovalRequest(request, source: source)

        guard response == .approved,
              shouldAttemptGovernedPMApprovalHandoff(for: stored) else {
            return stored
        }

        do {
            let assessment = try await routePMExecutionApprovedIntent(
                approvalRequestId: stored.approvalRequestId,
                source: source
            )
            await store.publishDiagnostic(
                "pm approval handoff routed approval_request=\(shortOrderID(stored.approvalRequestId)) status=\(assessment.status.rawValue) action=\(assessment.action.rawValue)",
                source: source,
                action: "pm_approval_request_handoff_routed",
                errorCode: assessment.blockedReasons.isEmpty ? nil : assessment.blockedReasons.map(\.rawValue).joined(separator: ",")
            )
            return (try? await getPMApprovalRequest(id: stored.approvalRequestId)) ?? stored
        } catch {
            let failedAssessment = PMExecutionRoutingAssessment(
                approvalRequestId: stored.approvalRequestId,
                decisionId: stored.decisionId,
                proposalId: stored.proposalId,
                proposalTitle: nil,
                proposalStatus: nil,
                environment: configuration.environment,
                isLiveArmed: isArmedForLiveTrading,
                killSwitchEnabled: killSwitchEnabled,
                status: .launchFailed,
                action: .none,
                summary: "The approved PM request could not be handed off to the governed routing path.",
                detail: error.localizedDescription,
                blockedReasons: []
            )
            _ = try? await persistPMExecutionRoutingAssessment(failedAssessment, source: source)
            await store.publishDiagnostic(
                "pm approval handoff failed approval_request=\(shortOrderID(stored.approvalRequestId)) reason=\(error.localizedDescription)",
                source: source,
                action: "pm_approval_request_handoff_failed",
                errorCode: "approval_handoff_failed"
            )
            return (try? await getPMApprovalRequest(id: stored.approvalRequestId)) ?? stored
        }
    }

    private func shouldAttemptGovernedPMApprovalHandoff(
        for request: PMApprovalRequest
    ) -> Bool {
        if request.requestType == .strategyChange {
            return false
        }
        if request.requestType == .liveOrderReview {
            return true
        }
        if request.requestType == .portfolioAction {
            return true
        }
        if trimmedOptionalDecisionText(request.proposalId) != nil {
            return true
        }
        return request.requestType == .proposalReview
    }

