    @discardableResult
    public func ensureInAppPMUserCommunicationSession(
        pmId: String? = nil,
        participantDisplayName: String = "Owner",
        source: AuditEventSource = .system
    ) async throws -> PMCommunicationSession {
        let resolvedPMID = try await resolvedConversationPMID(
            requestedPMID: pmId,
            source: source
        )
        let sessionID = "pm-user-in-app-\((resolvedPMID ?? "default").lowercased())"
        if let existing = try await pmCommunicationSessionStore.get(id: sessionID) {
            guard existing.status == .closed else {
                return existing
            }
            return try await upsertPMCommunicationSession(
                PMCommunicationSession(
                    sessionId: existing.sessionId,
                    channel: existing.channel,
                    externalConversationId: existing.externalConversationId,
                    pmId: existing.pmId,
                    participantId: existing.participantId,
                    participantDisplayName: existing.participantDisplayName ?? participantDisplayName,
                    status: .active,
                    createdAt: existing.createdAt,
                    updatedAt: nowDate()
                ),
                source: source
            )
        }

        let now = nowDate()
        let session = PMCommunicationSession(
            sessionId: sessionID,
            channel: .inApp,
            pmId: resolvedPMID,
            participantId: "owner",
            participantDisplayName: participantDisplayName,
            status: .active,
            createdAt: now,
            updatedAt: now
        )
        return try await upsertPMCommunicationSession(session, source: source)
    }

    @discardableResult
    public func createPMCommunicationMessage(
        sessionId: String,
        senderRole: PMCommunicationSenderRole,
        senderId: String? = nil,
        body: String,
        replyToMessageId: String? = nil,
        conversationResolution: PMConversationResolutionState? = nil,
        conversationActionPlan: PMConversationActionPlan? = nil,
        runtimeProvenance: PMRuntimeProvenance? = nil,
        telegramDelivery: TelegramPMDeliveryBehavior = .conversationReply,
        source: AuditEventSource = .system
    ) async throws -> PMCommunicationMessage {
        let now = nowDate()
        let session = try await getPMCommunicationSession(id: sessionId)
        _ = try await upsertPMCommunicationSession(
            PMCommunicationSession(
                sessionId: session.sessionId,
                channel: session.channel,
                externalConversationId: session.externalConversationId,
                pmId: session.pmId,
                participantId: session.participantId,
                participantDisplayName: session.participantDisplayName,
                status: session.status,
                createdAt: session.createdAt,
                updatedAt: now
            ),
            source: source
        )
        let direction: PMCommunicationMessageDirection = senderRole == .owner ? .incoming : .outgoing
        let message = PMCommunicationMessage(
            messageId: "pm-message-\(UUID().uuidString.lowercased())",
            sessionId: sessionId,
            direction: direction,
            senderRole: senderRole,
            senderId: senderId,
            body: body,
            sentAt: now,
            replyToMessageId: replyToMessageId,
            conversationResolution: conversationResolution,
            conversationActionPlan: conversationActionPlan,
            runtimeProvenance: runtimeProvenance,
            createdAt: now,
            updatedAt: now
        )
        let persisted = try await upsertPMCommunicationMessage(message, source: source)
        if direction == .outgoing,
           (session.channel == .telegram || session.channel == .mockTelegram),
           telegramDelivery.wakeUpClass != .doNotSendProactively {
            _ = try await sendTelegramMessageForPMCommunication(
                session: session,
                message: persisted,
                delivery: telegramDelivery,
                source: source
            )
        }
        return persisted
    }

    @discardableResult
    public func generatePMConversationReply(
        to ownerMessageId: String,
        source: AuditEventSource = .system
    ) async throws -> PMCommunicationMessage {
        guard let ownerMessage = try await pmCommunicationMessageStore.get(id: ownerMessageId) else {
            throw PMConversationReplyGenerationError.ownerMessageNotFound(id: ownerMessageId)
        }
        guard ownerMessage.senderRole == .owner else {
            throw PMConversationReplyGenerationError.messageMustBeOwnerAuthored(id: ownerMessageId)
        }

        let session = try await getPMCommunicationSession(id: ownerMessage.sessionId)
        guard session.status == .active else {
            throw PMConversationReplyGenerationError.conversationSessionClosed(id: session.sessionId)
        }

        let existingReply = try await listPMCommunicationMessages()
            .filter { $0.sessionId == session.sessionId }
            .contains(where: { $0.senderRole == .pm && $0.replyToMessageId == ownerMessageId })
        guard existingReply == false else {
            throw PMConversationReplyGenerationError.replyAlreadyExists(messageId: ownerMessageId)
        }

        do {
            let runtimeInvocation = try await invokePMConversationRuntime(
                ownerMessage: ownerMessage,
                session: session,
                source: source
            )
            let reply = try await createPMCommunicationMessage(
                sessionId: session.sessionId,
                senderRole: .pm,
                senderId: runtimeInvocation.responderPMID,
                body: runtimeInvocation.replyBody,
                replyToMessageId: ownerMessage.messageId,
                conversationResolution: runtimeInvocation.conversationResolution,
                conversationActionPlan: runtimeInvocation.conversationActionPlan,
                runtimeProvenance: runtimeInvocation.runtimeProvenance,
                source: source
            )
            for followThrough in runtimeInvocation.followThroughMessages
                where followThrough.body.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty == false {
                if let delegationId = followThrough.delegationDeliveryId {
                    let shouldDeliver = (try? await shouldDeliverPMDelegationFollowThrough(delegationId: delegationId)) ?? true
                    guard shouldDeliver else {
                        continue
                    }
                }
                if (session.channel == .telegram || session.channel == .mockTelegram),
                   followThrough.telegramDelivery.wakeUpClass == .doNotSendProactively {
                    await store.publishDiagnostic(
                        "pm conversation follow-through suppressed for telegram session=\(shortOrderID(session.sessionId)) owner_message=\(shortOrderID(ownerMessage.messageId)) reply=\(shortOrderID(reply.messageId))",
                        source: source,
                        action: "pm_conversation_telegram_follow_through_suppressed"
                    )
                    continue
                }
                do {
                    let delivered = try await createPMCommunicationMessage(
                        sessionId: session.sessionId,
                        senderRole: .pm,
                        senderId: runtimeInvocation.responderPMID,
                        body: followThrough.body,
                        replyToMessageId: reply.messageId,
                        telegramDelivery: followThrough.telegramDelivery,
                        source: source
                    )
                    if let delegationId = followThrough.delegationDeliveryId {
                        try await recordPMDelegationFollowThroughDelivery(
                            delegationId: delegationId,
                            deliveredMessage: delivered,
                            summary: followThrough.body,
                            source: source
                        )
                    }
                    await store.publishDiagnostic(
                        "pm conversation follow-through generated session=\(shortOrderID(session.sessionId)) owner_message=\(shortOrderID(ownerMessage.messageId)) reply=\(shortOrderID(reply.messageId))",
                        source: source,
                        action: "pm_conversation_follow_through_generated"
                    )
                } catch {
                    if let delegationId = followThrough.delegationDeliveryId {
                        try? await recordPMDelegationFollowThroughFailure(
                            delegationId: delegationId,
                            reason: error.localizedDescription,
                            source: source
                        )
                    }
                    await store.publishDiagnostic(
                        "pm conversation follow-through failed session=\(shortOrderID(session.sessionId)) owner_message=\(shortOrderID(ownerMessage.messageId)) reason=\(error.localizedDescription)",
                        source: source,
                        action: "pm_conversation_follow_through_failed"
                    )
                }
            }
            await store.publishDiagnostic(
                "pm conversation reply generated session=\(shortOrderID(session.sessionId)) owner_message=\(shortOrderID(ownerMessage.messageId)) channel=\(session.channel.rawValue)",
                source: source,
                action: "pm_conversation_reply_generated"
            )
            return reply
        } catch {
            let failureBody = makePMConversationReplyFailureNoteBody(
                error: error,
                session: session
            )
            _ = try? await recordLocalPMCommunicationSystemNote(
                sessionId: session.sessionId,
                body: failureBody,
                replyToMessageId: ownerMessage.messageId,
                source: source
            )
            throw error
        }
    }

    private func preferredPMCommunicationResponderID(
        for session: PMCommunicationSession,
        source: AuditEventSource
    ) async throws -> String? {
        let trimmedSessionPMID = session.pmId?.trimmingCharacters(in: .whitespacesAndNewlines)
        if let trimmedSessionPMID,
           trimmedSessionPMID.isEmpty == false,
           isOperationalExercisePMID(trimmedSessionPMID) == false {
            return trimmedSessionPMID
        }
        return try await ensurePrimaryPMProfile(source: source).pmId
    }

    private struct PMConversationRuntimeInvocation {
        let responderPMID: String?
        let runtimeSelection: ResolvedRuntimeSelection
        let replyBody: String
        let conversationResolution: PMConversationResolutionState?
        let conversationActionPlan: PMConversationActionPlan?
        let followThroughMessages: [PMConversationRuntimeFollowThrough]
        let runtimeProvenance: PMRuntimeProvenance?
    }

    private struct PMConversationRuntimeFollowThrough: Sendable, Equatable {
        let body: String
        let telegramDelivery: TelegramPMDeliveryBehavior
        let delegationDeliveryId: String?
    }

    private let pmConversationPlannerMode = "owner_conversation_action_planning"

    private enum PMConversationOpenLoopKind: Sendable, Equatable {
        case yesNoConfirmation
        case clarification
    }

    private struct PMConversationOpenLoop: Sendable, Equatable {
        let sourceMessageId: String
        let kind: PMConversationOpenLoopKind
        let promptSummary: String
        let fullText: String
        let pendingAskState: PMConversationPendingAskState?
    }

    private func invokePMConversationRuntime(
        ownerMessage: PMCommunicationMessage,
        session: PMCommunicationSession,
        source: AuditEventSource
    ) async throws -> PMConversationRuntimeInvocation {
        let now = nowDate()
        let responderPMID = try await preferredPMCommunicationResponderID(
            for: session,
            source: source
        )
        let (_, runtimeSelection) = try await resolvedPMRuntimeSettingsForExecution(now: now)
        let contextPack = try await assemblePMContextPack(pmId: responderPMID)
        let allSessions = try await listPMCommunicationSessions()
        let allMessages = try await listPMCommunicationMessages()
            .sorted { lhs, rhs in
                pmCommunicationMessage(lhs, occurredBefore: rhs)
            }
        let sessionMessages = pmConversationContinuityMessages(
            for: session,
            allSessions: allSessions,
            allMessages: allMessages
        )
        let recentOpenLoop = latestPMConversationOpenLoop(
            before: ownerMessage,
            sessionMessages: sessionMessages
        )
        let synthesized = try await synthesizePMConversationReplyIfPossible(
            ownerMessage: ownerMessage,
            session: session,
            contextPack: contextPack,
            runtimeSelection: runtimeSelection,
            allMessages: allMessages,
            sessionMessages: sessionMessages,
            recentOpenLoop: recentOpenLoop
        )
        let resolvedActionPlanResult: PMConversationResolvedActionPlanResult
        let conversationResolution: PMConversationResolutionState?
        let appliedActionResult: PMConversationActionApplicationResult
        if synthesized.usedModelBackedInterpretation {
            let resolvedActionPlan = resolvedPMConversationActionPlan(
                synthesized.conversationActionPlan,
                ownerMessage: ownerMessage,
                recentOpenLoop: recentOpenLoop,
                conversationResolution: synthesized.conversationResolution,
                replyBody: synthesized.replyBody
            )
            let enrichedResolution = enrichedPMConversationResolutionState(
                synthesized.conversationResolution,
                actionPlan: resolvedActionPlan.actionPlan,
                ownerMessage: ownerMessage,
                recentOpenLoop: recentOpenLoop
            )
            let appliedResolution = try await applyPMConversationResolutionIfNeeded(
                normalizedPMConversationResolutionState(
                    enrichedResolution,
                    ownerMessage: ownerMessage,
                    recentOpenLoop: recentOpenLoop
                ),
                ownerMessage: ownerMessage,
                session: session,
                responderPMID: responderPMID,
                source: source
            )
            resolvedActionPlanResult = resolvedActionPlan
            conversationResolution = appliedResolution
            appliedActionResult = try await applyPMConversationActionPlanIfNeeded(
                resolvedActionPlan.actionPlan,
                ownerMessage: ownerMessage,
                session: session,
                responderPMID: responderPMID,
                appliedResolution: appliedResolution,
                runtimeProvenance: synthesized.runtimeProvenance,
                source: source
            )
        } else {
            resolvedActionPlanResult = PMConversationResolvedActionPlanResult(
                actionPlan: nil,
                source: nil
            )
            conversationResolution = nil
            appliedActionResult = PMConversationActionApplicationResult(
                actionPlan: nil,
                context: PMConversationAppliedActionContext()
            )
        }
        await store.publishDiagnostic(
            "pm conversation runtime invoked session=\(shortOrderID(session.sessionId)) effective_runtime=\(runtimeSelection.effectiveRuntimeIdentifier) fallback=\(runtimeSelection.fallbackApplied)",
            source: source,
            action: "pm_conversation_runtime_invoke"
        )
        var runtimeProvenance = synthesized.runtimeProvenance
        if runtimeProvenance.conversationTrace != nil {
            runtimeProvenance.conversationTrace?.actionPlanSource = resolvedActionPlanResult.source
        }
        let commitmentConsistency = pmConversationWorkCommitmentConsistency(
            replyBody: synthesized.replyBody,
            actionPlan: appliedActionResult.actionPlan,
            appliedContext: appliedActionResult.context,
            latestOwnerAsk: ownerMessage.body,
            hasPriorLiveOrderReviewRouteTruth: pmConversationHasPriorLiveOrderReviewRouteTruth(
                approvalRequests: (try? await listPMApprovalRequests()) ?? [],
                latestOwnerAsk: ownerMessage.body
            )
        )
        if commitmentConsistency.visibleReplyModified,
           runtimeProvenance.conversationTrace != nil {
            runtimeProvenance.conversationTrace?.visibleReplyModifiedAfterSynthesis = true
        }
        let analystDelegationBlockers = commitmentConsistency.suppressAnalystDelegationBlockerFollowThrough
            ? []
            : appliedActionResult.context.analystDelegationBlockers
        var analystFollowThroughMessages: [PMConversationRuntimeFollowThrough] = []
        for followThrough in appliedActionResult.context.analystFollowThroughs {
            guard let body = await makePMConversationAnalystFollowThroughBody(
                followThrough,
                session: session,
                runtimeSelection: runtimeSelection,
                source: source
            ) else {
                continue
            }
            analystFollowThroughMessages.append(
                PMConversationRuntimeFollowThrough(
                    body: body,
                    telegramDelivery: .importantWakeUp(reason: "PM-requested analyst work completed."),
                    delegationDeliveryId: followThrough.delegationId
                )
            )
        }
        let analystBlockerMessages = analystDelegationBlockers.map {
            PMConversationRuntimeFollowThrough(
                body: "I could not launch that analyst task: \($0)",
                telegramDelivery: .importantWakeUp(reason: "PM-requested analyst work is blocked."),
                delegationDeliveryId: nil
            )
        }
        let governedWorkflowMessages = [makePMConversationGovernedWorkflowFollowThroughBody(appliedActionResult.context)]
            .compactMap { body -> PMConversationRuntimeFollowThrough? in
                guard let body else { return nil }
                return PMConversationRuntimeFollowThrough(
                    body: body,
                    telegramDelivery: .doNotSendProactively(reason: "Governed workflow follow-through remains app-local."),
                    delegationDeliveryId: nil
                )
            }
        return PMConversationRuntimeInvocation(
            responderPMID: responderPMID,
            runtimeSelection: runtimeSelection,
            replyBody: commitmentConsistency.replyBody,
            conversationResolution: conversationResolution,
            conversationActionPlan: commitmentConsistency.actionPlan,
            followThroughMessages: analystFollowThroughMessages + analystBlockerMessages + governedWorkflowMessages,
            runtimeProvenance: runtimeProvenance
        )
    }

    private func pmConversationContinuityMessages(
        for session: PMCommunicationSession,
        allSessions: [PMCommunicationSession],
        allMessages: [PMCommunicationMessage]
    ) -> [PMCommunicationMessage] {
        guard pmConversationChannelCarriesOwnerContinuity(session.channel) else {
            return allMessages.filter { $0.sessionId == session.sessionId }
        }

        let continuitySessionIDs = Set(
            allSessions
                .filter { candidate in
                    pmConversationSessionsShareOwnerContinuity(candidate, session)
                }
                .map(\.sessionId)
        )
        return allMessages.filter { continuitySessionIDs.contains($0.sessionId) }
    }

    private func pmConversationChannelCarriesOwnerContinuity(
        _ channel: PMCommunicationChannel
    ) -> Bool {
        switch channel {
        case .inApp, .telegram, .mockTelegram:
            return true
        case .genericRemote:
            return false
        }
    }

    private func pmConversationSessionsShareOwnerContinuity(
        _ lhs: PMCommunicationSession,
        _ rhs: PMCommunicationSession
    ) -> Bool {
        guard pmConversationChannelCarriesOwnerContinuity(lhs.channel),
              pmConversationChannelCarriesOwnerContinuity(rhs.channel) else {
            return false
        }

        let lhsPMID = lhs.pmId?.trimmingCharacters(in: .whitespacesAndNewlines)
        let rhsPMID = rhs.pmId?.trimmingCharacters(in: .whitespacesAndNewlines)
        if let lhsPMID,
           let rhsPMID,
           lhsPMID.isEmpty == false,
           rhsPMID.isEmpty == false,
           lhsPMID != rhsPMID {
            return false
        }

        return true
    }

    private struct PMConversationSynthesisResult: Sendable {
        let replyBody: String
        let conversationActionPlan: PMConversationActionPlan?
        let conversationResolution: PMConversationResolutionState?
        let runtimeProvenance: PMRuntimeProvenance
        let usedModelBackedInterpretation: Bool
    }

    private struct PMConversationResolvedActionPlanResult: Sendable {
        let actionPlan: PMConversationActionPlan?
        let source: PMConversationActionPlanSource?
    }

    private struct PMConversationFallbackReplyResult: Sendable {
        let body: String
        let trace: PMConversationTrace
    }

    private enum PMConversationSynthesisRequestProfile: String, Sendable {
        case balanced
        case compact
        case minimal
    }

    private struct PMConversationSynthesisAttempt: Sendable {
        let request: PMConversationOpenAISynthesisRequest
        let profile: PMConversationSynthesisRequestProfile
        let promptCharacterCount: Int
        let promptBudgetTrace: PMConversationPromptBudgetTrace
    }

    private func synthesizePMConversationModelReply(
        request: PMConversationOpenAISynthesisRequest,
        apiKey: String,
        runtimeSelection: ResolvedRuntimeSelection
    ) async throws -> PMConversationOpenAISynthesisOutput {
        switch runtimeSelection.effectiveProviderKind {
        case .openAI:
            return try await pmOpenAISynthesisProvider.synthesizeConversationReply(
                request: request,
                apiKey: apiKey
            )
        case .anthropic:
            return try await pmAnthropicSynthesisProvider.synthesizeConversationReply(
                request: request,
                apiKey: apiKey
            )
        }
    }

    private func pmConversationActualRuntimeIdentifier(
        runtimeSelection: ResolvedRuntimeSelection
    ) -> String {
        switch runtimeSelection.effectiveProviderKind {
        case .openAI:
            return "openai_responses[\(runtimeSelection.effectiveRuntimeIdentifier)]"
        case .anthropic:
            return "anthropic_messages[\(runtimeSelection.effectiveRuntimeIdentifier)]"
        }
    }

    private func pmConversationSynthesisStatus(
        runtimeSelection: ResolvedRuntimeSelection
    ) -> String {
        switch runtimeSelection.effectiveProviderKind {
        case .openAI:
            return "openai_responses"
        case .anthropic:
            return "anthropic_messages"
        }
    }

    private func pmConversationProviderErrorStatus(
        runtimeSelection: ResolvedRuntimeSelection
    ) -> String {
        "fallback_\(runtimeSelection.effectiveProviderKind.rawValue)_error"
    }

    private func pmConversationUnexpectedErrorSummary(
        runtimeSelection: ResolvedRuntimeSelection
    ) -> String {
        "\(runtimeSelection.effectiveProviderKind.rawValue)_unexpected_error"
    }

    private func synthesizePMConversationReplyIfPossible(
        ownerMessage: PMCommunicationMessage,
        session: PMCommunicationSession,
        contextPack: PMContextPack,
        runtimeSelection: ResolvedRuntimeSelection,
        allMessages: [PMCommunicationMessage],
        sessionMessages: [PMCommunicationMessage],
        recentOpenLoop: PMConversationOpenLoop?
    ) async throws -> PMConversationSynthesisResult {
        let launchedAt = nowDate()
        let credentialResolution = llmCredentialResolution(
            providerKind: runtimeSelection.effectiveProviderKind,
            credentialProfileId: runtimeSelection.effectiveCredentialProfileId
        )
        guard let apiKey = credentialResolution.apiKey else {
            let fallbackReply = makeFallbackPMConversationReply(
                runtimeSelection: runtimeSelection,
                degradedReason: credentialResolution.fallbackStatus,
                issueSummary: credentialResolution.synthesisIssueSummary,
                modelSynthesisAttempted: false,
                modelAttemptCount: 0,
                requestCharacterCount: nil,
                requestCompactionLevel: nil,
                promptBudgetTrace: nil,
                providerReturnedContent: false,
                providerResponseAccepted: false,
                providerResponseIssueSummary: credentialResolution.synthesisIssueSummary
            )
            return PMConversationSynthesisResult(
                replyBody: fallbackReply.body,
                conversationActionPlan: nil,
                conversationResolution: nil,
                runtimeProvenance: pmFallbackRuntimeProvenance(
                    runtimeSelection: runtimeSelection,
                    status: credentialResolution.fallbackStatus,
                    issueSummary: credentialResolution.synthesisIssueSummary,
                    launchedAt: launchedAt,
                    conversationTrace: fallbackReply.trace
                ),
                usedModelBackedInterpretation: false
            )
        }

        let strategyBrief = try await getPortfolioStrategyBrief()
        let analystCharters = try await listAnalystCharters()
        let approvalRequests = try await listPMApprovalRequests()
        let proposals = try await listProposals()
        let standingReports = try await listAnalystStandingReports()
        let pmDecisions = try await listPMDecisions()
        let needsAnalystFullDetailGrounding = pmConversationMayNeedAnalystFullDetailGrounding(ownerMessage.body)
        let analystMemos = try await listAnalystMemos()
        let analystEvidenceBundles = try await listAnalystEvidenceBundles()
        let promptBudgetPolicy = PMConversationPromptBudgetPolicy.recommended(
            runtimeIdentifier: runtimeSelection.effectiveRuntimeIdentifier,
            reasoningMode: runtimeSelection.effectiveReasoningMode
        )
        let liveExecutionProtectionSettings = await getLiveExecutionProtectionSettings()
        let agentSkillLibraryIndexSummary = await pmConversationAgentSkillLibraryIndexSummaryIfNeeded(ownerMessage.body)
        let signalTruthSummary = await pmConversationSignalTruthSummaryIfNeeded(ownerMessage.body)
        let confirmedAppTruthSummary = agentSkillLibraryIndexSummary + signalTruthSummary + pmConversationConfirmedAppTruthSummary(
            contextPack,
            approvalRequests: approvalRequests,
            latestOwnerAsk: ownerMessage.body,
            liveExecutionProtectionSettings: liveExecutionProtectionSettings
        )
        let detailedCommunicationHistorySummary = pmConversationDetailedCommunicationHistorySummary(
            ask: ownerMessage.body,
            latestOwnerMessage: ownerMessage,
            session: session,
            allMessages: allMessages,
            sessionMessages: sessionMessages
        )
        let exactSpecificEntryRequested = detailedCommunicationHistorySummary.contains(where: {
            $0.hasPrefix("Specific communication entry body window: ")
        })
        let normalizedOwnerAskForHistorySuppression = ownerMessage.body
            .lowercased()
            .replacingOccurrences(of: "[^a-z0-9]+", with: " ", options: .regularExpression)
            .trimmingCharacters(in: .whitespacesAndNewlines)
        let suppressHistoryForAnalystFullDetail = pmConversationShouldSuppressStaleHistoryForAnalystReportReading(
            normalizedAsk: normalizedOwnerAskForHistorySuppression,
            needsAnalystFullDetailGrounding: needsAnalystFullDetailGrounding,
            exactSpecificEntryRequested: exactSpecificEntryRequested
        )
        let suppressMixedHistoryContext = true
        let usesTargetedHistoryGrounding = detailedCommunicationHistorySummary.isEmpty == false
        let recentConversationSummary = pmConversationRecentHistorySummary(
            sessionMessages: sessionMessages,
            latestOwnerMessage: ownerMessage,
            recentOpenLoop: recentOpenLoop,
            suppressSyntheticRecaps: suppressMixedHistoryContext
        )
        let latestOwnerWorkingPortfolioUpdateSummary: [String] = []
        let suppressOlderPortfolioRecovery = exactSpecificEntryRequested
        let proposedTruthUpdateSummary = suppressOlderPortfolioRecovery ? [] : pmConversationProposedTruthUpdateSummary(
            latestOwnerMessage: ownerMessage,
            sessionMessages: sessionMessages,
            contextPack: contextPack
        )
        let analystArtifactSummary = pmConversationRelevantAnalystArtifactSummary(
            ask: ownerMessage.body,
            latestOwnerMessage: ownerMessage,
            allMessages: allMessages,
            contextPack: contextPack,
            standingReports: standingReports,
            pmDecisions: pmDecisions,
            analystMemos: analystMemos,
            analystEvidenceBundles: analystEvidenceBundles
        )
        let usesTargetedAnalystGrounding = analystArtifactSummary.isEmpty == false
        let needsStandingCandidateContext = pmConversationNeedsStandingCandidateContext(ownerMessage.body)
        let standingCandidateSummary = (usesTargetedAnalystGrounding && needsStandingCandidateContext == false)
            ? []
            : (
                needsStandingCandidateContext
                    ? pmConversationStandingCandidateSummary(contextPack)
                    : []
            )
        let conversationFragmentSummary = exactSpecificEntryRequested
            ? []
            : pmConversationConversationFragmentSummary(
                session: session,
                contextPack: contextPack
            )
        let activeConversationStateSummary = pmConversationActiveStateSummary(
            latestOwnerMessage: ownerMessage,
            recentOpenLoop: recentOpenLoop
        )
        let keepRecoveredContextAlongsideDetailedHistory = pmConversationNeedsComplementaryRecoveredContext(
            ownerMessage.body
        )
        let needsStandingReviewRecoveredContext = pmConversationNeedsStandingReviewRecovery(
            normalizedOwnerAskForHistorySuppression
        )
        let recoveredContextSummary = (exactSpecificEntryRequested && needsStandingReviewRecoveredContext == false)
            || (usesTargetedHistoryGrounding
                && keepRecoveredContextAlongsideDetailedHistory == false
                && needsStandingReviewRecoveredContext == false)
            ? []
            : pmConversationRecoveredContextSummary(
            ask: ownerMessage.body,
            session: session,
            sessionMessages: sessionMessages,
            contextPack: contextPack,
            standingReports: standingReports,
            pmDecisions: pmDecisions
        )
        let workingPortfolioDefinitionSummary = suppressOlderPortfolioRecovery ? [] : pmConversationWorkingPortfolioDefinitionSummary(
            latestOwnerMessage: ownerMessage,
            allMessages: allMessages,
            contextPack: contextPack
        )
        let operatingContextSummary = pmConversationOperatingContextSummary(
            contextPack,
            analystCharters: analystCharters,
            approvalRequests: approvalRequests,
            proposals: proposals,
            detailLevel: pmConversationNeedsExpandedOperatingContext(ownerMessage.body) ? .expanded : .essential
        )
        let needsExpandedOperatingContext = pmConversationNeedsExpandedOperatingContext(ownerMessage.body)
        let analystCharterDocumentSummary = pmConversationRelevantAnalystCharterDocumentSummary(
            ask: ownerMessage.body,
            analystCharters: analystCharters
        )

        func limited(_ values: [String], limit: Int?) -> [String] {
            limit.map { Array(values.prefix($0)) } ?? values
        }

        func limitedRecentConversation(_ values: [String], limit: Int?) -> [String] {
            guard let limit else { return values }
            guard values.count > limit else { return values }
            return Array(values.suffix(limit))
        }

        func makeAttempt(profile: PMConversationSynthesisRequestProfile) -> PMConversationSynthesisAttempt {
            let suppressRecoveredContextForAnalystFullDetail = suppressHistoryForAnalystFullDetail
                && needsStandingReviewRecoveredContext == false
            let recentConversationLimit: Int?
            let confirmedTruthLimit: Int?
            let latestOwnerWorkingPortfolioLimit: Int?
            let workingPortfolioLimit: Int?
            let proposedTruthLimit: Int?
            let standingCandidateLimit: Int?
            let analystArtifactLimit: Int?
            let conversationFragmentLimit: Int?
            let detailedHistoryLimit: Int?
            let activeConversationLimit: Int?
            let recoveredContextLimit: Int?
            let analystCharterDocumentLimit: Int?
            let operatingContextLimit: Int?
            switch profile {
            case .balanced:
                recentConversationLimit = suppressHistoryForAnalystFullDetail ? 1 : (usesTargetedHistoryGrounding ? 12 : 24)
                confirmedTruthLimit = 18
                latestOwnerWorkingPortfolioLimit = 2
                workingPortfolioLimit = 2
                proposedTruthLimit = 2
                standingCandidateLimit = 2
                analystArtifactLimit = usesTargetedAnalystGrounding ? 28 : 4
                conversationFragmentLimit = suppressHistoryForAnalystFullDetail || conversationFragmentSummary.isEmpty ? 0 : 1
                detailedHistoryLimit = suppressHistoryForAnalystFullDetail ? 0 : 3
                activeConversationLimit = 3
                recoveredContextLimit = suppressRecoveredContextForAnalystFullDetail || recoveredContextSummary.isEmpty ? 0 : 2
                analystCharterDocumentLimit = analystCharterDocumentSummary.isEmpty ? 0 : 2
                operatingContextLimit = needsExpandedOperatingContext ? 12 : 6
            case .compact:
                recentConversationLimit = suppressHistoryForAnalystFullDetail ? 1 : (usesTargetedHistoryGrounding ? 8 : 14)
                confirmedTruthLimit = 16
                latestOwnerWorkingPortfolioLimit = 2
                workingPortfolioLimit = 1
                proposedTruthLimit = 1
                standingCandidateLimit = 1
                analystArtifactLimit = usesTargetedAnalystGrounding ? 28 : 4
                conversationFragmentLimit = suppressHistoryForAnalystFullDetail || conversationFragmentSummary.isEmpty ? 0 : 1
                detailedHistoryLimit = suppressHistoryForAnalystFullDetail ? 0 : 2
                activeConversationLimit = 2
                recoveredContextLimit = suppressRecoveredContextForAnalystFullDetail || recoveredContextSummary.isEmpty ? 0 : 1
                analystCharterDocumentLimit = analystCharterDocumentSummary.isEmpty ? 0 : 1
                operatingContextLimit = needsExpandedOperatingContext ? 10 : 4
            case .minimal:
                recentConversationLimit = suppressHistoryForAnalystFullDetail ? 1 : (usesTargetedHistoryGrounding ? 6 : 8)
                confirmedTruthLimit = 12
                latestOwnerWorkingPortfolioLimit = 1
                workingPortfolioLimit = 1
                proposedTruthLimit = 0
                standingCandidateLimit = 0
                analystArtifactLimit = usesTargetedAnalystGrounding ? 28 : 4
                conversationFragmentLimit = suppressHistoryForAnalystFullDetail || conversationFragmentSummary.isEmpty ? 0 : 1
                detailedHistoryLimit = suppressHistoryForAnalystFullDetail ? 0 : 1
                activeConversationLimit = 1
                recoveredContextLimit = needsStandingReviewRecoveredContext && recoveredContextSummary.isEmpty == false ? 1 : 0
                analystCharterDocumentLimit = analystCharterDocumentSummary.isEmpty ? 0 : 1
                operatingContextLimit = needsExpandedOperatingContext ? 4 : 0
            }

            let request = PMConversationOpenAISynthesisRequest(
                runtimeIdentifier: runtimeSelection.effectiveRuntimeIdentifier,
                reasoningMode: runtimeSelection.effectiveReasoningMode,
                plannerMode: pmConversationPlannerMode,
                sessionChannel: session.channel.rawValue,
                ownerMessageBody: ownerMessage.body,
                strategyObjective: emptyToNil(strategyBrief.objectiveSummary),
                strategyThemes: strategyBrief.keyThemes,
                currentRiskPosture: emptyToNil(strategyBrief.currentRiskPosture),
                reviewEscalationPosture: emptyToNil(strategyBrief.reviewEscalationPosture),
                recentConversationSummary: limitedRecentConversation(recentConversationSummary, limit: recentConversationLimit),
                confirmedAppTruthSummary: limited(confirmedAppTruthSummary, limit: confirmedTruthLimit),
                latestOwnerWorkingPortfolioUpdateSummary: limited(latestOwnerWorkingPortfolioUpdateSummary, limit: latestOwnerWorkingPortfolioLimit),
                workingPortfolioDefinitionSummary: limited(workingPortfolioDefinitionSummary, limit: workingPortfolioLimit),
                proposedTruthUpdateSummary: proposedTruthLimit == 0 ? [] : limited(proposedTruthUpdateSummary, limit: proposedTruthLimit),
                standingCandidateSummary: standingCandidateLimit == 0 ? [] : limited(standingCandidateSummary, limit: standingCandidateLimit),
                analystArtifactSummary: analystArtifactLimit == 0 ? [] : limited(analystArtifactSummary, limit: analystArtifactLimit),
                conversationFragmentSummary: conversationFragmentLimit == 0 ? [] : limited(conversationFragmentSummary, limit: conversationFragmentLimit),
                detailedCommunicationHistorySummary: detailedHistoryLimit == 0 ? [] : limited(detailedCommunicationHistorySummary, limit: detailedHistoryLimit),
                activeConversationStateSummary: limited(activeConversationStateSummary, limit: activeConversationLimit),
                recoveredContextSummary: recoveredContextLimit == 0 ? [] : limited(recoveredContextSummary, limit: recoveredContextLimit),
                analystCharterDocumentSummary: analystCharterDocumentLimit == 0 ? [] : limited(analystCharterDocumentSummary, limit: analystCharterDocumentLimit),
                operatingContextSummary: operatingContextLimit == 0 ? [] : limited(operatingContextSummary, limit: operatingContextLimit)
            )
            let promptBudgetTrace = pmConversationPromptBudgetTrace(
                for: request,
                policy: promptBudgetPolicy
            )
            return PMConversationSynthesisAttempt(
                request: request,
                profile: profile,
                promptCharacterCount: promptBudgetTrace.totalPromptCharacterCount,
                promptBudgetTrace: promptBudgetTrace
            )
        }

        let balancedAttempt = makeAttempt(profile: .balanced)
        let compactAttempt = makeAttempt(profile: .compact)
        let minimalAttempt = makeAttempt(profile: .minimal)
        let promptProfileTraces = [balancedAttempt, compactAttempt, minimalAttempt].map { attempt in
            PMConversationPromptProfileTrace(
                profile: attempt.profile.rawValue,
                totalPromptCharacterCount: attempt.promptCharacterCount,
                fitsPromptBudget: attempt.promptCharacterCount <= promptBudgetPolicy.promptCharacterBudget,
                lanes: attempt.promptBudgetTrace.lanes
            )
        }
        let initialAttempt: PMConversationSynthesisAttempt
        if balancedAttempt.promptCharacterCount <= promptBudgetPolicy.promptCharacterBudget {
            initialAttempt = balancedAttempt
        } else if compactAttempt.promptCharacterCount <= promptBudgetPolicy.promptCharacterBudget {
            initialAttempt = compactAttempt
        } else {
            initialAttempt = minimalAttempt
        }

        var attemptCount = 0
        var finalAttempt = initialAttempt

        func successfulConversationTrace(
            attempt: PMConversationSynthesisAttempt,
            attemptCount: Int
        ) -> PMConversationTrace {
            PMConversationTrace(
                pathKind: .modelBacked,
                visibleReplySource: .modelReply,
                structuredOutputSchemaName: "pm_conversation_reply",
                structuredOutputSchemaLocallyValidated: true,
                usedLatestOwnerWorkingPortfolioGrounding: latestOwnerWorkingPortfolioUpdateSummary.isEmpty == false,
                usedWorkingPortfolioHistoryGrounding: workingPortfolioDefinitionSummary.isEmpty == false
                    || proposedTruthUpdateSummary.isEmpty == false,
                usedAnalystArtifactGrounding: analystArtifactSummary.isEmpty == false
                    || standingCandidateSummary.isEmpty == false,
                usedDetailedHistoryGrounding: attempt.request.detailedCommunicationHistorySummary.isEmpty == false,
                usedRecoveredContextGrounding: attempt.request.recoveredContextSummary.isEmpty == false
                    || attempt.request.conversationFragmentSummary.isEmpty == false,
                suppressedSyntheticHistoryRecaps: suppressMixedHistoryContext,
                modelSynthesisAttempted: true,
                modelProducedUsableReply: true,
                visibleReplyModifiedAfterSynthesis: false,
                modelAttemptCount: attemptCount,
                requestCharacterCount: attempt.promptCharacterCount,
                requestCompactionLevel: attempt.profile.rawValue,
                promptBudgetTrace: attempt.promptBudgetTrace,
                promptProfileTraces: promptProfileTraces,
                providerReturnedContent: true,
                providerResponseAccepted: true
            )
        }

        do {
            attemptCount += 1
            let output = try await synthesizePMConversationModelReply(
                request: initialAttempt.request,
                apiKey: apiKey,
                runtimeSelection: runtimeSelection
            )
            let traceAttempt = initialAttempt
            finalAttempt = initialAttempt

            let executionStatus = pmExecutionStatusRecord(
                category: .accepted,
                summary: "Latest PM conversation execution succeeded via live model-backed synthesis using \(runtimeSelection.effectiveRuntimeIdentifier).",
                checkedBy: "pm conversation execution",
                now: launchedAt
            )
            try await recordPMConversationExecutionStatus(
                executionStatus,
                runtimeSelection: runtimeSelection,
                now: launchedAt
            )

            return PMConversationSynthesisResult(
                replyBody: output.replyBody,
                conversationActionPlan: output.actionPlan,
                conversationResolution: normalizedPMConversationResolutionState(
                    output.resolution,
                    ownerMessage: ownerMessage,
                    recentOpenLoop: recentOpenLoop
                ),
                runtimeProvenance: PMRuntimeProvenance(
                    configuredProviderKind: runtimeSelection.configuredProviderKind,
                    configuredCredentialProfileId: runtimeSelection.configuredCredentialProfileId,
                    configuredRuntimeIdentifier: runtimeSelection.configuredRuntimeIdentifier,
                    configuredReasoningMode: runtimeSelection.configuredReasoningMode,
                    actualProviderKind: runtimeSelection.effectiveProviderKind,
                    actualCredentialProfileId: runtimeSelection.effectiveCredentialProfileId,
                    actualRuntimeIdentifier: pmConversationActualRuntimeIdentifier(runtimeSelection: runtimeSelection),
                    actualReasoningMode: runtimeSelection.effectiveReasoningMode,
                    usedOpenAI: runtimeSelection.effectiveProviderKind == .openAI,
                    synthesisStatus: pmConversationSynthesisStatus(runtimeSelection: runtimeSelection),
                    launchedAt: launchedAt,
                    conversationTrace: successfulConversationTrace(
                        attempt: traceAttempt,
                        attemptCount: attemptCount
                    )
                ),
                usedModelBackedInterpretation: true
            )
        } catch let error as PMOpenAISynthesisError {
            let retryAttempt: PMConversationSynthesisAttempt?
            if error.retryableAfterContextCompaction {
                switch initialAttempt.profile {
                case .balanced:
                    retryAttempt = compactAttempt
                case .compact:
                    retryAttempt = minimalAttempt
                case .minimal:
                    retryAttempt = nil
                }
            } else {
                retryAttempt = nil
            }
            if let retryAttempt {
                do {
                    attemptCount += 1
                    finalAttempt = retryAttempt
                    let output = try await synthesizePMConversationModelReply(
                        request: retryAttempt.request,
                        apiKey: apiKey,
                        runtimeSelection: runtimeSelection
                    )
                    let executionStatus = pmExecutionStatusRecord(
                        category: .accepted,
                        summary: "Latest PM conversation execution succeeded via live model-backed synthesis using \(runtimeSelection.effectiveRuntimeIdentifier) after bounded request compaction.",
                        checkedBy: "pm conversation execution",
                        now: launchedAt
                    )
                    try await recordPMConversationExecutionStatus(
                        executionStatus,
                        runtimeSelection: runtimeSelection,
                        now: launchedAt
                    )
                    return PMConversationSynthesisResult(
                        replyBody: output.replyBody,
                        conversationActionPlan: output.actionPlan,
                        conversationResolution: normalizedPMConversationResolutionState(
                            output.resolution,
                            ownerMessage: ownerMessage,
                            recentOpenLoop: recentOpenLoop
                        ),
                        runtimeProvenance: PMRuntimeProvenance(
                            configuredProviderKind: runtimeSelection.configuredProviderKind,
                            configuredCredentialProfileId: runtimeSelection.configuredCredentialProfileId,
                            configuredRuntimeIdentifier: runtimeSelection.configuredRuntimeIdentifier,
                            configuredReasoningMode: runtimeSelection.configuredReasoningMode,
                            actualProviderKind: runtimeSelection.effectiveProviderKind,
                            actualCredentialProfileId: runtimeSelection.effectiveCredentialProfileId,
                            actualRuntimeIdentifier: pmConversationActualRuntimeIdentifier(runtimeSelection: runtimeSelection),
                            actualReasoningMode: runtimeSelection.effectiveReasoningMode,
                            usedOpenAI: runtimeSelection.effectiveProviderKind == .openAI,
                            synthesisStatus: pmConversationSynthesisStatus(runtimeSelection: runtimeSelection),
                            launchedAt: launchedAt,
                            conversationTrace: successfulConversationTrace(
                                attempt: retryAttempt,
                                attemptCount: attemptCount
                            )
                        ),
                        usedModelBackedInterpretation: true
                    )
                } catch let retryError as PMOpenAISynthesisError {
                    let executionStatus = pmExecutionStatusRecord(
                        for: retryError,
                        runtimeSelection: runtimeSelection,
                        checkedBy: "pm conversation execution",
                        now: launchedAt
                    )
                    try? await recordPMConversationExecutionStatus(
                        executionStatus,
                        runtimeSelection: runtimeSelection,
                        now: launchedAt
                    )
                    let fallbackReply = makeFallbackPMConversationReply(
                        runtimeSelection: runtimeSelection,
                        degradedReason: pmConversationProviderErrorStatus(runtimeSelection: runtimeSelection),
                        issueSummary: retryError.boundedSummary,
                        modelSynthesisAttempted: true,
                        modelAttemptCount: attemptCount,
                        requestCharacterCount: retryAttempt.promptCharacterCount,
                        requestCompactionLevel: retryAttempt.profile.rawValue,
                        promptBudgetTrace: retryAttempt.promptBudgetTrace,
                        promptProfileTraces: promptProfileTraces,
                        providerReturnedContent: retryError.providerReturnedContent,
                        providerResponseAccepted: retryError.providerResponseAccepted,
                        providerResponseIssueSummary: retryError.boundedSummary
                    )
                    return PMConversationSynthesisResult(
                        replyBody: fallbackReply.body,
                        conversationActionPlan: nil,
                        conversationResolution: nil,
                        runtimeProvenance: pmFallbackRuntimeProvenance(
                            runtimeSelection: runtimeSelection,
                            status: pmConversationProviderErrorStatus(runtimeSelection: runtimeSelection),
                            issueSummary: retryError.boundedSummary,
                            launchedAt: launchedAt,
                            conversationTrace: fallbackReply.trace
                        ),
                        usedModelBackedInterpretation: false
                    )
                } catch {
                    let executionStatus = pmExecutionStatusRecord(
                        category: .internalFailure,
                        summary: "Latest PM conversation execution for \(runtimeSelection.effectiveRuntimeIdentifier) failed unexpectedly after bounded retry compaction.",
                        checkedBy: "pm conversation execution",
                        now: launchedAt
                    )
                    try? await recordPMConversationExecutionStatus(
                        executionStatus,
                        runtimeSelection: runtimeSelection,
                        now: launchedAt
                    )
                    let fallbackReply = makeFallbackPMConversationReply(
                        runtimeSelection: runtimeSelection,
                        degradedReason: pmConversationProviderErrorStatus(runtimeSelection: runtimeSelection),
                        issueSummary: pmConversationUnexpectedErrorSummary(runtimeSelection: runtimeSelection),
                        modelSynthesisAttempted: true,
                        modelAttemptCount: attemptCount,
                        requestCharacterCount: retryAttempt.promptCharacterCount,
                        requestCompactionLevel: retryAttempt.profile.rawValue,
                        promptBudgetTrace: retryAttempt.promptBudgetTrace,
                        promptProfileTraces: promptProfileTraces,
                        providerReturnedContent: false,
                        providerResponseAccepted: false,
                        providerResponseIssueSummary: pmConversationUnexpectedErrorSummary(runtimeSelection: runtimeSelection)
                    )
                    return PMConversationSynthesisResult(
                        replyBody: fallbackReply.body,
                        conversationActionPlan: nil,
                        conversationResolution: nil,
                        runtimeProvenance: pmFallbackRuntimeProvenance(
                            runtimeSelection: runtimeSelection,
                            status: pmConversationProviderErrorStatus(runtimeSelection: runtimeSelection),
                            issueSummary: pmConversationUnexpectedErrorSummary(runtimeSelection: runtimeSelection),
                            launchedAt: launchedAt,
                            conversationTrace: fallbackReply.trace
                        ),
                        usedModelBackedInterpretation: false
                    )
                }
            }

            let executionStatus = pmExecutionStatusRecord(
                for: error,
                runtimeSelection: runtimeSelection,
                checkedBy: "pm conversation execution",
                now: launchedAt
            )
            try? await recordPMConversationExecutionStatus(
                executionStatus,
                runtimeSelection: runtimeSelection,
                now: launchedAt
            )
            let fallbackReply = makeFallbackPMConversationReply(
                runtimeSelection: runtimeSelection,
                degradedReason: pmConversationProviderErrorStatus(runtimeSelection: runtimeSelection),
                issueSummary: error.boundedSummary,
                modelSynthesisAttempted: true,
                modelAttemptCount: attemptCount == 0 ? 1 : attemptCount,
                requestCharacterCount: finalAttempt.promptCharacterCount,
                requestCompactionLevel: finalAttempt.profile.rawValue,
                promptBudgetTrace: finalAttempt.promptBudgetTrace,
                promptProfileTraces: promptProfileTraces,
                providerReturnedContent: error.providerReturnedContent,
                providerResponseAccepted: error.providerResponseAccepted,
                providerResponseIssueSummary: error.boundedSummary
            )
            return PMConversationSynthesisResult(
                replyBody: fallbackReply.body,
                conversationActionPlan: nil,
                conversationResolution: nil,
                runtimeProvenance: pmFallbackRuntimeProvenance(
                    runtimeSelection: runtimeSelection,
                    status: pmConversationProviderErrorStatus(runtimeSelection: runtimeSelection),
                    issueSummary: error.boundedSummary,
                    launchedAt: launchedAt,
                    conversationTrace: fallbackReply.trace
                ),
                usedModelBackedInterpretation: false
            )
        } catch {
            let executionStatus = pmExecutionStatusRecord(
                category: .internalFailure,
                summary: "Latest PM conversation execution for \(runtimeSelection.effectiveRuntimeIdentifier) failed unexpectedly before a usable answer was accepted.",
                checkedBy: "pm conversation execution",
                now: launchedAt
            )
            try? await recordPMConversationExecutionStatus(
                executionStatus,
                runtimeSelection: runtimeSelection,
                now: launchedAt
            )
            let fallbackReply = makeFallbackPMConversationReply(
                runtimeSelection: runtimeSelection,
                degradedReason: pmConversationProviderErrorStatus(runtimeSelection: runtimeSelection),
                issueSummary: pmConversationUnexpectedErrorSummary(runtimeSelection: runtimeSelection),
                modelSynthesisAttempted: true,
                modelAttemptCount: attemptCount == 0 ? 1 : attemptCount,
                requestCharacterCount: finalAttempt.promptCharacterCount,
                requestCompactionLevel: finalAttempt.profile.rawValue,
                promptBudgetTrace: finalAttempt.promptBudgetTrace,
                promptProfileTraces: promptProfileTraces,
                providerReturnedContent: false,
                providerResponseAccepted: false,
                providerResponseIssueSummary: pmConversationUnexpectedErrorSummary(runtimeSelection: runtimeSelection)
            )
            return PMConversationSynthesisResult(
                replyBody: fallbackReply.body,
                conversationActionPlan: nil,
                conversationResolution: nil,
                runtimeProvenance: pmFallbackRuntimeProvenance(
                    runtimeSelection: runtimeSelection,
                    status: pmConversationProviderErrorStatus(runtimeSelection: runtimeSelection),
                    issueSummary: pmConversationUnexpectedErrorSummary(runtimeSelection: runtimeSelection),
                    launchedAt: launchedAt,
                    conversationTrace: fallbackReply.trace
                ),
                usedModelBackedInterpretation: false
            )
        }
    }

    private func resolvedPMConversationActionPlan(
        _ actionPlan: PMConversationActionPlan?,
        ownerMessage: PMCommunicationMessage,
        recentOpenLoop: PMConversationOpenLoop?,
        conversationResolution: PMConversationResolutionState?,
        replyBody: String
    ) -> PMConversationResolvedActionPlanResult {
        if let normalized = normalizedPMConversationActionPlan(
            actionPlan,
            ownerMessage: ownerMessage,
            recentOpenLoop: recentOpenLoop
        ) {
            return PMConversationResolvedActionPlanResult(
                actionPlan: normalized,
                source: .modelActionPlan
            )
        }
        if let derived = pmConversationActionPlanFromResolution(
            conversationResolution,
            ownerMessage: ownerMessage,
            recentOpenLoop: recentOpenLoop,
            replyBody: replyBody
        ) {
            return PMConversationResolvedActionPlanResult(
                actionPlan: derived,
                source: .modelResolution
            )
        }
        return PMConversationResolvedActionPlanResult(
            actionPlan: minimalPMConversationAnswerOnlyActionPlan(
                ownerMessage: ownerMessage,
                recentOpenLoop: recentOpenLoop,
                replyBody: replyBody
            ),
            source: .minimalAnswerOnly
        )
    }

    private func normalizedPMConversationActionPlan(
        _ actionPlan: PMConversationActionPlan?,
        ownerMessage: PMCommunicationMessage,
        recentOpenLoop: PMConversationOpenLoop?
    ) -> PMConversationActionPlan? {
        guard var actionPlan else { return nil }
        let summary = trimmedOptionalDecisionText(actionPlan.summary)
            ?? boundedConversationText(ownerMessage.body, limit: 220)
        let normalizedActions = actionPlan.actions.compactMap { action -> PMConversationActionIntent? in
            let summary = trimmedOptionalDecisionText(action.summary)
            guard let summary else { return nil }
            var normalized = action
            normalized.summary = summary
            normalized.title = trimmedOptionalDecisionText(action.title)
            normalized.body = trimmedOptionalDecisionText(action.body)
            normalized.detail = trimmedOptionalDecisionText(action.detail)
            normalized.targetId = trimmedOptionalDecisionText(action.targetId)
            normalized.charterId = trimmedOptionalDecisionText(action.charterId)
            normalized.proposalSymbol = normalizedPMConversationProposalSymbol(action.proposalSymbol)
            if let quantity = action.proposalQuantity, quantity > 0 {
                normalized.proposalQuantity = quantity
            } else {
                normalized.proposalQuantity = nil
            }
            normalized.liveOrderSymbol = normalizedPMConversationProposalSymbol(action.liveOrderSymbol)
            if let quantity = action.liveOrderQuantity, quantity > 0 {
                normalized.liveOrderQuantity = quantity
            } else {
                normalized.liveOrderQuantity = nil
            }
            if let notional = action.liveOrderNotionalAmount, notional > 0 {
                normalized.liveOrderNotionalAmount = notional
            } else {
                normalized.liveOrderNotionalAmount = nil
            }
            if let limitPrice = action.liveOrderLimitPrice, limitPrice > 0 {
                normalized.liveOrderLimitPrice = limitPrice
            } else {
                normalized.liveOrderLimitPrice = nil
            }
            normalized.runtimeIdentifier = trimmedOptionalDecisionText(action.runtimeIdentifier)
            normalized.watchlistSymbols = normalizedPMConversationWatchlistSymbolHints(action.watchlistSymbols)
            normalized.sourceMessageIds = orderedUniqueStrings(
                action.sourceMessageIds + [recentOpenLoop?.sourceMessageId, ownerMessage.messageId].compactMap { $0 }
            )
            return normalized
        }
        guard normalizedActions.isEmpty == false else { return nil }
        actionPlan.summary = summary
        actionPlan.actions = normalizedActions
        return actionPlan
    }

    private func liveOrderReviewPayloadForPMConversationAction(
        _ action: PMConversationActionIntent
    ) -> PMLiveOrderReviewPayload? {
        guard action.requestType == .liveOrderReview else {
            return nil
        }

        guard let symbol = normalizedPMConversationProposalSymbol(
            action.liveOrderSymbol ?? action.proposalSymbol
        ) else {
            return nil
        }
        guard let side = action.liveOrderSide ?? action.proposalSide else {
            return nil
        }
        guard let orderType = action.liveOrderType else {
            return nil
        }
        guard let timeInForce = action.liveOrderTimeInForce else {
            return nil
        }

        let quantity = [action.liveOrderQuantity, action.proposalQuantity]
            .compactMap { $0 }
            .first(where: { $0 > 0 })
        let notional = action.liveOrderNotionalAmount.flatMap { $0 > 0 ? $0 : nil }
        guard quantity != nil || notional != nil else {
            return nil
        }

        let limitPrice = action.liveOrderLimitPrice.flatMap { $0 > 0 ? $0 : nil }
        if orderType == .limit, limitPrice == nil {
            return nil
        }

        return PMLiveOrderReviewPayload(
            symbol: symbol,
            side: side,
            orderType: orderType,
            timeInForce: timeInForce,
            quantity: quantity,
            notionalAmount: notional,
            limitPrice: limitPrice,
            environment: .live,
            instructionSummary: trimmedOptionalDecisionText(action.detail ?? action.body ?? action.summary)
        )
    }

    private func pmConversationActionPlanFromResolution(
        _ conversationResolution: PMConversationResolutionState?,
        ownerMessage: PMCommunicationMessage,
        recentOpenLoop: PMConversationOpenLoop?,
        replyBody: String
    ) -> PMConversationActionPlan? {
        let resolution = conversationResolution
        let defaultSourceMessageIds = [recentOpenLoop?.sourceMessageId, ownerMessage.messageId].compactMap { $0 }
        let actions: [PMConversationActionIntent]
        switch resolution?.disposition {
        case .clarificationRequired:
            actions = [
                PMConversationActionIntent(
                    actionType: .askFollowUp,
                    summary: resolution?.pendingAsk?.promptSummary
                        ?? resolution?.ambiguitySummary
                        ?? "Ask one bounded follow-up question.",
                    sourceMessageIds: defaultSourceMessageIds
                )
            ]
        case .durableApplyNow:
            actions = [
                PMConversationActionIntent(
                    actionType: .upsertPMInstruction,
                    summary: resolution?.workingUnderstandingSummary
                        ?? resolution?.durableTitle
                        ?? "Apply one bounded PM instruction from this conversation.",
                    title: resolution?.durableTitle,
                    body: resolution?.durableBody,
                    instructionTargetKind: resolution?.instructionTargetKind,
                    operatingTruthKind: resolution?.operatingTruthKind,
                    sourceMessageIds: defaultSourceMessageIds
                )
            ]
        case .workingUnderstandingOnly:
            actions = [
                PMConversationActionIntent(
                    actionType: .updateConversationWorkingTruth,
                    summary: resolution?.operatingTruthSummary
                        ?? resolution?.workingUnderstandingSummary
                        ?? boundedConversationText(ownerMessage.body, limit: 220),
                    body: resolution?.operatingTruthBody,
                    operatingTruthKind: resolution?.operatingTruthKind,
                    sourceMessageIds: defaultSourceMessageIds
                )
            ]
        case .durableChangeProposed:
            if let pendingAsk = resolution?.pendingAsk {
                actions = [
                    PMConversationActionIntent(
                        actionType: .askFollowUp,
                        summary: pendingAsk.promptSummary,
                        body: pendingAsk.promptSummary,
                        instructionTargetKind: pendingAsk.instructionTargetKind,
                        operatingTruthKind: pendingAsk.operatingTruthKind,
                        sourceMessageIds: defaultSourceMessageIds
                    )
                ]
            } else {
                actions = [
                    PMConversationActionIntent(
                        actionType: .answerOnly,
                        summary: resolution?.workingUnderstandingSummary
                            ?? resolution?.operatingTruthSummary
                            ?? boundedConversationText(replyBody, limit: 220),
                        sourceMessageIds: defaultSourceMessageIds
                    )
                ]
            }
        default:
            actions = [
                PMConversationActionIntent(
                    actionType: .answerOnly,
                    summary: "Answer the owner naturally with no additional durable side effect.",
                    sourceMessageIds: defaultSourceMessageIds
                )
            ]
        }
        return PMConversationActionPlan(
            summary: resolution?.workingUnderstandingSummary
                ?? resolution?.operatingTruthSummary
                ?? boundedConversationText(replyBody, limit: 220),
            actions: actions
        )
    }

    private func minimalPMConversationAnswerOnlyActionPlan(
        ownerMessage: PMCommunicationMessage,
        recentOpenLoop: PMConversationOpenLoop?,
        replyBody: String
    ) -> PMConversationActionPlan {
        PMConversationActionPlan(
            summary: boundedConversationText(replyBody, limit: 220),
            actions: [
                PMConversationActionIntent(
                    actionType: .answerOnly,
                    summary: boundedConversationText(replyBody, limit: 220),
                    sourceMessageIds: [recentOpenLoop?.sourceMessageId, ownerMessage.messageId].compactMap { $0 }
                )
            ]
        )
    }

    private func enrichedPMConversationResolutionState(
        _ resolution: PMConversationResolutionState?,
        actionPlan: PMConversationActionPlan?,
        ownerMessage: PMCommunicationMessage,
        recentOpenLoop: PMConversationOpenLoop?
    ) -> PMConversationResolutionState? {
        var resolution = resolution ?? derivedPMConversationResolutionState(
            from: actionPlan,
            ownerMessage: ownerMessage,
            recentOpenLoop: recentOpenLoop
        )
        guard let actionPlan else {
            return normalizedPMConversationResolutionState(
                resolution,
                ownerMessage: ownerMessage,
                recentOpenLoop: recentOpenLoop
            )
        }

        if let workingTruthAction = actionPlan.actions.first(where: { $0.actionType == .updateConversationWorkingTruth }) {
            if resolution == nil {
                resolution = derivedPMConversationResolutionState(
                    from: PMConversationActionPlan(summary: actionPlan.summary, actions: [workingTruthAction]),
                    ownerMessage: ownerMessage,
                    recentOpenLoop: recentOpenLoop
                )
            } else {
                var existingResolution = resolution!
                if existingResolution.disposition == .conversationOnly {
                    existingResolution.disposition = .workingUnderstandingOnly
                }
                if existingResolution.workingUnderstandingSummary == nil {
                    existingResolution.workingUnderstandingSummary = workingTruthAction.summary
                }
                if existingResolution.operatingTruthKind == nil {
                    existingResolution.operatingTruthKind = workingTruthAction.operatingTruthKind ?? .workingPortfolioDefinition
                }
                if existingResolution.operatingTruthSummary == nil {
                    existingResolution.operatingTruthSummary = workingTruthAction.summary
                }
                if existingResolution.operatingTruthBody == nil {
                    existingResolution.operatingTruthBody = workingTruthAction.body ?? workingTruthAction.detail ?? workingTruthAction.summary
                }
                resolution = existingResolution
            }
        }

        if let instructionAction = actionPlan.actions.first(where: { $0.actionType == .upsertPMInstruction }) {
            if resolution == nil {
                resolution = derivedPMConversationResolutionState(
                    from: PMConversationActionPlan(summary: actionPlan.summary, actions: [instructionAction]),
                    ownerMessage: ownerMessage,
                    recentOpenLoop: recentOpenLoop
                )
            } else if resolution?.durableTargetType == nil {
                var existingResolution = resolution!
                existingResolution.disposition = .durableApplyNow
                existingResolution.workingUnderstandingSummary = existingResolution.workingUnderstandingSummary ?? instructionAction.summary
                existingResolution.operatingTruthKind = existingResolution.operatingTruthKind
                    ?? instructionAction.operatingTruthKind
                    ?? pmConversationOperatingTruthKind(from: instructionAction.instructionTargetKind)
                existingResolution.operatingTruthSummary = existingResolution.operatingTruthSummary ?? instructionAction.summary
                existingResolution.operatingTruthBody = existingResolution.operatingTruthBody ?? instructionAction.body ?? instructionAction.detail ?? instructionAction.summary
                existingResolution.durableTargetType = .pmInstruction
                existingResolution.instructionTargetKind = existingResolution.instructionTargetKind
                    ?? instructionAction.instructionTargetKind
                    ?? .operatingInstruction
                existingResolution.durableTitle = existingResolution.durableTitle ?? instructionAction.title ?? instructionAction.summary
                existingResolution.durableBody = existingResolution.durableBody ?? instructionAction.body ?? instructionAction.detail ?? instructionAction.summary
                resolution = existingResolution
            }
        }

        if let followUpAction = actionPlan.actions.first(where: { $0.actionType == .askFollowUp }),
           resolution == nil || resolution?.disposition == .conversationOnly {
            resolution = derivedPMConversationResolutionState(
                from: PMConversationActionPlan(summary: actionPlan.summary, actions: [followUpAction]),
                ownerMessage: ownerMessage,
                recentOpenLoop: recentOpenLoop
            )
        }

        if var existingResolution = resolution,
           pmConversationResolutionShouldNotCreateInstructionShadow(
            existingResolution,
            actionPlan: actionPlan
           ) {
            existingResolution.disposition = .conversationOnly
            existingResolution.durableTargetType = nil
            existingResolution.instructionTargetKind = nil
            existingResolution.durableTitle = nil
            existingResolution.durableBody = nil
            existingResolution.durableTargetId = nil
            resolution = existingResolution
        }

        if var existingResolution = resolution {
            existingResolution.sourceMessageIds = orderedUniqueStrings(
                existingResolution.sourceMessageIds
                    + actionPlan.actions.flatMap(\.sourceMessageIds)
                    + [recentOpenLoop?.sourceMessageId, ownerMessage.messageId].compactMap { $0 }
            )
            resolution = existingResolution
        }
        return normalizedPMConversationResolutionState(
            resolution,
            ownerMessage: ownerMessage,
            recentOpenLoop: recentOpenLoop
        )
    }

    private func pmConversationResolutionShouldNotCreateInstructionShadow(
        _ resolution: PMConversationResolutionState,
        actionPlan: PMConversationActionPlan
    ) -> Bool {
        guard resolution.durableTargetType == .pmInstruction,
              actionPlan.actions.contains(where: { $0.actionType == .updateAnalystCharter }),
              actionPlan.actions.contains(where: { $0.actionType == .upsertPMInstruction }) == false else {
            return false
        }
        return true
    }

    private func derivedPMConversationResolutionState(
        from actionPlan: PMConversationActionPlan?,
        ownerMessage: PMCommunicationMessage,
        recentOpenLoop: PMConversationOpenLoop?
    ) -> PMConversationResolutionState? {
        guard let actionPlan else { return nil }
        let sourceMessageIds = orderedUniqueStrings(
            actionPlan.actions.flatMap(\.sourceMessageIds)
                + [recentOpenLoop?.sourceMessageId, ownerMessage.messageId].compactMap { $0 }
        )

        if let instructionAction = actionPlan.actions.first(where: { $0.actionType == .upsertPMInstruction }) {
            let operatingTruthKind = instructionAction.operatingTruthKind
                ?? pmConversationOperatingTruthKind(from: instructionAction.instructionTargetKind)
            let durableBody = instructionAction.body ?? instructionAction.detail ?? instructionAction.summary
            return PMConversationResolutionState(
                intentClass: .instruction,
                disposition: .durableApplyNow,
                workingUnderstandingSummary: instructionAction.summary,
                operatingTruthKind: operatingTruthKind,
                operatingTruthSummary: instructionAction.summary,
                operatingTruthBody: durableBody,
                durableTargetType: .pmInstruction,
                instructionTargetKind: instructionAction.instructionTargetKind ?? .operatingInstruction,
                durableTitle: instructionAction.title ?? instructionAction.summary,
                durableBody: durableBody,
                sourceMessageIds: sourceMessageIds
            )
        }

        if let workingTruthAction = actionPlan.actions.first(where: { $0.actionType == .updateConversationWorkingTruth }) {
            return PMConversationResolutionState(
                intentClass: .instruction,
                disposition: .workingUnderstandingOnly,
                workingUnderstandingSummary: workingTruthAction.summary,
                operatingTruthKind: workingTruthAction.operatingTruthKind ?? .workingPortfolioDefinition,
                operatingTruthSummary: workingTruthAction.summary,
                operatingTruthBody: workingTruthAction.body ?? workingTruthAction.detail ?? workingTruthAction.summary,
                sourceMessageIds: sourceMessageIds
            )
        }

        if let followUpAction = actionPlan.actions.first(where: { $0.actionType == .askFollowUp }) {
            let promptSummary = followUpAction.body ?? followUpAction.detail ?? followUpAction.summary
            return PMConversationResolutionState(
                intentClass: .clarification,
                disposition: .clarificationRequired,
                ambiguitySummary: followUpAction.summary,
                pendingAsk: PMConversationPendingAskState(
                    kind: .clarification,
                    promptSummary: promptSummary,
                    workingUnderstandingSummary: followUpAction.summary,
                    operatingTruthKind: followUpAction.operatingTruthKind,
                    operatingTruthSummary: followUpAction.summary
                ),
                sourceMessageIds: sourceMessageIds
            )
        }

        if actionPlan.actions.contains(where: { $0.actionType == .answerOnly }) {
            return PMConversationResolutionState(
                intentClass: .general,
                disposition: .conversationOnly,
                sourceMessageIds: sourceMessageIds
            )
        }

        return nil
    }

    private func normalizedPMConversationResolutionState(
        _ resolution: PMConversationResolutionState?,
        ownerMessage: PMCommunicationMessage,
        recentOpenLoop: PMConversationOpenLoop?
    ) -> PMConversationResolutionState? {
        guard var resolution else { return nil }

        func trimmed(_ value: String?) -> String? {
            guard let value else { return nil }
            let trimmed = value.trimmingCharacters(in: .whitespacesAndNewlines)
            return trimmed.isEmpty ? nil : trimmed
        }

        resolution.workingUnderstandingSummary = trimmed(resolution.workingUnderstandingSummary)
        resolution.ambiguitySummary = trimmed(resolution.ambiguitySummary)
        resolution.operatingTruthSummary = trimmed(resolution.operatingTruthSummary)
        resolution.operatingTruthBody = trimmed(resolution.operatingTruthBody)
        resolution.durableTitle = trimmed(resolution.durableTitle)
        resolution.durableBody = trimmed(resolution.durableBody)
        resolution.durableTargetId = trimmed(resolution.durableTargetId)
        resolution.sourceMessageIds = orderedUniqueStrings(
            resolution.sourceMessageIds + [recentOpenLoop?.sourceMessageId, ownerMessage.messageId].compactMap { $0 }
        )
        if resolution.operatingTruthKind == nil {
            resolution.operatingTruthKind = pmConversationOperatingTruthKind(from: resolution.instructionTargetKind)
        }
        if resolution.operatingTruthSummary == nil {
            resolution.operatingTruthSummary = resolution.workingUnderstandingSummary
        }
        if resolution.operatingTruthBody == nil {
            resolution.operatingTruthBody = resolution.operatingTruthSummary ?? resolution.durableBody
        }

        if var pendingAsk = resolution.pendingAsk {
            pendingAsk.promptSummary = trimmed(pendingAsk.promptSummary) ?? boundedConversationText(ownerMessage.body, limit: 220)
            pendingAsk.workingUnderstandingSummary = trimmed(pendingAsk.workingUnderstandingSummary)
            pendingAsk.operatingTruthSummary = trimmed(pendingAsk.operatingTruthSummary)
            pendingAsk.durableTitle = trimmed(pendingAsk.durableTitle)
            pendingAsk.durableBody = trimmed(pendingAsk.durableBody)
            if pendingAsk.operatingTruthKind == nil {
                pendingAsk.operatingTruthKind = pmConversationOperatingTruthKind(from: pendingAsk.instructionTargetKind)
            }
            if pendingAsk.operatingTruthSummary == nil {
                pendingAsk.operatingTruthSummary = pendingAsk.workingUnderstandingSummary
            }
            if pendingAsk.durableTargetType != .pmInstruction {
                pendingAsk.instructionTargetKind = nil
                pendingAsk.durableTitle = nil
                pendingAsk.durableBody = nil
            }
            resolution.pendingAsk = pendingAsk
        }

        if resolution.durableTargetType != .pmInstruction {
            resolution.instructionTargetKind = nil
            resolution.durableTitle = nil
            resolution.durableBody = nil
            resolution.durableTargetId = nil
        }

        return resolution
    }

    private func makeFallbackPMConversationResolution(
        ownerMessage: PMCommunicationMessage,
        recentOpenLoop: PMConversationOpenLoop?
    ) -> PMConversationResolutionState? {
        let sourceMessageIds = [recentOpenLoop?.sourceMessageId, ownerMessage.messageId].compactMap { $0 }
        if let recentOpenLoop {
            return PMConversationResolutionState(
                intentClass: .clarification,
                disposition: .clarificationRequired,
                ambiguitySummary: "The PM runtime was unavailable, so the app did not interpret the owner's latest reply to the unresolved PM ask.",
                pendingAsk: recentOpenLoop.pendingAskState ?? PMConversationPendingAskState(
                    kind: recentOpenLoop.kind == .yesNoConfirmation ? .yesNoConfirmation : .clarification,
                    promptSummary: recentOpenLoop.promptSummary
                ),
                sourceMessageIds: sourceMessageIds
            )
        }

        return PMConversationResolutionState(
            intentClass: .general,
            disposition: .conversationOnly,
            sourceMessageIds: [ownerMessage.messageId]
        )
    }

    private func applyPMConversationResolutionIfNeeded(
        _ resolution: PMConversationResolutionState?,
        ownerMessage: PMCommunicationMessage,
        session: PMCommunicationSession,
        responderPMID: String?,
        source: AuditEventSource
    ) async throws -> PMConversationResolutionState? {
        guard var resolution else { return nil }
        guard resolution.disposition == .durableApplyNow,
              resolution.durableTargetType == .pmInstruction,
              let durableTitle = resolution.durableTitle,
              let durableBody = resolution.durableBody else {
            return resolution
        }

        let category = pmConversationInstructionCategory(
            resolution.instructionTargetKind ?? .operatingInstruction
        )
        try await archiveSupersededConversationInstructions(
            sessionId: session.sessionId,
            category: category,
            source: source
        )
        let instruction = try await promotePMCommunicationMessageToInstruction(
            messageId: ownerMessage.messageId,
            pmId: responderPMID ?? PMProfile.primaryPMID,
            title: durableTitle,
            body: durableBody,
            category: category,
            source: source
        )
        resolution.durableTargetId = instruction.instructionId
        return resolution
    }

