        var executionAssessment: PMExecutionRoutingAssessment?
        var approvalWorkflowBlockers: [String] = []
        var analystFollowThroughs: [PMConversationAnalystFollowThrough] = []
        var analystDelegationBlockers: [String] = []
        var watchlistUpdates: [PMConversationWatchlistUpdateResult] = []
        var charterUpdates: [PMConversationAnalystCharterUpdateResult] = []
    }

    private struct PMConversationActionApplicationResult: Sendable {
        var actionPlan: PMConversationActionPlan?
        var context: PMConversationAppliedActionContext
    }

    private struct PMConversationWorkCommitmentConsistencyResult: Sendable {
        var replyBody: String
        var actionPlan: PMConversationActionPlan?
        var visibleReplyModified: Bool
        var suppressAnalystDelegationBlockerFollowThrough: Bool
    }

    private struct PMConversationApprovalCommitmentClaim: Sendable {
        var claimsApprovalOrReview: Bool
        var claimsLocalAuthOrExecution: Bool

        var isEmpty: Bool {
            claimsApprovalOrReview == false && claimsLocalAuthOrExecution == false
        }
    }

    private func pmConversationWorkCommitmentConsistency(
        replyBody: String,
        actionPlan: PMConversationActionPlan?,
        appliedContext: PMConversationAppliedActionContext,
        latestOwnerAsk: String,
        hasPriorLiveOrderReviewRouteTruth: Bool
    ) -> PMConversationWorkCommitmentConsistencyResult {
        let trimmedReply = replyBody.trimmingCharacters(in: .whitespacesAndNewlines)
        let claimsAnalystWork = pmConversationReplyClaimsAppOwnedWorkCommitment(trimmedReply)
        let approvalClaim = pmConversationApprovalCommitmentClaim(in: trimmedReply)
        guard claimsAnalystWork || approvalClaim.isEmpty == false else {
            return PMConversationWorkCommitmentConsistencyResult(
                replyBody: trimmedReply,
                actionPlan: actionPlan,
                visibleReplyModified: false,
                suppressAnalystDelegationBlockerFollowThrough: false
            )
        }

        if approvalClaim.isEmpty == false {
            let approvalConsistency = pmConversationApprovalCommitmentConsistency(
                replyBody: trimmedReply,
                actionPlan: actionPlan,
                appliedContext: appliedContext,
                claim: approvalClaim,
                latestOwnerAsk: latestOwnerAsk,
                hasPriorLiveOrderReviewRouteTruth: hasPriorLiveOrderReviewRouteTruth
            )
            if approvalConsistency.visibleReplyModified {
                return approvalConsistency
            }
        }

        guard claimsAnalystWork else {
            return PMConversationWorkCommitmentConsistencyResult(
                replyBody: trimmedReply,
                actionPlan: actionPlan,
                visibleReplyModified: false,
                suppressAnalystDelegationBlockerFollowThrough: false
            )
        }

        let launchedDelegationIDs = Set(appliedContext.analystFollowThroughs.map(\.delegationId))
        let appliedAnalystLaunchExists = actionPlan?.actions.contains(where: { action in
            action.actionType == .launchAdHocAnalystDelegation
                && trimmedOptionalDecisionText(action.targetId).map { launchedDelegationIDs.contains($0) } == true
                && trimmedOptionalDecisionText(action.charterId) != nil
        }) == true
        guard appliedAnalystLaunchExists == false else {
            return PMConversationWorkCommitmentConsistencyResult(
                replyBody: trimmedReply,
                actionPlan: actionPlan,
                visibleReplyModified: false,
                suppressAnalystDelegationBlockerFollowThrough: false
            )
        }

        let replacement: String
        let detail: String
        if let blocker = appliedContext.analystDelegationBlockers.first {
            detail = blocker
            replacement = "I could not launch that analyst task: \(blocker)"
        } else {
            detail = "The visible PM reply claimed app-owned analyst/research work, but the hidden action plan did not create a valid analyst delegation. No delegation, analyst task, or worker launch was created."
            replacement = "I have not launched analyst work for this yet. The app did not receive a valid hidden analyst-delegation action for that visible work commitment, so no delegation, analyst task, or worker launch exists. I need to create a properly recorded analyst task with a valid app-owned analyst/charter target before treating this as in progress."
        }

        return PMConversationWorkCommitmentConsistencyResult(
            replyBody: replacement,
            actionPlan: pmConversationActionPlanMarkedWithWorkCommitmentGuard(actionPlan, detail: detail),
            visibleReplyModified: true,
            suppressAnalystDelegationBlockerFollowThrough: appliedContext.analystDelegationBlockers.isEmpty == false
        )
    }

    private func pmConversationApprovalCommitmentConsistency(
        replyBody: String,
        actionPlan: PMConversationActionPlan?,
        appliedContext: PMConversationAppliedActionContext,
        claim: PMConversationApprovalCommitmentClaim,
        latestOwnerAsk: String,
        hasPriorLiveOrderReviewRouteTruth: Bool
    ) -> PMConversationWorkCommitmentConsistencyResult {
        if hasPriorLiveOrderReviewRouteTruth,
           pmConversationOwnerAskIsLiveOrderReadback(latestOwnerAsk),
           pmConversationActionPlanIsAnswerOnly(actionPlan) {
            return PMConversationWorkCommitmentConsistencyResult(
                replyBody: replyBody,
                actionPlan: actionPlan,
                visibleReplyModified: false,
                suppressAnalystDelegationBlockerFollowThrough: false
            )
        }

        if claim.claimsLocalAuthOrExecution,
           let approvalRequest = appliedContext.lastApprovalRequest,
           approvalRequest.status == .pending {
            guard appliedContext.lastApprovalRequestOwnerVisible else {
                return pmConversationApprovalCreatedButNotOwnerVisibleConsistency(
                    replyBody: replyBody,
                    actionPlan: actionPlan,
                    approvalRequest: approvalRequest
                )
            }
            let detail = "The visible PM reply claimed an in-app approval / LocalAuthentication handoff, but safe-apply only created a pending PM approval request. LocalAuthentication is not waiting yet; it is invoked later from an in-app governed Live NEW/REPLACE route."
            let replacement = "I created the in-app review item \"\(boundedConversationText(approvalRequest.subject, limit: 140))\" in Command Center > Your Decisions. It is not a Touch ID or Mac password prompt yet: LocalAuthentication only happens later from the in-app governed Live NEW/REPLACE route after the required review, preflight, and safety checks."
            return PMConversationWorkCommitmentConsistencyResult(
                replyBody: replacement,
                actionPlan: pmConversationActionPlanMarkedWithWorkCommitmentGuard(actionPlan, detail: detail),
                visibleReplyModified: true,
                suppressAnalystDelegationBlockerFollowThrough: false
            )
        }

        if claim.claimsApprovalOrReview,
           let approvalRequest = appliedContext.lastApprovalRequest,
           approvalRequest.status == .pending {
            guard appliedContext.lastApprovalRequestOwnerVisible else {
                return pmConversationApprovalCreatedButNotOwnerVisibleConsistency(
                    replyBody: replyBody,
                    actionPlan: actionPlan,
                    approvalRequest: approvalRequest
                )
            }
            return PMConversationWorkCommitmentConsistencyResult(
                replyBody: replyBody,
                actionPlan: actionPlan,
                visibleReplyModified: false,
                suppressAnalystDelegationBlockerFollowThrough: false
            )
        }

        if claim.claimsLocalAuthOrExecution,
           let assessment = appliedContext.executionAssessment {
            if assessment.status == .routedSuccessfully || assessment.status == .partiallyRouted {
                return PMConversationWorkCommitmentConsistencyResult(
                    replyBody: replyBody,
                    actionPlan: actionPlan,
                    visibleReplyModified: false,
                    suppressAnalystDelegationBlockerFollowThrough: false
                )
            }
            let detail = "The visible PM reply claimed an in-app approval / execution / LocalAuthentication handoff, but the governed route did not create a reachable Live order approval path. Route assessment: \(assessment.summary)"
            let replacement = "I did not create a reachable in-app Touch ID or Live order route. \(assessment.summary) \(boundedConversationText(assessment.detail, limit: 260))"
            return PMConversationWorkCommitmentConsistencyResult(
                replyBody: replacement.trimmingCharacters(in: .whitespacesAndNewlines),
                actionPlan: pmConversationActionPlanMarkedWithWorkCommitmentGuard(actionPlan, detail: detail),
                visibleReplyModified: true,
                suppressAnalystDelegationBlockerFollowThrough: false
            )
        }

        guard claim.claimsApprovalOrReview || claim.claimsLocalAuthOrExecution else {
            return PMConversationWorkCommitmentConsistencyResult(
                replyBody: replyBody,
                actionPlan: actionPlan,
                visibleReplyModified: false,
                suppressAnalystDelegationBlockerFollowThrough: false
            )
        }

        let blocker = appliedContext.approvalWorkflowBlockers.first
        let detail = blocker
            ?? "The visible PM reply claimed an app-owned approval, Your Decisions item, order route, or LocalAuthentication next step, but safe-apply did not create a pending PM approval request, governed routing assessment, or reachable in-app route."
        let replacement = blocker.map {
            "I could not create the in-app approval item: \($0)"
        } ?? "I have not created an in-app approval item or Touch ID route for this. No PM approval request, governed order-review artifact, LocalAuthentication handoff, or order attempt exists yet. I need a valid hidden app-owned approval action, or one bounded follow-up if order details are missing, before anything can appear in Command Center > Your Decisions."

        return PMConversationWorkCommitmentConsistencyResult(
            replyBody: replacement,
            actionPlan: pmConversationActionPlanMarkedWithWorkCommitmentGuard(actionPlan, detail: detail),
            visibleReplyModified: true,
            suppressAnalystDelegationBlockerFollowThrough: false
        )
    }

    private func pmConversationApprovalCreatedButNotOwnerVisibleConsistency(
        replyBody _: String,
        actionPlan: PMConversationActionPlan?,
        approvalRequest: PMApprovalRequest
    ) -> PMConversationWorkCommitmentConsistencyResult {
        let detail = "Safe-apply created PM approval request \(shortOrderID(approvalRequest.approvalRequestId)), but the owner-decision projection does not classify it as owner-visible. The PM reply cannot claim Command Center > Your Decisions has a waiting item until that projection is true."
        let replacement = "I created a PM review record for \"\(boundedConversationText(approvalRequest.subject, limit: 140))\", but it is not currently visible in Command Center > Your Decisions. I have not placed or routed any order. The app needs the review item to be owner-visible before I can say it is waiting for your decision."
        return PMConversationWorkCommitmentConsistencyResult(
            replyBody: replacement,
            actionPlan: pmConversationActionPlanMarkedWithWorkCommitmentGuard(actionPlan, detail: detail),
            visibleReplyModified: true,
            suppressAnalystDelegationBlockerFollowThrough: false
        )
    }

    private func pmConversationActionPlanIsAnswerOnly(_ actionPlan: PMConversationActionPlan?) -> Bool {
        guard let actionPlan else { return true }
        guard actionPlan.actions.isEmpty == false else { return true }
        return actionPlan.actions.allSatisfy { $0.actionType == .answerOnly }
    }

    private func pmConversationOwnerAskIsLiveOrderReadback(_ ownerAsk: String) -> Bool {
        let normalized = normalizedPMCommitmentText(ownerAsk)
        guard normalized.isEmpty == false else { return false }
        let orderSignals = [
            "order", "trade", "live order", "live trade", "touch id",
            "mac password", "local authentication", "localauthentication",
            "route", "routed", "blotter"
        ]
        let readbackSignals = [
            "what happened", "status", "did", "was", "is", "why", "where",
            "tell me", "confirm", "read back", "readback", "sent", "submitted",
            "placed", "filled", "complete", "completed", "approved"
        ]
        return orderSignals.contains(where: { normalized.contains($0) })
            && readbackSignals.contains(where: { normalized.contains($0) })
    }

    private func pmConversationHasPriorLiveOrderReviewRouteTruth(
        approvalRequests: [PMApprovalRequest],
        latestOwnerAsk: String
    ) -> Bool {
        guard pmConversationOwnerAskIsLiveOrderReadback(latestOwnerAsk) else { return false }
        return pmConversationRecentLiveOrderReviewRouteRequests(
            approvalRequests: approvalRequests,
            latestOwnerAsk: latestOwnerAsk,
            limit: 1
        ).isEmpty == false
    }

    private func pmConversationReplyClaimsAppOwnedWorkCommitment(_ replyBody: String) -> Bool {
        let normalized = normalizedPMCommitmentText(replyBody)
        guard normalized.isEmpty == false else { return false }
        let commitmentPhrases = [
            "i'll put", "i will put", "i'm putting", "i am putting",
            "i'll ask", "i will ask", "i'm asking", "i am asking",
            "i'll have", "i will have", "i'm having", "i am having",
            "i'll route", "i will route", "i'm routing", "i am routing",
            "i'll send", "i will send", "i'm sending", "i am sending",
            "i'll launch", "i will launch", "i'm launching", "i am launching",
            "i've created", "i have created", "i created", "i'm creating", "i am creating",
            "i'll start", "i will start", "i'm starting", "i am starting",
            "i'll run a bounded", "i will run a bounded",
            "i'll do a bounded", "i will do a bounded"
        ]
        guard commitmentPhrases.contains(where: { normalized.contains($0) }) else {
            return false
        }
        let appOwnedWorkSignals = [
            "analyst",
            "delegation",
            "research task",
            "ad hoc research",
            "analyst research",
            "bounded lookup",
            "lookup",
            "worker",
            "work item",
            "task"
        ]
        return appOwnedWorkSignals.contains(where: { normalized.contains($0) })
    }

    private func pmConversationApprovalCommitmentClaim(in replyBody: String) -> PMConversationApprovalCommitmentClaim {
        let normalized = normalizedPMCommitmentText(replyBody)
        guard normalized.isEmpty == false else {
            return PMConversationApprovalCommitmentClaim(
                claimsApprovalOrReview: false,
                claimsLocalAuthOrExecution: false
            )
        }

        let commitmentPhrases = [
            "i'll create", "i will create", "i'm creating", "i am creating",
            "i've created", "i have created", "i created",
            "i'll put", "i will put", "i'm putting", "i am putting",
            "i'll route", "i will route", "i'm routing", "i am routing",
            "i'll move", "i will move", "i'm moving", "i am moving",
            "i've set up", "i have set up", "i set up",
            "ready for approval", "approval is waiting", "approve in the app",
            "approve via"
        ]
        let approvalSignals = [
            "approval", "review item", "pm ask",
            "your decisions", "in-app", "in app", "order review"
        ]
        let localAuthSignals = [
            "touch id", "mac password", "local authentication", "localauthentication"
        ]
        let executionSignals = [
            "order is ready", "ready to place", "ready for execution",
            "route to execution", "routing to execution", "submit the order",
            "place the order"
        ]

        let hasCommitment = commitmentPhrases.contains(where: { normalized.contains($0) })
        let claimsApprovalOrReview = hasCommitment
            && approvalSignals.contains(where: { normalized.contains($0) })
        let claimsLocalAuthOrExecution = (localAuthSignals.contains(where: { normalized.contains($0) })
            && ["approve", "approval", "waiting", "next", "ready", "route"].contains(where: { normalized.contains($0) }))
            || (hasCommitment && executionSignals.contains(where: { normalized.contains($0) }))

        return PMConversationApprovalCommitmentClaim(
            claimsApprovalOrReview: claimsApprovalOrReview,
            claimsLocalAuthOrExecution: claimsLocalAuthOrExecution
        )
    }

    private func normalizedPMCommitmentText(_ text: String) -> String {
        text
            .lowercased()
            .replacingOccurrences(of: "’", with: "'")
            .replacingOccurrences(of: "‘", with: "'")
            .replacingOccurrences(of: "“", with: "\"")
            .replacingOccurrences(of: "”", with: "\"")
            .replacingOccurrences(of: "\\s+", with: " ", options: .regularExpression)
            .trimmingCharacters(in: .whitespacesAndNewlines)
    }

    private func pmConversationActionPlanMarkedWithWorkCommitmentGuard(
        _ actionPlan: PMConversationActionPlan?,
        detail: String
    ) -> PMConversationActionPlan? {
        guard var actionPlan else { return nil }
        guard actionPlan.actions.isEmpty == false else { return actionPlan }
        let guardDetail = "Work commitment consistency guard: \(boundedConversationText(detail, limit: 360))"
        if let index = actionPlan.actions.firstIndex(where: { $0.actionType == .launchAdHocAnalystDelegation }) {
            actionPlan.actions[index].detail = guardDetail
        } else if let index = actionPlan.actions.firstIndex(where: { $0.actionType == .answerOnly }) {
            actionPlan.actions[index].detail = guardDetail
        } else {
            actionPlan.actions[0].detail = guardDetail
        }
        return validatedPMConversationActionPlan(actionPlan)
    }

    private func applyPMConversationActionPlanIfNeeded(
        _ actionPlan: PMConversationActionPlan?,
        ownerMessage: PMCommunicationMessage,
        session: PMCommunicationSession,
        responderPMID: String?,
        appliedResolution: PMConversationResolutionState?,
        runtimeProvenance: PMRuntimeProvenance?,
        source: AuditEventSource
    ) async throws -> PMConversationActionApplicationResult {
        guard var actionPlan else {
            return PMConversationActionApplicationResult(
                actionPlan: nil,
                context: PMConversationAppliedActionContext()
            )
        }

        var context = PMConversationAppliedActionContext()
        let actor = responderPMID ?? PMProfile.primaryPMID
        if let instructionId = appliedResolution?.durableTargetId,
           let index = actionPlan.actions.firstIndex(where: { $0.actionType == .upsertPMInstruction }) {
            actionPlan.actions[index].targetId = instructionId
        }

        for index in actionPlan.actions.indices {
            let action = actionPlan.actions[index]
            switch action.actionType {
            case .answerOnly, .askFollowUp, .updateConversationWorkingTruth, .upsertPMInstruction:
                continue

            case .updateWatchlistSymbols:
                let result = try await applyPMConversationWatchlistUpdate(
                    action: action,
                    actor: actor,
                    source: source
                )
                actionPlan.actions[index].detail = result.detail
                context.watchlistUpdates.append(result)

            case .upsertPMMandate:
                let trimmedTargetID = trimmedOptionalDecisionText(action.targetId)
                let existing: PMMandate?
                if let trimmedTargetID {
                    existing = try? await getPMMandate(id: trimmedTargetID)
                } else {
                    existing = nil
                }
                let now = nowDate()
                let mandate = PMMandate(
                    mandateId: existing?.mandateId ?? "pm-mandate-\(UUID().uuidString.lowercased())",
                    pmId: existing?.pmId ?? actor,
                    title: action.title ?? action.summary,
                    objectiveSummary: action.summary,
                    scope: action.body ?? action.detail ?? action.summary,
                    constraints: existing?.constraints ?? [],
                    riskBoundaries: existing?.riskBoundaries ?? [],
                    successCriteria: existing?.successCriteria ?? [action.summary],
                    createdAt: existing?.createdAt ?? now,
                    updatedAt: now
                )
                let stored = try await upsertPMMandate(mandate, source: source)
                actionPlan.actions[index].targetId = stored.mandateId

            case .upsertPMNotebookEntry:
                let trimmedTargetID = trimmedOptionalDecisionText(action.targetId)
                let existing: PMNotebookEntry?
                if let trimmedTargetID {
                    existing = try? await getPMNotebookEntry(id: trimmedTargetID)
                } else {
                    existing = nil
                }
                let now = nowDate()
                let entry = PMNotebookEntry(
                    entryId: existing?.entryId ?? "pm-notebook-\(UUID().uuidString.lowercased())",
                    pmId: existing?.pmId ?? actor,
                    title: action.title ?? action.summary,
                    body: action.body ?? action.detail ?? action.summary,
                    tags: existing?.tags ?? [],
                    sourceSummary: existing?.sourceSummary ?? "Created from PM/User conversation",
                    createdAt: existing?.createdAt ?? now,
                    updatedAt: now
                )
                let stored = try await upsertPMNotebookEntry(entry, source: source)
                actionPlan.actions[index].targetId = stored.entryId

            case .launchAdHocAnalystDelegation:
                guard let charter = try await resolvedPMConversationActionPlanCharter(for: action) else {
                    let requestedTarget = [
                        trimmedOptionalDecisionText(action.charterId),
                        trimmedOptionalDecisionText(action.targetId),
                        trimmedOptionalDecisionText(action.title),
                        trimmedOptionalDecisionText(action.summary)
                    ]
                    .compactMap { $0 }
                    .first ?? "unspecified analyst"
                    let blocker = "The PM selected analyst delegation, but the app could not resolve an actual app-owned analyst/charter id for \(boundedConversationText(requestedTarget, limit: 160)). No delegation, task, or worker launch was created. Ask which standing analyst or app-owned charter should handle this work. Do not treat this as a research-capability limit; once an app-owned analyst/charter target is selected, that charter's source restrictions govern the analyst's research breadth."
                    actionPlan.actions[index].detail = blocker
                    actionPlan.actions[index].targetId = nil
                    actionPlan.actions[index].charterId = nil
                    context.analystDelegationBlockers.append(blocker)
                    continue
                }
                let now = nowDate()
                let selectedSkillResolution = await resolvePMConversationSelectedSkillReferences(
                    action.selectedSkillReferences,
                    actor: actor,
                    now: now
                )
                if let blocker = selectedSkillResolution.blocker {
                    actionPlan.actions[index].detail = blocker
                    actionPlan.actions[index].targetId = nil
                    actionPlan.actions[index].charterId = charter.charterId
                    context.analystDelegationBlockers.append(blocker)
                    continue
                }
                let title = action.title ?? action.summary
                let ownerAskBody = ownerMessage.body.trimmingCharacters(in: .whitespacesAndNewlines)
                let ownerAskQuestions = AnalystTaskQuestionChecklist.questions(
                    taskDescription: ownerAskBody,
                    taskingBrief: nil
                )
                let actionBody = action.body?.trimmingCharacters(in: .whitespacesAndNewlines)
                let actionSummary = action.summary.trimmingCharacters(in: .whitespacesAndNewlines)
                let rationale: String
                if ownerAskQuestions.count >= 4, ownerAskBody.isEmpty == false {
                    rationale = ownerAskBody
                } else if let actionBody, actionBody.isEmpty == false {
                    rationale = actionBody
                } else {
                    rationale = ownerAskBody.isEmpty ? actionSummary : ownerAskBody
                }
                let requestedOutputs = action.requestedOutputs.isEmpty ? [.finding] : action.requestedOutputs
                var taskingBrief = PMTaskingBrief(
                    taskObjective: action.summary,
                    expectedOutputs: requestedOutputs.map(\.rawValue),
                    selectedSkillReferences: selectedSkillResolution.references
                )
                let researchQuestions = normalizedPMConversationResearchQuestions(
                    ownerMessageBody: ownerMessage.body,
                    action: action,
                    title: title,
                    rationale: rationale,
                    brief: taskingBrief
                )
                if researchQuestions.isEmpty == false {
                    taskingBrief.researchQuestions = researchQuestions
                    taskingBrief.coverageRequired = true
                }
                var delegation = try await promotePMCommunicationMessageToDelegation(
                    messageId: ownerMessage.messageId,
                    pmId: actor,
                    charterId: charter.charterId,
                    title: title,
                    rationale: rationale,
                    requestedOutputs: requestedOutputs,
                    taskingBrief: taskingBrief,
                    source: source
                )
                let task: AnalystTask
                if let existingTaskId = delegation.taskId,
                   let existingTask = try? await getAnalystTask(id: existingTaskId) {
                    task = existingTask
                } else {
                    let newTask = try await makePMConversationAnalystTask(
                        action: action,
                        charter: charter,
                        delegation: delegation,
                        taskingBrief: taskingBrief,
                        taskId: "task-\(UUID().uuidString.lowercased())",
                        pmId: actor,
                        now: now
                    )
                    task = try await upsertAnalystTask(newTask, source: source)
                    delegation.taskId = task.taskId
                    delegation.updatedAt = nowDate()
                    delegation = try await upsertPMDelegation(delegation, source: source)
                }
                actionPlan.actions[index].targetId = delegation.delegationId
                actionPlan.actions[index].charterId = charter.charterId
                context.lastDelegationId = delegation.delegationId
                let wantsProposal = delegation.requestedOutputs.contains(.proposalDraft)
                let wantsSignal = wantsProposal || delegation.requestedOutputs.contains(.signal)
                let shouldLaunch = shouldLaunchPMConversationDelegation(delegation)
                guard shouldLaunch else {
                    actionPlan.actions[index].detail = "This PM request already has a durable \(charter.title) delegation/task (\(shortOrderID(delegation.delegationId)) / \(shortOrderID(task.taskId))). The app did not create a duplicate analyst task or relaunch the worker from the same owner message."
                    continue
                }
                let launchResult: AnalystWorkerLaunchResult
                do {
                    launchResult = try await launchAnalystWorkerForPMDelegation(
                        delegationID: delegation.delegationId,
                        draftSignal: wantsSignal,
                        draftProposal: wantsProposal,
                        source: source
                    )
                } catch {
                    let blocker = "I created the \(charter.title) delegation/task (\(shortOrderID(delegation.delegationId)) / \(shortOrderID(task.taskId))), but the analyst worker launch failed: \(boundedConversationText(error.localizedDescription, limit: 220)). The failed launch is durable and traceable; the analyst is not currently running until the launch is retried or the blocker is resolved."
                    actionPlan.actions[index].detail = blocker
                    context.analystDelegationBlockers.append(blocker)
                    continue
                }
                let memo = await resolvedAnalystMemoForWorkerLaunchResult(
                    launchResult,
                    fallbackDelegationId: delegation.delegationId,
                    fallbackTaskId: task.taskId
                )
                context.analystFollowThroughs.append(
                    PMConversationAnalystFollowThrough(
                        delegationId: delegation.delegationId,
                        charterId: charter.charterId,
                        charterTitle: charter.title,
                        delegationTitle: delegation.title,
                        requestedSkillReferences: selectedSkillResolution.references,
                        launchResult: launchResult,
                        memo: memo
                    )
                )

            case .updateAnalystCharter:
                guard let existing = try await resolvedPMConversationActionPlanCharter(for: action) else {
                    let targetLabel = trimmedOptionalDecisionText(action.title)
                        ?? trimmedOptionalDecisionText(action.summary)
                        ?? "requested analyst charter"
                    let detail = "The model emitted update_analyst_charter but did not provide a charterId/targetId or a uniquely resolvable app-owned charter title. No analyst charter was changed."
                    context.charterUpdates.append(
                        PMConversationAnalystCharterUpdateResult(
                            charterId: nil,
                            charterTitle: targetLabel,
                            applied: false,
                            summary: "I could not update the analyst charter because the target charter was not uniquely resolved.",
                            detail: detail
                        )
                    )
                    actionPlan.actions[index].detail = detail
                    continue
                }
                guard let documentPatch = pmConversationAnalystCharterDocumentPatch(for: action) else {
                    let detail = "The model emitted update_analyst_charter for \(existing.title), but the action did not include bounded charter text to add or merge. No analyst charter was changed."
                    context.charterUpdates.append(
                        PMConversationAnalystCharterUpdateResult(
                            charterId: existing.charterId,
                            charterTitle: existing.title,
                            applied: false,
                            summary: "I could not update \(existing.title) because the charter update text was missing.",
                            detail: detail
                        )
                    )
                    actionPlan.actions[index].targetId = existing.charterId
                    actionPlan.actions[index].charterId = existing.charterId
                    actionPlan.actions[index].detail = detail
                    continue
                }
                let now = nowDate()
                let updatedDocumentBody = mergedPMConversationAnalystCharterDocumentBody(
                    existing: existing.primaryDocumentBody,
                    patch: documentPatch,
                    fallbackTitle: action.title
                )
                let revisionSummary = trimmedOptionalDecisionText(action.detail)
                    ?? trimmedOptionalDecisionText(action.summary)
                    ?? "Updated from PM/User conversation action plan."
                let charter = AnalystCharter(
                    charterId: existing.charterId,
                    analystId: existing.analystId,
                    title: existing.title,
                    coverageScope: existing.coverageScope,
                    strategyFamily: existing.strategyFamily,
                    summary: trimmedOptionalDecisionText(action.summary) ?? existing.summary,
                    documentBody: updatedDocumentBody,
                    revisionSummary: revisionSummary,
                    benchRole: existing.benchRole,
                    duties: existing.duties,
                    constraints: existing.constraints,
                    expectedOutputs: existing.expectedOutputs,
                    allowedSources: existing.allowedSources,
                    sourcePolicy: existing.sourcePolicy,
                    defaultRuntimePolicy: existing.defaultRuntimePolicy,
                    updatedBy: actor,
                    updateSource: .pmConversation,
                    createdAt: existing.createdAt,
                    updatedAt: now
                )
                let stored = try await upsertAnalystCharter(charter, source: source)
                actionPlan.actions[index].targetId = stored.charterId
                actionPlan.actions[index].charterId = stored.charterId
                let verified = try await getAnalystCharter(id: stored.charterId)
                guard pmConversationAnalystCharterDocumentBodyContainsPatch(
                    verified.primaryDocumentBody,
                    patch: documentPatch
                ) else {
                    let detail = "The app wrote \(stored.title) through AnalystCharterStore, but read-back verification did not find the requested charter text in the canonical charter body. Treat the charter update as blocked until the canonical charter can be verified."
                    context.charterUpdates.append(
                        PMConversationAnalystCharterUpdateResult(
                            charterId: stored.charterId,
                            charterTitle: stored.title,
                            applied: false,
                            summary: "I could not verify the \(stored.title) charter update in the canonical charter body.",
                            detail: detail
                        )
                    )
                    actionPlan.actions[index].detail = detail
                    continue
                }
                context.charterUpdates.append(
                    PMConversationAnalystCharterUpdateResult(
                        charterId: verified.charterId,
                        charterTitle: verified.title,
                        applied: true,
                        summary: "I updated and verified the \(verified.title) charter in the app-owned charter store.",
                        detail: "Read-back verification confirmed the canonical charter body contains the requested requirement while preserving the existing charter body. Revision note: \(boundedConversationText(revisionSummary, limit: 220))"
                    )
                )

            case .updateRuntimeSetting:
                guard let runtimeIdentifier = trimmedOptionalDecisionText(action.runtimeIdentifier) else {
                    continue
                }
                let now = nowDate()
                switch action.runtimeSettingScope ?? .pm {
                case .pm:
                    let existing = try await getPMRuntimeSettings()
                    let stored = try await upsertPMRuntimeSettings(
                        PMRuntimeSettings(
                            settingsId: existing.settingsId,
                            runtimeIdentifier: runtimeIdentifier,
                            reasoningMode: action.reasoningMode ?? existing.reasoningMode,
                            validationStatus: existing.validationStatus,
                            lastKnownGoodRuntime: existing.lastKnownGoodRuntime,
                            lastFallback: existing.lastFallback,
                            updatedBy: actor,
                            updateSource: .pmControlPlane,
                            createdAt: existing.createdAt,
                            updatedAt: now
                        ),
                        source: source
                    )
                    actionPlan.actions[index].targetId = stored.settingsId
                case .recentNewsAnalyst:
                    let existing = try await getRecentNewsAnalystRuntimeSettings()
                    let stored = try await upsertRecentNewsAnalystRuntimeSettings(
                        RecentNewsAnalystRuntimeSettings(
                            settingsId: existing.settingsId,
                            runtimeIdentifier: runtimeIdentifier,
                            reasoningMode: action.reasoningMode ?? existing.reasoningMode,
                            validationStatus: existing.validationStatus,
                            lastKnownGoodRuntime: existing.lastKnownGoodRuntime,
                            lastFallback: existing.lastFallback,
                            updatedBy: actor,
                            updateSource: .pmControlPlane,
                            createdAt: existing.createdAt,
                            updatedAt: now
                        ),
                        source: source
                    )
                    actionPlan.actions[index].targetId = stored.settingsId
                case .standingBench:
                    let existing = try await getStandingBenchAnalystRuntimeSettings()
                    let stored = try await upsertStandingBenchAnalystRuntimeSettings(
                        StandingBenchAnalystRuntimeSettings(
                            settingsId: existing.settingsId,
                            runtimeIdentifier: runtimeIdentifier,
                            reasoningMode: action.reasoningMode ?? existing.reasoningMode,
                            validationStatus: existing.validationStatus,
                            lastKnownGoodRuntime: existing.lastKnownGoodRuntime,
                            lastFallback: existing.lastFallback,
                            updatedBy: actor,
                            updateSource: .pmControlPlane,
                            createdAt: existing.createdAt,
                            updatedAt: now
                        ),
                        source: source
                    )
                    actionPlan.actions[index].targetId = stored.settingsId
                }

            case .createPMDecision:
                let now = nowDate()
                let resolvedCharterID = try await resolvedPMConversationActionPlanCharter(for: action)?.charterId
                    ?? trimmedOptionalDecisionText(action.charterId)
                let linkedProposalID = try await resolvedPMConversationProposalID(
                    for: action,
                    context: context
                )
                let decision = PMDecisionRecord(
                    decisionId: "pm-decision-\(UUID().uuidString.lowercased())",
                    pmId: actor,
                    title: action.title ?? action.summary,
                    summary: action.body ?? action.summary,
                    recommendedAction: action.detail,
                    ownerAsk: action.detail,
                    sourceCommunicationMessageId: ownerMessage.messageId,
                    decisionType: action.decisionType ?? .recommendation,
                    status: .active,
                    delegationId: context.lastDelegationId,
                    charterId: resolvedCharterID,
                    proposalId: linkedProposalID,
                    runtimeProvenance: runtimeProvenance,
                    createdAt: now,
                    updatedAt: now
                )
                let stored = try await upsertPMDecision(decision, source: source)
                actionPlan.actions[index].targetId = stored.decisionId
                context.lastDecisionId = stored.decisionId
                context.lastDecision = stored

            case .createPMApprovalRequest:
                guard let decisionId = try await resolvedPMConversationDecisionID(
                    for: action,
                    context: context,
                    ownerMessage: ownerMessage,
                    actor: actor,
                    source: source
                ) else {
                    let blocker = "The PM selected an in-app approval request, but the action was not linked to a newly created PM decision or an existing app-owned decision/request target. No approval item was created in Command Center > Your Decisions."
                    actionPlan.actions[index].detail = blocker
                    context.approvalWorkflowBlockers.append(blocker)
                    continue
                }
                let liveOrderReview = liveOrderReviewPayloadForPMConversationAction(action)
                if action.requestType == .liveOrderReview,
                   liveOrderReview == nil {
                    let blocker = "The PM selected a Live order review, but the hidden action did not include a complete machine-readable Live order payload: symbol, side, order type, time-in-force, and quantity or notional amount. No approval item was created."
                    actionPlan.actions[index].detail = blocker
                    context.approvalWorkflowBlockers.append(blocker)
                    continue
                }
                let request = try await createPMApprovalRequestFromDecision(
                    decisionId: decisionId,
                    subject: action.title,
                    rationale: action.body ?? action.summary,
                    requestedActionSummary: action.detail,
                    requestType: action.requestType,
                    liveOrderReview: liveOrderReview,
                    source: source
                )
                actionPlan.actions[index].targetId = request.approvalRequestId
                context.lastApprovalRequestId = request.approvalRequestId
                context.lastApprovalRequest = request
                context.lastApprovalRequestOwnerVisible = try await pmConversationApprovalRequestIsOwnerVisible(request)

            case .approvePMApprovalRequest:
                guard let approvalRequestId = try await resolvedPMConversationApprovalRequestID(
                    for: action,
                    context: context
                ) else {
                    let blocker = "The PM selected approval of an app-owned request, but the app could not resolve exactly one pending PM approval request from current context. No approval response was recorded."
                    actionPlan.actions[index].detail = blocker
                    context.approvalWorkflowBlockers.append(blocker)
                    continue
                }
                let request = try await getPMApprovalRequest(id: approvalRequestId)
                let linkedRequest = try await linkPMApprovalRequestToLatestProposalIfNeeded(
                    request,
                    context: context,
                    source: source
                )
                if shouldBlockTelegramLiveExecutionApproval(
                    response: .approved,
                    request: linkedRequest,
                    session: session
                ) {
                    let blocker = makeTelegramLiveOrderReviewApprovalBlockedAcknowledgement()
                    actionPlan.actions[index].detail = blocker
                    actionPlan.actions[index].targetId = linkedRequest.approvalRequestId
                    context.approvalWorkflowBlockers.append(blocker)
                    context.lastApprovalRequestId = linkedRequest.approvalRequestId
                    context.lastApprovalRequest = linkedRequest
                    context.lastApprovalRequestOwnerVisible = try await pmConversationApprovalRequestIsOwnerVisible(linkedRequest)
                    await store.publishDiagnostic(
                        "telegram pm action-plan live-order approval blocked approval_request=\(shortOrderID(linkedRequest.approvalRequestId))",
                        source: source,
                        action: "telegram_pm_action_plan_live_order_approval_blocked"
                    )
                    continue
                }
                let updatedRequest: PMApprovalRequest
                if linkedRequest.status == .pending || linkedRequest.ownerResponse != .approved {
                    updatedRequest = try await respondToPMApprovalRequest(
                        requestId: linkedRequest.approvalRequestId,
                        response: .approved,
                        source: source
                    )
                } else {
                    updatedRequest = linkedRequest
                }
                actionPlan.actions[index].targetId = updatedRequest.approvalRequestId
                context.lastApprovalRequestId = updatedRequest.approvalRequestId
                context.lastApprovalRequest = updatedRequest
                context.lastApprovalRequestOwnerVisible = try await pmConversationApprovalRequestIsOwnerVisible(updatedRequest)
                if let assessment = updatedRequest.lastExecutionRoutingAssessment {
                    context.executionAssessment = assessment
                }

            case .createOrUpdateProposal:
                if let outcome = try await upsertPMConversationProposal(
                    action: action,
                    context: context,
                    ownerMessage: ownerMessage,
                    actor: actor,
                    source: source
                ) {
                    actionPlan.actions[index].targetId = outcome.proposal.proposalId
                    actionPlan.actions[index].proposalSymbol = outcome.symbol
                    context.lastProposal = outcome.proposal
                    context.lastProposalWasCreated = outcome.wasCreated
                }

            case .routeGovernedExecutionNextStep:
                guard let approvalRequestId = try await resolvedPMConversationApprovalRequestID(
                    for: action,
                    context: context
                ) else {
                    let assessment = PMExecutionRoutingAssessment(
                        approvalRequestId: "unresolved",
                        decisionId: nil,
                        proposalId: nil,
                        proposalTitle: nil,
                        proposalStatus: nil,
                        environment: configuration.environment,
                        isLiveArmed: isArmedForLiveTrading,
                        killSwitchEnabled: killSwitchEnabled,
                        status: .invalidState,
                        action: .none,
                        summary: "I could not route the governed execution step because there is no resolved owner-approved PM ask linked to this action.",
                        detail: "The model selected a governed routing action, but the app could not resolve a specific approved PM approval request from app-owned state. I need the PM ask/approval target to be explicit before any paper-order route can run.",
                        blockedReasons: [.ownerApprovalRequired]
                    )
                    actionPlan.actions[index].detail = assessment.summary
                    context.executionAssessment = assessment
                    context.approvalWorkflowBlockers.append(assessment.summary)
                    continue
                }
                if let existingAssessment = context.executionAssessment,
                   existingAssessment.approvalRequestId == approvalRequestId {
                    actionPlan.actions[index].targetId = approvalRequestId
                    actionPlan.actions[index].detail = existingAssessment.summary
                    continue
                }
                let assessment = try await routePMExecutionApprovedIntent(
                    approvalRequestId: approvalRequestId,
                    source: source
                )
                actionPlan.actions[index].targetId = approvalRequestId
                actionPlan.actions[index].detail = assessment.summary
                context.executionAssessment = assessment
                if let refreshedRequest = try? await getPMApprovalRequest(id: approvalRequestId) {
                    context.lastApprovalRequestId = refreshedRequest.approvalRequestId
                    context.lastApprovalRequest = refreshedRequest
                    context.lastApprovalRequestOwnerVisible = try await pmConversationApprovalRequestIsOwnerVisible(refreshedRequest)
                }
            }
        }

        return PMConversationActionApplicationResult(
            actionPlan: validatedPMConversationActionPlan(actionPlan),
            context: context
        )
    }

    private func pmConversationApprovalRequestIsOwnerVisible(
        _ request: PMApprovalRequest
    ) async throws -> Bool {
        let decisions = try await listPMDecisions()
        return makeOwnerActionableApprovalRequests(
            approvalRequests: [request],
            decisions: decisions
        )
        .contains { $0.approvalRequestId == request.approvalRequestId }
    }

    private func applyPMConversationWatchlistUpdate(
        action: PMConversationActionIntent,
        actor: String,
        source: AuditEventSource
    ) async throws -> PMConversationWatchlistUpdateResult {
        let operation = action.watchlistOperation ?? .add
        let normalized = normalizedPMConversationWatchlistSymbols(action.watchlistSymbols)
        guard normalized.valid.isEmpty == false else {
            let rejected = normalized.rejected.isEmpty ? action.watchlistSymbols : normalized.rejected
            return PMConversationWatchlistUpdateResult(
                operation: operation,
                requestedSymbols: action.watchlistSymbols,
                addedSymbols: [],
                removedSymbols: [],
                alreadyPresentSymbols: [],
                notPresentSymbols: [],
                rejectedSymbols: orderedUniqueStrings(rejected),
                chartWallSelectedSymbols: [],
                chartWallOmittedSymbols: [],
                summary: "I could not update the watchlist because the action did not include any valid symbols.",
                detail: "Rejected symbols: \(orderedUniqueStrings(rejected).joined(separator: ", "))."
            )
        }

        let currentWatchlist = await store.snapshot().watchlistSymbols
        let currentSet = Set(currentWatchlist)
        let now = nowDate()
        let addedSymbols: [String]
        let removedSymbols: [String]
        let alreadyPresentSymbols: [String]
        let notPresentSymbols: [String]
        let updatedWatchlist: [String]

        switch operation {
        case .add:
            addedSymbols = normalized.valid.filter { currentSet.contains($0) == false }
            alreadyPresentSymbols = normalized.valid.filter { currentSet.contains($0) }
            removedSymbols = []
            notPresentSymbols = []
            updatedWatchlist = orderedUniqueStrings(currentWatchlist + addedSymbols)
        case .remove:
            let removalSet = Set(normalized.valid)
            addedSymbols = []
            alreadyPresentSymbols = []
            removedSymbols = normalized.valid.filter { currentSet.contains($0) }
            notPresentSymbols = normalized.valid.filter { currentSet.contains($0) == false }
            updatedWatchlist = currentWatchlist.filter { removalSet.contains($0) == false }
        }

        await setWatchSymbols(updatedWatchlist)
        let updatedSnapshot = await store.snapshot()
        let chartConfiguration = try await portfolioWatchChartWallConfigurationStore.loadOrDefault(
            watchlistSymbols: updatedSnapshot.watchlistSymbols
        )
        let selectedCandidate: [String]
        switch operation {
        case .add:
            selectedCandidate = orderedUniqueStrings(chartConfiguration.selectedSymbols + normalized.valid)
        case .remove:
            let removalSet = Set(normalized.valid)
            selectedCandidate = chartConfiguration.selectedSymbols.filter { removalSet.contains($0) == false }
        }

        let updatedChartConfiguration = try await upsertPortfolioWatchChartWallConfiguration(
            PortfolioWatchChartWallConfiguration(
                selectedSymbols: selectedCandidate,
                updatedBy: actor,
                updateSource: .pmConversation,
                createdAt: chartConfiguration.createdAt,
                updatedAt: now
            ),
            source: source
        )
        let selectedSet = Set(updatedChartConfiguration.selectedSymbols)
        let chartWallOmittedSymbols = operation == .add
            ? normalized.valid.filter { selectedSet.contains($0) == false }
            : []

        let summary: String
        let detail: String
        switch operation {
        case .add:
            summary = addedSymbols.isEmpty
                ? "The requested symbols were already on the app watchlist."
                : "I added \(addedSymbols.joined(separator: ", ")) to the app watchlist."
            var detailParts: [String] = []
            if alreadyPresentSymbols.isEmpty == false {
                detailParts.append("Already present: \(alreadyPresentSymbols.joined(separator: ", ")).")
            }
            if normalized.rejected.isEmpty == false {
                detailParts.append("Rejected invalid symbols: \(normalized.rejected.joined(separator: ", ")).")
            }
            if chartWallOmittedSymbols.isEmpty == false {
                detailParts.append(
                    "Portfolio Watch selection is capped at \(PortfolioWatchChartWallConfiguration.maximumSelectedSymbols), so these symbols are on the watchlist but not selected on the chart wall: \(chartWallOmittedSymbols.joined(separator: ", "))."
                )
            } else {
                detailParts.append("Portfolio Watch chart-wall selection now includes the requested valid symbols.")
            }
            detail = detailParts.joined(separator: " ")
        case .remove:
            summary = removedSymbols.isEmpty
                ? "None of the requested symbols were present on the app watchlist."
                : "I removed \(removedSymbols.joined(separator: ", ")) from the app watchlist."
            var detailParts: [String] = []
            if notPresentSymbols.isEmpty == false {
                detailParts.append("Not present: \(notPresentSymbols.joined(separator: ", ")).")
            }
            if normalized.rejected.isEmpty == false {
                detailParts.append("Rejected invalid symbols: \(normalized.rejected.joined(separator: ", ")).")
            }
            detailParts.append("Portfolio Watch chart-wall selection was updated through the app-owned configuration path.")
            detail = detailParts.joined(separator: " ")
        }

        await store.publishDiagnostic(
            "pm watchlist update operation=\(operation.rawValue) added=\(addedSymbols.joined(separator: ",")) removed=\(removedSymbols.joined(separator: ",")) already_present=\(alreadyPresentSymbols.joined(separator: ",")) rejected=\(normalized.rejected.joined(separator: ",")) chart_selected=\(updatedChartConfiguration.selectedSymbols.count)",
            source: source,
            action: "pm_watchlist_update"
        )

        return PMConversationWatchlistUpdateResult(
            operation: operation,
            requestedSymbols: normalized.valid,
            addedSymbols: addedSymbols,
            removedSymbols: removedSymbols,
            alreadyPresentSymbols: alreadyPresentSymbols,
            notPresentSymbols: notPresentSymbols,
            rejectedSymbols: normalized.rejected,
            chartWallSelectedSymbols: updatedChartConfiguration.selectedSymbols,
            chartWallOmittedSymbols: chartWallOmittedSymbols,
            summary: summary,
            detail: detail
        )
    }

    private func normalizedPMConversationWatchlistSymbols(
        _ symbols: [String]
    ) -> (valid: [String], rejected: [String]) {
        let allowed = CharacterSet(charactersIn: "ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789.-")
        var seen: Set<String> = []
        var valid: [String] = []
        var rejected: [String] = []

        for symbol in symbols {
            let normalized = symbol
                .trimmingCharacters(in: .whitespacesAndNewlines)
                .uppercased()
            guard normalized.isEmpty == false else {
                continue
            }
            guard normalized.count <= 32,
                  normalized.unicodeScalars.allSatisfy({ allowed.contains($0) }) else {
                rejected.append(normalized)
                continue
            }
            if seen.insert(normalized).inserted {
                valid.append(normalized)
            }
        }

        return (valid, orderedUniqueStrings(rejected))
    }

    private func normalizedPMConversationWatchlistSymbolHints(_ symbols: [String]) -> [String] {
        orderedUniqueStrings(
            symbols.map {
                $0.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
            }
            .filter { $0.isEmpty == false }
        )
    }

    private func normalizedPMConversationResearchQuestions(
        ownerMessageBody: String,
        action: PMConversationActionIntent,
        title: String,
        rationale: String,
        brief: PMTaskingBrief
    ) -> [String] {
        let ownerQuestions = AnalystTaskQuestionChecklist.questions(
            taskDescription: ownerMessageBody,
            taskingBrief: nil
        )
        if ownerQuestions.count >= 4 {
            return ownerQuestions
        }

        let objectiveContext = [
            title,
            action.summary,
            action.body ?? "",
            brief.taskObjective ?? "",
            brief.reviewLens ?? "",
            brief.challengeInstruction ?? ""
        ]
        .joined(separator: "\n")
        let objectiveQuestions = AnalystTaskQuestionChecklist.questions(
            taskTitle: title,
            taskDescription: objectiveContext,
            taskingBrief: nil
        )
        if objectiveQuestions.isEmpty == false {
            return objectiveQuestions
        }

        return AnalystTaskQuestionChecklist.questions(
            taskTitle: title,
            taskDescription: rationale,
            taskingBrief: brief
        )
    }

    private func inferredPMConversationAnalystSymbols(
        action: PMConversationActionIntent,
        title: String,
        rationale: String,
        brief: PMTaskingBrief?
    ) -> [String] {
        let values = [
            title,
            rationale,
            action.summary,
            action.detail ?? "",
            brief?.taskObjective ?? "",
            brief?.whyNow ?? "",
            brief?.researchQuestions.joined(separator: " ") ?? ""
        ]
        .joined(separator: " ")
        guard let expression = try? NSRegularExpression(pattern: #"(?<![A-Za-z0-9])\$?([A-Z][A-Z0-9.]{1,5})(?![A-Za-z0-9])"#) else {
            return []
        }
        let range = NSRange(values.startIndex..<values.endIndex, in: values)
        var symbols: [String] = []
        var seen = Set<String>()
        for match in expression.matches(in: values, options: [], range: range) {
            guard match.numberOfRanges > 1,
                  let tokenRange = Range(match.range(at: 1), in: values) else {
                continue
            }
            let symbol = String(values[tokenRange])
                .trimmingCharacters(in: CharacterSet(charactersIn: "."))
                .uppercased()
            guard symbol.count >= 2,
                  symbol.count <= 6,
                  isDeniedPMConversationAnalystSymbol(symbol) == false,
                  seen.insert(symbol).inserted else {
                continue
            }
            symbols.append(symbol)
            if symbols.count >= 8 {
                break
            }
        }
        return symbols
    }

    private func normalizedPMConversationAnalystSymbolHints(_ symbols: [String]) -> [String] {
        orderedUniqueStrings(
            normalizedPMConversationWatchlistSymbolHints(symbols)
                .filter { isDeniedPMConversationAnalystSymbol($0) == false }
        )
    }

    private func isDeniedPMConversationAnalystSymbol(_ symbol: String) -> Bool {
        let denied: Set<String> = [
            "AI", "API", "APR", "CEO", "CFO", "COO", "CPI", "EPS", "ETF", "FDA", "FOMC",
            "FY", "GDP", "GTC", "HTTP", "IPO", "IR", "LLM", "MAC", "MVP", "PM", "RSS",
            "SEC", "SIP", "TV", "UI", "UX", "WS"
        ]
        return denied.contains(symbol.uppercased())
    }

    private func resolvedPMConversationActionPlanCharter(
        for action: PMConversationActionIntent
    ) async throws -> AnalystCharter? {
        let charters = try await listAnalystCharters()
        let directHints = [
            trimmedOptionalDecisionText(action.charterId),
            trimmedOptionalDecisionText(action.targetId)
        ].compactMap { $0 }

        for hint in directHints {
            if let exact = charters.first(where: { $0.charterId == hint || $0.analystId == hint }) {
                return exact
            }
        }

        let normalizedDirectHints = Set(directHints.map(pmConversationCharterLookupKey))
        if normalizedDirectHints.isEmpty == false {
            let directMatches = charters.filter { charter in
                normalizedDirectHints.contains(pmConversationCharterLookupKey(charter.charterId))
                    || normalizedDirectHints.contains(pmConversationCharterLookupKey(charter.analystId))
                    || normalizedDirectHints.contains(pmConversationCharterLookupKey(charter.title))
            }
            if directMatches.count == 1 {
                return directMatches[0]
            }
        }

        let textualHints = [
            trimmedOptionalDecisionText(action.summary),
            trimmedOptionalDecisionText(action.title),
            trimmedOptionalDecisionText(action.body),
            trimmedOptionalDecisionText(action.detail)
        ].compactMap { $0 }
        if let canonicalRecentNews = pmConversationCanonicalRecentNewsCharter(
            from: charters,
            hints: directHints + textualHints
        ) {
            return canonicalRecentNews
        }
        let normalizedTextualHints = textualHints.map(pmConversationCharterLookupKey).filter { $0.isEmpty == false }
        for hint in normalizedTextualHints {
            let matches = charters.filter { charter in
                pmConversationCharterTextualHint(hint, uniquelyMatches: charter)
            }
            if matches.count == 1 {
                return matches[0]
            }
        }

        return nil
    }

    private func pmConversationCanonicalRecentNewsCharter(
        from charters: [AnalystCharter],
        hints: [String]
    ) -> AnalystCharter? {
        let combinedHint = pmConversationCharterLookupKey(hints.joined(separator: " "))
        guard combinedHint.contains("charter"),
              combinedHint.contains("recent"),
              combinedHint.contains("analyst") || combinedHint.contains("news") else {
            return nil
        }
        return charters.first(where: { $0.charterId == recentNewsStandingAnalystCharterID })
    }

    private func pmConversationCharterTextualHint(_ hint: String, uniquelyMatches charter: AnalystCharter) -> Bool {
        let keys = [
            pmConversationCharterLookupKey(charter.title),
            pmConversationCharterLookupKey(charter.analystId),
            pmConversationCharterLookupKey(charter.charterId)
        ].filter { $0.isEmpty == false }

        return keys.contains { key in
            hint == key
                || hint.contains(key)
                || (hint.count >= 12 && key.contains(hint))
        }
    }

    private func pmConversationCharterLookupKey(_ text: String) -> String {
        text
            .lowercased()
            .components(separatedBy: CharacterSet.alphanumerics.inverted)
            .filter { $0.isEmpty == false }
            .joined(separator: " ")
    }

    private func pmConversationAnalystCharterDocumentPatch(
        for action: PMConversationActionIntent
    ) -> String? {
        let body = trimmedOptionalDecisionText(action.body)
        let detail = trimmedOptionalDecisionText(action.detail)
        let summary = trimmedOptionalDecisionText(action.summary)
        let title = trimmedOptionalDecisionText(action.title)
        let combinedKey = pmConversationCharterLookupKey(
            [title, summary, body, detail]
                .compactMap { $0 }
                .joined(separator: " ")
        )

        if combinedKey.contains("rss"),
           combinedKey.contains("article"),
           combinedKey.contains("material"),
           (combinedKey.contains("linked") || combinedKey.contains("source")) {
            return """
            ## Material RSS Source-Article Review
            - When an app-ingested RSS/news item appears potentially material, open and review the linked source article when accessible before finalizing significance.
            - Do not rely only on the app-ingested headline, snippet, or summary for material conclusions when a source link exists.
            - If the linked article cannot be accessed, state that limitation explicitly in the memo/report.
            - Distinguish what came from the app-ingested RSS trigger from what was confirmed through source-article review and supplemental research.
            """
        }

        guard let patch = body ?? detail else { return nil }
        if patch.hasPrefix("#") {
            return patch
        }

        let heading = title ?? "PM Conversation Charter Update"
        return """
        ## \(boundedConversationText(heading, limit: 120))
        \(patch)
        """
    }

    private func mergedPMConversationAnalystCharterDocumentBody(
        existing: String,
        patch: String,
        fallbackTitle: String?
    ) -> String {
        let trimmedExisting = existing.trimmingCharacters(in: .whitespacesAndNewlines)
        let trimmedPatch = patch.trimmingCharacters(in: .whitespacesAndNewlines)
        guard trimmedPatch.isEmpty == false else { return trimmedExisting }
        if trimmedExisting.isEmpty {
            return trimmedPatch
        }

        let existingKey = pmConversationCharterLookupKey(trimmedExisting)
        let patchKey = pmConversationCharterLookupKey(trimmedPatch)
        if patchKey.isEmpty == false,
           existingKey.contains(patchKey) {
            return trimmedExisting
        }

        if trimmedPatch.hasPrefix("#") {
            return "\(trimmedExisting)\n\n\(trimmedPatch)"
        }

        let heading = trimmedOptionalDecisionText(fallbackTitle) ?? "PM Conversation Charter Update"
        return """
        \(trimmedExisting)

        ## \(boundedConversationText(heading, limit: 120))
        \(trimmedPatch)
        """
    }

    private func pmConversationAnalystCharterDocumentBodyContainsPatch(
        _ body: String,
        patch: String
    ) -> Bool {
        let bodyKey = pmConversationCharterLookupKey(body)
        let patchKey = pmConversationCharterLookupKey(patch)
        guard bodyKey.isEmpty == false,
              patchKey.isEmpty == false else {
            return false
        }
        return bodyKey.contains(patchKey)
    }

    private func resolvedAnalystMemoForWorkerLaunchResult(
        _ launchResult: AnalystWorkerLaunchResult,
        fallbackDelegationId: String?,
        fallbackTaskId: String?
    ) async -> AnalystMemo? {
        if let memoID = launchResult.memoId,
           let memo = try? await getAnalystMemo(id: memoID) {
            return memo
        }

        let refreshed = (try? await analystMemoStore.reloadFromDisk()) ?? []
        if let memoID = launchResult.memoId,
           let memo = refreshed.first(where: { $0.memoId == memoID }) {
            return memo
        }

        let delegationID = launchResult.delegationId ?? fallbackDelegationId
        let taskID = launchResult.taskId ?? fallbackTaskId
        return refreshed
            .filter { memo in
                (delegationID != nil && memo.delegationId == delegationID)
                    || (taskID != nil && memo.taskId == taskID)
            }
            .sorted { lhs, rhs in
                if lhs.updatedAt == rhs.updatedAt { return lhs.memoId < rhs.memoId }
                return lhs.updatedAt > rhs.updatedAt
            }
            .first
    }

    private func makePMConversationAnalystFollowThroughBody(
        _ followThrough: PMConversationAnalystFollowThrough,
        session: PMCommunicationSession,
        runtimeSelection: ResolvedRuntimeSelection,
        source: AuditEventSource
    ) async -> String? {
        if let existing = try? await existingCanonicalPMDelegationFollowThroughBody(
            delegationId: followThrough.delegationId
        ) {
            return existing
        }

        let generated: String?
        if let synthesized = await synthesizePMConversationAnalystFollowThroughBodyIfPossible(
            followThrough,
            session: session,
            runtimeSelection: runtimeSelection
        ) {
            generated = synthesized
        } else {
            generated = makeFallbackPMConversationAnalystFollowThroughBody(followThrough)
        }
        guard let generated else { return nil }
        let body = sanitizedOwnerFacingPMFollowThroughBody(generated)
        guard body.isEmpty == false else { return nil }
        try? await recordPMDelegationFollowThroughCanonicalBody(
            delegationId: followThrough.delegationId,
            body: body,
            source: source
        )
        return body
    }

    private func existingCanonicalPMDelegationFollowThroughBody(
        delegationId: String
    ) async throws -> String? {
        let delegation = try await getPMDelegation(id: delegationId)
        guard let body = delegation.followThrough?.canonicalBody?
            .trimmingCharacters(in: .whitespacesAndNewlines),
              body.isEmpty == false else {
            return nil
        }
        return sanitizedOwnerFacingPMFollowThroughBody(body)
    }

    private func makeFallbackPMConversationAnalystFollowThroughBody(
        _ followThrough: PMConversationAnalystFollowThrough
    ) -> String? {
        let analystLabel = trimmedOptionalDecisionText(followThrough.charterTitle) ?? "analyst"
        let delegationLabel = trimmedOptionalDecisionText(followThrough.delegationTitle)
        let intro = delegationLabel.map {
            "The \(analystLabel) work is back on \($0). I could not run PM synthesis for the follow-through, so I’m giving you a compact fallback summary here; the full analyst memo stays in PM Inbox."
        } ?? "The \(analystLabel) work is back. I could not run PM synthesis for the follow-through, so I’m giving you a compact fallback summary here; the full analyst memo stays in PM Inbox."

        var paragraphs = [intro]
        if followThrough.requestedSkillReferences.isEmpty == false {
            paragraphs.append(
                "Methods used/requested: \(makePMConversationFollowThroughSkillTitleLine(followThrough.requestedSkillReferences))"
            )
        }
        if let memo = followThrough.memo {
            let presentation = makeAnalystMemoReadablePresentation(memo)
            paragraphs.append("Bottom line: \(boundedConversationText(presentation.executiveSummary, limit: 520))")
            if memo.questionCoverage.isEmpty == false {
                paragraphs.append(makePMConversationAnalystQuestionDigest(memo.questionCoverage))
            }
            paragraphs.append("Current view: \(boundedConversationText(presentation.currentView, limit: 420))")
            paragraphs.append("Recommended next step: \(boundedConversationText(presentation.recommendedNextStep, limit: 360))")
            if presentation.confidenceSummary.isEmpty == false {
                paragraphs.append("Confidence: \(presentation.confidenceSummary)")
            }
            paragraphs.append("For source detail, open PM Inbox / Recent Analyst Activity or ask me for a deeper drill-down on any one question.")
        } else {
            let memoTitle = trimmedOptionalDecisionText(followThrough.launchResult.memoTitle)
            let completedText = memoTitle.map {
                "The worker reported that \"\(boundedConversationText($0, limit: 140))\" completed, but the app could not load the durable analyst memo in time to run PM synthesis for this follow-through."
            } ?? "The analyst worker reported completion, but the app could not load the durable analyst memo in time to run PM synthesis for this follow-through."
            paragraphs.append(completedText)
            paragraphs.append("No order, proposal, or trading action was created from this follow-through. Open PM Inbox / Recent Analyst Activity for the full analyst memo, or ask me to retry the PM synthesis once the memo is visible.")
        }

        let body = paragraphs
            .map { $0.trimmingCharacters(in: CharacterSet.whitespacesAndNewlines) }
            .filter { $0.isEmpty == false }
            .joined(separator: "\n\n")
        return body.isEmpty ? nil : body
    }

    private func synthesizePMConversationAnalystFollowThroughBodyIfPossible(
        _ followThrough: PMConversationAnalystFollowThrough,
        session: PMCommunicationSession,
        runtimeSelection: ResolvedRuntimeSelection
    ) async -> String? {
        guard let memo = followThrough.memo else {
            return nil
        }
        let credentialResolution = llmCredentialResolution(
            providerKind: runtimeSelection.effectiveProviderKind,
            credentialProfileId: runtimeSelection.effectiveCredentialProfileId
        )
        guard let apiKey = credentialResolution.apiKey else {
            return nil
        }

        let analystLabel = trimmedOptionalDecisionText(followThrough.charterTitle) ?? "analyst"
        let taskLabel = trimmedOptionalDecisionText(followThrough.delegationTitle) ?? memo.title
        let request = PMConversationOpenAISynthesisRequest(
            runtimeIdentifier: runtimeSelection.effectiveRuntimeIdentifier,
            reasoningMode: runtimeSelection.effectiveReasoningMode,
            plannerMode: "analyst_follow_through_synthesis",
            sessionChannel: session.channel.rawValue,
            ownerMessageBody: """
            A PM-requested \(analystLabel) task completed: \(taskLabel).

            Synthesize the analyst result for the owner. Use your PM judgment to decide what matters and what to emphasize; the analyst memo, question coverage, and source summary are context for your reasoning, not a deterministic script or a content block to paste. Write a compact executive brief with the key answers, the most important unresolved gaps, and any source caveats you judge material. The full report is available in PM Inbox / Recent Analyst Activity. Keep the reply useful and owner-facing, and do not create trading authority, proposals, approvals, or orders.
            """,
            analystArtifactSummary: pmConversationAnalystFollowThroughSynthesisArtifacts(followThrough),
            operatingContextSummary: [
                "analyst_follow_through_contract=PM LLM synthesizes the completed analyst result for the owner. Deterministic code supplies app-owned memo/question/source truth and records delivery, but does not decide the wording, facts deserving emphasis, or final summary structure.",
                "full_report_location=PM Inbox / Recent Analyst Activity contains the complete memo, source details, evidence, skill usage, and question coverage."
            ]
        )
        do {
            let output = try await synthesizePMConversationModelReply(
                request: request,
                apiKey: apiKey,
                runtimeSelection: runtimeSelection
            )
            let body = output.replyBody.trimmingCharacters(in: .whitespacesAndNewlines)
            guard body.isEmpty == false else {
                return nil
            }
            return body
        } catch {
            return nil
        }
    }

    private func pmConversationAnalystFollowThroughSynthesisArtifacts(
        _ followThrough: PMConversationAnalystFollowThrough
    ) -> [String] {
        var artifacts: [String] = []
        if followThrough.requestedSkillReferences.isEmpty == false {
            artifacts.append("Requested methods/skills: \(makePMTaskingSelectedSkillReferencesLine(followThrough.requestedSkillReferences))")
        }
        guard let memo = followThrough.memo else {
            artifacts.append("Launch result: \(boundedConversationText(followThrough.launchResult.summary, limit: 1_000))")
            return artifacts
        }
        let presentation = makeAnalystMemoReadablePresentation(memo)
        artifacts.append(
            """
            COMPLETED_AD_HOC_ANALYST_MEMO
            analyst=\(followThrough.charterTitle)
            task=\(followThrough.delegationTitle)
            memoTitle=\(memo.title)
            executiveSummary=\(boundedConversationText(presentation.executiveSummary, limit: 1_200))
            currentView=\(boundedConversationText(presentation.currentView, limit: 1_000))
            evidenceSummary=\(boundedConversationText(memo.evidenceSummary, limit: 1_500))
            uncertaintySummary=\(boundedConversationText(memo.uncertaintySummary, limit: 1_000))
            recommendedNextStep=\(boundedConversationText(presentation.recommendedNextStep, limit: 800))
            confidence=\(presentation.confidenceSummary)
            """
        )
        if memo.questionCoverage.isEmpty == false {
            artifacts.append(
                """
                REQUIRED_QUESTION_COVERAGE
                \(makeAnalystMemoQuestionCoverageBody(memo.questionCoverage))
                """
            )
        }
        if memo.skillUsageSummaries.isEmpty == false {
            artifacts.append(
                """
                METHOD_USAGE
                \(pmConversationAnalystFollowThroughSkillUsageBody(memo.skillUsageSummaries))
                """
            )
        }
        return artifacts
    }

    private func pmConversationAnalystFollowThroughSkillUsageBody(
        _ values: [AgentSkillUsageSummary]
    ) -> String {
        values.prefix(8).map { value in
            let sources = value.referenceSources.isEmpty
                ? ""
                : " sources=\(value.referenceSources.map(\.displayTitle).joined(separator: ", "))"
            return "- \(value.skillTitle): requirement=\(value.requirement.displayTitle) usage=\(value.usage.displayTitle)\(sources). \(boundedConversationText(value.usageSummary, limit: 260))"
        }
        .joined(separator: "\n")
    }

    private func makePMConversationFollowThroughSkillTitleLine(
        _ references: [AgentSkillTaskReference]
    ) -> String {
        let parts = references.prefix(4).map { reference in
            let title = boundedConversationText(reference.skillTitle, limit: 80)
            return "\(title) (\(reference.requirement.displayTitle.lowercased()))"
        }
        let suffix = references.count > 4 ? " +\(references.count - 4) more" : ""
        return (parts.joined(separator: ", ") + suffix)
            .trimmingCharacters(in: .whitespacesAndNewlines)
    }

    private func makePMConversationAnalystQuestionDigest(
        _ coverage: [AnalystQuestionCoverage]
    ) -> String {
        let answerLines = coverage
            .prefix(AnalystTaskQuestionChecklist.maxQuestionCount)
            .map { item -> String in
                let question = boundedConversationText(item.question, limit: 96)
                let answer = boundedConversationText(item.answerSummary, limit: 210)
                return "- \(item.status.displayTitle): \(question) — \(answer)"
            }
        let gaps = coverage.compactMap { item -> String? in
            switch item.status {
            case .answered:
                return nil
            case .partial, .notFound, .blocked, .notAddressed:
                let gap = item.remainingGap?.trimmingCharacters(in: .whitespacesAndNewlines)
                guard let gap, gap.isEmpty == false else {
                    return nil
                }
                return "\(boundedConversationText(item.question, limit: 70)): \(boundedConversationText(gap, limit: 120))"
            }
        }
        var sections: [String] = []
        if answerLines.isEmpty == false {
            sections.append("Direct answers:\n\(answerLines.joined(separator: "\n"))")
        }
        if gaps.isEmpty == false {
            sections.append("Still unresolved:\n\(gaps.prefix(4).map { "- \($0)" }.joined(separator: "\n"))")
        }
        return sections.joined(separator: "\n\n")
    }

    private func sanitizedOwnerFacingPMFollowThroughBody(_ body: String) -> String {
        let normalized = body
            .replacingOccurrences(of: "\r\n", with: "\n")
            .replacingOccurrences(of: "\r", with: "\n")
        let keptLines = normalized
            .split(separator: "\n", omittingEmptySubsequences: false)
            .map(String.init)
            .filter { line in
                pmFollowThroughLineContainsInternalMetadata(line) == false
            }
        return keptLines
            .joined(separator: "\n")
            .replacingOccurrences(of: "\n{3,}", with: "\n\n", options: .regularExpression)
            .trimmingCharacters(in: .whitespacesAndNewlines)
    }

    private func pmFollowThroughLineContainsInternalMetadata(_ line: String) -> Bool {
        let lowered = line.lowercased()
        let markers = [
            "alpaca_analyst_worker",
            "run-once succeeded",
            "progress_event:",
            "charter_seeded:",
            "openai_key_configured:",
            "used_openai:",
            "pm_id:",
            "delegation_id:",
            "analyst_id:",
            "charter_id:",
            "task_id:",
            "resolved_runtime_",
            "actual_runtime_",
            "runtime_launched_at:",
            "evidence_bundle_id:",
            "finding_id:",
            "drafted_signal_id:",
            "drafted_proposal_id:",
            "provider payload",
            "worker run note"
        ]
        if markers.contains(where: { lowered.contains($0) }) {
            return true
        }
        let rawIDPatterns = [
            #"\b(task|delegation|charter|finding|memo)-[a-z0-9][a-z0-9_-]{10,}\b"#,
            #"\bsig-[a-z0-9][a-z0-9_-]{10,}\b"#,
            #"\b[a-z_]*(task|delegation|charter|finding|memo|signal|evidence_bundle|runtime|provider|worker)[a-z_]*_id\s*[:=]"#
        ]
        return rawIDPatterns.contains { pattern in
            lowered.range(of: pattern, options: .regularExpression) != nil
        }
    }

    private func shouldDeliverPMDelegationFollowThrough(delegationId: String) async throws -> Bool {
        let delegation = try await getPMDelegation(id: delegationId)
        return delegation.followThrough?.status != .delivered
    }

    private func recordPMDelegationFollowThroughCanonicalBody(
        delegationId: String,
        body: String,
        source: AuditEventSource
    ) async throws {
        var delegation = try await getPMDelegation(id: delegationId)
        let now = nowDate()
        var followThrough = delegation.followThrough ?? PMDelegationFollowThrough(
            status: .pending,
            sourceCommunicationSessionId: delegation.sourceCommunicationSessionId,
            sourceCommunicationMessageId: delegation.sourceCommunicationMessageId,
            requestedAt: delegation.createdAt,
            updatedAt: now
        )
        if followThrough.canonicalBody?.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty != false {
            followThrough.canonicalBody = sanitizedOwnerFacingPMFollowThroughBody(body)
            followThrough.canonicalBodyCreatedAt = now
        }
        followThrough.updatedAt = now
        delegation.followThrough = followThrough
        delegation.updatedAt = now
        _ = try await upsertPMDelegation(delegation, source: source)
    }

    private func recordPMDelegationFollowThroughDelivery(
        delegationId: String,
        deliveredMessage: PMCommunicationMessage,
        summary: String,
        source: AuditEventSource
    ) async throws {
        var delegation = try await getPMDelegation(id: delegationId)
        let now = nowDate()
        var followThrough = delegation.followThrough ?? PMDelegationFollowThrough(
            status: .pending,
            sourceCommunicationSessionId: delegation.sourceCommunicationSessionId,
            sourceCommunicationMessageId: delegation.sourceCommunicationMessageId,
            requestedAt: delegation.createdAt,
            updatedAt: now
        )
        followThrough.status = .delivered
        followThrough.lastDeliveryAttemptAt = deliveredMessage.sentAt
        followThrough.deliveredMessageId = deliveredMessage.messageId
        followThrough.deliverySummary = boundedConversationText(summary, limit: 420)
        if followThrough.canonicalBody?.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty != false {
            followThrough.canonicalBody = sanitizedOwnerFacingPMFollowThroughBody(summary)
            followThrough.canonicalBodyCreatedAt = deliveredMessage.sentAt
        }
        if let session = try? await getPMCommunicationSession(id: deliveredMessage.sessionId),
           session.channel == .telegram || session.channel == .mockTelegram {
            followThrough.telegramDeliveredMessageId = deliveredMessage.messageId
            followThrough.telegramFailureReason = nil
        }
        followThrough.failureReason = nil
        followThrough.updatedAt = now
        delegation.followThrough = followThrough
        delegation.updatedAt = now
        _ = try await upsertPMDelegation(delegation, source: source)
    }

    private func recordPMDelegationFollowThroughFailure(
        delegationId: String,
        reason: String,
        source: AuditEventSource
    ) async throws {
        var delegation = try await getPMDelegation(id: delegationId)
        let now = nowDate()
        var followThrough = delegation.followThrough ?? PMDelegationFollowThrough(
            status: .pending,
            sourceCommunicationSessionId: delegation.sourceCommunicationSessionId,
            sourceCommunicationMessageId: delegation.sourceCommunicationMessageId,
            requestedAt: delegation.createdAt,
            updatedAt: now
        )
        followThrough.status = .failed
        followThrough.lastDeliveryAttemptAt = now
        followThrough.failureReason = boundedConversationText(reason, limit: 260)
        followThrough.telegramFailureReason = boundedConversationText(reason, limit: 260)
        followThrough.updatedAt = now
        delegation.followThrough = followThrough
        delegation.updatedAt = now
        _ = try await upsertPMDelegation(delegation, source: source)
    }

    private struct PMConversationProposalUpsertOutcome: Sendable, Equatable {
        let proposal: StrategyProposal
        let symbol: String?
        let wasCreated: Bool
    }

    private func makePMConversationGovernedWorkflowFollowThroughBody(
        _ context: PMConversationAppliedActionContext
    ) -> String? {
        var paragraphs: [String] = []

        if let proposal = context.lastProposal {
            let boundedTitle = boundedConversationText(proposal.title, limit: 140)
            if context.lastProposalWasCreated {
                paragraphs.append("I drafted the governed proposal \"\(boundedTitle)\" in the normal \(proposal.intendedEnvironmentPaperOnly ? "paper" : "strategy") path.")
            } else {
                paragraphs.append("I updated the governed proposal \"\(boundedTitle)\" in the normal app-owned path.")
            }
            if proposal.approval.status == .draft {
                paragraphs.append("It remains a draft until it goes through the existing proposal review step.")
            }
        }

        for update in context.watchlistUpdates {
            paragraphs.append(update.summary)
            let detail = boundedConversationText(update.detail, limit: 320)
            if detail.isEmpty == false,
               detail.caseInsensitiveCompare(update.summary) != .orderedSame {
                paragraphs.append(detail)
            }
        }

        for update in context.charterUpdates {
            paragraphs.append(update.summary)
            let detail = boundedConversationText(update.detail, limit: 360)
            if detail.isEmpty == false,
               detail.caseInsensitiveCompare(update.summary) != .orderedSame {
                paragraphs.append(detail)
            }
        }

        if let approvalRequest = context.lastApprovalRequest {
            if approvalRequest.status == .resolved,
               approvalRequest.ownerResponse == .approved {
                paragraphs.append(
                    "I recorded your explicit approval on the PM ask \"\(boundedConversationText(approvalRequest.subject, limit: 140))\"."
                )
                if let pendingExecution = approvedPendingPaperPortfolioExecutionState(for: approvalRequest) {
                    paragraphs.append(
                        "I requested app-owned market-data recovery for these blocked symbols: \(pendingExecution.missingPriceSymbols.joined(separator: ", "))."
                    )
                    if pendingExecution.automaticRetryEnabled {
                        paragraphs.append(
                            "No new owner approval is required while this approved paper-portfolio execution remains blocked only on usable prices."
                        )
                    }
                }
            } else {
                paragraphs.append(
                    "I created the approval-ready PM ask \"\(boundedConversationText(approvalRequest.subject, limit: 140))\" in the normal owner loop."
                )
            }
            if context.executionAssessment == nil, approvalRequest.status == .pending {
                paragraphs.append(
                    "The next step is the surfaced owner approval ask itself. No governed routing or paper-trade execution runs until that response is on record."
                )
            }
        } else if let decision = context.lastDecision,
                  context.lastProposal != nil || context.executionAssessment == nil {
            paragraphs.append(
                "I recorded the bounded PM recommendation \"\(boundedConversationText(decision.title, limit: 140))\" in the PM layer."
            )
        }

        if let assessment = context.executionAssessment {
            paragraphs.append(assessment.summary)
            let detail = boundedConversationText(assessment.detail, limit: 260)
            if detail.isEmpty == false,
               detail.caseInsensitiveCompare(assessment.summary) != .orderedSame {
                paragraphs.append(detail)
            }
        }

        let body = paragraphs
            .map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
            .filter { $0.isEmpty == false }
            .joined(separator: "\n\n")
        return body.isEmpty ? nil : body
    }

    private func resolvedPMConversationProposal(
        for action: PMConversationActionIntent,
        context: PMConversationAppliedActionContext
    ) async throws -> StrategyProposal? {
        if let targetId = trimmedOptionalDecisionText(action.targetId) {
            if let proposal = try await proposalStore.getProposal(id: targetId) {
                return proposal
            }
            if let request = try? await getPMApprovalRequest(id: targetId),
               let proposalId = trimmedOptionalDecisionText(request.proposalId),
               let proposal = try await proposalStore.getProposal(id: proposalId) {
                return proposal
            }
            if let decision = try? await getPMDecision(id: targetId),
               let proposalId = trimmedOptionalDecisionText(decision.proposalId),
               let proposal = try await proposalStore.getProposal(id: proposalId) {
                return proposal
            }
        }

        guard let proposalId = context.lastProposal?.proposalId else { return nil }
        return try await proposalStore.getProposal(id: proposalId) ?? context.lastProposal
    }

    private func resolvedPMConversationProposalID(
        for action: PMConversationActionIntent,
        context: PMConversationAppliedActionContext
    ) async throws -> String? {
        try await resolvedPMConversationProposal(for: action, context: context)?.proposalId
    }

    private func upsertPMConversationProposal(
        action: PMConversationActionIntent,
        context: PMConversationAppliedActionContext,
        ownerMessage: PMCommunicationMessage,
        actor: String,
        source: AuditEventSource
    ) async throws -> PMConversationProposalUpsertOutcome? {
        let existing = try await resolvedPMConversationProposal(for: action, context: context)
        if let existing, existing.approval.status != .draft {
            return nil
        }

        let normalizedSymbol = normalizedPMConversationProposalSymbol(
            action.proposalSymbol
                ?? existing?.scope.symbols?.first
                ?? existing?.parameters["symbol"]?.stringValue
        )
        guard existing != nil || normalizedSymbol != nil else {
            return nil
        }

        let now = nowDate()
        let side = action.proposalSide
            ?? pmConversationProposalSide(from: existing?.parameters["side"]?.stringValue)
            ?? .buy
        let quantity = max(1, action.proposalQuantity ?? existing?.parameters["qty"]?.intValue ?? 1)
        let summary = trimmedOptionalDecisionText(action.summary)
            ?? existing?.summary
            ?? "Bounded PM proposal drafted from conversation."
        let title = trimmedOptionalDecisionText(action.title)
            ?? existing?.title
            ?? pmConversationProposalTitle(symbol: normalizedSymbol, side: side)
        let rationale = trimmedOptionalDecisionText(action.body)
            ?? trimmedOptionalDecisionText(action.detail)
            ?? existing?.rationale
            ?? ownerMessage.body

        var parameters = existing?.parameters ?? [:]
        if existing == nil || existing?.strategyId == "paper_oneshot" {
            parameters["enableTrading"] = .bool(true)
            if let normalizedSymbol {
                parameters["symbol"] = .string(normalizedSymbol)
            }
            parameters["qty"] = .number(Double(quantity))
            parameters["side"] = .string(side.rawValue)
            parameters["type"] = .string(parameters["type"]?.stringValue ?? "market")
        }

        var metadata = existing?.metadata ?? [:]
        metadata["sourceCommunicationSessionId"] = .string(ownerMessage.sessionId)
        metadata["sourceCommunicationMessageId"] = .string(ownerMessage.messageId)
        metadata["pmConversationPlannedAction"] = .string(PMConversationActionType.createOrUpdateProposal.rawValue)

        let proposal = StrategyProposal(
            proposalId: existing?.proposalId ?? "pm-proposal-\(UUID().uuidString.lowercased())",
            createdAt: existing?.createdAt ?? now,
            updatedAt: now,
            createdBy: existing?.createdBy ?? actor,
            title: title,
            summary: summary,
            strategyId: existing?.strategyId ?? "paper_oneshot",
            parameters: parameters,
            scope: StrategyProposalScope(
                symbols: normalizedSymbol.map { [$0] } ?? existing?.scope.symbols,
                watchlistReference: existing?.scope.watchlistReference
            ),
            intendedEnvironmentPaperOnly: existing?.intendedEnvironmentPaperOnly ?? true,
            constraints: existing?.constraints ?? StrategyProposalConstraints(
                maxOrdersPerMinute: 1,
                maxNotionalPerOrder: Decimal(10_000),
                maxDailyNotional: Decimal(10_000),
                allowShort: side == .sell,
                allowOptions: false
            ),
            testPlan: existing?.testPlan ?? StrategyProposalTestPlan(
                durationMinutes: 60,
                successMetrics: ["paper_path_validated", "no_safety_breaks"],
                stopConditions: ["manual_stop", "unexpected_errors"]
            ),
            rationale: rationale,
            metadata: metadata,
            originatingSignalId: existing?.originatingSignalId,
            analystLineage: existing?.analystLineage,
            approval: existing?.approval ?? StrategyProposalApproval(status: .draft),
            runResult: existing?.runResult
        )

        let stored = try await upsertProposal(proposal, source: source)
        return PMConversationProposalUpsertOutcome(
            proposal: stored,
            symbol: normalizedSymbol,
            wasCreated: existing == nil
        )
    }

    private func linkPMApprovalRequestToLatestProposalIfNeeded(
        _ request: PMApprovalRequest,
        context: PMConversationAppliedActionContext,
        source: AuditEventSource
    ) async throws -> PMApprovalRequest {
        guard trimmedOptionalDecisionText(request.proposalId) == nil,
              let proposal = context.lastProposal else {
            return request
        }

        let now = nowDate()
        var updatedRequest = request
        updatedRequest.proposalId = proposal.proposalId
        updatedRequest.updatedAt = now
        let storedRequest = try await upsertPMApprovalRequest(updatedRequest, source: source)

        if let decisionId = trimmedOptionalDecisionText(storedRequest.decisionId),
           var decision = try? await getPMDecision(id: decisionId),
           trimmedOptionalDecisionText(decision.proposalId) == nil {
            decision.proposalId = proposal.proposalId
            decision.updatedAt = now
            _ = try await upsertPMDecision(decision, source: source)
        }

        return storedRequest
    }

    private func resolvedPMConversationDecisionID(
        for action: PMConversationActionIntent,
        context: PMConversationAppliedActionContext,
        ownerMessage _: PMCommunicationMessage,
        actor _: String,
        source _: AuditEventSource
    ) async throws -> String? {
        if let targetId = trimmedOptionalDecisionText(action.targetId) {
            if (try? await getPMDecision(id: targetId)) != nil {
                return targetId
            }
            if let request = try? await getPMApprovalRequest(id: targetId),
               let decisionId = trimmedOptionalDecisionText(request.decisionId) {
                return decisionId
            }
            let decisions = try await listPMDecisions()
                .filter { trimmedOptionalDecisionText($0.proposalId) == targetId }
                .sorted { lhs, rhs in
                    if lhs.updatedAt == rhs.updatedAt {
                        return lhs.decisionId < rhs.decisionId
                    }
                    return lhs.updatedAt > rhs.updatedAt
                }
            if let decisionId = decisions.first?.decisionId {
                return decisionId
            }
        }
        return context.lastDecisionId
    }

    private func pmApprovalRequestAppearsToBePaperPortfolioEstablishment(
        _ request: PMApprovalRequest
    ) -> Bool {
        guard request.requestType == .portfolioAction || request.requestType == .proposalReview else {
            return false
        }
        let normalizedCombinedText = normalizedPMConversationCueText(
            [
                request.subject,
                request.rationale,
                request.requestedActionSummary,
                request.approvedNextStepSummary
            ]
                .compactMap { $0 }
                .joined(separator: " ")
        )
        guard normalizedCombinedText.contains("paper") else {
            return false
        }
        if normalizedCombinedText.contains("portfolio") == false {
            guard request.requestType == .proposalReview else {
                return false
            }
            let approvedPaperStepMarkers = [
                "approved paper step",
                "approved paper safe next step",
                "paper safe next step",
                "paper safe path",
                "governed paper path"
            ]
            guard approvedPaperStepMarkers.contains(where: { normalizedCombinedText.contains($0) }) else {
                return false
            }
        }
        return normalizedCombinedText.contains("initial paper portfolio")
            || normalizedCombinedText.contains("working paper portfolio")
            || normalizedCombinedText.contains("paper establishment")
            || normalizedCombinedText.contains("establish")
            || normalizedCombinedText.contains("execute")
            || normalizedCombinedText.contains("place")
            || normalizedCombinedText.contains("approved paper step")
            || normalizedCombinedText.contains("paper safe next step")
            || normalizedCombinedText.contains("paper safe path")
    }

    private func resolvedPMConversationApprovalRequestID(
        for action: PMConversationActionIntent,
        context: PMConversationAppliedActionContext
    ) async throws -> String? {
        let requests = try await listPMApprovalRequests()
            .sorted { lhs, rhs in
                if lhs.updatedAt == rhs.updatedAt {
                    return lhs.approvalRequestId < rhs.approvalRequestId
                }
                return lhs.updatedAt > rhs.updatedAt
            }

        if let targetId = trimmedOptionalDecisionText(action.targetId) {
            if requests.contains(where: { $0.approvalRequestId == targetId }) {
                return targetId
            }
            if let request = requests.first(where: { $0.decisionId == targetId }) {
                return request.approvalRequestId
            }
            if let request = requests.first(where: { trimmedOptionalDecisionText($0.proposalId) == targetId }) {
                return request.approvalRequestId
            }
        }

        if let lastApprovalRequestId = context.lastApprovalRequestId {
            return lastApprovalRequestId
        }

        if action.actionType == .approvePMApprovalRequest {
            let pendingPaperEstablishmentRequests = requests.filter { request in
                request.status == .pending
                    && pmApprovalRequestAppearsToBePaperPortfolioEstablishment(request)
            }
            if pendingPaperEstablishmentRequests.count == 1 {
                return pendingPaperEstablishmentRequests[0].approvalRequestId
            }
        }

        if action.actionType == .routeGovernedExecutionNextStep {
            let appOwnedPendingPaperExecutions = requests.filter { request in
                approvedPendingPaperPortfolioExecutionState(for: request) != nil
            }
            if let mostRecentPendingExecution = appOwnedPendingPaperExecutions.first {
                return mostRecentPendingExecution.approvalRequestId
            }

            let approvedPaperEstablishmentRequests = requests.filter { request in
                request.status == .resolved
                    && request.ownerResponse == .approved
                    && pmApprovalRequestAppearsToBePaperPortfolioEstablishment(request)
            }
            if let mostRecentApprovedRequest = approvedPaperEstablishmentRequests.first {
                return mostRecentApprovedRequest.approvalRequestId
            }
        }

        return nil
    }

    private func normalizedPMConversationProposalSymbol(_ value: String?) -> String? {
        guard let value else { return nil }
        let trimmed = value.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        return trimmed.isEmpty ? nil : trimmed
    }

    private func pmConversationProposalSide(from value: String?) -> OrderSide? {
        switch value?.trimmingCharacters(in: .whitespacesAndNewlines).lowercased() {
        case "buy":
            return .buy
        case "sell":
            return .sell
        default:
            return nil
        }
    }

    private func pmConversationProposalTitle(symbol: String?, side: OrderSide) -> String {
        let symbolLabel = symbol ?? "single-name"
        let sideLabel = side == .sell ? "Short" : "Long"
        return "\(sideLabel) paper proposal: \(symbolLabel)"
    }

    private func archiveSupersededConversationInstructions(
        sessionId: String,
        category: String,
        source: AuditEventSource
    ) async throws {
        let messages = try await listPMCommunicationMessages()
            .filter { $0.sessionId == sessionId }
            .sorted { lhs, rhs in
                pmCommunicationMessage(lhs, occurredBefore: rhs)
            }

        for message in messages.reversed() {
            guard message.promotion?.targetType == .instruction,
                  let instructionId = message.promotion?.targetId,
                  let instruction = try await pmInstructionStore.get(id: instructionId),
                  instruction.status == .active,
                  instruction.category == category else {
                continue
            }

            let archived = PMInstruction(
                instructionId: instruction.instructionId,
                pmId: instruction.pmId,
                title: instruction.title,
                body: instruction.body,
                category: instruction.category,
                status: .archived,
                effectiveAt: instruction.effectiveAt,
                sourceAnalystStrategyFollowUpCandidateId: instruction.sourceAnalystStrategyFollowUpCandidateId,
                sourceAnalystStrategyImplicationId: instruction.sourceAnalystStrategyImplicationId,
                sourceAnalystMemoId: instruction.sourceAnalystMemoId,
                sourceAnalystFindingId: instruction.sourceAnalystFindingId,
                sourceAnalystEvidenceBundleId: instruction.sourceAnalystEvidenceBundleId,
                createdAt: instruction.createdAt,
                updatedAt: nowDate()
            )
            _ = try await upsertPMInstruction(archived, source: source)
            break
        }
    }

    private func pmConversationInstructionCategory(
        _ kind: PMConversationInstructionTargetKind
    ) -> String {
        switch kind {
        case .operatingInstruction:
            return "conversation_operating_instruction"
        case .workingPortfolioDefinition:
            return "conversation_working_portfolio_definition"
        }
    }

    private struct PMConversationOperatingTruthSnapshot: Sendable, Equatable {
        let kind: PMConversationOperatingTruthKind
        let summary: String
        let body: String
        let sourceLabel: String
        let sourceMessageId: String?
        let asOf: Date
    }

    private func pmConversationOperatingTruthKind(
        from instructionTargetKind: PMConversationInstructionTargetKind?
    ) -> PMConversationOperatingTruthKind? {
        switch instructionTargetKind {
        case .operatingInstruction:
            return .operatingInstruction
        case .workingPortfolioDefinition:
            return .workingPortfolioDefinition
        case nil:
            return nil
        }
    }

    private func pmConversationLatestConversationOperatingTruthSnapshot(
        kind: PMConversationOperatingTruthKind,
        before latestOwnerMessage: PMCommunicationMessage,
        allMessages: [PMCommunicationMessage]
    ) -> PMConversationOperatingTruthSnapshot? {
        let snapshots = allMessages
            .filter { message in
                message.senderRole == .pm
                    && pmCommunicationMessage(message, occurredBefore: latestOwnerMessage)
            }
            .compactMap { message in
                pmConversationOperatingTruthSnapshot(
                    from: message,
                    expectedKind: kind
                )
            }
        return snapshots.max { lhs, rhs in
            if lhs.asOf == rhs.asOf {
                let lhsTieBreaker = lhs.sourceMessageId ?? lhs.summary
                let rhsTieBreaker = rhs.sourceMessageId ?? rhs.summary
                return lhsTieBreaker < rhsTieBreaker
            }
            return lhs.asOf < rhs.asOf
        }
    }

    private func pmConversationOperatingTruthSnapshot(
        from message: PMCommunicationMessage,
        expectedKind: PMConversationOperatingTruthKind
    ) -> PMConversationOperatingTruthSnapshot? {
        guard let resolution = message.conversationResolution else { return nil }

        let resolvedKind = resolution.operatingTruthKind
            ?? pmConversationOperatingTruthKind(from: resolution.instructionTargetKind)
        if resolvedKind == expectedKind {
            let summary = resolution.operatingTruthSummary
                ?? resolution.workingUnderstandingSummary
                ?? resolution.durableTitle
                ?? resolution.durableBody
                ?? resolution.ambiguitySummary
            let body = resolution.operatingTruthBody
                ?? resolution.durableBody
                ?? resolution.operatingTruthSummary
                ?? resolution.workingUnderstandingSummary
            if let summary, let body {
                return PMConversationOperatingTruthSnapshot(
                    kind: expectedKind,
                    summary: summary,
                    body: body,
                    sourceLabel: resolution.durableTargetType == .pmInstruction
                        ? "bounded PM instruction"
                        : "recent PM conversation state",
                    sourceMessageId: message.messageId,
                    asOf: message.sentAt
                )
            }
        }

        if let pendingAsk = resolution.pendingAsk {
            let pendingKind = pendingAsk.operatingTruthKind
                ?? pmConversationOperatingTruthKind(from: pendingAsk.instructionTargetKind)
            if pendingKind == expectedKind {
                let summary = pendingAsk.operatingTruthSummary
                    ?? pendingAsk.workingUnderstandingSummary
                    ?? pendingAsk.promptSummary
                return PMConversationOperatingTruthSnapshot(
                    kind: expectedKind,
                    summary: summary,
                    body: summary,
                    sourceLabel: "recent PM open loop",
                    sourceMessageId: message.messageId,
                    asOf: message.sentAt
                )
            }
        }

        return nil
    }

    private func pmConversationLatestWorkingPortfolioDefinitionSnapshot(
        latestOwnerMessage: PMCommunicationMessage,
        allMessages: [PMCommunicationMessage],
        contextPack: PMContextPack
    ) -> PMConversationOperatingTruthSnapshot? {
        var candidates: [PMConversationOperatingTruthSnapshot] = []

        if let conversationSnapshot = pmConversationLatestConversationOperatingTruthSnapshot(
            kind: .workingPortfolioDefinition,
            before: latestOwnerMessage,
            allMessages: allMessages
        ) {
            candidates.append(conversationSnapshot)
        }

        if let instruction = pmConversationLatestWorkingPortfolioInstruction(contextPack) {
            candidates.append(
                PMConversationOperatingTruthSnapshot(
                    kind: .workingPortfolioDefinition,
                    summary: instruction.body,
                    body: instruction.body,
                    sourceLabel: "bounded PM instruction",
                    sourceMessageId: nil,
                    asOf: instruction.updatedAt
                )
            )
        }

        if let reconstructed = pmConversationReconstructedWorkingPortfolioSnapshot(
            before: latestOwnerMessage,
            allMessages: allMessages
        ) {
            candidates.append(reconstructed)
        }

        return candidates.max { lhs, rhs in
            if lhs.asOf == rhs.asOf {
                return lhs.sourceLabel < rhs.sourceLabel
            }
            return lhs.asOf < rhs.asOf
        }
    }

    private func pmConversationReconstructedWorkingPortfolioSnapshot(
        before latestOwnerMessage: PMCommunicationMessage,
        allMessages: [PMCommunicationMessage]
    ) -> PMConversationOperatingTruthSnapshot? {
        guard let cluster = pmConversationRecentWorkingPortfolioCluster(
            before: latestOwnerMessage,
            allMessages: allMessages
        ), let latest = cluster.last else {
            return nil
        }

        let narrative = pmConversationWorkingPortfolioNarrative(from: cluster)
        guard narrative.isEmpty == false else { return nil }

        return PMConversationOperatingTruthSnapshot(
            kind: .workingPortfolioDefinition,
            summary: narrative,
            body: narrative,
            sourceLabel: "recent conversation reconstruction",
            sourceMessageId: latest.messageId,
            asOf: latest.sentAt
        )
    }

    private func pmConversationRecentWorkingPortfolioCluster(
        before latestOwnerMessage: PMCommunicationMessage,
        allMessages: [PMCommunicationMessage]
    ) -> [PMCommunicationMessage]? {
        let searchWindow: TimeInterval = 120 * 24 * 60 * 60
        let contextGap: TimeInterval = 14 * 24 * 60 * 60
        let priorMessages = allMessages
            .filter { message in
                message.senderRole != .system
                    && pmCommunicationMessage(message, occurredBefore: latestOwnerMessage)
                    && (
                        message.senderRole != .pm
                            || (
                                pmConversationUsesDeterministicVisibleReplyPath(message) == false
                                    &&
                                pmConversationLooksLikeDeterministicHistoryRenderer(message.body) == false
                                    && pmConversationLooksLikeSyntheticConversationRecap(message.body) == false
                            )
                    )
                    && latestOwnerMessage.sentAt.timeIntervalSince(message.sentAt) <= searchWindow
            }
            .sorted { lhs, rhs in
                pmCommunicationMessage(lhs, occurredBefore: rhs)
            }
        guard priorMessages.isEmpty == false else { return nil }

        let scored = priorMessages.enumerated().compactMap { index, message -> (index: Int, score: Int)? in
            let score = pmConversationHistoryAnchorScore(
                for: message,
                askSignals: pmConversationRecoverySignals(from: latestOwnerMessage.body),
                asksForWorkingPortfolio: true,
                currentSessionId: latestOwnerMessage.sessionId
            )
            guard score > 0 else { return nil }
            return (index: index, score: score)
        }
        guard let anchor = scored.max(by: { lhs, rhs in
            if lhs.score == rhs.score {
                return priorMessages[lhs.index].sentAt < priorMessages[rhs.index].sentAt
            }
            return lhs.score < rhs.score
        }) else {
            return nil
        }

        let anchorMessage = priorMessages[anchor.index]
        let anchorSessionMessages = priorMessages.filter { $0.sessionId == anchorMessage.sessionId }
        guard let anchorSessionIndex = anchorSessionMessages.firstIndex(where: { $0.messageId == anchorMessage.messageId }) else {
            return [anchorMessage]
        }

        var lower = anchorSessionIndex
        var upper = anchorSessionIndex
        let anchorTokens = pmConversationRecoverySignals(from: anchorMessage.body)
        let supersedingCorrection = pmConversationLooksLikeSupersedingCorrection(anchorMessage.body)

        if supersedingCorrection == false {
            while lower > 0 && (upper - lower + 1) < 6 {
                let candidate = anchorSessionMessages[lower - 1]
                let topicOverlap = anchorTokens.intersection(pmConversationRecoverySignals(from: candidate.body))
                let replyLinked = candidate.replyToMessageId == anchorSessionMessages[lower].messageId
                    || anchorSessionMessages[lower].replyToMessageId == candidate.messageId
                let closeGap = anchorSessionMessages[lower].sentAt.timeIntervalSince(candidate.sentAt) <= contextGap
                if pmConversationWorkingPortfolioSignalScore(candidate.body) > 0
                    || replyLinked
                    || (closeGap && topicOverlap.isEmpty == false) {
                    lower -= 1
                } else {
                    break
                }
            }
        }

        while upper < anchorSessionMessages.count - 1 && (upper - lower + 1) < 6 {
            let candidate = anchorSessionMessages[upper + 1]
            let topicOverlap = anchorTokens.intersection(pmConversationRecoverySignals(from: candidate.body))
            let replyLinked = candidate.replyToMessageId == anchorSessionMessages[upper].messageId
                || anchorSessionMessages[upper].replyToMessageId == candidate.messageId
            let closeGap = candidate.sentAt.timeIntervalSince(anchorSessionMessages[upper].sentAt) <= contextGap
            if pmConversationWorkingPortfolioSignalScore(candidate.body) > 0
                || replyLinked
                || (closeGap && topicOverlap.isEmpty == false) {
                upper += 1
            } else {
                break
            }
        }

        let cluster = Array(anchorSessionMessages[lower...upper])
        return cluster.isEmpty ? nil : cluster
    }

    private func pmConversationWorkingPortfolioSignalScore(_ body: String) -> Int {
        let normalized = body.lowercased()
        var score = 0
        var hasPortfolioCue = false

        if normalized.contains("initial paper portfolio") { score += 6; hasPortfolioCue = true }
        if normalized.contains("paper portfolio") { score += 5; hasPortfolioCue = true }
        if normalized.contains("working paper portfolio") { score += 5; hasPortfolioCue = true }
        if normalized.contains("working portfolio") { score += 4; hasPortfolioCue = true }
        if normalized.contains("current proposed paper portfolio") { score += 5; hasPortfolioCue = true }
        if normalized.contains("portfolio definition") || normalized.contains("portfolio structure") { score += 4; hasPortfolioCue = true }
        if normalized.contains("long sleeve") || normalized.contains("short sleeve") || normalized.contains("hedge sleeve") { score += 3; hasPortfolioCue = true }
        if normalized.contains("gross") || normalized.contains("deployed") || normalized.contains("cash buffer") { score += 2; hasPortfolioCue = true }
        if normalized.contains("short side") || normalized.contains("long side") { score += 2; hasPortfolioCue = true }
        if normalized.contains("long positions:") || normalized.contains("short positions:") { score += 5; hasPortfolioCue = true }
        if pmConversationLooksLikeExplicitWorkingPortfolioStatement(body) { score += 6; hasPortfolioCue = true }
        if hasPortfolioCue && pmConversationLooksLikeDirective(body) { score += 2 }

        let symbolCount = pmConversationDirectiveSymbolCandidates(
            in: body.replacingOccurrences(of: "#", with: "")
        ).count
        score += hasPortfolioCue ? min(symbolCount, 4) : 0
        return score
    }

    private func pmConversationLooksLikeExplicitWorkingPortfolioStatement(_ body: String) -> Bool {
        let normalized = body.lowercased()
        let hasPortfolioLeadIn = normalized.contains("here is the current proposed paper portfolio")
            || normalized.contains("here is our current proposed paper portfolio")
            || normalized.contains("here is the current paper portfolio")
            || normalized.contains("the current proposed paper portfolio")
            || normalized.contains("current proposed paper portfolio")
        let hasLongShortList = normalized.contains("long positions:")
            || normalized.contains("short positions:")
            || normalized.contains("long sleeve:")
            || normalized.contains("short sleeve:")
            || normalized.contains("long side:")
            || normalized.contains("short side:")
        let symbolCount = pmConversationDirectiveSymbolCandidates(
            in: body.replacingOccurrences(of: "#", with: "")
        ).count
        return (hasLongShortList && symbolCount >= 3)
            || (hasPortfolioLeadIn && hasLongShortList)
    }

    private func pmConversationLooksLikeSupersedingCorrection(_ body: String) -> Bool {
        let normalized = body.lowercased()
        return normalized.contains("correction")
            || normalized.contains("replace")
            || normalized.contains("swap")
            || normalized.contains("instead")
            || normalized.contains("drop")
            || normalized.contains("remove")
    }

    private func pmConversationWorkingPortfolioNarrative(
        from messages: [PMCommunicationMessage]
    ) -> String {
        let combined = messages.map(\.body).joined(separator: " ")
        return pmConversationWorkingPortfolioNarrative(fromText: combined)
    }

    private func pmConversationWorkingPortfolioNarrative(fromText text: String) -> String {
        if let exactListBody = pmConversationExactWorkingPortfolioListBody(fromText: text) {
            return exactListBody
        }

        let cleaned = pmConversationSanitizedWorkingPortfolioText(text)
        guard cleaned.isEmpty == false else { return "" }
        return boundedConversationText(cleaned, limit: 420)
    }

    private func pmConversationExactWorkingPortfolioListBody(fromText text: String) -> String? {
        guard pmConversationLooksLikeExplicitWorkingPortfolioStatement(text) else {
            return nil
        }

        let longLine = pmConversationFirstRegexMatch(
            pattern: "(?im)^\\s*(long positions|long sleeve|long side)\\s*:\\s*(.+)$",
            in: text
        )
        let shortLine = pmConversationFirstRegexMatch(
            pattern: "(?im)^\\s*(short positions|short sleeve|short side)\\s*:\\s*(.+)$",
            in: text
        )

        var segments: [String] = []
        if let longLine {
            segments.append(longLine.trimmingCharacters(in: .whitespacesAndNewlines))
        }
        if let shortLine {
            segments.append(shortLine.trimmingCharacters(in: .whitespacesAndNewlines))
        }

        let body = segments.joined(separator: ". ")
        return body.isEmpty ? nil : body
    }

    private func pmConversationSanitizedWorkingPortfolioText(_ text: String) -> String {
        text
            .replacingOccurrences(of: "**", with: "")
            .replacingOccurrences(of: "#", with: "")
            .replacingOccurrences(of: "||", with: " ")
            .replacingOccurrences(of: "\\b(owner|pm):\\s*", with: "", options: .regularExpression)
            .replacingOccurrences(of: "\\s+", with: " ", options: .regularExpression)
            .trimmingCharacters(in: .whitespacesAndNewlines)
    }

    private func pmConversationFirstRegexMatch(
        pattern: String,
        in text: String
    ) -> String? {
        pmConversationAllRegexMatches(pattern: pattern, in: text).first
    }

    private func pmConversationAllRegexMatches(
        pattern: String,
        in text: String
    ) -> [String] {
        guard let expression = try? NSRegularExpression(pattern: pattern) else {
            return []
        }
        let nsRange = NSRange(text.startIndex..<text.endIndex, in: text)
        return expression.matches(in: text, range: nsRange).compactMap { match in
            Range(match.range, in: text).map { String(text[$0]) }
        }
    }

    private func pmConversationRegexCaptureGroups(
        pattern: String,
        in text: String
    ) -> [[String]] {
        guard let expression = try? NSRegularExpression(pattern: pattern) else {
            return []
        }
        let nsRange = NSRange(text.startIndex..<text.endIndex, in: text)
        return expression.matches(in: text, range: nsRange).map { match in
            (1..<match.numberOfRanges).compactMap { index in
                Range(match.range(at: index), in: text).map { String(text[$0]) }
            }
        }
    }

    private enum PMConversationOperatingContextDetailLevel: Sendable {
        case essential
        case expanded
    }

    private func pmConversationNeedsExpandedOperatingContext(_ ask: String) -> Bool {
        let normalized = ask.lowercased()
        let expandedSignals = [
            "launch",
            "research",
            "analyst",
            "delegate",
            "delegation",
            "charter",
            "proposal",
            "approval",
            "approve",
            "decision",
            "route",
            "execution",
            "execute",
            "runtime",
            "instruction",
            "mandate",
            "13f",
            "sec",
            "filer",
            "filing",
            "costco",
            "add ",
            "remove ",
            "queue",
            "bench"
        ]
        return expandedSignals.contains { normalized.contains($0) }
    }

    private func pmConversationNeedsStandingCandidateContext(_ ask: String) -> Bool {
        let normalized = ask.lowercased()
        let candidateSignals = [
            "standing-review",
            "standing review",
            "candidate",
            "proposal",
            "app truth",
            "working truth",
            "long side",
            "short side",
            "hedge",
            "conviction",
            "reasoning",
            "analyst",
            "report",
            "should we discuss",
            "discuss"
        ]
        return candidateSignals.contains { normalized.contains($0) }
    }

    private func pmConversationNeedsComplementaryRecoveredContext(_ ask: String) -> Bool {
        let normalized = ask.lowercased()
        return normalized.contains("notebook")
            || normalized.contains("promoted")
            || normalized.contains("memory")
            || normalized.contains("note")
            || normalized.contains("standing-review")
            || normalized.contains("standing review")
            || normalized.contains("standing-report review")
            || normalized.contains("standing report review")
    }

    private func pmConversationRelevantAnalystCharterDocumentSummary(
        ask: String,
        analystCharters: [AnalystCharter]
    ) -> [String] {
        let askKey = pmConversationCharterLookupKey(ask)
        guard askKey.contains("charter") else { return [] }
        let visibleCharters = analystCharters.filter { isLegacyDuplicateAnalystCharter($0) == false }
        var selected: [AnalystCharter] = []

        if askKey.contains("recent"),
           askKey.contains("analyst") || askKey.contains("news"),
           let canonicalRecentNews = visibleCharters.first(where: { $0.charterId == recentNewsStandingAnalystCharterID }) {
            selected.append(canonicalRecentNews)
        }

        for charter in visibleCharters {
            let titleKey = pmConversationCharterLookupKey(charter.title)
            let analystKey = pmConversationCharterLookupKey(charter.analystId)
            let charterKey = pmConversationCharterLookupKey(charter.charterId)
            guard selected.contains(where: { $0.charterId == charter.charterId }) == false else {
                continue
            }
            if [titleKey, analystKey, charterKey].contains(where: { key in
                key.isEmpty == false && (askKey.contains(key) || key.contains(askKey))
            }) {
                selected.append(charter)
            }
        }

        return selected
            .prefix(2)
            .map { pmConversationAnalystCharterDocumentTruthSummary($0, askKey: askKey) }
    }

    private func pmConversationAnalystCharterDocumentTruthSummary(
        _ charter: AnalystCharter,
        askKey: String
    ) -> String {
        let body = charter.primaryDocumentBody
        let containsMaterialRSSRule = pmConversationAnalystCharterBodyContainsMaterialRSSSourceArticleRequirement(body)
        let excerpt = pmConversationAnalystCharterDocumentExcerpt(body: body, askKey: askKey)
        return [
            "canonical_analyst_charter id=\(charter.charterId)",
            "analyst=\(charter.analystId)",
            "title=\(charter.title)",
            "updatedAt=\(DateCodec.formatISO8601(charter.updatedAt))",
            "updateSource=\(charter.updateSource.rawValue)",
            "contains_material_rss_source_article_review_rule=\(containsMaterialRSSRule ? "yes" : "no")",
            "current_body_excerpt=\(excerpt)"
        ].joined(separator: " ")
    }

    private func pmConversationAnalystCharterBodyContainsMaterialRSSSourceArticleRequirement(
        _ body: String
    ) -> Bool {
        let key = pmConversationCharterLookupKey(body)
        return key.contains("app ingested")
            && key.contains("rss")
            && key.contains("linked source article")
            && key.contains("material")
            && (key.contains("cannot be accessed") || key.contains("inaccessible"))
    }

    private func pmConversationAnalystCharterDocumentExcerpt(
        body: String,
        askKey: String
    ) -> String {
        let markers: [String]
        if askKey.contains("rss") || askKey.contains("article") || askKey.contains("source") || askKey.contains("material") {
            markers = [
                "## Material RSS Source-Article Review",
                "Material RSS Source-Article Review",
                "Source Policy And Research Conduct",
                "Research Expectations"
            ]
        } else {
            markers = [
                "Source Policy And Research Conduct",
                "Research Expectations",
                "Mission"
            ]
        }

        for marker in markers {
            if let excerpt = pmConversationDocumentExcerpt(around: marker, in: body) {
                return excerpt
            }
        }
        return boundedConversationText(body, limit: 1_500)
    }

    private func pmConversationDocumentExcerpt(
        around marker: String,
        in body: String
    ) -> String? {
        guard let range = body.range(of: marker, options: [.caseInsensitive]) else {
            return nil
        }
        let lowerBound = body.index(
            range.lowerBound,
            offsetBy: -450,
            limitedBy: body.startIndex
        ) ?? body.startIndex
        let upperBound = body.index(
            range.upperBound,
            offsetBy: 1_050,
            limitedBy: body.endIndex
        ) ?? body.endIndex
        return boundedConversationText(String(body[lowerBound..<upperBound]), limit: 1_500)
    }

    private func pmConversationOperatingContextSummary(
        _ contextPack: PMContextPack,
        analystCharters: [AnalystCharter],
        approvalRequests: [PMApprovalRequest],
        proposals: [StrategyProposal],
        detailLevel: PMConversationOperatingContextDetailLevel
    ) -> [String] {
        let queue = contextPack.operatingContext.standingReviewQueue
        let bench = contextPack.operatingContext.standingBench
        var lines: [String] = [
            "pm_operating_guide=Use a valid app-owned analyst/charter target for analyst work. Do not claim work launched without a delegation/task/job. Preserve the owner's research ask; do not invent source restrictions, official-only limits, or bespoke source workflows.",
            "ad_hoc_research_contract=launch_ad_hoc_analyst_delegation requires exact app-owned charterId. Pick the closest valid standing/ad hoc analyst lane when the broad domain fits; do not require a bespoke topical route. Ask which analyst/charter to use only when several plausible targets are materially ambiguous or none fits at all. SEC filer, 13F, or asset-manager holdings research can route to Financials Analyst when available.",
            "source_constraint_contract=The PM action plan is not a source-policy authority. Source restrictions come only from the selected analyst charter, selected skills, explicit owner/task wording, and hard app governance. Do not add source-tier policy text to hidden analyst tasking unless the owner asked for it.",
            "confidence_contract=Low-confidence findings are context for PM judgment and uncertainty framing, not deterministic blockers by themselves."
        ]
        let standingBenchIDs = Set(contextPack.operatingContext.standingBench.map(\.charterId))
        let adHocRoutes = analystCharters
            .filter { standingBenchIDs.contains($0.charterId) == false }
            .sorted { lhs, rhs in
                if lhs.updatedAt == rhs.updatedAt {
                    return lhs.charterId < rhs.charterId
                }
                return lhs.updatedAt > rhs.updatedAt
            }

        let routeDirectoryEntries = orderedUniqueStrings(
            bench.map { "id=\($0.charterId) title=\($0.title)" }
                + adHocRoutes.map { "id=\($0.charterId) title=\($0.title)" }
        )
        if routeDirectoryEntries.isEmpty == false {
            lines.append(
                "available_analyst_routes=\(routeDirectoryEntries.prefix(12).joined(separator: " | "))"
            )
        }
        lines.append("standing_review_queue_pending=\(queue.pendingCount)")
        if contextPack.sharedPortfolioTruth.positionCount > 0 {
            lines.append("portfolio_positions=\(contextPack.sharedPortfolioTruth.positionCount)")
        } else {
            lines.append("portfolio_positions=0")
        }
        if contextPack.sharedPortfolioTruth.watchlistPreview.isEmpty == false {
            lines.append(
                "watchlist=\(contextPack.sharedPortfolioTruth.watchlistPreview.prefix(8).joined(separator: ", "))"
            )
        }

        if detailLevel == .essential {
            let routedApprovalSummaries = approvalRequests
                .filter { $0.lastExecutionRoutingAssessment != nil }
                .sorted { lhs, rhs in
                    if lhs.updatedAt == rhs.updatedAt {
                        return lhs.approvalRequestId < rhs.approvalRequestId
                    }
                    return lhs.updatedAt > rhs.updatedAt
                }
                .prefix(2)
                .compactMap { request -> String? in
                    guard let assessment = request.lastExecutionRoutingAssessment else { return nil }
                    return "id=\(request.approvalRequestId) status=\(assessment.status.rawValue) action=\(assessment.action.rawValue) summary=\(boundedConversationText(assessment.summary, limit: 180))"
                }
            if routedApprovalSummaries.isEmpty == false {
                lines.append(
                    "latest_pm_approval_route_results=\(routedApprovalSummaries.joined(separator: " | "))"
                )
            }
            if approvalRequests.isEmpty == false {
                let approvalRequestIDs = approvalRequests
                    .sorted { lhs, rhs in
                        if lhs.updatedAt == rhs.updatedAt {
                            return lhs.approvalRequestId < rhs.approvalRequestId
                        }
                        return lhs.updatedAt > rhs.updatedAt
                    }
                    .prefix(3)
                    .map(\.approvalRequestId)
                    .joined(separator: ", ")
                lines.append(
                    "approval_request_ids=\(approvalRequestIDs)"
                )
            }
            if proposals.isEmpty == false {
                let proposalIDs = proposals
                    .sorted { lhs, rhs in
                        if lhs.updatedAt == rhs.updatedAt {
                            return lhs.proposalId < rhs.proposalId
                        }
                        return lhs.updatedAt > rhs.updatedAt
                    }
                    .prefix(3)
                    .map(\.proposalId)
                    .joined(separator: ", ")
                lines.append(
                    "proposal_ids=\(proposalIDs)"
                )
            }
            return lines
        }

        let recentDelegations = contextPack.relevantDelegations
            .filter { isExercisePMDelegation($0) == false }
            .sorted { lhs, rhs in
                if lhs.updatedAt == rhs.updatedAt {
                    return lhs.delegationId < rhs.delegationId
                }
                return lhs.updatedAt > rhs.updatedAt
            }
            .prefix(6)
        if recentDelegations.isEmpty == false {
            lines.append(
                "recent_pm_analyst_delegations=\(recentDelegations.map(\.delegationId).joined(separator: ", "))"
            )
            for delegation in recentDelegations {
                let summary = makePMDelegationObservabilitySummary(
                    delegation: delegation,
                    now: contextPack.assembledAt
                )
                let launchStatus = delegation.lastLaunch?.status.rawValue ?? "not_launched"
                let progress = summary.progressSummary.map {
                    " progress=\(boundedConversationText($0, limit: 180))"
                } ?? ""
                let followThroughStatus = delegation.followThrough?.status.rawValue ?? "not_required"
                let deliveredMessage = delegation.followThrough?.deliveredMessageId.map {
                    " delivered_message=\(shortOrderID($0))"
                } ?? ""
                let updated = DateCodec.formatISO8601(delegation.updatedAt)
                lines.append(
                    "pm_analyst_delegation id=\(delegation.delegationId) analyst=\(delegation.analystId) charter=\(delegation.charterId) task=\(delegation.taskId ?? "-") status=\(delegation.status.rawValue) execution=\(summary.executionState.rawValue) launch=\(launchStatus) workflow=\(summary.workflowState.rawValue) follow_through=\(followThroughStatus)\(deliveredMessage) updated=\(updated) title=\(boundedConversationText(delegation.title, limit: 160))\(progress)"
                )
            }
        }

        if bench.isEmpty == false {
            lines.append(
                "analyst_bench_titles=\(bench.prefix(8).map(\.title).joined(separator: ", "))"
            )
            for member in bench.prefix(8) {
                let cadence = member.standingSchedule.enabled
                    ? member.standingSchedule.cadenceSummary
                    : "ad_hoc_only"
                lines.append(
                    "analyst_bench_member id=\(member.charterId) title=\(member.title) analyst=\(member.analystId) coverage=\(boundedConversationText(member.coverageScope, limit: 140)) ad_hoc=\(member.adHocTaskingAvailable ? "yes" : "no") pending_review=\(member.outstandingStandingReviewCount) cadence=\(boundedConversationText(cadence, limit: 80))"
                )
            }
        }

        if adHocRoutes.isEmpty == false {
            lines.append(
                "ad_hoc_analyst_routes=\(adHocRoutes.prefix(4).map(\.title).joined(separator: ", "))"
            )
            for charter in adHocRoutes.prefix(4) {
                lines.append(
                    "analyst_route id=\(charter.charterId) title=\(charter.title) analyst=\(charter.analystId) coverage=\(boundedConversationText(charter.coverageScope, limit: 140))"
                )
            }
        }
        let recentApprovalRequests = approvalRequests
            .sorted { lhs, rhs in
                if lhs.updatedAt == rhs.updatedAt {
                    return lhs.approvalRequestId < rhs.approvalRequestId
                }
                return lhs.updatedAt > rhs.updatedAt
            }
            .prefix(6)
        if recentApprovalRequests.isEmpty == false {
            lines.append(
                "approval_request_ids=\(recentApprovalRequests.map(\.approvalRequestId).joined(separator: ", "))"
            )
            for request in recentApprovalRequests {
                let response = request.ownerResponse?.rawValue ?? "none"
                let proposal = trimmedOptionalDecisionText(request.proposalId) ?? "-"
                let decision = trimmedOptionalDecisionText(request.decisionId) ?? "-"
                lines.append(
                    "approval_request id=\(request.approvalRequestId) type=\(request.requestType.rawValue) status=\(request.status.rawValue) owner_response=\(response) proposal=\(proposal) decision=\(decision) subject=\(boundedConversationText(request.subject, limit: 140))"
                )
            }
        }
        let recentProposals = proposals
            .sorted { lhs, rhs in
                if lhs.updatedAt == rhs.updatedAt {
                    return lhs.proposalId < rhs.proposalId
                }
                return lhs.updatedAt > rhs.updatedAt
            }
            .prefix(6)
        if recentProposals.isEmpty == false {
            lines.append(
                "proposal_ids=\(recentProposals.map(\.proposalId).joined(separator: ", "))"
            )
            for proposal in recentProposals {
                let symbols = proposal.scope.symbols?.prefix(4).joined(separator: ", ") ?? "-"
                lines.append(
                    "proposal id=\(proposal.proposalId) status=\(proposal.approval.status.rawValue) strategy=\(proposal.strategyId) paper_only=\(proposal.intendedEnvironmentPaperOnly ? "yes" : "no") symbols=\(symbols) title=\(boundedConversationText(proposal.title, limit: 140))"
                )
            }
        }
        return lines
    }

    private func pmConversationLatestWorkingPortfolioInstruction(
        _ contextPack: PMContextPack
    ) -> PMInstruction? {
        contextPack.activeInstructions.first {
            $0.category == pmConversationInstructionCategory(.workingPortfolioDefinition)
        }
    }

    private func pmConversationWorkingPortfolioDefinitionSummary(
        latestOwnerMessage: PMCommunicationMessage,
        allMessages: [PMCommunicationMessage],
        contextPack: PMContextPack
    ) -> [String] {
        guard let snapshot = pmConversationLatestWorkingPortfolioDefinitionSnapshot(
            latestOwnerMessage: latestOwnerMessage,
            allMessages: allMessages,
            contextPack: contextPack
        ) else {
            return []
        }

        var line = "Latest conversation-owned working portfolio definition: \(boundedConversationText(snapshot.body, limit: 360))"
        if contextPack.sharedPortfolioTruth.positionCount == 0 {
            line += " Confirmed app holdings still show none recorded, so treat this as the current working definition rather than validated holdings."
        } else {
            line += " This remains separate from the app-confirmed holdings view."
        }
        line += " Source: \(snapshot.sourceLabel)."
        return [line]
    }

    private func pmConversationMayNeedAnalystFullDetailGrounding(_ ask: String) -> Bool {
        let normalizedAsk = ask
            .lowercased()
            .replacingOccurrences(of: "[^a-z0-9]+", with: " ", options: .regularExpression)
            .trimmingCharacters(in: .whitespacesAndNewlines)
        let askSignals = pmConversationRecoverySignals(from: ask)
        let explicitlyNamedSymbols = Set(pmConversationOrderedSymbolCandidates(in: ask))
        return pmConversationLooksLikeLatestReviewedAnalystReportAsk(normalizedAsk: normalizedAsk)
            || pmConversationLooksLikeLatestAnalystSourceAsk(normalizedAsk: normalizedAsk)
            || pmConversationLooksLikeAnalystReportDetailAsk(
            normalizedAsk: normalizedAsk,
            askSignals: askSignals,
            explicitlyNamedSymbols: explicitlyNamedSymbols
        )
    }

    private func pmConversationRelevantAnalystArtifactSummary(
        ask: String,
        latestOwnerMessage: PMCommunicationMessage,
        allMessages: [PMCommunicationMessage],
        contextPack: PMContextPack,
        standingReports: [AnalystStandingReport],
        pmDecisions: [PMDecisionRecord],
        analystMemos: [AnalystMemo],
        analystEvidenceBundles: [AnalystEvidenceBundle]
    ) -> [String] {
        let normalizedAsk = ask
            .lowercased()
            .replacingOccurrences(of: "[^a-z0-9]+", with: " ", options: .regularExpression)
            .trimmingCharacters(in: .whitespacesAndNewlines)
        let workingSnapshot = pmConversationLatestWorkingPortfolioDefinitionSnapshot(
            latestOwnerMessage: latestOwnerMessage,
            allMessages: allMessages,
            contextPack: contextPack
        )
        let queryText = [
            ask,
            workingSnapshot?.summary,
            workingSnapshot?.body
        ]
        .compactMap { $0?.trimmingCharacters(in: .whitespacesAndNewlines) }
        .filter { $0.isEmpty == false }
        .joined(separator: " ")
        let querySignals = pmConversationRecoverySignals(from: queryText)
        let explicitlyNamedSymbols = Set(pmConversationOrderedSymbolCandidates(in: queryText))
        let targetedDetailSummaries = pmConversationTargetedAnalystReportDetailSummaries(
            ask: ask,
            standingReports: standingReports,
            pmDecisions: pmDecisions,
            analystMemos: analystMemos,
            analystEvidenceBundles: analystEvidenceBundles
        )
        let targetedAdHocSourceSummaries = pmConversationTargetedAnalystMemoSourceSummaries(
            ask: ask,
            analystMemos: analystMemos,
            analystEvidenceBundles: analystEvidenceBundles
        )
        let targetedSkillUsageSummaries = pmConversationTargetedAnalystReportSkillUsageSummaries(
            ask: ask,
            contextPack: contextPack,
            standingReports: standingReports,
            pmDecisions: pmDecisions,
            analystMemos: analystMemos
        )
        let targetedDelegationSkillRequestSummaries = pmConversationTargetedAnalystDelegationSkillRequestSummaries(
            ask: ask,
            contextPack: contextPack
        )
        let openBenchFullReportSummaries = pmConversationOpenStandingAnalystBenchFullReportSummaries(
            standingReports: standingReports,
            pmDecisions: pmDecisions,
            analystMemos: analystMemos,
            analystEvidenceBundles: analystEvidenceBundles
        )
        let looksLikeLatestReviewedReportAsk = pmConversationLooksLikeLatestReviewedAnalystReportAsk(
            normalizedAsk: normalizedAsk
        )
        let looksLikeLatestAnalystSourceAsk = pmConversationLooksLikeLatestAnalystSourceAsk(
            normalizedAsk: normalizedAsk
        )
        if targetedSkillUsageSummaries.isEmpty == false {
            var seen = Set<String>()
            return (
                targetedDelegationSkillRequestSummaries
                    + targetedSkillUsageSummaries
                    + targetedDetailSummaries
                    + openBenchFullReportSummaries
            )
                .compactMap { summary in
                    seen.insert(summary).inserted ? summary : nil
                }
        }
        if targetedDelegationSkillRequestSummaries.isEmpty == false {
            var seen = Set<String>()
            return (targetedDelegationSkillRequestSummaries + targetedDetailSummaries + openBenchFullReportSummaries)
                .compactMap { summary in
                    seen.insert(summary).inserted ? summary : nil
                }
        }
        if looksLikeLatestReviewedReportAsk || looksLikeLatestAnalystSourceAsk {
            let laneSummaries = pmConversationAnalystReportLaneRetrieval(
                normalizedAsk: normalizedAsk,
                standingReports: standingReports,
                pmDecisions: pmDecisions
            ).summaries
            if looksLikeLatestAnalystSourceAsk,
               looksLikeLatestReviewedReportAsk == false,
               targetedAdHocSourceSummaries.isEmpty == false {
                var seen = Set<String>()
                return (targetedAdHocSourceSummaries + targetedDetailSummaries + laneSummaries)
                    .compactMap { summary in
                        seen.insert(summary).inserted ? summary : nil
                    }
            }
            guard targetedDetailSummaries.isEmpty == false else {
                var seen = Set<String>()
                return (laneSummaries + openBenchFullReportSummaries)
                    .compactMap { summary in
                        seen.insert(summary).inserted ? summary : nil
                    }
            }
            if looksLikeLatestAnalystSourceAsk && looksLikeLatestReviewedReportAsk == false {
                var seen = Set<String>()
                return (targetedDetailSummaries + laneSummaries)
                    .compactMap { summary in
                        seen.insert(summary).inserted ? summary : nil
                    }
            }
            var seen = Set<String>()
            return (targetedDetailSummaries + laneSummaries + openBenchFullReportSummaries)
                .compactMap { summary in
                    seen.insert(summary).inserted ? summary : nil
                }
        }
        guard querySignals.isEmpty == false || explicitlyNamedSymbols.isEmpty == false else {
            var seen = Set<String>()
            return (targetedDetailSummaries + openBenchFullReportSummaries)
                .compactMap { summary in
                    seen.insert(summary).inserted ? summary : nil
                }
        }

        let workingSymbols = Set(
            workingSnapshot.map { snapshot in
                pmConversationOrderedSymbolCandidates(in: snapshot.body)
            } ?? []
        )
        let asksForReasoningDepth = normalizedAsk.contains("reasoning")
            || normalizedAsk.contains("why")
            || normalizedAsk.contains("conviction")
            || normalizedAsk.contains("case")
            || normalizedAsk.contains("thesis")

        var candidates: [(score: Int, sortDate: Date, summary: String)] = []

        for report in standingReports {
            let analystTitle = report.title
                .replacingOccurrences(of: " Standing Report", with: "")
                .trimmingCharacters(in: .whitespacesAndNewlines)

            for section in report.sections {
                for item in section.items {
                    let textValues = [
                        report.title,
                        report.summary,
                        report.headlineView,
                        report.portfolioRelevanceSummary,
                        section.title,
                        section.summary ?? "",
                        item.symbol ?? "",
                        item.headline,
                        item.detail
                    ]
                    var score = pmConversationRecoveryScore(
                        textValues: textValues,
                        askSignals: querySignals
                    )
                    let directSymbolMatch = item.symbol.map { explicitlyNamedSymbols.contains($0.uppercased()) } ?? false
                    if score <= 0 && directSymbolMatch == false {
                        continue
                    }

                    if let symbol = item.symbol,
                       workingSymbols.contains(symbol.uppercased()) {
                        score += 4
                    }
                    if directSymbolMatch {
                        score += 5
                    }
                    if item.conviction != nil {
                        score += 2
                    }
                    if asksForReasoningDepth,
                       item.detail.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty == false {
                        score += 2
                    }

                    let convictionFragment = item.conviction.map { " Conviction \($0)/10." } ?? ""
                    let symbolFragment = item.symbol.map { "\($0) — " } ?? ""
                    let detail = item.detail.trimmingCharacters(in: .whitespacesAndNewlines)
                    let detailFragment = detail.isEmpty ? "" : " Reasoning: \(openAIResponsesTrimmed(detail, limit: 240))."
                    let summary = "\(symbolFragment)\(analystTitle) / \(section.title): \(openAIResponsesTrimmed(item.headline, limit: 180)).\(convictionFragment)\(detailFragment)"
                    candidates.append((score: score, sortDate: report.updatedAt, summary: summary))
                }
            }
        }

        for memo in contextPack.recentAnalystMemos {
            let textValues = [
                memo.title,
                memo.executiveSummary,
                memo.currentView,
                memo.evidenceSummary,
                memo.uncertaintySummary,
                memo.recommendedNextStep
            ]
            var score = pmConversationRecoveryScore(
                textValues: textValues,
                askSignals: querySignals
            )
            let directSymbolMatch = explicitlyNamedSymbols.contains(where: { symbol in
                [memo.title, memo.executiveSummary, memo.currentView, memo.evidenceSummary, memo.uncertaintySummary, memo.recommendedNextStep]
                    .joined(separator: " ")
                    .uppercased()
                    .contains(symbol)
            })
            guard score > 0 || directSymbolMatch else {
                continue
            }
            if directSymbolMatch {
                score += 4
            }
            if asksForReasoningDepth {
                score += 1
            }
            let summary = "Analyst memo: \(memo.title) — \(openAIResponsesTrimmed(memo.currentView, limit: 220)). Evidence: \(openAIResponsesTrimmed(memo.evidenceSummary, limit: 180))."
            candidates.append((score: score, sortDate: memo.updatedAt, summary: summary))
        }

        for decision in contextPack.recentDecisions {
            var textValues: [String] = [
                decision.title,
                decision.summary,
                decision.recommendedAction ?? ""
            ]
            textValues.append(contentsOf: decision.standingReviewAttentionItems ?? [])
            textValues.append(contentsOf: decision.standingReviewCandidateLongs ?? [])
            textValues.append(contentsOf: decision.standingReviewCandidateShorts ?? [])
            textValues.append(contentsOf: decision.standingReviewCandidateThemes ?? [])
            textValues.append(contentsOf: decision.standingReviewFollowUpItems ?? [])
            textValues.append(contentsOf: decision.standingReviewAnalystTitles ?? [])
            var score = pmConversationRecoveryScore(
                textValues: textValues,
                askSignals: querySignals
            )
            let directSymbolMatch = explicitlyNamedSymbols.contains(where: { symbol in
                textValues.joined(separator: " ").uppercased().contains(symbol)
            })
            guard score > 0 || directSymbolMatch else {
                continue
            }
            if directSymbolMatch {
                score += 3
            }
            if workingSnapshot != nil {
                score += 1
            }
            let summary = "PM standing-review summary: \(decision.title) — \(openAIResponsesTrimmed(decision.summary, limit: 220)). \(openAIResponsesTrimmed(decision.recommendedAction ?? "", limit: 160))"
            candidates.append((score: score, sortDate: decision.updatedAt, summary: summary))
        }

        var rankedSeen = Set<String>()
        let rankedCandidates = candidates
            .sorted { lhs, rhs in
                if lhs.score == rhs.score {
                    if lhs.sortDate == rhs.sortDate {
                        return lhs.summary < rhs.summary
                    }
                    return lhs.sortDate > rhs.sortDate
                }
                return lhs.score > rhs.score
            }
            .compactMap { candidate in
                rankedSeen.insert(candidate.summary).inserted ? candidate.summary : nil
            }
        var seen = Set<String>()
        let baseFullReportSummaries = targetedDetailSummaries + openBenchFullReportSummaries
        let includesFullAnalystReportDocument = baseFullReportSummaries.contains { summary in
            summary.contains("FULL_ANALYST_REPORT_DOCUMENT")
                || summary.contains("FULL_ANALYST_REPORT_DOCUMENTS")
        }
        if includesFullAnalystReportDocument {
            return baseFullReportSummaries
                .compactMap { summary in
                    seen.insert(summary).inserted ? summary : nil
                }
        }
        let maxAnalystArtifactSummaryCount = includesFullAnalystReportDocument
            ? 28
            : (targetedDetailSummaries.isEmpty ? 6 : 10)
        return (baseFullReportSummaries + rankedCandidates)
            .compactMap { summary in
                seen.insert(summary).inserted ? summary : nil
            }
            .prefix(maxAnalystArtifactSummaryCount)
            .map { $0 }
    }

    private func pmConversationTargetedAnalystMemoSourceSummaries(
        ask: String,
        analystMemos: [AnalystMemo],
        analystEvidenceBundles: [AnalystEvidenceBundle]
    ) -> [String] {
        let normalizedAsk = ask
            .lowercased()
            .replacingOccurrences(of: "[^a-z0-9]+", with: " ", options: .regularExpression)
            .trimmingCharacters(in: .whitespacesAndNewlines)
        guard pmConversationLooksLikeLatestAnalystSourceAsk(normalizedAsk: normalizedAsk) else {
            return []
        }

        let askSignals = pmConversationRecoverySignals(from: ask)
        let requestedDefinitions = pmConversationRequestedAnalystDefinitions(
            normalizedAsk: normalizedAsk,
            askSignals: askSignals
        )
        let requestedCharterIDs = Set(requestedDefinitions.map(\.charterId))
        let requestedAnalystIDs = Set(requestedDefinitions.map(\.analystId))
        let bundlesByID = Dictionary(uniqueKeysWithValues: analystEvidenceBundles.map { ($0.bundleId, $0) })

        let scoredMemos = analystMemos.compactMap { memo -> (score: Int, memo: AnalystMemo, bundle: AnalystEvidenceBundle?)? in
            guard isExerciseArtifactIdentifier(memo.memoId) == false else {
                return nil
            }
            let bundle = memo.evidenceBundleId.flatMap { bundlesByID[$0] }
                ?? analystEvidenceBundles
                    .filter { candidate in
                        candidate.taskId == memo.taskId
                            || candidate.charterId == memo.charterId
                            || candidate.analystId == memo.analystId
                    }
                    .sorted { lhs, rhs in
                        if lhs.updatedAt == rhs.updatedAt { return lhs.bundleId < rhs.bundleId }
                        return lhs.updatedAt > rhs.updatedAt
                    }
                    .first
            var score = pmConversationRecoveryScore(
                textValues: [
                    memo.title,
                    memo.executiveSummary,
                    memo.currentView,
                    memo.evidenceSummary,
                    memo.uncertaintySummary,
                    memo.recommendedNextStep,
                    bundle?.summary ?? "",
                    bundle?.refs.map { "\($0.title) \($0.summary ?? "") \($0.url ?? "")" }.joined(separator: " ") ?? ""
                ],
                askSignals: askSignals
            )
            if requestedCharterIDs.contains(memo.charterId ?? "") || requestedAnalystIDs.contains(memo.analystId) {
                score += 20
            }
            if normalizedAsk.contains("latest") {
                score += 1
            }
            guard score > 0 else {
                return nil
            }
            return (score: score, memo: memo, bundle: bundle)
        }

        let selected = scoredMemos
            .sorted { lhs, rhs in
                if lhs.score == rhs.score {
                    if lhs.memo.updatedAt == rhs.memo.updatedAt { return lhs.memo.memoId < rhs.memo.memoId }
                    return lhs.memo.updatedAt > rhs.memo.updatedAt
                }
                return lhs.score > rhs.score
            }
            .prefix(requestedDefinitions.isEmpty ? 3 : max(1, requestedDefinitions.count))

        return selected.map { candidate in
            let memo = candidate.memo
            let analystTitle = requestedDefinitions.first(where: {
                $0.charterId == memo.charterId || $0.analystId == memo.analystId
            })?.title ?? memo.analystId
            let sourceLines: String
            if let bundle = candidate.bundle, bundle.refs.isEmpty == false {
                sourceLines = bundle.refs
                    .prefix(10)
                    .map(pmConversationEvidenceRefDetailedLine)
                    .joined(separator: "\n")
            } else {
                sourceLines = "No linked AnalystEvidenceBundle refs were found for this memo. State that source-level readback is incomplete rather than inventing sources."
            }
            let bundleSummary = candidate.bundle?.summary.trimmingCharacters(in: .whitespacesAndNewlines)
            let bundleSummaryLine = bundleSummary.map {
                "Evidence bundle summary: \(openAIResponsesTrimmed($0, limit: 320))"
            } ?? "Evidence bundle summary: none linked."
            return """
            AD_HOC_ANALYST_SOURCE_TIER_GROUNDING
            Role: app-owned latest AnalystMemo and AnalystEvidenceBundle source grounding for PM readback. Use these source names and tiers before conversation prose. Do not omit a listed reputable secondary source just because it did not confirm the final answer.
            Analyst lane: \(analystTitle)
            Memo id: \(pmConversationShortArtifactID(memo.memoId))
            Task id: \(memo.taskId.map { pmConversationShortArtifactID($0) } ?? "none")
            Delegation id: \(memo.delegationId.map { pmConversationShortArtifactID($0) } ?? "none")
            Memo title: \(pmConversationFullReportText(memo.title))
            Updated at: \(DateCodec.formatISO8601(memo.updatedAt))
            Memo evidence summary: \(openAIResponsesTrimmed(memo.evidenceSummary, limit: 360))
            \(bundleSummaryLine)
            Source refs:
            \(sourceLines)
            """
        }
    }

    private func pmConversationAgentSkillLibraryIndexSummaryIfNeeded(_ ask: String) async -> [String] {
        let normalizedAsk = ask
            .lowercased()
            .replacingOccurrences(of: "[^a-z0-9]+", with: " ", options: .regularExpression)
            .trimmingCharacters(in: .whitespacesAndNewlines)
        guard pmConversationLooksLikeAgentSkillAsk(normalizedAsk: normalizedAsk) else {
            return []
        }
        do {
            let activeSkills = try await listAgentSkills(includeArchived: false)
            guard activeSkills.isEmpty == false else {
                return [
                    "AGENT_SKILLS_LIBRARY_INDEX: no active app-owned Agent Skills are currently available. Do not invent skill records."
                ]
            }
            let intro = "AGENT_SKILLS_LIBRARY_INDEX: active app-owned Agent Skills. Use these exact ids/titles when the owner asks what skills exist or asks you to task an analyst with specific skills. Skills are reusable methodology guidance only; they do not grant source, proposal, approval, execution, or trading authority."
            let skillLines = activeSkills.prefix(12).map { skill in
                let category = skill.category.displayTitle
                let summary = openAIResponsesTrimmed(skill.summary, limit: 180)
                return "AGENT_SKILL_RECORD id=\(skill.skillId) title=\(skill.title) category=\(category) summary=\(summary)"
            }
            return [intro] + skillLines
        } catch {
            return [
                "AGENT_SKILLS_LIBRARY_INDEX: unavailable because the app-owned Agent Skill store could not be read. Do not invent skill records."
            ]
        }
    }

    private func pmConversationTargetedAnalystReportSkillUsageSummaries(
        ask: String,
        contextPack: PMContextPack,
        standingReports: [AnalystStandingReport],
        pmDecisions: [PMDecisionRecord],
        analystMemos: [AnalystMemo]
    ) -> [String] {
        let normalizedAsk = ask
            .lowercased()
            .replacingOccurrences(of: "[^a-z0-9]+", with: " ", options: .regularExpression)
            .trimmingCharacters(in: .whitespacesAndNewlines)
        guard pmConversationLooksLikeAnalystReportSkillUsageAsk(normalizedAsk: normalizedAsk) else {
            return []
        }

        let askSignals = pmConversationRecoverySignals(from: ask)
        var requestedDefinitions = pmConversationRequestedAnalystDefinitions(
            normalizedAsk: normalizedAsk,
            askSignals: askSignals
        )
        if requestedDefinitions.isEmpty,
           let recentSkillDelegation = contextPack.relevantDelegations
            .filter({ $0.taskingBrief?.selectedSkillReferences.isEmpty == false })
            .sorted(by: { lhs, rhs in
                if lhs.updatedAt == rhs.updatedAt { return lhs.delegationId < rhs.delegationId }
                return lhs.updatedAt > rhs.updatedAt
            })
            .first,
           let definition = StandingAnalystBenchSeed.definitions.first(where: {
               $0.charterId == recentSkillDelegation.charterId
           }) {
            requestedDefinitions = [definition]
        }
        guard requestedDefinitions.isEmpty == false else {
            return []
        }

        let ownerVisibleReports = standingReports
            .filter { isExerciseArtifactIdentifier($0.reportId) == false }
        let groupedReports = Dictionary(grouping: ownerVisibleReports) { report in
            pmConversationCanonicalAnalystReportLaneKey(report)
        }
        let decisionsByReportID = pmConversationPMReviewDecisionsByStandingReportID(
            pmDecisions,
            standingReports: ownerVisibleReports
        )
        let memosByID = Dictionary(uniqueKeysWithValues: analystMemos.map { ($0.memoId, $0) })

        return requestedDefinitions.compactMap { definition -> String? in
            let reports = groupedReports[definition.charterId] ?? []
            let sortedReports = reports.sorted {
                pmConversationAnalystReportRecencySort(
                    lhs: $0,
                    rhs: $1,
                    decisionsByReportID: decisionsByReportID
                )
            }
            guard let report = sortedReports.first(where: { $0.deliveryStatus == .reviewedByPM }) ?? sortedReports.first else {
                return """
                AGENT_SKILL_USAGE_FOR_LATEST_ANALYST_REPORT
                Analyst lane: \(definition.title)
                App-owned skill usage blocker: no standing report was found for this analyst lane. Do not infer skill usage from generic methodology prose.
                """
            }
            let linkedMemo = pmConversationLinkedAnalystMemo(
                for: report,
                memosByID: memosByID,
                analystMemos: analystMemos
            )
            let linkedDecision = decisionsByReportID[report.reportId]
            let timestamp = pmConversationAnalystReportReviewSortTimestamp(
                report,
                linkedDecision: linkedDecision
            )
            let timestampKind = pmConversationAnalystReportReviewTimestampKind(
                report,
                linkedDecision: linkedDecision
            )
            let memoOnlyUsage = (linkedMemo?.skillUsageSummaries ?? []).filter { memoUsage in
                report.skillUsageSummaries.contains(where: { $0.skillId == memoUsage.skillId }) == false
            }
            let reportUsage = report.skillUsageSummaries.isEmpty
                ? "Report skill usage records: none persisted on AnalystStandingReport."
                : "Report skill usage records:\n\(pmConversationSkillUsageRecordLines(report.skillUsageSummaries))"
            let memoUsage = memoOnlyUsage.isEmpty
                ? "Linked memo-only skill usage records: none."
                : "Linked memo-only skill usage records:\n\(pmConversationSkillUsageRecordLines(memoOnlyUsage))"
            return """
            AGENT_SKILL_USAGE_FOR_LATEST_ANALYST_REPORT
            Role: app-owned persisted Agent Skill usage for a latest analyst-report readback question. Use these exact skill ids/titles/statuses before report prose. If records exist here, do not invent generic method labels from memo text.
            Analyst lane: \(definition.title)
            Selection: latest \(report.deliveryStatus == .reviewedByPM ? "reviewed" : "available") report for this analyst lane.
            Report id: \(pmConversationShortArtifactID(report.reportId))
            Linked memo id: \(pmConversationShortArtifactID(report.memoId))
            Timestamp to use: \(DateCodec.formatISO8601(timestamp)) [\(timestampKind)]
            Report title to use: \(pmConversationFullReportText(report.title))
            \(reportUsage)
            \(memoUsage)
            """
        }
    }

    private func pmConversationTargetedAnalystDelegationSkillRequestSummaries(
        ask: String,
        contextPack: PMContextPack
    ) -> [String] {
        let normalizedAsk = ask
            .lowercased()
            .replacingOccurrences(of: "[^a-z0-9]+", with: " ", options: .regularExpression)
            .trimmingCharacters(in: .whitespacesAndNewlines)
        guard pmConversationLooksLikeAnalystSkillTaskingAsk(normalizedAsk: normalizedAsk) else {
            return []
        }
        let askSignals = pmConversationRecoverySignals(from: ask)
        let requestedDefinitions = pmConversationRequestedAnalystDefinitions(
            normalizedAsk: normalizedAsk,
            askSignals: askSignals
        )
        let candidateDelegations: [PMDelegationRecord]
        if requestedDefinitions.isEmpty {
            candidateDelegations = contextPack.relevantDelegations
        } else {
            let requestedCharterIDs = Set(requestedDefinitions.map(\.charterId))
            candidateDelegations = contextPack.relevantDelegations.filter {
                requestedCharterIDs.contains($0.charterId)
            }
        }

        let sortedDelegations = candidateDelegations
            .filter { isExercisePMDelegation($0) == false }
            .sorted { lhs, rhs in
                if lhs.updatedAt == rhs.updatedAt { return lhs.delegationId < rhs.delegationId }
                return lhs.updatedAt > rhs.updatedAt
            }
        guard sortedDelegations.isEmpty == false else {
            return []
        }

        let selected = sortedDelegations
            .filter { $0.taskingBrief?.selectedSkillReferences.isEmpty == false }
            .prefix(requestedDefinitions.isEmpty ? 3 : max(1, requestedDefinitions.count))
        if selected.isEmpty {
            let laneLabel = requestedDefinitions.map(\.title).joined(separator: ", ")
            return [
                """
                AGENT_SKILL_REQUESTS_FOR_PM_ANALYST_TASKING
                App-owned requested-skill blocker: recent \(laneLabel.isEmpty ? "analyst" : laneLabel) delegations did not persist selected Agent Skill references. Do not infer requested skills from generic delegation prose.
                """
            ]
        }

        return selected.map { delegation in
            let skillLines = (delegation.taskingBrief?.selectedSkillReferences ?? [])
                .prefix(8)
                .map { reference -> String in
                    let title = openAIResponsesTrimmed(reference.skillTitle, limit: 100)
                    let rationale = reference.rationale
                        .map { " rationale=\(openAIResponsesTrimmed($0, limit: 180))" }
                        ?? ""
                    return "- skillId=\(reference.skillId) skillTitle=\(title) requirement=\(reference.requirement.displayTitle) source=\(reference.source.displayTitle)\(rationale)"
                }
                .joined(separator: "\n")
            let analystTitle = requestedDefinitions.first(where: { $0.charterId == delegation.charterId })?.title
                ?? delegation.analystId
            return """
            AGENT_SKILL_REQUESTS_FOR_PM_ANALYST_TASKING
            Role: app-owned selected Agent Skill references requested by PM conversation/delegation tasking. Use these exact ids/titles for questions about what skills the PM asked an analyst to use; do not infer generic method names from prose.
            Analyst lane: \(analystTitle)
            Delegation id: \(pmConversationShortArtifactID(delegation.delegationId))
            Task id: \(delegation.taskId.map { pmConversationShortArtifactID($0) } ?? "none")
            Delegation title: \(pmConversationFullReportText(delegation.title))
            Updated at: \(DateCodec.formatISO8601(delegation.updatedAt))
            Requested Agent Skills:
            \(skillLines)
            """
        }
    }

    private func pmConversationTargetedAnalystReportDetailSummaries(
        ask: String,
        standingReports: [AnalystStandingReport],
        pmDecisions: [PMDecisionRecord],
        analystMemos: [AnalystMemo],
        analystEvidenceBundles: [AnalystEvidenceBundle]
    ) -> [String] {
        let normalizedAsk = ask
            .lowercased()
            .replacingOccurrences(of: "[^a-z0-9]+", with: " ", options: .regularExpression)
            .trimmingCharacters(in: .whitespacesAndNewlines)
        let askSignals = pmConversationRecoverySignals(from: ask)
        let explicitlyNamedSymbols = Set(pmConversationOrderedSymbolCandidates(in: ask))
        guard pmConversationLooksLikeLatestAnalystSourceAsk(normalizedAsk: normalizedAsk)
            || pmConversationLooksLikeAnalystReportDetailAsk(
            normalizedAsk: normalizedAsk,
            askSignals: askSignals,
            explicitlyNamedSymbols: explicitlyNamedSymbols
        ) else {
            return []
        }

        let laneRetrieval = pmConversationAnalystReportLaneRetrieval(
            normalizedAsk: normalizedAsk,
            standingReports: standingReports,
            pmDecisions: pmDecisions
        )
        let requestedDefinitions = pmConversationRequestedAnalystDefinitions(
            normalizedAsk: normalizedAsk,
            askSignals: askSignals
        )
        let forceAllStandingLaneDetail = pmConversationLooksLikeLatestReviewedAnalystReportAsk(
            normalizedAsk: normalizedAsk
        ) && requestedDefinitions.isEmpty
        let crossAnalystFullDetail = pmConversationCrossAnalystReportFullDetailSummaries(
            normalizedAsk: normalizedAsk,
            askSignals: askSignals,
            explicitlyNamedSymbols: explicitlyNamedSymbols,
            standingReports: standingReports,
            pmDecisions: pmDecisions,
            analystMemos: analystMemos,
            analystEvidenceBundles: analystEvidenceBundles,
            forceAllStandingLanes: forceAllStandingLaneDetail,
            preferredDefinitions: requestedDefinitions
        )
        if crossAnalystFullDetail.isEmpty == false {
            return crossAnalystFullDetail + laneRetrieval.summaries
        }
        let needsSpecificDetail = pmConversationNeedsSpecificAnalystReportDetail(
            normalizedAsk: normalizedAsk,
            explicitlyNamedSymbols: explicitlyNamedSymbols
        )
        if needsSpecificDetail == false {
            return laneRetrieval.summaries
        }

        let scoredReports = standingReports.compactMap { report -> (score: Int, report: AnalystStandingReport)? in
            let score = pmConversationAnalystReportDetailScore(
                report: report,
                normalizedAsk: normalizedAsk,
                askSignals: askSignals,
                explicitlyNamedSymbols: explicitlyNamedSymbols
            )
            return score > 0 ? (score, report) : nil
        }
        let selectedReports = scoredReports
            .sorted { lhs, rhs in
                if lhs.score == rhs.score {
                    if lhs.report.updatedAt == rhs.report.updatedAt {
                        return lhs.report.reportId < rhs.report.reportId
                    }
                    return lhs.report.updatedAt > rhs.report.updatedAt
                }
                return lhs.score > rhs.score
            }
            .reduce(into: [(score: Int, report: AnalystStandingReport)]()) { selected, candidate in
                let candidateLaneKey = pmConversationCanonicalAnalystReportLaneKey(candidate.report)
                guard selected.contains(where: { pmConversationCanonicalAnalystReportLaneKey($0.report) == candidateLaneKey }) == false else {
                    return
                }
                selected.append(candidate)
            }
            .prefix(2)
            .map(\.report)

        guard selectedReports.isEmpty == false else {
            return laneRetrieval.summaries
        }

        var summaries: [String] = []
        for report in selectedReports {
            let analystTitle = pmConversationAnalystReportDisplayTitle(report)
            let memosByID = Dictionary(uniqueKeysWithValues: analystMemos.map { ($0.memoId, $0) })
            let evidenceBundlesByID = Dictionary(uniqueKeysWithValues: analystEvidenceBundles.map { ($0.bundleId, $0) })
            let decisionsByReportID = pmConversationPMReviewDecisionsByStandingReportID(
                pmDecisions,
                standingReports: standingReports
            )
            let linkedMemo = pmConversationLinkedAnalystMemo(
                for: report,
                memosByID: memosByID,
                analystMemos: analystMemos
            )
            let linkedEvidenceBundle = pmConversationLinkedAnalystEvidenceBundle(
                for: report,
                linkedMemo: linkedMemo,
                evidenceBundlesByID: evidenceBundlesByID,
                analystEvidenceBundles: analystEvidenceBundles
            )
            let linkedDecision = pmConversationLinkedPMReviewDecision(
                for: report,
                decisionsByReportID: decisionsByReportID,
                pmDecisions: pmDecisions
            )
            summaries.append(
                pmConversationAtomicAnalystReportDocumentContext(
                    analystTitle: analystTitle,
                    report: report,
                    selection: "selected report for this analyst/detail ask",
                    linkedMemo: linkedMemo,
                    linkedEvidenceBundle: linkedEvidenceBundle,
                    linkedDecision: linkedDecision
                )
            )
            let linkedFullDetail = pmConversationLinkedAnalystReportFullDetailFragments(
                report: report,
                linkedMemo: linkedMemo,
                linkedEvidenceBundle: linkedEvidenceBundle,
                linkedDecision: linkedDecision
            )
            if report.sections.isEmpty && linkedFullDetail.isEmpty {
                summaries.append(
                    "Analyst report detail retrieval blocker: matched \(analystTitle) report \"\(report.title)\", but no detail section matched the owner's referenced section/content. Analyst-created report source: AnalystStandingReport.sections[].items[].detail."
                )
                continue
            }
        }

        var merged: [String] = []
        var seen = Set<String>()
        for summary in summaries + laneRetrieval.summaries
            where seen.insert(summary).inserted {
            merged.append(summary)
        }
        return merged
    }

    private func pmConversationCrossAnalystReportFullDetailSummaries(
        normalizedAsk: String,
        askSignals: Set<String>,
        explicitlyNamedSymbols: Set<String>,
        standingReports: [AnalystStandingReport],
        pmDecisions: [PMDecisionRecord],
        analystMemos: [AnalystMemo],
        analystEvidenceBundles: [AnalystEvidenceBundle],
        forceAllStandingLanes: Bool = false,
        preferredDefinitions: [StandingAnalystBenchSeed.Definition] = []
    ) -> [String] {
        let hasPreferredDefinitions = preferredDefinitions.isEmpty == false
        guard hasPreferredDefinitions
            || forceAllStandingLanes
            || pmConversationLooksLikeCrossAnalystReportDetailAsk(normalizedAsk: normalizedAsk) else {
            return []
        }

        let ownerVisibleReports = standingReports
            .filter { isExerciseArtifactIdentifier($0.reportId) == false }
        let decisionsByReportID = pmConversationPMReviewDecisionsByStandingReportID(
            pmDecisions,
            standingReports: ownerVisibleReports
        )
        let groupedReports = Dictionary(grouping: ownerVisibleReports) { report in
            pmConversationCanonicalAnalystReportLaneKey(report)
        }
        let memosByID = Dictionary(uniqueKeysWithValues: analystMemos.map { ($0.memoId, $0) })
        let evidenceBundlesByID = Dictionary(uniqueKeysWithValues: analystEvidenceBundles.map { ($0.bundleId, $0) })
        let wantsSectorOnly = normalizedAsk.contains("sector analyst")
            || normalizedAsk.contains("sector analysts")
            || normalizedAsk.contains("each of the sector")
        let definitions = hasPreferredDefinitions
            ? preferredDefinitions
            : StandingAnalystBenchSeed.definitions.filter { definition in
                wantsSectorOnly ? definition.benchRole == .sector : true
            }
        guard definitions.isEmpty == false else { return [] }

        let rankedDefinitions = definitions.enumerated()
            .map { indexedDefinition in
                (
                    offset: indexedDefinition.offset,
                    definition: indexedDefinition.element,
                    score: pmConversationAnalystDefinitionRetrievalScore(
                        indexedDefinition.element,
                        normalizedAsk: normalizedAsk,
                        askSignals: askSignals
                    )
                )
            }
            .sorted { lhs, rhs in
                if lhs.score == rhs.score {
                    return lhs.offset < rhs.offset
                }
                return lhs.score > rhs.score
            }

        let laneDocuments = rankedDefinitions.compactMap { definition -> String? in
            let reports = groupedReports[definition.definition.charterId] ?? []
            let sortedReports = reports.sorted {
                pmConversationAnalystReportRecencySort(
                    lhs: $0,
                    rhs: $1,
                    decisionsByReportID: decisionsByReportID
                )
            }
            guard let report = sortedReports.first(where: { $0.deliveryStatus == .reviewedByPM }) ?? sortedReports.first else {
                return "\(definition.definition.title): no standing report found for this lane."
            }
            let linkedMemo = pmConversationLinkedAnalystMemo(
                for: report,
                memosByID: memosByID,
                analystMemos: analystMemos
            )
            let linkedEvidenceBundle = pmConversationLinkedAnalystEvidenceBundle(
                for: report,
                linkedMemo: linkedMemo,
                evidenceBundlesByID: evidenceBundlesByID,
                analystEvidenceBundles: analystEvidenceBundles
            )
            let linkedDecision = pmConversationLinkedPMReviewDecision(
                for: report,
                decisionsByReportID: decisionsByReportID,
                pmDecisions: pmDecisions
            )
            return pmConversationAtomicAnalystReportDocumentContext(
                analystTitle: definition.definition.title,
                report: report,
                selection: "latest \(report.deliveryStatus == .reviewedByPM ? "reviewed" : "available") report for this analyst lane in cross-analyst retrieval",
                linkedMemo: linkedMemo,
                linkedEvidenceBundle: linkedEvidenceBundle,
                linkedDecision: linkedDecision
            )
        }
        guard laneDocuments.isEmpty == false else { return [] }

        let instruction: String
        if hasPreferredDefinitions {
            let preferredTitles = definitions.map(\.title).joined(separator: ", ")
            instruction = "Named analyst full-report retrieval for PM reasoning: full analyst-created standing-report context for the analyst lane(s) explicitly referenced by the owner (\(preferredTitles)). The all-lane latest-reviewed index remains available separately for PM reasoning, but answer named-lane report questions from these full report documents first. Do not substitute another analyst lane or stale ranked snippet for a named-lane ask."
        } else if forceAllStandingLanes {
            instruction = "Open analyst-lane full-report retrieval for PM reasoning: full analyst-created standing-report context for the latest reviewed standing report in each analyst lane. Full report contexts are ordered by retrieval relevance to the owner ask while keeping every standing lane open. The PM model must choose the relevant lane from the owner message; deterministic app code is not choosing the answer. Use this full report context before compact recaps, and do not substitute another analyst for a named-lane ask."
        } else if wantsSectorOnly {
            instruction = "Cross-sector analyst full-report retrieval for PM reasoning: full analyst-created standing-report context from each standing sector analyst lane, ordered by retrieval relevance while keeping the sector lanes open. Use these lane details before compact recaps; if a lane lacks a matching short/long/material section, say so rather than generalizing."
        } else {
            instruction = "Cross-analyst full-report retrieval for PM reasoning: full analyst-created standing-report context from every standing analyst lane, ordered by retrieval relevance while keeping all lanes open. Use these lane details before compact recaps; if a lane lacks matching detail, say so rather than substituting another analyst."
        }
        var summaries = [instruction]
        summaries.append(contentsOf: laneDocuments)
        return summaries
    }

    private func pmConversationOpenStandingAnalystBenchFullReportSummaries(
        standingReports: [AnalystStandingReport],
        pmDecisions: [PMDecisionRecord],
        analystMemos: [AnalystMemo],
        analystEvidenceBundles: [AnalystEvidenceBundle]
    ) -> [String] {
        let ownerVisibleReports = standingReports
            .filter { isExerciseArtifactIdentifier($0.reportId) == false }
        guard ownerVisibleReports.isEmpty == false else {
            return []
        }

        let decisionsByReportID = pmConversationPMReviewDecisionsByStandingReportID(
            pmDecisions,
            standingReports: ownerVisibleReports
        )
        let groupedReports = Dictionary(grouping: ownerVisibleReports) { report in
            pmConversationCanonicalAnalystReportLaneKey(report)
        }
        let memosByID = Dictionary(uniqueKeysWithValues: analystMemos.map { ($0.memoId, $0) })
        let evidenceBundlesByID = Dictionary(uniqueKeysWithValues: analystEvidenceBundles.map { ($0.bundleId, $0) })
        let definitions = StandingAnalystBenchSeed.definitions.filter {
            $0.charterId != recentNewsStandingAnalystCharterID
        }

        let laneDocuments = definitions.compactMap { definition -> String? in
            let reports = groupedReports[definition.charterId] ?? []
            let sortedReports = reports.sorted {
                pmConversationAnalystReportRecencySort(
                    lhs: $0,
                    rhs: $1,
                    decisionsByReportID: decisionsByReportID
                )
            }
            guard let report = sortedReports.first(where: { $0.deliveryStatus == .reviewedByPM }) ?? sortedReports.first else {
                return "\(definition.title): no standing report found for this lane."
            }
            let linkedMemo = pmConversationLinkedAnalystMemo(
                for: report,
                memosByID: memosByID,
                analystMemos: analystMemos
            )
            let linkedEvidenceBundle = pmConversationLinkedAnalystEvidenceBundle(
                for: report,
                linkedMemo: linkedMemo,
                evidenceBundlesByID: evidenceBundlesByID,
                analystEvidenceBundles: analystEvidenceBundles
            )
            let linkedDecision = pmConversationLinkedPMReviewDecision(
                for: report,
                decisionsByReportID: decisionsByReportID,
                pmDecisions: pmDecisions
            )
            return pmConversationAtomicAnalystReportDocumentContext(
                analystTitle: definition.title,
                report: report,
                selection: "latest \(report.deliveryStatus == .reviewedByPM ? "reviewed" : "available") report for this standing analyst lane in the open analyst bench reading context",
                linkedMemo: linkedMemo,
                linkedEvidenceBundle: linkedEvidenceBundle,
                linkedDecision: linkedDecision
            )
        }
        guard laneDocuments.isEmpty == false else {
            return []
        }

        return [
            "Open standing analyst bench full-report context for PM reasoning: latest durable analyst-created report documents for every non-Recent-News standing analyst lane. This is app-owned reading material, not deterministic app interpretation of the owner message. The PM model must reason over the owner's latest turn and decide whether any lane or lanes matter. If the PM determines the owner is asking about a particular analyst lane, answer from that lane or say that lane lacks a report; do not substitute another analyst lane as the answer."
        ] + laneDocuments
    }

    private func pmConversationRequestedAnalystDefinitions(
        normalizedAsk: String,
        askSignals: Set<String>
    ) -> [StandingAnalystBenchSeed.Definition] {
        StandingAnalystBenchSeed.definitions.filter { definition in
            pmConversationAskReferencesAnalystDefinition(
                definition,
                normalizedAsk: normalizedAsk,
                askSignals: askSignals
            )
        }
    }

    private func pmConversationAskReferencesAnalystDefinition(
        _ definition: StandingAnalystBenchSeed.Definition,
        normalizedAsk: String,
        askSignals: Set<String>
    ) -> Bool {
        let normalizedTitle = definition.title
            .lowercased()
            .replacingOccurrences(of: "[^a-z0-9]+", with: " ", options: .regularExpression)
            .trimmingCharacters(in: .whitespacesAndNewlines)
        if normalizedTitle.isEmpty == false,
           normalizedAsk.contains(normalizedTitle) {
            return true
        }
        let identifierAliases = [
            definition.charterId,
            definition.analystId,
            definition.coverageScope
        ]
            .map {
                $0.lowercased()
                    .replacingOccurrences(of: "[^a-z0-9]+", with: " ", options: .regularExpression)
                    .trimmingCharacters(in: .whitespacesAndNewlines)
            }
            .filter { $0.isEmpty == false }
        if identifierAliases.contains(where: { normalizedAsk.contains($0) }) {
            return true
        }

        let titleTokens = normalizedTitle
            .split(whereSeparator: { $0.isWhitespace })
            .map(String.init)
            .filter { token in
                token != "analyst" && token != "and" && token.count >= 4
            }
        guard titleTokens.isEmpty == false else {
            return false
        }
        return titleTokens.allSatisfy { askSignals.contains($0) }
    }

    private func pmConversationFocusedAnalystReportFullDetailContexts(
        definition: StandingAnalystBenchSeed.Definition,
        groupedReports: [String: [AnalystStandingReport]],
        decisionsByReportID: [String: PMDecisionRecord],
        pmDecisions: [PMDecisionRecord],
        memosByID: [String: AnalystMemo],
        analystMemos: [AnalystMemo],
        evidenceBundlesByID: [String: AnalystEvidenceBundle],
        analystEvidenceBundles: [AnalystEvidenceBundle]
    ) -> [String] {
        let reports = groupedReports[definition.charterId] ?? []
        let sortedReports = reports.sorted {
            pmConversationAnalystReportRecencySort(
                lhs: $0,
                rhs: $1,
                decisionsByReportID: decisionsByReportID
            )
        }
        guard let report = sortedReports.first(where: { $0.deliveryStatus == .reviewedByPM }) ?? sortedReports.first else {
            return []
        }
        let linkedMemo = pmConversationLinkedAnalystMemo(
            for: report,
            memosByID: memosByID,
            analystMemos: analystMemos
        )
        let linkedEvidenceBundle = pmConversationLinkedAnalystEvidenceBundle(
            for: report,
            linkedMemo: linkedMemo,
            evidenceBundlesByID: evidenceBundlesByID,
            analystEvidenceBundles: analystEvidenceBundles
        )
        let linkedDecision = pmConversationLinkedPMReviewDecision(
            for: report,
            decisionsByReportID: decisionsByReportID,
            pmDecisions: pmDecisions
        )
        return [
            pmConversationAtomicAnalystReportDocumentContext(
                analystTitle: definition.title,
                report: report,
                selection: "latest \(report.deliveryStatus == .reviewedByPM ? "reviewed" : "available") report for this lane",
                linkedMemo: linkedMemo,
                linkedEvidenceBundle: linkedEvidenceBundle,
                linkedDecision: linkedDecision
            )
        ]
    }

    private func pmConversationAtomicAnalystReportDocumentContext(
        analystTitle: String,
        report: AnalystStandingReport,
        selection: String,
        linkedMemo: AnalystMemo?,
        linkedEvidenceBundle: AnalystEvidenceBundle?,
        linkedDecision: PMDecisionRecord?
    ) -> String {
        let timestamp = pmConversationAnalystReportReviewSortTimestamp(
            report,
            linkedDecision: linkedDecision
        )
        let timestampKind = pmConversationAnalystReportReviewTimestampKind(
            report,
            linkedDecision: linkedDecision
        )

        var contexts: [String] = [
            """
            FULL_ANALYST_REPORT_DOCUMENT
            Analyst lane: \(analystTitle)
            Selection: \(selection).
            Role of this text: durable analyst-created standing report reading material plus directly linked analyst memo/evidence. The PM model must reason over it; the app is not composing the visible answer.
            Report id: \(pmConversationShortArtifactID(report.reportId))
            Linked memo id: \(pmConversationShortArtifactID(report.memoId))
            Review status: \(report.deliveryStatus.rawValue)
            Timestamp to use: \(DateCodec.formatISO8601(timestamp)) [\(timestampKind)]
            Report title to use: \(pmConversationFullReportText(report.title))
            Reporting window to use when relevant: \(pmConversationFullReportText(report.reportingWindowSummary))
            """
        ]

        if let linkedEvidenceBundle {
            let appNews = linkedEvidenceBundle.refs
                .filter { $0.sourceKind == .appNews }
                .map { pmConversationFocusedEvidenceRefFragment($0) }
            let supplemental = linkedEvidenceBundle.refs
                .filter { $0.sourceKind == .web || $0.sourceKind == .manualNote }
                .map { pmConversationFocusedEvidenceRefFragment($0) }
            contexts.append(
                """
                FULL_REPORT_LINKED_MEMO_AND_EVIDENCE
                Analyst lane: \(analystTitle)
                Role: primary analyst-created report body and direct evidence grounding for this report. For material-article, signal, support-list, detailed-supporting-section, and candidate-detail questions, read these linked analyst memo/evidence entries before report-schema scaffolding or PM treatment metadata.

                \(pmConversationFocusedLinkedMemoFragment(linkedMemo))

                Linked app-owned news/article refs:
                \(appNews.isEmpty ? "(none linked)" : appNews.enumerated().map { index, value in "\(index + 1). \(value)" }.joined(separator: "\n"))

                Supplemental/support sources checked:
                \(supplemental.isEmpty ? "(none linked)" : supplemental.enumerated().map { index, value in "\(index + 1). \(value)" }.joined(separator: "\n"))

                Evidence bundle summary:
                \(pmConversationFullReportText(linkedEvidenceBundle.summary))
                """
            )
        } else {
            contexts.append(
                """
                FULL_REPORT_LINKED_MEMO_AND_EVIDENCE
                Analyst lane: \(analystTitle)
                Role: primary analyst-created report body and direct evidence grounding for this report. For material-article, signal, support-list, detailed-supporting-section, and candidate-detail questions, read the linked analyst memo body before report-schema scaffolding or PM treatment metadata.

                \(pmConversationFocusedLinkedMemoFragment(linkedMemo))

                Linked app-owned news/article refs: no separately persisted evidence bundle was available for this report. Use the linked memo evidence summary above as the analyst-created article/support grounding.
                """
            )
        }

        let reportSkillUsage = pmConversationFullReportSkillUsageContext(
            report: report,
            linkedMemo: linkedMemo
        )
        if reportSkillUsage.isEmpty == false {
            contexts.append(
                """
                FULL_REPORT_AGENT_SKILL_USAGE
                Analyst lane: \(analystTitle)
                Role: app-owned persisted Agent Skill usage for this report. For questions asking which skills were used, applied, or considered, answer from these exact skill ids/titles/statuses before inferring methods from prose.

                \(reportSkillUsage)
                """
            )
        }

        contexts.append(
            """
            FULL_ANALYST_REPORT_FIELDS
            Analyst lane: \(analystTitle)
            Report title to use:
            \(pmConversationFullReportText(report.title))

            Summary:
            \(pmConversationFullReportText(report.summary))

            Headline/current view:
            \(pmConversationFullReportText(report.headlineView))

            Portfolio relevance:
            \(pmConversationFullReportText(report.portfolioRelevanceSummary))

            Reporting window to use when relevant:
            \(pmConversationFullReportText(report.reportingWindowSummary))

            Portfolio scope:
            \(pmConversationFullReportText(report.portfolioScopeSummary))

            Open questions:
            \(report.openQuestions.isEmpty ? "(none recorded)" : report.openQuestions.map { pmConversationFullReportText($0) }.joined(separator: "\n"))
            """
        )

        let substantiveSectionFragments = report.sections.compactMap { section -> String? in
            let fragment = pmConversationFocusedReportSectionFragment(section)
            guard fragment.isEmpty == false else { return nil }
            return """
            FULL_REPORT_SECTION
            Analyst lane: \(analystTitle)
            Source: AnalystStandingReport.sections[].items[].detail after excluding legacy schema scaffolding.
            Use: For detailed-supporting-section, short/long candidate, material-signal, support, and evidence questions, read this section directly.
            \(fragment)
            """
        }
        let omittedScaffoldSectionTitles = report.sections.compactMap { section -> String? in
            pmConversationStandingReportScaffoldSectionOmissionTitle(section)
        }
        if substantiveSectionFragments.isEmpty {
            contexts.append(
                "FULL_REPORT_SECTION: \(analystTitle) has no substantive AnalystStandingReport.sections[].items[].detail entries after excluding legacy schema scaffolding. Use FULL_REPORT_LINKED_MEMO_AND_EVIDENCE as the primary analyst-created report body."
            )
        } else {
            contexts.append(contentsOf: substantiveSectionFragments)
        }
        if omittedScaffoldSectionTitles.isEmpty == false {
            contexts.append(
                """
                REPORT_SCHEMA_SCAFFOLD_OMITTED
                Analyst lane: \(analystTitle)
                Role: compatibility scaffolding from early standing-report artifact generation, not analyst-created substantive report detail. These omitted sections must not be treated as the report's material signal, article list, candidate list, or PM answer source.
                Omitted scaffold sections: \(omittedScaffoldSectionTitles.joined(separator: ", "))
                """
            )
        }

        contexts.append(
            """
            FULL_REPORT_PM_REVIEW_TREATMENT_METADATA
            Analyst lane: \(analystTitle)
            Role of this section: PM review/treatment metadata only. Use it for PM-treatment questions, but do not let it override analyst memo/evidence or report section detail when the owner asks what the analyst report contained.

            \(pmConversationFocusedLinkedDecisionFragment(linkedDecision))
            """
        )
        return [
            """
            FULL_ANALYST_REPORT_DOCUMENTS
            Source boundary: the following is one atomic analyst-created report document plus directly linked memo, evidence bundle, and PM review/treatment metadata. It is not PM/User communication history and it is not an app-composed answer packet.
            PM reading instruction: read this whole document before answering latest-report, material-article, signal, support, evidence, candidate, or detailed-section asks about \(analystTitle). Treat FULL_REPORT_LINKED_MEMO_AND_EVIDENCE as the full analyst-created report body when standing-report sections contain legacy scaffolding. Sparse or scaffolded standing-report sections do not mean the report body is missing when linked memo/evidence is present. Read linked memo/evidence first, then substantive report fields/sections, then PM treatment metadata. Use the exact report title, timestamp, and reporting window fields above; do not invent or infer missing dates, date ranges, or generic report titles. Do not answer from PM treatment alone or from omitted report-schema scaffold.

            \(contexts.joined(separator: "\n\n---\n\n"))
            """
        ]
        .joined(separator: "\n")
    }

    private func pmConversationFullReportText(_ value: String) -> String {
        let trimmed = value.trimmingCharacters(in: .whitespacesAndNewlines)
        return trimmed.isEmpty ? "(empty)" : trimmed
    }

    private func pmConversationFullReportSkillUsageContext(
        report: AnalystStandingReport,
        linkedMemo: AnalystMemo?
    ) -> String {
        var fragments: [String] = []
        if report.skillUsageSummaries.isEmpty == false {
            fragments.append(
                "Report skill usage records:\n\(pmConversationSkillUsageRecordLines(report.skillUsageSummaries))"
            )
        }
        if let linkedMemo {
            let memoOnlyUsage = linkedMemo.skillUsageSummaries.filter { memoUsage in
                report.skillUsageSummaries.contains(where: { $0.skillId == memoUsage.skillId }) == false
            }
            if memoOnlyUsage.isEmpty == false {
                fragments.append(
                    "Linked memo-only skill usage records:\n\(pmConversationSkillUsageRecordLines(memoOnlyUsage))"
                )
            }
        }
        return fragments.joined(separator: "\n")
    }

    private func pmConversationAnalystDefinitionRetrievalScore(
        _ definition: StandingAnalystBenchSeed.Definition,
        normalizedAsk: String,
        askSignals: Set<String>
    ) -> Int {
        let normalizedTitle = definition.title
            .lowercased()
            .replacingOccurrences(of: "[^a-z0-9]+", with: " ", options: .regularExpression)
            .trimmingCharacters(in: .whitespacesAndNewlines)
        var score = 0
        if normalizedTitle.isEmpty == false,
           normalizedAsk.contains(normalizedTitle) {
            score += 100
        }
        for token in normalizedTitle.split(whereSeparator: { $0.isWhitespace }).map(String.init)
            where token.count >= 4 && askSignals.contains(token) {
            score += 12
        }
        let identifierText = [
            definition.charterId,
            definition.analystId,
            definition.coverageScope,
            definition.strategyFamily,
            definition.summary
        ]
        let identifierSignals = pmConversationRecoverySignals(from: identifierText.joined(separator: " "))
        score += askSignals.intersection(identifierSignals).count
        return score
    }

    private func pmConversationFocusedEvidenceRefFragment(_ ref: AnalystEvidenceRef) -> String {
        var pieces = [
            "Title: \(pmConversationFullReportText(ref.title))"
        ]
        if let summary = ref.summary?.trimmingCharacters(in: .whitespacesAndNewlines),
           summary.isEmpty == false {
            pieces.append("Summary: \(pmConversationFullReportText(summary))")
        }
        if let source = ref.sourceIdentifier?.trimmingCharacters(in: .whitespacesAndNewlines),
           source.isEmpty == false {
            pieces.append("Source: \(pmConversationFullReportText(source))")
        } else if let url = ref.url,
                  let host = URL(string: url)?.host?.trimmingCharacters(in: .whitespacesAndNewlines),
                  host.isEmpty == false {
            pieces.append("Source: \(host)")
        }
        return pieces.joined(separator: " | ")
    }

    private func pmConversationFocusedLinkedMemoFragment(_ linkedMemo: AnalystMemo?) -> String {
        guard let linkedMemo else {
            return "FULL_LINKED_ANALYST_MEMO_BODY: none."
        }
        return """
        FULL_LINKED_ANALYST_MEMO_BODY
        Linked memo \(pmConversationShortArtifactID(linkedMemo.memoId))
        Title:
        \(pmConversationFullReportText(linkedMemo.title))
        Updated at:
        \(DateCodec.formatISO8601(linkedMemo.updatedAt))
        Executive summary:
        \(pmConversationFullReportText(linkedMemo.executiveSummary))
        Current view:
        \(pmConversationFullReportText(linkedMemo.currentView))
        Evidence summary:
        \(pmConversationFullReportText(linkedMemo.evidenceSummary))
        Recommended next step:
        \(pmConversationFullReportText(linkedMemo.recommendedNextStep))
        Uncertainty:
        \(pmConversationFullReportText(linkedMemo.uncertaintySummary))
        Agent skill usage:
        \(linkedMemo.skillUsageSummaries.isEmpty ? "(none persisted on linked memo)" : pmConversationSkillUsageRecordLines(linkedMemo.skillUsageSummaries))
        """
    }

    private func pmConversationFocusedLinkedDecisionFragment(_ linkedDecision: PMDecisionRecord?) -> String {
        guard let linkedDecision else {
            return "PM reviewed/treatment record: none linked."
        }
        var pieces = [
            "decision \(pmConversationShortArtifactID(linkedDecision.decisionId)) updated \(DateCodec.formatISO8601(linkedDecision.updatedAt))",
            "summary \(pmConversationFullReportText(linkedDecision.summary))"
        ]
        if let action = linkedDecision.recommendedAction?.trimmingCharacters(in: .whitespacesAndNewlines),
           action.isEmpty == false {
            pieces.append("PM action \(pmConversationFullReportText(action))")
        }
        if let evidence = linkedDecision.evidenceSummary?.trimmingCharacters(in: .whitespacesAndNewlines),
           evidence.isEmpty == false {
            pieces.append("PM evidence \(pmConversationFullReportText(evidence))")
        }
        if let attention = linkedDecision.standingReviewAttentionItems,
           attention.isEmpty == false {
            pieces.append("attention items \(attention.map { pmConversationFullReportText($0) }.joined(separator: " | "))")
        }
        if let followUps = linkedDecision.standingReviewFollowUpItems,
           followUps.isEmpty == false {
            pieces.append("follow-up items \(followUps.map { pmConversationFullReportText($0) }.joined(separator: " | "))")
        }
        if let shorts = linkedDecision.standingReviewCandidateShorts,
           shorts.isEmpty == false {
            pieces.append("candidate shorts \(shorts.map { pmConversationFullReportText($0) }.joined(separator: " | "))")
        }
        return "PM reviewed/treatment record:\n\(pieces.joined(separator: "\n"))"
    }

    private func pmConversationFocusedReportSectionFragment(
        _ section: AnalystStandingReportSection
    ) -> String {
        var sectionParts = [
            "section \(pmConversationFullReportText(section.title)) [\(section.kind.rawValue)]"
        ]
        if let summary = section.summary?.trimmingCharacters(in: .whitespacesAndNewlines),
           summary.isEmpty == false,
           pmConversationLooksLikeStandingReportScaffoldText(summary) == false {
            sectionParts.append("summary \(pmConversationFullReportText(summary))")
        }
        let items = section.items
            .filter { pmConversationIsStandingReportScaffoldItem($0) == false }
            .map { item -> String in
                var itemParts = [
                    "headline \(pmConversationFullReportText(item.headline))",
                    "stance \(item.stance.displayTitle)"
                ]
                if let symbol = item.symbol?.trimmingCharacters(in: .whitespacesAndNewlines),
                   symbol.isEmpty == false {
                    itemParts.append("symbol \(symbol)")
                }
                if let conviction = item.conviction {
                    itemParts.append("conviction \(conviction)/10")
                }
                let detail = item.detail.trimmingCharacters(in: .whitespacesAndNewlines)
                if detail.isEmpty == false {
                    itemParts.append("detail \(pmConversationFullReportText(detail))")
                }
                return "{\(itemParts.joined(separator: "; "))}"
            }
        if items.isEmpty == false {
            sectionParts.append("items \(items.joined(separator: " / "))")
        }
        guard sectionParts.count > 1 else { return "" }
        return sectionParts.joined(separator: "; ")
    }

    private func pmConversationStandingReportScaffoldSectionOmissionTitle(
        _ section: AnalystStandingReportSection
    ) -> String? {
        let hasSubstantiveSummary = section.summary
            .map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
            .map { $0.isEmpty == false && pmConversationLooksLikeStandingReportScaffoldText($0) == false }
            ?? false
        let substantiveItemCount = section.items.filter { pmConversationIsStandingReportScaffoldItem($0) == false }.count
        guard hasSubstantiveSummary == false, substantiveItemCount == 0 else {
            return nil
        }
        guard section.items.isEmpty == false || section.summary?.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty == false else {
            return nil
        }
        return section.title
    }

    private func pmConversationIsStandingReportScaffoldItem(
        _ item: AnalystStandingReportItem
    ) -> Bool {
        let identifier = item.itemId
            .lowercased()
            .trimmingCharacters(in: .whitespacesAndNewlines)
        if identifier.contains("placeholder") {
            return true
        }
        let text = "\(item.headline) \(item.detail)"
        return pmConversationLooksLikeStandingReportScaffoldText(text)
    }

    private func pmConversationLooksLikeStandingReportScaffoldText(_ text: String) -> Bool {
        let normalized = text
            .lowercased()
            .replacingOccurrences(of: "[^a-z0-9]+", with: " ", options: .regularExpression)
            .trimmingCharacters(in: .whitespacesAndNewlines)
        guard normalized.isEmpty == false else { return false }
        let scaffoldPhrases = [
            "structured materiality section is now in place",
            "later sector macro and risk slices can populate this section",
            "stable section for truly material developments",
            "pm review structure is now explicit",
            "recurring report now exposes triage ready sections",
            "no bounded low signal developments are being asserted yet",
            "placeholder keeps the contract ready",
            "long candidate ranking will populate here",
            "short candidate ranking will populate here",
            "macro transmission view will populate here",
            "etf or cross asset expression will populate here",
            "risk issue ranking will populate here",
            "legacy schema placeholder",
            "recurring standing review this artifact exists so pm inbox can review recurring analyst intelligence through a stable contract",
            "this artifact exists so pm inbox can review recurring analyst intelligence through a stable contract instead of a generic memo blob",
            "standing report remains tied to portfolio construction recurring analyst reporting remains decision useful only when anchored"
        ]
        return scaffoldPhrases.contains { normalized.contains($0) }
    }

    private func pmConversationLooksLikeCrossAnalystReportDetailAsk(
        normalizedAsk: String
    ) -> Bool {
        let broadSignal = normalizedAsk.contains(" each ")
            || normalizedAsk.hasPrefix("each ")
            || normalizedAsk.contains(" all ")
            || normalizedAsk.hasPrefix("all ")
            || normalizedAsk.contains(" every ")
            || normalizedAsk.hasPrefix("every ")
            || normalizedAsk.contains("across all")
        guard broadSignal,
              normalizedAsk.contains("analyst") || normalizedAsk.contains("analysts") else {
            return false
        }
        return normalizedAsk.contains("report")
            || normalizedAsk.contains("reports")
            || normalizedAsk.contains("detail")
            || normalizedAsk.contains("section")
            || normalizedAsk.contains("candidate")
            || normalizedAsk.contains("short")
            || normalizedAsk.contains("long")
            || normalizedAsk.contains("material")
            || normalizedAsk.contains("support")
    }

    private func pmConversationAnalystReportFullDetailLaneFragment(
        analystTitle: String,
        report: AnalystStandingReport,
        normalizedAsk: String,
        askSignals: Set<String>,
        explicitlyNamedSymbols: Set<String>,
        linkedMemo: AnalystMemo?,
        linkedEvidenceBundle: AnalystEvidenceBundle?,
        linkedDecision: PMDecisionRecord?
    ) -> String {
        let timestamp = pmConversationAnalystReportReviewSortTimestamp(
            report,
            linkedDecision: linkedDecision
        )
        let timestampKind = pmConversationAnalystReportReviewTimestampKind(
            report,
            linkedDecision: linkedDecision
        )
        let sections = pmConversationAnalystReportFullDetailSections(
            report: report,
            normalizedAsk: normalizedAsk,
            askSignals: askSignals,
            explicitlyNamedSymbols: explicitlyNamedSymbols
        )
        let sectionFragments = sections.prefix(6).map { section in
            pmConversationAnalystReportSectionFullDetailFragment(
                section,
                normalizedAsk: normalizedAsk,
                askSignals: askSignals,
                explicitlyNamedSymbols: explicitlyNamedSymbols
            )
        }
        let sectionSummary: String
        if sectionFragments.isEmpty {
            if normalizedAsk.contains("short") {
                sectionSummary = "No retrieved short-candidate section was present in the latest report detail."
            } else if normalizedAsk.contains("long") {
                sectionSummary = "No retrieved long-candidate section was present in the latest report detail."
            } else {
                sectionSummary = "No matching detailed section was present in the bounded report detail."
            }
        } else {
            sectionSummary = sectionFragments.joined(separator: " ; ")
        }
        let linkedFragments = pmConversationLinkedAnalystReportFullDetailFragments(
            report: report,
            linkedMemo: linkedMemo,
            linkedEvidenceBundle: linkedEvidenceBundle,
            linkedDecision: linkedDecision
        )
        let linkedSummary = linkedFragments.isEmpty ? "" : " Linked detail: \(linkedFragments.joined(separator: " | "))"
        let statusLabel = report.deliveryStatus == .reviewedByPM ? "latest reviewed report" : "latest report"
        return "\(analystTitle): \(statusLabel) (status \(report.deliveryStatus.rawValue)) \(pmConversationShortArtifactID(report.reportId)) timestamp \(DateCodec.formatISO8601(timestamp)) [\(timestampKind)] title \(openAIResponsesTrimmed(report.title, limit: 120)). Report fields: summary \(openAIResponsesTrimmed(report.summary, limit: 360)); headline \(openAIResponsesTrimmed(report.headlineView, limit: 260)); portfolio relevance \(openAIResponsesTrimmed(report.portfolioRelevanceSummary, limit: 320)); reporting window \(openAIResponsesTrimmed(report.reportingWindowSummary, limit: 180)). Full report sections: \(sectionSummary).\(linkedSummary)"
    }

    private func pmConversationAnalystReportFullDetailSections(
        report: AnalystStandingReport,
        normalizedAsk: String,
        askSignals: Set<String>,
        explicitlyNamedSymbols: Set<String>
    ) -> [AnalystStandingReportSection] {
        if normalizedAsk.contains("short") {
            let sections = report.sections.filter {
                $0.kind == .shortIdeas || $0.title.lowercased().contains("short")
            }
            if sections.isEmpty == false { return sections }
        }
        if normalizedAsk.contains("long") {
            let sections = report.sections.filter {
                $0.kind == .longIdeas || $0.title.lowercased().contains("long")
            }
            if sections.isEmpty == false { return sections }
        }
        if normalizedAsk.contains("material")
            || normalizedAsk.contains("article")
            || normalizedAsk.contains("articles")
            || normalizedAsk.contains("signal")
            || normalizedAsk.contains("support")
            || normalizedAsk.contains("source")
            || normalizedAsk.contains("news") {
            let priorityKinds: [AnalystStandingReportSectionKind] = [
                .materialDevelopments,
                .importantItems,
                .evidence,
                .portfolioRelevance,
                .riskIssues,
                .followUp
            ]
            let sections = report.sections.filter { section in
                priorityKinds.contains(section.kind)
                    || section.title.lowercased().contains("material")
                    || section.title.lowercased().contains("support")
                    || section.title.lowercased().contains("evidence")
                    || section.title.lowercased().contains("signal")
            }
            if sections.isEmpty == false { return sections }
        }
        let scored = pmConversationRelevantAnalystReportDetailSections(
            report: report,
            normalizedAsk: normalizedAsk,
            askSignals: askSignals,
            explicitlyNamedSymbols: explicitlyNamedSymbols
        )
        if scored.isEmpty == false { return scored }
        return Array(report.sections.prefix(2))
    }

    private func pmConversationAnalystReportSectionFullDetailFragment(
        _ section: AnalystStandingReportSection,
        normalizedAsk: String,
        askSignals: Set<String>,
        explicitlyNamedSymbols: Set<String>
    ) -> String {
        let summary = section.summary
            .map { " summary \(openAIResponsesTrimmed($0, limit: 180))" }
            ?? ""
        let items = pmConversationRelevantAnalystReportDetailItems(
            section: section,
            normalizedAsk: normalizedAsk,
            askSignals: askSignals,
            explicitlyNamedSymbols: explicitlyNamedSymbols
        )
        if items.isEmpty {
            return "\(section.title)\(summary)"
        }
        return "\(section.title)\(summary) items \(items.joined(separator: " / "))"
    }

    private func pmConversationLinkedAnalystMemo(
        for report: AnalystStandingReport,
        memosByID: [String: AnalystMemo],
        analystMemos: [AnalystMemo]
    ) -> AnalystMemo? {
        if let memo = memosByID[report.memoId] {
            return memo
        }
        let reportLane = pmConversationCanonicalAnalystReportLaneKey(report)
        return analystMemos
            .filter { memo in
                memo.analystId == report.analystId
                    || memo.charterId == report.charterId
                    || memo.charterId == reportLane
            }
            .sorted { lhs, rhs in
                if lhs.updatedAt == rhs.updatedAt { return lhs.memoId < rhs.memoId }
                return lhs.updatedAt > rhs.updatedAt
            }
            .first
    }

    private func pmConversationLinkedAnalystEvidenceBundle(
        for report: AnalystStandingReport,
        linkedMemo: AnalystMemo?,
        evidenceBundlesByID: [String: AnalystEvidenceBundle],
        analystEvidenceBundles: [AnalystEvidenceBundle]
    ) -> AnalystEvidenceBundle? {
        if let bundleID = linkedMemo?.evidenceBundleId,
           let bundle = evidenceBundlesByID[bundleID] {
            return bundle
        }
        let reportLane = pmConversationCanonicalAnalystReportLaneKey(report)
        return analystEvidenceBundles
            .filter { bundle in
                bundle.analystId == report.analystId
                    || bundle.charterId == report.charterId
                    || bundle.charterId == reportLane
                    || bundle.taskId == report.scheduleId
            }
            .sorted { lhs, rhs in
                if lhs.updatedAt == rhs.updatedAt { return lhs.bundleId < rhs.bundleId }
                return lhs.updatedAt > rhs.updatedAt
            }
            .first
    }

    private func pmConversationLinkedPMReviewDecision(
        for report: AnalystStandingReport,
        decisionsByReportID: [String: PMDecisionRecord],
        pmDecisions: [PMDecisionRecord]
    ) -> PMDecisionRecord? {
        decisionsByReportID[report.reportId]
            ?? pmConversationPMReviewDecisionFallback(for: report, decisions: pmDecisions)
    }

    private func pmConversationLinkedAnalystReportFullDetailFragments(
        report: AnalystStandingReport,
        linkedMemo: AnalystMemo?,
        linkedEvidenceBundle: AnalystEvidenceBundle?,
        linkedDecision: PMDecisionRecord?
    ) -> [String] {
        var fragments: [String] = []
        if report.evidenceReferenceSummary.isEmpty == false {
            fragments.append(
                "Report evidence refs: \(report.evidenceReferenceSummary.prefix(3).map { openAIResponsesTrimmed($0, limit: 160) }.joined(separator: " ; "))"
            )
        }
        if report.skillUsageSummaries.isEmpty == false {
            fragments.append(
                "Report skill usage: \(pmConversationSkillUsageFragment(report.skillUsageSummaries))"
            )
        }
        if let linkedMemo {
            fragments.append(
                "Linked memo \(pmConversationShortArtifactID(linkedMemo.memoId)): executive \(openAIResponsesTrimmed(linkedMemo.executiveSummary, limit: 220)); current view \(openAIResponsesTrimmed(linkedMemo.currentView, limit: 220)); evidence \(openAIResponsesTrimmed(linkedMemo.evidenceSummary, limit: 220)); next step \(openAIResponsesTrimmed(linkedMemo.recommendedNextStep, limit: 180))"
            )
            let memoOnlyUsage = linkedMemo.skillUsageSummaries.filter { memoUsage in
                report.skillUsageSummaries.contains(where: { $0.skillId == memoUsage.skillId }) == false
            }
            if memoOnlyUsage.isEmpty == false {
                fragments.append(
                    "Linked memo skill usage: \(pmConversationSkillUsageFragment(memoOnlyUsage))"
                )
            }
        }
        if let linkedEvidenceBundle {
            let appNews = linkedEvidenceBundle.refs
                .filter { $0.sourceKind == .appNews }
                .prefix(4)
                .map { ref in
                    pmConversationEvidenceRefFragment(ref)
                }
            if appNews.isEmpty == false {
                fragments.append("Material/app-owned news refs: \(appNews.joined(separator: " ; "))")
            }
            let supplemental = linkedEvidenceBundle.refs
                .filter { $0.sourceKind == .web || $0.sourceKind == .manualNote }
                .prefix(4)
                .map { ref in
                    pmConversationEvidenceRefFragment(ref)
                }
            if supplemental.isEmpty == false {
                fragments.append("Supplemental/support sources checked: \(supplemental.joined(separator: " ; "))")
            }
            if linkedEvidenceBundle.summary.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty == false {
                fragments.append("Evidence bundle summary: \(openAIResponsesTrimmed(linkedEvidenceBundle.summary, limit: 220))")
            }
        }
        if let linkedDecision {
            var decisionParts = [
                "summary \(openAIResponsesTrimmed(linkedDecision.summary, limit: 220))"
            ]
            if let action = linkedDecision.recommendedAction?.trimmingCharacters(in: .whitespacesAndNewlines),
               action.isEmpty == false {
                decisionParts.append("PM action \(openAIResponsesTrimmed(action, limit: 180))")
            }
            if let evidence = linkedDecision.evidenceSummary?.trimmingCharacters(in: .whitespacesAndNewlines),
               evidence.isEmpty == false {
                decisionParts.append("PM evidence \(openAIResponsesTrimmed(evidence, limit: 180))")
            }
            if let shorts = linkedDecision.standingReviewCandidateShorts,
               shorts.isEmpty == false {
                decisionParts.append("candidate shorts \(shorts.prefix(5).map { openAIResponsesTrimmed($0, limit: 120) }.joined(separator: " ; "))")
            }
            if let attention = linkedDecision.standingReviewAttentionItems,
               attention.isEmpty == false {
                decisionParts.append("attention items \(attention.prefix(4).map { openAIResponsesTrimmed($0, limit: 120) }.joined(separator: " ; "))")
            }
            fragments.append(
                "PM reviewed/treatment record \(pmConversationShortArtifactID(linkedDecision.decisionId)) updated \(DateCodec.formatISO8601(linkedDecision.updatedAt)): \(decisionParts.joined(separator: "; "))"
            )
        }
        return fragments
    }

    private func pmConversationSkillUsageFragment(_ values: [AgentSkillUsageSummary]) -> String {
        values.prefix(6).map { value in
            let title = openAIResponsesTrimmed(value.skillTitle, limit: 80)
            let requirement = value.requirement.displayTitle
            let usage = value.usage.displayTitle
            let summary = openAIResponsesTrimmed(value.usageSummary, limit: 160)
            return "\(title) (\(requirement), \(usage)): \(summary)"
        }
        .joined(separator: " ; ")
    }

    private func pmConversationSkillUsageRecordLines(_ values: [AgentSkillUsageSummary]) -> String {
        values.prefix(12).map { value in
            let title = openAIResponsesTrimmed(value.skillTitle, limit: 100)
            let requirement = value.requirement.displayTitle
            let usage = value.usage.displayTitle
            let summary = openAIResponsesTrimmed(value.usageSummary, limit: 260)
            let sources = value.referenceSources.isEmpty
                ? "unspecified"
                : value.referenceSources.map(\.displayTitle).joined(separator: ", ")
            return "- skillId=\(value.skillId) skillTitle=\(title) requirement=\(requirement) usage=\(usage) sources=\(sources) summary=\(summary)"
        }
        .joined(separator: "\n")
    }

    private func pmConversationEvidenceRefFragment(_ ref: AnalystEvidenceRef) -> String {
        var pieces = [openAIResponsesTrimmed(ref.title, limit: 140)]
        if let summary = ref.summary?.trimmingCharacters(in: .whitespacesAndNewlines),
           summary.isEmpty == false {
            pieces.append(openAIResponsesTrimmed(summary, limit: 140))
        }
        if let source = ref.sourceIdentifier?.trimmingCharacters(in: .whitespacesAndNewlines),
           source.isEmpty == false {
            pieces.append("source \(openAIResponsesTrimmed(source, limit: 80))")
        } else if let url = ref.url,
                  let host = URL(string: url)?.host?.trimmingCharacters(in: .whitespacesAndNewlines),
                  host.isEmpty == false {
            pieces.append("source \(host)")
        }
        return pieces.joined(separator: " — ")
    }

    private func pmConversationEvidenceRefDetailedLine(_ ref: AnalystEvidenceRef) -> String {
        let tier = sourceTierForStandingEvidenceRef(ref)
        var pieces = [
            "- title=\(openAIResponsesTrimmed(ref.title, limit: 140))",
            "sourceKind=\(ref.sourceKind.displayTitle)",
            "sourceTier=\(tier.displayTitle)"
        ]
        if let source = ref.sourceIdentifier?.trimmingCharacters(in: .whitespacesAndNewlines),
           source.isEmpty == false {
            pieces.append("sourceIdentifier=\(openAIResponsesTrimmed(source, limit: 100))")
        } else if let url = ref.url,
                  let host = URL(string: url)?.host?.trimmingCharacters(in: .whitespacesAndNewlines),
                  host.isEmpty == false {
            pieces.append("host=\(openAIResponsesTrimmed(host, limit: 100))")
        }
        if let summary = ref.summary?.trimmingCharacters(in: .whitespacesAndNewlines),
           summary.isEmpty == false {
            pieces.append("summary=\(openAIResponsesTrimmed(summary, limit: 220))")
        }
        if let note = ref.freshnessNote?.trimmingCharacters(in: .whitespacesAndNewlines),
           note.isEmpty == false {
            pieces.append("provenance=\(openAIResponsesTrimmed(note, limit: 180))")
        }
        return pieces.joined(separator: " ")
    }

    private struct PMConversationAnalystReportLaneRetrieval {
        var summaries: [String]
    }

    private struct PMConversationAnalystReportLane {
        var laneKey: String
        var analystTitle: String
        var latestReport: AnalystStandingReport?
        var latestReviewedReport: AnalystStandingReport?
        var latestReviewedDecision: PMDecisionRecord?
        var displayOrder: Int
    }

    private func pmConversationAnalystReportLaneRetrieval(
        normalizedAsk: String,
        standingReports: [AnalystStandingReport],
        pmDecisions: [PMDecisionRecord]
    ) -> PMConversationAnalystReportLaneRetrieval {
        _ = normalizedAsk
        let ownerVisibleReports = standingReports
            .filter { isExerciseArtifactIdentifier($0.reportId) == false }
        let decisionsByReportID = pmConversationPMReviewDecisionsByStandingReportID(
            pmDecisions,
            standingReports: ownerVisibleReports
        )
        let groupedReports = Dictionary(grouping: ownerVisibleReports) { report in
            pmConversationCanonicalAnalystReportLaneKey(report)
        }

        var consumedLaneKeys = Set<String>()
        var lanes: [PMConversationAnalystReportLane] = []
        for (index, definition) in StandingAnalystBenchSeed.definitions.enumerated() {
            let reports = groupedReports[definition.charterId] ?? []
            let sortedReports = reports.sorted {
                pmConversationAnalystReportRecencySort(
                    lhs: $0,
                    rhs: $1,
                    decisionsByReportID: decisionsByReportID
                )
            }
            let latestReviewedReport = sortedReports.first { $0.deliveryStatus == .reviewedByPM }
            consumedLaneKeys.insert(definition.charterId)
            lanes.append(
                PMConversationAnalystReportLane(
                    laneKey: definition.charterId,
                    analystTitle: definition.title,
                    latestReport: sortedReports.first,
                    latestReviewedReport: latestReviewedReport,
                    latestReviewedDecision: latestReviewedReport.flatMap { decisionsByReportID[$0.reportId] },
                    displayOrder: index
                )
            )
        }

        let unknownLanes = groupedReports.compactMap { laneKey, reports -> PMConversationAnalystReportLane? in
            guard consumedLaneKeys.contains(laneKey) == false else {
                return nil
            }
            let sortedReports = reports.sorted {
                pmConversationAnalystReportRecencySort(
                    lhs: $0,
                    rhs: $1,
                    decisionsByReportID: decisionsByReportID
                )
            }
            guard let latestReport = sortedReports.first else {
                return nil
            }
            let latestReviewedReport = sortedReports.first { $0.deliveryStatus == .reviewedByPM }
            return PMConversationAnalystReportLane(
                laneKey: laneKey,
                analystTitle: pmConversationAnalystReportDisplayTitle(latestReport),
                latestReport: latestReport,
                latestReviewedReport: latestReviewedReport,
                latestReviewedDecision: latestReviewedReport.flatMap { decisionsByReportID[$0.reportId] },
                displayOrder: StandingAnalystBenchSeed.definitions.count + 100
            )
        }
        lanes.append(contentsOf: unknownLanes.sorted { lhs, rhs in
            let lhsDate = lhs.latestReport?.updatedAt ?? .distantPast
            let rhsDate = rhs.latestReport?.updatedAt ?? .distantPast
            if lhsDate == rhsDate {
                return lhs.laneKey < rhs.laneKey
            }
            return lhsDate > rhsDate
        })

        return PMConversationAnalystReportLaneRetrieval(
            summaries: pmConversationAnalystReportLaneIndexSummaries(lanes: lanes)
        )
    }

    private func pmConversationAnalystReportLaneKey(_ report: AnalystStandingReport) -> String {
        let charterId = report.charterId.trimmingCharacters(in: .whitespacesAndNewlines)
        if charterId.isEmpty == false {
            return charterId
        }
        let analystId = report.analystId.trimmingCharacters(in: .whitespacesAndNewlines)
        if analystId.isEmpty == false {
            return analystId
        }
        return pmConversationAnalystReportDisplayTitle(report)
    }

    private func pmConversationCanonicalAnalystReportLaneKey(_ report: AnalystStandingReport) -> String {
        if let definition = pmConversationCanonicalStandingAnalystDefinition(for: report) {
            return definition.charterId
        }
        return pmConversationAnalystReportLaneKey(report)
    }

    private func pmConversationCanonicalStandingAnalystDefinition(
        for report: AnalystStandingReport
    ) -> StandingAnalystBenchSeed.Definition? {
        let reportIdentifiers = [
            report.charterId,
            report.analystId,
            report.scheduleId,
            report.reportId,
            report.memoId
        ]
            .map { $0.trimmingCharacters(in: .whitespacesAndNewlines).lowercased() }
            .filter { $0.isEmpty == false }

        for definition in StandingAnalystBenchSeed.definitions {
            let canonicalIdentifiers = [
                definition.charterId,
                definition.analystId,
                "standing-report-\(definition.charterId)",
                "standing-report-\(definition.analystId)"
            ]
                .map { $0.lowercased() }
            if reportIdentifiers.contains(where: { identifier in
                canonicalIdentifiers.contains(identifier)
                    || canonicalIdentifiers.contains(where: { identifier.contains($0) })
            }) {
                return definition
            }
        }

        let normalizedReportTitle = pmConversationAnalystReportDisplayTitle(report)
            .lowercased()
            .replacingOccurrences(of: "[^a-z0-9]+", with: " ", options: .regularExpression)
            .trimmingCharacters(in: .whitespacesAndNewlines)
        guard normalizedReportTitle.isEmpty == false else {
            return nil
        }
        return StandingAnalystBenchSeed.definitions.first { definition in
            let normalizedDefinitionTitle = definition.title
                .lowercased()
                .replacingOccurrences(of: "[^a-z0-9]+", with: " ", options: .regularExpression)
                .trimmingCharacters(in: .whitespacesAndNewlines)
            return normalizedReportTitle == normalizedDefinitionTitle
                || normalizedReportTitle.hasPrefix("\(normalizedDefinitionTitle) ")
        }
    }

    private func pmConversationPMReviewDecisionsByStandingReportID(
        _ decisions: [PMDecisionRecord],
        standingReports: [AnalystStandingReport] = []
    ) -> [String: PMDecisionRecord] {
        var decisionsByReportID: [String: PMDecisionRecord] = [:]
        for decision in decisions
            where decision.status == .active && isExercisePMDecision(decision) == false {
            for reportID in pmConversationStandingReportIDs(for: decision) {
                guard reportID.isEmpty == false else { continue }
                if let existing = decisionsByReportID[reportID],
                   existing.updatedAt >= decision.updatedAt {
                    continue
                }
                decisionsByReportID[reportID] = decision
            }
        }
        for report in standingReports where decisionsByReportID[report.reportId] == nil {
            if let fallback = pmConversationPMReviewDecisionFallback(for: report, decisions: decisions) {
                decisionsByReportID[report.reportId] = fallback
            }
        }
        return decisionsByReportID
    }

    private func pmConversationPMReviewDecisionFallback(
        for report: AnalystStandingReport,
        decisions: [PMDecisionRecord]
    ) -> PMDecisionRecord? {
        let analystTitle = pmConversationAnalystReportDisplayTitle(report)
            .lowercased()
            .replacingOccurrences(of: "[^a-z0-9]+", with: " ", options: .regularExpression)
            .trimmingCharacters(in: .whitespacesAndNewlines)
        let definition = pmConversationCanonicalStandingAnalystDefinition(for: report)
        let canonicalTitle = definition?.title
            .lowercased()
            .replacingOccurrences(of: "[^a-z0-9]+", with: " ", options: .regularExpression)
            .trimmingCharacters(in: .whitespacesAndNewlines)
        let canonicalCharterID = definition?.charterId.lowercased() ?? report.charterId.lowercased()
        let reportStartWindow = report.createdAt.addingTimeInterval(-6 * 60 * 60)
        let reportEndWindow = max(max(report.updatedAt, report.deliveredToPMInboxAt), report.createdAt)
            .addingTimeInterval(24 * 60 * 60)
        return decisions
            .filter { decision in
                guard decision.status == .active,
                      isExercisePMDecision(decision) == false,
                      decision.updatedAt >= reportStartWindow,
                      decision.updatedAt <= reportEndWindow else {
                    return false
                }
                let explicitReportIDs = pmConversationStandingReportIDs(for: decision)
                if explicitReportIDs.isEmpty == false {
                    return explicitReportIDs.contains(report.reportId)
                }
                if decision.charterId?.lowercased() == canonicalCharterID {
                    return true
                }
                let titles = decision.standingReviewAnalystTitles ?? []
                if titles.contains(where: { title in
                    let normalized = title
                        .lowercased()
                        .replacingOccurrences(of: "[^a-z0-9]+", with: " ", options: .regularExpression)
                        .trimmingCharacters(in: .whitespacesAndNewlines)
                    return normalized == analystTitle
                        || (canonicalTitle != nil && normalized == canonicalTitle)
                }) {
                    return true
                }
                let text = [
                    decision.title,
                    decision.summary,
                    decision.recommendedAction ?? "",
                    decision.evidenceSummary ?? ""
                ]
                .joined(separator: " ")
                .lowercased()
                .replacingOccurrences(of: "[^a-z0-9]+", with: " ", options: .regularExpression)
                return text.contains(analystTitle)
                    || (canonicalTitle.map { text.contains($0) } ?? false)
            }
            .sorted { lhs, rhs in
                if lhs.updatedAt == rhs.updatedAt {
                    return lhs.decisionId < rhs.decisionId
                }
                return lhs.updatedAt > rhs.updatedAt
            }
            .first
    }

    private func pmConversationStandingReportIDs(
        for decision: PMDecisionRecord
    ) -> [String] {
        var ids: [String] = []
        if let primaryStandingReportID = decision.primaryStandingReportId,
           primaryStandingReportID.isEmpty == false {
            ids.append(primaryStandingReportID)
        }
        if let standingReportIDs = decision.standingReportIds {
            ids.append(contentsOf: standingReportIDs.filter { $0.isEmpty == false })
        }

        var seen = Set<String>()
        return ids.filter { seen.insert($0).inserted }
    }

    private func pmConversationAnalystReportRecencySort(
        lhs: AnalystStandingReport,
        rhs: AnalystStandingReport,
        decisionsByReportID: [String: PMDecisionRecord]
    ) -> Bool {
        let lhsTimestamp = pmConversationAnalystReportReviewSortTimestamp(
            lhs,
            linkedDecision: decisionsByReportID[lhs.reportId]
        )
        let rhsTimestamp = pmConversationAnalystReportReviewSortTimestamp(
            rhs,
            linkedDecision: decisionsByReportID[rhs.reportId]
        )
        if lhsTimestamp == rhsTimestamp {
            return lhs.reportId < rhs.reportId
        }
        return lhsTimestamp > rhsTimestamp
    }

    private func pmConversationAnalystReportReviewSortTimestamp(
        _ report: AnalystStandingReport,
        linkedDecision: PMDecisionRecord? = nil
    ) -> Date {
        if let linkedDecision {
            return max(linkedDecision.updatedAt, linkedDecision.createdAt)
        }
        return max(max(report.updatedAt, report.deliveredToPMInboxAt), report.createdAt)
    }

    private func pmConversationAnalystReportReviewTimestampKind(
        _ report: AnalystStandingReport,
        linkedDecision: PMDecisionRecord?
    ) -> String {
        if linkedDecision != nil {
            return "PM review decision updatedAt"
        }
        if report.deliveryStatus == .reviewedByPM {
            return "reviewed_by_pm report updatedAt"
        }
        if report.deliveredToPMInboxAt >= report.createdAt {
            return "deliveredToPMInboxAt"
        }
        return "createdAt"
    }

    private func pmConversationLooksLikeLatestReviewedAnalystReportAsk(
        normalizedAsk: String
    ) -> Bool {
        guard normalizedAsk.contains("analyst"),
              normalizedAsk.contains("report") else {
            return false
        }
        let tokens = Set(
            normalizedAsk
                .split(whereSeparator: { $0.isWhitespace })
                .map(String.init)
        )
        let latestSignal = normalizedAsk.contains("last")
            || normalizedAsk.contains("latest")
            || normalizedAsk.contains("most recent")
            || normalizedAsk.contains("that latest")
        let reviewedOrTimestampSignal = tokens.contains("reviewed")
            || tokens.contains("review")
            || (tokens.contains("day") && tokens.contains("time"))
            || tokens.contains("date")
            || tokens.contains("timestamp")
            || tokens.contains("time")
        let latestReportContentSignal = normalizedAsk.contains("only material")
            || normalizedAsk.contains("material signal")
            || normalizedAsk.contains("material signals")
        let explicitDetailSignal = tokens.contains("detail")
            || tokens.contains("details")
            || tokens.contains("detailed")
            || tokens.contains("section")
            || tokens.contains("sections")
            || tokens.contains("candidate")
            || tokens.contains("candidates")
            || tokens.contains("short")
            || tokens.contains("shorts")
            || tokens.contains("long")
            || tokens.contains("longs")
            || tokens.contains("article")
            || tokens.contains("articles")
            || tokens.contains("support")
            || tokens.contains("source")
            || tokens.contains("sources")
            || tokens.contains("evidence")
            || tokens.contains("skill")
            || tokens.contains("skills")
        if explicitDetailSignal && reviewedOrTimestampSignal == false && latestReportContentSignal == false {
            return false
        }
        return latestSignal && (reviewedOrTimestampSignal || latestReportContentSignal)
    }

    private func pmConversationLooksLikeLatestAnalystSourceAsk(
        normalizedAsk: String
    ) -> Bool {
        let analystSignal = normalizedAsk.contains("analyst")
        let sourceSignal = normalizedAsk.contains("source")
            || normalizedAsk.contains("sources")
            || normalizedAsk.contains("evidence")
            || normalizedAsk.contains("official")
            || normalizedAsk.contains("primary")
            || normalizedAsk.contains("secondary")
        let latestSignal = normalizedAsk.contains("latest")
            || normalizedAsk.contains("most recent")
            || normalizedAsk.contains("last")
            || normalizedAsk.contains("that latest")
        let researchSignal = normalizedAsk.contains("research")
            || normalizedAsk.contains("memo")
            || normalizedAsk.contains("task")
            || normalizedAsk.contains("work")
            || normalizedAsk.contains("report")
        if analystSignal && sourceSignal && (latestSignal || researchSignal) {
            return true
        }
        let recentNewsLaneSignal = normalizedAsk.contains("recent news")
            || normalizedAsk.contains("recent-news")
            || normalizedAsk.contains("news analyst")
        guard recentNewsLaneSignal else {
            return false
        }
        if latestSignal {
            return normalizedAsk.contains(" from ")
                || normalizedAsk.hasSuffix(" from")
                || normalizedAsk.contains(" take")
                || normalizedAsk.contains(" said")
                || normalizedAsk.contains(" say")
                || normalizedAsk.contains(" report")
        }
        let naturalAskSignal = normalizedAsk.contains("what did")
            || normalizedAsk.contains("what has")
            || normalizedAsk.contains("what does")
            || normalizedAsk.contains("what s new")
            || normalizedAsk.contains("whats new")
        let analystReadSignal = normalizedAsk.contains(" say")
            || normalizedAsk.contains(" said")
            || normalizedAsk.contains(" take")
            || normalizedAsk.contains(" view")
            || normalizedAsk.contains(" latest")
        return naturalAskSignal && analystReadSignal
    }

