    private func pmConversationAnalystReportLaneIndexSummaries(
        lanes: [PMConversationAnalystReportLane]
    ) -> [String] {
        let sortedLanes = lanes.sorted { lhs, rhs in
            if lhs.displayOrder == rhs.displayOrder {
                let lhsDate = lhs.latestReport?.updatedAt ?? .distantPast
                let rhsDate = rhs.latestReport?.updatedAt ?? .distantPast
                if lhsDate == rhsDate {
                    return lhs.laneKey < rhs.laneKey
                }
                return lhsDate > rhsDate
            }
            return lhs.displayOrder < rhs.displayOrder
        }
        let maxLaneCount = StandingAnalystBenchSeed.definitions.count
        let visibleLanes = Array(sortedLanes.prefix(maxLaneCount))
        let omittedLaneCount = max(0, sortedLanes.count - visibleLanes.count)
        let laneFragments = visibleLanes.map(pmConversationAnalystReportLaneFragment)
        let omittedSuffix = omittedLaneCount > 0
            ? " \(omittedLaneCount) non-standing extra lane(s) were omitted from this bounded latest-report prompt."
            : ""
        let instruction = "Analyst report lane index for PM reasoning: app-owned latest report status for every standing analyst lane. The PM model must choose the relevant analyst lane from the owner message; deterministic app code is not choosing the analyst lane. If the owner names or implies a lane, answer from that lane, or say no matching reviewed/report artifact exists for that lane. Do not substitute another analyst as the answer to a named-lane request.\(omittedSuffix)"
        let maxSummaryCount = 4
        let laneSummaryCount = max(1, maxSummaryCount - 1)
        let groupSize = max(1, Int(ceil(Double(laneFragments.count) / Double(laneSummaryCount))))
        var summaries = [instruction]
        var groupIndex = 0
        var cursor = 0
        while cursor < laneFragments.count && summaries.count < maxSummaryCount {
            groupIndex += 1
            let nextCursor = min(cursor + groupSize, laneFragments.count)
            let group = laneFragments[cursor..<nextCursor].joined(separator: " | ")
            summaries.append("Analyst report lane group \(groupIndex): \(group)")
            cursor = nextCursor
        }
        return summaries
    }

    private func pmConversationAnalystReportLaneFragment(
        _ lane: PMConversationAnalystReportLane
    ) -> String {
        if let reviewed = lane.latestReviewedReport {
            let linkedDecision = lane.latestReviewedDecision
            let timestamp = pmConversationAnalystReportReviewSortTimestamp(
                reviewed,
                linkedDecision: linkedDecision
            )
            let timestampKind = pmConversationAnalystReportReviewTimestampKind(
                reviewed,
                linkedDecision: linkedDecision
            )
            let detailHint = pmConversationLatestReviewedAnalystReportDetailHint(reviewed)
            let treatmentHint = linkedDecision
                .flatMap { pmConversationLatestReviewedAnalystReportDecisionHint($0) } ?? ""
            return "\(lane.analystTitle): latest reviewed \(DateCodec.formatISO8601(timestamp)) [\(timestampKind)]; report \(pmConversationShortArtifactID(reviewed.reportId)); title \(openAIResponsesTrimmed(reviewed.title, limit: 72)); signal \(openAIResponsesTrimmed(reviewed.headlineView.isEmpty ? reviewed.summary : reviewed.headlineView, limit: 120)).\(detailHint)\(treatmentHint)"
        }
        if let latest = lane.latestReport {
            let timestamp = pmConversationAnalystReportReviewSortTimestamp(latest)
            return "\(lane.analystTitle): no reviewed report found; latest status \(latest.deliveryStatus.rawValue), latest report \(DateCodec.formatISO8601(timestamp)); report \(pmConversationShortArtifactID(latest.reportId)); title \(openAIResponsesTrimmed(latest.title, limit: 72)); signal \(openAIResponsesTrimmed(latest.headlineView.isEmpty ? latest.summary : latest.headlineView, limit: 120))"
        }
        return "\(lane.analystTitle): no standing report found"
    }

    private func pmConversationLatestReviewedAnalystReportDetailHint(
        _ report: AnalystStandingReport
    ) -> String {
        let priorityKinds: [AnalystStandingReportSectionKind] = [
            .materialDevelopments,
            .importantItems,
            .portfolioRelevance,
            .riskIssues,
            .macroViews,
            .followUp
        ]
        let prioritizedSections = report.sections.filter { section in
            priorityKinds.contains(section.kind)
                || section.title.lowercased().contains("material")
                || section.title.lowercased().contains("signal")
        }
        let sections = prioritizedSections.isEmpty ? report.sections : prioritizedSections
        let fragments = sections.prefix(2).map { section in
            let rawSummary = section.summary?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
            let summary: String
            if rawSummary.isEmpty || pmConversationLooksLikeStandingReportScaffoldText(rawSummary) {
                summary = ""
            } else {
                summary = " summary \(openAIResponsesTrimmed(rawSummary, limit: 80))"
            }
            let items = section.items
                .filter { pmConversationIsStandingReportScaffoldItem($0) == false }
                .prefix(2)
                .map { item in
                var itemLine = openAIResponsesTrimmed(item.headline, limit: 80)
                let detail = item.detail.trimmingCharacters(in: .whitespacesAndNewlines)
                if detail.isEmpty == false {
                    itemLine += " detail \(openAIResponsesTrimmed(detail, limit: 90))"
                }
                return itemLine
            }
            guard items.isEmpty == false || summary.isEmpty == false else {
                return ""
            }
            guard items.isEmpty == false else {
                return "\(section.title)\(summary)"
            }
            return "\(section.title)\(summary) items \(items.joined(separator: " / "))"
        }.filter { $0.isEmpty == false }
        guard fragments.isEmpty == false else {
            return ""
        }
        return " Details: \(openAIResponsesTrimmed(fragments.joined(separator: "; "), limit: 260))."
    }

    private func pmConversationLatestReviewedAnalystReportDecisionHint(
        _ decision: PMDecisionRecord
    ) -> String? {
        let treatment = emptyToNil(decision.recommendedAction) ?? emptyToNil(decision.summary)
        guard let treatment else {
            return nil
        }
        return " PM treatment: \(openAIResponsesTrimmed(treatment, limit: 120))."
    }

    private func pmConversationShortArtifactID(
        _ value: String,
        limit: Int = 96
    ) -> String {
        let trimmed = value.trimmingCharacters(in: .whitespacesAndNewlines)
        guard trimmed.count > limit else { return trimmed }
        return "\(trimmed.prefix(limit))..."
    }

    private func pmConversationLooksLikeAnalystReportDetailAsk(
        normalizedAsk: String,
        askSignals: Set<String>,
        explicitlyNamedSymbols: Set<String>
    ) -> Bool {
        let detailSignals: Set<String> = [
            "detail", "details", "detailed",
            "section", "sections", "candidate", "candidates", "short", "shorts", "long", "longs",
            "inbox", "supporting", "support", "supports", "source", "sources", "evidence",
            "material", "signal", "signals", "article", "articles", "skill", "skills"
        ]
        if askSignals.intersection(detailSignals).isEmpty == false,
           normalizedAsk.contains("analyst") || normalizedAsk.contains("report") || normalizedAsk.contains("section") {
            return true
        }
        if normalizedAsk.contains("open details")
            || normalizedAsk.contains("detailed supporting section")
            || normalizedAsk.contains("best short candidates")
            || normalizedAsk.contains("best long candidates") {
            return true
        }
        return explicitlyNamedSymbols.isEmpty == false
            && (normalizedAsk.contains("report") || normalizedAsk.contains("analyst"))
    }

    private func pmConversationAnalystReportDetailScore(
        report: AnalystStandingReport,
        normalizedAsk: String,
        askSignals: Set<String>,
        explicitlyNamedSymbols: Set<String>
    ) -> Int {
        let analystTitle = pmConversationAnalystReportDisplayTitle(report)
        let reportValues = [
            report.reportId,
            report.analystId,
            report.charterId,
            report.title,
            analystTitle,
            report.summary,
            report.headlineView,
            report.portfolioRelevanceSummary
        ]
        var score = pmConversationRecoveryScore(
            textValues: reportValues,
            askSignals: askSignals
        )

        let normalizedAnalystTitle = analystTitle
            .lowercased()
            .replacingOccurrences(of: "[^a-z0-9]+", with: " ", options: .regularExpression)
            .trimmingCharacters(in: .whitespacesAndNewlines)
        if normalizedAnalystTitle.isEmpty == false,
           normalizedAsk.contains(normalizedAnalystTitle) {
            score += 12
        }
        for token in normalizedAnalystTitle.components(separatedBy: .whitespacesAndNewlines)
            where token.count >= 4 && askSignals.contains(token) {
            score += 4
        }
        if normalizedAsk.contains("sector analyst"),
           report.charterId.lowercased().contains("sector") {
            score += 2
        }

        for section in report.sections {
            score += pmConversationAnalystReportDetailSectionScore(
                section: section,
                normalizedAsk: normalizedAsk,
                askSignals: askSignals,
                explicitlyNamedSymbols: explicitlyNamedSymbols
            )
        }
        return score
    }

    private func pmConversationRelevantAnalystReportDetailSections(
        report: AnalystStandingReport,
        normalizedAsk: String,
        askSignals: Set<String>,
        explicitlyNamedSymbols: Set<String>
    ) -> [AnalystStandingReportSection] {
        report.sections
            .map { section in
                (
                    score: pmConversationAnalystReportDetailSectionScore(
                        section: section,
                        normalizedAsk: normalizedAsk,
                        askSignals: askSignals,
                        explicitlyNamedSymbols: explicitlyNamedSymbols
                    ),
                    section: section
                )
            }
            .filter { $0.score > 0 }
            .sorted { lhs, rhs in
                if lhs.score == rhs.score {
                    return lhs.section.sectionId < rhs.section.sectionId
                }
                return lhs.score > rhs.score
            }
            .map(\.section)
    }

    private func pmConversationAnalystReportDetailSectionScore(
        section: AnalystStandingReportSection,
        normalizedAsk: String,
        askSignals: Set<String>,
        explicitlyNamedSymbols: Set<String>
    ) -> Int {
        let sectionValues = [
            section.kind.displayTitle,
            section.title,
            section.summary ?? ""
        ] + section.items.flatMap { item in
            [
                item.symbol ?? "",
                item.headline,
                item.detail,
                item.stance.displayTitle
            ]
        }
        var score = pmConversationRecoveryScore(
            textValues: sectionValues,
            askSignals: askSignals
        )

        let normalizedSectionTitle = section.title
            .lowercased()
            .replacingOccurrences(of: "[^a-z0-9]+", with: " ", options: .regularExpression)
            .trimmingCharacters(in: .whitespacesAndNewlines)
        if normalizedSectionTitle.isEmpty == false,
           normalizedAsk.contains(normalizedSectionTitle) {
            score += 8
        }
        if normalizedAsk.contains("short"),
           section.kind == .shortIdeas {
            score += 10
        }
        if normalizedAsk.contains("long"),
           section.kind == .longIdeas {
            score += 8
        }
        if normalizedAsk.contains("detailed supporting section")
            || normalizedAsk.contains("open details")
            || normalizedAsk.contains("detail section") {
            score += 2
        }
        for symbol in explicitlyNamedSymbols {
            if section.items.contains(where: { item in
                item.symbol?.uppercased() == symbol
                    || item.headline.uppercased().contains(symbol)
                    || item.detail.uppercased().contains(symbol)
            }) {
                score += 5
            }
        }
        return score
    }

    private func pmConversationRelevantAnalystReportDetailItems(
        section: AnalystStandingReportSection,
        normalizedAsk: String,
        askSignals: Set<String>,
        explicitlyNamedSymbols: Set<String>
    ) -> [String] {
        let scoredItems = section.items.map { item in
            var score = pmConversationRecoveryScore(
                textValues: [
                    item.symbol ?? "",
                    item.headline,
                    item.detail,
                    item.stance.displayTitle
                ],
                askSignals: askSignals
            )
            if normalizedAsk.contains("short"),
               item.stance == .short {
                score += 5
            }
            if normalizedAsk.contains("long"),
               item.stance == .long {
                score += 4
            }
            for symbol in explicitlyNamedSymbols {
                if item.symbol?.uppercased() == symbol
                    || item.headline.uppercased().contains(symbol)
                    || item.detail.uppercased().contains(symbol) {
                    score += 6
                }
            }
            return (score: score, item: item)
        }

        let filteredItems: [AnalystStandingReportItem]
        let positiveMatches = scoredItems
            .filter { $0.score > 0 }
            .sorted { lhs, rhs in
                if lhs.score == rhs.score {
                    return lhs.item.itemId < rhs.item.itemId
                }
                return lhs.score > rhs.score
            }
            .map(\.item)
        if positiveMatches.isEmpty {
            filteredItems = Array(section.items.prefix(8))
        } else {
            filteredItems = Array(positiveMatches.prefix(8))
        }

        return filteredItems.prefix(8).map { item in
            let symbol = item.symbol.map { "\($0) " } ?? ""
            let conviction = item.conviction.map { " Conviction \($0)/10" } ?? ""
            let detail = item.detail.trimmingCharacters(in: .whitespacesAndNewlines)
            let detailFragment = detail.isEmpty
                ? ""
                : " Detail: \(openAIResponsesTrimmed(detail, limit: 520))."
            return "\(symbol)[\(item.stance.displayTitle)\(conviction)]: \(openAIResponsesTrimmed(item.headline, limit: 180)).\(detailFragment)"
        }
    }

    private func pmConversationAnalystReportDisplayTitle(
        _ report: AnalystStandingReport
    ) -> String {
        report.title
            .replacingOccurrences(of: " Standing Report", with: "")
            .replacingOccurrences(of: " standing report", with: "", options: .caseInsensitive)
            .trimmingCharacters(in: .whitespacesAndNewlines)
    }

    private func pmConversationRecentHistorySummary(
        sessionMessages: [PMCommunicationMessage],
        latestOwnerMessage: PMCommunicationMessage,
        recentOpenLoop: PMConversationOpenLoop?,
        suppressSyntheticRecaps: Bool
    ) -> [String] {
        let selectedMessages = Array(sessionMessages.suffix(160))
        return selectedMessages.compactMap { message in
            if suppressSyntheticRecaps,
               message.messageId != latestOwnerMessage.messageId,
               message.messageId != recentOpenLoop?.sourceMessageId,
               pmConversationShouldSuppressMixedHistoryMessage(message) {
                return nil
            }
            let body = pmConversationPreferredHistoryBody(for: message)
            guard body.isEmpty == false else { return nil }
            let role = message.senderRole == .owner ? "owner" : message.senderRole.rawValue
            let prefix: String
            if message.messageId == latestOwnerMessage.messageId {
                prefix = "\(role) (latest ask)"
            } else if message.messageId == recentOpenLoop?.sourceMessageId {
                prefix = "\(role) (latest unresolved ask)"
            } else if message.replyToMessageId == latestOwnerMessage.messageId {
                prefix = "\(role) (reply)"
            } else {
                prefix = role
            }
            return "\(prefix): \(boundedConversationText(body, limit: 1_200))"
        }
    }

    private func pmConversationShouldSuppressMixedHistoryMessage(
        _ message: PMCommunicationMessage
    ) -> Bool {
        let rawBody = pmConversationRawHistoryBody(for: message)
        return pmConversationUsesDeterministicVisibleReplyPath(message)
            || pmConversationLooksLikeDeterministicHistoryRenderer(rawBody)
            || pmConversationLooksLikeSyntheticConversationRecap(rawBody)
    }

    private func pmConversationActiveStateSummary(
        latestOwnerMessage: PMCommunicationMessage,
        recentOpenLoop: PMConversationOpenLoop?
    ) -> [String] {
        var lines: [String] = []

        if let recentOpenLoop {
            switch recentOpenLoop.kind {
            case .yesNoConfirmation:
                lines.append("Latest unresolved PM confirmation ask: \(recentOpenLoop.promptSummary)")
            case .clarification:
                lines.append("Latest unresolved PM clarification ask: \(recentOpenLoop.promptSummary)")
            }
            if let workingSummary = recentOpenLoop.pendingAskState?.workingUnderstandingSummary,
               workingSummary.isEmpty == false {
                lines.append("Latest PM working understanding attached to that ask: \(workingSummary)")
            }
            if recentOpenLoop.pendingAskState?.durableTargetType == .pmInstruction {
                lines.append("If that ask is confirmed, the bounded durable target path is a PM instruction rather than holdings truth.")
            }
        }

        if latestOwnerMessage.replyToMessageId == recentOpenLoop?.sourceMessageId {
            lines.append("The owner explicitly replied to the PM message that opened the active loop.")
        }

        return Array(lines.prefix(4))
    }

    private func pmConversationConfirmedAppTruthSummary(
        _ contextPack: PMContextPack,
        approvalRequests: [PMApprovalRequest],
        latestOwnerAsk: String,
        liveExecutionProtectionSettings: LiveExecutionProtectionSettings
    ) -> [String] {
        var lines: [String] = []

        if contextPack.sharedPortfolioTruth.positionCount == 0 {
            lines.append("Confirmed current holdings in app truth: none recorded.")
        } else {
            let positions = contextPack.sharedPortfolioTruth.topPositions.map {
                "\($0.symbol) (\($0.directionLabel), \($0.marketValue))"
            }
            lines.append("Confirmed current holdings in app truth: \(positions.joined(separator: ", "))")
        }

        if contextPack.sharedPortfolioTruth.openOrderCount == 0 {
            lines.append("Confirmed current open orders in app truth: none recorded.")
        } else {
            lines.append(
                "Confirmed current open orders in app truth: \(contextPack.sharedPortfolioTruth.openOrderPreview.joined(separator: ", "))"
            )
        }

        lines.append(
            contentsOf: pmConversationLiveOrderReviewRouteTruthSummary(
                approvalRequests: approvalRequests,
                latestOwnerAsk: latestOwnerAsk
            )
        )

        if let paperStatus = contextPack.sharedPortfolioTruth.paperEstablishmentExecutionStatus {
            lines.append(
                "Confirmed paper-establishment execution lifecycle in app truth: \(paperStatus.summary)"
            )
            if paperStatus.missingPriceSymbols.isEmpty == false {
                lines.append(
                    "Current paper-establishment missing prices in app truth: \(paperStatus.missingPriceSymbols.joined(separator: ", "))."
                )
            }
            if paperStatus.targetSymbols.isEmpty == false {
                lines.append(
                    "Current paper-establishment target symbols in app truth: \(paperStatus.targetSymbols.joined(separator: ", "))."
                )
            }
            if let planStatus = paperStatus.orderPlanStatus {
                lines.append(
                    "Latest paper-establishment order-plan status in app truth: \(planStatus.rawValue). order_attempts=\(paperStatus.orderAttemptCount) accepted=\(paperStatus.acceptedOrderAttemptCount) failed=\(paperStatus.failedOrderAttemptCount)."
                )
            }
            if paperStatus.blockedReasons.isEmpty == false {
                lines.append(
                    "Latest paper-establishment route blockers in app truth: \(paperStatus.blockedReasons.map(\.rawValue).joined(separator: ", "))."
                )
            }
            if let blocker = paperStatus.lastBlockerSummary,
               blocker.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty == false {
                lines.append(
                    "Latest paper-establishment route/retry blocker in app truth: \(boundedConversationText(blocker, limit: 220))"
                )
            }
            if paperStatus.automaticRetryEnabled {
                lines.append(
                    "App-owned paper-establishment recovery state: automatic retry is armed for this approved request when usable prices become available."
                )
            } else if paperStatus.state == .approvedNoActiveExecutionState {
                lines.append(
                    "App-owned paper-establishment recovery state: no automatic retry/pending execution is currently armed for the approved request."
                )
            }
        }

        lines.append(
            "Confirmed system readiness in app truth: \(contextPack.systemReadiness.status.displayName). \(boundedConversationText(contextPack.systemReadiness.summary, limit: 220))"
        )
        if contextPack.systemReadiness.blockers.isEmpty == false {
            lines.append(
                "Current readiness blockers in app truth: \(contextPack.systemReadiness.blockers.prefix(3).joined(separator: " "))"
            )
        }

        lines.append(contentsOf: makePMContextPortfolioWatchReadinessSummaryLines(contextPack.portfolioWatchReadiness))
        lines.append(
            liveExecutionProtectionConfirmedAppTruthLine(settings: liveExecutionProtectionSettings)
        )

        let alpacaReadiness = keychainProvider.alpacaCredentialReadiness(
            for: configuration.environment
        )
        if alpacaReadiness.isReady {
            lines.append(
                "Confirmed Alpaca trading credential readiness in app truth: \(configuration.environment.rawValue) order placement credentials are available."
            )
        } else {
            var missingPieces: [String] = []
            if alpacaReadiness.publicKeyFound == false {
                missingPieces.append("public key")
            }
            if alpacaReadiness.secretKeyFound == false {
                missingPieces.append("secret key")
            }
            let missingSummary = missingPieces.isEmpty ? "credentials" : missingPieces.joined(separator: " and ")
            lines.append(
                "Confirmed Alpaca trading credential blocker in app truth: \(configuration.environment.rawValue) order placement is blocked because the trading \(missingSummary) are unavailable in Keychain. Existing account data does not prove current order-submission readiness."
            )
        }

        lines.append(contentsOf: makePMContextPortfolioIntelligenceSummaryLines(contextPack.portfolioIntelligence))

        if contextPack.sharedPortfolioTruth.watchlistPreview.isEmpty {
            lines.append("Confirmed current watchlist in app truth: none recorded.")
        } else {
            lines.append(
                "Confirmed current watchlist in app truth: \(contextPack.sharedPortfolioTruth.watchlistPreview.joined(separator: ", "))"
            )
        }

        if let strategyBrief = contextPack.sharedPortfolioTruth.strategyBrief {
            lines.append(
                "Confirmed strategy brief posture: objective \(strategyBrief.objectiveSummary); risk posture \(strategyBrief.currentRiskPosture)."
            )
        }

        if contextPack.sharedPortfolioTruth.pendingPaperExecutions.isEmpty == false {
            for pending in contextPack.sharedPortfolioTruth.pendingPaperExecutions.prefix(2) {
                lines.append(
                    "Approved paper-portfolio execution already recorded in app truth: \(boundedConversationText(pending.subject, limit: 180))."
                )
                lines.append(
                    "Current execution blocker in app truth: usable prices missing for \(pending.missingPriceSymbols.joined(separator: ", "))."
                )
                if pending.automaticRetryEnabled {
                    lines.append(
                        "App-owned recovery state: market-data recovery is already requested for those symbols, and the app will reattempt sizing/submission automatically when usable prices arrive without asking for the same approval again."
                    )
                } else {
                    lines.append(
                        "App-owned recovery state: no automatic retry is armed yet."
                    )
                }
            }
        }

        return lines
    }

    private func pmConversationSignalTruthSummaryIfNeeded(_ ownerAsk: String) async -> [String] {
        guard pmConversationAskNeedsSignalTruth(ownerAsk) else {
            return []
        }

        do {
            let signals = try await signalStore.list(limit: 100)
            return makePMConversationSignalTruthSummary(
                ask: ownerAsk,
                signals: signals,
                now: nowDate(),
                limit: 8
            )
        } catch {
            return [
                "Signal truth unavailable: app-owned Signal Store could not be read for this reply (\(boundedConversationText(error.localizedDescription, limit: 160)))."
            ]
        }
    }

