        latestOwnerMessage: PMCommunicationMessage,
        sessionMessages: [PMCommunicationMessage],
        contextPack: PMContextPack
    ) -> [String] {
        var lines: [String] = []

        lines.append(
            contentsOf: contextPack.activeInstructions.prefix(3).map { instruction in
                "Durable PM instruction still in force until archived or replaced: \(instruction.title) — \(boundedConversationText(instruction.body, limit: 260))"
