    private func pmConversationOwnerFacingRecoveredContextLine(_ summary: String) -> String {
        let trimmed = summary.trimmingCharacters(in: .whitespacesAndNewlines)
        let specificEntryPrefix = "Specific communication entry body window: "
        let conversationPrefix = "Conversation continuity: "
        let communicationLogPrefix = "Detailed communication-log body window: "
        let communicationLogExcerptPrefix = "Detailed communication-log excerpt: "
        let weekScaleCommunicationLogPrefix = "Week-scale communication-log body window: "
        let notebookPrefix = "PM notebook: "
        let memoryPrefix = "Retrieved memory: "
        let promotedPrefix = "Promoted communication outcome: "
        let standingReviewPrefix = "Standing-review memory: "

        if trimmed.hasPrefix(specificEntryPrefix) {
            return "Specific earlier communication entry: \(trimmed.dropFirst(specificEntryPrefix.count))"
        }
        if trimmed.hasPrefix(weekScaleCommunicationLogPrefix) {
            return "Earlier this week's communication log: \(trimmed.dropFirst(weekScaleCommunicationLogPrefix.count))"
        }
        if trimmed.hasPrefix(communicationLogPrefix) {
            return "Recent communication log excerpt: \(trimmed.dropFirst(communicationLogPrefix.count))"
        }
        if trimmed.hasPrefix(communicationLogExcerptPrefix) {
            return "Recent communication log excerpt: \(trimmed.dropFirst(communicationLogExcerptPrefix.count))"
        }
        if trimmed.hasPrefix(conversationPrefix) {
            return "Earlier conversation context: \(trimmed.dropFirst(conversationPrefix.count))"
        }
        if trimmed.hasPrefix(notebookPrefix) {
            return "Notebook note: \(trimmed.dropFirst(notebookPrefix.count))"
        }
        if trimmed.hasPrefix(memoryPrefix) {
            return "Relevant remembered preference: \(trimmed.dropFirst(memoryPrefix.count))"
        }
        if trimmed.hasPrefix(promotedPrefix) {
            return "Recorded communication outcome: \(trimmed.dropFirst(promotedPrefix.count))"
        }
        if trimmed.hasPrefix(standingReviewPrefix) {
            return "Standing-review conclusion: \(trimmed.dropFirst(standingReviewPrefix.count))"
        }
        if trimmed.hasPrefix("Same-day communication thread") {
            return trimmed.replacingOccurrences(of: "Same-day communication thread", with: "Earlier same-day thread")
        }
        return trimmed
    }

    private func pmConversationRecentLiveOrderReviewRouteRequests(
        approvalRequests: [PMApprovalRequest],
        latestOwnerAsk: String,
        limit: Int
    ) -> [PMApprovalRequest] {
        guard pmConversationOwnerAskIsLiveOrderReadback(latestOwnerAsk) else {
            return []
        }

        let normalizedAsk = normalizedPMCommitmentText(latestOwnerAsk)
        let mentionedSymbols = Set(
            approvalRequests
                .compactMap { $0.liveOrderReview?.symbol.trimmingCharacters(in: .whitespacesAndNewlines).uppercased() }
                .filter { symbol in
                    normalizedAsk.contains(symbol.lowercased())
                }
        )

        let liveOrderReviewRequests = approvalRequests
            .filter { request in
                isExercisePMApprovalRequest(request) == false
                    && request.requestType == .liveOrderReview
                    && (
                        request.lastExecutionRoutingAssessment != nil
                            || request.status == .pending
                            || request.ownerResponse != nil
                    )
            }
            .filter { request in
                guard mentionedSymbols.isEmpty == false else { return true }
                guard let symbol = request.liveOrderReview?.symbol.trimmingCharacters(in: .whitespacesAndNewlines).uppercased() else {
                    return true
                }
                return mentionedSymbols.contains(symbol)
            }
            .sorted { lhs, rhs in
                if lhs.updatedAt == rhs.updatedAt {
                    return lhs.approvalRequestId < rhs.approvalRequestId
                }
                return lhs.updatedAt > rhs.updatedAt
            }

        return Array(liveOrderReviewRequests.prefix(max(limit, 0)))
    }

    private func pmConversationLiveOrderReviewRouteTruthSummary(
        approvalRequests: [PMApprovalRequest],
        latestOwnerAsk: String
    ) -> [String] {
        let requests = pmConversationRecentLiveOrderReviewRouteRequests(
            approvalRequests: approvalRequests,
            latestOwnerAsk: latestOwnerAsk,
            limit: 2
        )
        guard requests.isEmpty == false else {
            if pmConversationOwnerAskIsLiveOrderReadback(latestOwnerAsk) {
                return [
                    "Confirmed Live order review route in app truth: no recent live_order_review approval or route record matched this status/readback ask."
                ]
            }
            return []
        }

        return requests.flatMap { request -> [String] in
            var lines: [String] = []
            var payloadParts: [String] = []
            if let payload = request.liveOrderReview {
                payloadParts.append(payload.symbol.trimmingCharacters(in: .whitespacesAndNewlines).uppercased())
                payloadParts.append(payload.side.rawValue)
                payloadParts.append(payload.orderType.rawValue)
                payloadParts.append(payload.timeInForce.rawValue)
                if let quantity = payload.quantity {
                    payloadParts.append("quantity=\(quantity.description)")
                }
                if let notional = payload.notionalAmount {
                    payloadParts.append("target_notional=\(notional.description)")
                }
                payloadParts.append("environment=\(payload.environment.rawValue)")
            }
            let ownerResponse = request.ownerResponse?.rawValue ?? "none"
            lines.append(
                "Confirmed Live order review route in app truth: subject=\"\(boundedConversationText(request.subject, limit: 140))\" request_status=\(request.status.rawValue) owner_response=\(ownerResponse)\(payloadParts.isEmpty ? "" : " payload=\(payloadParts.joined(separator: " "))")."
            )
            if let assessment = request.lastExecutionRoutingAssessment {
                lines.append(
                    "Confirmed Live order review routing result in app truth: route_status=\(assessment.status.rawValue) action=\(assessment.action.rawValue) environment=\(assessment.environment.rawValue) live_armed=\(assessment.isLiveArmed) kill_switch=\(assessment.killSwitchEnabled ? "on" : "off") summary=\(boundedConversationText(assessment.summary, limit: 220))"
                )
                let detail = boundedConversationText(assessment.detail, limit: 360)
                if detail.isEmpty == false,
                   detail.caseInsensitiveCompare(assessment.summary) != .orderedSame {
                    lines.append(
                        "Confirmed Live order review route detail in app truth: \(detail)"
                    )
                }
                if assessment.blockedReasons.isEmpty == false {
                    lines.append(
                        "Confirmed Live order review blockers in app truth: \(assessment.blockedReasons.map(\.rawValue).joined(separator: ", "))."
                    )
                }
            } else {
                lines.append(
                    "Confirmed Live order review routing result in app truth: no route/preflight assessment is recorded yet for this review."
                )
            }
            if let lifecycle = request.liveOrderExecutionLifecycleState {
                lines.append(
                    "Confirmed Live order review order lifecycle in app truth: status=\(lifecycle.status.rawValue) symbol=\(lifecycle.symbol) side=\(lifecycle.side.rawValue) quantity=\(lifecycle.quantity.map(String.init) ?? "-") summary=\(boundedConversationText(lifecycle.summary, limit: 220))"
                )
                let detail = boundedConversationText(lifecycle.detail, limit: 360)
                if detail.isEmpty == false,
                   detail.caseInsensitiveCompare(lifecycle.summary) != .orderedSame {
                    lines.append("Confirmed Live order lifecycle detail in app truth: \(detail)")
                }
                if lifecycle.completionFollowThroughMessageId != nil {
                    lines.append("Confirmed Live order PM completion follow-through in app truth: delivered.")
                }
            }
            if request.ownerAcknowledgedAt != nil {
                lines.append("Confirmed Live order review cleanup in app truth: owner acknowledged/cleared this review from active decisions.")
            }
            return lines
        }
    }

    private func pmConversationNaturalHistorySnippet(_ summary: String) -> String {
        let ownerFacing = pmConversationOwnerFacingRecoveredContextLine(summary)
        let normalized = ownerFacing.replacingOccurrences(of: " || ", with: " Then ")
        let specificEntryPrefix = "Specific earlier communication entry: "
        let prefixes = [
            specificEntryPrefix,
            "Recent communication log excerpt: ",
            "Earlier same-day thread",
            "Earlier conversation context: ",
            "Notebook note: ",
            "Relevant remembered preference: ",
            "Recorded communication outcome: "
        ]

        if normalized.hasPrefix("Earlier same-day thread"),
           let separatorRange = normalized.range(of: ": ") {
            return String(normalized[separatorRange.upperBound...]).trimmingCharacters(in: .whitespacesAndNewlines)
        }

        if normalized.hasPrefix(specificEntryPrefix) {
            let body = String(normalized.dropFirst(specificEntryPrefix.count)).trimmingCharacters(in: .whitespacesAndNewlines)
            let searchRange = body.range(of: "Then pm [") ?? body.range(of: "pm [")
            if let searchRange,
               let replySeparator = body[searchRange.lowerBound...].range(of: "]: ") {
                return String(body[replySeparator.upperBound...]).trimmingCharacters(in: .whitespacesAndNewlines)
            }
            return body
        }

        for prefix in prefixes where normalized.hasPrefix(prefix) {
            return String(normalized.dropFirst(prefix.count)).trimmingCharacters(in: .whitespacesAndNewlines)
        }

        return normalized
    }

    private func pmConversationNaturalHistoryPriority(
        summary: String,
        normalizedAsk: String
    ) -> Int {
        let trimmed = summary.trimmingCharacters(in: .whitespacesAndNewlines)
        if normalizedAsk.contains("notebook"), trimmed.hasPrefix("PM notebook: ") {
            return 6
        }
        if trimmed.hasPrefix("Specific communication entry body window: ") {
            return 8
        }
        if trimmed.hasPrefix("Week-scale communication-log body window: ") {
            return 6
        }
        if trimmed.hasPrefix("Detailed communication-log body window: ")
            || trimmed.hasPrefix("Detailed communication-log excerpt: ") {
            return 5
        }
        if trimmed.hasPrefix("Same-day communication thread") {
            return 4
        }
        if trimmed.hasPrefix("PM notebook: ") {
            return 3
        }
        if trimmed.hasPrefix("Retrieved memory: ") || trimmed.hasPrefix("Promoted communication outcome: ") {
            return 2
        }
        if trimmed.hasPrefix("Conversation continuity: ") {
            return 0
        }
        return 1
    }

    private func pmConversationNaturalHistoryFallbackBody(
        ask: String,
        detailedCommunicationHistorySummary: [String],
        recoveredContextSummary: [String],
        confirmedHoldingsRecorded: Bool
    ) -> String? {
        let normalizedAsk = ask.lowercased()
        let prioritizedSummaries = (detailedCommunicationHistorySummary + recoveredContextSummary)
            .enumerated()
            .sorted { lhs, rhs in
                let lhsPriority = pmConversationNaturalHistoryPriority(
                    summary: lhs.element,
                    normalizedAsk: normalizedAsk
                )
                let rhsPriority = pmConversationNaturalHistoryPriority(
                    summary: rhs.element,
                    normalizedAsk: normalizedAsk
                )
                if lhsPriority == rhsPriority {
                    return lhs.offset < rhs.offset
                }
                return lhsPriority > rhsPriority
            }
            .map(\.element)
        guard let leadSummary = prioritizedSummaries.first else {
            return nil
        }
        let exactSpecificEntryRequested = leadSummary
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .hasPrefix("Specific communication entry body window: ")

        let leadSnippet = boundedConversationText(
            pmConversationNaturalHistorySnippet(leadSummary),
            limit: 460
        )
        guard leadSnippet.isEmpty == false else {
            return nil
        }

        let asksForPortfolio = pmConversationAsksForWorkingPortfolioDefinition(normalizedAsk)
            || normalizedAsk.contains("portfolio")
            || normalizedAsk.contains("positions")
            || normalizedAsk.contains("position")
            || normalizedAsk.contains("long")
            || normalizedAsk.contains("short")
        let referencesEarlierWeek = normalizedAsk.contains("last week")
            || normalizedAsk.contains("earlier this week")
        let asksRecallQuestion = normalizedAsk.contains("what did we decide")
            || normalizedAsk.contains("remind me")
            || normalizedAsk.contains("what was the latest")
            || normalizedAsk.contains("what did i say")
            || normalizedAsk.contains("what did we say")
            || normalizedAsk.contains("do you recall")
            || normalizedAsk.contains("do you remember")
            || normalizedAsk.contains("can you see")
            || normalizedAsk.contains("pull that")

        let intro: String
        if asksForPortfolio {
            intro = referencesEarlierWeek
                ? "Earlier this week, the latest proposed paper portfolio I can recover was \(leadSnippet)."
                : "The latest proposed paper portfolio I can recover from our recent conversation is \(leadSnippet)."
        } else if asksRecallQuestion {
            intro = referencesEarlierWeek
                ? "Earlier this week, the clearest earlier answer I can recover was \(leadSnippet)."
                : "The clearest earlier answer I can recover from our conversation is \(leadSnippet)."
        } else {
            intro = "The clearest earlier context I can recover is \(leadSnippet)."
        }

        var lines = [intro]
        if exactSpecificEntryRequested == false, prioritizedSummaries.count > 1 {
            let followThrough = boundedConversationText(
                pmConversationNaturalHistorySnippet(prioritizedSummaries[1]),
                limit: 320
            )
            if followThrough.isEmpty == false && followThrough != leadSnippet {
                lines.append("A nearby detail from the same thread is \(followThrough).")
            }
        }
        if asksForPortfolio {
            lines.append(
                confirmedHoldingsRecorded
                    ? "I’m treating that as the latest conversation-defined proposal alongside the current app-confirmed holdings view."
                    : "I’m treating that as the latest conversation-defined proposal, not as confirmed holdings."
            )
        }
        return lines.joined(separator: "\n\n")
    }

    private func pmConversationNaturalAnalystArtifactFallbackBody(
        ask: String,
        analystArtifactSummary: [String],
        latestWorkingPortfolioSnapshot: PMConversationOperatingTruthSnapshot?
    ) -> String? {
        let normalizedAsk = ask.lowercased()
        let asksForAnalystGrounding = normalizedAsk.contains("analyst")
            || normalizedAsk.contains("report")
            || normalizedAsk.contains("reports")
            || normalizedAsk.contains("research")
            || normalizedAsk.contains("memo")
            || normalizedAsk.contains("conviction")
            || normalizedAsk.contains("reasoning")
            || normalizedAsk.contains("view")
            || normalizedAsk.contains("case")
            || normalizedAsk.contains("thesis")
        guard asksForAnalystGrounding else {
            return nil
        }

        if analystArtifactSummary.isEmpty {
            if let latestWorkingPortfolioSnapshot {
                return [
                    "I’m still carrying your latest proposed portfolio as the current working context: \(boundedConversationText(latestWorkingPortfolioSnapshot.body, limit: 320)).",
                    "I do not yet have enough recent analyst detail recovered to give a cleaner conviction or reasoning answer than that. If you want, I can re-anchor on the relevant analyst work next."
                ].joined(separator: "\n\n")
            }
            return "I do not yet have enough recent analyst detail recovered to answer that conviction or reasoning question cleanly."
        }

        let intro: String
        if normalizedAsk.contains("short") || normalizedAsk.contains("hedge") {
            intro = "For the short-side follow-up, here is the cleanest recent analyst grounding I can recover:"
        } else if normalizedAsk.contains("long") {
            intro = "For the long-side follow-up, here is the cleanest recent analyst grounding I can recover:"
        } else {
            intro = "Here is the cleanest recent analyst grounding I can recover for that follow-up:"
        }
        let lines = analystArtifactSummary.prefix(4).map { "- \($0)" }.joined(separator: "\n")
        return [intro, lines].joined(separator: "\n\n")
    }

    private func pmConversationLooksLikeDeterministicHistoryRenderer(_ body: String) -> Bool {
        let normalized = body.lowercased()
        let markers = [
            "here is the strongest earlier context i found",
            "the most relevant prior context i found",
            "if you want, i can go one layer deeper",
            "i checked the earlier app-owned conversation context",
            "i checked the bounded standing-review conclusions linked to recent reviewed analyst reports",
            "i’m grounding this on the current objective",
            "i'm grounding this on the current objective",
            "the app does not currently show confirmed holdings",
            "any long, short, or theme ideas from standing review remain candidate research context"
        ]
        let markerCount = markers.reduce(into: 0) { count, marker in
            if normalized.contains(marker) {
                count += 1
            }
        }
        return normalized.contains("here is the strongest earlier context i found") || markerCount >= 2
    }

    private func pmConversationUsesDeterministicVisibleReplyPath(
        _ message: PMCommunicationMessage
    ) -> Bool {
        guard message.senderRole == .pm,
              let runtimeProvenance = message.runtimeProvenance else {
            return false
        }
        if runtimeProvenance.conversationTrace?.visibleReplySource == .deterministicFallback {
            return true
        }
        return runtimeProvenance.usedOpenAI == false
            && runtimeProvenance.actualRuntimeIdentifier.hasPrefix("deterministic_local_fallback[")
    }

    private func pmConversationSanitizedHistoryRendererBody(_ body: String) -> String {
        let paragraphs = body
            .components(separatedBy: "\n\n")
            .map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
            .filter { $0.isEmpty == false }
            .filter { paragraph in
                let normalized = paragraph.lowercased()
                return normalized.contains("here is the strongest earlier context i found") == false
                    && normalized.contains("the most relevant prior context i found") == false
                    && normalized.contains("if you want, i can go one layer deeper") == false
                    && normalized.contains("the app does not currently show confirmed holdings") == false
                    && normalized.contains("any long, short, or theme ideas from standing review remain candidate research context") == false
                    && normalized.contains("i’m grounding this on the current objective") == false
                    && normalized.contains("i'm grounding this on the current objective") == false
            }
        return paragraphs.joined(separator: "\n\n").trimmingCharacters(in: .whitespacesAndNewlines)
    }

    private func pmConversationPreferredHistoryBody(
        for message: PMCommunicationMessage
    ) -> String {
        let rawBody = message.body.trimmingCharacters(in: .whitespacesAndNewlines)
        let operatingTruthBody = message.conversationResolution?.operatingTruthBody?
            .trimmingCharacters(in: .whitespacesAndNewlines)

        guard rawBody.isEmpty == false else {
            return operatingTruthBody ?? ""
        }

        if pmConversationUsesDeterministicVisibleReplyPath(message) {
            if let operatingTruthBody, operatingTruthBody.isEmpty == false {
                return operatingTruthBody
            }
            return pmConversationSanitizedHistoryRendererBody(rawBody)
        }

        if pmConversationLooksLikeDeterministicHistoryRenderer(rawBody) {
            if let operatingTruthBody, operatingTruthBody.isEmpty == false {
                return operatingTruthBody
            }
            return pmConversationSanitizedHistoryRendererBody(rawBody)
        }

        if pmConversationLooksLikeSyntheticConversationRecap(rawBody),
           let operatingTruthBody,
           operatingTruthBody.isEmpty == false {
            return operatingTruthBody
        }

        return rawBody
    }

    private func pmConversationHistoryTextValues(
        for message: PMCommunicationMessage
    ) -> [String] {
        var values = [pmConversationPreferredHistoryBody(for: message)]
        if let resolution = message.conversationResolution {
            if let summary = resolution.operatingTruthSummary?.trimmingCharacters(in: .whitespacesAndNewlines),
               summary.isEmpty == false {
                values.append(summary)
            }
            if let body = resolution.operatingTruthBody?.trimmingCharacters(in: .whitespacesAndNewlines),
               body.isEmpty == false {
                values.append(body)
            }
        }
        return orderedUniqueStrings(values.filter { $0.isEmpty == false })
    }

    private func pmConversationHistoryAnchorScore(
        for message: PMCommunicationMessage,
        askSignals: Set<String>,
        asksForWorkingPortfolio: Bool,
        currentSessionId: String
    ) -> Int {
        let textValues = pmConversationHistoryTextValues(for: message)
        var score = pmConversationRecoveryScore(
            textValues: textValues,
            askSignals: askSignals
        )
        if asksForWorkingPortfolio {
            score += textValues.reduce(into: 0) { valueScore, text in
                valueScore += pmConversationWorkingPortfolioSignalScore(text)
            }
            if message.senderRole == .owner
                && (pmConversationLooksLikeDirective(message.body)
                    || pmConversationLooksLikeExplicitWorkingPortfolioStatement(message.body)) {
                score += 3
            }
            let resolvedKind = message.conversationResolution?.operatingTruthKind
                ?? pmConversationOperatingTruthKind(from: message.conversationResolution?.instructionTargetKind)
            if resolvedKind == .workingPortfolioDefinition {
                score += 8
            }
        }
        if message.sessionId == currentSessionId {
            score += 2
        }
        if pmConversationUsesDeterministicVisibleReplyPath(message) {
            score -= 16
        }
        if pmConversationLooksLikeDeterministicHistoryRenderer(message.body) {
            score -= 12
        }
        if pmConversationLooksLikeSyntheticConversationRecap(message.body) {
            score -= 8
        }
        return score
    }

    private func pmConversationCommunicationLogExcerptSummary(
        _ messages: [PMCommunicationMessage],
        prefix: String
    ) -> String {
        let excerpt = messages
            .compactMap { message -> String? in
                let body = pmConversationPreferredHistoryBody(for: message)
                guard body.isEmpty == false else { return nil }
                let role = message.senderRole == .owner ? "owner" : message.senderRole.rawValue
                return "\(role): \(openAIResponsesTrimmed(body, limit: 1_200))"
            }
            .joined(separator: " || ")
        guard excerpt.isEmpty == false else {
            return ""
        }
        return "\(prefix)\(excerpt)"
    }

    private struct PMConversationSpecificEntryReference: Sendable, Equatable {
        let referencedAt: Date?
        let hasExplicitTime: Bool
        let preferredSenderRole: PMCommunicationSenderRole?
        let messageIDHint: String?
    }

    private struct PMConversationSpecificEntryContext: Sendable, Equatable {
        let matchedMessageId: String
        let sessionId: String
        let sortDate: Date
        let summary: String
    }

    private func pmConversationRawHistoryBody(
        for message: PMCommunicationMessage
    ) -> String {
        message.body.trimmingCharacters(in: .whitespacesAndNewlines)
    }

    private func pmConversationSpecificEntryReference(
        from ask: String,
        relativeTo anchorDate: Date
    ) -> PMConversationSpecificEntryReference? {
        let normalized = ask.lowercased()
        let preferredSenderRole: PMCommunicationSenderRole?
        if normalized.contains("your response")
            || normalized.contains("your reply")
            || normalized.contains("pm response")
            || normalized.contains("pm reply")
            || normalized.contains("response to me") {
            preferredSenderRole = .pm
        } else if normalized.contains("my message")
            || normalized.contains("my prompt")
            || normalized.contains("my earlier note") {
            preferredSenderRole = .owner
        } else {
            preferredSenderRole = nil
        }

        let explicitEntryLanguage = normalized.contains("actual list is in your response")
            || normalized.contains("the actual list is in your response")
            || normalized.contains("that detailed log")
            || normalized.contains("detailed log file")
            || normalized.contains("specific earlier response")
            || normalized.contains("that earlier response")
            || normalized.contains("that response")
            || normalized.contains("that reply")
            || pmConversationContainsMonthReference(normalized)
            || normalized.contains("at 11:")
            || normalized.contains("at 10:")
            || normalized.contains("at 12:")
            || normalized.contains("at 1:")
            || normalized.contains("at 2:")
            || normalized.contains("at 3:")
            || normalized.contains("at 4:")
            || normalized.contains("at 5:")
            || normalized.contains("at 6:")
            || normalized.contains("at 7:")
            || normalized.contains("at 8:")
            || normalized.contains("at 9:")
        let referencedAt = pmConversationSpecificEntryDateReference(
            from: ask,
            relativeTo: anchorDate
        )
        let messageIDHint = pmConversationSpecificEntryMessageIDHint(from: ask)
        guard referencedAt != nil
                || messageIDHint != nil
                || (explicitEntryLanguage && preferredSenderRole != nil) else {
            return nil
        }
        return PMConversationSpecificEntryReference(
            referencedAt: referencedAt?.date,
            hasExplicitTime: referencedAt?.hasExplicitTime ?? false,
            preferredSenderRole: preferredSenderRole,
            messageIDHint: messageIDHint
        )
    }

    private func pmConversationContainsMonthReference(_ normalizedAsk: String) -> Bool {
        pmConversationFirstRegexMatch(
            pattern: "(?i)\\b(?:on\\s+)?(january|february|march|april|may|june|july|august|september|sept|october|november|december|jan|feb|mar|apr|jun|jul|aug|sep|oct|nov|dec)\\b",
            in: normalizedAsk
        ) != nil
    }

    private func pmConversationSpecificEntryMessageIDHint(
        from ask: String
    ) -> String? {
        pmConversationFirstRegexMatch(
            pattern: "(?i)\\bpm-message-[a-z0-9-]+\\b",
            in: ask
        )?.lowercased()
    }

    private func pmConversationSpecificEntryDateReference(
        from ask: String,
        relativeTo anchorDate: Date
    ) -> (date: Date, hasExplicitTime: Bool)? {
        let monthPattern = "(?i)\\b(january|february|march|april|may|june|july|august|september|sept|october|november|december|jan|feb|mar|apr|jun|jul|aug|sep|oct|nov|dec)"
        let combinedPattern = "\(monthPattern)\\s+(\\d{1,2})(?:,)?(?:\\s+(\\d{1,2}:\\d{2}(?::\\d{2})?(?:\\s*[AaPp][Mm])?))?"
        guard let expression = try? NSRegularExpression(pattern: combinedPattern) else {
            return nil
        }
        let nsRange = NSRange(ask.startIndex..<ask.endIndex, in: ask)
        guard let match = expression.firstMatch(in: ask, range: nsRange),
              let monthRange = Range(match.range(at: 1), in: ask),
              let dayRange = Range(match.range(at: 2), in: ask) else {
            return nil
        }

        let monthToken = String(ask[monthRange])
        let dayToken = String(ask[dayRange])
        let timeToken: String? = {
            guard match.range(at: 3).location != NSNotFound,
                  let range = Range(match.range(at: 3), in: ask) else {
                return nil
            }
            return String(ask[range])
        }()

        let formats: [String]
        if timeToken == nil {
            formats = ["MMMM d yyyy", "MMM d yyyy"]
        } else if timeToken?.lowercased().contains("am") == true || timeToken?.lowercased().contains("pm") == true {
            formats = ["MMMM d yyyy h:mm:ss a", "MMMM d yyyy h:mm a", "MMM d yyyy h:mm:ss a", "MMM d yyyy h:mm a"]
        } else {
            formats = ["MMMM d yyyy H:mm:ss", "MMMM d yyyy H:mm", "MMM d yyyy H:mm:ss", "MMM d yyyy H:mm"]
        }

        let year = Calendar.current.component(.year, from: anchorDate)
        let dateInput = timeToken.map { "\(monthToken) \(dayToken) \(year) \($0)" } ?? "\(monthToken) \(dayToken) \(year)"

        for format in formats {
            let formatter = DateFormatter()
            formatter.locale = Locale(identifier: "en_US_POSIX")
            formatter.timeZone = TimeZone.current
            formatter.calendar = Calendar(identifier: .gregorian)
            formatter.dateFormat = format
            guard let parsed = formatter.date(from: dateInput) else {
                continue
            }
            if parsed.timeIntervalSince(anchorDate) <= 24 * 60 * 60 {
                return (parsed, timeToken != nil)
            }
            if let priorYearDate = Calendar.current.date(byAdding: .year, value: -1, to: parsed) {
                return (priorYearDate, timeToken != nil)
            }
            return (parsed, timeToken != nil)
        }
        return nil
    }

    private func pmConversationSpecificEntryTimestampScore(
        messageDate: Date,
        referencedDate: Date,
        hasExplicitTime: Bool
    ) -> Int {
        let delta = abs(messageDate.timeIntervalSince(referencedDate))
        if hasExplicitTime {
            switch delta {
            case 0..<2:
                return 220
            case 0..<30:
                return 180
            case 0..<5 * 60:
                return 150
            case 0..<30 * 60:
                return 110
            case 0..<2 * 60 * 60:
                return 70
            default:
                break
            }
        } else if Calendar.current.isDate(messageDate, inSameDayAs: referencedDate) {
            return 120
        } else if delta < 24 * 60 * 60 {
            return 70
        }
        return 0
    }

    private func pmConversationLooksLikeSyntheticConversationRecap(_ body: String) -> Bool {
        let normalized = body.lowercased()
        let ownerCount = normalized.components(separatedBy: "owner:").count - 1
        let pmCount = normalized.components(separatedBy: "pm:").count - 1
        let roleMarkerCount = ownerCount + pmCount
        let recapFraming = normalized.hasPrefix("from our recent conversation")
            || normalized.hasPrefix("from our earlier conversation")
            || normalized.hasPrefix("from our recent communications")
            || normalized.hasPrefix("supporting detail:")
        if roleMarkerCount >= 2 {
            return true
        }
        if recapFraming && normalized.contains("latest proposed") {
            return true
        }
        return roleMarkerCount >= 1
            && (normalized.contains("from our recent conversation")
                || normalized.contains("from our earlier conversation")
                || normalized.contains("latest proposed")
                || normalized.contains("supporting detail"))
    }

    private func pmConversationExactEntryThread(
        around matchedMessage: PMCommunicationMessage,
        allMessages: [PMCommunicationMessage]
    ) -> [PMCommunicationMessage] {
        let messagesByID = Dictionary(uniqueKeysWithValues: allMessages.map { ($0.messageId, $0) })
        let sameSessionMessages = allMessages
            .filter { $0.sessionId == matchedMessage.sessionId && $0.senderRole != .system }
            .sorted { lhs, rhs in
                pmCommunicationMessage(lhs, occurredBefore: rhs)
            }

        var selectedIDs = Set([matchedMessage.messageId])
        if let replyToMessageId = matchedMessage.replyToMessageId,
           let repliedToMessage = messagesByID[replyToMessageId] {
            selectedIDs.insert(repliedToMessage.messageId)
        }

        if matchedMessage.senderRole == .owner {
            if let pmReply = sameSessionMessages.first(where: { candidate in
                candidate.senderRole == .pm
                    && candidate.replyToMessageId == matchedMessage.messageId
                    && pmCommunicationMessage(matchedMessage, occurredBefore: candidate)
            }) {
                selectedIDs.insert(pmReply.messageId)
            }
        } else if matchedMessage.senderRole == .pm {
            if matchedMessage.replyToMessageId == nil,
               let priorOwner = sameSessionMessages.last(where: { candidate in
                    candidate.senderRole == .owner
                        && pmCommunicationMessage(candidate, occurredBefore: matchedMessage)
                        && matchedMessage.sentAt.timeIntervalSince(candidate.sentAt) <= 30 * 60
               }) {
                selectedIDs.insert(priorOwner.messageId)
            }
        }

        return sameSessionMessages.filter { selectedIDs.contains($0.messageId) }
    }

    private func pmConversationSpecificEntryContext(
        ask: String,
        latestOwnerMessage: PMCommunicationMessage,
        allMessages: [PMCommunicationMessage]
    ) -> PMConversationSpecificEntryContext? {
        guard let reference = pmConversationSpecificEntryReference(
            from: ask,
            relativeTo: latestOwnerMessage.sentAt
        ) else {
            return nil
        }

        let askSignals = pmConversationRecoverySignals(from: ask)
        let asksForWorkingPortfolio = pmConversationAsksForWorkingPortfolioDefinition(ask.lowercased())
        let candidateMessages = allMessages
            .filter { message in
                message.senderRole != .system
                    && pmCommunicationMessage(message, occurredBefore: latestOwnerMessage)
            }

        let scoredCandidates = candidateMessages.compactMap { message -> (message: PMCommunicationMessage, score: Int, proximity: TimeInterval)? in
            let rawBody = pmConversationRawHistoryBody(for: message)
            guard rawBody.isEmpty == false else {
                return nil
            }

            var score = pmConversationRecoveryScore(
                textValues: pmConversationHistoryTextValues(for: message) + [rawBody],
                askSignals: askSignals
            )

            if asksForWorkingPortfolio {
                score += pmConversationWorkingPortfolioSignalScore(rawBody)
            }

            if let preferredSenderRole = reference.preferredSenderRole {
                score += message.senderRole == preferredSenderRole ? 40 : -10
            }

            if let referencedDate = reference.referencedAt {
                let timestampScore = pmConversationSpecificEntryTimestampScore(
                    messageDate: message.sentAt,
                    referencedDate: referencedDate,
                    hasExplicitTime: reference.hasExplicitTime
                )
                guard timestampScore > 0 || reference.hasExplicitTime == false else {
                    return nil
                }
                score += timestampScore
            }

            if let messageIDHint = reference.messageIDHint,
               message.messageId.lowercased() == messageIDHint {
                score += 240
            }

            if pmConversationUsesDeterministicVisibleReplyPath(message) {
                score -= 36
            }
            if pmConversationLooksLikeDeterministicHistoryRenderer(rawBody) {
                score -= 30
            }
            if pmConversationLooksLikeSyntheticConversationRecap(rawBody) {
                score -= 18
            }
            guard score > 0 else { return nil }

            let proximity = reference.referencedAt.map { abs(message.sentAt.timeIntervalSince($0)) } ?? .greatestFiniteMagnitude
            return (message, score, proximity)
        }

        guard let bestMatch = scoredCandidates.max(by: { lhs, rhs in
            if lhs.score == rhs.score {
                if lhs.proximity == rhs.proximity {
                    return lhs.message.sentAt < rhs.message.sentAt
                }
                return lhs.proximity > rhs.proximity
            }
            return lhs.score < rhs.score
        }) else {
            return nil
        }

        let threadMessages = pmConversationExactEntryThread(
            around: bestMatch.message,
            allMessages: allMessages
        )
        guard let latestThreadMessage = threadMessages.last else {
            return nil
        }

        let formatter = ISO8601DateFormatter()
        formatter.formatOptions = [.withInternetDateTime]
        let excerpt = threadMessages
            .compactMap { message -> String? in
                let body = pmConversationRawHistoryBody(for: message)
                guard body.isEmpty == false else { return nil }
                let role = message.senderRole == .owner ? "owner" : message.senderRole.rawValue
                let timestamp = formatter.string(from: message.sentAt)
                return "\(role) [\(timestamp)]: \(openAIResponsesTrimmed(body, limit: 4_000))"
            }
            .joined(separator: " || ")
        guard excerpt.isEmpty == false else {
            return nil
        }

        return PMConversationSpecificEntryContext(
            matchedMessageId: bestMatch.message.messageId,
            sessionId: bestMatch.message.sessionId,
            sortDate: latestThreadMessage.sentAt,
            summary: "Specific communication entry body window: \(excerpt)"
        )
    }

    private func pmConversationOwnerFacingRecoveredContextLines(
        _ summaries: [String],
        limit: Int
    ) -> [String] {
        Array(summaries.prefix(limit)).map(pmConversationOwnerFacingRecoveredContextLine)
    }

    private func pmConversationStandingCandidateSummary(
        _ contextPack: PMContextPack
    ) -> [String] {
        var lines: [String] = []

        for decision in contextPack.recentDecisions.prefix(4) {
            let candidateLongs = decision.standingReviewCandidateLongs ?? []
            let candidateShorts = decision.standingReviewCandidateShorts ?? []
            let candidateThemes = decision.standingReviewCandidateThemes ?? []
            guard candidateLongs.isEmpty == false || candidateShorts.isEmpty == false || candidateThemes.isEmpty == false else {
                continue
            }

            var segments: [String] = []
            if candidateLongs.isEmpty == false {
                segments.append("long ideas \(candidateLongs.prefix(3).joined(separator: " | "))")
            }
            if candidateShorts.isEmpty == false {
                segments.append("short or hedge ideas \(candidateShorts.prefix(3).joined(separator: " | "))")
            }
            if candidateThemes.isEmpty == false {
                segments.append("themes \(candidateThemes.prefix(2).joined(separator: " | "))")
            }
            lines.append(
                "Standing-review candidate ideas only, not confirmed holdings: \(segments.joined(separator: " • "))"
            )
        }

        return lines
    }

    private func pmConversationConversationFragmentSummary(
        session: PMCommunicationSession,
        contextPack: PMContextPack
    ) -> [String] {
        var lines: [String] = []

        if let crossChannelContinuity = contextPack.recentConversationContinuity.first(where: {
            $0.sessionId != session.sessionId && $0.channel != session.channel
        }) {
            lines.append(
                "Recent same-owner continuity carried from \(crossChannelContinuity.channel == .inApp ? "the app conversation" : "Telegram"): \(crossChannelContinuity.continuitySummary)"
            )
        }

        if lines.isEmpty,
           let crossSessionContinuity = contextPack.recentConversationContinuity.first(where: {
               $0.sessionId != session.sessionId
           }) {
            lines.append(
                "Recent same-owner continuity from another session: \(crossSessionContinuity.continuitySummary)"
            )
        }

        return lines
    }

    private func pmConversationDetailedCommunicationHistorySummary(
        ask: String,
        latestOwnerMessage: PMCommunicationMessage,
        session: PMCommunicationSession,
        allMessages: [PMCommunicationMessage],
        sessionMessages: [PMCommunicationMessage]
    ) -> [String] {
        let normalizedAsk = ask.lowercased()
        let explicitLogReview = pmConversationExplicitlyRequestsCommunicationLogReview(normalizedAsk)
        let asksForDetailedHistory = pmConversationNeedsDetailedCommunicationHistory(normalizedAsk)
        guard explicitLogReview || asksForDetailedHistory else {
            return []
        }

        if let specificEntryContext = pmConversationSpecificEntryContext(
            ask: ask,
            latestOwnerMessage: latestOwnerMessage,
            allMessages: allMessages
        ) {
            return [specificEntryContext.summary]
        }

        let askSignals = pmConversationRecoverySignals(from: ask)
        let asksForWorkingPortfolio = pmConversationAsksForWorkingPortfolioDefinition(normalizedAsk)
        let lowVolumeRecentWeekMessages = allMessages.filter { message in
            message.senderRole != .system
                && pmCommunicationMessage(message, occurredBefore: latestOwnerMessage)
                && latestOwnerMessage.sentAt.timeIntervalSince(message.sentAt) <= (7 * 24 * 60 * 60)
        }
        let lowVolumeRecentWeek = lowVolumeRecentWeekMessages.count <= 160
        var recovered: [(score: Int, sortDate: Date, summary: String)] = []
        var sessionIDsAlreadyRepresented = Set<String>()

        if asksForWorkingPortfolio,
           let cluster = pmConversationRecentWorkingPortfolioCluster(
                before: latestOwnerMessage,
                allMessages: allMessages
           ),
           let latestClusterMessage = cluster.last {
            let summary = pmConversationCommunicationLogExcerptSummary(
                cluster,
                prefix: lowVolumeRecentWeek
                    ? "Week-scale communication-log body window: "
                    : "Detailed communication-log body window: "
            )
            if summary.isEmpty == false {
                recovered.append((
                    score: 30 + cluster.count,
                    sortDate: latestClusterMessage.sentAt,
                    summary: summary
                ))
                sessionIDsAlreadyRepresented.insert(latestClusterMessage.sessionId)
            }
        }

        let eligibleMessages = allMessages
            .filter { message in
                message.senderRole != .system
                    && pmCommunicationMessage(message, occurredBefore: latestOwnerMessage)
            }
        let messagesBySession = Dictionary(grouping: eligibleMessages, by: \.sessionId)

        for (_, candidateMessages) in messagesBySession {
            let sortedMessages = candidateMessages.sorted { lhs, rhs in
                if lhs.sentAt == rhs.sentAt {
                    return lhs.messageId < rhs.messageId
                }
                return lhs.sentAt < rhs.sentAt
            }
            guard sortedMessages.isEmpty == false else { continue }

            let scoredAnchors = sortedMessages.enumerated().compactMap { indexed -> (index: Int, score: Int)? in
                let message = indexed.element
                let score = pmConversationHistoryAnchorScore(
                    for: message,
                    askSignals: askSignals,
                    asksForWorkingPortfolio: asksForWorkingPortfolio,
                    currentSessionId: session.sessionId
                )
                return score > 0 ? (index: indexed.offset, score: score) : nil
            }

            let anchorIndex: Int
            let anchorScore: Int
            if let bestAnchor = scoredAnchors.max(by: { lhs, rhs in
                if lhs.score == rhs.score {
                    return lhs.index < rhs.index
                }
                return lhs.score < rhs.score
            }) {
                anchorIndex = bestAnchor.index
                anchorScore = bestAnchor.score
            } else if explicitLogReview {
                anchorIndex = max(sortedMessages.count - 2, 0)
                anchorScore = 1
            } else {
                continue
            }

            let fullRecentSessionWindow = lowVolumeRecentWeek
                && latestOwnerMessage.sentAt.timeIntervalSince(sortedMessages.last?.sentAt ?? .distantPast) <= (7 * 24 * 60 * 60)
                && sortedMessages.count <= 14
                && sortedMessages.contains(where: { pmConversationLooksLikeDeterministicHistoryRenderer($0.body) }) == false
            let lowerBound = max(anchorIndex - (lowVolumeRecentWeek ? 4 : 2), 0)
            let upperBound = min(anchorIndex + (lowVolumeRecentWeek ? 5 : 3), sortedMessages.count - 1)
            let excerptMessages = fullRecentSessionWindow
                ? sortedMessages
                : Array(sortedMessages[lowerBound...upperBound])
            guard let latestExcerptMessage = excerptMessages.last else { continue }
            if sessionIDsAlreadyRepresented.contains(latestExcerptMessage.sessionId) {
                continue
            }

            let summary = pmConversationCommunicationLogExcerptSummary(
                excerptMessages,
                prefix: fullRecentSessionWindow
                    ? "Week-scale communication-log body window: "
                    : "Detailed communication-log body window: "
            )
            guard summary.isEmpty == false else { continue }

            recovered.append((
                score: 10 + anchorScore + excerptMessages.count,
                sortDate: latestExcerptMessage.sentAt,
                summary: summary
            ))
            sessionIDsAlreadyRepresented.insert(latestExcerptMessage.sessionId)
        }

        var seenSummaries = Set<String>()
        return recovered
            .sorted { lhs, rhs in
                if lhs.score == rhs.score {
                    if lhs.sortDate == rhs.sortDate {
                        return lhs.summary < rhs.summary
                    }
                    return lhs.sortDate > rhs.sortDate
                }
                return lhs.score > rhs.score
            }
            .compactMap { entry in
                seenSummaries.insert(entry.summary).inserted ? entry.summary : nil
            }
            .prefix(lowVolumeRecentWeek ? 6 : 4)
            .map { $0 }
    }

    private func pmConversationActiveMemoryIsSufficientForHistoryAsk(
        ask: String,
        latestOwnerMessage: PMCommunicationMessage,
        session: PMCommunicationSession,
        sessionMessages: [PMCommunicationMessage]
    ) -> Bool {
        let normalizedAsk = ask.lowercased()
        if pmConversationAsksForWorkingPortfolioDefinition(normalizedAsk) {
            return pmConversationRecentWorkingPortfolioCluster(
                before: latestOwnerMessage,
                allMessages: sessionMessages
            ) != nil
        }

        let askSignals = pmConversationRecoverySignals(from: ask)
        let priorMessages = sessionMessages.filter { message in
            message.senderRole != .system
                && pmCommunicationMessage(message, occurredBefore: latestOwnerMessage)
        }
        let matchedCount = priorMessages.reduce(into: 0) { count, message in
            if pmConversationRecoveryScore(textValues: [message.body], askSignals: askSignals) > 0 {
                count += 1
            }
        }
        if matchedCount >= 2 {
            return true
        }

        return pmConversationSameDayThreadRecoverySummary(
            askSignals: askSignals,
            asksForRecoveredContext: true,
            session: session,
            sessionMessages: sessionMessages
        ) != nil
    }

    private func pmConversationLooksLikeDirective(_ body: String) -> Bool {
        let normalized = body.lowercased()
        let markers = [
            "replace", "instead", "update", "change", "switch", "swap", "add ", "remove", "drop",
            "hold", "keep", "avoid", "wait", "do not", "don't", "maintain", "reduce", "increase",
            "rebuild", "treat", "use", "stop", "resume"
        ]
        return markers.contains { normalized.contains($0) }
    }

    private func pmConversationOrderedSymbolCandidates(in value: String) -> [String] {
        orderedUniqueStrings(
            value
                .components(separatedBy: CharacterSet.alphanumerics.inverted)
                .map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
                .filter { token in
                    let upper = token.uppercased()
                    return upper == token && token.count >= 2 && token.count <= 5 && token.allSatisfy(\.isLetter)
                }
                .map { $0.uppercased() }
        )
    }

    private func pmConversationDirectiveSymbolCandidates(in value: String) -> Set<String> {
        Set(pmConversationOrderedSymbolCandidates(in: value))
    }

    private func boundedConversationText(_ text: String, limit: Int) -> String {
        openAIResponsesTrimmed(text, limit: limit)
    }

    private func pmConversationRecoveredContextSummary(
        ask: String,
        session: PMCommunicationSession,
        sessionMessages: [PMCommunicationMessage],
        contextPack: PMContextPack,
        standingReports: [AnalystStandingReport],
        pmDecisions: [PMDecisionRecord]
    ) -> [String] {
        let normalizedAsk = ask.lowercased()
        let askSignals = pmConversationRecoverySignals(from: ask)
        let sessionMessageIDs = Set(sessionMessages.map(\.messageId))
        let asksForRecoveredContext = pmConversationNeedsRecoveredContext(normalizedAsk)
        let asksForStandingReviewRecovery = pmConversationNeedsStandingReviewRecovery(normalizedAsk)
        let asksForNotebookContext = normalizedAsk.contains("notebook")
            || normalizedAsk.contains("note")
            || normalizedAsk.contains("promoted")
        let notebookOnlyAsk = asksForNotebookContext
            && pmConversationNeedsDetailedCommunicationHistory(normalizedAsk) == false
        var recovered: [(score: Int, sortDate: Date, summary: String)] = []

        recovered.append(
            contentsOf: pmStandingReviewRecoveredContextEntries(
                askSignals: askSignals,
                asksForStandingReviewRecovery: asksForStandingReviewRecovery,
                contextPack: contextPack,
                standingReports: standingReports,
                pmDecisions: pmDecisions
            )
        )

        let sameDayRecovery = asksForStandingReviewRecovery == false && notebookOnlyAsk == false
            ? pmConversationSameDayThreadRecoverySummary(
                askSignals: askSignals,
                asksForRecoveredContext: asksForRecoveredContext,
                session: session,
                sessionMessages: sessionMessages
            )
            : nil

        if let sameDayRecovery {
            recovered.append(sameDayRecovery)
        }

        if asksForStandingReviewRecovery {
            return recovered
                .sorted { lhs, rhs in
                    if lhs.score == rhs.score {
                        if lhs.sortDate == rhs.sortDate {
                            return lhs.summary < rhs.summary
                        }
                        return lhs.sortDate > rhs.sortDate
                    }
                    return lhs.score > rhs.score
                }
                .prefix(6)
                .map(\.summary)
        }

        for continuity in contextPack.recentConversationContinuity {
            if sameDayRecovery != nil && continuity.sessionId == session.sessionId {
                continue
            }
            let score = pmConversationRecoveryScore(
                textValues: [continuity.continuitySummary] + continuity.topicSignals,
                askSignals: askSignals
            ) + (continuity.sessionId == session.sessionId ? 4 : 0) - (notebookOnlyAsk ? 6 : 0) - (asksForNotebookContext ? 4 : 0)
            if score > 0 || (asksForRecoveredContext && asksForStandingReviewRecovery == false) {
                recovered.append((
                    score: max(score, asksForRecoveredContext && asksForStandingReviewRecovery == false ? 1 : 0),
                    sortDate: continuity.latestMessageAt,
                    summary: "Conversation continuity: \(continuity.continuitySummary)"
                ))
            }
        }

        for note in contextPack.recentNotebookEntries {
            let score = pmConversationRecoveryScore(
                textValues: [note.title, note.sourceSummary ?? note.body],
                askSignals: askSignals
            ) + (asksForNotebookContext ? 8 : 0)
            if score > 0 || (asksForRecoveredContext && asksForStandingReviewRecovery == false) {
                let noteBody = note.body.trimmingCharacters(in: .whitespacesAndNewlines)
                let noteSource = note.sourceSummary?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
                let excerptSource = noteBody.isEmpty ? noteSource : noteBody
                recovered.append((
                    score: max(score, asksForRecoveredContext && asksForStandingReviewRecovery == false ? 1 : 0),
                    sortDate: note.updatedAt,
                    summary: "PM notebook: \(note.title) — \(openAIResponsesTrimmed(excerptSource, limit: 360))"
                ))
            }
        }

        for memory in contextPack.retrievedInteractionMemories {
            let score = pmConversationRecoveryScore(
                textValues: [memory.title, memory.summary] + memory.matchedSignals,
                askSignals: askSignals
            ) + (memory.sourceCommunicationMessageId.map(sessionMessageIDs.contains(_:)) == true ? 3 : 0)
            if score > 0 || (asksForRecoveredContext && asksForStandingReviewRecovery == false) {
                recovered.append((
                    score: max(score, asksForRecoveredContext && asksForStandingReviewRecovery == false ? 1 : 0),
                    sortDate: memory.updatedAt,
                    summary: "Retrieved memory: \(memory.title) — \(openAIResponsesTrimmed(memory.summary, limit: 300))"
                ))
            }
        }

        for outcome in contextPack.promotedCommunicationOutcomes {
            let score = pmConversationRecoveryScore(
                textValues: [outcome.targetTitle, outcome.targetSummary, outcome.targetExcerpt, outcome.originSummary],
                askSignals: askSignals
            ) + (asksForNotebookContext ? 8 : 0)
            if score > 0 || (asksForRecoveredContext && asksForStandingReviewRecovery == false) {
                recovered.append((
                    score: max(score, asksForRecoveredContext && asksForStandingReviewRecovery == false ? 1 : 0),
                    sortDate: outcome.promotedAt,
                    summary: "Promoted communication outcome: \(outcome.targetTitle) — \(openAIResponsesTrimmed(outcome.targetExcerpt, limit: 320))"
                ))
            }
        }

        return recovered
            .sorted { lhs, rhs in
                if lhs.score == rhs.score {
                    if lhs.sortDate == rhs.sortDate {
                        return lhs.summary < rhs.summary
                    }
                    return lhs.sortDate > rhs.sortDate
                }
                return lhs.score > rhs.score
            }
            .prefix(6)
            .map(\.summary)
    }

    private func pmConversationNeedsRecoveredContext(_ normalizedAsk: String) -> Bool {
        pmConversationNeedsDetailedCommunicationHistory(normalizedAsk)
            || normalizedAsk.contains("notebook")
            || normalizedAsk.contains("look back")
            || normalizedAsk.contains("reconstruct")
