    private func pmConversationSameDayThreadRecoverySummary(
        askSignals: Set<String>,
        asksForRecoveredContext: Bool,
        session: PMCommunicationSession,
        sessionMessages: [PMCommunicationMessage]
    ) -> (score: Int, sortDate: Date, summary: String)? {
        guard let latestOwnerMessage = sessionMessages.last(where: { $0.senderRole == .owner }) else {
            return nil
        }

        let sameDayMessages = sessionMessages
            .filter { message in
                message.messageId != latestOwnerMessage.messageId
                    && pmCommunicationMessage(message, occurredBefore: latestOwnerMessage)
                    && Calendar.current.isDate(message.sentAt, inSameDayAs: latestOwnerMessage.sentAt)
            }
            .sorted { lhs, rhs in
                pmCommunicationMessage(lhs, occurredBefore: rhs)
            }
        guard sameDayMessages.isEmpty == false else { return nil }

        let scoredMessages = sameDayMessages.map { message in
            (
                message: message,
                score: pmConversationRecoveryScore(
                    textValues: [message.body],
                    askSignals: askSignals
                )
            )
        }

        var selectedMessages: [PMCommunicationMessage]
        let totalScore: Int
        if scoredMessages.contains(where: { $0.score > 0 }) {
            let matched = scoredMessages.filter { $0.score > 0 }
            let matchedIndices = scoredMessages.enumerated().compactMap { indexed in
                indexed.element.score > 0 ? indexed.offset : nil
            }
            let maxMessages = asksForRecoveredContext ? 12 : 8
            let latestMatchedIndex = matchedIndices.last ?? (sameDayMessages.count - 1)
            var startIndex = matchedIndices.first ?? latestMatchedIndex
            var endIndex = latestMatchedIndex
            if endIndex - startIndex + 1 > maxMessages {
                startIndex = max(0, endIndex - (maxMessages - 1))
            }
            while endIndex - startIndex + 1 < maxMessages && startIndex > 0 {
                startIndex -= 1
            }
            while endIndex - startIndex + 1 < maxMessages && endIndex < sameDayMessages.count - 1 {
                endIndex += 1
            }
            selectedMessages = Array(sameDayMessages[startIndex...endIndex])
            if selectedMessages.count < maxMessages,
               let first = selectedMessages.first,
               let firstIndex = sameDayMessages.firstIndex(where: { $0.messageId == first.messageId }) {
                var prependIndex = firstIndex - 1
                var mutableSelected = selectedMessages
                while mutableSelected.count < maxMessages && prependIndex >= 0 {
                    mutableSelected.insert(sameDayMessages[prependIndex], at: 0)
                    prependIndex -= 1
                }
                selectedMessages = mutableSelected
            }
            totalScore = matched.reduce(0) { $0 + $1.score }
        } else if asksForRecoveredContext {
            selectedMessages = Array(sameDayMessages.suffix(12))
            totalScore = 1
        } else {
            return nil
        }

        let participant = session.participantDisplayName ?? session.participantId ?? "participant"
        let excerpt = selectedMessages
            .map { message in
                let role = message.senderRole == .owner ? "owner" : message.senderRole.rawValue
                return "\(role): \(openAIResponsesTrimmed(message.body, limit: 220))"
            }
            .joined(separator: " || ")
        guard let latestRecoveredMessage = selectedMessages.last else {
            return nil
        }

        return (
            score: 6 + min(totalScore, 8) + selectedMessages.count,
            sortDate: latestRecoveredMessage.sentAt,
            summary: "Same-day communication thread (\(session.channel.rawValue) with \(participant)): \(excerpt)"
        )
    }

    private func pmStandingReviewRecoveredContextEntries(
        askSignals: Set<String>,
        asksForStandingReviewRecovery: Bool,
        contextPack: PMContextPack,
        standingReports: [AnalystStandingReport],
        pmDecisions: [PMDecisionRecord]
    ) -> [(score: Int, sortDate: Date, summary: String)] {
        let reportsByID = Dictionary(uniqueKeysWithValues: standingReports.map { ($0.reportId, $0) })
        var seenDecisionIDs = Set<String>()
        let candidateDecisions = (contextPack.recentDecisions + pmDecisions)
            .filter { decision in
                guard isExercisePMDecision(decision) == false,
                      let standingReportIds = decision.standingReportIds,
                      standingReportIds.isEmpty == false else {
                    return false
                }
                return seenDecisionIDs.insert(decision.decisionId).inserted
            }

        var recoveredEntries: [(score: Int, sortDate: Date, summary: String)] = []
        for decision in candidateDecisions {
            guard let standingReportIds = decision.standingReportIds,
                  standingReportIds.isEmpty == false else {
                continue
            }

            let linkedReports = standingReportIds.compactMap { reportsByID[$0] }
            let linkedReport = decision.primaryStandingReportId.flatMap { reportsByID[$0] } ?? linkedReports.first
            let attentionItems = orderedUniqueStrings(
                decision.standingReviewAttentionItems
                    ?? standingReviewAttentionSummaries(in: linkedReports, limit: 4)
            )
            let candidateLongs = orderedUniqueStrings(
                decision.standingReviewCandidateLongs
                    ?? standingReviewSectionSummaries(in: linkedReports, kinds: [.longIdeas], limit: 4)
            )
            let candidateShorts = orderedUniqueStrings(
                decision.standingReviewCandidateShorts
                    ?? standingReviewSectionSummaries(in: linkedReports, kinds: [.shortIdeas, .etfIdeas], limit: 4)
            )
            let candidateThemes = orderedUniqueStrings(
                decision.standingReviewCandidateThemes
                    ?? standingReviewSectionSummaries(in: linkedReports, kinds: [.macroViews, .portfolioRelevance], limit: 4)
            )
            let followUpItems = orderedUniqueStrings(
                decision.standingReviewFollowUpItems
                    ?? standingReviewFollowUpSummaries(in: linkedReports, limit: 4)
            )
            let analystTitles = orderedUniqueStrings(
                decision.standingReviewAnalystTitles
                    ?? linkedReports.map { $0.title.replacingOccurrences(of: " Standing Report", with: "") }
            )
            var textValues: [String] = [
                decision.title,
                decision.summary,
                decision.recommendedAction ?? "",
                linkedReport?.title ?? "",
                linkedReport?.headlineView ?? "",
                linkedReport?.summary ?? ""
            ]
            textValues.append(contentsOf: attentionItems)
            textValues.append(contentsOf: candidateLongs)
            textValues.append(contentsOf: candidateShorts)
            textValues.append(contentsOf: candidateThemes)
            textValues.append(contentsOf: followUpItems)
            textValues.append(contentsOf: analystTitles)
            let score = pmConversationRecoveryScore(
                textValues: textValues,
                askSignals: askSignals
            )
            guard score > 0 || asksForStandingReviewRecovery else {
                continue
            }

            let dispositionLabel =
                decision.standingReviewDisposition
                    .flatMap { pmStandingReviewDisposition(from: $0)?.displayTitle }
                ?? decision.standingReviewDisposition
                ?? "Standing review completed"

            var segments: [String] = ["disposition: \(dispositionLabel)"]
            if analystTitles.isEmpty == false {
                segments.append("analysts: \(analystTitles.prefix(3).joined(separator: ", "))")
            }
            if candidateLongs.isEmpty == false {
                segments.append("long ideas: \(candidateLongs.prefix(3).joined(separator: " | "))")
            }
            if candidateShorts.isEmpty == false {
                segments.append("short or hedge ideas: \(candidateShorts.prefix(3).joined(separator: " | "))")
            }
            if candidateThemes.isEmpty == false {
                segments.append("themes: \(candidateThemes.prefix(2).joined(separator: " | "))")
            }
            if attentionItems.isEmpty == false {
                segments.append("high-priority conclusions: \(attentionItems.prefix(2).joined(separator: " | "))")
            }
            if followUpItems.isEmpty == false {
                segments.append("follow-up: \(followUpItems.prefix(2).joined(separator: " | "))")
            }
            if let recommendedAction = decision.recommendedAction,
               recommendedAction.isEmpty == false {
                segments.append("PM treatment: \(recommendedAction)")
            }
            if let linkedReport {
                let linkedView = linkedReport.headlineView.trimmingCharacters(in: .whitespacesAndNewlines)
                segments.append(
                    "linked report: \(linkedReport.title) — \(openAIResponsesTrimmed(linkedView.isEmpty ? linkedReport.summary : linkedView, limit: 220))"
                )
            }

            recoveredEntries.append((
                score: max(score, asksForStandingReviewRecovery ? 7 : score),
                sortDate: decision.updatedAt,
                summary: "Standing-review memory: \(decision.title) — \(segments.joined(separator: " • "))"
            ))
        }
        return recoveredEntries
    }

    private func pmConversationRecoverySignals(from ask: String) -> Set<String> {
        let normalized = ask
            .lowercased()
            .replacingOccurrences(of: "[^a-z0-9]+", with: " ", options: .regularExpression)
        return Set(
            normalized
                .components(separatedBy: .whitespacesAndNewlines)
                .filter { $0.count >= 3 }
        )
    }

    private func pmConversationRecoveryScore(
        textValues: [String],
        askSignals: Set<String>
    ) -> Int {
        guard askSignals.isEmpty == false else {
            return 0
        }
        let candidateSignals = Set(
            textValues
                .joined(separator: " ")
                .lowercased()
                .replacingOccurrences(of: "[^a-z0-9]+", with: " ", options: .regularExpression)
                .components(separatedBy: .whitespacesAndNewlines)
                .filter { $0.count >= 3 }
        )
        return askSignals.intersection(candidateSignals).count
    }

    private func emptyToNil(_ value: String?) -> String? {
        guard let trimmed = value?.trimmingCharacters(in: .whitespacesAndNewlines),
              trimmed.isEmpty == false else {
            return nil
        }
        return trimmed
    }

    private func pmFallbackRuntimeProvenance(
        runtimeSelection: ResolvedRuntimeSelection,
        status: String,
        issueSummary: String?,
        launchedAt: Date,
        conversationTrace: PMConversationTrace? = nil
    ) -> PMRuntimeProvenance {
        PMRuntimeProvenance(
            configuredProviderKind: runtimeSelection.configuredProviderKind,
            configuredCredentialProfileId: runtimeSelection.configuredCredentialProfileId,
            configuredRuntimeIdentifier: runtimeSelection.configuredRuntimeIdentifier,
            configuredReasoningMode: runtimeSelection.configuredReasoningMode,
            actualProviderKind: runtimeSelection.effectiveProviderKind,
            actualCredentialProfileId: runtimeSelection.effectiveCredentialProfileId,
            actualRuntimeIdentifier: "deterministic_local_fallback[\(runtimeSelection.effectiveRuntimeIdentifier)]",
            actualReasoningMode: runtimeSelection.effectiveReasoningMode,
            usedOpenAI: false,
            synthesisStatus: status,
            synthesisIssueSummary: issueSummary,
            launchedAt: launchedAt,
            conversationTrace: conversationTrace
        )
    }

    private func pmConversationFallbackTrigger(
        degradedReason: String,
        issueSummary: String?
    ) -> PMConversationFallbackTriggerKind {
        let summary = (issueSummary ?? degradedReason).lowercased()
        if summary.contains("openai_api_key_missing")
            || summary.contains("anthropic_api_key_missing") {
            return .credentialUnavailable
        }
        if summary.contains("openai_api_key_empty")
            || summary.contains("anthropic_api_key_empty")
            || summary.contains("anthropic_credential_profile_disabled")
            || summary.contains("anthropic_credential_auth_unsupported")
            || degradedReason == "fallback_openai_key_unavailable"
            || degradedReason == "fallback_anthropic_key_unavailable" {
            return .credentialEmpty
        }
        if summary.contains("invalid_schema") || summary.contains("invalid_json_schema") {
            return .invalidSchema
        }
        if summary.contains("auth_failure") {
            return .authFailure
        }
        if summary.contains("network_error") {
            return .networkFailure
        }
        if summary.contains("provider_failure_status=408") {
            return .timeout
        }
        if summary.contains("provider_failure_status=429")
            || summary.contains("rate_limit_or_quota_status=429") {
            return .rateLimitOrQuota
        }
        if summary.contains("invalid_runtime")
            || summary.contains("http_status=404")
            || summary.contains("http_status=422") {
            return .invalidRuntime
        }
        if summary.contains("request_too_large_status=")
            || summary.contains("http_status=413") {
            return .requestTooLarge
        }
        if summary.contains("provider_failure_status=") {
            return .providerUnavailable
        }
        if summary.contains("openai_refusal")
            || summary.contains("anthropic_refusal") {
            return .refusal
        }
        if summary.contains("malformed_response")
            || summary.contains("invalid_response") {
            return .malformedResponse
        }
        return .internalFailure
    }

    private func pmConversationFallbackFailureSummary(
        for trigger: PMConversationFallbackTriggerKind,
        providerKind: LLMProviderKind
    ) -> String {
        switch trigger {
        case .credentialUnavailable:
            return "\(providerKind.displayName) credentials are unavailable for the PM runtime"
        case .credentialEmpty:
            return "the configured \(providerKind.displayName) credential is empty or unusable"
        case .invalidSchema:
            return "the PM structured-output schema is invalid for the configured runtime"
        case .authFailure:
            return "the PM runtime could not authenticate with the model provider"
        case .networkFailure:
            return "the PM runtime could not reach the model provider"
        case .timeout:
            return "the PM runtime timed out before producing a usable answer"
        case .rateLimitOrQuota:
            return "the PM runtime was rate-limited or quota-blocked"
        case .invalidRuntime:
            return "the configured PM runtime is unavailable"
        case .requestTooLarge:
            return "the PM runtime could not complete because the request was too large"
        case .providerUnavailable:
            return "the PM runtime failed because the model provider was unavailable"
        case .refusal:
            return "the PM runtime returned no usable answer"
        case .malformedResponse:
            return "the PM runtime returned an unusable response"
        case .internalFailure:
            return "the PM runtime failed before it produced a usable answer"
        }
    }

    private func pmConversationFallbackNextStep(
        for trigger: PMConversationFallbackTriggerKind,
        providerKind: LLMProviderKind
    ) -> String {
        switch trigger {
        case .credentialUnavailable, .credentialEmpty, .invalidSchema, .authFailure, .invalidRuntime:
            return "Check the PM runtime configuration or \(providerKind.displayName) access, then retry."
        case .networkFailure, .timeout, .rateLimitOrQuota, .providerUnavailable:
            return "Retry in a moment once the PM runtime is available again."
        case .requestTooLarge, .refusal, .malformedResponse, .internalFailure:
            return "Retry the request, or restate it more narrowly, and I’ll try again."
        }
    }

    private func makeFallbackPMConversationReply(
        runtimeSelection: ResolvedRuntimeSelection,
        degradedReason: String,
        issueSummary: String?,
        modelSynthesisAttempted: Bool,
        modelAttemptCount: Int,
        requestCharacterCount: Int?,
        requestCompactionLevel: String?,
        promptBudgetTrace: PMConversationPromptBudgetTrace? = nil,
        promptProfileTraces: [PMConversationPromptProfileTrace] = [],
        providerReturnedContent: Bool,
        providerResponseAccepted: Bool,
        providerResponseIssueSummary: String?
    ) -> PMConversationFallbackReplyResult {
        let trigger = pmConversationFallbackTrigger(
            degradedReason: degradedReason,
            issueSummary: issueSummary
        )
        let trace = PMConversationTrace(
            pathKind: .degradedFallback,
            visibleReplySource: .deterministicFallback,
            structuredOutputSchemaName: modelSynthesisAttempted ? "pm_conversation_reply" : nil,
            structuredOutputSchemaLocallyValidated: {
                guard modelSynthesisAttempted else { return nil }
                return trigger == .invalidSchema ? false : true
            }(),
            modelSynthesisAttempted: modelSynthesisAttempted,
            modelProducedUsableReply: false,
            visibleReplyModifiedAfterSynthesis: false,
            modelAttemptCount: modelAttemptCount,
            requestCharacterCount: requestCharacterCount,
            requestCompactionLevel: requestCompactionLevel,
            promptBudgetTrace: promptBudgetTrace,
            promptProfileTraces: promptProfileTraces,
            providerReturnedContent: providerReturnedContent,
            providerResponseAccepted: providerResponseAccepted,
            providerResponseIssueSummary: providerResponseIssueSummary,
            fallbackTrigger: trigger,
            fallbackTriggerWasAllowedRuntimeFailure: true,
            degradedReason: issueSummary ?? degradedReason
        )
        let body = [
            "I couldn't complete a PM answer because the PM runtime failed: \(pmConversationFallbackFailureSummary(for: trigger, providerKind: runtimeSelection.effectiveProviderKind)).",
            pmConversationFallbackNextStep(for: trigger, providerKind: runtimeSelection.effectiveProviderKind)
        ].joined(separator: "\n\n")
        return PMConversationFallbackReplyResult(body: body, trace: trace)
    }

    private func latestPMConversationMessage(
        before ownerMessage: PMCommunicationMessage,
        sessionMessages: [PMCommunicationMessage]
    ) -> PMCommunicationMessage? {
        sessionMessages
            .filter { candidate in
                candidate.senderRole == .pm
                    && pmCommunicationMessage(candidate, occurredBefore: ownerMessage)
            }
            .sorted { lhs, rhs in
                pmCommunicationMessage(lhs, occurredBefore: rhs)
            }
            .last
    }

    private func pmConversationAsksForWorkingPortfolioDefinition(_ normalizedAsk: String) -> Bool {
        let asksForOverview = normalizedAsk.contains("list")
            || normalizedAsk.contains("what is")
            || normalizedAsk.contains("what's")
            || normalizedAsk.contains("show")
            || normalizedAsk.contains("restate")
            || normalizedAsk.contains("summarize")
            || normalizedAsk.contains("recap")
            || normalizedAsk.contains("refresh me")
            || normalizedAsk.contains("latest")
            || normalizedAsk.contains("current")
        let asksForInitialPaperPortfolio = normalizedAsk.contains("initial paper portfolio")
            || ((normalizedAsk.contains("working paper portfolio")
                    || normalizedAsk.contains("paper portfolio definition")
                    || normalizedAsk.contains("paper portfolio structure"))
                && asksForOverview)
        let asksForWorkingPortfolio = normalizedAsk.contains("working portfolio")
            || (normalizedAsk.contains("working") && normalizedAsk.contains("portfolio"))
        let asksForStructure = normalizedAsk.contains("portfolio structure")
            || normalizedAsk.contains("latest structure")
            || normalizedAsk.contains("current structure")
            || normalizedAsk.contains("list the latest")
            || normalizedAsk.contains("list latest")
            || normalizedAsk.contains("latest portfolio")
            || normalizedAsk.contains("most recent list")
        let asksForLongShortPositions = normalizedAsk.contains("long and short positions")
            || normalizedAsk.contains("long/short positions")
            || normalizedAsk.contains("long and short names")
            || normalizedAsk.contains("long and short structure")
            || normalizedAsk.contains("long/short structure")
            || normalizedAsk.contains("long positions")
            || normalizedAsk.contains("short positions")
            || normalizedAsk.contains("long sleeve")
            || normalizedAsk.contains("short sleeve")
            || normalizedAsk.contains("short side")
            || normalizedAsk.contains("long side")
        let historicalRecall = normalizedAsk.contains("earlier")
            || normalizedAsk.contains("recent")
            || normalizedAsk.contains("last week")
            || normalizedAsk.contains("this week")
            || normalizedAsk.contains("recall")
            || normalizedAsk.contains("remember")
            || normalizedAsk.contains("what did we")
            || normalizedAsk.contains("what was the latest")

        return asksForInitialPaperPortfolio
            || (asksForWorkingPortfolio && asksForStructure)
            || (normalizedAsk.contains("paper portfolio") && (asksForStructure || asksForLongShortPositions))
            || (asksForLongShortPositions && historicalRecall)
    }

    private func normalizedPMConversationCueText(_ raw: String) -> String {
        raw
            .lowercased()
            .replacingOccurrences(of: "-", with: " ")
            .replacingOccurrences(of: "‑", with: " ")
            .replacingOccurrences(of: "–", with: " ")
            .replacingOccurrences(of: "—", with: " ")
    }

    private func latestPMConversationOpenLoop(
        before ownerMessage: PMCommunicationMessage,
        sessionMessages: [PMCommunicationMessage]
    ) -> PMConversationOpenLoop? {
        guard let latestPMMessage = latestPMConversationMessage(
            before: ownerMessage,
            sessionMessages: sessionMessages
        ) else {
            return nil
        }

        let normalized = latestPMMessage.body
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .lowercased()
        guard normalized.isEmpty == false else {
            return nil
        }

        if let pendingAsk = latestPMMessage.conversationResolution?.pendingAsk {
            let kind: PMConversationOpenLoopKind = switch pendingAsk.kind {
            case .yesNoConfirmation:
                .yesNoConfirmation
            case .clarification:
                .clarification
            }
            return PMConversationOpenLoop(
                sourceMessageId: latestPMMessage.messageId,
                kind: kind,
                promptSummary: pendingAsk.promptSummary,
                fullText: latestPMMessage.body,
                pendingAskState: pendingAsk
            )
        }

        if pmConversationMessageRequestsYesNoConfirmation(normalized) {
            return PMConversationOpenLoop(
                sourceMessageId: latestPMMessage.messageId,
                kind: .yesNoConfirmation,
                promptSummary: boundedConversationText(latestPMMessage.body, limit: 220),
                fullText: latestPMMessage.body,
                pendingAskState: nil
            )
        }

        if pmConversationMessageRequestsClarification(normalized) {
            return PMConversationOpenLoop(
                sourceMessageId: latestPMMessage.messageId,
                kind: .clarification,
                promptSummary: boundedConversationText(latestPMMessage.body, limit: 220),
                fullText: latestPMMessage.body,
                pendingAskState: nil
            )
        }

        return nil
    }

    private func pmConversationMessageRequestsYesNoConfirmation(_ normalizedMessage: String) -> Bool {
        if normalizedMessage.contains("yes / no")
            || normalizedMessage.contains("yes/no")
            || normalizedMessage.contains("if \"yes\"")
            || normalizedMessage.contains("if yes")
            || normalizedMessage.contains("please answer yes or no")
            || normalizedMessage.contains("answer yes or no") {
            return true
        }

        let asksForConfirmation = normalizedMessage.contains("please confirm")
            || normalizedMessage.contains("do you want me to")
            || normalizedMessage.contains("should i")
            || normalizedMessage.contains("can i carry")
            || normalizedMessage.contains("shall i")
        return asksForConfirmation && normalizedMessage.contains("?")
    }

    private func pmConversationMessageRequestsClarification(_ normalizedMessage: String) -> Bool {
        if normalizedMessage.contains("which")
            || normalizedMessage.contains("what do you want")
            || normalizedMessage.contains("please tell me")
            || normalizedMessage.contains("point me to the next")
            || normalizedMessage.contains("what should i") {
            return normalizedMessage.contains("?") || normalizedMessage.contains("please")
        }
        return false
    }

    private func pmCommunicationMessage(
        _ lhs: PMCommunicationMessage,
        occurredBefore rhs: PMCommunicationMessage
    ) -> Bool {
        if lhs.sentAt == rhs.sentAt {
            return lhs.messageId < rhs.messageId
        }
        return lhs.sentAt < rhs.sentAt
    }

    @discardableResult
    private func recordLocalPMCommunicationSystemNote(
        sessionId: String,
        body: String,
        replyToMessageId: String? = nil,
        source: AuditEventSource
    ) async throws -> PMCommunicationMessage {
        let now = nowDate()
        let session = try await getPMCommunicationSession(id: sessionId)
        _ = try await upsertPMCommunicationSession(
            PMCommunicationSession(
                sessionId: session.sessionId,
                channel: session.channel,
                externalConversationId: session.externalConversationId,
                pmId: session.pmId,
                participantId: session.participantId,
                participantDisplayName: session.participantDisplayName,
                status: session.status,
                createdAt: session.createdAt,
                updatedAt: now
            ),
            source: source
        )

        let note = PMCommunicationMessage(
            messageId: "pm-message-\(UUID().uuidString.lowercased())",
            sessionId: session.sessionId,
            direction: .incoming,
            senderRole: .system,
            senderId: nil,
            body: body,
            sentAt: now,
            replyToMessageId: replyToMessageId,
            createdAt: now,
            updatedAt: now
        )
        let stored = try await upsertPMCommunicationMessage(note, source: source)
        await store.publishDiagnostic(
            "pm conversation system note recorded session=\(shortOrderID(session.sessionId)) reply_to=\(shortOrderID(replyToMessageId ?? "none"))",
            source: source,
            action: "pm_conversation_system_note"
        )
        return stored
    }

    private func makePMConversationReplyFailureNoteBody(
        error: Error,
        session: PMCommunicationSession
    ) -> String {
        let description = (error as? LocalizedError)?.errorDescription ?? error.localizedDescription
        if session.channel == .telegram || session.channel == .mockTelegram,
           error is TelegramBridgeError {
            return "The PM reply was saved in the app-owned communication log, but Telegram delivery failed: \(description)"
        }
        return "Your message was recorded, but the PM reply could not be completed: \(description)"
    }

    public func buildTelegramApprovalRequestPrompt(
        approvalRequestId: String
    ) async throws -> String {
        let request = try await getPMApprovalRequest(id: approvalRequestId)
        let memo = try await loadTelegramApprovalMemoPresentation(request: request)
        return makeTelegramApprovalRequestPrompt(request: request, memo: memo)
    }

    public func buildTelegramDecisionPrompt(
        decisionId: String,
        wakeUpClass: TelegramPMWakeUpClass? = nil
    ) async throws -> String {
        let decision = try await getPMDecision(id: decisionId)
        let context = try await loadTelegramDecisionTransportContext(decision: decision)
        let effectiveWakeUpClass = wakeUpClass
            ?? classifyTelegramDecisionWakeUpClass(
                decision: decision,
                memo: context.memo,
                recentNewsWakeUp: context.recentNewsWakeUp,
                portfolioRiskWakeUp: context.portfolioRiskWakeUp
            )
        return makeTelegramDecisionNotificationPrompt(
            decision: decision,
            memo: context.memo,
            wakeUpClass: effectiveWakeUpClass,
            recentNewsWakeUp: context.recentNewsWakeUp,
            portfolioRiskWakeUp: context.portfolioRiskWakeUp
        )
    }

    @discardableResult
    public func sendTelegramApprovalRequestPrompt(
        approvalRequestId: String,
        sessionId: String,
        source: AuditEventSource = .system
    ) async throws -> PMCommunicationMessage {
        let request = try await getPMApprovalRequest(id: approvalRequestId)
        let session = try await getPMCommunicationSession(id: sessionId)
        guard session.channel == .telegram || session.channel == .mockTelegram else {
            throw TelegramBridgeError.telegramSessionNotBound(sessionId: sessionId)
        }

        let memo = try await loadTelegramApprovalMemoPresentation(request: request)
        let body = makeTelegramApprovalRequestPrompt(request: request, memo: memo)
        let message = try await createPMCommunicationMessage(
            sessionId: sessionId,
            senderRole: .pm,
            senderId: request.pmId,
            body: body,
            replyToMessageId: nil,
            telegramDelivery: .approvalRequired(reason: "Explicit PM approval request."),
            source: source
        )

        if request.sourceCommunicationMessageId != message.messageId {
            var updatedRequest = request
            updatedRequest.sourceCommunicationMessageId = message.messageId
            updatedRequest.updatedAt = nowDate()
            _ = try await upsertPMApprovalRequest(updatedRequest, source: source)
        }
        return message
    }

    @discardableResult
    public func sendTelegramDecisionPrompt(
        decisionId: String,
        sessionId: String,
        wakeUpClass: TelegramPMWakeUpClass? = nil,
        source: AuditEventSource = .system
    ) async throws -> PMCommunicationMessage {
        let decision = try await getPMDecision(id: decisionId)
        let session = try await getPMCommunicationSession(id: sessionId)
        guard session.channel == .telegram || session.channel == .mockTelegram else {
            throw TelegramBridgeError.telegramSessionNotBound(sessionId: sessionId)
        }

        let context = try await loadTelegramDecisionTransportContext(decision: decision)
        let effectiveWakeUpClass = wakeUpClass
            ?? classifyTelegramDecisionWakeUpClass(
                decision: decision,
                memo: context.memo,
                recentNewsWakeUp: context.recentNewsWakeUp,
                portfolioRiskWakeUp: context.portfolioRiskWakeUp
            )
        guard effectiveWakeUpClass != .doNotSendProactively else {
            throw TelegramBridgeError.proactiveSendSuppressed(
                reason: "This PM item stays passive in Telegram by default and does not justify a proactive wake-up."
            )
        }

        let body = makeTelegramDecisionNotificationPrompt(
            decision: decision,
            memo: context.memo,
            wakeUpClass: effectiveWakeUpClass,
            recentNewsWakeUp: context.recentNewsWakeUp,
            portfolioRiskWakeUp: context.portfolioRiskWakeUp
        )
        let delivery: TelegramPMDeliveryBehavior
        switch effectiveWakeUpClass {
        case .approvalRequired:
            delivery = .approvalRequired(reason: "Explicit PM decision ask.")
        case .importantWakeUp:
            delivery = .importantWakeUp(reason: "Material PM decision update.")
        case .quietInfo:
            delivery = .quietInfo(reason: "Low-urgency PM informational update.")
        case .conversationReply:
            delivery = .conversationReply
        case .doNotSendProactively:
            delivery = .doNotSendProactively(reason: "Passive PM item.")
        }

        return try await createPMCommunicationMessage(
            sessionId: sessionId,
            senderRole: .pm,
            senderId: decision.pmId,
            body: body,
            replyToMessageId: nil,
            telegramDelivery: delivery,
            source: source
        )
    }

    private enum TelegramBotTokenRequestContext {
        case polling
        case status
        case outbound
    }

    private static let telegramNoChangePollStatusHeartbeatInterval: TimeInterval = 300

    private func telegramBotToken(
        for context: TelegramBotTokenRequestContext,
        throttleMissingForPolling: Bool = true
    ) -> String? {
        if let cachedTelegramBotToken,
           cachedTelegramBotToken.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty == false {
            incrementTelegramTokenCacheHit(for: context)
            return cachedTelegramBotToken
        }

        let now = nowDate()
        if context == .polling,
           throttleMissingForPolling,
           let lastMissingTelegramBotTokenReadAt,
           now.timeIntervalSince(lastMissingTelegramBotTokenReadAt) < Self.telegramMissingBotTokenRetryInterval {
            telegramBridgeRuntimeDiagnosticsState.pollingTokenMissingThrottleCount += 1
            telegramBridgeRuntimeDiagnosticsState.missingBotTokenCount += 1
            return nil
        }

        incrementTelegramTokenKeychainRead(for: context)
        let token = TelegramBotKeychainStatusProvider(
            keychainProvider: keychainProvider
        ).botToken()?.trimmingCharacters(in: .whitespacesAndNewlines)
        guard let token, token.isEmpty == false else {
            if context == .polling {
                lastMissingTelegramBotTokenReadAt = now
            }
            telegramBridgeRuntimeDiagnosticsState.missingBotTokenCount += 1
            return nil
        }

        cachedTelegramBotToken = token
        lastMissingTelegramBotTokenReadAt = nil
        return token
    }

    private func incrementTelegramTokenKeychainRead(for context: TelegramBotTokenRequestContext) {
        switch context {
        case .polling:
            telegramBridgeRuntimeDiagnosticsState.pollingTokenKeychainReadCount += 1
        case .status:
            telegramBridgeRuntimeDiagnosticsState.statusTokenKeychainReadCount += 1
        case .outbound:
            telegramBridgeRuntimeDiagnosticsState.outboundTokenKeychainReadCount += 1
        }
    }

    private func incrementTelegramTokenCacheHit(for context: TelegramBotTokenRequestContext) {
        switch context {
        case .polling:
            telegramBridgeRuntimeDiagnosticsState.pollingTokenCacheHitCount += 1
        case .status:
            telegramBridgeRuntimeDiagnosticsState.statusTokenCacheHitCount += 1
        case .outbound:
            telegramBridgeRuntimeDiagnosticsState.outboundTokenCacheHitCount += 1
        }
    }

    public func telegramBridgeStatus() async -> TelegramBridgeStatus {
        let state = await bootstrappedTelegramOwnerRouteAllowlist(await telegramBridgeStateStore.load())
        let allowlistedOwnerChatId = resolvedTelegramOwnerAllowlistedChatId(state)
        let allowlistedOwnerSessionId = state.allowlistedOwnerSessionId?
            .trimmingCharacters(in: .whitespacesAndNewlines).isEmpty == false
            ? state.allowlistedOwnerSessionId
            : allowlistedOwnerChatId.map { telegramSessionID(chatId: $0) }
        let allowlistedOwnerParticipantLabel = state.allowlistedOwnerParticipantLabel?
            .trimmingCharacters(in: .whitespacesAndNewlines).isEmpty == false
            ? state.allowlistedOwnerParticipantLabel
            : state.lastBoundParticipantLabel
        let tokenConfigured = telegramBotToken(for: .status) != nil
        return TelegramBridgeStatus(
            tokenConfigured: tokenConfigured,
            allowlistedOwnerChatId: allowlistedOwnerChatId,
            allowlistedOwnerSessionId: allowlistedOwnerSessionId,
            allowlistedOwnerParticipantLabel: allowlistedOwnerParticipantLabel,
            lastConsumedUpdateId: state.lastConsumedUpdateId,
            lastPollAt: state.lastPollAt,
            lastPollSummary: state.lastPollSummary,
            lastRequestedOffset: state.lastRequestedOffset,
            lastHighestFetchedUpdateId: state.lastHighestFetchedUpdateId,
            lastRecoveryTriggered: state.lastRecoveryTriggered,
            lastRecoveryOffset: state.lastRecoveryOffset,
            lastWebhookPresent: state.lastWebhookPresent,
            lastWebhookPendingUpdateCount: state.lastWebhookPendingUpdateCount,
            lastWebhookLastErrorMessage: state.lastWebhookLastErrorMessage,
            lastBoundChatId: state.lastBoundChatId,
            lastBoundSessionId: state.lastBoundSessionId,
            lastBoundParticipantLabel: state.lastBoundParticipantLabel,
            lastOutboundAt: state.lastOutboundAt,
            lastOutboundSummary: state.lastOutboundSummary,
            lastOutboundWakeUpClass: state.lastOutboundWakeUpClass,
            lastOutboundSilent: state.lastOutboundSilent,
            lastOutboundReason: state.lastOutboundReason,
            unauthorizedInboundCount: state.unauthorizedInboundCount,
            lastUnauthorizedInboundAt: state.lastUnauthorizedInboundAt,
            lastUnauthorizedChatId: state.lastUnauthorizedChatId,
            lastUnauthorizedParticipantLabel: state.lastUnauthorizedParticipantLabel
        )
    }

    public func telegramBridgeRuntimeDiagnostics() -> TelegramBridgeRuntimeDiagnostics {
        telegramBridgeRuntimeDiagnosticsState
    }

    @discardableResult
    public func pollTelegramUpdates(
        pmId: String? = nil,
        source: AuditEventSource = .system
    ) async throws -> TelegramBridgePollResult {
        telegramBridgeRuntimeDiagnosticsState.pollCount += 1
        guard let botToken = telegramBotToken(for: .polling) else {
            throw TelegramBridgeError.missingBotToken
        }

        let existingState = await telegramBridgeStateStore.load()
        let requestedOffset = existingState.lastConsumedUpdateId.map { $0 + 1 }
        let webhookInfo = try await telegramBotService.getWebhookInfo(botToken: botToken)
        let webhookPresent = webhookInfo.hasWebhook
        var webhookCleared = false
        if webhookPresent {
            webhookCleared = try await telegramBotService.deleteWebhook(
                botToken: botToken,
                dropPendingUpdates: false
            )
        }

        var updates = try await telegramBotService.getUpdates(
            botToken: botToken,
            offset: requestedOffset
        )
        let recoveryOffset = telegramRecoveryOffset(
            existingState: existingState,
            primaryUpdates: updates
        )
        let recoveryTriggered = recoveryOffset != nil
        if let recoveryOffset {
            let recovered = try await telegramBotService.getUpdates(
                botToken: botToken,
                offset: recoveryOffset
            )
            updates = mergeTelegramUpdates(primary: updates, recovery: recovered)
        }

        var updatedState = await bootstrappedTelegramOwnerRouteAllowlist(existingState)
        var ingestedMessageCount = 0
        var duplicateUpdateCount = 0
        var skippedUnsupportedCount = 0
        var unauthorizedIgnoredCount = 0
        var approvalResponseCount = 0
        var clarificationReplyCount = 0
        var replyGenerationError: Error?
        var maxConsumedUpdateId = existingState.lastConsumedUpdateId
        let highestFetchedUpdateId = updates.map(\.updateId).max()
        var lastBoundChatId = existingState.lastBoundChatId
        var lastBoundSessionId = existingState.lastBoundSessionId
        var lastBoundParticipantLabel = existingState.lastBoundParticipantLabel
        let allowlistedOwnerChatId = resolvedTelegramOwnerAllowlistedChatId(updatedState)
        if let allowlistedOwnerChatId {
            updatedState.allowlistedOwnerChatId = allowlistedOwnerChatId
            if updatedState.allowlistedOwnerSessionId?.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty ?? true {
                updatedState.allowlistedOwnerSessionId = telegramSessionID(chatId: allowlistedOwnerChatId)
            }
            if updatedState.allowlistedOwnerParticipantLabel?.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty ?? true {
                updatedState.allowlistedOwnerParticipantLabel = updatedState.lastBoundParticipantLabel
            }
        }

        for update in updates.sorted(by: { $0.updateId < $1.updateId }) {
            guard let inboundMessage = update.message else {
                if let currentMax = maxConsumedUpdateId, update.updateId <= currentMax {
                    duplicateUpdateCount += 1
                    continue
                }
                maxConsumedUpdateId = max(maxConsumedUpdateId ?? update.updateId, update.updateId)
                continue
            }

            let trimmedBody = inboundMessage.text?
                .trimmingCharacters(in: .whitespacesAndNewlines)
            guard let trimmedBody, trimmedBody.isEmpty == false else {
                skippedUnsupportedCount += 1
                maxConsumedUpdateId = max(maxConsumedUpdateId ?? update.updateId, update.updateId)
                continue
            }

            let inboundParticipantLabel = inboundMessage.from?.displayName ?? inboundMessage.chat.displayName
            guard let allowlistedOwnerChatId,
                  inboundMessage.chat.id == allowlistedOwnerChatId else {
                unauthorizedIgnoredCount += 1
                updatedState.unauthorizedInboundCount += 1
                updatedState.lastUnauthorizedInboundAt = inboundMessage.sentAt
                updatedState.lastUnauthorizedChatId = inboundMessage.chat.id
                updatedState.lastUnauthorizedParticipantLabel = inboundParticipantLabel
                maxConsumedUpdateId = max(maxConsumedUpdateId ?? update.updateId, update.updateId)
                continue
            }

            let session = try await ensureTelegramPMUserCommunicationSession(
                chatId: inboundMessage.chat.id,
                participantId: inboundMessage.from?.id,
                participantDisplayName: inboundParticipantLabel,
                pmId: pmId,
                updatedAt: inboundMessage.sentAt,
                source: source
            )

            let messageId = telegramInboundMessageID(
                chatId: inboundMessage.chat.id,
                telegramMessageId: inboundMessage.messageId
            )
            let replyToMessageId = inboundMessage.replyToMessage.map {
                telegramInboundMessageID(
                    chatId: inboundMessage.chat.id,
                    telegramMessageId: $0.messageId
                )
            }
            let existingMessage = try await pmCommunicationMessageStore.get(id: messageId)
            if let currentMax = maxConsumedUpdateId,
               update.updateId <= currentMax,
               existingMessage != nil || recoveryTriggered == false {
                duplicateUpdateCount += 1
                continue
            }
            let message = PMCommunicationMessage(
                messageId: messageId,
                sessionId: session.sessionId,
                direction: .incoming,
                senderRole: .owner,
                senderId: inboundMessage.from?.id ?? inboundMessage.chat.id,
                body: trimmedBody,
                sentAt: inboundMessage.sentAt,
                replyToMessageId: replyToMessageId,
                promotion: existingMessage?.promotion,
                createdAt: existingMessage?.createdAt ?? inboundMessage.sentAt,
                updatedAt: inboundMessage.sentAt
            )
            let persistedMessage = try await upsertPMCommunicationMessage(message, source: source)

            ingestedMessageCount += existingMessage == nil ? 1 : 0
            if existingMessage == nil,
               let outcome = try await handleTelegramInboundIntent(
                   session: session,
                   message: persistedMessage,
                   source: source
               ) {
                approvalResponseCount += outcome.recordedApprovalResponse ? 1 : 0
                clarificationReplyCount += outcome.sentClarificationReply ? 1 : 0
            } else if existingMessage == nil {
                do {
                    _ = try await generatePMConversationReply(
                        to: persistedMessage.messageId,
                        source: source
                    )
                } catch {
                    if replyGenerationError == nil {
                        replyGenerationError = error
                    }
                }
            }
            maxConsumedUpdateId = max(maxConsumedUpdateId ?? update.updateId, update.updateId)
            lastBoundChatId = inboundMessage.chat.id
            lastBoundSessionId = session.sessionId
            lastBoundParticipantLabel = session.participantDisplayName
            updatedState.allowlistedOwnerChatId = inboundMessage.chat.id
            updatedState.allowlistedOwnerSessionId = session.sessionId
            updatedState.allowlistedOwnerParticipantLabel = session.participantDisplayName
        }

        let outboundState: TelegramBridgeState
        if ingestedMessageCount > 0 || approvalResponseCount > 0 || clarificationReplyCount > 0 {
            outboundState = await telegramBridgeStateStore.load()
        } else {
            outboundState = existingState
        }
        let pollSummary = makeTelegramPollSummary(
            fetchedUpdateCount: updates.count,
            ingestedMessageCount: ingestedMessageCount,
            duplicateUpdateCount: duplicateUpdateCount,
            skippedUnsupportedCount: skippedUnsupportedCount,
            unauthorizedIgnoredCount: unauthorizedIgnoredCount,
            approvalResponseCount: approvalResponseCount,
            clarificationReplyCount: clarificationReplyCount,
            requestedOffset: requestedOffset,
            highestFetchedUpdateId: highestFetchedUpdateId,
            webhookPresent: webhookPresent,
            webhookCleared: webhookCleared,
            webhookPendingUpdateCount: webhookInfo.pendingUpdateCount,
            recoveryTriggered: recoveryTriggered,
            recoveryOffset: recoveryOffset,
            ownerRouteAllowlisted: resolvedTelegramOwnerAllowlistedChatId(updatedState) != nil,
            learnedChatBound: lastBoundChatId != nil && lastBoundSessionId != nil
        )
        let pollCompletedAt = nowDate()
        let routeChanged = updatedState.allowlistedOwnerChatId != existingState.allowlistedOwnerChatId
            || updatedState.allowlistedOwnerSessionId != existingState.allowlistedOwnerSessionId
            || updatedState.allowlistedOwnerParticipantLabel != existingState.allowlistedOwnerParticipantLabel
            || lastBoundChatId != existingState.lastBoundChatId
            || lastBoundSessionId != existingState.lastBoundSessionId
            || lastBoundParticipantLabel != existingState.lastBoundParticipantLabel
        let outboundChanged = outboundState.lastOutboundAt != existingState.lastOutboundAt
            || outboundState.lastOutboundSummary != existingState.lastOutboundSummary
            || outboundState.lastOutboundWakeUpClass != existingState.lastOutboundWakeUpClass
            || outboundState.lastOutboundSilent != existingState.lastOutboundSilent
            || outboundState.lastOutboundReason != existingState.lastOutboundReason
        let webhookChanged = webhookPresent != existingState.lastWebhookPresent
            || webhookInfo.pendingUpdateCount != existingState.lastWebhookPendingUpdateCount
            || webhookInfo.lastErrorMessage != existingState.lastWebhookLastErrorMessage
        let pollShouldPersistState = updates.isEmpty == false
            || ingestedMessageCount > 0
            || duplicateUpdateCount > 0
            || skippedUnsupportedCount > 0
            || unauthorizedIgnoredCount > 0
            || approvalResponseCount > 0
            || clarificationReplyCount > 0
            || maxConsumedUpdateId != existingState.lastConsumedUpdateId
            || recoveryTriggered != existingState.lastRecoveryTriggered
            || recoveryOffset != existingState.lastRecoveryOffset
            || webhookChanged
            || routeChanged
            || outboundChanged
        let pollMateriallyChangedState = ingestedMessageCount > 0
            || approvalResponseCount > 0
            || clarificationReplyCount > 0
            || unauthorizedIgnoredCount > 0
            || routeChanged
            || outboundChanged
        let heartbeatDue = existingState.lastPollAt.map {
            pollCompletedAt.timeIntervalSince($0) >= Self.telegramNoChangePollStatusHeartbeatInterval
        } ?? true
        let shouldPersistPollState = pollShouldPersistState || heartbeatDue
        if pollMateriallyChangedState {
            telegramBridgeRuntimeDiagnosticsState.materialChangePollCount += 1
        } else {
            telegramBridgeRuntimeDiagnosticsState.noChangePollCount += 1
        }
        if ingestedMessageCount > 0 || approvalResponseCount > 0 || clarificationReplyCount > 0 {
            telegramBridgeRuntimeDiagnosticsState.communicationChangePollCount += 1
        }
        if shouldPersistPollState {
            telegramBridgeRuntimeDiagnosticsState.statusRefreshRecommendedPollCount += 1
        }
        if shouldPersistPollState && pollMateriallyChangedState == false && heartbeatDue {
            telegramBridgeRuntimeDiagnosticsState.heartbeatRefreshPollCount += 1
        }

        if shouldPersistPollState {
            updatedState.lastConsumedUpdateId = maxConsumedUpdateId
            updatedState.lastPollAt = pollCompletedAt
            updatedState.lastRequestedOffset = requestedOffset
            updatedState.lastHighestFetchedUpdateId = highestFetchedUpdateId
            updatedState.lastRecoveryTriggered = recoveryTriggered
            updatedState.lastRecoveryOffset = recoveryOffset
            updatedState.lastWebhookPresent = webhookPresent
            updatedState.lastWebhookPendingUpdateCount = webhookInfo.pendingUpdateCount
            updatedState.lastWebhookLastErrorMessage = webhookInfo.lastErrorMessage
            updatedState.lastBoundChatId = lastBoundChatId
            updatedState.lastBoundSessionId = lastBoundSessionId
            updatedState.lastBoundParticipantLabel = lastBoundParticipantLabel
            updatedState.lastOutboundAt = outboundState.lastOutboundAt
            updatedState.lastOutboundSummary = outboundState.lastOutboundSummary
            updatedState.lastOutboundWakeUpClass = outboundState.lastOutboundWakeUpClass
            updatedState.lastOutboundSilent = outboundState.lastOutboundSilent
            updatedState.lastOutboundReason = outboundState.lastOutboundReason
            updatedState.lastPollSummary = pollSummary
            _ = try await telegramBridgeStateStore.save(updatedState)
            telegramBridgeRuntimeDiagnosticsState.durableStateSaveCount += 1
            await publishPMPersistenceDiagnostics()
            await store.publishDiagnostic(
                "telegram bridge poll completed fetched=\(updates.count) ingested=\(ingestedMessageCount) duplicates=\(duplicateUpdateCount) skipped=\(skippedUnsupportedCount) unauthorized=\(unauthorizedIgnoredCount) requested_offset=\(requestedOffset.map(String.init) ?? "nil") highest_fetched=\(highestFetchedUpdateId.map(String.init) ?? "nil") webhook_present=\(webhookPresent) webhook_cleared=\(webhookCleared) recovery=\(recoveryTriggered)",
                source: source,
                action: "telegram_bridge_poll"
            )
        }

        if let replyGenerationError {
            throw replyGenerationError
        }

        return TelegramBridgePollResult(
            fetchedUpdateCount: updates.count,
            ingestedMessageCount: ingestedMessageCount,
            duplicateUpdateCount: duplicateUpdateCount,
            skippedUnsupportedCount: skippedUnsupportedCount,
            unauthorizedIgnoredCount: unauthorizedIgnoredCount,
            approvalResponseCount: approvalResponseCount,
            clarificationReplyCount: clarificationReplyCount,
            requestedOffset: requestedOffset,
            highestFetchedUpdateId: highestFetchedUpdateId,
            recoveryTriggered: recoveryTriggered,
            recoveryOffset: recoveryOffset,
            webhookPresent: webhookPresent,
            webhookPendingUpdateCount: webhookInfo.pendingUpdateCount,
            lastConsumedUpdateId: shouldPersistPollState ? updatedState.lastConsumedUpdateId : existingState.lastConsumedUpdateId,
            allowlistedOwnerChatId: resolvedTelegramOwnerAllowlistedChatId(updatedState),
            allowlistedOwnerSessionId: updatedState.allowlistedOwnerSessionId
                ?? resolvedTelegramOwnerAllowlistedChatId(updatedState).map { telegramSessionID(chatId: $0) },
            boundChatId: updatedState.lastBoundChatId,
            boundSessionId: updatedState.lastBoundSessionId,
            statusRefreshRecommended: shouldPersistPollState
        )
    }

    @discardableResult
    public func promotePMCommunicationMessageToNotebookEntry(
        messageId: String,
        pmId: String,
        title: String,
        body: String,
        sourceSummary: String? = nil,
        source: AuditEventSource = .system
    ) async throws -> PMNotebookEntry {
        let message = try await requirePromotableCommunicationMessage(id: messageId)
        let validatedPMID = try validatedPMCommunicationPromotionPMID(pmId)
        let validatedTitle = try validatedPMCommunicationPromotionTitle(title)
        let validatedBody = try validatedPMCommunicationPromotionBody(body)
        let now = nowDate()
        let entry = PMNotebookEntry(
            entryId: "pm-note-\(UUID().uuidString.lowercased())",
            pmId: validatedPMID,
            title: validatedTitle,
            body: validatedBody,
            sourceSummary: sourceSummary ?? defaultCommunicationPromotionSourceSummary(message),
            createdAt: now,
            updatedAt: now
        )
        let stored = try await upsertPMNotebookEntry(entry, source: source)
        _ = try await upsertPMCommunicationPromotion(
            message: message,
            targetType: .notebookEntry,
            targetId: stored.entryId,
            source: source
        )
        return stored
    }

    @discardableResult
    public func promotePMCommunicationMessageToInstruction(
        messageId: String,
        pmId: String,
        title: String,
        body: String,
        category: String = "communication_promotion",
        source: AuditEventSource = .system
    ) async throws -> PMInstruction {
        let message = try await requirePromotableCommunicationMessage(id: messageId)
        let validatedPMID = try validatedPMCommunicationPromotionPMID(pmId)
        let validatedTitle = try validatedPMCommunicationPromotionTitle(title)
        let validatedBody = try validatedPMCommunicationPromotionBody(body)
        let now = nowDate()
        let instruction = PMInstruction(
            instructionId: "pm-instruction-\(UUID().uuidString.lowercased())",
            pmId: validatedPMID,
            title: validatedTitle,
            body: validatedBody,
            category: category,
            status: .active,
            createdAt: now,
            updatedAt: now
        )
        let stored = try await upsertPMInstruction(instruction, source: source)
        _ = try await upsertPMCommunicationPromotion(
            message: message,
            targetType: .instruction,
            targetId: stored.instructionId,
            source: source
        )
        return stored
    }

    @discardableResult
    public func promotePMCommunicationMessageToDecision(
        messageId: String,
        pmId: String,
        title: String,
        summary: String,
        decisionType: PMDecisionType = .other,
        source: AuditEventSource = .system
