        let message = try await requirePromotableCommunicationMessage(id: messageId)
        let validatedPMID = try validatedPMCommunicationPromotionPMID(pmId)
        let validatedTitle = try validatedPMCommunicationPromotionTitle(title)
        let validatedSummary = try validatedPMCommunicationPromotionBody(summary)
        let now = nowDate()
        let decision = PMDecisionRecord(
            decisionId: "pm-decision-\(UUID().uuidString.lowercased())",
            pmId: validatedPMID,
            title: validatedTitle,
            summary: validatedSummary,
            sourceCommunicationMessageId: message.messageId,
            decisionType: decisionType,
            status: .active,
            createdAt: now,
            updatedAt: now
        )
        let stored = try await upsertPMDecision(decision, source: source)
        _ = try await upsertPMCommunicationPromotion(
            message: message,
            targetType: .decision,
            targetId: stored.decisionId,
            source: source
        )
        return stored
    }

    @discardableResult
    public func promotePMCommunicationMessageToApprovalRequest(
