    @discardableResult
    public func createPMApprovalRequestFromDecision(
        decisionId: String,
        subject: String? = nil,
        rationale: String? = nil,
        requestedActionSummary: String? = nil,
        approvedNextStepSummary: String? = nil,
        rejectedNextStepSummary: String? = nil,
        reviewedNextStepSummary: String? = nil,
        requestType: PMApprovalRequestType? = nil,
        liveOrderReview: PMLiveOrderReviewPayload? = nil,
        source: AuditEventSource = .system
    ) async throws -> PMApprovalRequest {
        let decision = try await getPMDecision(id: decisionId)
        let existingRequests = try await listPMApprovalRequests()
        if let pending = existingRequests.first(where: { $0.decisionId == decisionId && $0.status == .pending }) {
            return pending
        }
        if let approvedPendingExecution = existingRequests.first(where: {
            $0.decisionId == decisionId && approvedPendingPaperPortfolioExecutionState(for: $0) != nil
        }) {
            return approvedPendingExecution
        }

        let now = nowDate()
        let derivedSubject = trimmedOptionalDecisionText(subject)
            ?? "Review PM recommendation: \(decision.title)"
        let derivedRationale = trimmedOptionalDecisionText(rationale)
            ?? decision.summary
        let derivedRequestType = requestType
            ?? (decision.proposalId == nil ? .portfolioAction : .proposalReview)
        let derivedRequestedActionSummary = trimmedOptionalDecisionText(requestedActionSummary)
            ?? decision.ownerAsk
            ?? decision.recommendedAction
        let derivedApprovedNextStepSummary = trimmedOptionalDecisionText(approvedNextStepSummary)
            ?? decision.approvedNextStepSummary
            ?? defaultPMApprovedNextStepSummary(decision: decision)
        let derivedRejectedNextStepSummary = trimmedOptionalDecisionText(rejectedNextStepSummary)
            ?? defaultPMRejectedNextStepSummary(decision: decision)
        let derivedReviewedNextStepSummary = trimmedOptionalDecisionText(reviewedNextStepSummary)
            ?? defaultPMReviewedNextStepSummary(decision: decision)

        let request = PMApprovalRequest(
            approvalRequestId: "pm-approval-\(UUID().uuidString.lowercased())",
            pmId: decision.pmId,
            subject: derivedSubject,
            rationale: derivedRationale,
            requestedActionSummary: derivedRequestedActionSummary,
            approvedNextStepSummary: derivedApprovedNextStepSummary,
            rejectedNextStepSummary: derivedRejectedNextStepSummary,
            reviewedNextStepSummary: derivedReviewedNextStepSummary,
            sourceCommunicationMessageId: decision.sourceCommunicationMessageId,
            requestType: derivedRequestType,
            status: .pending,
            decisionId: decision.decisionId,
            delegationId: decision.delegationId,
            findingId: decision.findingId,
            signalId: decision.signalId,
            proposalId: decision.proposalId,
            liveOrderReview: liveOrderReview,
            createdAt: now,
            updatedAt: now
        )
        return try await upsertPMApprovalRequest(request, source: source)
    }

