    private struct AlpacaTradingCredentialRouteBlocker: Sendable, Equatable {
        let readiness: AlpacaCredentialReadiness
        let summary: String
        let detail: String
        let blockedReasons: [PMExecutionRoutingBlockReason]
    }

    private func alpacaTradingCredentialRouteBlocker(
        for environment: Environment
    ) -> AlpacaTradingCredentialRouteBlocker? {
        let readiness = keychainProvider.alpacaCredentialReadiness(for: environment)
        guard readiness.isReady == false else {
            return nil
        }

        var missingPieces: [String] = []
        if readiness.publicKeyFound == false {
            missingPieces.append("public key")
        }
        if readiness.secretKeyFound == false {
            missingPieces.append("secret key")
        }
        let missingSummary = missingPieces.isEmpty
            ? "credentials"
            : missingPieces.joined(separator: " and ")
        let environmentLabel = environment.rawValue.capitalized
        let detail = [
            "Order placement is blocked because the \(environmentLabel) Alpaca trading \(missingSummary) did not resolve from Keychain for the current app process.",
            "Existing account data may be from an earlier reconciliation and does not prove current order-submission readiness.",
            "No order will be submitted until the \(environment.rawValue) trading credentials are available through the Engine-owned Alpaca credential path."
        ].joined(separator: " ")

        return AlpacaTradingCredentialRouteBlocker(
            readiness: readiness,
            summary: "\(environmentLabel) Alpaca trading credentials are unavailable.",
            detail: detail,
            blockedReasons: [.alpacaTradingCredentialsUnavailable]
        )
    }

    private func workingPaperPortfolioTargetSymbols(
        for request: PMApprovalRequest
    ) async -> [String] {
        guard let sourceText = try? await latestWorkingPaperPortfolioExecutionSourceText(for: request),
              sourceText.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty == false else {
            return []
        }
        return orderedUniqueStrings(
            parseWorkingPaperPortfolioExecutionTargets(from: sourceText).map(\.symbol)
        )
    }

    private func latestWorkingPaperPortfolioExecutionSourceText(
        for request: PMApprovalRequest
    ) async throws -> String? {
        let instructions = try await pmInstructionStore.loadAll()
            .filter { instruction in
                instruction.status == .active
                    && instruction.category == pmConversationInstructionCategory(.workingPortfolioDefinition)
                    && (trimmedOptionalDecisionText(request.pmId) == nil || instruction.pmId == request.pmId)
            }
            .sorted { lhs, rhs in
                if lhs.updatedAt == rhs.updatedAt {
                    return lhs.instructionId < rhs.instructionId
                }
                return lhs.updatedAt > rhs.updatedAt
            }

        if let latestInstruction = instructions.first,
           latestInstruction.body.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty == false {
            return latestInstruction.body
        }

        let fallback = [
            request.requestedActionSummary,
            request.rationale,
            request.subject,
            request.approvedNextStepSummary
        ]
        .compactMap(trimmedOptionalDecisionText)
        .joined(separator: " ")
        .trimmingCharacters(in: .whitespacesAndNewlines)
        return fallback.isEmpty ? nil : fallback
    }

    private func parseWorkingPaperPortfolioExecutionTargets(
        from text: String
    ) -> [PMWorkingPaperPortfolioTarget] {
        let normalizedText = text.replacingOccurrences(of: "#", with: "")
        let directMatches = pmConversationRegexCaptureGroups(
            pattern: "(?i)\\b(long|short)\\b\\s+([A-Z][A-Z0-9\\.\\-]*)\\s*(-?\\d+(?:\\.\\d+)?)%",
            in: normalizedText
        ).compactMap { captures -> PMWorkingPaperPortfolioTarget? in
            guard captures.count >= 3 else { return nil }
            let side: OrderSide = captures[0].lowercased() == "short" ? .sell : .buy
            return pmWorkingPaperPortfolioTarget(
                symbol: captures[1],
                side: side,
                rawWeight: captures[2]
            )
        }

        let sectionMatches =
            parseWorkingPaperPortfolioExecutionSectionTargets(
                from: normalizedText,
                sideLabel: "long",
                side: .buy
            )
            + parseWorkingPaperPortfolioExecutionSectionTargets(
                from: normalizedText,
                sideLabel: "short",
                side: .sell
            )

        let preferred = sectionMatches.count > directMatches.count ? sectionMatches : directMatches
        var seen: Set<String> = []
        var ordered: [PMWorkingPaperPortfolioTarget] = []
        for target in preferred {
            let key = "\(target.side.rawValue):\(target.symbol)"
            if seen.insert(key).inserted {
                ordered.append(target)
            }
        }
        return ordered
    }

    private func parseWorkingPaperPortfolioExecutionSectionTargets(
        from text: String,
        sideLabel: String,
        side: OrderSide
    ) -> [PMWorkingPaperPortfolioTarget] {
        let pattern = "(?is)\\b\(sideLabel)(?: positions| sleeve| side)?\\b\\s*:?(.*?)(?=\\b(?:long|short)(?: positions| sleeve| side)?\\b|$)"
        let sections = pmConversationRegexCaptureGroups(
            pattern: pattern,
            in: text
        ).compactMap { $0.first }

        return sections.flatMap { section in
            pmConversationRegexCaptureGroups(
                pattern: "([A-Z][A-Z0-9\\.\\-]*)\\s*(-?\\d+(?:\\.\\d+)?)%",
                in: section
            ).compactMap { captures -> PMWorkingPaperPortfolioTarget? in
                guard captures.count >= 2 else { return nil }
                return pmWorkingPaperPortfolioTarget(
                    symbol: captures[0],
                    side: side,
                    rawWeight: captures[1]
                )
            }
        }
    }

    private func pmWorkingPaperPortfolioTarget(
        symbol: String,
        side: OrderSide,
        rawWeight: String
    ) -> PMWorkingPaperPortfolioTarget? {
        let normalizedSymbol = symbol.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        guard normalizedSymbol.isEmpty == false,
              let parsedWeight = decimalValue(rawWeight),
              parsedWeight != .zero else {
            return nil
        }
        return PMWorkingPaperPortfolioTarget(
            symbol: normalizedSymbol,
            side: side,
            weightPercent: abs(parsedWeight)
        )
    }

    private func workingPaperPortfolioSizingPrice(
        symbol: String,
        snapshot: StoreSnapshot
    ) -> Decimal? {
        guard let quote = snapshot.quotesBySymbol[symbol] else {
            return nil
        }
        if let last = positiveDecimal(from: quote.lastPrice) {
            return last
        }
        if let bid = quote.bidPrice,
           let ask = quote.askPrice,
           bid > 0,
           ask > 0 {
            return positiveDecimal(from: (bid + ask) / 2.0)
        }
        return positiveDecimal(from: quote.bidPrice) ?? positiveDecimal(from: quote.askPrice)
    }

    private func positiveDecimal(from value: Double?) -> Decimal? {
        guard let value, value > 0 else {
            return nil
        }
        return Decimal(string: String(value), locale: Locale(identifier: "en_US_POSIX"))
    }

    private func wholeShareQuantityFloor(from quantity: Decimal) -> Int {
        let number = NSDecimalNumber(decimal: quantity)
        let zero = NSDecimalNumber(value: 0)
        guard number.compare(zero) == .orderedDescending else {
            return 0
        }

        let rounded = number.rounding(
            accordingToBehavior: NSDecimalNumberHandler(
                roundingMode: .down,
                scale: 0,
                raiseOnExactness: false,
                raiseOnOverflow: false,
                raiseOnUnderflow: false,
                raiseOnDivideByZero: false
            )
        )
        guard rounded.compare(zero) == .orderedDescending else {
            return 0
        }
        if rounded.compare(NSDecimalNumber(value: Int.max)) == .orderedDescending {
            return Int.max
        }
        return rounded.intValue
    }

    private func wholeShareQuantityNearest(from quantity: Decimal) -> Int {
        let number = NSDecimalNumber(decimal: quantity)
        let zero = NSDecimalNumber(value: 0)
        guard number.compare(zero) == .orderedDescending else {
            return 0
        }

        let rounded = number.rounding(
            accordingToBehavior: NSDecimalNumberHandler(
                roundingMode: .plain,
                scale: 0,
                raiseOnExactness: false,
                raiseOnOverflow: false,
                raiseOnUnderflow: false,
                raiseOnDivideByZero: false
            )
        )
        guard rounded.compare(zero) == .orderedDescending else {
            return 0
        }
        if rounded.compare(NSDecimalNumber(value: Int.max)) == .orderedDescending {
            return Int.max
        }
        return rounded.intValue
    }

    private func paperPortfolioDecimalText(
        _ value: Decimal,
        scale: Int16 = 4
    ) -> String {
        let rounded = NSDecimalNumber(decimal: value).rounding(
            accordingToBehavior: NSDecimalNumberHandler(
                roundingMode: .plain,
                scale: scale,
                raiseOnExactness: false,
                raiseOnOverflow: false,
                raiseOnUnderflow: false,
                raiseOnDivideByZero: false
            )
        )
        return rounded.stringValue
    }

    private func paperPortfolioZeroQuantityDetailText(
        _ details: [PMWorkingPaperPortfolioZeroQuantityDetail]
    ) -> String {
        guard details.isEmpty == false else {
            return ""
        }
        let lines = details.map { detail in
            "\(detail.symbol): equity \(paperPortfolioDecimalText(detail.equity, scale: 2)), target weight \(paperPortfolioDecimalText(detail.weightPercent, scale: 4))%, price \(paperPortfolioDecimalText(detail.sizingPrice, scale: 4)), target notional \(paperPortfolioDecimalText(detail.targetNotional, scale: 2)), raw quantity \(paperPortfolioDecimalText(detail.rawQuantity, scale: 6)), whole-share quantity \(detail.wholeShareQuantity)."
        }
        return "Sizing math for below-one-share blockers: \(lines.joined(separator: " "))"
    }

    private struct PMWorkingPaperPortfolioPriceRepairResult: Sendable, Equatable {
        var pricesBySymbol: [String: Decimal]
        var repairedSymbols: [String]
        var missingSymbols: [String]
        var detail: String?
    }

    private func repairWorkingPaperPortfolioSizingPrices(
        symbols: [String],
        source: AuditEventSource
    ) async -> PMWorkingPaperPortfolioPriceRepairResult {
        let normalizedSymbols = orderedUniqueStrings(Array(MarketDataSubscriptionSet.normalized(symbols))).sorted()
        guard workingPaperPortfolioPriceRepairEnabled,
              normalizedSymbols.isEmpty == false else {
            return PMWorkingPaperPortfolioPriceRepairResult(
                pricesBySymbol: [:],
                repairedSymbols: [],
                missingSymbols: normalizedSymbols,
                detail: workingPaperPortfolioPriceRepairEnabled
                    ? nil
                    : "Bounded historical-bar price repair is disabled for this Engine instance."
            )
        }

        let end = nowDate().addingTimeInterval(60)
        let start = Calendar(identifier: .gregorian)
            .date(byAdding: .day, value: -14, to: end)
            ?? end.addingTimeInterval(-14 * 24 * 60 * 60)
        do {
            let bars = try await barsProvider.fetchBars(
                symbols: normalizedSymbols,
                timeframe: .oneDay,
                start: start,
                end: end,
                limit: 1000,
                feed: ReplayFeed(marketDataFeed: configuration.marketDataFeed)
            )
            var latestBarsBySymbol: [String: Bar] = [:]
            for bar in bars {
                let symbol = bar.symbol.uppercased()
                guard normalizedSymbols.contains(symbol),
                      bar.close > 0 else {
                    continue
                }
                if let existing = latestBarsBySymbol[symbol],
                   existing.timestamp >= bar.timestamp {
                    continue
                }
                latestBarsBySymbol[symbol] = bar
            }

            let pricesBySymbol = latestBarsBySymbol.compactMapValues { bar in
                positiveDecimal(from: bar.close)
            }
            let repairedSymbols = normalizedSymbols.filter { pricesBySymbol[$0] != nil }
            let missingSymbols = normalizedSymbols.filter { pricesBySymbol[$0] == nil }
            await store.publishDiagnostic(
                "pm paper-portfolio price repair provider=alpaca_bars timeframe=1Day requested=\(normalizedSymbols.joined(separator: ",")) repaired=\(repairedSymbols.joined(separator: ",")) missing=\(missingSymbols.joined(separator: ","))",
                source: source,
                action: "pm_paper_portfolio_price_repair"
            )
            let detail: String? = missingSymbols.isEmpty
                ? "I repaired missing execution-sizing prices from bounded Engine-owned Alpaca daily bars."
                : "I attempted bounded Engine-owned Alpaca daily-bar price repair, but no usable recent close was returned for: \(missingSymbols.joined(separator: ", "))."
            return PMWorkingPaperPortfolioPriceRepairResult(
                pricesBySymbol: pricesBySymbol,
                repairedSymbols: repairedSymbols,
                missingSymbols: missingSymbols,
                detail: detail
            )
        } catch {
            let detail = "I attempted bounded Engine-owned Alpaca daily-bar price repair, but the repair failed: \(boundedConversationText(error.localizedDescription, limit: 180))."
            await store.publishDiagnostic(
                "pm paper-portfolio price repair failed provider=alpaca_bars requested=\(normalizedSymbols.joined(separator: ",")) reason=\(boundedConversationText(error.localizedDescription, limit: 180))",
                source: source,
                action: "pm_paper_portfolio_price_repair_failed",
                errorCode: "pm_paper_portfolio_price_repair_failed"
            )
            return PMWorkingPaperPortfolioPriceRepairResult(
                pricesBySymbol: [:],
                repairedSymbols: [],
                missingSymbols: normalizedSymbols,
                detail: detail
            )
        }
    }

    private func buildWorkingPaperPortfolioExecutionPlan(
        for request: PMApprovalRequest,
        source: AuditEventSource = .engine
    ) async throws -> PMWorkingPaperPortfolioExecutionPlan {
        let snapshot = await store.snapshot()

        guard snapshot.positions.isEmpty else {
            return PMWorkingPaperPortfolioExecutionPlan(
                sourceText: "",
                targetSymbols: [],
                entries: [],
                alreadyOpenSymbols: [],
                missingPriceSymbols: [],
                zeroQuantitySymbols: [],
                blockedReasons: [.currentHoldingsPresent],
                blockedDetails: [
                    "I did not submit the initial paper-portfolio establishment orders because the app already shows confirmed holdings. This narrow first-establishment path only runs while confirmed holdings are still empty."
                ]
            )
        }

        guard let sourceText = try await latestWorkingPaperPortfolioExecutionSourceText(for: request),
              sourceText.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty == false else {
            return PMWorkingPaperPortfolioExecutionPlan(
                sourceText: "",
                targetSymbols: [],
                entries: [],
                alreadyOpenSymbols: [],
                missingPriceSymbols: [],
                zeroQuantitySymbols: [],
                blockedReasons: [.workingPortfolioDefinitionMissing],
                blockedDetails: [
                    "I did not submit the paper-portfolio orders because the app does not currently have a machine-readable working paper-portfolio definition to execute."
                ]
            )
        }

        let targets = parseWorkingPaperPortfolioExecutionTargets(from: sourceText)
        guard targets.isEmpty == false else {
            return PMWorkingPaperPortfolioExecutionPlan(
                sourceText: sourceText,
                targetSymbols: [],
                entries: [],
                alreadyOpenSymbols: [],
                missingPriceSymbols: [],
                zeroQuantitySymbols: [],
                blockedReasons: [.workingPortfolioExecutionPlanMissing],
                blockedDetails: [
                    "I did not submit the paper-portfolio orders because the current working target is not in a machine-readable weighted format yet."
                ]
            )
        }
        let targetSymbols = orderedUniqueStrings(targets.map(\.symbol))

        guard let equity = await currentAccountEquity(),
              equity > .zero else {
            return PMWorkingPaperPortfolioExecutionPlan(
                sourceText: sourceText,
                targetSymbols: targetSymbols,
                entries: [],
                alreadyOpenSymbols: [],
                missingPriceSymbols: [],
                zeroQuantitySymbols: [],
                blockedReasons: [.accountEquityUnavailable],
                blockedDetails: [
                    "I did not submit the paper-portfolio orders because current account equity is unavailable, so I cannot size the target positions safely yet."
                ]
            )
        }

        let openOrderSymbols = Set(snapshot.openOrders.map { $0.symbol.uppercased() })
        var entries: [PMWorkingPaperPortfolioPlanEntry] = []
        var alreadyOpenSymbols: [String] = []
        var missingPriceSymbols: [String] = []
        var zeroQuantitySymbols: [String] = []
        var zeroQuantityDetails: [PMWorkingPaperPortfolioZeroQuantityDetail] = []
        var storePricesBySymbol: [String: Decimal] = [:]

        for target in targets where openOrderSymbols.contains(target.symbol) == false {
            storePricesBySymbol[target.symbol] = workingPaperPortfolioSizingPrice(
                symbol: target.symbol,
                snapshot: snapshot
            )
        }
        let symbolsNeedingRepair = targetSymbols.filter { symbol in
            openOrderSymbols.contains(symbol) == false && storePricesBySymbol[symbol] == nil
        }
        let repairResult = await repairWorkingPaperPortfolioSizingPrices(
            symbols: symbolsNeedingRepair,
            source: source
        )

        for target in targets {
            if openOrderSymbols.contains(target.symbol) {
                alreadyOpenSymbols.append(target.symbol)
                continue
            }
            guard let price = storePricesBySymbol[target.symbol] ?? repairResult.pricesBySymbol[target.symbol] else {
                missingPriceSymbols.append(target.symbol)
                continue
            }

            let targetNotional = (equity * target.weightPercent) / Decimal(100)
            let quantityDecimal = targetNotional / price
            let quantity = wholeShareQuantityFloor(from: quantityDecimal)
            guard quantity > 0 else {
                zeroQuantitySymbols.append(target.symbol)
                zeroQuantityDetails.append(
                    PMWorkingPaperPortfolioZeroQuantityDetail(
                        symbol: target.symbol,
                        equity: equity,
                        weightPercent: target.weightPercent,
                        targetNotional: targetNotional,
                        sizingPrice: price,
                        rawQuantity: quantityDecimal,
                        wholeShareQuantity: quantity
                    )
                )
                continue
            }

            entries.append(
                PMWorkingPaperPortfolioPlanEntry(
                    symbol: target.symbol,
                    side: target.side,
                    weightPercent: target.weightPercent,
                    targetNotional: targetNotional,
                    sizingPrice: price,
                    quantity: quantity
                )
            )
        }

        var blockedReasons: [PMExecutionRoutingBlockReason] = []
        var blockedDetails: [String] = []
        if missingPriceSymbols.isEmpty == false {
            blockedReasons.append(.marketPriceUnavailable)
            blockedDetails.append(
                "I do not currently have usable prices to size these symbols: \(missingPriceSymbols.sorted().joined(separator: ", "))."
            )
            if let repairDetail = repairResult.detail,
               repairResult.missingSymbols.isEmpty == false {
                blockedDetails.append(repairDetail)
            }
        }
        if zeroQuantitySymbols.isEmpty == false {
            blockedReasons.append(.workingPortfolioExecutionPlanMissing)
            blockedDetails.append(
                "The current equity and target weights would round below one share for these symbols: \(zeroQuantitySymbols.sorted().joined(separator: ", "))."
            )
            let detail = paperPortfolioZeroQuantityDetailText(zeroQuantityDetails)
            if detail.isEmpty == false {
                blockedDetails.append(detail)
            }
        }

        return PMWorkingPaperPortfolioExecutionPlan(
            sourceText: sourceText,
            targetSymbols: targetSymbols,
            entries: entries,
            alreadyOpenSymbols: orderedUniqueStrings(alreadyOpenSymbols),
            missingPriceSymbols: orderedUniqueStrings(missingPriceSymbols),
            zeroQuantitySymbols: orderedUniqueStrings(zeroQuantitySymbols),
            blockedReasons: blockedReasons,
            blockedDetails: blockedDetails
        )
    }

    private func paperPortfolioExecutionPriceRecoverySource(
        approvalRequestId: String
    ) -> String {
        "pm.paper_portfolio_price_recovery.\(approvalRequestId.lowercased())"
    }

    private func approvedPendingPaperPortfolioExecutionState(
        for request: PMApprovalRequest
    ) -> PMPaperPortfolioExecutionPendingState? {
        guard request.status == .resolved,
              request.ownerResponse == .approved,
              let pendingState = request.paperPortfolioExecutionPendingState,
              pendingState.status == .waitingForUsablePrices else {
            return nil
        }
        return pendingState
    }

    private func requestWorkingPaperPortfolioPriceRecoverySubscriptions(
        approvalRequestId: String,
        symbols: [String],
        source: AuditEventSource
    ) async {
        let normalizedSymbols = Array(MarketDataSubscriptionSet.normalized(symbols)).sorted()
        guard normalizedSymbols.isEmpty == false else {
            return
        }

        let subscriptionSource = paperPortfolioExecutionPriceRecoverySource(
            approvalRequestId: approvalRequestId
        )
        await subscribeQuotes(symbols: normalizedSymbols, source: subscriptionSource)
        await subscribeTrades(symbols: normalizedSymbols, source: subscriptionSource)
        await subscribeBars(symbols: normalizedSymbols, source: subscriptionSource)
        await store.publishDiagnostic(
            "pm paper-portfolio price recovery subscribed approval_request=\(shortOrderID(approvalRequestId)) symbols=\(normalizedSymbols.joined(separator: ","))",
            source: source,
            action: "pm_paper_portfolio_price_recovery_subscribe"
        )
    }

    private func persistApprovedWorkingPaperPortfolioExecutionPendingState(
        request: PMApprovalRequest,
        missingPriceSymbols: [String],
        summary: String,
        detail: String,
        source: AuditEventSource,
        retryAttemptedAt: Date? = nil
    ) async throws -> PMApprovalRequest {
        let normalizedSymbols = Array(MarketDataSubscriptionSet.normalized(missingPriceSymbols)).sorted()
        guard normalizedSymbols.isEmpty == false else {
            return try await clearApprovedWorkingPaperPortfolioExecutionPendingState(
                request: request,
                source: source
            )
        }

        let requestedAt = nowDate()
        await requestWorkingPaperPortfolioPriceRecoverySubscriptions(
            approvalRequestId: request.approvalRequestId,
            symbols: normalizedSymbols,
            source: source
        )

        var updated = request
        updated.paperPortfolioExecutionPendingState = PMPaperPortfolioExecutionPendingState(
            status: .waitingForUsablePrices,
            missingPriceSymbols: normalizedSymbols,
            marketDataSubscriptionSymbols: normalizedSymbols,
            automaticRetryEnabled: true,
            lastBlockerSummary: summary,
            lastBlockerDetail: detail,
            lastMarketDataSubscriptionRequestedAt: requestedAt,
            lastRetryAttemptedAt: retryAttemptedAt
                ?? request.paperPortfolioExecutionPendingState?.lastRetryAttemptedAt,
            updatedAt: requestedAt
        )
        updated.updatedAt = requestedAt
        let stored = try await upsertPMApprovalRequest(updated, source: source)
        await store.publishDiagnostic(
            "pm paper-portfolio execution pending approval_request=\(shortOrderID(stored.approvalRequestId)) missing_prices=\(normalizedSymbols.joined(separator: ",")) retry_armed=true",
            source: source,
            action: "pm_paper_portfolio_execution_pending"
        )
        return stored
    }

    private func clearApprovedWorkingPaperPortfolioExecutionPendingState(
        request: PMApprovalRequest,
        source: AuditEventSource
    ) async throws -> PMApprovalRequest {
        await marketDataStream.clearSource(
            paperPortfolioExecutionPriceRecoverySource(
                approvalRequestId: request.approvalRequestId
            )
        )
        guard request.paperPortfolioExecutionPendingState != nil else {
            return request
        }

        var updated = request
        updated.paperPortfolioExecutionPendingState = nil
        updated.updatedAt = nowDate()
        let stored = try await upsertPMApprovalRequest(updated, source: source)
        await store.publishDiagnostic(
            "pm paper-portfolio execution pending cleared approval_request=\(shortOrderID(stored.approvalRequestId))",
            source: source,
            action: "pm_paper_portfolio_execution_pending_cleared"
        )
        return stored
    }

    private func persistWorkingPaperPortfolioExecutionLifecycleState(
        request: PMApprovalRequest,
        status: PMPaperPortfolioExecutionLifecycleStatus,
        orderPlanStatus: PMPaperPortfolioExecutionOrderPlanStatus,
        summary: String,
        detail: String,
        targetSymbols: [String] = [],
        missingPriceSymbols: [String] = [],
        blockedReasons: [PMExecutionRoutingBlockReason] = [],
        source: AuditEventSource,
        lastRouteActionAt: Date? = nil,
        lastRetryAttemptedAt: Date? = nil,
        orderAttemptCount: Int = 0,
        acceptedOrderAttemptCount: Int = 0,
        failedOrderAttemptCount: Int = 0
    ) async throws -> PMApprovalRequest {
        let now = nowDate()
        var updated = request
        updated.paperPortfolioExecutionLifecycleState = PMPaperPortfolioExecutionLifecycleState(
            status: status,
            orderPlanStatus: orderPlanStatus,
            summary: summary,
            detail: detail,
            targetSymbols: Array(MarketDataSubscriptionSet.normalized(targetSymbols)).sorted(),
            missingPriceSymbols: Array(MarketDataSubscriptionSet.normalized(missingPriceSymbols)).sorted(),
            blockedReasons: orderedUniqueBlockReasons(blockedReasons),
            lastRouteActionAt: lastRouteActionAt ?? request.paperPortfolioExecutionLifecycleState?.lastRouteActionAt,
            lastRetryAttemptedAt: lastRetryAttemptedAt ?? request.paperPortfolioExecutionLifecycleState?.lastRetryAttemptedAt,
            orderAttemptCount: max(0, orderAttemptCount),
            acceptedOrderAttemptCount: max(0, acceptedOrderAttemptCount),
            failedOrderAttemptCount: max(0, failedOrderAttemptCount),
            updatedAt: now
        )
        updated.updatedAt = now
        let stored = try await upsertPMApprovalRequest(updated, source: source)
        await store.publishDiagnostic(
            "pm paper-portfolio execution lifecycle approval_request=\(shortOrderID(stored.approvalRequestId)) status=\(status.rawValue) plan=\(orderPlanStatus.rawValue) attempts=\(orderAttemptCount) accepted=\(acceptedOrderAttemptCount) failed=\(failedOrderAttemptCount)",
            source: source,
            action: "pm_paper_portfolio_execution_lifecycle"
        )
        return stored
    }

    private func assessWorkingPaperPortfolioExecutionRouting(
        request: PMApprovalRequest
    ) async throws -> PMExecutionRoutingAssessment {
        guard configuration.environment == .paper else {
            return makePMExecutionRoutingAssessment(
                request: request,
                proposal: nil,
                status: .blockedEnvironmentMismatch,
                action: .none,
                summary: "The current working paper-portfolio establishment path only runs in Paper, but the app is not in Paper right now.",
                detail: "Switch the app back to Paper before asking me to submit the initial paper-portfolio establishment orders through the app-owned order path.",
                blockedReasons: [.environmentMismatch] + currentLiveReadinessBlockReasons()
            )
        }

        if let credentialBlocker = alpacaTradingCredentialRouteBlocker(for: .paper) {
            return makePMExecutionRoutingAssessment(
                request: request,
                proposal: nil,
                status: .blockedExecutionPrerequisites,
                action: .none,
                summary: credentialBlocker.summary,
                detail: credentialBlocker.detail,
                blockedReasons: credentialBlocker.blockedReasons
            )
        }

        let plan = try await buildWorkingPaperPortfolioExecutionPlan(for: request, source: .engine)
        if plan.entries.isEmpty, plan.alreadyOpenSymbols.isEmpty == false, plan.blockedReasons.isEmpty {
            return makePMExecutionRoutingAssessment(
                request: request,
                proposal: nil,
                status: .routedSuccessfully,
                action: .none,
                summary: "The app already has open paper-establishment orders recorded for the current target, so I would not submit duplicates.",
                detail: "Open order symbols already on record: \(plan.alreadyOpenSymbols.joined(separator: ", ")). Fills are still pending authoritative confirmation.",
                blockedReasons: []
            )
        }

        if plan.entries.isEmpty {
            return makePMExecutionRoutingAssessment(
                request: request,
                proposal: nil,
                status: .blockedExecutionPrerequisites,
                action: .none,
                summary: plan.blockedDetails.first
                    ?? "The app cannot build an executable paper-portfolio order plan yet.",
                detail: plan.blockedDetails.joined(separator: " "),
                blockedReasons: plan.blockedReasons
            )
        }

        let readyCount = plan.entries.count
        if plan.blockedDetails.isEmpty == false || plan.alreadyOpenSymbols.isEmpty == false {
            var details = plan.blockedDetails
            if plan.alreadyOpenSymbols.isEmpty == false {
                details.append(
                    "These symbols already have open orders on record and will be skipped to avoid duplicates: \(plan.alreadyOpenSymbols.joined(separator: ", "))."
                )
            }
            return makePMExecutionRoutingAssessment(
                request: request,
                proposal: nil,
                status: .executableNowPaper,
                action: .submitWorkingPortfolioEstablishmentOrders,
                summary: "The app can submit \(readyCount) paper-portfolio establishment order\(readyCount == 1 ? "" : "s") now, while other legs still need attention.",
                detail: details.joined(separator: " "),
                blockedReasons: plan.blockedReasons
            )
        }

        return makePMExecutionRoutingAssessment(
            request: request,
            proposal: nil,
            status: .executableNowPaper,
            action: .submitWorkingPortfolioEstablishmentOrders,
            summary: "The current working paper portfolio is ready to submit through the app-owned paper order path.",
            detail: "I have a machine-readable weighted target, usable pricing, and account equity to size the initial paper-portfolio establishment orders now.",
            blockedReasons: []
        )
    }

    private func assessLiveOrderReviewExecutionRouting(
        request: PMApprovalRequest
    ) async throws -> PMExecutionRoutingAssessment {
        guard configuration.environment == .live else {
            return makePMExecutionRoutingAssessment(
                request: request,
                proposal: nil,
                status: .blockedEnvironmentMismatch,
                action: .none,
                summary: "The approved Live order review is blocked because the app is not currently set to Live.",
                detail: "Switch the app to Live and arm it before routing this already-approved Live order review. No order has been sent.",
                blockedReasons: [.environmentMismatch]
            )
        }

        let liveReadinessReasons = currentLiveReadinessBlockReasons()
        if liveReadinessReasons.contains(.killSwitchEnabled) {
            return makePMExecutionRoutingAssessment(
                request: request,
                proposal: nil,
                status: .blockedKillSwitch,
                action: .none,
                summary: "The approved Live order review is blocked by the kill switch.",
                detail: "Turn off the kill switch before any Live NEW/REPLACE order can enter the Engine order path. No order has been sent.",
                blockedReasons: liveReadinessReasons
            )
        }
        if liveReadinessReasons.contains(.liveNotArmed) {
            return makePMExecutionRoutingAssessment(
                request: request,
                proposal: nil,
                status: .blockedLiveNotArmed,
                action: .none,
                summary: "The approved Live order review is blocked because Live is disarmed.",
                detail: "Arm Live before routing this already-approved Live order review. No order has been sent.",
                blockedReasons: liveReadinessReasons
            )
        }

        guard let payload = request.liveOrderReview else {
            return makePMExecutionRoutingAssessment(
                request: request,
                proposal: nil,
                status: .blockedExecutionPrerequisites,
                action: .none,
                summary: "The approved Live order review is missing the structured order payload needed for routing.",
                detail: "The app needs machine-readable symbol, side, order type, time-in-force, and quantity or notional before it can enter the governed order path. No order has been sent.",
                blockedReasons: [.liveOrderReviewPayloadMissing]
            )
        }

        guard payload.environment == .live else {
            return makePMExecutionRoutingAssessment(
                request: request,
                proposal: nil,
                status: .blockedEnvironmentMismatch,
                action: .none,
                summary: "The approved order-review payload is not marked for Live execution.",
                detail: "Create a new Live order review with an explicit Live environment before routing. No order has been sent.",
                blockedReasons: [.environmentMismatch]
            )
        }

        let sizing = await resolveLiveOrderReviewSizing(
            payload: payload,
            approvalRequestId: request.approvalRequestId,
            source: .engine,
            requestSubscriptionsOnBlock: true
        )

        guard case .resolved(let resolvedSizing) = sizing else {
            let blocker = sizing.blocker
            return makePMExecutionRoutingAssessment(
                request: request,
                proposal: nil,
                status: .blockedExecutionPrerequisites,
                action: .submitLiveOrderReview,
                summary: blocker.summary,
                detail: blocker.detail,
                blockedReasons: blocker.blockedReasons
            )
        }

        return makePMExecutionRoutingAssessment(
            request: request,
            proposal: nil,
            status: .executableNowLive,
            action: .submitLiveOrderReview,
            summary: "The approved Live order review is ready to enter the governed Engine order path.",
            detail: "Routing now will submit \(resolvedSizing.quantity) \(payload.symbol.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()) share\(resolvedSizing.quantity == 1 ? "" : "s") through Engine. \(resolvedSizing.detail) If Live execution local-auth protection is enabled, Touch ID or the Mac password is required immediately before REST submission.",
            blockedReasons: []
        )
    }

    private struct PMLiveOrderReviewResolvedSizing: Sendable, Equatable {
        let quantity: Int
        let detail: String
    }

    private struct PMLiveOrderReviewSizingBlocker: Sendable, Equatable {
        let summary: String
        let detail: String
        let blockedReasons: [PMExecutionRoutingBlockReason]
    }

    private enum PMLiveOrderReviewSizingResolution: Sendable, Equatable {
        case resolved(PMLiveOrderReviewResolvedSizing)
        case blocked(PMLiveOrderReviewSizingBlocker)

        var blocker: PMLiveOrderReviewSizingBlocker {
            switch self {
            case .resolved:
                return PMLiveOrderReviewSizingBlocker(
                    summary: "The approved Live order review sizing resolved successfully.",
                    detail: "No sizing blocker is active.",
                    blockedReasons: []
                )
            case .blocked(let blocker):
                return blocker
            }
        }
    }

    private func liveOrderReviewSizingPriceRecoverySource(
        approvalRequestId: String
    ) -> String {
        "pm.live_order_review_price_recovery.\(approvalRequestId.lowercased())"
    }

    private func requestLiveOrderReviewSizingPriceSubscriptions(
        approvalRequestId: String,
        symbol: String,
        source: AuditEventSource
    ) async {
        let normalizedSymbols = Array(MarketDataSubscriptionSet.normalized([symbol])).sorted()
        guard normalizedSymbols.isEmpty == false else {
            return
        }

        let subscriptionSource = liveOrderReviewSizingPriceRecoverySource(
            approvalRequestId: approvalRequestId
        )
        await subscribeQuotes(symbols: normalizedSymbols, source: subscriptionSource)
        await subscribeTrades(symbols: normalizedSymbols, source: subscriptionSource)
        await subscribeBars(symbols: normalizedSymbols, source: subscriptionSource)
        await store.publishDiagnostic(
            "pm live-order review price recovery subscribed approval_request=\(shortOrderID(approvalRequestId)) symbols=\(normalizedSymbols.joined(separator: ","))",
            source: source,
            action: "pm_live_order_review_price_recovery_subscribe"
        )
    }

    private func resolveLiveOrderReviewSizing(
        payload: PMLiveOrderReviewPayload,
        approvalRequestId: String,
        source: AuditEventSource,
        requestSubscriptionsOnBlock: Bool
    ) async -> PMLiveOrderReviewSizingResolution {
        let normalizedSymbol = payload.symbol
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .uppercased()
        guard normalizedSymbol.isEmpty == false else {
            return .blocked(PMLiveOrderReviewSizingBlocker(
                summary: "The approved Live order review is missing a usable symbol.",
                detail: "Create a new Live order review with a machine-readable symbol before routing. No order has been sent.",
                blockedReasons: [.liveOrderReviewPayloadMissing]
            ))
        }

        if let quantity = payload.quantity {
            guard quantity > 0 else {
                return .blocked(PMLiveOrderReviewSizingBlocker(
                    summary: "The approved Live order review has an invalid share quantity.",
                    detail: "The app-owned route requires a positive whole-share quantity before it can enter Engine. No order has been sent.",
                    blockedReasons: [.liveOrderReviewPayloadMissing]
                ))
            }
            return .resolved(PMLiveOrderReviewResolvedSizing(
                quantity: quantity,
                detail: "The review already contains a concrete whole-share quantity."
            ))
        }

        guard let notionalAmount = payload.notionalAmount,
              notionalAmount > .zero else {
            return .blocked(PMLiveOrderReviewSizingBlocker(
                summary: "The approved Live order review is missing quantity or notional sizing.",
                detail: "The app-owned route needs either a positive whole-share quantity or a positive notional amount that can be converted to whole shares from a usable price. No order has been sent.",
                blockedReasons: [.liveOrderReviewPayloadMissing]
            ))
        }

        let price: Decimal
        let priceSourceSummary: String
        let observedAt: Date?
        switch payload.orderType {
        case .market:
            let snapshot = await store.snapshot()
            guard let resolvedLiveValue = resolvePortfolioWatchLiveValue(
                from: snapshot.quotesBySymbol[normalizedSymbol]
            ),
                  let resolvedPrice = positiveDecimal(from: resolvedLiveValue.price)
            else {
                if requestSubscriptionsOnBlock {
                    await requestLiveOrderReviewSizingPriceSubscriptions(
                        approvalRequestId: approvalRequestId,
                        symbol: normalizedSymbol,
                        source: source
                    )
                }
                return .blocked(PMLiveOrderReviewSizingBlocker(
                    summary: "The approved Live order review is waiting for a usable \(normalizedSymbol) price before it can size whole shares.",
                    detail: "The owner supplied \(paperPortfolioDecimalText(notionalAmount, scale: 2)) notional and asked for nearest-share sizing, but Store has no usable \(normalizedSymbol) live price yet. The app requested quote/trade/bar updates for \(normalizedSymbol). No order has been sent.",
                    blockedReasons: [.marketPriceUnavailable]
                ))
            }
            guard let liveObservedAt = resolvedLiveValue.observedAt else {
                if requestSubscriptionsOnBlock {
                    await requestLiveOrderReviewSizingPriceSubscriptions(
                        approvalRequestId: approvalRequestId,
                        symbol: normalizedSymbol,
                        source: source
                    )
                }
                return .blocked(PMLiveOrderReviewSizingBlocker(
                    summary: "The approved Live order review has a \(normalizedSymbol) price without a usable timestamp.",
                    detail: "Nearest-share sizing for a Live market order requires a timestamped Store price. The app requested fresh quote/trade/bar updates for \(normalizedSymbol). No order has been sent.",
                    blockedReasons: [.marketPriceUnavailable]
                ))
            }
            let maximumAge: TimeInterval = 15 * 60
            let age = nowDate().timeIntervalSince(liveObservedAt)
            guard age >= 0, age <= maximumAge else {
                if requestSubscriptionsOnBlock {
                    await requestLiveOrderReviewSizingPriceSubscriptions(
                        approvalRequestId: approvalRequestId,
                        symbol: normalizedSymbol,
                        source: source
                    )
                }
                return .blocked(PMLiveOrderReviewSizingBlocker(
                    summary: "The approved Live order review is waiting for a fresher \(normalizedSymbol) price before it can size whole shares.",
                    detail: "The latest \(resolvedLiveValue.source.displayTitle.lowercased()) price for \(normalizedSymbol) is from \(DateCodec.formatISO8601(liveObservedAt)), which is outside the 15-minute sizing window for this Live market order. The app requested fresh quote/trade/bar updates. No order has been sent.",
                    blockedReasons: [.marketPriceUnavailable]
                ))
            }
            price = resolvedPrice
            priceSourceSummary = resolvedLiveValue.source.displayTitle
            observedAt = liveObservedAt
        case .limit:
            guard let limitPrice = payload.limitPrice,
                  limitPrice > .zero else {
                return .blocked(PMLiveOrderReviewSizingBlocker(
                    summary: "The approved Live limit-order review is missing a usable limit price for notional sizing.",
                    detail: "A notional limit-order review can only be converted to whole shares when the review includes a positive limit price. No order has been sent.",
                    blockedReasons: [.liveOrderReviewPayloadMissing]
                ))
            }
            price = limitPrice
            priceSourceSummary = "Limit Price"
            observedAt = nil
        default:
            return .blocked(PMLiveOrderReviewSizingBlocker(
                summary: "The approved Live order review uses an unsupported order type for notional sizing.",
                detail: "The app-owned direct Live order review route can convert notional market orders using live Store pricing, or limit orders using the explicit limit price. No order has been sent.",
                blockedReasons: [.liveOrderReviewSizingUnsupported]
            ))
        }

        let rawQuantity = notionalAmount / price
        let quantity = wholeShareQuantityNearest(from: rawQuantity)
        guard quantity > 0 else {
            return .blocked(PMLiveOrderReviewSizingBlocker(
                summary: "The approved Live order review rounds below one whole share.",
                detail: "Target notional \(paperPortfolioDecimalText(notionalAmount, scale: 2)) at sizing price \(paperPortfolioDecimalText(price, scale: 4)) produces raw quantity \(paperPortfolioDecimalText(rawQuantity, scale: 6)), which cannot route as a positive whole-share order. No order has been sent.",
                blockedReasons: [.liveOrderReviewSizingUnsupported]
            ))
        }

        let expectedNotional = Decimal(quantity) * price
        let deviation = expectedNotional - notionalAmount
        var detailParts = [
            "Sizing converted target notional \(paperPortfolioDecimalText(notionalAmount, scale: 2)) using \(priceSourceSummary.lowercased()) price \(paperPortfolioDecimalText(price, scale: 4)) into raw quantity \(paperPortfolioDecimalText(rawQuantity, scale: 6)) and nearest whole-share quantity \(quantity).",
            "Expected notional is \(paperPortfolioDecimalText(expectedNotional, scale: 2)); deviation from target is \(paperPortfolioDecimalText(deviation, scale: 2))."
        ]
        if let observedAt {
            detailParts.append("Sizing price observed at \(DateCodec.formatISO8601(observedAt)).")
        }
        return .resolved(PMLiveOrderReviewResolvedSizing(
            quantity: quantity,
            detail: detailParts.joined(separator: " ")
        ))
    }

    private func routeLiveOrderReviewExecution(
        request: PMApprovalRequest,
        source: AuditEventSource
    ) async throws -> PMExecutionRoutingAssessment {
        let assessment = try await assessLiveOrderReviewExecutionRouting(request: request)
        guard assessment.action == .submitLiveOrderReview,
              assessment.status == .executableNowLive,
              let payload = request.liveOrderReview else {
            return assessment
        }
        let sizing = await resolveLiveOrderReviewSizing(
            payload: payload,
            approvalRequestId: request.approvalRequestId,
            source: source,
            requestSubscriptionsOnBlock: true
        )
        guard case .resolved(let resolvedSizing) = sizing else {
            let blocker = sizing.blocker
            return makePMExecutionRoutingAssessment(
                request: request,
                proposal: nil,
                status: .blockedExecutionPrerequisites,
                action: .submitLiveOrderReview,
                summary: blocker.summary,
                detail: blocker.detail,
                blockedReasons: blocker.blockedReasons
            )
        }

        await store.publishDiagnostic(
            "pm live-order review route start approval_request=\(shortOrderID(request.approvalRequestId)) symbol=\(payload.symbol.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()) qty=\(resolvedSizing.quantity)",
            source: source,
            action: "pm_live_order_review_route_start"
        )

        let result = await submitOrderIntent(
            .place(
                PlaceOrderIntent(
                    instrumentType: .equity,
                    symbol: payload.symbol,
                    qty: resolvedSizing.quantity,
                    side: payload.side,
                    type: payload.orderType,
                    limitPrice: payload.limitPrice,
                    timeInForce: payload.timeInForce
                )
            ),
            source: "ui.pm_live_order_review.\(request.approvalRequestId)"
        )

        if result.accepted {
            _ = try? await persistLiveOrderReviewExecutionLifecycleState(
                request: request,
                state: makeLiveOrderReviewSubmittedLifecycleState(
                    payload: payload,
                    quantity: resolvedSizing.quantity,
                    orderId: result.orderID,
                    sourceDetail: resolvedSizing.detail
                ),
                source: source
            )
            return makePMExecutionRoutingAssessment(
                request: request,
                proposal: nil,
                status: .routedSuccessfully,
                action: .submitLiveOrderReview,
                summary: "The approved Live order review was routed through the Engine order path.",
                detail: "\(resolvedSizing.detail) Engine accepted the Live order submission attempt. Check Orders Blotter and broker trade updates for authoritative order lifecycle. LocalAuthentication remained at the final Engine boundary when enabled.",
                blockedReasons: []
            )
        }

        let blockedReasons = liveOrderReviewRouteBlockReasons(errorCode: result.errorCode)
        let status = liveOrderReviewRouteStatus(errorCode: result.errorCode)
        let blockedAssessment = makePMExecutionRoutingAssessment(
            request: request,
            proposal: nil,
            status: status,
            action: .submitLiveOrderReview,
            summary: liveOrderReviewRouteBlockedSummary(errorCode: result.errorCode),
            detail: result.message,
            blockedReasons: blockedReasons
        )
        _ = try? await persistLiveOrderReviewExecutionLifecycleState(
            request: request,
            state: makeLiveOrderReviewBlockedLifecycleState(
                payload: payload,
                quantity: resolvedSizing.quantity,
                summary: blockedAssessment.summary,
                detail: blockedAssessment.detail
            ),
            source: source
        )
        await recordLiveOrderReviewCompletionFollowThroughIfNeeded(
            approvalRequestId: request.approvalRequestId,
            source: source
        )
        return blockedAssessment
    }

    private func makeLiveOrderReviewSubmittedLifecycleState(
        payload: PMLiveOrderReviewPayload,
        quantity: Int,
        orderId: String?,
        sourceDetail: String
    ) -> PMLiveOrderReviewExecutionLifecycleState {
        PMLiveOrderReviewExecutionLifecycleState(
            status: .submitted,
            summary: "The approved Live order review was submitted through the Engine order path.",
            detail: "\(sourceDetail) Engine accepted the submission attempt. Orders Blotter and broker trade updates remain authoritative for fill status.",
            orderId: orderId,
            symbol: payload.symbol,
            side: payload.side,
            orderType: payload.orderType,
            timeInForce: payload.timeInForce,
            quantity: quantity,
            openOrderStatus: "submitted",
            updatedAt: nowDate()
        )
    }

    private func makeLiveOrderReviewBlockedLifecycleState(
        payload: PMLiveOrderReviewPayload,
        quantity: Int?,
        summary: String,
        detail: String
    ) -> PMLiveOrderReviewExecutionLifecycleState {
        PMLiveOrderReviewExecutionLifecycleState(
            status: .blocked,
            summary: summary,
            detail: detail,
            symbol: payload.symbol,
            side: payload.side,
            orderType: payload.orderType,
            timeInForce: payload.timeInForce,
            quantity: quantity,
            openOrderStatus: "not_submitted",
            updatedAt: nowDate()
        )
    }

    @discardableResult
    private func persistLiveOrderReviewExecutionLifecycleState(
        request: PMApprovalRequest,
        state: PMLiveOrderReviewExecutionLifecycleState,
        source: AuditEventSource
    ) async throws -> PMApprovalRequest {
        var refreshed = (try? await getPMApprovalRequest(id: request.approvalRequestId)) ?? request
        refreshed.liveOrderExecutionLifecycleState = state
        refreshed.updatedAt = nowDate()
        let stored = try await upsertPMApprovalRequest(refreshed, source: source)
        await store.publishDiagnostic(
            "pm live-order review lifecycle approval_request=\(shortOrderID(stored.approvalRequestId)) status=\(state.status.rawValue) order_id=\(state.orderId.map(shortOrderID) ?? "-") symbol=\(state.symbol)",
            source: source,
            action: "pm_live_order_review_lifecycle"
        )
        return stored
    }

    private func liveOrderReviewRouteStatus(errorCode: String?) -> PMExecutionRoutingStatus {
        switch errorCode {
        case .some(ManualOrderValidationError.liveTradingNotArmed.errorCode):
            return .blockedLiveNotArmed
        case .some(ManualOrderValidationError.tradingDisabledByKillSwitch.errorCode):
            return .blockedKillSwitch
        case .some(ManualOrderValidationError.localUserPresenceCanceled.errorCode),
            .some(ManualOrderValidationError.localUserPresenceFailed.errorCode),
            .some(ManualOrderValidationError.localUserPresenceUnavailable.errorCode),
            .some(ManualOrderValidationError.localUserPresenceSystemError.errorCode),
            .some(ManualOrderValidationError.staleArmingSession.errorCode),
            .some(ManualOrderValidationError.emptySymbol.errorCode),
            .some(ManualOrderValidationError.invalidQuantity.errorCode),
            .some(ManualOrderValidationError.unsupportedOrderType.errorCode),
            .some(ManualOrderValidationError.limitPriceRequired.errorCode),
            .some(ManualOrderValidationError.invalidLimitPrice.errorCode):
            return .blockedExecutionPrerequisites
        default:
            return .launchFailed
        }
    }

    private func liveOrderReviewRouteBlockReasons(errorCode: String?) -> [PMExecutionRoutingBlockReason] {
        switch errorCode {
        case .some(ManualOrderValidationError.liveTradingNotArmed.errorCode):
            return [.liveNotArmed]
        case .some(ManualOrderValidationError.staleArmingSession.errorCode):
            return [.liveNotArmed]
        case .some(ManualOrderValidationError.tradingDisabledByKillSwitch.errorCode):
            return [.killSwitchEnabled]
        case .some(ManualOrderValidationError.localUserPresenceCanceled.errorCode),
            .some(ManualOrderValidationError.localUserPresenceFailed.errorCode),
            .some(ManualOrderValidationError.localUserPresenceUnavailable.errorCode),
            .some(ManualOrderValidationError.localUserPresenceSystemError.errorCode):
            return [.localAuthenticationBlocked]
        case .some(ManualOrderValidationError.emptySymbol.errorCode),
            .some(ManualOrderValidationError.invalidQuantity.errorCode),
            .some(ManualOrderValidationError.unsupportedOrderType.errorCode),
            .some(ManualOrderValidationError.limitPriceRequired.errorCode),
            .some(ManualOrderValidationError.invalidLimitPrice.errorCode):
            return [.liveOrderReviewPayloadMissing]
        default:
            return [.orderSubmissionFailed]
        }
    }

    private func liveOrderReviewRouteBlockedSummary(errorCode: String?) -> String {
        switch errorCode {
        case .some(ManualOrderValidationError.localUserPresenceCanceled.errorCode):
            return "The approved Live order review was blocked because local authentication was canceled."
        case .some(ManualOrderValidationError.localUserPresenceFailed.errorCode),
            .some(ManualOrderValidationError.localUserPresenceUnavailable.errorCode),
            .some(ManualOrderValidationError.localUserPresenceSystemError.errorCode):
            return "The approved Live order review was blocked by local authentication."
        case .some(ManualOrderValidationError.liveTradingNotArmed.errorCode):
            return "The approved Live order review was blocked because Live is disarmed."
        case .some(ManualOrderValidationError.staleArmingSession.errorCode):
            return "The approved Live order review was blocked because the Live arming session is stale."
        case .some(ManualOrderValidationError.tradingDisabledByKillSwitch.errorCode):
            return "The approved Live order review was blocked by the kill switch."
        default:
            return "The approved Live order review could not be submitted through the Engine order path."
        }
    }

    private func liveOrderReviewExecutionStatus(
        from update: TradeUpdateEvent
    ) -> PMLiveOrderReviewExecutionLifecycleStatus {
        let event = update.event.lowercased()
        let orderStatus = update.orderStatus?.lowercased()
        if event == "fill" || orderStatus == "filled" {
            return .filled
        }
        if event == "partial_fill"
            || event == "partial-fill"
            || orderStatus == "partially_filled"
            || orderStatus == "partially-filled" {
            return .partiallyFilled
        }
        if event == "canceled" || event == "cancelled" || orderStatus == "canceled" || orderStatus == "cancelled" {
            return .canceled
        }
        if event == "rejected" || orderStatus == "rejected" {
            return .rejected
        }
        if event == "expired" || orderStatus == "expired" {
            return .expired
        }
        return .submitted
    }

    private func liveOrderReviewExecutionSummary(
        status: PMLiveOrderReviewExecutionLifecycleStatus,
        symbol: String,
        side: OrderSide
    ) -> String {
        switch status {
        case .submitted:
            return "The Live \(symbol) \(side.rawValue) order is submitted and still awaiting terminal broker status."
        case .partiallyFilled:
            return "The Live \(symbol) \(side.rawValue) order is partially filled and may still have open quantity."
        case .filled:
            return "The Live \(symbol) \(side.rawValue) completed."
        case .canceled:
            return "The Live \(symbol) \(side.rawValue) order was canceled before full completion."
        case .rejected:
            return "The Live \(symbol) \(side.rawValue) order was rejected."
        case .expired:
            return "The Live \(symbol) \(side.rawValue) order expired."
        case .blocked:
            return "The Live \(symbol) \(side.rawValue) order did not submit."
        }
    }

    private func liveOrderReviewExecutionDetail(
        status: PMLiveOrderReviewExecutionLifecycleStatus,
        payload: PMLiveOrderReviewPayload,
        quantity: Int?,
        filledQuantity: String?,
        averageFillPrice: String?,
        positionQuantity: String?,
        openOrderStatus: String?
    ) -> String {
        let symbol = payload.symbol.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        let quantityText = quantity.map { "\($0)" } ?? "?"
        var parts: [String] = [
            "The app handled \(quantityText) \(symbol) share\(quantity == 1 ? "" : "s") as a \(payload.orderType.rawValue)/\(payload.timeInForce.rawValue) order after owner approval and the governed Live route."
        ]
        if let filledQuantity {
            parts.append("Filled quantity: \(filledQuantity).")
        }
        if let averageFillPrice {
            parts.append("Average fill price: \(averageFillPrice).")
        }
        if let positionQuantity {
            parts.append("Current recorded \(symbol) position quantity: \(positionQuantity).")
        }
        if let openOrderStatus {
            parts.append("Latest order status: \(openOrderStatus).")
        }
        if status.isTerminal {
            parts.append("No further owner action is required on this review unless the owner wants follow-up.")
        } else {
            parts.append("Orders Blotter remains authoritative while the order is still open or changing.")
        }
        return parts.joined(separator: " ")
    }

    private func reconcileLiveOrderReviewExecutionLifecycleForTradeUpdate(
        _ update: TradeUpdateEvent,
        source: AuditEventSource
    ) async {
        do {
            let requests = try await listPMApprovalRequests()
                .filter { request in
                    request.requestType == .liveOrderReview
                        && request.ownerResponse == .approved
                        && request.liveOrderExecutionLifecycleState?.orderId == update.orderID
                }
            guard requests.isEmpty == false else {
                return
            }

            let snapshot = await store.snapshot()
            for request in requests {
                guard let payload = request.liveOrderReview,
                      let previousState = request.liveOrderExecutionLifecycleState else {
                    continue
                }
                let symbol = payload.symbol.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
                let status = liveOrderReviewExecutionStatus(from: update)
                let orderStatus = snapshot.ordersByID[update.orderID]?.status
                    ?? update.orderStatus
                    ?? update.event
                let positionQuantity = snapshot.positions
                    .first { $0.symbol.uppercased() == symbol }?
                    .qty
                let quantity = previousState.quantity
                    ?? update.qty.flatMap { Int($0) }
                    ?? payload.quantity
                let state = PMLiveOrderReviewExecutionLifecycleState(
                    status: status,
                    summary: liveOrderReviewExecutionSummary(
                        status: status,
                        symbol: symbol,
                        side: payload.side
                    ),
                    detail: liveOrderReviewExecutionDetail(
                        status: status,
                        payload: payload,
                        quantity: quantity,
                        filledQuantity: update.filledQty ?? previousState.filledQuantity,
                        averageFillPrice: update.filledAvgPrice ?? previousState.averageFillPrice,
                        positionQuantity: positionQuantity ?? previousState.positionQuantity,
                        openOrderStatus: orderStatus
                    ),
                    orderId: update.orderID,
                    symbol: symbol,
                    side: payload.side,
                    orderType: payload.orderType,
                    timeInForce: payload.timeInForce,
                    quantity: quantity,
                    filledQuantity: update.filledQty ?? previousState.filledQuantity,
                    averageFillPrice: update.filledAvgPrice ?? previousState.averageFillPrice,
                    positionQuantity: positionQuantity ?? previousState.positionQuantity,
                    openOrderStatus: orderStatus,
                    completionFollowThroughMessageId: previousState.completionFollowThroughMessageId,
                    completionFollowThroughDeliveredAt: previousState.completionFollowThroughDeliveredAt,
                    updatedAt: nowDate()
                )
                _ = try await persistLiveOrderReviewExecutionLifecycleState(
                    request: request,
                    state: state,
                    source: source
                )
                if status.isTerminal {
                    await recordLiveOrderReviewCompletionFollowThroughIfNeeded(
                        approvalRequestId: request.approvalRequestId,
                        source: source
                    )
                }
            }
        } catch {
            await store.publishDiagnostic(
                "pm live-order review lifecycle reconciliation failed reason=\(error.localizedDescription)",
                source: source,
                action: "pm_live_order_review_lifecycle_reconcile_failed"
            )
        }
    }

    private func recordLiveOrderReviewCompletionFollowThroughIfNeeded(
        approvalRequestId: String,
        source: AuditEventSource
    ) async {
        do {
            var request = try await getPMApprovalRequest(id: approvalRequestId)
            guard var lifecycle = request.liveOrderExecutionLifecycleState,
                  lifecycle.status.isTerminal,
                  lifecycle.completionFollowThroughMessageId == nil,
                  let sourceMessageId = trimmedOptionalDecisionText(request.sourceCommunicationMessageId),
                  let sourceMessage = try await pmCommunicationMessageStore.get(id: sourceMessageId) else {
                return
            }

            let body = makeLiveOrderReviewCompletionFollowThroughBody(
                lifecycle: lifecycle
            )
            let message = try await createPMCommunicationMessage(
                sessionId: sourceMessage.sessionId,
                senderRole: .pm,
                senderId: request.pmId,
                body: body,
                replyToMessageId: nil,
                source: source
            )
            lifecycle.completionFollowThroughMessageId = message.messageId
            lifecycle.completionFollowThroughDeliveredAt = message.sentAt
            request.liveOrderExecutionLifecycleState = lifecycle
            request.updatedAt = nowDate()
            _ = try await upsertPMApprovalRequest(request, source: source)
            await store.publishDiagnostic(
                "pm live-order review completion follow-through approval_request=\(shortOrderID(approvalRequestId)) message=\(shortOrderID(message.messageId)) status=\(lifecycle.status.rawValue)",
                source: source,
                action: "pm_live_order_review_completion_follow_through"
            )
        } catch {
            await store.publishDiagnostic(
                "pm live-order review completion follow-through failed approval_request=\(shortOrderID(approvalRequestId)) reason=\(error.localizedDescription)",
                source: source,
                action: "pm_live_order_review_completion_follow_through_failed"
            )
        }
    }

    private func makeLiveOrderReviewCompletionFollowThroughBody(
        lifecycle: PMLiveOrderReviewExecutionLifecycleState
    ) -> String {
        let symbol = lifecycle.symbol.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
        let quantityText = lifecycle.quantity.map {
            "\($0) share\($0 == 1 ? "" : "s")"
        } ?? "the reviewed share quantity"
        let routeText = "The app handled \(quantityText) of \(symbol) as a \(lifecycle.orderType.rawValue)/\(lifecycle.timeInForce.rawValue) \(lifecycle.side.rawValue) order after your in-app approval and the governed Live route."

        switch lifecycle.status {
        case .filled:
            var parts = [
                "The Live \(symbol) \(lifecycle.side.rawValue) completed.",
                routeText
            ]
            if let filled = lifecycle.filledQuantity {
                parts.append("Filled quantity: \(filled).")
            }
            if let average = lifecycle.averageFillPrice {
                parts.append("Average fill price: \(average).")
            }
            if let position = lifecycle.positionQuantity {
                parts.append("The Live portfolio now records \(position) \(symbol) shares.")
            }
            parts.append("No further owner action is needed for this completed review; Orders Blotter remains the authoritative order history.")
            return parts.joined(separator: " ")
        case .canceled:
            return "The Live \(symbol) \(lifecycle.side.rawValue) review is closed because the order was canceled before completion. \(routeText) No completion fill was recorded, and Orders Blotter remains the authoritative order history."
        case .rejected:
            return "The Live \(symbol) \(lifecycle.side.rawValue) review is closed because the order was rejected. \(routeText) No completed position change should be inferred from this review; see Orders Blotter for broker status."
        case .expired:
            return "The Live \(symbol) \(lifecycle.side.rawValue) review is closed because the order expired. \(routeText) No completed fill was recorded."
        case .blocked:
            return "The Live \(symbol) \(lifecycle.side.rawValue) review did not submit: \(boundedConversationText(lifecycle.summary, limit: 220)) \(boundedConversationText(lifecycle.detail, limit: 360)) No order was placed from this review."
        case .submitted, .partiallyFilled:
            return "The Live \(symbol) \(lifecycle.side.rawValue) order is not terminal yet. \(routeText) Current status: \(lifecycle.summary)"
        }
    }

    @discardableResult
    public func acknowledgePMApprovalRequest(
        requestId: String,
        acknowledgedBy: String = "owner",
        source: AuditEventSource = .system
    ) async throws -> PMApprovalRequest {
        var request = try await getPMApprovalRequest(id: requestId)
        request.ownerAcknowledgedAt = nowDate()
        request.ownerAcknowledgedBy = acknowledgedBy
        request.updatedAt = nowDate()
        let stored = try await upsertPMApprovalRequest(request, source: source)
        await store.publishDiagnostic(
            "pm approval request acknowledged id=\(shortOrderID(stored.approvalRequestId))",
            source: source,
            action: "pm_approval_request_acknowledged"
        )
        return stored
    }

    private func routeWorkingPaperPortfolioExecution(
        request: PMApprovalRequest,
        source: AuditEventSource
    ) async throws -> PMExecutionRoutingAssessment {
        var request = request
        let routeAttemptedAt = nowDate()
        guard request.status == .resolved,
              request.ownerResponse == .approved else {
            return makePMExecutionRoutingAssessment(
                request: request,
                proposal: nil,
                status: .invalidState,
                action: .none,
                summary: "This PM ask still needs an approved owner response before the app can route the paper-establishment orders.",
                detail: "The working paper-portfolio establishment path only runs after app-owned PM approval is resolved as approved.",
                blockedReasons: [.ownerApprovalRequired]
            )
        }

        if let credentialBlocker = alpacaTradingCredentialRouteBlocker(for: .paper) {
            request = try await clearApprovedWorkingPaperPortfolioExecutionPendingState(
                request: request,
                source: source
            )
            request = try await persistWorkingPaperPortfolioExecutionLifecycleState(
                request: request,
                status: .blocked,
                orderPlanStatus: .blocked,
                summary: credentialBlocker.summary,
                detail: credentialBlocker.detail,
                targetSymbols: await workingPaperPortfolioTargetSymbols(for: request),
                blockedReasons: credentialBlocker.blockedReasons,
                source: source,
                lastRouteActionAt: routeAttemptedAt
            )
            await store.publishDiagnostic(
                "pm paper-portfolio execution blocked reason=alpaca_trading_credentials_unavailable env=paper public_key=\(credentialBlocker.readiness.publicKeyFound) secret_key=\(credentialBlocker.readiness.secretKeyFound)",
                source: source,
                level: .warning,
                action: "pm_paper_portfolio_execution_credentials_blocked",
                errorCode: PMExecutionRoutingBlockReason.alpacaTradingCredentialsUnavailable.rawValue
            )
            return makePMExecutionRoutingAssessment(
                request: request,
                proposal: nil,
                status: .blockedExecutionPrerequisites,
                action: .none,
                summary: credentialBlocker.summary,
                detail: credentialBlocker.detail,
                blockedReasons: credentialBlocker.blockedReasons
            )
        }

        let plan = try await buildWorkingPaperPortfolioExecutionPlan(for: request, source: source)

        if plan.entries.isEmpty, plan.alreadyOpenSymbols.isEmpty == false, plan.blockedReasons.isEmpty {
            request = try await clearApprovedWorkingPaperPortfolioExecutionPendingState(
                request: request,
                source: source
            )
            request = try await persistWorkingPaperPortfolioExecutionLifecycleState(
                request: request,
                status: .ordersAlreadyRecorded,
                orderPlanStatus: .skippedExistingOrders,
                summary: "The app already has the current paper-establishment orders on record, so I did not submit duplicates.",
                detail: "Open order symbols already recorded: \(plan.alreadyOpenSymbols.joined(separator: ", ")). Fills are still pending authoritative confirmation.",
                targetSymbols: plan.targetSymbols,
                source: source,
                lastRouteActionAt: routeAttemptedAt
            )
            return makePMExecutionRoutingAssessment(
                request: request,
                proposal: nil,
                status: .routedSuccessfully,
                action: .none,
                summary: "The app already has the current paper-establishment orders on record, so I did not submit duplicates.",
                detail: "Open order symbols already recorded: \(plan.alreadyOpenSymbols.joined(separator: ", ")). Fills are still pending authoritative confirmation.",
                blockedReasons: []
            )
        }

        if plan.entries.isEmpty {
            if plan.missingPriceSymbols.isEmpty == false {
                let summary = plan.blockedDetails.first
                    ?? "I do not currently have usable prices to size the current paper-portfolio targets."
                let detail = [
                    plan.blockedDetails.joined(separator: " "),
                    "I requested app-owned market-data subscriptions for those symbols and recorded this already-approved paper-portfolio establishment as pending automatic retry when usable prices arrive.",
                    "No new owner approval is required for that retry."
                ]
                    .filter { $0.isEmpty == false }
                    .joined(separator: " ")
                request = try await persistApprovedWorkingPaperPortfolioExecutionPendingState(
                    request: request,
                    missingPriceSymbols: plan.missingPriceSymbols,
                    summary: summary,
                    detail: detail,
                    source: source
                )
                request = try await persistWorkingPaperPortfolioExecutionLifecycleState(
                    request: request,
                    status: .waitingForUsablePrices,
                    orderPlanStatus: .waitingForUsablePrices,
                    summary: summary,
                    detail: detail,
                    targetSymbols: plan.targetSymbols,
                    missingPriceSymbols: plan.missingPriceSymbols,
                    blockedReasons: plan.blockedReasons,
                    source: source,
                    lastRouteActionAt: routeAttemptedAt
                )
                return makePMExecutionRoutingAssessment(
                    request: request,
                    proposal: nil,
                    status: .blockedExecutionPrerequisites,
                    action: .none,
                    summary: summary,
                    detail: detail,
                    blockedReasons: plan.blockedReasons
                )
            }

            request = try await clearApprovedWorkingPaperPortfolioExecutionPendingState(
                request: request,
                source: source
            )
            let blockedSummary = plan.blockedDetails.first
                ?? "The app cannot build an executable paper-portfolio order plan yet."
            let blockedDetail = plan.blockedDetails.joined(separator: " ")
            request = try await persistWorkingPaperPortfolioExecutionLifecycleState(
                request: request,
                status: .blocked,
                orderPlanStatus: .blocked,
                summary: blockedSummary,
                detail: blockedDetail,
                targetSymbols: plan.targetSymbols,
                blockedReasons: plan.blockedReasons,
                source: source,
                lastRouteActionAt: routeAttemptedAt
            )
            return makePMExecutionRoutingAssessment(
                request: request,
                proposal: nil,
                status: .blockedExecutionPrerequisites,
                action: .none,
                summary: blockedSummary,
                detail: blockedDetail,
                blockedReasons: plan.blockedReasons
            )
        }

        await store.publishDiagnostic(
            "pm paper-portfolio execution start approval_request=\(shortOrderID(request.approvalRequestId)) ready_orders=\(plan.entries.count) skipped_existing=\(plan.alreadyOpenSymbols.count) blocked_preflight=\(plan.blockedDetails.count)",
            source: source,
            action: "pm_paper_portfolio_execution_start"
        )

        var attempts: [PMWorkingPaperPortfolioSubmissionAttempt] = []
        for entry in plan.entries {
            let result = await submitOrderIntent(
                .place(
                    PlaceOrderIntent(
                        instrumentType: .equity,
                        symbol: entry.symbol,
                        qty: entry.quantity,
                        side: entry.side,
                        type: .market,
                        timeInForce: .day
                    )
                ),
                source: "ui.pm_paper_portfolio_establishment"
            )
            attempts.append(
                PMWorkingPaperPortfolioSubmissionAttempt(
                    entry: entry,
                    result: result
                )
            )
        }

        let acceptedAttempts = attempts.filter { $0.result.accepted }
        let failedAttempts = attempts.filter { $0.result.accepted == false }
        let acceptedSummary = acceptedAttempts.map {
            "\($0.entry.symbol) \($0.entry.side.rawValue) \($0.entry.quantity)"
        }
        let failureSummary = failedAttempts.map {
            "\($0.entry.symbol) \($0.entry.side.rawValue) \($0.entry.quantity): \($0.result.message)"
        }

        await store.publishDiagnostic(
            "pm paper-portfolio execution completed approval_request=\(shortOrderID(request.approvalRequestId)) accepted=\(acceptedAttempts.count) failed=\(failedAttempts.count)",
            source: source,
            action: "pm_paper_portfolio_execution_complete",
            errorCode: failedAttempts.isEmpty ? nil : "pm_paper_portfolio_partial_failure"
        )

        var detailParts: [String] = []
        if acceptedSummary.isEmpty == false {
            detailParts.append("Accepted order attempts: \(acceptedSummary.joined(separator: ", ")).")
        }
        if plan.alreadyOpenSymbols.isEmpty == false {
            detailParts.append("Skipped duplicate submission for symbols that already have open orders on record: \(plan.alreadyOpenSymbols.joined(separator: ", ")).")
        }
        if plan.blockedDetails.isEmpty == false {
            detailParts.append(plan.blockedDetails.joined(separator: " "))
        }
        if failureSummary.isEmpty == false {
            detailParts.append("Submission failures: \(failureSummary.joined(separator: " | ")).")
        }
        let detail = detailParts.joined(separator: " ")

        if plan.missingPriceSymbols.isEmpty == false {
            let retryDetail = [
                detail,
                "I requested app-owned market-data subscriptions for the remaining blocked symbols and recorded this approved execution for automatic retry when usable prices arrive.",
                "No new owner approval is required for those remaining legs."
            ]
                .filter { $0.isEmpty == false }
                .joined(separator: " ")
            request = try await persistApprovedWorkingPaperPortfolioExecutionPendingState(
                request: request,
                missingPriceSymbols: plan.missingPriceSymbols,
                summary: failedAttempts.isEmpty
                    ? "The remaining paper-portfolio legs still need usable prices before I can submit them."
                    : "Some paper-portfolio legs are still waiting on usable prices or failed during submission.",
                detail: retryDetail,
                source: source,
                retryAttemptedAt: routeAttemptedAt
            )
        } else {
            request = try await clearApprovedWorkingPaperPortfolioExecutionPendingState(
                request: request,
                source: source
            )
        }

        if failedAttempts.isEmpty, plan.blockedDetails.isEmpty {
            request = try await persistWorkingPaperPortfolioExecutionLifecycleState(
                request: request,
                status: .submitted,
                orderPlanStatus: .submitted,
                summary: "I submitted the current paper-portfolio establishment orders through the app. Fills are not yet confirmed.",
                detail: detail,
                targetSymbols: plan.targetSymbols,
                source: source,
                lastRouteActionAt: routeAttemptedAt,
                orderAttemptCount: attempts.count,
                acceptedOrderAttemptCount: acceptedAttempts.count,
                failedOrderAttemptCount: failedAttempts.count
            )
            return makePMExecutionRoutingAssessment(
                request: request,
                proposal: nil,
                status: .routedSuccessfully,
                action: .submitWorkingPortfolioEstablishmentOrders,
                summary: "I submitted the current paper-portfolio establishment orders through the app. Fills are not yet confirmed.",
                detail: detail,
                blockedReasons: []
            )
        }

        if acceptedAttempts.isEmpty == false {
            var partialBlockedReasons = plan.blockedReasons
            if failedAttempts.isEmpty == false {
                partialBlockedReasons.append(.orderSubmissionFailed)
            }
            request = try await persistWorkingPaperPortfolioExecutionLifecycleState(
                request: request,
                status: .partiallySubmitted,
                orderPlanStatus: .partiallySubmitted,
                summary: "I submitted part of the current paper-portfolio establishment order set, but some legs are still blocked or failed.",
                detail: detail,
                targetSymbols: plan.targetSymbols,
                missingPriceSymbols: plan.missingPriceSymbols,
                blockedReasons: orderedUniqueBlockReasons(partialBlockedReasons),
                source: source,
                lastRouteActionAt: routeAttemptedAt,
                orderAttemptCount: attempts.count,
                acceptedOrderAttemptCount: acceptedAttempts.count,
                failedOrderAttemptCount: failedAttempts.count
            )
            return makePMExecutionRoutingAssessment(
                request: request,
                proposal: nil,
                status: .partiallyRouted,
                action: .submitWorkingPortfolioEstablishmentOrders,
                summary: "I submitted part of the current paper-portfolio establishment order set, but some legs are still blocked or failed.",
                detail: detail,
                blockedReasons: orderedUniqueBlockReasons(partialBlockedReasons)
            )
        }

        request = try await persistWorkingPaperPortfolioExecutionLifecycleState(
            request: request,
            status: .failed,
            orderPlanStatus: .failed,
            summary: "I attempted to route the current paper-portfolio establishment orders, but none were accepted.",
            detail: detail.isEmpty ? "No order attempts were accepted." : detail,
            targetSymbols: plan.targetSymbols,
            missingPriceSymbols: plan.missingPriceSymbols,
            blockedReasons: orderedUniqueBlockReasons(
                plan.blockedReasons + [.orderSubmissionFailed]
            ),
            source: source,
            lastRouteActionAt: routeAttemptedAt,
            orderAttemptCount: attempts.count,
            acceptedOrderAttemptCount: acceptedAttempts.count,
            failedOrderAttemptCount: failedAttempts.count
        )
        return makePMExecutionRoutingAssessment(
            request: request,
            proposal: nil,
            status: .launchFailed,
            action: .submitWorkingPortfolioEstablishmentOrders,
            summary: "I attempted to route the current paper-portfolio establishment orders, but none were accepted.",
            detail: detail.isEmpty ? "No order attempts were accepted." : detail,
            blockedReasons: orderedUniqueBlockReasons(
                plan.blockedReasons + [.orderSubmissionFailed]
            )
        )
    }

    private func orderedUniqueBlockReasons(
        _ reasons: [PMExecutionRoutingBlockReason]
    ) -> [PMExecutionRoutingBlockReason] {
        var seen: Set<PMExecutionRoutingBlockReason> = []
        var ordered: [PMExecutionRoutingBlockReason] = []
        for reason in reasons {
            if seen.insert(reason).inserted {
                ordered.append(reason)
            }
        }
        return ordered
    }

    public func assessPMExecutionRouting(
        approvalRequestId: String
    ) async throws -> PMExecutionRoutingAssessment {
        let request = try await getPMApprovalRequest(id: approvalRequestId)
        let liveReadinessReasons = currentLiveReadinessBlockReasons()
        let normalizedProposalID = request.proposalId?.trimmingCharacters(in: .whitespacesAndNewlines)

        guard request.status == .resolved,
              request.ownerResponse == .approved
        else {
            return makePMExecutionRoutingAssessment(
                request: request,
                proposal: nil,
                status: .invalidState,
                action: .none,
                summary: "This PM ask still needs an approved owner response before the app can route the next governed step.",
                detail: "Record the owner's approval on the PM request before moving the linked recommendation into the existing proposal or execution path.",
                blockedReasons: [.ownerApprovalRequired]
            )
        }

        if request.requestType == .liveOrderReview {
            return try await assessLiveOrderReviewExecutionRouting(request: request)
        }

        guard let proposalID = normalizedProposalID,
              proposalID.isEmpty == false
        else {
            if request.requestType == .portfolioAction {
                return try await assessWorkingPaperPortfolioExecutionRouting(request: request)
            }
            return makePMExecutionRoutingAssessment(
                request: request,
                proposal: nil,
                status: .invalidState,
                action: .none,
                summary: "This PM request is not linked to a proposal-backed next step.",
                detail: "The approval loop can only route through the existing proposal execution path when the PM request points to a specific proposal.",
                blockedReasons: [.proposalNotLinked] + liveReadinessReasons
            )
        }

        guard let proposal = try await proposalStore.getProposal(id: proposalID) else {
            return makePMExecutionRoutingAssessment(
                request: request,
                proposal: nil,
                status: .invalidState,
                action: .none,
                summary: "The linked proposal record could not be found.",
                detail: "Refresh the proposal context or recreate the PM recommendation before attempting to route this next step.",
                blockedReasons: [.linkedProposalMissing] + liveReadinessReasons
            )
        }

        switch proposal.approval.status {
        case .draft:
            return makePMExecutionRoutingAssessment(
                request: request,
                proposal: proposal,
                status: .blockedMissingProposalApproval,
                action: .submitProposalForReview,
                summary: "Ready to route into the existing proposal review path.",
                detail: "The PM-approved next step can submit the linked proposal for separate review now. Execution still remains blocked until that existing proposal approval path is completed.",
                blockedReasons: [.proposalApprovalRequired] + liveReadinessReasons
            )
        case .proposed:
            return makePMExecutionRoutingAssessment(
                request: request,
                proposal: proposal,
                status: .blockedMissingProposalApproval,
                action: .none,
                summary: "The linked proposal is already waiting on separate proposal approval.",
                detail: "No further routing is available yet. The next step remains behind the existing proposal review and approval workflow.",
                blockedReasons: [.proposalApprovalRequired] + liveReadinessReasons
            )
        case .deniedPaper:
            return makePMExecutionRoutingAssessment(
                request: request,
                proposal: proposal,
                status: .invalidState,
                action: .none,
                summary: "The linked proposal has already been denied for paper.",
                detail: "Create a revised recommendation or a new proposal if the PM wants to pursue a different next step.",
                blockedReasons: [.proposalDenied] + liveReadinessReasons
            )
        case .approvedPaper:
            guard configuration.environment == .paper else {
                return makePMExecutionRoutingAssessment(
                    request: request,
                    proposal: proposal,
                    status: .blockedEnvironmentMismatch,
                    action: .none,
                    summary: "The linked proposal is approved for the governed paper path, but the app is currently set to Live.",
                    detail: "Switch the app back to Paper before routing this approved next step through the current proposal execution path. Live posture remains governed separately and is never implied by PM approval.",
                    blockedReasons: [.environmentMismatch] + liveReadinessReasons
                )
            }

            return makePMExecutionRoutingAssessment(
                request: request,
                proposal: proposal,
                status: .executableNowPaper,
                action: .startProposalExecution,
                summary: "This PM-approved next step is ready to route through the existing paper-safe execution path.",
                detail: "The linked proposal is already approved for paper. Routing now will launch the existing proposal start flow and create the normal paper-run records.",
                blockedReasons: []
            )
        }
    }

    @discardableResult
    private func persistPMExecutionRoutingAssessment(
        _ assessment: PMExecutionRoutingAssessment,
        source: AuditEventSource
    ) async throws -> PMExecutionRoutingAssessment {
        var request = try await getPMApprovalRequest(id: assessment.approvalRequestId)
        request.lastExecutionRoutingAssessment = assessment
        request.updatedAt = nowDate()
        _ = try await upsertPMApprovalRequest(request, source: source)
        await store.publishDiagnostic(
            "pm execution route assessed approval_request=\(shortOrderID(assessment.approvalRequestId)) status=\(assessment.status.rawValue) action=\(assessment.action.rawValue)",
            source: source,
            action: "pm_execution_route_assessment_recorded",
            errorCode: assessment.blockedReasons.isEmpty ? nil : assessment.blockedReasons.map(\.rawValue).joined(separator: ",")
        )
        return assessment
    }

    public func routePMExecutionApprovedIntent(
        approvalRequestId: String,
        source: AuditEventSource = .system
    ) async throws -> PMExecutionRoutingAssessment {
        let assessment = try await assessPMExecutionRouting(approvalRequestId: approvalRequestId)
        let request = try await getPMApprovalRequest(id: approvalRequestId)
        let normalizedProposalID = trimmedOptionalDecisionText(request.proposalId)

        if source == .ipc,
           request.requestType == .liveOrderReview {
            return try await persistPMExecutionRoutingAssessment(
                PMExecutionRoutingAssessment(
                    approvalRequestId: assessment.approvalRequestId,
                    decisionId: assessment.decisionId,
                    proposalId: assessment.proposalId,
                    proposalTitle: assessment.proposalTitle,
                    proposalStatus: assessment.proposalStatus,
                    environment: assessment.environment,
                    isLiveArmed: assessment.isLiveArmed,
                    killSwitchEnabled: assessment.killSwitchEnabled,
                    status: .blockedExecutionPrerequisites,
                    action: .none,
                    summary: "Live order routing must be completed in the Mac app.",
                    detail: "Ordinary IPC cannot submit Live order reviews. Open Command Center > Your Decisions on the Mac to complete the governed Live approval and routing path.",
                    blockedReasons: [.localAppRequiredForLiveExecution]
                ),
                source: source
            )
        }

        if request.requestType == .portfolioAction,
           normalizedProposalID == nil,
           assessment.environment == .paper,
           request.status == .resolved,
           request.ownerResponse == .approved {
            let routed = try await routeWorkingPaperPortfolioExecution(
                request: request,
                source: source
            )
            return try await persistPMExecutionRoutingAssessment(routed, source: source)
        }

        if request.requestType == .liveOrderReview,
           request.status == .resolved,
           request.ownerResponse == .approved {
            let routed = try await routeLiveOrderReviewExecution(
                request: request,
                source: source
            )
            return try await persistPMExecutionRoutingAssessment(routed, source: source)
        }

        switch assessment.action {
        case .none:
            return try await persistPMExecutionRoutingAssessment(assessment, source: source)
        case .submitProposalForReview:
            guard let proposalID = assessment.proposalId else {
                return try await persistPMExecutionRoutingAssessment(PMExecutionRoutingAssessment(
                    approvalRequestId: assessment.approvalRequestId,
                    decisionId: assessment.decisionId,
                    proposalId: assessment.proposalId,
                    proposalTitle: assessment.proposalTitle,
                    proposalStatus: assessment.proposalStatus,
                    environment: assessment.environment,
                    isLiveArmed: assessment.isLiveArmed,
                    killSwitchEnabled: assessment.killSwitchEnabled,
                    status: .invalidState,
                    action: .none,
                    summary: "The PM request is missing a linked proposal.",
                    detail: "Routing cannot continue without proposal linkage.",
                    blockedReasons: [.proposalNotLinked]
                ), source: source)
            }
            do {
                let proposal = try await submitProposal(id: proposalID, source: source)
                await store.publishDiagnostic(
                    "pm execution route submitted proposal id=\(proposal.proposalId) approval_request=\(shortOrderID(approvalRequestId))",
                    source: source,
                    strategyID: proposal.strategyId,
                    action: "pm_execution_route_submit_proposal"
                )
                return try await persistPMExecutionRoutingAssessment(PMExecutionRoutingAssessment(
                    approvalRequestId: assessment.approvalRequestId,
                    decisionId: assessment.decisionId,
                    proposalId: proposal.proposalId,
                    proposalTitle: proposal.title,
                    proposalStatus: proposal.approval.status,
                    environment: assessment.environment,
                    isLiveArmed: assessment.isLiveArmed,
                    killSwitchEnabled: assessment.killSwitchEnabled,
                    status: .routedSuccessfully,
                    action: .submitProposalForReview,
                    summary: "The approved PM next step has been routed into the existing proposal review path.",
                    detail: "The linked proposal is now submitted for separate review. Execution remains blocked until that existing approval step is completed.",
                    blockedReasons: []
                ), source: source)
            } catch {
                return try await persistPMExecutionRoutingAssessment(PMExecutionRoutingAssessment(
                    approvalRequestId: assessment.approvalRequestId,
                    decisionId: assessment.decisionId,
                    proposalId: assessment.proposalId,
                    proposalTitle: assessment.proposalTitle,
                    proposalStatus: assessment.proposalStatus,
                    environment: assessment.environment,
                    isLiveArmed: assessment.isLiveArmed,
                    killSwitchEnabled: assessment.killSwitchEnabled,
                    status: .launchFailed,
                    action: .submitProposalForReview,
                    summary: "Routing into the proposal review path failed.",
                    detail: error.localizedDescription,
                    blockedReasons: assessment.blockedReasons
                ), source: source)
            }
        case .submitWorkingPortfolioEstablishmentOrders:
            let routed = try await routeWorkingPaperPortfolioExecution(
                request: request,
                source: source
            )
            return try await persistPMExecutionRoutingAssessment(routed, source: source)
        case .submitLiveOrderReview:
            let routed = try await routeLiveOrderReviewExecution(
                request: request,
                source: source
            )
            return try await persistPMExecutionRoutingAssessment(routed, source: source)
        case .startProposalExecution:
            guard let proposalID = assessment.proposalId else {
                return try await persistPMExecutionRoutingAssessment(PMExecutionRoutingAssessment(
                    approvalRequestId: assessment.approvalRequestId,
                    decisionId: assessment.decisionId,
                    proposalId: assessment.proposalId,
                    proposalTitle: assessment.proposalTitle,
                    proposalStatus: assessment.proposalStatus,
                    environment: assessment.environment,
                    isLiveArmed: assessment.isLiveArmed,
                    killSwitchEnabled: assessment.killSwitchEnabled,
                    status: .invalidState,
                    action: .none,
                    summary: "The PM request is missing a linked proposal.",
                    detail: "Routing cannot continue without proposal linkage.",
                    blockedReasons: [.proposalNotLinked]
                ), source: source)
            }
            do {
                let status = try await startStrategyFromProposal(
                    proposalID: proposalID,
                    source: source
                )
                await store.publishDiagnostic(
                    "pm execution route launched proposal id=\(proposalID) approval_request=\(shortOrderID(approvalRequestId)) strategy_id=\(status.id)",
                    source: source,
                    strategyID: status.id,
                    action: "pm_execution_route_launch"
                )
                return try await persistPMExecutionRoutingAssessment(PMExecutionRoutingAssessment(
                    approvalRequestId: assessment.approvalRequestId,
                    decisionId: assessment.decisionId,
                    proposalId: assessment.proposalId,
                    proposalTitle: assessment.proposalTitle,
                    proposalStatus: assessment.proposalStatus,
                    environment: assessment.environment,
                    isLiveArmed: assessment.isLiveArmed,
                    killSwitchEnabled: assessment.killSwitchEnabled,
                    status: .routedSuccessfully,
                    action: .startProposalExecution,
                    summary: "The approved PM next step has been routed through the existing paper-safe execution path.",
                    detail: "The linked approved paper proposal was launched through the existing strategy start flow and recorded as a normal paper run.",
                    blockedReasons: []
                ), source: source)
            } catch {
                return try await persistPMExecutionRoutingAssessment(PMExecutionRoutingAssessment(
                    approvalRequestId: assessment.approvalRequestId,
                    decisionId: assessment.decisionId,
                    proposalId: assessment.proposalId,
                    proposalTitle: assessment.proposalTitle,
                    proposalStatus: assessment.proposalStatus,
                    environment: assessment.environment,
                    isLiveArmed: assessment.isLiveArmed,
                    killSwitchEnabled: assessment.killSwitchEnabled,
                    status: .launchFailed,
                    action: .startProposalExecution,
                    summary: "Routing through the existing execution path failed.",
                    detail: error.localizedDescription,
                    blockedReasons: assessment.blockedReasons
                ), source: source)
            }
        }
    }

    public func archivePMExerciseArtifacts(
        source: AuditEventSource = .system
    ) async throws -> PMExerciseArtifactArchiveSummary {
        let now = nowDate()

        var archivedApprovalRequests = 0
        for request in try await pmApprovalRequestStore.loadAll() where isExercisePMApprovalRequest(request) {
            guard request.status != .stale && request.status != .withdrawn else {
                continue
            }
            var updated = request
            updated.status = .stale
            updated.updatedAt = now
            _ = try await pmApprovalRequestStore.upsert(updated)
            archivedApprovalRequests += 1
        }

        var archivedDecisions = 0
        for decision in try await pmDecisionStore.loadAll() where isExercisePMDecision(decision) {
            guard decision.status != .withdrawn && decision.status != .superseded else {
                continue
            }
            var updated = decision
            updated.status = .withdrawn
            updated.updatedAt = now
            _ = try await pmDecisionStore.upsert(updated)
            archivedDecisions += 1
        }

        var archivedDelegations = 0
        for delegation in try await pmDelegationStore.loadAll() where isExercisePMDelegation(delegation) {
            guard delegation.status != .canceled else {
                continue
            }
            var updated = delegation
            updated.status = .canceled
            updated.updatedAt = now
            _ = try await pmDelegationStore.upsert(updated)
            archivedDelegations += 1
        }

        var closedSessions = 0
        for session in try await pmCommunicationSessionStore.loadAll() where isExercisePMCommunicationSession(session) {
            guard session.status != .closed else {
                continue
            }
            var updated = session
            updated.status = .closed
            updated.updatedAt = now
            _ = try await pmCommunicationSessionStore.upsert(updated)
            closedSessions += 1
        }

        let summary = PMExerciseArtifactArchiveSummary(
            approvalRequestsArchived: archivedApprovalRequests,
            decisionsArchived: archivedDecisions,
            delegationsArchived: archivedDelegations,
            communicationSessionsClosed: closedSessions
        )
        await publishPMPersistenceDiagnostics()
        await store.publishDiagnostic(
            "pm exercise artifacts archived total=\(summary.totalAffected)",
            source: source,
            action: "pm_exercise_archive"
        )
        return summary
    }

    @discardableResult
    public func promotePMCommunicationMessageToDelegation(
        messageId: String,
        pmId: String,
        charterId: String,
        title: String,
        rationale: String,
        requestedOutputs: [PMDelegationRequestedOutput] = [.finding],
        taskingBrief: PMTaskingBrief? = nil,
        source: AuditEventSource = .system
    ) async throws -> PMDelegationRecord {
        guard let message = try await pmCommunicationMessageStore.get(id: messageId) else {
            throw PMUserCommunicationPromotionError.messageNotFound(id: messageId)
        }
        let validatedPMID = try validatedPMCommunicationPromotionPMID(pmId)
        let validatedCharterID = charterId.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !validatedCharterID.isEmpty else {
            throw PMUserCommunicationPromotionError.charterIdRequired
        }
        guard let charter = try await analystCharterStore.get(id: validatedCharterID) else {
            throw PMUserCommunicationPromotionError.charterNotFound(id: validatedCharterID)
        }
        let validatedTitle = try validatedPMCommunicationPromotionTitle(title)
        let validatedRationale = try validatedPMCommunicationPromotionRationale(rationale)
        let now = nowDate()
        if var existing = try await existingPMDelegationForSourceMessage(
            messageId: message.messageId,
            pmId: validatedPMID,
            charterId: charter.charterId
        ) {
            if existing.followThrough == nil {
                existing.followThrough = requiredPMDelegationFollowThrough(
                    message: message,
                    requestedAt: existing.createdAt,
                    updatedAt: now
                )
                existing.updatedAt = now
                existing = try await upsertPMDelegation(existing, source: source)
            }
            if let promotion = message.promotion {
                guard promotion.targetType == .delegation,
                      promotion.targetId == existing.delegationId else {
                    throw PMUserCommunicationPromotionError.messageAlreadyPromoted(id: messageId)
                }
            } else {
                _ = try await upsertPMCommunicationPromotion(
                    message: message,
                    targetType: .delegation,
                    targetId: existing.delegationId,
                    source: source
                )
            }
            return existing
        }
        if message.promotion != nil {
            throw PMUserCommunicationPromotionError.messageAlreadyPromoted(id: messageId)
        }
        let delegation = PMDelegationRecord(
            delegationId: "delegation-\(UUID().uuidString.lowercased())",
            pmId: validatedPMID,
            analystId: charter.analystId,
            charterId: charter.charterId,
            title: validatedTitle,
            rationale: validatedRationale,
            taskingBrief: taskingBrief,
            requestedOutputs: requestedOutputs,
            status: .issued,
            sourceCommunicationSessionId: message.sessionId,
            sourceCommunicationMessageId: message.messageId,
            followThrough: requiredPMDelegationFollowThrough(
                message: message,
                requestedAt: now,
                updatedAt: now
            ),
            createdAt: now,
            updatedAt: now
        )
        let stored = try await upsertPMDelegation(delegation, source: source)
        _ = try await upsertPMCommunicationPromotion(
            message: message,
            targetType: .delegation,
            targetId: stored.delegationId,
            source: source
        )
        return stored
    }

    private func existingPMDelegationForSourceMessage(
        messageId: String,
        pmId: String,
        charterId: String
    ) async throws -> PMDelegationRecord? {
        let normalizedMessageId = messageId.trimmingCharacters(in: .whitespacesAndNewlines)
        let normalizedPMID = pmId.trimmingCharacters(in: .whitespacesAndNewlines)
        let normalizedCharterID = charterId.trimmingCharacters(in: .whitespacesAndNewlines)
        guard normalizedMessageId.isEmpty == false,
              normalizedPMID.isEmpty == false,
              normalizedCharterID.isEmpty == false else {
            return nil
        }
        return try await pmDelegationStore.loadAll()
            .filter {
                $0.sourceCommunicationMessageId == normalizedMessageId
                    && $0.pmId == normalizedPMID
                    && $0.charterId == normalizedCharterID
                    && $0.parentDelegationId == nil
                    && $0.sourceFollowUpActionId == nil
            }
            .sorted { lhs, rhs in
                if lhs.createdAt == rhs.createdAt { return lhs.delegationId < rhs.delegationId }
                return lhs.createdAt < rhs.createdAt
            }
            .first
    }

    private func requiredPMDelegationFollowThrough(
        message: PMCommunicationMessage,
        requestedAt: Date,
        updatedAt: Date
    ) -> PMDelegationFollowThrough {
        PMDelegationFollowThrough(
            status: .pending,
            sourceCommunicationSessionId: message.sessionId,
            sourceCommunicationMessageId: message.messageId,
            requestedAt: requestedAt,
            updatedAt: updatedAt
        )
    }

    public func listPMDelegations() async throws -> [PMDelegationRecord] {
        let delegations = try await pmDelegationStore.loadAll()
        await publishPMPersistenceDiagnostics()
        return delegations
    }

    public func getPMDelegation(id: String) async throws -> PMDelegationRecord {
        guard let delegation = try await pmDelegationStore.get(id: id) else {
            throw PMDelegationStoreError.delegationNotFound(id: id)
        }
        await publishPMPersistenceDiagnostics()
        return delegation
    }

    @discardableResult
    public func submitPMDelegationFollowUp(
        _ request: PMDelegationFollowUpRequest,
        source: AuditEventSource = .ui
    ) async throws -> PMDelegationFollowUpResult {
        let normalized = try validatePMDelegationFollowUpRequest(request)
        guard let sourceDelegation = try await pmDelegationStore.get(id: normalized.sourceDelegationId) else {
            throw PMDelegationFollowUpValidationError.sourceDelegationNotFound(id: normalized.sourceDelegationId)
        }
        let sourceTask: AnalystTask?
        if let sourceTaskID = sourceDelegation.taskId {
            sourceTask = try await getAnalystTask(id: sourceTaskID)
        } else {
            sourceTask = nil
        }
        let now = nowDate()

        let followUpAction = PMAnalystFollowUpAction(
            actionId: "pm-follow-up-\(UUID().uuidString.lowercased())",
            actionType: normalized.actionType,
            summary: normalized.summary,
            requestedCharterId: normalized.requestedCharterId,
            requestedRuntimePolicy: normalized.requestedRuntimePolicy,
            taskingBrief: normalized.taskingBrief,
            createdAt: now
        )

        var updatedSourceDelegation = sourceDelegation
        updatedSourceDelegation.followUpActions.append(followUpAction)
        _ = try await upsertPMDelegation(updatedSourceDelegation, source: source)

        if normalized.actionType == .accept {
            let decision = try await upsertPMDecision(
                PMDecisionRecord(
                    decisionId: "pm-decision-\(UUID().uuidString.lowercased())",
                    pmId: sourceDelegation.pmId,
                    title: "PM accepted analyst output: \(sourceDelegation.title)",
                    summary: "\(normalized.summary) This preserves existing approval, proposal, and trading gates.",
                    decisionType: .recommendation,
                    status: .active,
                    delegationId: sourceDelegation.delegationId,
                    charterId: sourceDelegation.charterId,
                    taskId: sourceDelegation.taskId,
                    findingId: sourceDelegation.linkedFindingIDs.last,
                    signalId: sourceDelegation.linkedSignalIDs.last,
                    proposalId: sourceDelegation.linkedProposalIDs.last,
                    createdAt: now,
                    updatedAt: now
                ),
                source: source
            )
            await store.publishDiagnostic(
                "pm delegation follow-up accepted delegation=\(shortOrderID(sourceDelegation.delegationId)) action=\(shortOrderID(followUpAction.actionId)) decision=\(shortOrderID(decision.decisionId))",
                source: source,
                action: "pm_delegation_follow_up_accept"
            )
            return PMDelegationFollowUpResult(
                sourceDelegationId: sourceDelegation.delegationId,
                sourceFollowUpActionId: followUpAction.actionId,
                createdDecisionId: decision.decisionId
            )
        }

        let targetCharterId = normalized.requestedCharterId ?? sourceDelegation.charterId
        let targetCharter = try await getAnalystCharter(id: targetCharterId)
        let requestedRuntimePolicy = try await resolveFollowUpRuntimePolicy(
            request: normalized,
            sourceDelegation: sourceDelegation,
            targetCharter: targetCharter,
            now: now
        )
        let taskingBrief = normalized.taskingBrief
            ?? sourceDelegation.taskingBrief
            ?? sourceTask?.pmTaskingBrief
        let childTaskId = "task-\(UUID().uuidString.lowercased())"
        let childDelegationId = "delegation-\(UUID().uuidString.lowercased())"
        let childTask = try await makeFollowUpAnalystTask(
            sourceDelegation: sourceDelegation,
            sourceTask: sourceTask,
            targetCharter: targetCharter,
            followUpAction: followUpAction,
            taskingBrief: taskingBrief,
            taskId: childTaskId,
            now: now
        )
        _ = try await upsertAnalystTask(childTask, source: source)

        let childDelegation = PMDelegationRecord(
            delegationId: childDelegationId,
            pmId: sourceDelegation.pmId,
            analystId: targetCharter.analystId,
            charterId: targetCharter.charterId,
            taskId: childTask.taskId,
            title: childTask.title,
            rationale: makeFollowUpDelegationRationale(
                sourceDelegation: sourceDelegation,
                followUpAction: followUpAction
            ),
            taskingBrief: taskingBrief,
            requestedOutputs: sourceDelegation.requestedOutputs,
            status: .issued,
            parentDelegationId: sourceDelegation.delegationId,
            sourceFollowUpActionId: followUpAction.actionId,
            runtimePolicyOverride: requestedRuntimePolicy,
            createdAt: now,
            updatedAt: now
        )
        _ = try await upsertPMDelegation(childDelegation, source: source)

        let wantsProposal = childDelegation.requestedOutputs.contains(.proposalDraft)
        let wantsSignal = wantsProposal || childDelegation.requestedOutputs.contains(.signal)
        let launchResult = try await launchAnalystWorkerForPMDelegation(
            delegationID: childDelegation.delegationId,
            draftSignal: wantsSignal,
            draftProposal: wantsProposal,
            source: source
        )
        await store.publishDiagnostic(
            "pm delegation follow-up launched source_delegation=\(shortOrderID(sourceDelegation.delegationId)) child_delegation=\(shortOrderID(childDelegation.delegationId)) action=\(shortOrderID(followUpAction.actionId)) runtime=\(requestedRuntimePolicy?.runtimeIdentifier ?? "-")",
            source: source,
            action: "pm_delegation_follow_up_launch"
        )
        return PMDelegationFollowUpResult(
            sourceDelegationId: sourceDelegation.delegationId,
            sourceFollowUpActionId: followUpAction.actionId,
            createdDelegationId: childDelegation.delegationId,
            createdTaskId: childTask.taskId,
            launchResult: launchResult
        )
    }

    @discardableResult
    public func upsertPMDelegation(
        _ delegation: PMDelegationRecord,
        source: AuditEventSource = .system
    ) async throws -> PMDelegationRecord {
        let normalized = try await validatedPMDelegation(delegation)
        let updated = try await pmDelegationStore.upsert(normalized)
        await publishPMPersistenceDiagnostics()
        await store.publishDiagnostic(
            "pm delegation upserted id=\(shortOrderID(updated.delegationId)) charter=\(shortOrderID(updated.charterId))",
            source: source,
            action: "pm_delegation_upsert"
        )
        return updated
    }

    @discardableResult
    public func resolvePMDelegationWorkerIssue(
        delegationId: String,
        resolvedBy: String = "owner",
        reason: PMDelegationIssueResolutionReason = .ownerDismissed,
        summary: String = "Owner/operator marked this failed or degraded worker launch issue resolved from active surfaces; durable history remains traceable.",
        supersededByDelegationId: String? = nil,
        source: AuditEventSource = .ui
    ) async throws -> PMDelegationRecord {
        var delegation = try await getPMDelegation(id: delegationId)
        let observability = makePMDelegationObservabilitySummary(delegation: delegation)
        guard isActivePMDelegationWorkerIssue(delegation: delegation, summary: observability) else {
            return delegation
        }

        let now = nowDate()
        let resolvedByValue = resolvedBy.trimmingCharacters(in: .whitespacesAndNewlines)
        let summaryValue = summary.trimmingCharacters(in: .whitespacesAndNewlines)
        let supersededBy = supersededByDelegationId?.trimmingCharacters(in: .whitespacesAndNewlines)
        delegation.issueResolution = PMDelegationIssueResolution(
            resolvedAt: now,
            resolvedBy: resolvedByValue.isEmpty ? "owner" : resolvedByValue,
            reason: reason,
            summary: summaryValue.isEmpty
                ? "Worker issue resolved from active owner surfaces; durable history remains traceable."
                : summaryValue,
            supersededByDelegationId: supersededBy?.isEmpty == true ? nil : supersededBy
        )
        delegation.updatedAt = now
        let updated = try await upsertPMDelegation(delegation, source: source)
        await store.publishDiagnostic(
            "pm delegation worker issue resolved id=\(shortOrderID(updated.delegationId)) reason=\(reason.rawValue)",
            source: source,
            action: "pm_delegation_worker_issue_resolved"
        )
        return updated
    }

    @discardableResult
    public func resolveActivePMDelegationWorkerIssues(
        resolvedBy: String = "owner",
        summary: String = "Owner/operator dismissed stale failed worker launch issues from active surfaces; durable history remains traceable.",
        source: AuditEventSource = .ui
    ) async throws -> [PMDelegationRecord] {
        let delegations = try await listPMDelegations()
        var resolved: [PMDelegationRecord] = []
        for delegation in delegations where isActivePMDelegationWorkerIssue(delegation: delegation) {
            let updated = try await resolvePMDelegationWorkerIssue(
                delegationId: delegation.delegationId,
                resolvedBy: resolvedBy,
                reason: .ownerDismissed,
                summary: summary,
                source: source
            )
            resolved.append(updated)
        }
        return resolved
    }

