    @discardableResult
    public func applyAnalystSourceAccessSuggestionAction(
        suggestionId: String,
        action: AnalystSourceAccessSuggestionAction,
        updatedBy: String,
        source: AuditEventSource = .ipc
    ) async throws -> AnalystSourceAccessSuggestionRecord {
        var suggestion = try await getAnalystSourceAccessSuggestion(id: suggestionId)
        guard suggestion.status.isActive else {
            throw AnalystSourceAccessSuggestionActionValidationError.suggestionNotActive(id: suggestionId)
        }

        let trimmedUpdatedBy = updatedBy.trimmingCharacters(in: .whitespacesAndNewlines)
        let actor = trimmedUpdatedBy.isEmpty ? "pm-control-plane" : trimmedUpdatedBy
        let now = nowDate()
        let policyEntry = preferredPolicyEntry(for: suggestion)

        switch action {
        case .addToPreferredSources:
            var charter = try await resolvedAnalystCharter(for: suggestion)
            charter.sourcePolicy.reputableWebResearchAllowed = true
            charter.sourcePolicy.preferredSources = mergedPolicyEntries(
                charter.sourcePolicy.preferredSources,
                appending: policyEntry
            )
            charter.sourcePolicy.restrictedSources = removingPolicyEntry(
                policyEntry,
                from: charter.sourcePolicy.restrictedSources
            )
            charter.revisionSummary = "Source policy update from analyst suggestion: added preferred source \(policyEntry)."
            charter.updatedBy = actor
            charter.updateSource = .sourceSuggestionAction
            let updatedCharter = try await analystCharterStore.upsert(try validatedAnalystCharter(charter))

            suggestion.status = .addedToPreferredSources
            suggestion.resolvedCharterId = updatedCharter.charterId
            suggestion.appliedPolicyEntry = policyEntry
            suggestion.resolutionSummary = "Added \(policyEntry) to preferred sources for \(updatedCharter.title)."
        case .addToRestrictedSources:
            var charter = try await resolvedAnalystCharter(for: suggestion)
            charter.sourcePolicy.restrictedSources = mergedPolicyEntries(
                charter.sourcePolicy.restrictedSources,
                appending: policyEntry
            )
            charter.sourcePolicy.preferredSources = removingPolicyEntry(
                policyEntry,
                from: charter.sourcePolicy.preferredSources
            )
            charter.revisionSummary = "Source policy update from analyst suggestion: added restricted source \(policyEntry)."
            charter.updatedBy = actor
            charter.updateSource = .sourceSuggestionAction
            let updatedCharter = try await analystCharterStore.upsert(try validatedAnalystCharter(charter))

            suggestion.status = .addedToRestrictedSources
            suggestion.resolvedCharterId = updatedCharter.charterId
            suggestion.appliedPolicyEntry = policyEntry
            suggestion.resolutionSummary = "Added \(policyEntry) to restricted sources for \(updatedCharter.title)."
        case .dismiss:
            suggestion.status = .dismissed
            suggestion.resolvedCharterId = suggestion.charterId
            suggestion.appliedPolicyEntry = nil
            suggestion.resolutionSummary = "Dismissed without changing charter source policy."
        }

        suggestion.resolvedBy = actor
        suggestion.closedAt = now

        let updated = try await analystSourceAccessSuggestionStore.upsert(
            try validatedAnalystSourceAccessSuggestion(suggestion)
        )
        await publishAnalystPersistenceDiagnostics()
        await store.publishDiagnostic(
            "analyst source suggestion action applied id=\(shortOrderID(updated.suggestionId)) status=\(updated.status.rawValue)",
            source: source,
            action: "analyst_source_access_suggestion_action"
        )
        return updated
    }

