    private func buildAnalystContextPack(
        charter: AnalystCharter,
        pmID: String?,
        snapshot: StoreSnapshot,
        recentNews: [NewsEvent],
        strategyBrief: PortfolioStrategyBrief?,
        taskSkillReferences: [AgentSkillTaskReference] = [],
        assembledAt: Date
    ) async throws -> AnalystContextPack {
        let relevantMandates: [PMMandate]
        let relevantInstructions: [PMInstruction]
        if let pmID, pmID.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty == false {
            let mandates = try await pmMandateStore.loadAll()
            let instructions = try await pmInstructionStore.loadAll()
            relevantMandates = mandates.filter { $0.pmId == pmID }
            relevantInstructions = instructions.filter { $0.pmId == pmID && $0.status == .active }
        } else {
            relevantMandates = []
            relevantInstructions = []
        }

        let scopedMemory = try await analystScopedMemorySnapshot(
            analystId: charter.analystId,
            charterId: charter.charterId,
            now: assembledAt
        )
        let referencedSkills = try await analystSkillContextItems(
            for: charter,
            taskSkillReferences: taskSkillReferences,
            assembledAt: assembledAt
        )

        return AnalystContextPack(
            sharedCurrentTruth: AnalystSharedCurrentTruth(
                positions: snapshot.positions.map(makeAnalystPositionContext),
                watchlistSymbols: snapshot.watchlistSymbols.map { $0.uppercased() },
                portfolioStrategyBrief: strategyBrief.map(makeAnalystStrategyBriefContext),
                recentNews: recentNews.map(makeAnalystNewsContextItem),
                pmMandates: relevantMandates.map(makeAnalystMandateContextItem),
                pmInstructions: relevantInstructions.map(makeAnalystInstructionContextItem)
            ),
            scopedMemory: scopedMemory,
            referencedSkills: referencedSkills,
            assembledAt: assembledAt
        )
    }

    private func analystSkillContextItems(
        for charter: AnalystCharter,
        taskSkillReferences: [AgentSkillTaskReference] = [],
        assembledAt _: Date
    ) async throws -> [AgentSkillContextItem] {
        let combinedReferences = mergedAgentSkillContextReferences(
            charterReferences: charter.skillReferences,
            taskReferences: taskSkillReferences
        )
        guard combinedReferences.isEmpty == false else { return [] }
        let skills = try await agentSkillStore.loadAll()
        let skillsByID = Dictionary(uniqueKeysWithValues: skills.map { ($0.skillId, $0) })
        return combinedReferences.prefix(8).map { reference in
            let skillID = reference.skillId.trimmingCharacters(in: .whitespacesAndNewlines)
            guard let skill = skillsByID[skillID] else {
                return AgentSkillContextItem(
                    skillId: skillID,
                    title: skillID,
                    summary: "Referenced Agent Skill is missing from the active library.",
                    documentBody: nil,
                    category: nil,
                    requirement: reference.requirement,
                    rationale: reference.rationale,
                    availability: .missing,
                    statusNote: "Skill reference is configured on the charter, but the skill record is missing. Do not invent the method body.",
                    skillUpdatedAt: nil,
                    referenceSources: reference.sources
                )
            }

            let active = skill.status == .active
            return AgentSkillContextItem(
                skillId: skill.skillId,
                title: skill.title,
                summary: skill.summary,
                documentBody: active ? skill.documentBody : nil,
                category: skill.category,
                requirement: reference.requirement,
                rationale: reference.rationale,
                availability: active ? .active : .archived,
                statusNote: active
                    ? nil
                    : "Skill is archived. Mention that the configured reference is inactive if it matters, and do not apply the archived body as live methodology guidance.",
                skillUpdatedAt: skill.updatedAt,
                referenceSources: reference.sources
            )
        }
    }

    private struct MergedAgentSkillContextReference: Sendable, Equatable {
        var skillId: String
        var requirement: AgentSkillReferenceRequirement
        var rationale: String?
        var sources: [AgentSkillReferenceSource]
    }

    private func mergedAgentSkillContextReferences(
        charterReferences: [AgentSkillReference],
        taskReferences: [AgentSkillTaskReference]
    ) -> [MergedAgentSkillContextReference] {
        var orderedIDs: [String] = []
        var mergedByID: [String: MergedAgentSkillContextReference] = [:]

        func merge(
            skillId rawSkillId: String,
            requirement: AgentSkillReferenceRequirement,
            rationale: String?,
            source: AgentSkillReferenceSource
        ) {
            let skillId = rawSkillId.trimmingCharacters(in: .whitespacesAndNewlines)
            guard skillId.isEmpty == false else { return }
            let key = skillId.lowercased()
            if mergedByID[key] == nil {
                orderedIDs.append(key)
                mergedByID[key] = MergedAgentSkillContextReference(
                    skillId: skillId,
                    requirement: requirement,
                    rationale: trimmedOptionalDecisionText(rationale),
                    sources: [source]
                )
                return
            }
            guard var existing = mergedByID[key] else { return }
            existing.requirement = strongestAgentSkillRequirement(existing.requirement, requirement)
            if let rationale = trimmedOptionalDecisionText(rationale),
               existing.rationale?.contains(rationale) != true {
                let existingRationale = existing.rationale ?? ""
                existing.rationale = existingRationale.isEmpty
                    ? rationale
                    : "\(existingRationale) | \(source.displayTitle): \(rationale)"
            }
            if existing.sources.contains(source) == false {
                existing.sources.append(source)
            }
            mergedByID[key] = existing
        }

        for reference in charterReferences {
            merge(
                skillId: reference.skillId,
                requirement: reference.requirement,
                rationale: reference.rationale,
                source: .analystCharter
            )
        }
        for reference in taskReferences {
            merge(
                skillId: reference.skillId,
                requirement: reference.requirement,
                rationale: reference.rationale,
                source: reference.source
            )
        }

        return orderedIDs.compactMap { mergedByID[$0] }
    }

    private func strongestAgentSkillRequirement(
        _ lhs: AgentSkillReferenceRequirement,
        _ rhs: AgentSkillReferenceRequirement
    ) -> AgentSkillReferenceRequirement {
        func rank(_ requirement: AgentSkillReferenceRequirement) -> Int {
            switch requirement {
            case .available:
                return 0
            case .recommended:
                return 1
            case .required:
                return 2
            }
        }
        return rank(rhs) > rank(lhs) ? rhs : lhs
    }

    private func analystScopedMemorySnapshot(
        analystId: String,
        charterId: String?,
        now: Date
    ) async throws -> AnalystScopedMemorySnapshot {
        let tasks = try await analystTaskStore.loadAll()
        let findings = try await analystFindingStore.loadAll()
        let memos = try await analystMemoStore.loadAll()
        let memory = try await loadOrBootstrapAnalystScopedMemoryRecord(
            analystId: analystId,
            charterId: charterId,
            tasks: tasks,
            findings: findings,
            memos: memos,
            now: now
        )
        return makeAnalystScopedMemorySnapshot(
            memory: memory,
            memosByID: Dictionary(uniqueKeysWithValues: memos.map { ($0.memoId, $0) }),
            findingsByID: Dictionary(uniqueKeysWithValues: findings.map { ($0.findingId, $0) })
        )
    }

    private func loadOrBootstrapAnalystScopedMemoryRecord(
        analystId: String,
        charterId: String?,
        tasks: [AnalystTask],
        findings: [AnalystFinding],
        memos: [AnalystMemo],
        now: Date
    ) async throws -> AnalystScopedMemoryRecord {
        if let existing = try await analystScopedMemoryStore.getByAnalystID(analystId) {
            return existing
        }

        let bootstrapped = bootstrapAnalystScopedMemoryRecord(
            analystId: analystId,
            charterId: charterId,
            tasks: tasks,
            findings: findings,
            memos: memos,
            now: now
        )
        return try await analystScopedMemoryStore.upsert(bootstrapped)
    }

    private func refreshAnalystScopedMemory(
        analystId: String,
        charterId: String?,
        task: AnalystTask? = nil,
        finding: AnalystFinding? = nil,
        memo: AnalystMemo? = nil,
        now: Date
    ) async throws {
        let tasks = try await analystTaskStore.loadAll()
        let findings = try await analystFindingStore.loadAll()
        let memos = try await analystMemoStore.loadAll()
        let existing = try await loadOrBootstrapAnalystScopedMemoryRecord(
            analystId: analystId,
            charterId: charterId,
            tasks: tasks,
            findings: findings,
            memos: memos,
            now: now
        )
        let updated = mergeAnalystScopedMemoryRecord(
            existing: existing,
            task: task,
            finding: finding,
            memo: memo,
            now: now
        )
        _ = try await analystScopedMemoryStore.upsert(updated)
    }

    @discardableResult
    public func draftSignalFromAnalystFinding(
        id: String,
        source: AuditEventSource = .ui
    ) async throws -> Signal {
        guard var finding = try await analystFindingStore.get(id: id) else {
            throw AnalystFindingStoreError.findingNotFound(id: id)
        }

        let bundle: AnalystEvidenceBundle
        guard let bundleID = finding.evidenceBundleId else {
            throw AnalystFindingSignalDraftError.ineligibleFinding(
                id: id,
                reason: "finding is missing an evidence bundle"
            )
        }
        guard let resolvedBundle = try await analystEvidenceBundleStore.get(id: bundleID) else {
            throw AnalystFindingSignalDraftError.ineligibleFinding(
                id: id,
                reason: "linked evidence bundle was not found"
            )
        }
        bundle = resolvedBundle

        let signal = try await makeSignalFromAnalystFinding(finding: finding, bundle: bundle)
        let updatedSignal = try await signalStore.upsert(signal)
        finding.linkedSignalId = updatedSignal.signalId
        _ = try await analystFindingStore.upsert(finding)

        await refreshSignalsSnapshot()
        await publishAnalystPersistenceDiagnostics()
        await store.publishDiagnostic(
            "signal drafted from analyst finding signal_id=\(shortOrderID(updatedSignal.signalId)) finding_id=\(shortOrderID(finding.findingId))",
            source: source,
            action: "analyst_finding_draft_signal"
        )
        return updatedSignal
    }

