    public func launchAnalystWorkerOnce(
        charterID: String,
        taskID: String? = nil,
        intendedRuntimePolicy: AnalystRuntimePolicy? = nil,
        draftSignal: Bool = false,
        draftProposal: Bool = false,
        source: AuditEventSource = .ui
    ) async throws -> AnalystWorkerLaunchResult {
        let trimmedCharterID = charterID.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmedCharterID.isEmpty else {
            throw AnalystWorkerLaunchError.workerLaunchFailed(reason: "charter id is required")
        }

        let trimmedTaskID = taskID?.trimmingCharacters(in: .whitespacesAndNewlines)
        let resolvedTaskID = (trimmedTaskID?.isEmpty == false) ? trimmedTaskID : nil
        if let resolvedTaskID {
            let existingTask = try await analystTaskStore.get(id: resolvedTaskID)
            if let existingTask, existingTask.contextPack == nil {
                let resolvedCharterID: String
                if let taskCharterID = existingTask.charterId?.trimmingCharacters(in: .whitespacesAndNewlines),
                   taskCharterID.isEmpty == false {
                    resolvedCharterID = taskCharterID
                } else {
                    resolvedCharterID = trimmedCharterID
                }
                let charter = try await getAnalystCharter(id: resolvedCharterID)
                let snapshot = await store.snapshot()
                let recentNews = try await newsStore.listRecent(limit: 20, since: nil)
                let strategyBrief = try await getPortfolioStrategyBrief()
                var enrichedTask = existingTask
                enrichedTask.contextPack = try await buildAnalystContextPack(
                    charter: charter,
                    pmID: nil,
                    snapshot: snapshot,
                    recentNews: recentNews,
                    strategyBrief: strategyBrief,
                    taskSkillReferences: existingTask.pmTaskingBrief?.selectedSkillReferences ?? [],
                    assembledAt: nowDate()
                )
                _ = try await upsertAnalystTask(enrichedTask, source: .engine)
            }
        }

        do {
            try await prepareAnalystWorkerIPCIfNeeded(source: source)
            let result = try await analystWorkerLauncher.runOnce(
                request: AnalystWorkerLaunchRequest(
                    charterId: trimmedCharterID,
                    taskId: resolvedTaskID,
                    intendedRuntimePolicy: intendedRuntimePolicy,
                    draftSignal: draftSignal,
                    draftProposal: draftProposal
                )
            )
            let runtimeText = result.runtimeProvenance.map {
                " runtime=\($0.actualRuntimeIdentifier)"
            } ?? ""
            let memoText = result.memoId.map { " memo=\(shortOrderID($0))" } ?? ""
            let signalText = result.draftedSignalId.map { " signal=\(shortOrderID($0))" } ?? ""
            let proposalText = result.draftedProposalId.map { " proposal=\(shortOrderID($0))" } ?? ""
            let externalText: String
            if let status = result.externalEvidenceStatus, status != "ok" {
                let detail = result.externalEvidenceIssueSummary ?? status
                externalText = " external=\(detail)"
            } else {
                externalText = ""
            }
            await store.publishDiagnostic(
                "analyst worker completed charter=\(shortOrderID(result.charterId)) task=\(result.taskId.map(shortOrderID) ?? "-")\(memoText) finding=\(result.findingId.map(shortOrderID) ?? "-")\(signalText)\(proposalText)\(runtimeText)\(externalText)",
                source: source,
                action: "analyst_worker_launch_completed"
            )
            return result
        } catch {
            await store.publishDiagnostic(
                "analyst worker launch failed charter=\(shortOrderID(trimmedCharterID)) task=\(trimmedTaskID.map(shortOrderID) ?? "-") reason=\(error.localizedDescription)",
                source: source,
                action: "analyst_worker_launch_failed"
            )
            throw error
        }
    }

    public func launchAnalystWorkerForPMDelegation(
        delegationID: String,
        draftSignal: Bool = false,
        draftProposal: Bool = false,
        source: AuditEventSource = .ui
    ) async throws -> AnalystWorkerLaunchResult {
        let trimmedDelegationID = delegationID.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmedDelegationID.isEmpty else {
            throw AnalystWorkerLaunchError.workerLaunchFailed(reason: "delegation id is required")
        }
        if draftProposal && draftSignal == false {
            throw AnalystWorkerLaunchError.workerLaunchFailed(reason: "proposal drafting requires draftSignal")
        }

        let delegation = try await validatedPMDelegation(try await getPMDelegation(id: trimmedDelegationID))
        let charter = try await getAnalystCharter(id: delegation.charterId)
        if let taskID = delegation.taskId,
           var task = try await analystTaskStore.get(id: taskID),
           task.contextPack == nil {
            let snapshot = await store.snapshot()
            let recentNews = try await newsStore.listRecent(limit: 20, since: nil)
            let strategyBrief = try await getPortfolioStrategyBrief()
            task.contextPack = try await buildAnalystContextPack(
                charter: charter,
                pmID: delegation.pmId,
                snapshot: snapshot,
                recentNews: recentNews,
                strategyBrief: strategyBrief,
                taskSkillReferences: task.pmTaskingBrief?.selectedSkillReferences
                    ?? delegation.taskingBrief?.selectedSkillReferences
                    ?? [],
                assembledAt: nowDate()
            )
            _ = try await upsertAnalystTask(task, source: .engine)
        }

        let resolvedRuntimePolicy = try await resolvedRuntimePolicy(
            delegationRuntimeOverride: delegation.runtimePolicyOverride,
            charter: charter,
            now: nowDate()
        )
        let launchStartedAt = Date()
        var runningDelegation = delegation
        runningDelegation.lastLaunch = PMDelegationLastLaunch(
            launchedAt: launchStartedAt,
            status: .running,
            summary: "Analyst worker launched and is awaiting progress updates.",
            lastProgressAt: launchStartedAt,
            progressStage: "launch_started",
            completedAt: nil
        )
        runningDelegation.updatedAt = launchStartedAt
        _ = try await upsertPMDelegation(runningDelegation, source: source)

        do {
            try await prepareAnalystWorkerIPCIfNeeded(source: source)
            let result = try await analystWorkerLauncher.runOnce(
                request: AnalystWorkerLaunchRequest(
                    charterId: charter.charterId,
                    taskId: delegation.taskId,
                    delegationId: delegation.delegationId,
                    pmId: delegation.pmId,
                    intendedRuntimePolicy: resolvedRuntimePolicy,
                    draftSignal: draftSignal,
                    draftProposal: draftProposal
                ),
                onProgress: { [pmDelegationStore] update in
                    Task.detached {
                        await Self.recordPMDelegationLaunchProgress(
                            pmDelegationStore: pmDelegationStore,
                            delegationID: trimmedDelegationID,
                            update: update
                        )
                    }
                }
            )
            var updatedDelegation = try await validatedPMDelegation(try await getPMDelegation(id: trimmedDelegationID))
            updatedDelegation.status = .completed
            let launchStatus: PMDelegationLastLaunchStatus
            let launchSummary: String
            let launchIssueSummary = result.synthesisIssueSummary ?? result.externalEvidenceIssueSummary
            if let synthesisStatus = result.synthesisStatus,
               synthesisStatus == "fallback_missing_openai_key" {
                launchStatus = .healthy
                launchSummary = "Local deterministic fallback: OpenAI API key missing for this run."
            } else if let synthesisStatus = result.synthesisStatus,
                      synthesisStatus == "fallback_openai_error" {
                launchStatus = .healthy
                launchSummary = launchIssueSummary.map {
                    "Local deterministic fallback after OpenAI path issue: \($0)"
                } ?? "Local deterministic fallback after OpenAI path issue."
            } else if let externalStatus = result.externalEvidenceStatus,
                      externalStatus != "ok" {
                launchStatus = .degradedExternalEvidence
                if let issueSummary = result.externalEvidenceIssueSummary,
                   !issueSummary.isEmpty {
                    launchSummary = "Degraded external evidence: \(issueSummary)"
                } else {
                    launchSummary = result.summary
                }
            } else {
                launchStatus = .healthy
                launchSummary = result.summary
            }
            let completedAt = Date()
            updatedDelegation.lastLaunch = PMDelegationLastLaunch(
                launchedAt: updatedDelegation.lastLaunch?.launchedAt ?? result.runtimeProvenance?.launchedAt ?? completedAt,
                status: launchStatus,
                summary: launchSummary,
                lastProgressAt: completedAt,
                progressStage: "completed",
                lastIssueSummary: launchIssueSummary,
                completedAt: completedAt
            )
            if let findingID = result.findingId {
                updatedDelegation.linkedFindingIDs = appendUnique(findingID, to: updatedDelegation.linkedFindingIDs)
            }
            if let signalID = result.draftedSignalId {
                updatedDelegation.linkedSignalIDs = appendUnique(signalID, to: updatedDelegation.linkedSignalIDs)
            }
            if let proposalID = result.draftedProposalId {
                updatedDelegation.linkedProposalIDs = appendUnique(proposalID, to: updatedDelegation.linkedProposalIDs)
            }
            if let runtimeProvenance = result.runtimeProvenance {
                updatedDelegation.lastRuntimeProvenance = runtimeProvenance
            } else if let resolvedRuntimePolicy {
                updatedDelegation.lastRuntimeProvenance = AnalystRuntimeProvenance(
                    intendedPolicy: resolvedRuntimePolicy,
                    actualRuntimeIdentifier: resolvedRuntimePolicy.runtimeIdentifier,
                    actualReasoningMode: resolvedRuntimePolicy.reasoningMode,
                    launchedAt: Date()
                )
            }
            updatedDelegation.updatedAt = Date()
            _ = try await upsertPMDelegation(updatedDelegation, source: source)
            await refreshPortfolioRiskReviewAnchorIfNeeded(
                delegation: updatedDelegation,
                charter: charter,
                source: source
            )

            let runtimeText = result.runtimeProvenance.map {
                " runtime=\($0.actualRuntimeIdentifier)"
            } ?? ""
            let memoText = result.memoId.map { " memo=\(shortOrderID($0))" } ?? ""
            await store.publishDiagnostic(
                "pm delegation launched delegation=\(shortOrderID(updatedDelegation.delegationId)) pm=\(shortOrderID(updatedDelegation.pmId)) charter=\(shortOrderID(updatedDelegation.charterId)) task=\(updatedDelegation.taskId.map(shortOrderID) ?? "-")\(memoText) finding=\(result.findingId.map(shortOrderID) ?? "-") signal=\(result.draftedSignalId.map(shortOrderID) ?? "-") proposal=\(result.draftedProposalId.map(shortOrderID) ?? "-")\(runtimeText)",
                source: source,
                action: "pm_delegation_launch_completed"
            )
            return result
        } catch {
            var failedDelegation = delegation
            failedDelegation.lastLaunch = PMDelegationLastLaunch(
                launchedAt: failedDelegation.lastLaunch?.launchedAt ?? Date(),
                status: .failed,
                summary: error.localizedDescription,
                lastProgressAt: Date(),
                progressStage: "failed",
                lastIssueSummary: error.localizedDescription,
                completedAt: Date()
            )
            failedDelegation.updatedAt = Date()
            _ = try? await upsertPMDelegation(failedDelegation, source: source)
            await store.publishDiagnostic(
                "pm delegation launch failed delegation=\(shortOrderID(trimmedDelegationID)) pm=\(shortOrderID(delegation.pmId)) reason=\(error.localizedDescription)",
                source: source,
                action: "pm_delegation_launch_failed"
            )
            throw error
        }
    }

    private struct AnalystWorkerIPCPreflightIssue: Sendable, Equatable {
        var category: String
        var host: String
        var port: Int?
        var tokenPresent: Bool
        var metadataSource: String
        var detail: String?

        var boundedSummary: String {
            var parts = [
                "category=\(category)",
                "host=\(host)",
                "port=\(port.map(String.init) ?? "-")",
                "token_present=\(tokenPresent)",
                "metadata=\(metadataSource)"
            ]
            if let detail,
               detail.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty == false {
                parts.append("detail=\(detail)")
            }
            return parts.joined(separator: " ")
        }
    }

    private func prepareAnalystWorkerIPCIfNeeded(source: AuditEventSource) async throws {
        guard analystWorkerLauncher.requiresAppIPCServer else {
            return
        }

        if ipcServer == nil || ipcPort == nil || ipcAuthToken == nil {
            await store.publishDiagnostic(
                "worker IPC preflight starting IPC server because in-memory worker link was unavailable",
                source: source,
                level: .warning,
                action: "analyst_worker_ipc_preflight",
                errorCode: "ipc_not_running"
            )
            await startIPCServer()
        }

        if let issue = await analystWorkerIPCPreflightIssue() {
            await store.publishDiagnostic(
                "worker IPC preflight failed \(issue.boundedSummary) restart_attempt=true",
                source: source,
                level: .warning,
                action: "analyst_worker_ipc_preflight",
                errorCode: "ipc_unreachable"
            )
            await stopIPCServer()
            await startIPCServer()

            if let retryIssue = await analystWorkerIPCPreflightIssue() {
                await store.publishDiagnostic(
                    "worker IPC preflight failed after restart \(retryIssue.boundedSummary)",
                    source: source,
                    level: .error,
                    action: "analyst_worker_ipc_preflight",
                    errorCode: "ipc_unreachable_after_restart"
                )
                throw AnalystWorkerLaunchError.workerLaunchFailed(
                    reason: "worker IPC link unavailable after restart: \(retryIssue.boundedSummary)"
                )
            }

            await store.publishDiagnostic(
                "worker IPC preflight restarted loopback server successfully",
                source: source,
                action: "analyst_worker_ipc_preflight"
            )
        }
    }

    private func analystWorkerIPCPreflightIssue() async -> AnalystWorkerIPCPreflightIssue? {
        let metadataSource = workerIPCMetadataSourceLabel()
        let runtimeInfo: AgentControlRuntimeInfo
        do {
            runtimeInfo = try ipcRuntimeInfoStore.load()
        } catch let error as AgentControlRuntimeInfoStoreError {
            let category: String
            switch error {
            case .missingFile:
                category = "missing_runtime_metadata"
            case .invalidFile:
                category = "invalid_runtime_metadata"
            case .unsupportedPath:
                category = "unsupported_runtime_metadata_path"
            }
            return AnalystWorkerIPCPreflightIssue(
                category: category,
                host: "127.0.0.1",
                port: nil,
                tokenPresent: false,
                metadataSource: metadataSource,
                detail: nil
            )
        } catch {
            return AnalystWorkerIPCPreflightIssue(
                category: "runtime_metadata_error",
                host: "127.0.0.1",
                port: nil,
                tokenPresent: false,
                metadataSource: metadataSource,
                detail: boundedWorkerIPCDetail(error.localizedDescription)
            )
        }

        guard let url = URL(string: "http://\(runtimeInfo.host):\(runtimeInfo.port)/status") else {
            return AnalystWorkerIPCPreflightIssue(
                category: "invalid_url",
                host: runtimeInfo.host,
                port: runtimeInfo.port,
                tokenPresent: runtimeInfo.token.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty == false,
                metadataSource: metadataSource,
                detail: nil
            )
        }

        var request = URLRequest(url: url)
        request.httpMethod = "GET"
        request.timeoutInterval = 2
        request.setValue(runtimeInfo.token, forHTTPHeaderField: "X-Agent-Token")
        request.setValue("application/json", forHTTPHeaderField: "Accept")

        let session = URLSession(configuration: .ephemeral)
        defer {
            session.finishTasksAndInvalidate()
        }

        let data: Data
        let response: URLResponse
        do {
            (data, response) = try await session.data(for: request)
        } catch {
            return AnalystWorkerIPCPreflightIssue(
                category: workerIPCTransportCategory(error),
                host: runtimeInfo.host,
                port: runtimeInfo.port,
                tokenPresent: runtimeInfo.token.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty == false,
                metadataSource: metadataSource,
                detail: nil
            )
        }

        guard let http = response as? HTTPURLResponse else {
            return AnalystWorkerIPCPreflightIssue(
                category: "invalid_response",
                host: runtimeInfo.host,
                port: runtimeInfo.port,
                tokenPresent: runtimeInfo.token.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty == false,
                metadataSource: metadataSource,
                detail: nil
            )
        }

        let envelope = try? JSONDecoder().decode(AgentControlEnvelope.self, from: data)
        if http.statusCode == 401 || envelope?.error?.code == "unauthorized" {
            return AnalystWorkerIPCPreflightIssue(
                category: "unauthorized",
                host: runtimeInfo.host,
                port: runtimeInfo.port,
                tokenPresent: runtimeInfo.token.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty == false,
                metadataSource: metadataSource,
                detail: nil
            )
        }
        guard http.statusCode >= 200, http.statusCode < 300 else {
            return AnalystWorkerIPCPreflightIssue(
                category: "http_status",
                host: runtimeInfo.host,
                port: runtimeInfo.port,
                tokenPresent: runtimeInfo.token.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty == false,
                metadataSource: metadataSource,
                detail: "status=\(http.statusCode)"
            )
        }
        guard envelope?.ok == true else {
            return AnalystWorkerIPCPreflightIssue(
                category: envelope?.error?.code ?? "invalid_envelope",
                host: runtimeInfo.host,
                port: runtimeInfo.port,
                tokenPresent: runtimeInfo.token.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty == false,
                metadataSource: metadataSource,
                detail: boundedWorkerIPCDetail(envelope?.error?.message)
            )
        }
        return nil
    }

    private func workerIPCMetadataSourceLabel() -> String {
        guard let url = try? ipcRuntimeInfoStore.fileURL().standardizedFileURL else {
            return "unknown"
        }
        let root = AppSupportPaths.rootDirectory().standardizedFileURL
        if url.path.hasPrefix(root.path) {
            return "app_support/\(url.lastPathComponent)"
        }
        return url.lastPathComponent
    }

    private nonisolated func workerIPCTransportCategory(_ error: Error) -> String {
        let nsError = error as NSError
        if let underlying = nsError.userInfo[NSUnderlyingErrorKey] as? NSError,
           underlying.domain == NSPOSIXErrorDomain,
           underlying.code == ECONNREFUSED {
            return "connection_refused"
        }
        guard nsError.domain == NSURLErrorDomain else {
            return "transport_error"
        }
        switch nsError.code {
        case NSURLErrorCannotConnectToHost:
            return "connection_refused"
        case NSURLErrorTimedOut:
            return "timed_out"
        case NSURLErrorNetworkConnectionLost:
            return "network_connection_lost"
        case NSURLErrorCannotFindHost:
            return "cannot_find_host"
        case NSURLErrorNotConnectedToInternet:
            return "not_connected"
        default:
            return "transport_error"
        }
    }

    private nonisolated func boundedWorkerIPCDetail(_ raw: String?) -> String? {
        guard let raw else {
            return nil
        }
        let trimmed = raw
            .replacingOccurrences(of: "\n", with: " ")
            .trimmingCharacters(in: .whitespacesAndNewlines)
        guard trimmed.isEmpty == false else {
            return nil
        }
        return String(trimmed.prefix(160))
    }

    private static func recordPMDelegationLaunchProgress(
        pmDelegationStore: PMDelegationStore,
        delegationID: String,
        update: AnalystWorkerProgressUpdate
    ) async {
        guard var delegation = try? await pmDelegationStore.get(id: delegationID) else {
            return
        }
        guard delegation.status != .canceled else {
            return
        }
        if let completedAt = delegation.lastLaunch?.completedAt,
           completedAt >= update.reportedAt {
            return
        }
        if let lastProgressAt = delegation.lastLaunch?.lastProgressAt,
           lastProgressAt > update.reportedAt {
            return
        }

        delegation.lastLaunch = PMDelegationLastLaunch(
            launchedAt: delegation.lastLaunch?.launchedAt ?? update.reportedAt,
            status: .progressing,
            summary: update.summary,
            lastProgressAt: update.reportedAt,
            progressStage: update.stage,
            lastIssueSummary: update.issueSummary,
            completedAt: nil
        )
        delegation.updatedAt = update.reportedAt
        _ = try? await pmDelegationStore.upsert(delegation)
    }

