    @discardableResult
    public func draftProposalFromSignal(
        id: String,
        strategyID: String = "heartbeat",
        source: AuditEventSource = .ui
    ) async throws -> StrategyProposal {
        guard var signal = try await signalStore.get(id: id) else {
            throw SignalStoreError.signalNotFound(id: id)
        }

        let proposalID = try await draftProposalFromSignal(
            signal: signal,
            strategyID: strategyID,
            sourceJobID: "ui.signal_draft",
            source: source
        )
        signal.draftedProposalId = proposalID
        signal.linkedProposalId = proposalID
        _ = try await signalStore.upsert(signal)
        await refreshSignalsSnapshot()
        await refreshProposalsSnapshot()

        guard let proposal = try await proposalStore.getProposal(id: proposalID) else {
            throw ProposalStoreError.proposalNotFound(id: proposalID)
        }
        return proposal
    }

    @discardableResult
    public func draftProposalFromAnalystSignal(
        id: String,
        strategyID: String = "heartbeat",
        source: AuditEventSource = .ui
    ) async throws -> StrategyProposal {
        guard let signal = try await signalStore.get(id: id) else {
            throw SignalStoreError.signalNotFound(id: id)
        }
        try validateAnalystSignalEligibleForProposal(signal)
        return try await draftProposalFromSignal(id: id, strategyID: strategyID, source: source)
    }

    public func replayQuick(
        proposalID: String,
        symbols: [String],
        timeframe: BarTimeframe,
        days: Int,
        end: Date?,
        speed: ReplaySpeed,
        autoIngest: Bool,
        feed: ReplayFeed,
        simulateTrades: Bool = false,
        allowTradingInReplay: Bool = false,
        fillPolicy: ReplayFillPolicy = .nextOpenMarket,
        slippageBps: ReplaySlippageBps = ReplaySlippageBps(),
        source: AuditEventSource = .ipc
    ) async throws -> ReplayRunResult {
        let window = try ReplayWindow.resolve(days: days, end: end, now: nowDate)
        let request = ReplayRunRequest(
            proposalID: proposalID,
            symbols: symbols,
            timeframe: timeframe,
            start: window.start,
            end: window.end,
            speed: speed,
            autoIngest: autoIngest,
            feed: feed,
            simulateTrades: simulateTrades,
            allowTradingInReplay: allowTradingInReplay,
            fillPolicy: fillPolicy,
            slippageBps: slippageBps
        )
        return try await replayRun(request: request, source: source)
    }

    private func replayRun(
        request: ReplayRunRequest,
        source: AuditEventSource
    ) async throws -> ReplayRunResult {
        guard configuration.environment == .paper else {
            throw StrategyProposalExecutionError.proposalRequiresPaperEnvironment(
                proposalId: request.proposalID
            )
        }

        let normalizedSymbols = Array(MarketDataSubscriptionSet.normalized(request.symbols)).sorted()
        guard !normalizedSymbols.isEmpty else {
            throw ReplayError.invalidSymbols
        }
        guard request.start < request.end else {
            throw ReplayError.invalidDateRange
        }

        guard let proposal = try await proposalStore.getProposal(id: request.proposalID) else {
            throw ProposalStoreError.proposalNotFound(id: request.proposalID)
        }
        guard proposal.approval.status == .approvedPaper else {
            throw StrategyProposalExecutionError.strategyNotApprovedForPaper(
                proposalId: proposal.proposalId
            )
        }

        let replaySimulation = ReplaySimulationConfig(
            simulateTrades: request.simulateTrades,
            allowTradingInReplay: request.allowTradingInReplay,
            fillPolicy: request.fillPolicy,
            slippageBps: request.slippageBps
        )
        if replaySimulation.simulateTrades && !replaySimulation.allowTradingInReplay {
            throw ReplayError.replaySimulationNotEnabled
        }
        let simulateTrades = replaySimulation.simulateTrades && replaySimulation.allowTradingInReplay

        var barsIngested = 0
        if request.autoIngest {
            let ingestResult = try await barsIngestService.ingest(
                ReplayIngestRequest(
                    symbols: normalizedSymbols,
                    timeframe: request.timeframe,
                    start: request.start,
                    end: request.end,
                    feed: request.feed
                )
            )
            barsIngested = ingestResult.barsIngested
        }

        let bars = try await barsCache.queryBars(
            symbols: normalizedSymbols,
            timeframe: request.timeframe,
            start: request.start,
            end: request.end
        )
        guard !bars.isEmpty else {
            throw ReplayError.noBarsInCache
        }

        let runID = UUID().uuidString
        let runStartedAt = request.start
        var startingEquity = await currentAccountEquity()
        var startingCash: Decimal?
        if simulateTrades {
            let defaultCash = startingEquity ?? Decimal(100_000)
            startingCash = defaultCash
            startingEquity = defaultCash
        }
        let runRecord = PaperRunRecord(
            runId: runID,
            proposalId: proposal.proposalId,
            strategyId: proposal.strategyId,
            startedAt: runStartedAt,
            endedAt: nil,
            status: .running,
            stopReason: nil,
            runType: .replay,
            environment: .paper,
            dataSource: ReplayDataSource(
                provider: "alpaca",
                cache: "sqlite",
                symbols: normalizedSymbols,
                timeframe: request.timeframe,
                start: request.start,
                end: request.end,
                feed: request.feed
            ),
            replaySimulation: ReplaySimulationMetadata(
                simulateTrades: replaySimulation.simulateTrades,
                allowTradingInReplay: replaySimulation.allowTradingInReplay,
                fillPolicy: replaySimulation.fillPolicy,
                slippageBps: replaySimulation.slippageBps
            ),
            parametersSnapshot: proposal.parameters,
            constraintsSnapshot: proposal.constraints,
            metrics: PaperRunMetrics(
                lastUpdatedAt: runStartedAt,
                startingCash: startingCash,
                endingCash: startingCash,
                startingEquity: startingEquity,
                endingEquity: startingEquity
            )
        )

        let simBroker: SimBroker? = simulateTrades
            ? SimBroker(
                simulation: replaySimulation,
                initialCash: startingCash ?? 100_000,
                initialTime: request.start,
                orderIDPrefix: "sim-\(proposal.strategyId)"
            )
            : nil

        _ = try await startStrategyInternal(
            id: proposal.strategyId,
            params: proposal.parameters,
            source: source,
            proposalID: proposal.proposalId,
            proposalConstraints: proposal.constraints
        )
        _ = try await paperRunStore.createRun(runRecord)
        activePaperRunsByRunID[runID] = runRecord
        activeRunIDByStrategyID[proposal.strategyId] = runID
        activeReplayRunIDByStrategyID[proposal.strategyId] = runID
        if let simBroker {
            replaySimBrokerByStrategyID[proposal.strategyId] = simBroker
            replayCurrentTimeByStrategyID[proposal.strategyId] = request.start
            await applyReplayAccountSnapshot(
                runID: runID,
                snapshot: await simBroker.snapshot(),
                at: request.start
            )
        } else {
            replaySimBrokerByStrategyID[proposal.strategyId] = nil
            replayCurrentTimeByStrategyID[proposal.strategyId] = request.start
        }
        dirtyRunIDs.remove(runID)
        await refreshProposalRunsSnapshot(proposalID: proposal.proposalId)

        do {
            let runner = ReplayRunner(
                clock: ReplayClock(
                    speed: request.speed,
                    sleep: replaySleep
                )
            )
            let progress = await runner.run(bars: bars) { [weak self] bar in
                await self?.processReplayBar(
                    strategyID: proposal.strategyId,
                    runID: runID,
                    bar: bar
                )
            }

            await applyReplayProgress(
                runID: runID,
                barsProcessed: progress.barsProcessed,
                symbolsSeen: Set(progress.symbolsSeen),
                at: bars.last?.timestamp ?? request.start
            )

            if let simBroker {
                replayCurrentTimeByStrategyID[proposal.strategyId] = request.end
                let finalTick = await simBroker.finalize(endTime: request.end)
                for event in finalTick.events {
                    await processTradeUpdate(event, allowRESTRepairs: false)
                }
                await applyReplayAccountSnapshot(
                    runID: runID,
                    snapshot: finalTick.accountSnapshot,
                    at: request.end
                )
            }

            _ = try await strategyRunner.stop(id: proposal.strategyId)
            await finalizePaperRunIfActive(
                strategyID: proposal.strategyId,
                status: .stopped,
                stopReason: "duration_elapsed",
                source: source
            )
            return ReplayRunResult(
                runID: runID,
                proposalID: proposal.proposalId,
                barsProcessed: progress.barsProcessed,
                barsIngested: barsIngested,
                speed: request.speed,
                simulateTrades: simulateTrades,
                fillPolicy: replaySimulation.fillPolicy,
                slippageBps: replaySimulation.slippageBps
            )
        } catch {
            _ = try? await strategyRunner.stop(id: proposal.strategyId)
            await finalizePaperRunIfActive(
                strategyID: proposal.strategyId,
                status: .error,
                stopReason: "error",
                source: source
            )
            throw error
        }
    }

    @discardableResult
    public func upsertProposal(
        _ proposal: StrategyProposal,
        source: AuditEventSource = .ui
    ) async throws -> StrategyProposal {
        let previous = try await proposalStore.getProposal(id: proposal.proposalId)
        let updated = try await proposalStore.upsertProposal(proposal)
        await refreshProposalsSnapshot()
        await store.publishDiagnostic(
            previous == nil
                ? "proposal created id=\(updated.proposalId) strategy_id=\(updated.strategyId)"
                : "proposal updated id=\(updated.proposalId) strategy_id=\(updated.strategyId)",
            source: source,
            strategyID: updated.strategyId,
            action: previous == nil ? "proposal_created" : "proposal_updated"
        )
        return updated
    }

