    @discardableResult
    public func armLiveTrading() async -> String? {
        guard configuration.environment == .live else {
            isArmedForLiveTrading = false
            armingSessionID = nil
            await publishTradingSafetyState()
            return nil
        }

        isArmedForLiveTrading = true
        armingSessionID = newArmingSessionID()
        blockedActionAuditStateByKey.removeAll()
        let shortID = shortSessionID(armingSessionID)
        await store.publishDiagnostic("live trading armed session=\(shortID)")
        await publishTradingSafetyState()
        if isStarted {
            await requestConnectivityRecoveryAfterModeChange(trigger: "live_arm")
        }
        return armingSessionID
    }

    public func disarmLiveTrading() async {
        guard isArmedForLiveTrading || armingSessionID != nil else {
            await publishTradingSafetyState()
            return
        }

        isArmedForLiveTrading = false
        armingSessionID = nil
        blockedActionAuditStateByKey.removeAll()
        await store.publishDiagnostic("live trading disarmed")
        await publishTradingSafetyState()
    }

    public func setKillSwitchEnabled(_ enabled: Bool) async {
        guard killSwitchEnabled != enabled else {
            await publishTradingSafetyState()
            return
        }
        killSwitchEnabled = enabled
        blockedActionAuditStateByKey.removeAll()
        await store.publishDiagnostic("kill switch \(enabled ? "enabled" : "disabled")")
        await publishTradingSafetyState()
    }

    public func setEnvironment(_ environment: Environment) async {
        guard configuration.environment != environment else {
            return
        }
        configuration.environment = environment
        restClient = restClientFactory(environment)
        alpacaNewsClient = nil
        barsProvider = barsProviderFactory(environment)
        barsIngestService = BarsIngestService(
            barsProvider: barsProvider,
            barsCache: barsCache
        )
        lastKnownAccount = nil
        assetCache.removeAll()
        optionContractCache.removeAll()
        blockedActionAuditStateByKey.removeAll()

        if environment == .live {
            isArmedForLiveTrading = false
            armingSessionID = nil
            await store.publishDiagnostic("live trading disarmed by default for new live session")
        } else {
            isArmedForLiveTrading = false
            armingSessionID = nil
        }
        await publishTradingSafetyState()

        await tradeUpdatesStream.updateEnvironment(environment)
        await marketDataStream.updateEnvironment(environment)
        guard isStarted else {
            return
        }
        await requestConnectivityRecoveryAfterModeChange(trigger: "environment_change")
    }

    public func setMarketDataFeed(_ feed: MarketDataFeed) async {
        guard configuration.marketDataFeed != feed else {
            return
        }

        configuration.marketDataFeed = feed
        await marketDataStream.updateFeed(feed)
        await store.publishDiagnostic("market_data feed set to \(feed.displayName.lowercased())")

        guard isStarted else {
            return
        }

        var watchlistSymbols = await store.snapshot().watchlistSymbols
        if feed == .test, watchlistSymbols.isEmpty {
            watchlistSymbols = ["FAKEPACA"]
            watchlistPersistence.saveWatchlistSymbols(watchlistSymbols)
            await store.setWatchlistSymbols(watchlistSymbols)
        }
        await requestConnectivityRecoveryAfterModeChange(trigger: "feed_change")
        await syncMarketDataLifecycle(watchlistSymbols: watchlistSymbols)
    }

    public func start() async {
        guard !isStarted else {
            return
        }
        isStarted = true
        lastRecoveryStartedAt = nowDate()
        await publishAlwaysOnRecovering(event: .engineStart)
        await configureJobRunnerIfNeeded()
        await store.enableDefaultAuditPersistenceIfNeeded()
        if configuration.environment == .live {
            isArmedForLiveTrading = false
            armingSessionID = nil
            await store.publishDiagnostic("live trading disarmed on app start")
        } else {
            isArmedForLiveTrading = false
            armingSessionID = nil
        }
        await publishTradingSafetyState()
        await startIPCServer()
        if let primaryPM = try? await ensurePrimaryPMProfile(source: .engine) {
            _ = try? await ensurePMOperatingGuideInstruction(pmId: primaryPM.pmId, source: .engine)
        }
        _ = try? await ensureAgentSkillsSeeded(source: .engine)
        async let credentialPreflight: Void = performLaunchTimeCredentialPreflightIfNeeded()
        async let startupReconciliation: Void = runStartupReconciliation()
        _ = await credentialPreflight
        _ = await startupReconciliation

        var watchlistSymbols = Array(
            MarketDataSubscriptionSet.normalized(
                watchlistPersistence.loadWatchlistSymbols()
            )
        ).sorted()
        if configuration.marketDataFeed == .test, watchlistSymbols.isEmpty {
            watchlistSymbols = ["FAKEPACA"]
            watchlistPersistence.saveWatchlistSymbols(watchlistSymbols)
            await store.publishDiagnostic("watchlist initialized to FAKEPACA for test market-data feed")
        }
        await store.setWatchlistSymbols(watchlistSymbols)
        await refreshProposalsSnapshot()
        await refreshJobsSnapshot()
        await refreshSchedulesSnapshot()
        await refreshRSSFeedsSnapshot()
        await reconcilePersistedRSSNewsSources(trigger: "engine_start", force: true)
        await refreshBuiltInNewsSourceState()
        await refreshNewsSnapshot()
        await refreshSignalsSnapshot()
        _ = await maintenanceService.loadPolicy()
        await publishRetentionPolicyPersistenceDiagnostics()
        await jobRunner.resumePendingJobsOnStartup()
        await scheduler.start()
        await refreshSchedulesSnapshot()
        do {
            _ = try await triggerPMStandingReviewWakeIfNeeded(
                trigger: .engineReady,
                source: .engine
            )
        } catch {
            await store.publishDiagnostic(
                "pm standing review wake degraded trigger=engine_ready reason=\(error.localizedDescription)",
                source: .engine,
                action: "pm_standing_review_wake_failed"
            )
        }
        do {
            let cleanupSummary = try await closeLingeringBackgroundStandingReviewArtifacts(
                source: .engine
            )
            if cleanupSummary.didChange {
                await store.publishDiagnostic(
                    "pm standing review startup cleanup closed stale background artifacts requests=\(cleanupSummary.withdrawnApprovalRequests) decisions=\(cleanupSummary.withdrawnDecisions)",
                    source: .engine,
                    action: "pm_standing_review_cleanup"
                )
                await store.publish(StoreEvent(name: "pm_standing_review_cycle_closed"))
            }
        } catch {
            await store.publishDiagnostic(
                "pm standing review cleanup degraded reason=\(error.localizedDescription)",
                source: .engine,
                action: "pm_standing_review_cleanup_failed"
            )
        }

        await ensureTradeUpdatesPipelineStarted()

        await syncMarketDataLifecycle(watchlistSymbols: watchlistSymbols)
        await resumeApprovedPendingPaperPortfolioExecutionsIfNeeded(source: .engine)
        await store.setStrategyStatuses(await strategyRunner.statuses())
        strategyRunMonitorTask = Task { [weak self] in
            await self?.monitorStrategyRuns()
        }
        lastRecoveryCompletedAt = nowDate()
        await publishDerivedAlwaysOnReadiness(event: .engineStart)
    }

    public func handleHostAvailabilityEvent(_ event: HostAvailabilityEvent) async {
        lastHostLifecycleEvent = event

        switch event {
        case .hostWillSleep:
            await publishAlwaysOnPaused(event: event)
        case .appBecameInactive, .appEnteredBackground:
            await publishDerivedAlwaysOnReadiness(event: event)
        case .engineStart, .appBecameActive, .hostDidWake, .manualRecovery:
            guard isStarted else {
                await publishDerivedAlwaysOnReadiness(event: event)
                return
            }
            if event == .appBecameActive,
               let lastRecoveryStartedAt,
               nowDate().timeIntervalSince(lastRecoveryStartedAt) < hostActiveRecoveryMinimumInterval {
                await publishDerivedAlwaysOnReadiness(event: event)
                return
            }
            await performHostResumeRecovery(event: event)
        }
    }

    private func performHostResumeRecovery(event: HostAvailabilityEvent) async {
        let startedAt = nowDate()
        lastRecoveryStartedAt = startedAt
        await publishAlwaysOnRecovering(event: event)
        await publishHostResumeCredentialReadiness(event: event)
        await runStartupReconciliation()
        await restartTradeUpdatesAfterHostResumeIfNeeded()

        let watchlistSymbols = await store.snapshot().watchlistSymbols
        let marketDataSymbols = await portfolioWatchMarketDataCoverageSymbols(
            watchlistSymbols: watchlistSymbols
        )
        if shouldRunMarketData(for: marketDataSymbols) {
            await restartMarketDataAfterHostResume(subscriptionSymbols: marketDataSymbols)
        } else {
            await stopMarketDataPipeline()
        }

        do {
            try await scheduler.recoverAfterWake()
        } catch {
            await store.publishDiagnostic(
                "scheduler wake recovery degraded reason=\(error.localizedDescription)",
                source: .engine,
                action: "schedule_wake_recovery_failed"
            )
        }
        await refreshJobsSnapshot()
        await refreshSchedulesSnapshot()
        await resumeApprovedPendingPaperPortfolioExecutionsIfNeeded(source: .engine)
        lastRecoveryCompletedAt = nowDate()
        await publishDerivedAlwaysOnReadiness(event: event)
    }

    private func publishHostResumeCredentialReadiness(event: HostAvailabilityEvent) async {
        for environment in Environment.allCases {
            let alpacaReadiness = keychainProvider.alpacaCredentialReadiness(
                for: environment
            )
            let activeMarker = environment == configuration.environment ? " active=true" : " active=false"
            await store.publishDiagnostic(
                "alpaca host recovery preflight trigger=\(event.rawValue) env=\(environment.rawValue)\(activeMarker) ready=\(alpacaReadiness.isReady) public_key=\(alpacaReadiness.publicKeyFound) secret_key=\(alpacaReadiness.secretKeyFound)",
                source: .engine,
                action: "alpaca_host_recovery_preflight"
            )
        }
    }

    private func restartTradeUpdatesAfterHostResumeIfNeeded() async {
        guard isStarted else {
            return
        }
        await ensureTradeUpdatesPipelineStarted()
        await tradeUpdatesStream.requestReconnect(reason: "host_resume")
    }

    private func ensureTradeUpdatesPipelineStarted() async {
        if tradeUpdatesEventTask == nil {
            await tradeUpdatesStream.start()
            tradeUpdatesEventTask = Task { [weak self, tradeUpdatesStream] in
                for await event in tradeUpdatesStream.events {
                    await self?.handleTradeUpdatesEvent(event)
                }
            }
        } else {
            await tradeUpdatesStream.start()
        }
    }

    private func requestConnectivityRecoveryAfterModeChange(trigger: String) async {
        await ensureTradeUpdatesPipelineStarted()
        await tradeUpdatesStream.requestReconnect(reason: trigger)

        let watchlistSymbols = await store.snapshot().watchlistSymbols
        let marketDataSymbols = await portfolioWatchMarketDataCoverageSymbols(
            watchlistSymbols: watchlistSymbols
        )
        if shouldRunMarketData(for: marketDataSymbols) {
            await ensureMarketDataPipelineStarted()
            await marketDataStream.requestReconnect(reason: trigger)
            await marketDataStream.setWatchSymbols(marketDataSymbols)
        } else {
            await stopMarketDataPipeline()
        }
        await publishDerivedAlwaysOnReadinessForCurrentLifecycle()
    }

    private func restartMarketDataAfterHostResume(subscriptionSymbols: [String]) async {
        guard isStarted else {
            return
        }
        if marketDataEventTask == nil {
            await ensureMarketDataPipelineStarted()
        } else {
            await marketDataStream.stop()
            await marketDataStream.start()
        }
        await marketDataStream.setWatchSymbols(subscriptionSymbols)
    }

    private func publishAlwaysOnRecovering(event: HostAvailabilityEvent) async {
        let now = nowDate()
        lastHostLifecycleEvent = event
        alwaysOnReadinessGeneration &+= 1
        await store.setAlwaysOnReadiness(
            AlwaysOnReadinessState(
                status: .recoveringAfterWake,
                summary: "Recovering and reconciling app-owned truth after \(event.displayName).",
                detail: AlwaysOnReadinessState.hostAvailabilityContract,
                lastUpdatedAt: now,
                lastLifecycleEvent: event,
                lastRecoveryStartedAt: lastRecoveryStartedAt ?? now,
                lastRecoveryCompletedAt: lastRecoveryCompletedAt,
                lastRecoveryTrigger: event
            )
        )
    }

    private func publishAlwaysOnPaused(event: HostAvailabilityEvent) async {
        let now = nowDate()
        lastHostLifecycleEvent = event
        alwaysOnReadinessGeneration &+= 1
        await store.setAlwaysOnReadiness(
            AlwaysOnReadinessState(
                status: .pausedByHost,
                summary: "Paused by host sleep or suspension.",
                detail: AlwaysOnReadinessState.hostAvailabilityContract,
                blockers: ["Host sleep or suspension pauses active app workflows until wake/relaunch recovery runs."],
                lastUpdatedAt: now,
                lastLifecycleEvent: event,
                lastRecoveryStartedAt: lastRecoveryStartedAt,
                lastRecoveryCompletedAt: lastRecoveryCompletedAt,
                lastRecoveryTrigger: lastHostLifecycleEvent
            )
        )
    }

    @discardableResult
    private func reconcileStreamRuntimeStateIntoStore() async -> StoreSnapshot {
        let tradeRuntime = await tradeUpdatesStream.runtimeSnapshot()
        let marketDataRuntime = await marketDataStream.runtimeSnapshot()
        var snapshot = await store.snapshot()
        var didUpdateStore = false
        let shouldReconcileTradeRuntime = tradeRuntime.isRunning ||
            tradeRuntime.hasSocketTask ||
            tradeRuntime.state != .disconnected
        let shouldReconcileMarketDataRuntime = marketDataRuntime.isRunning ||
            marketDataRuntime.hasSocketTask ||
            marketDataRuntime.state != .disconnected ||
            marketDataRuntime.desiredSubscriptions.isEmpty == false ||
            marketDataRuntime.activeSubscriptions.isEmpty == false

        if shouldReconcileTradeRuntime,
           snapshot.connectionState != tradeRuntime.state.rawValue {
            await store.setConnectionState(tradeRuntime.state)
            didUpdateStore = true
        }
        if shouldReconcileMarketDataRuntime,
           snapshot.marketDataConnectionState != marketDataRuntime.state.rawValue {
            await store.setMarketDataConnectionState(marketDataRuntime.state)
            didUpdateStore = true
        }
        if shouldReconcileMarketDataRuntime,
           snapshot.marketDataDesiredSubscriptions != marketDataRuntime.desiredSubscriptions {
            await store.publishMarketDataDesiredSubscription(marketDataRuntime.desiredSubscriptions)
            didUpdateStore = true
        }
        if shouldReconcileMarketDataRuntime,
           snapshot.marketDataSubscriptions != marketDataRuntime.activeSubscriptions {
            await store.publishMarketDataSubscription(marketDataRuntime.activeSubscriptions)
            didUpdateStore = true
        }
        if snapshot.tradeUpdatesLastDiagnostic != tradeRuntime.lastDiagnostic ||
            snapshot.tradeUpdatesLastError != tradeRuntime.lastError ||
            snapshot.marketDataLastDiagnostic != marketDataRuntime.lastDiagnostic ||
            snapshot.marketDataLastErrorCode != marketDataRuntime.lastErrorCode ||
            snapshot.marketDataLastErrorMessage != marketDataRuntime.lastErrorMessage {
            await store.setStreamRuntimeDiagnostics(
                tradeUpdatesLastDiagnostic: tradeRuntime.lastDiagnostic,
                tradeUpdatesLastError: tradeRuntime.lastError,
                marketDataLastDiagnostic: marketDataRuntime.lastDiagnostic,
                marketDataLastErrorCode: marketDataRuntime.lastErrorCode,
                marketDataLastErrorMessage: marketDataRuntime.lastErrorMessage
            )
            didUpdateStore = true
        }
        if marketDataRuntime.activeSubscriptions.isEmpty {
            if lastMarketDataSubscriptionAcknowledgedAt != nil {
                lastMarketDataSubscriptionAcknowledgedAt = nil
            }
        } else if lastMarketDataSubscriptionAcknowledgedAt == nil {
            lastMarketDataSubscriptionAcknowledgedAt = marketDataRuntime.lastSubscriptionAcknowledgedAt
        }

        if didUpdateStore {
            snapshot = await store.snapshot()
        }
        return snapshot
    }

    private func publishDerivedAlwaysOnReadiness(event: HostAvailabilityEvent) async {
        if lastHostLifecycleEvent == .hostWillSleep,
           event != .hostDidWake,
           event != .manualRecovery {
            return
        }
        let generation = alwaysOnReadinessGeneration
        let snapshot = await reconcileStreamRuntimeStateIntoStore()
        let now = nowDate()
        let alpacaReadiness = keychainProvider.alpacaCredentialReadiness(
            for: configuration.environment
        )
        let assessment = makeAlwaysOnReadinessAssessment(
            isEngineStarted: isStarted,
            alpacaCredentialsReady: alpacaReadiness.isReady,
            snapshot: snapshot,
            now: now
        )
        guard generation == alwaysOnReadinessGeneration else {
            return
        }
        if lastHostLifecycleEvent == .hostWillSleep,
           event != .hostDidWake,
           event != .manualRecovery {
            return
        }
        await store.setAlwaysOnReadiness(
            AlwaysOnReadinessState(
                status: assessment.status,
                summary: assessment.summary,
                detail: assessment.detail,
                blockers: assessment.blockers,
                lastUpdatedAt: now,
                lastLifecycleEvent: event,
                lastRecoveryStartedAt: lastRecoveryStartedAt,
                lastRecoveryCompletedAt: lastRecoveryCompletedAt,
                lastRecoveryTrigger: lastRecoveryStartedAt == nil ? nil : event
            )
        )
    }

    private func performLaunchTimeCredentialPreflightIfNeeded() async {
        guard launchTimeCredentialPreflightCompleted == false else {
            return
        }
        launchTimeCredentialPreflightCompleted = true

        let telegramTokenConfigured = telegramBotToken(for: .status) != nil
        await store.publishDiagnostic(
            "telegram launch preflight token_configured=\(telegramTokenConfigured)",
            source: .engine,
            action: "telegram_launch_preflight"
        )

        for environment in Environment.allCases {
            let alpacaReadiness = keychainProvider.alpacaCredentialReadiness(
                for: environment
            )
            let activeMarker = environment == configuration.environment ? " active=true" : " active=false"
            await store.publishDiagnostic(
                "alpaca launch preflight env=\(environment.rawValue)\(activeMarker) ready=\(alpacaReadiness.isReady) public_key=\(alpacaReadiness.publicKeyFound) secret_key=\(alpacaReadiness.secretKeyFound)",
                source: .engine,
                action: "alpaca_launch_preflight"
            )
        }

        let appResolution = openAICredentialResolution(
            from: llmCredentialResolution(
                providerKind: .openAI,
                credentialProfileId: LLMCredentialProfile.openAIDefaultProfileID
            )
        )
        await store.publishDiagnostic(
            "openai launch preflight app_ready=\(appResolution.isReady) status=\(appResolution.status.rawValue)",
            source: .engine,
            action: "openai_launch_preflight"
        )

        do {
            let workerReady = try await analystWorkerLauncher.preflightOpenAIKeyAccess()
            await store.publishDiagnostic(
                "openai launch preflight worker_ready=\(workerReady)",
                source: .engine,
                action: "openai_launch_preflight"
            )
        } catch {
            await store.publishDiagnostic(
                "openai launch preflight worker_degraded reason=\(error.localizedDescription)",
                source: .engine,
                action: "openai_launch_preflight_failed"
            )
        }
    }

    public func stop() async {
        await positionsRefresher.cancel()
        await openOrdersRefresher.cancel()
        await paperRunPersistenceRefresher.cancel()
        await scheduler.stop()

        guard isStarted else {
            return
        }

        isStarted = false
        strategyRunMonitorTask?.cancel()
        strategyRunMonitorTask = nil
        pendingPaperExecutionRetryTask?.cancel()
        pendingPaperExecutionRetryTask = nil
        await finalizeAllActivePaperRuns(
            status: .aborted,
            stopReason: "engine_stop",
            source: .engine
        )
        await jobRunner.handleEngineStop()
        await strategyRunner.stopAll()
        strategyRunConstraintStateByID.removeAll()
        await stopIPCServer()

        tradeUpdatesEventTask?.cancel()
        tradeUpdatesEventTask = nil
        await tradeUpdatesStream.stop()

        marketDataNoFirstDataMonitorTask?.cancel()
        marketDataNoFirstDataMonitorTask = nil
        marketDataEventTask?.cancel()
        marketDataEventTask = nil
        await marketDataStream.stop()

        isConnected = false
        await store.setConnectionState(.disconnected)
        await store.setMarketDataConnectionState(.disconnected)
    }

    public func setWatchSymbols(_ symbols: [String]) async {
        let normalized = Array(MarketDataSubscriptionSet.normalized(symbols)).sorted()
        watchlistPersistence.saveWatchlistSymbols(normalized)
        await store.setWatchlistSymbols(normalized)

        guard isStarted else {
            return
        }
        await syncMarketDataLifecycle(watchlistSymbols: normalized)
    }

    public func addWatchSymbol(_ symbol: String) async {
        var symbols = await store.snapshot().watchlistSymbols
        symbols.append(symbol)
        await setWatchSymbols(symbols)
    }

    public func removeWatchSymbol(_ symbol: String) async {
        let normalized = symbol
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .uppercased()
        guard !normalized.isEmpty else {
            return
        }

        var symbols = await store.snapshot().watchlistSymbols
        symbols.removeAll { $0 == normalized }
        await setWatchSymbols(symbols)
    }

