    public func placeOrder(
        instrumentType: InstrumentType = .equity,
        symbol: String,
        qty: Int,
        side: OrderSide,
        type: OrderType,
        limitPrice: Decimal? = nil,
        timeInForce: TimeInForce = .day,
        bracket: BracketOrderInput? = nil,
        source: String = "ui",
        armingSessionID: String? = nil
    ) async throws -> String {
        try await enforceTradingSafetyForSubmission(
            source: source,
            providedArmingSessionID: armingSessionID
        )

        let normalizedSymbol = symbol
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .uppercased()

        guard !normalizedSymbol.isEmpty else {
            throw ManualOrderValidationError.emptySymbol
        }
        if instrumentType == .option, OptionContractSymbol.parse(normalizedSymbol) == nil {
            throw ManualOrderValidationError.invalidOptionSymbol
        }
        guard qty > 0 else {
            throw ManualOrderValidationError.invalidQuantity
        }
        guard type == .market || type == .limit else {
            throw ManualOrderValidationError.unsupportedOrderType
        }
        if instrumentType == .option,
           timeInForce != .day,
           timeInForce != .gtc {
            throw ManualOrderValidationError.unsupportedOptionTimeInForce
        }
        if instrumentType == .option, bracket != nil {
            throw ManualOrderValidationError.optionBracketNotSupported
        }

        let openingShort: Bool
        if instrumentType == .equity {
            openingShort = await isOpeningOrIncreasingShort(
                symbol: normalizedSymbol,
                side: side
            )
        } else {
            openingShort = false
        }
        if openingShort {
            try await runShortPreflight(symbol: normalizedSymbol)
        }

        let limitPriceString: String?
        if type == .limit {
            guard let limitPrice else {
                throw ManualOrderValidationError.limitPriceRequired
            }
            limitPriceString = try positiveDecimalString(
                limitPrice,
                error: .invalidLimitPrice
            )
        } else {
            limitPriceString = nil
        }

        let orderClass: OrderClass?
        let takeProfit: TakeProfitRequest?
        let stopLoss: StopLossRequest?
        if let bracket {
            let takeProfitString = try positiveDecimalString(
                bracket.takeProfitLimitPrice,
                error: .invalidBracketTakeProfit
            )
            let stopLossString = try positiveDecimalString(
                bracket.stopLossStopPrice,
                error: .invalidBracketStopLoss
            )
            let stopLossLimitString = try bracket.stopLossLimitPrice.map {
                try positiveDecimalString($0, error: .invalidBracketStopLimitPrice)
            }

            if let limitPrice, type == .limit {
                try validateBracketRelation(
                    side: side,
                    entryPrice: limitPrice,
                    takeProfitPrice: bracket.takeProfitLimitPrice,
                    stopLossPrice: bracket.stopLossStopPrice
                )
            }

            orderClass = .bracket
            takeProfit = TakeProfitRequest(limitPrice: takeProfitString)
            stopLoss = StopLossRequest(
                stopPrice: stopLossString,
                limitPrice: stopLossLimitString
            )
        } else {
            orderClass = nil
            takeProfit = nil
            stopLoss = nil
        }

        await store.publishDiagnostic(
            "manual order intent instrument=\(instrumentType.rawValue) symbol=\(normalizedSymbol) qty=\(qty) side=\(side.rawValue) type=\(type.rawValue) tif=\(timeInForce.rawValue) bracket=\(bracket != nil)"
            ,
            source: auditSource(from: source),
            symbol: normalizedSymbol,
            action: "order_intent"
        )

        let request = NewOrderRequest(
            instrumentType: instrumentType,
            symbol: normalizedSymbol,
            qty: String(qty),
            side: side,
            type: type,
            timeInForce: timeInForce,
            limitPrice: limitPriceString,
            orderClass: orderClass,
            takeProfit: takeProfit,
            stopLoss: stopLoss
        )

        try await requireLocalUserPresenceForLiveOrderIfNeeded(
            challenge: liveOrderSubmissionChallenge(
                symbol: normalizedSymbol,
                side: side,
                orderType: type,
                qty: qty
            ),
            source: source,
            symbol: normalizedSymbol,
            orderID: nil,
            action: "live_order_local_auth"
        )

        do {
            let order = try await restClient.placeOrder(request: request)
            await store.recordSubmittedOrder(order)
            await store.publishDiagnostic(
                "manual order submit success order_id=\(shortOrderID(order.id)) symbol=\(normalizedSymbol)",
                source: auditSource(from: source),
                orderID: order.id,
                symbol: normalizedSymbol,
                action: "order_submit"
            )
            return order.id
        } catch {
            if openingShort, isLikelyShortRejection(error) {
                await store.publishDiagnostic(
                    "short order rejected by broker symbol=\(normalizedSymbol) reason=\(error.localizedDescription)",
                    source: auditSource(from: source),
                    symbol: normalizedSymbol,
                    action: "order_submit",
                    errorCode: "short_rejected"
                )
            }
            await store.publishDiagnostic(
                "manual order submit failed symbol=\(normalizedSymbol) reason=\(error.localizedDescription)",
                source: auditSource(from: source),
                symbol: normalizedSymbol,
                action: "order_submit",
                errorCode: "order_submit_failed"
            )
            throw error
        }
    }

    public func replaceOrder(
        orderID: String,
        qty: Int? = nil,
        limitPrice: Decimal? = nil,
        source: String = "ui",
        armingSessionID: String? = nil
    ) async throws -> String {
        try await enforceTradingSafetyForSubmission(
            source: source,
            providedArmingSessionID: armingSessionID
        )

        let normalizedOrderID = orderID
            .trimmingCharacters(in: .whitespacesAndNewlines)
        guard !normalizedOrderID.isEmpty else {
            throw ManualOrderValidationError.invalidOrderID
        }

        guard qty != nil || limitPrice != nil else {
            throw ManualOrderValidationError.replaceRequiresChanges
        }

        let qtyString: String?
        if let qty {
            guard qty > 0 else {
                throw ManualOrderValidationError.invalidReplaceQuantity
            }
            qtyString = String(qty)
        } else {
            qtyString = nil
        }

        let limitPriceString: String?
        if let limitPrice {
            limitPriceString = try positiveDecimalString(
                limitPrice,
                error: .invalidReplaceLimitPrice
            )
        } else {
            limitPriceString = nil
        }

        await store.publishDiagnostic(
            "manual replace intent order_id=\(shortOrderID(normalizedOrderID)) qty=\(qtyString ?? "-") limit_price=\(limitPriceString ?? "-")"
            ,
            source: auditSource(from: source),
            orderID: normalizedOrderID,
            action: "replace_intent"
        )

        try await requireLocalUserPresenceForLiveOrderIfNeeded(
            challenge: liveOrderReplacementChallenge(orderID: normalizedOrderID),
            source: source,
            symbol: nil,
            orderID: normalizedOrderID,
            action: "live_replace_local_auth"
        )

        do {
            let order = try await restClient.replaceOrder(
                orderId: normalizedOrderID,
                request: ReplaceOrderRequest(
                    qty: qtyString,
                    limitPrice: limitPriceString
                )
            )
            await store.publishDiagnostic(
                "manual replace success order_id=\(shortOrderID(order.id)) source_order_id=\(shortOrderID(normalizedOrderID))",
                source: auditSource(from: source),
                orderID: order.id,
                action: "replace_submit"
            )
            return order.id
        } catch {
            await store.publishDiagnostic(
                "manual replace failed order_id=\(shortOrderID(normalizedOrderID)) reason=\(error.localizedDescription)",
                source: auditSource(from: source),
                orderID: normalizedOrderID,
                action: "replace_submit",
                errorCode: "replace_submit_failed"
            )
            throw error
        }
    }

    public func submitOrderIntent(
        _ intent: OrderIntent,
        source: String = "strategy"
    ) async -> OrderIntentSubmissionResult {
        let strategyID = strategyID(fromSource: source)
        if let strategyID {
            await recordRunIntentSubmission(
                strategyID: strategyID,
                intent: intent
            )
            if let replayRunID = replayRunIDForStrategy(strategyID) {
                if let simBroker = replaySimBrokerByStrategyID[strategyID] {
                    let replayNow = replayCurrentTimeByStrategyID[strategyID]
                        ?? activePaperRunsByRunID[replayRunID]?.startedAt
                        ?? nowDate()
                    await simBroker.setCurrentTime(replayNow)
                    let submission = await simBroker.submit(
                        intent: intent,
                        source: source
                    )
                    let result = submission.result
                    await recordRunIntentOutcome(
                        strategyID: strategyID,
                        intent: intent,
                        result: result
                    )
                    for event in submission.events {
                        await processTradeUpdate(event, allowRESTRepairs: false)
                    }
                    await applyReplayAccountSnapshot(
                        runID: replayRunID,
                        snapshot: submission.accountSnapshot,
                        at: replayNow
                    )
                    return result
                }

                let result = OrderIntentSubmissionResult.failure(
                    code: ReplayError.replayTradingNotEnabled.code,
                    message: ReplayError.replayTradingNotEnabled.message
                )
                await recordRunIntentOutcome(
                    strategyID: strategyID,
                    intent: intent,
                    result: result
                )
                await store.publishDiagnostic(
                    "replay blocked order intent strategy_id=\(strategyID) run_id=\(shortOrderID(replayRunID))",
                    source: .strategy,
                    level: .warning,
                    strategyID: strategyID,
                    action: "replay_order_blocked",
                    errorCode: ReplayError.replayTradingNotEnabled.code
                )
                return result
            }
        }

        let result: OrderIntentSubmissionResult
        switch intent {
        case .place(let placeIntent):
            do {
                let orderID = try await placeOrder(
                    instrumentType: placeIntent.instrumentType,
                    symbol: placeIntent.symbol,
                    qty: placeIntent.qty,
                    side: placeIntent.side,
                    type: placeIntent.type,
                    limitPrice: placeIntent.limitPrice,
                    timeInForce: placeIntent.timeInForce,
                    bracket: placeIntent.bracket,
                    source: source,
                    armingSessionID: strategyArmingSessionID()
                )
                result = .success(orderID: orderID, message: "Order submitted.")
            } catch let error as ManualOrderValidationError {
                result = .failure(code: error.errorCode, message: error.localizedDescription)
            } catch {
                result = .failure(code: "order_submit_failed", message: error.localizedDescription)
            }
        case .replace(let replaceIntent):
            do {
                let orderID = try await replaceOrder(
                    orderID: replaceIntent.orderID,
                    qty: replaceIntent.qty,
                    limitPrice: replaceIntent.limitPrice,
                    source: source,
                    armingSessionID: strategyArmingSessionID()
                )
                result = .success(orderID: orderID, message: "Replace submitted.")
            } catch let error as ManualOrderValidationError {
                result = .failure(code: error.errorCode, message: error.localizedDescription)
            } catch {
                result = .failure(code: "order_replace_failed", message: error.localizedDescription)
            }
        case .cancel(let orderID):
            await cancelOrder(orderID: orderID)
            result = .success(orderID: orderID, message: "Cancel requested.")
        }

        if let strategyID {
            await recordRunIntentOutcome(
                strategyID: strategyID,
                intent: intent,
                result: result
            )
        }
        return result
    }

    public func fetchOptionContract(symbolOrID: String) async -> OptionContract? {
        let normalized = symbolOrID
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .uppercased()
        guard !normalized.isEmpty else {
            return nil
        }

        if let cached = optionContractCache[normalized] {
            return cached
        }

        do {
            let contract = try await restClient.fetchOptionContract(symbolOrID: normalized)
            optionContractCache[normalized] = contract
            return contract
        } catch {
            await store.publishDiagnostic("option contract lookup failed symbol=\(normalized)")
            return nil
        }
    }

    private func runStartupReconciliation() async {
        do {
            async let account = restClient.fetchAccount()
            async let positions = restClient.fetchPositions()
            async let openOrders = restClient.fetchOpenOrders()
            let resolvedAccount = try await account
            lastKnownAccount = resolvedAccount
            await store.applyStartupSnapshot(
                account: resolvedAccount,
                positions: try await positions,
                openOrders: try await openOrders
            )
        } catch {
            await store.publishDiagnostic("startup reconciliation failed: \(error.localizedDescription)")
        }
    }

