    public func setMemoryReliefActionProvider(
        _ provider: (@MainActor @Sendable (MemoryReliefRequest) async -> JSONValue)?
    ) {
        memoryReliefActionProvider = provider
    }

    private func runMemoryReliefAction(_ request: MemoryReliefRequest) async -> JSONValue {
        guard let provider = memoryReliefActionProvider else {
            return .object([
                "available": .bool(false),
                "dryRun": .bool(request.dryRun),
                "force": .bool(request.force),
                "reason": .string(request.reason),
                "summary": .string("Memory relief is not available until the Mac app runtime is attached.")
            ])
        }
        return await provider(request)
    }

    private func liveExecutionProtectionStatusJSON(
        settings: LiveExecutionProtectionSettings
    ) -> JSONValue {
        var object: [String: JSONValue] = [
            "localUserPresenceRequiredForLiveOrders": .bool(settings.localUserPresenceRequiredForLiveOrders),
            "appliesTo": .array([
                .string("live_new"),
                .string("live_replace")
            ]),
            "paperAffected": .bool(false),
            "cancelRequiresLocalAuth": .bool(false),
            "disableRequiresLocalAuth": .bool(true),
            "updatedAt": .string(DateCodec.formatISO8601(settings.updatedAt)),
            "updatedBy": .string(settings.updatedBy),
            "updateSource": .string(settings.updateSource.rawValue)
        ]
        if let lastLocalUserPresenceAuthorizationResult {
            object["lastAuthorizationStatus"] = .string(lastLocalUserPresenceAuthorizationResult.status.rawValue)
            object["lastAuthorizationCheckedAt"] = .string(DateCodec.formatISO8601(lastLocalUserPresenceAuthorizationResult.checkedAt))
        } else {
            object["lastAuthorizationStatus"] = .null
            object["lastAuthorizationCheckedAt"] = .null
        }
        return .object(object)
    }

