            "rssEnabledFeeds": .number(Double(snapshot.rssFeedSummary.enabledCount)),
            "newsCount": .number(Double(snapshot.recentNews.count)),
            "newsRuntime": .object([
                "cleanupRequestCount": .number(Double(rssNewsCleanupRequestCount)),
                "cleanupFullScanCount": .number(Double(rssNewsCleanupFullScanCount)),
                "cleanupSkippedNoSourceChangeCount": .number(Double(rssNewsCleanupSkippedNoSourceChangeCount)),
                "cleanupRemovedEventCount": .number(Double(rssNewsCleanupRemovedEventCount)),
                "cleanupAffectedFileCount": .number(Double(rssNewsCleanupAffectedFileCount)),
                "knownEventIDLoadCount": .number(Double(newsStoreRuntimeDiagnostics.knownEventIDLoadCount)),
                "knownEventIDLoadDecodedLineCount": .number(Double(newsStoreRuntimeDiagnostics.knownEventIDLoadDecodedLineCount)),
                "listRecentRequestCount": .number(Double(newsStoreRuntimeDiagnostics.listRecentRequestCount)),
                "listRecentFileReadCount": .number(Double(newsStoreRuntimeDiagnostics.listRecentFileReadCount)),
                "listRecentDecodedLineCount": .number(Double(newsStoreRuntimeDiagnostics.listRecentDecodedLineCount)),
                "listRecentReturnedCount": .number(Double(newsStoreRuntimeDiagnostics.listRecentReturnedCount)),
                "listRecentByReceivedAtRequestCount": .number(Double(newsStoreRuntimeDiagnostics.listRecentByReceivedAtRequestCount)),
                "listRecentByReceivedAtFileReadCount": .number(Double(newsStoreRuntimeDiagnostics.listRecentByReceivedAtFileReadCount)),
                "listRecentByReceivedAtDecodedLineCount": .number(Double(newsStoreRuntimeDiagnostics.listRecentByReceivedAtDecodedLineCount)),
                "listRecentByReceivedAtReturnedCount": .number(Double(newsStoreRuntimeDiagnostics.listRecentByReceivedAtReturnedCount)),
                "purgeRSSSourcesCount": .number(Double(newsStoreRuntimeDiagnostics.purgeRSSSourcesCount)),
                "purgeRSSSourcesFileScanCount": .number(Double(newsStoreRuntimeDiagnostics.purgeRSSSourcesFileScanCount)),
                "purgeRSSSourcesDecodedLineCount": .number(Double(newsStoreRuntimeDiagnostics.purgeRSSSourcesDecodedLineCount)),
                "purgeRSSSourcesRemovedEventCount": .number(Double(newsStoreRuntimeDiagnostics.purgeRSSSourcesRemovedEventCount)),
                "purgeRSSSourcesAffectedFileCount": .number(Double(newsStoreRuntimeDiagnostics.purgeRSSSourcesAffectedFileCount))
            ]),
            "ownerSurfaceRuntime": ownerSurfaceRuntimeDiagnostics ?? .object([:]),
            "signalsCount": .number(Double(snapshot.signals.count)),
            "watchlist": .array(snapshot.watchlistSymbols.map(JSONValue.string)),
            "buildInfo": .string(snapshot.build),
            "strategies": .array(strategies.map(jsonValue(strategyStatus:))),
            "paperEstablishmentExecution": agentControlPaperEstablishmentExecutionStatusJSON(
                snapshot: snapshot,
                approvalRequests: approvalRequests
            ),
            "alpacaTradingCredentials": .object([
                "environment": .string(alpacaReadiness.environment.rawValue),
                "ready": .bool(alpacaReadiness.isReady),
                "publicKeyFound": .bool(alpacaReadiness.publicKeyFound),
                "secretKeyFound": .bool(alpacaReadiness.secretKeyFound),
                "checkedAt": .string(DateCodec.formatISO8601(alpacaReadiness.checkedAt)),
                "orderPlacementReady": .bool(alpacaReadiness.isReady),
                "accountDataCurrentlyOrderReady": .bool(alpacaReadiness.isReady && snapshot.accountSummary != nil),
                "summary": .string(
                    alpacaReadiness.isReady
                        ? "\(configuration.environment.rawValue.capitalized) Alpaca trading credentials are available for order placement."
                        : "\(configuration.environment.rawValue.capitalized) Alpaca trading credentials are unavailable; any account data shown may be stale and order submission is blocked."
                )
            ]),
            "ipcRunning": .bool(ipcServer != nil),
            "ipcHost": .string("127.0.0.1"),
            "ipcPort": ipcPort.map { .number(Double($0)) } ?? .null
        ]

        if let summary = snapshot.accountSummary {
            result["account"] = .object([
                "accountIdentifierRedacted": .bool(true),
                "status": .string(summary.status),
                "buyingPower": .string(summary.buyingPower),
                "cash": .string(summary.cash),
                "equity": .string(summary.equity),
                "canShortSellEquities": .bool(summary.canShortSellEquities)
            ])
        } else {
            result["account"] = .null
        }

        return .object(result)
    }

    private func buildIdentityStatusJSON() -> JSONValue {
        let mainBundle = Bundle.main
        let executablePath = mainBundle.executableURL?.path ?? CommandLine.arguments.first ?? ""
        let executableModifiedAt: JSONValue = {
            guard executablePath.isEmpty == false,
                  let attributes = try? FileManager.default.attributesOfItem(atPath: executablePath),
                  let modifiedAt = attributes[.modificationDate] as? Date
            else {
                return .null
            }
            return .string(DateCodec.formatISO8601(modifiedAt))
        }()

        return .object([
            "tradingKitBuildInfo": .string(Self.buildInfo),
            "processIdentifier": .number(Double(ProcessInfo.processInfo.processIdentifier)),
            "processName": .string(ProcessInfo.processInfo.processName),
            "bundleIdentifier": mainBundle.bundleIdentifier.map(JSONValue.string) ?? .null,
            "bundlePath": .string(mainBundle.bundlePath),
            "executablePath": .string(executablePath),
            "executableModifiedAt": executableModifiedAt
        ])
    }

    private func portfolioWatchRuntimeStatusJSON(
        snapshot: StoreSnapshot,
        chartWallConfiguration: PortfolioWatchChartWallConfiguration?
    ) -> JSONValue {
        let selectedSymbols = PortfolioWatchChartWallConfiguration.effectiveSelectedSymbols(
            selectedSymbols: chartWallConfiguration?.selectedSymbols ?? [],
            watchlistSymbols: snapshot.watchlistSymbols
        )
        let selectedSet = Set(selectedSymbols)
        let desired = snapshot.marketDataDesiredSubscriptions
        let active = snapshot.marketDataSubscriptions
        let pricedCount = selectedSymbols.filter { symbol in
            resolvePortfolioWatchLiveValue(
                from: snapshot.quotesBySymbol[symbol] ?? snapshot.optionQuotesBySymbol[symbol]
            ) != nil
        }.count
        let noDataSymbols = selectedSymbols.filter { symbol in
            let quote = snapshot.quotesBySymbol[symbol] ?? snapshot.optionQuotesBySymbol[symbol]
            let subscribed = active.quotes.contains(symbol)
                || active.trades.contains(symbol)
                || active.bars.contains(symbol)
                || active.optionQuotes.contains(symbol)
                || active.optionTrades.contains(symbol)
                || active.optionBars.contains(symbol)
            return subscribed && resolvePortfolioWatchLiveValue(from: quote) == nil
        }

        return .object([
            "configurationId": chartWallConfiguration.map { .string($0.configurationId) } ?? .null,
            "selectedSymbols": .array(selectedSymbols.map(JSONValue.string)),
            "watchlistSymbols": .array(snapshot.watchlistSymbols.map(JSONValue.string)),
            "selectedCount": .number(Double(selectedSymbols.count)),
            "pricedSelectedCount": .number(Double(pricedCount)),
            "requestedSelectedCount": .number(Double(selectedSymbols.filter { symbol in
                desired.quotes.contains(symbol)
                    || desired.trades.contains(symbol)
                    || desired.bars.contains(symbol)
                    || desired.optionQuotes.contains(symbol)
                    || desired.optionTrades.contains(symbol)
                    || desired.optionBars.contains(symbol)
            }.count)),
            "activeSelectedCount": .number(Double(selectedSymbols.filter { symbol in
                active.quotes.contains(symbol)
                    || active.trades.contains(symbol)
                    || active.bars.contains(symbol)
                    || active.optionQuotes.contains(symbol)
                    || active.optionTrades.contains(symbol)
                    || active.optionBars.contains(symbol)
            }.count)),
            "activeButNoUsablePriceSymbols": .array(noDataSymbols.map(JSONValue.string)),
            "lastMarketDataReceivedAt": snapshot.lastMarketDataReceivedAt
                .map { .string(DateCodec.formatISO8601($0)) } ?? .null,
            "lastMarketDataReceivedSymbol": snapshot.lastMarketDataReceivedSymbol.map(JSONValue.string) ?? .null,
            "symbols": .array(
                selectedSymbols.map { symbol in
                    portfolioWatchSymbolRuntimeStatusJSON(
                        symbol: symbol,
                        selectedSymbols: selectedSet,
                        snapshot: snapshot
                    )
                }
            )
        ])
    }

    private func portfolioWatchSymbolRuntimeStatusJSON(
        symbol: String,
        selectedSymbols: Set<String>,
        snapshot: StoreSnapshot
    ) -> JSONValue {
        let quote = snapshot.quotesBySymbol[symbol] ?? snapshot.optionQuotesBySymbol[symbol]
        let resolved = resolvePortfolioWatchLiveValue(from: quote)
        let desired = snapshot.marketDataDesiredSubscriptions
        let active = snapshot.marketDataSubscriptions
        return .object([
            "symbol": .string(symbol),
            "selected": .bool(selectedSymbols.contains(symbol)),
            "watchlisted": .bool(snapshot.watchlistSymbols.contains(symbol)),
            "desired": .object([
                "quotes": .bool(desired.quotes.contains(symbol)),
                "trades": .bool(desired.trades.contains(symbol)),
                "bars": .bool(desired.bars.contains(symbol)),
                "optionQuotes": .bool(desired.optionQuotes.contains(symbol)),
                "optionTrades": .bool(desired.optionTrades.contains(symbol)),
                "optionBars": .bool(desired.optionBars.contains(symbol))
            ]),
            "active": .object([
                "quotes": .bool(active.quotes.contains(symbol)),
                "trades": .bool(active.trades.contains(symbol)),
                "bars": .bool(active.bars.contains(symbol)),
                "optionQuotes": .bool(active.optionQuotes.contains(symbol)),
                "optionTrades": .bool(active.optionTrades.contains(symbol)),
                "optionBars": .bool(active.optionBars.contains(symbol))
            ]),
            "latestPrice": resolved.map { .number($0.price) } ?? .null,
            "latestPriceSource": resolved.map { .string($0.source.displayTitle) } ?? .null,
            "latestPriceObservedAt": resolved?.observedAt
                .map { .string(DateCodec.formatISO8601($0)) } ?? .null,
            "lastQuoteAt": quote?.lastQuoteTimestamp.map(JSONValue.string) ?? .null,
            "lastTradeAt": quote?.lastTradeTimestamp.map(JSONValue.string) ?? .null,
            "lastBarAt": quote?.lastBarTimestamp.map(JSONValue.string) ?? .null
        ])
    }

    private func agentControlPaperEstablishmentExecutionStatusJSON(
        snapshot: StoreSnapshot,
        approvalRequests: [PMApprovalRequest]
    ) -> JSONValue {
        let establishmentRequests = approvalRequests
            .filter {
                isExercisePMApprovalRequest($0) == false
                    && pmApprovalRequestAppearsToBePaperPortfolioEstablishment($0)
            }
            .sorted {
                if $0.updatedAt == $1.updatedAt {
                    return $0.approvalRequestId < $1.approvalRequestId
                }
                return $0.updatedAt > $1.updatedAt
            }

        if let lifecycleRequest = establishmentRequests.first(where: {
            $0.status == .resolved
                && $0.ownerResponse == .approved
                && $0.paperPortfolioExecutionLifecycleState != nil
        }),
           let lifecycleState = lifecycleRequest.paperPortfolioExecutionLifecycleState {
            return .object([
                "state": .string(lifecycleState.status.rawValue),
                "summary": .string(lifecycleState.summary),
                "detail": .string(lifecycleState.detail),
                "approvalRequestId": .string(lifecycleRequest.approvalRequestId),
                "subject": .string(lifecycleRequest.subject),
                "targetSymbols": .array(lifecycleState.targetSymbols.map(JSONValue.string)),
                "missingPriceSymbols": .array(lifecycleState.missingPriceSymbols.map(JSONValue.string)),
                "blockedReasons": .array(lifecycleState.blockedReasons.map { .string($0.rawValue) }),
                "automaticRetryEnabled": .bool(lifecycleRequest.paperPortfolioExecutionPendingState?.automaticRetryEnabled ?? false),
                "orderPlanStatus": .string(lifecycleState.orderPlanStatus.rawValue),
                "lastRouteActionAt": lifecycleState.lastRouteActionAt
                    .map { .string(DateCodec.formatISO8601($0)) } ?? .null,
                "lastRetryAttemptedAt": lifecycleState.lastRetryAttemptedAt
                    .map { .string(DateCodec.formatISO8601($0)) } ?? .null,
                "orderAttemptCount": .number(Double(lifecycleState.orderAttemptCount)),
                "acceptedOrderAttemptCount": .number(Double(lifecycleState.acceptedOrderAttemptCount)),
                "failedOrderAttemptCount": .number(Double(lifecycleState.failedOrderAttemptCount)),
                "lastRoutingStatus": lifecycleRequest.lastExecutionRoutingAssessment
                    .map { .string($0.status.rawValue) } ?? .null,
                "lastRoutingAction": lifecycleRequest.lastExecutionRoutingAssessment
                    .map { .string($0.action.rawValue) } ?? .null,
                "updatedAt": .string(DateCodec.formatISO8601(lifecycleState.updatedAt))
            ])
        }

        if snapshot.positions.isEmpty == false || snapshot.openOrders.isEmpty == false {
            return .object([
                "state": .string("orders_or_positions_recorded"),
                "summary": .string("Current positions or open orders are recorded; inspect Orders Blotter and Positions for order-attempt truth."),
                "approvalRequestId": .null,
                "subject": .null,
                "missingPriceSymbols": .array([]),
                "automaticRetryEnabled": .bool(false)
            ])
        }

        if let waiting = establishmentRequests.first(where: {
            $0.status == .resolved
                && $0.ownerResponse == .approved
                && $0.paperPortfolioExecutionPendingState?.status == .waitingForUsablePrices
        }),
           let pendingState = waiting.paperPortfolioExecutionPendingState {
            return .object([
                "state": .string("approved_waiting_for_usable_prices"),
                "summary": .string("Owner approval is recorded and paper-establishment execution is pending on usable prices before retry/order submission."),
                "approvalRequestId": .string(waiting.approvalRequestId),
                "subject": .string(waiting.subject),
                "missingPriceSymbols": .array(pendingState.missingPriceSymbols.map(JSONValue.string)),
                "automaticRetryEnabled": .bool(pendingState.automaticRetryEnabled),
                "lastBlockerSummary": .string(pendingState.lastBlockerSummary),
                "lastRetryAttemptedAt": pendingState.lastRetryAttemptedAt
                    .map { .string(DateCodec.formatISO8601($0)) } ?? .null,
                "updatedAt": .string(DateCodec.formatISO8601(pendingState.updatedAt))
            ])
        }

        if let approved = establishmentRequests.first(where: {
            $0.status == .resolved && $0.ownerResponse == .approved
        }) {
            return .object([
                "state": .string("approved_no_active_execution_state"),
                "summary": .string("Owner approval is recorded, but app truth has no active pending execution/retry state, open order, holding, or order-attempt lifecycle recorded."),
                "approvalRequestId": .string(approved.approvalRequestId),
                "subject": .string(approved.subject),
                "missingPriceSymbols": .array([]),
                "automaticRetryEnabled": .bool(false),
                "updatedAt": .string(DateCodec.formatISO8601(approved.updatedAt))
            ])
        }

        if let pending = establishmentRequests.first(where: { $0.status == .pending }) {
            return .object([
                "state": .string("approval_pending"),
                "summary": .string("Paper-establishment is waiting on the surfaced owner approval request before governed execution can run."),
                "approvalRequestId": .string(pending.approvalRequestId),
                "subject": .string(pending.subject),
                "missingPriceSymbols": .array([]),
                "automaticRetryEnabled": .bool(false),
                "updatedAt": .string(DateCodec.formatISO8601(pending.updatedAt))
            ])
        }

        return .object([
            "state": .string("no_active_approval"),
            "summary": .string("No active paper-establishment approval, pending execution state, open order, holding, or order-attempt lifecycle is recorded."),
            "approvalRequestId": .null,
            "subject": .null,
            "missingPriceSymbols": .array([]),
            "automaticRetryEnabled": .bool(false)
        ])
    }

    private func startIPCServer() async {
        await store.publishDiagnostic(
            "ipc_start_attempt host=127.0.0.1 preferredPort=\(ipcPreferredPort)",
            source: .system,
            action: "ipc_start"
        )
        guard ipcServer == nil else {
            return
        }

        let token = newIPCToken()
        let router = AgentControlRouter(
            authToken: token,
            handlers: .init(
                status: { [weak self] in
                    await self?.agentControlStatusJSON() ?? .object([:])
                },
                strategies: { [weak self] in
                    await self?.strategyRunner.statuses() ?? []
                },
                startStrategy: { [weak self] id, params in
                    guard let self else {
                        throw StrategyRunnerError.strategyNotFound(id: id)
                    }
                    return try await self.startStrategy(id: id, params: params, source: .ipc)
                },
                startStrategyFromProposal: { [weak self] proposalID in
                    guard let self else {
                        throw ProposalStoreError.proposalNotFound(id: proposalID)
                    }
                    return try await self.startStrategyFromProposal(
                        proposalID: proposalID,
                        source: .ipc
                    )
                },
                stopStrategy: { [weak self] id in
                    guard let self else {
                        throw StrategyRunnerError.strategyNotFound(id: id)
                    }
                    return try await self.stopStrategy(id: id, source: .ipc)
                },
                setStrategyParams: { [weak self] id, params in
                    guard let self else {
                        throw StrategyRunnerError.strategyNotFound(id: id)
                    }
                    return try await self.setStrategyParameters(id: id, params: params, source: .ipc)
                },
                proposals: { [weak self] in
                    guard let self else {
                        return []
                    }
                    return try await self.listProposalRows()
                },
                proposal: { [weak self] proposalID in
                    guard let self else {
                        return nil
                    }
                    return try await self.getProposal(id: proposalID)
                },
                upsertProposal: { [weak self] proposal in
                    guard let self else {
                        return proposal
                    }
                    return try await self.upsertProposal(proposal, source: .ipc)
                },
                submitProposal: { [weak self] proposalID in
                    guard let self else {
                        throw ProposalStoreError.proposalNotFound(id: proposalID)
                    }
                    return try await self.submitProposal(id: proposalID, source: .ipc)
                },
                approveProposalPaper: { [weak self] proposalID, reviewer, notes in
                    guard let self else {
                        throw ProposalStoreError.proposalNotFound(id: proposalID)
                    }
                    return try await self.approveProposalForPaper(
                        id: proposalID,
                        reviewedBy: reviewer,
                        notes: notes,
                        source: .ipc
                    )
                },
                denyProposalPaper: { [weak self] proposalID, reviewer, notes in
                    guard let self else {
                        throw ProposalStoreError.proposalNotFound(id: proposalID)
                    }
                    return try await self.denyProposalForPaper(
                        id: proposalID,
                        reviewedBy: reviewer,
                        notes: notes,
                        source: .ipc
                    )
                },
                listRuns: { [weak self] proposalID in
                    guard let self else {
                        return []
                    }
                    return try await self.listRuns(proposalID: proposalID)
                },
                getRun: { [weak self] runID in
                    guard let self else {
                        throw PaperRunStoreError.runNotFound(id: runID)
                    }
                    return try await self.getRun(runID: runID)
                },
                exportRun: { [weak self] runID in
                    guard let self else {
                        throw PaperRunStoreError.runNotFound(id: runID)
                    }
                    return try await self.exportRunJSON(runID: runID)
                },
                listJobs: { [weak self] in
                    guard let self else {
                        return []
                    }
                    return try await self.listJobs()
                },
                getJob: { [weak self] jobID in
                    guard let self else {
                        throw JobStoreError.jobNotFound(id: jobID)
                    }
                    return try await self.getJob(jobID: jobID)
                },
                submitJob: { [weak self] type, params in
                    guard let self else {
                        throw JobRunnerError.invalidParameters(message: "Engine unavailable")
