                        timeframe: request.timeframe,
                        days: request.days,
                        end: request.end,
                        speed: request.speed,
                        autoIngest: request.autoIngest,
                        feed: request.feed,
                        simulateTrades: request.simulateTrades,
                        allowTradingInReplay: request.allowTradingInReplay,
                        fillPolicy: request.fillPolicy,
                        slippageBps: request.slippageBps,
                        source: .ipc
                    )
                },
                armLive: { [weak self] in
                    await self?.armLiveTrading()
                },
                disarmLive: { [weak self] in
                    await self?.disarmLiveTrading()
                },
                setKillSwitch: { [weak self] enabled in
                    await self?.setKillSwitchEnabled(enabled)
                }
            )
        )

        let server = LoopbackHTTPServer()
        do {
            let port = try await server.start(
                host: "127.0.0.1",
                preferredPort: ipcPreferredPort
            ) { request in
                await router.handle(request)
            }
            let listeningPort = await server.listeningPort()
            guard listeningPort == port, port > 0 else {
                throw LoopbackHTTPServer.ServerError.invalidResolvedPort
            }

            ipcServer = server
            ipcRouter = router
            ipcAuthToken = token
            ipcPort = port

            var runtimeWritten = true
            do {
                try ipcRuntimeInfoStore.save(
                    AgentControlRuntimeInfo(host: "127.0.0.1", port: port, token: token)
                )
            } catch {
                runtimeWritten = false
                try? ipcRuntimeInfoStore.clear()
                await store.publishDiagnostic(
                    "ipc_runtime_write_failed error=\(error.localizedDescription)",
                    source: .system,
                    level: .warning,
                    action: "ipc_runtime_file"
                )
            }

            await store.setIPCStatus(
                IPCServerStatus(
                    running: true,
                    host: "127.0.0.1",
                    port: port,
                    tokenFile: try? ipcRuntimeInfoStore.fileURL().path
                )
            )
            await store.publishDiagnostic(
                "ipc_started host=127.0.0.1 port=\(port) runtime_written=\(runtimeWritten) token_rotated=true fallback_from_preferred=\(port != Int(ipcPreferredPort))",
                source: .system,
                action: "ipc_start"
            )
        } catch {
            ipcServer = nil
            ipcRouter = nil
            ipcAuthToken = nil
            ipcPort = nil
            try? ipcRuntimeInfoStore.clear()
            await store.setIPCStatus(.stopped())
            await store.publishDiagnostic(
                "ipc_start_failed error=\(error.localizedDescription)",
                source: .system,
                level: .error,
                action: "ipc_start"
            )
        }
    }

    @discardableResult
    private func startStrategyInternal(
        id: String,
        params: [String: JSONValue],
        source: AuditEventSource,
        proposalID: String?,
        proposalConstraints: StrategyProposalConstraints?
    ) async throws -> StrategyStatusSnapshot {
        strategyRunConstraintStateByID[id] = StrategyRunConstraintState()
        let context = makeStrategyContext(
            strategyID: id,
            proposalID: proposalID,
            proposalConstraints: proposalConstraints
        )
        let status = try await strategyRunner.start(
            id: id,
            params: params,
            context: context,
            proposalID: proposalID,
            proposalConstraints: proposalConstraints
        )
        await store.publishDiagnostic(
            "strategy started id=\(id)",
            source: source,
            strategyID: id,
            action: "strategy_start"
        )
        return status
    }

    private func stopIPCServer() async {
        if let ipcServer {
            await ipcServer.stop()
        }
        ipcServer = nil
        ipcRouter = nil
        ipcAuthToken = nil
        ipcPort = nil
        try? ipcRuntimeInfoStore.clear()
        await store.setIPCStatus(.stopped())
        await store.publishDiagnostic(
            "ipc_stopped",
            source: .system,
            action: "ipc_stop"
        )
    }

    private func makeStrategyContext(
        strategyID: String,
        proposalID: String? = nil,
        proposalConstraints: StrategyProposalConstraints? = nil
    ) -> StrategyContext {
        let snapshotInterval = strategySnapshotIntervalSec
        let snapshotPump = StrategySnapshotPump()
        let snapshots = AsyncStream<StoreSnapshot> { continuation in
            let store = self.store
            let task = Task {
                continuation.yield(await store.snapshot())
                while !Task.isCancelled {
                    if snapshotInterval > 0 {
                        try? await Task.sleep(
                            nanoseconds: UInt64(snapshotInterval * 1_000_000_000)
                        )
                    } else {
                        await Task.yield()
                    }
                    continuation.yield(await store.snapshot())
                }
                continuation.finish()
            }
            snapshotPump.setTask(task)
            continuation.onTermination = { _ in
                snapshotPump.cancel()
            }
        }

        return StrategyContext(
            snapshots: snapshots,
            currentSnapshot: { [store] in
                await store.snapshot()
            },
            submit: { [unowned self] intent in
                if let rejection = await self.enforceStrategyProposalConstraintsIfNeeded(
                    strategyID: strategyID,
                    proposalID: proposalID,
                    proposalConstraints: proposalConstraints,
                    intent: intent
                ) {
                    if let code = rejection.errorCode {
                        let symbol: String?
                        if case .place(let place) = intent {
                            symbol = place.symbol
                        } else {
                            symbol = nil
                        }
                        await self.recordBlockedProposalIntentForRun(
                            strategyID: strategyID,
                            symbol: symbol,
                            errorCode: code
                        )
                    }
                    return rejection
                }
                return await self.submitOrderIntent(intent, source: "strategy.\(strategyID)")
            },
            sleep: { delay in
                guard delay > 0 else {
                    await Task.yield()
                    return
                }
                try? await Task.sleep(nanoseconds: UInt64(delay * 1_000_000_000))
            },
            audit: { [store] level, message, action, symbol, orderID in
                await store.publishDiagnostic(
                    message,
                    source: .strategy,
                    level: level,
                    strategyID: strategyID,
                    orderID: orderID,
                    symbol: symbol,
                    action: action
                )
            },
            shutdown: {
                snapshotPump.cancel()
            }
        )
    }

    private func enforceStrategyProposalConstraintsIfNeeded(
        strategyID: String,
        proposalID: String?,
        proposalConstraints: StrategyProposalConstraints?,
        intent: OrderIntent
    ) async -> OrderIntentSubmissionResult? {
        guard let proposalConstraints else {
            return nil
        }
        guard case .place(let placeIntent) = intent else {
            return nil
        }

        if let allowOptions = proposalConstraints.allowOptions,
           !allowOptions,
           placeIntent.instrumentType == .option {
            await store.publishDiagnostic(
                "proposal constraint blocked options proposal_id=\(proposalID ?? "-") strategy_id=\(strategyID)",
                source: .strategy,
                level: .warning,
                strategyID: strategyID,
                symbol: placeIntent.symbol,
                action: "proposal_constraint_blocked",
                errorCode: "proposal_options_not_allowed"
            )
            return .failure(
                code: "proposal_options_not_allowed",
                message: "Proposal does not allow options orders."
            )
        }

        if let allowShort = proposalConstraints.allowShort,
           !allowShort,
           placeIntent.side == .sell {
            await store.publishDiagnostic(
                "proposal constraint blocked short proposal_id=\(proposalID ?? "-") strategy_id=\(strategyID)",
                source: .strategy,
                level: .warning,
                strategyID: strategyID,
                symbol: placeIntent.symbol,
                action: "proposal_constraint_blocked",
                errorCode: "proposal_short_not_allowed"
            )
            return .failure(
                code: "proposal_short_not_allowed",
                message: "Proposal does not allow short sell intents."
            )
        }

        let nowTime = now()
        var state = strategyRunConstraintStateByID[strategyID] ?? StrategyRunConstraintState()
        let windowStart = nowTime - 60
        state.placeSubmissionTimestamps.removeAll { $0 < windowStart }
        if state.placeSubmissionTimestamps.count >= proposalConstraints.maxOrdersPerMinute {
            strategyRunConstraintStateByID[strategyID] = state
            await store.publishDiagnostic(
                "proposal constraint blocked rate proposal_id=\(proposalID ?? "-") strategy_id=\(strategyID)",
                source: .strategy,
                level: .warning,
                strategyID: strategyID,
                symbol: placeIntent.symbol,
                action: "proposal_constraint_blocked",
                errorCode: "proposal_max_orders_per_minute"
            )
            return .failure(
                code: "proposal_max_orders_per_minute",
                message: "Proposal maxOrdersPerMinute exceeded."
            )
        }
        state.placeSubmissionTimestamps.append(nowTime)

        if let limitPrice = placeIntent.limitPrice {
            let orderNotional = limitPrice * Decimal(placeIntent.qty)
            if orderNotional > proposalConstraints.maxNotionalPerOrder {
                strategyRunConstraintStateByID[strategyID] = state
                await store.publishDiagnostic(
                    "proposal constraint blocked max_notional_per_order proposal_id=\(proposalID ?? "-") strategy_id=\(strategyID)",
                    source: .strategy,
                    level: .warning,
                    strategyID: strategyID,
                    symbol: placeIntent.symbol,
                    action: "proposal_constraint_blocked",
                    errorCode: "proposal_max_notional_per_order"
                )
                return .failure(
                    code: "proposal_max_notional_per_order",
                    message: "Proposal maxNotionalPerOrder exceeded."
                )
            }

            if let maxDailyNotional = proposalConstraints.maxDailyNotional,
               state.cumulativeNotional + orderNotional > maxDailyNotional {
                strategyRunConstraintStateByID[strategyID] = state
                await store.publishDiagnostic(
                    "proposal constraint blocked max_daily_notional proposal_id=\(proposalID ?? "-") strategy_id=\(strategyID)",
                    source: .strategy,
                    level: .warning,
                    strategyID: strategyID,
                    symbol: placeIntent.symbol,
                    action: "proposal_constraint_blocked",
                    errorCode: "proposal_max_daily_notional"
                )
                return .failure(
                    code: "proposal_max_daily_notional",
                    message: "Proposal maxDailyNotional exceeded."
                )
            }

            state.cumulativeNotional += orderNotional
        }

        strategyRunConstraintStateByID[strategyID] = state
        return nil
    }

    private func shouldRunMarketData(for watchlistSymbols: [String]) -> Bool {
        configuration.marketDataFeed == .test || !watchlistSymbols.isEmpty
    }

    private func syncMarketDataLifecycle(watchlistSymbols: [String]) async {
        let subscriptionSymbols = await portfolioWatchMarketDataCoverageSymbols(
            watchlistSymbols: watchlistSymbols
        )
        if shouldRunMarketData(for: subscriptionSymbols) {
            await ensureMarketDataPipelineStarted()
            await marketDataStream.setWatchSymbols(subscriptionSymbols)
        } else {
            await stopMarketDataPipeline()
        }
    }

    private func portfolioWatchMarketDataCoverageSymbols(
        watchlistSymbols: [String]
    ) async -> [String] {
        let normalizedWatchlist = Array(
            MarketDataSubscriptionSet.normalized(watchlistSymbols)
        ).sorted()
        let chartWallConfiguration = try? await portfolioWatchChartWallConfigurationStore.loadOrDefault(
            watchlistSymbols: normalizedWatchlist
        )
        let selectedSymbols = PortfolioWatchChartWallConfiguration.effectiveSelectedSymbols(
            selectedSymbols: chartWallConfiguration?.selectedSymbols ?? [],
            watchlistSymbols: normalizedWatchlist
        )
        return orderedUniqueStrings(normalizedWatchlist + selectedSymbols)
    }

    private func ensureMarketDataPipelineStarted() async {
        guard marketDataEventTask == nil else {
            ensureMarketDataNoFirstDataMonitorStarted()
            return
        }

        await marketDataStream.start()
        marketDataEventTask = Task { [weak self, marketDataStream] in
            for await event in marketDataStream.events {
                await self?.handleMarketDataEvent(event)
            }
        }
        ensureMarketDataNoFirstDataMonitorStarted()
    }

    private func stopMarketDataPipeline() async {
        marketDataNoFirstDataMonitorTask?.cancel()
        marketDataNoFirstDataMonitorTask = nil
        marketDataEventTask?.cancel()
        marketDataEventTask = nil
        await marketDataStream.stop()
        await store.setMarketDataConnectionState(.disconnected)
    }

    private func ensureMarketDataNoFirstDataMonitorStarted() {
        guard marketDataNoFirstDataMonitorTask == nil else {
            return
        }
        let interval = marketDataNoFirstDataMonitorInterval
        let sleep = marketDataNoFirstDataMonitorSleep
        marketDataNoFirstDataMonitorTask = Task { [weak self] in
            while Task.isCancelled == false {
                await sleep(interval)
                guard Task.isCancelled == false else {
                    return
                }
                await self?.evaluateMarketDataNoFirstDataRecovery(trigger: "monitor")
            }
        }
    }

    private func handleTradeUpdatesEvent(_ event: TradeUpdatesStreamEvent) async {
        switch event {
        case .connectionStateChanged(let state):
            isConnected = (state == .subscribed)
            await store.setConnectionState(state)
            if state == .subscribed {
                await store.publish(StoreEvent(name: "trade_updates_subscribed"))
            }
            if state == .disconnected {
                await store.publish(StoreEvent(name: "trade_updates_disconnected"))
            }
            await publishDerivedAlwaysOnReadinessForCurrentLifecycle()
        case .tradeUpdate(let update):
            await processTradeUpdate(update)
        case .diagnostic(let message):
            await store.publishDiagnostic(message)
            await publishDerivedAlwaysOnReadinessForCurrentLifecycle()
        }
    }

    func processTradeUpdate(
        _ update: TradeUpdateEvent,
        allowRESTRepairs: Bool = true
    ) async {
        await store.publishTradeUpdate(update)
        await recordTradeUpdateForRuns(update)
        await reconcileLiveOrderReviewExecutionLifecycleForTradeUpdate(update, source: .engine)

        if allowRESTRepairs && shouldScheduleOpenOrdersRefresh(for: update) {
            await store.publishDiagnostic("open orders refresh scheduled trigger=\(update.event.lowercased())")
            await openOrdersRefresher.trigger { [weak self] in
                await self?.runOpenOrdersRefresh()
            }
        }

        guard allowRESTRepairs,
              configuration.refreshPositionsOnFill,
              shouldSchedulePositionsRefresh(for: update)
        else {
            return
        }

        await store.publishDiagnostic("positions refresh scheduled trigger=\(update.event.lowercased())")
        await positionsRefresher.trigger { [weak self] in
            await self?.runPositionsRefresh()
        }
    }

    func handleMarketDataEvent(_ event: MarketDataStreamEvent) async {
        switch event {
        case .connectionStateChanged(let state):
            if state == .disconnected {
                lastMarketDataSubscriptionAcknowledgedAt = nil
            }
            await store.setMarketDataConnectionState(state)
            await publishDerivedAlwaysOnReadinessForCurrentLifecycle()
        case .desiredSubscriptionChanged(let subscriptions):
            await store.publishMarketDataDesiredSubscription(subscriptions)
            await publishDerivedAlwaysOnReadinessForCurrentLifecycle()
        case .subscriptionChanged(let subscriptions):
            lastMarketDataSubscriptionAcknowledgedAt = subscriptions.isEmpty ? nil : nowDate()
            await store.publishMarketDataSubscription(subscriptions)
            await publishDerivedAlwaysOnReadinessForCurrentLifecycle()
        case .quote(let quote):
            await store.publishMarketQuote(quote)
            await publishMarketDataDrivenAlwaysOnReadinessForCurrentLifecycle()
            await scheduleApprovedPendingPaperPortfolioExecutionRetry(
                triggerSymbols: [quote.symbol],
                source: .engine
            )
        case .trade(let trade):
            await store.publishMarketTrade(trade)
            await publishMarketDataDrivenAlwaysOnReadinessForCurrentLifecycle()
            await scheduleApprovedPendingPaperPortfolioExecutionRetry(
                triggerSymbols: [trade.symbol],
                source: .engine
            )
        case .bar(let bar):
            await store.publishMarketBar(bar)
            await publishMarketDataDrivenAlwaysOnReadinessForCurrentLifecycle()
            await scheduleApprovedPendingPaperPortfolioExecutionRetry(
                triggerSymbols: [bar.symbol],
                source: .engine
            )
        case .diagnostic(let message):
            await store.publishDiagnostic(message)
            await publishDerivedAlwaysOnReadinessForCurrentLifecycle()
        }
    }

    private func publishDerivedAlwaysOnReadinessForCurrentLifecycle() async {
        guard lastHostLifecycleEvent != .hostWillSleep else {
            return
        }
        await publishDerivedAlwaysOnReadiness(event: lastHostLifecycleEvent ?? .engineStart)
    }

    private func publishMarketDataDrivenAlwaysOnReadinessForCurrentLifecycle() async {
        guard lastHostLifecycleEvent != .hostWillSleep else {
            return
        }
        let now = nowDate()
        if let lastMarketDataDrivenReadinessPublishAt,
           now.timeIntervalSince(lastMarketDataDrivenReadinessPublishAt) < marketDataReadinessPublishMinimumInterval {
            return
        }
        lastMarketDataDrivenReadinessPublishAt = now
        await publishDerivedAlwaysOnReadiness(event: lastHostLifecycleEvent ?? .engineStart)
    }

    @discardableResult
    func evaluateMarketDataNoFirstDataRecoveryForTesting(
        trigger: String = "test"
    ) async -> Bool {
        await evaluateMarketDataNoFirstDataRecovery(trigger: trigger)
    }

    @discardableResult
    private func evaluateMarketDataNoFirstDataRecovery(trigger: String) async -> Bool {
        guard isStarted,
              marketDataEventTask != nil
        else {
            return false
        }
        let snapshot = await store.snapshot()
        let assessedAt = nowDate()
        let assessment = makeMarketDataNoFirstDataRecoveryAssessment(
            desiredMarketData: snapshot.marketDataDesiredSubscriptions,
            activeMarketData: snapshot.marketDataSubscriptions,
            marketDataConnectionState: snapshot.marketDataConnectionState,
            lastMarketDataReceivedAt: snapshot.lastMarketDataReceivedAt,
            lastSubscriptionAcknowledgedAt: lastMarketDataSubscriptionAcknowledgedAt,
            now: assessedAt,
            feed: configuration.marketDataFeed,
            lastRecoveryAt: lastMarketDataNoFirstDataRecoveryAt,
            recoveryCount: marketDataNoFirstDataRecoveryCount,
            maximumRecoveryCount: marketDataNoFirstDataRecoveryMaximumCount,
            firstAckGrace: marketDataNoFirstDataFirstAckGrace,
            recoveryMinimumInterval: marketDataNoFirstDataRecoveryMinimumInterval
        )
        guard assessment.shouldRecover else {
            return false
        }

        let watchlistSymbols = snapshot.watchlistSymbols
        let subscriptionSymbols = await portfolioWatchMarketDataCoverageSymbols(
            watchlistSymbols: watchlistSymbols
        )
        guard shouldRunMarketData(for: subscriptionSymbols) else {
            return false
        }

        marketDataNoFirstDataRecoveryCount += 1
        lastMarketDataNoFirstDataRecoveryAt = assessedAt
        lastMarketDataNoFirstDataRecoveryReason = assessment.reason
        let reason = assessment.reason ?? "active subscriptions acknowledged but no Store market-data event arrived"
        await store.publishDiagnostic(
            "market_data no-first-data recovery triggered count=\(marketDataNoFirstDataRecoveryCount) trigger=\(trigger) symbols=\(subscriptionSymbols.prefix(12).joined(separator: ",")) reason=\(reason)",
            source: .engine,
            level: .warning,
            action: "market_data_no_first_data_recovery"
        )
        await marketDataStream.requestReconnect(reason: "no_first_data")
        await marketDataStream.setWatchSymbols(subscriptionSymbols)
        await publishDerivedAlwaysOnReadinessForCurrentLifecycle()
        return true
    }

    private func resumeApprovedPendingPaperPortfolioExecutionsIfNeeded(
        source: AuditEventSource
    ) async {
        do {
            let requests = try await listPMApprovalRequests()
                .filter { approvedPendingPaperPortfolioExecutionState(for: $0) != nil }
                .sorted { lhs, rhs in
                    if lhs.updatedAt == rhs.updatedAt {
                        return lhs.approvalRequestId < rhs.approvalRequestId
                    }
                    return lhs.updatedAt > rhs.updatedAt
                }

            guard requests.isEmpty == false else {
                return
            }

            for request in requests {
                guard let pendingState = approvedPendingPaperPortfolioExecutionState(for: request) else {
                    continue
                }
                await requestWorkingPaperPortfolioPriceRecoverySubscriptions(
                    approvalRequestId: request.approvalRequestId,
                    symbols: pendingState.marketDataSubscriptionSymbols,
                    source: source
                )
            }

            await scheduleApprovedPendingPaperPortfolioExecutionRetry(
                triggerSymbols: nil,
                source: source
            )
        } catch {
            await store.publishDiagnostic(
                "pm paper-portfolio pending execution resume degraded reason=\(error.localizedDescription)",
                source: source,
                action: "pm_paper_portfolio_execution_resume_failed"
            )
        }
    }

    private func scheduleApprovedPendingPaperPortfolioExecutionRetry(
        triggerSymbols: [String]?,
        source: AuditEventSource
    ) async {
        pendingPaperExecutionRetryTask?.cancel()
        let normalizedTriggerSymbols = triggerSymbols.map {
            Array(MarketDataSubscriptionSet.normalized($0)).sorted()
        }
        let delay = pmPendingPaperExecutionRetryDebounceWindow
        pendingPaperExecutionRetryTask = Task { [weak self] in
            guard let self else { return }
            await self.pmPendingPaperExecutionRetrySleep(delay)
            guard Task.isCancelled == false else {
                return
            }
            await self.retryApprovedPendingPaperPortfolioExecutionsIfNeeded(
                triggerSymbols: normalizedTriggerSymbols,
                source: source
            )
        }
    }

    private func retryApprovedPendingPaperPortfolioExecutionsIfNeeded(
        triggerSymbols: [String]?,
        source: AuditEventSource
    ) async {
        do {
            let requests = try await listPMApprovalRequests()
                .filter { approvedPendingPaperPortfolioExecutionState(for: $0) != nil }
                .sorted { lhs, rhs in
                    if lhs.updatedAt == rhs.updatedAt {
                        return lhs.approvalRequestId < rhs.approvalRequestId
                    }
                    return lhs.updatedAt > rhs.updatedAt
                }

            guard requests.isEmpty == false else {
                return
            }

            let triggerSet = triggerSymbols.map(Set.init)
            for request in requests {
                guard let pendingState = approvedPendingPaperPortfolioExecutionState(for: request) else {
                    continue
                }
                if let triggerSet,
                   triggerSet.isDisjoint(with: Set(pendingState.missingPriceSymbols)) {
                    continue
                }

                let retriedAt = nowDate()
                let assessment = try await routeWorkingPaperPortfolioExecution(
                    request: request,
                    source: source
                )
                await recordApprovedPendingPaperPortfolioExecutionAutoRetryFollowThroughIfNeeded(
                    request: request,
                    assessment: assessment,
                    source: source
                )

                if assessment.status == .blockedExecutionPrerequisites,
                   assessment.blockedReasons.contains(.marketPriceUnavailable) {
                    var refreshedRequest = try await getPMApprovalRequest(id: request.approvalRequestId)
                    if var pending = refreshedRequest.paperPortfolioExecutionPendingState {
                        pending.lastRetryAttemptedAt = retriedAt
                        pending.updatedAt = retriedAt
                        refreshedRequest.paperPortfolioExecutionPendingState = pending
                        refreshedRequest.updatedAt = retriedAt
                        _ = try await upsertPMApprovalRequest(refreshedRequest, source: source)
                    }
                }
            }
        } catch {
            await store.publishDiagnostic(
                "pm paper-portfolio pending execution retry degraded reason=\(error.localizedDescription)",
                source: source,
                action: "pm_paper_portfolio_execution_retry_failed"
            )
        }
    }

    private func recordApprovedPendingPaperPortfolioExecutionAutoRetryFollowThroughIfNeeded(
        request: PMApprovalRequest,
        assessment: PMExecutionRoutingAssessment,
        source: AuditEventSource
    ) async {
        guard source != .ui else {
            return
        }
        if assessment.status == .blockedExecutionPrerequisites,
           assessment.blockedReasons.contains(.marketPriceUnavailable) {
            return
        }
        guard let sourceMessageId = trimmedOptionalDecisionText(request.sourceCommunicationMessageId) else {
            return
        }

        do {
            guard let sourceMessage = try await pmCommunicationMessageStore.get(id: sourceMessageId) else {
                return
            }
            let detail = boundedConversationText(assessment.detail, limit: 520)
            let body = [
                "Approved paper-portfolio execution retry update:",
                assessment.summary,
                detail.isEmpty || detail.caseInsensitiveCompare(assessment.summary) == .orderedSame ? nil : detail
            ]
                .compactMap { $0 }
                .joined(separator: "\n\n")
            _ = try await createPMCommunicationMessage(
                sessionId: sourceMessage.sessionId,
                senderRole: .pm,
                senderId: request.pmId,
                body: body,
                replyToMessageId: nil,
                source: source
            )
            await store.publishDiagnostic(
                "pm paper-portfolio pending execution retry follow-through recorded approval_request=\(shortOrderID(request.approvalRequestId)) session=\(shortOrderID(sourceMessage.sessionId)) status=\(assessment.status.rawValue)",
                source: source,
                action: "pm_paper_portfolio_execution_retry_follow_through"
            )
        } catch {
            await store.publishDiagnostic(
                "pm paper-portfolio pending execution retry follow-through failed approval_request=\(shortOrderID(request.approvalRequestId)) reason=\(error.localizedDescription)",
                source: source,
                action: "pm_paper_portfolio_execution_retry_follow_through_failed"
            )
        }
    }

    private func shouldSchedulePositionsRefresh(for update: TradeUpdateEvent) -> Bool {
        let trigger = update.event.lowercased()
        if trigger == "fill" || trigger == "partial_fill" || trigger == "partial-fill" {
            return true
        }

        guard let status = update.orderStatus?.lowercased() else {
            return false
        }
        return status == "filled" || status == "partially_filled" || status == "partially-filled"
    }

    private func shouldScheduleOpenOrdersRefresh(for update: TradeUpdateEvent) -> Bool {
        let trigger = update.event.lowercased()
        let triggerEvents: Set<String> = [
            "new",
            "pending_new",
            "pending-new",
            "replaced",
            "canceled",
            "cancelled",
            "rejected",
            "fill",
            "partial_fill",
            "partial-fill"
        ]
        if triggerEvents.contains(trigger) {
            return true
        }

        guard let status = update.orderStatus?.lowercased() else {
            return false
        }
        let closingOrChangingStatuses: Set<String> = [
            "new",
            "pending_new",
            "pending-new",
            "replaced",
            "canceled",
            "cancelled",
            "rejected",
            "filled",
            "partially_filled",
            "partially-filled"
        ]
        return closingOrChangingStatuses.contains(status)
    }

    private func runOpenOrdersRefresh() async {
        do {
            let openOrders = try await restClient.fetchOpenOrders()
            await store.reconcileOpenOrdersSnapshot(openOrders)
            await store.publishDiagnostic("open orders refresh completed open_orders=\(openOrders.count)")
        } catch {
            await store.publishDiagnostic("open orders refresh failed reason=\(error.localizedDescription)")
        }
    }

    private func runPositionsRefresh() async {
        do {
            let positions = try await restClient.fetchPositions()

            var account: Account?
            do {
                let latestAccount = try await restClient.fetchAccount()
                lastKnownAccount = latestAccount
                account = latestAccount
            } catch {
                await store.publishDiagnostic("positions refresh account update skipped reason=\(error.localizedDescription)")
            }

            await store.applyPositionsRefreshSnapshot(positions: positions, account: account)
            await store.publishDiagnostic("positions refresh completed positions=\(positions.count)")
        } catch {
            await store.publishDiagnostic("positions refresh failed reason=\(error.localizedDescription)")
        }
    }

