        await store.setTradingSafetyState(
            isLive: configuration.environment == .live,
            isArmedForLiveTrading: isArmedForLiveTrading,
            armingSessionID: armingSessionID,
            killSwitchEnabled: killSwitchEnabled
        )
    }

    private func configureJobRunnerIfNeeded() async {
        guard !jobRunnerConfigured else {
            return
        }
        jobRunnerConfigured = true

        await jobRunner.configure(
            monitorExecutor: { [weak self] job, updateProgress in
                guard let self else {
                    throw JobRunnerError.invalidParameters(message: "Engine unavailable for monitor job.")
                }
                return try await self.executeMonitorJob(
                    job: job,
                    updateProgress: updateProgress
                )
            },
            replayBatchExecutor: { [weak self] job, updateProgress in
                guard let self else {
                    throw JobRunnerError.invalidParameters(message: "Engine unavailable for replay batch job.")
                }
                return try await self.executeReplayBatchJob(
                    job: job,
                    updateProgress: updateProgress
                )
            },
            rssPollExecutor: { [weak self] job, updateProgress in
                guard let self else {
                    throw JobRunnerError.invalidParameters(message: "Engine unavailable for rss poll job.")
                }
                return try await self.executeRSSPollJob(
                    job: job,
                    updateProgress: updateProgress
                )
            },
            newsRetentionExecutor: { [weak self] job, updateProgress in
                guard let self else {
                    throw JobRunnerError.invalidParameters(message: "Engine unavailable for news retention job.")
                }
                return try await self.executeNewsRetentionJob(
                    job: job,
                    updateProgress: updateProgress
                )
            },
            analystSignalsExecutor: { [weak self] job, updateProgress in
                guard let self else {
                    throw JobRunnerError.invalidParameters(message: "Engine unavailable for analyst signals job.")
                }
                return try await self.executeAnalystSignalsJob(
                    job: job,
                    updateProgress: updateProgress
                )
            },
            standingAnalystReportExecutor: { [weak self] job, updateProgress in
                guard let self else {
                    throw JobRunnerError.invalidParameters(message: "Engine unavailable for standing analyst report job.")
                }
                return try await self.executeStandingAnalystReportJob(
                    job: job,
                    updateProgress: updateProgress
                )
            },
            recentNewsAnalystExecutor: { [weak self] job, updateProgress in
                guard let self else {
                    throw JobRunnerError.invalidParameters(message: "Engine unavailable for recent news analyst job.")
                }
                return try await self.executeRecentNewsAnalystJob(
                    job: job,
                    updateProgress: updateProgress
                )
            },
            portfolioRiskAnalystExecutor: { [weak self] job, updateProgress in
                guard let self else {
                    throw JobRunnerError.invalidParameters(message: "Engine unavailable for portfolio risk analyst job.")
                }
                return try await self.executePortfolioRiskAnalystJob(
                    job: job,
                    updateProgress: updateProgress
                )
            },
            maintenanceRetentionExecutor: { [weak self] job, updateProgress in
                guard let self else {
                    throw JobRunnerError.invalidParameters(message: "Engine unavailable for maintenance retention job.")
                }
                return await self.executeMaintenanceRetentionJob(
                    job: job,
                    updateProgress: updateProgress
                )
            },
            onJobUpdated: { [weak self] _ in
                guard let self else {
                    return
                }
                await self.refreshJobsSnapshot()
            },
            onDiagnostic: { [weak self] message, level, action in
                await self?.store.publishDiagnostic(
                    message,
                    source: .engine,
                    level: level,
                    action: action
                )
            }
        )
    }

    private func executeMonitorJob(
        job: JobRecord,
        updateProgress: JobRunner.JobProgressUpdater
    ) async throws -> JobExecutionReport {
        let intervalSec = try monitorIntervalParam(job.parameters["intervalSec"])
        let threshold = try monitorThresholdParam(job.parameters["threshold"])
        let maxTicks = try monitorMaxTicksParam(job.parameters["maxTicks"])
        let configuredSymbols = try monitorSymbolsParam(job.parameters["symbols"])

        var baselineBySymbol: [String: Double] = [:]
        var alertsTriggered = 0
        var ticks = 0

        while !Task.isCancelled {
            let snapshot = await store.snapshot()
            let symbols = resolvedMonitorSymbols(
                configuredSymbols: configuredSymbols,
                snapshot: snapshot
            )

            for symbol in symbols {
                guard let price = monitorPrice(
                    for: symbol,
                    snapshot: snapshot
                ) else {
                    continue
                }

                let baseline = baselineBySymbol[symbol] ?? price
                baselineBySymbol[symbol] = baseline
                guard baseline > 0 else {
                    continue
                }

                let score = (price - baseline) / baseline
                if abs(score) >= threshold {
                    alertsTriggered += 1
                    let roundedScore = roundedScoreValue(score)
                    let roundedThreshold = roundedScoreValue(threshold)
                    await store.publishDiagnostic(
                        "job monitor alert id=\(shortOrderID(job.jobId)) symbol=\(symbol) score=\(roundedScore) threshold=\(roundedThreshold)",
                        source: .engine,
                        symbol: symbol,
                        action: "job_monitor_alert"
                    )
                    await store.publishNotification(
                        source: "job.monitor",
                        message: "\(symbol) score \(roundedScore) crossed threshold \(roundedThreshold)",
                        jobId: job.jobId,
                        symbol: symbol,
                        score: score
                    )
                }
            }

            ticks += 1
            if let maxTicks {
                await updateProgress(
                    Double(ticks) / Double(maxTicks),
                    "Monitor tick \(ticks)/\(maxTicks)"
                )
                if ticks >= maxTicks {
                    break
                }
            } else if shouldPublishIndefiniteMonitorProgress(
                ticks: ticks,
                intervalSec: intervalSec
            ) {
                await updateProgress(nil, "Monitor tick \(ticks)")
            }

            await replaySleep(intervalSec)
        }

        if Task.isCancelled {
            throw CancellationError()
        }

        let result: JSONValue = .object([
            "jobType": .string(JobType.monitor.rawValue),
            "ticks": .number(Double(ticks)),
            "alertsTriggered": .number(Double(alertsTriggered)),
            "symbolsObserved": .array(resolvedMonitorObservedSymbols(baselines: baselineBySymbol).map(JSONValue.string))
        ])
        return JobExecutionReport(result: result)
    }

    private func shouldPublishIndefiniteMonitorProgress(
        ticks: Int,
        intervalSec: TimeInterval
    ) -> Bool {
        guard ticks > 0 else {
            return false
        }
        if ticks == 1 {
            return true
        }
        let updateEveryTicks = max(
            1,
            Int(ceil(Self.indefiniteMonitorProgressMinimumIntervalSec / intervalSec))
        )
        return ticks.isMultiple(of: updateEveryTicks)
    }

    private func executeRSSPollJob(
        job: JobRecord,
        updateProgress: JobRunner.JobProgressUpdater
    ) async throws -> JobExecutionReport {
        let selectedFeedIDs = Set(try stringListParam(job.parameters["feedIds"]))
        let maxItemsPerFeed = try newsMaxItemsParam(job.parameters["maxItemsPerFeed"])
        let includeAlpaca = replayBoolParam(job.parameters["includeAlpaca"], defaultValue: true)

        var totalInserted = 0
        var totalDuplicates = 0
        var totalErrors = 0
        var totalFeedsPolled = 0
        var totalItemsParsed = 0
        var totalSECFilingsParsed = 0
        var totalFailedFeeds = 0
        var totalSECFailures = 0
        var perFeedInserted: [String: Int] = [:]
        var perFeedFailures: [String: Int] = [:]
        await updateProgress(0, "RSS poll started")

        let now = nowDate()
        let feeds = try await rssFeedStore.listFeeds()
        let enabledFeeds = feeds.filter { feed in
            if !feed.enabled {
                return false
            }
            if selectedFeedIDs.isEmpty {
                return true
            }
            return selectedFeedIDs.contains(feed.id)
        }

        var cycleSummaries: [String] = []
        for feed in enabledFeeds {
            do {
                let polled = try await pollRSSFeed(
                    feed: feed,
                    maxItemsPerFeed: maxItemsPerFeed,
                    now: now
                )
                totalFeedsPolled += 1
                totalItemsParsed += polled.itemsParsed
                totalInserted += polled.inserted
                totalDuplicates += polled.duplicates
                perFeedInserted[feed.id, default: 0] += polled.inserted
                cycleSummaries.append("\(feed.name):parsed\(polled.itemsParsed)/+\(polled.inserted)/dup\(polled.duplicates)")
            } catch {
                totalErrors += 1
                totalFailedFeeds += 1
                perFeedFailures[feed.id, default: 0] += 1
                if let rssError = error as? RSSFeedFetchError {
                    cycleSummaries.append("\(feed.name):\(rssError.compactSummary)")
                } else {
                    cycleSummaries.append("\(feed.name):error")
                }
                await store.publishDiagnostic(
                    "rss poll failed feed=\(feed.name) reason=\(error.localizedDescription)",
                    source: .engine,
                    level: .warning,
                    action: "rss_poll"
                )
            }
        }

        let secFilings = await secFilingsProvider.fetchRecentFilings(
            for: await store.snapshot().watchlistSymbols
        )
        if secFilings.requestedSymbols.isEmpty {
            newsIngestStatus.secStatus = "watchlist_empty"
        } else {
            totalSECFilingsParsed = secFilings.filings.count
            totalSECFailures += secFilings.failedSymbols.count
            totalErrors += secFilings.failedSymbols.count

            let secEvents = secFilings.filings.map {
                NewsEventFactory.makeFromSECFiling(filing: $0, now: now)
            }
            let appended = try await newsStore.append(secEvents)
            totalInserted += appended.inserted
            totalDuplicates += appended.duplicates

            if secFilings.filings.isEmpty,
               secFilings.failedSymbols.isEmpty,
               secFilings.diagnostics.isEmpty {
                newsIngestStatus.secStatus = "watch=\(secFilings.requestedSymbols.count) no_recent_filings"
                cycleSummaries.append("SEC:no_recent_filings")
            } else {
                newsIngestStatus.secStatus =
                    "watch=\(secFilings.requestedSymbols.count) filings=\(secFilings.filings.count) new=\(appended.inserted) dup=\(appended.duplicates) failed=\(secFilings.failedSymbols.count)"
                cycleSummaries.append(
                    "SEC:watch\(secFilings.requestedSymbols.count)/filings\(secFilings.filings.count)/+\(appended.inserted)/dup\(appended.duplicates)/fail\(secFilings.failedSymbols.count)"
                )
            }

            for diagnostic in secFilings.diagnostics {
                await store.publishDiagnostic(
                    diagnostic,
                    source: .engine,
                    level: .warning,
                    action: "rss_poll"
                )
            }
        }

        let alpacaNewsEnabled = includeAlpaca
            ? await newsSourceSettingsStore.load().alpacaNewsEnabled
            : true
        if includeAlpaca && !alpacaNewsEnabled {
            newsIngestStatus.alpacaStatus = "disabled"
        } else if includeAlpaca {
            do {
                let items = try await resolveAlpacaNewsClient().fetchLatest(limit: maxItemsPerFeed)
                let events = items.map { NewsEventFactory.makeFromAlpaca(item: $0, now: now) }
                let appended = try await newsStore.append(events)
                totalInserted += appended.inserted
                totalDuplicates += appended.duplicates
                newsIngestStatus.alpacaStatus = "ok new=\(appended.inserted) dup=\(appended.duplicates)"
            } catch {
                totalErrors += 1
                newsIngestStatus.alpacaStatus = "unavailable (\(type(of: error)))"
                await store.publishDiagnostic(
                    "alpaca news ingest unavailable reason=\(error.localizedDescription)",
                    source: .engine,
                    level: .warning,
                    action: "alpaca_news_ingest"
                )
            }
        }

        if cycleSummaries.isEmpty, enabledFeeds.isEmpty {
            cycleSummaries = ["no_enabled_feeds"]
        }

        newsIngestStatus.rssStatus = cycleSummaries.joined(separator: " | ")
        newsIngestStatus.lastUpdatedAt = now
        await store.setNewsIngestStatus(newsIngestStatus)
        await refreshRSSFeedsSnapshot(lastPollStatus: newsIngestStatus.rssStatus)
        await refreshNewsSnapshot()
        await publishNewsPersistenceDiagnostics()

        let summary = "rss_poll: feeds=\(totalFeedsPolled) parsed=\(totalItemsParsed) sec=\(totalSECFilingsParsed) new=\(totalInserted) dup=\(totalDuplicates) failed=\(totalFailedFeeds + totalSECFailures)"
        await updateProgress(1, summary)
        let result: JSONValue = .object([
            "jobType": .string(JobType.rssPoll.rawValue),
            "ticks": .number(1),
            "feedsPolled": .number(Double(totalFeedsPolled)),
            "itemsParsed": .number(Double(totalItemsParsed)),
            "secFilingsParsed": .number(Double(totalSECFilingsParsed)),
            "secRequestedSymbols": .number(Double(secFilings.requestedSymbols.count)),
            "secResolvedSymbols": .number(Double(secFilings.resolvedSymbols.count)),
            "secFailedSymbols": .number(Double(secFilings.failedSymbols.count)),
            "newEvents": .number(Double(totalInserted)),
            "inserted": .number(Double(totalInserted)),
            "duplicates": .number(Double(totalDuplicates)),
            "failedFeeds": .number(Double(totalFailedFeeds + totalSECFailures)),
            "errors": .number(Double(totalErrors)),
            "feeds": .object(perFeedInserted.mapValues { .number(Double($0)) }),
            "feedFailures": .object(perFeedFailures.mapValues { .number(Double($0)) }),
            "summary": .string(summary)
        ])
        return JobExecutionReport(result: result)
    }

    private func executeNewsRetentionJob(
        job: JobRecord,
        updateProgress: JobRunner.JobProgressUpdater
    ) async throws -> JobExecutionReport {
        let keepDays = max(1, job.parameters["keepDays"]?.intValue ?? 30)
        let maxTotalMB = job.parameters["maxTotalMB"]?.intValue

        await updateProgress(0, "Retention started")
        let result = try await newsStore.purge(
            keepDays: keepDays,
            maxTotalMB: maxTotalMB
        )
        await refreshNewsSnapshot()
        await publishNewsPersistenceDiagnostics()
        await updateProgress(1, "Retention completed")

        await store.publishDiagnostic(
            "news retention completed keep_days=\(keepDays) files_removed=\(result.filesRemoved) bytes_removed=\(result.bytesRemoved)",
            source: .engine,
            action: "news_retention"
        )

        return JobExecutionReport(
            result: .object([
                "jobType": .string(JobType.newsRetention.rawValue),
                "keepDays": .number(Double(keepDays)),
                "filesRemoved": .number(Double(result.filesRemoved)),
                "bytesRemoved": .number(Double(result.bytesRemoved)),
                "maxTotalMB": maxTotalMB.map { .number(Double($0)) } ?? .null
            ])
        )
    }

    private func executeMaintenanceRetentionJob(
        job: JobRecord,
        updateProgress: JobRunner.JobProgressUpdater
    ) async -> JobExecutionReport {
        let dryRun = replayBoolParam(job.parameters["dryRun"], defaultValue: true)
        let jobTelemetryCleanupBefore = job.parameters["jobTelemetryCleanupBefore"]?.stringValue
            .flatMap(DateCodec.parseISO8601)
        let policy = await maintenanceService.loadPolicy().normalized()

        await updateProgress(0, "Maintenance started")
        let summary = await maintenanceService.run(
            policy: policy,
            dryRun: dryRun,
            jobTelemetryCleanupBefore: jobTelemetryCleanupBefore
        )
        await refreshNewsSnapshot()
        await refreshJobsSnapshot()
        await refreshSchedulesSnapshot()
        await publishRetentionPolicyPersistenceDiagnostics()
        await updateProgress(1, "Maintenance completed")

        let level: AuditEventLevel = summary.hasErrors ? .warning : .info
        await store.publishDiagnostic(
            summary.compactSummaryLine,
            source: .engine,
            level: level,
            action: "maintenance_retention"
        )

        return JobExecutionReport(
            result: maintenanceRunSummaryJSON(summary)
        )
    }

    private func executeAnalystSignalsJob(
        job: JobRecord,
        updateProgress: JobRunner.JobProgressUpdater
    ) async throws -> JobExecutionReport {
        let intervalSec = try monitorIntervalParam(job.parameters["pollIntervalSec"])
        let lookbackMinutes = try replayPositiveIntParam(
            job.parameters["lookbackMinutes"],
            defaultValue: 240,
            field: "lookbackMinutes"
        )
        let minScoreThreshold = try analystMinScoreThreshold(job.parameters["minScoreThreshold"])
        let mode = try analystSignalsMode(job.parameters["mode"])
        let strategyIDForDrafts = analystSignalsDraftStrategyID(job.parameters["strategyIdForDrafts"])
        let maxTicks = try monitorMaxTicksParam(job.parameters["maxTicks"])
        let sourceJobID = job.jobId

        var ticks = 0
        var insertedSignals = 0
        var updatedSignals = 0
        var draftedProposals = 0

        while !Task.isCancelled {
            let now = nowDate()
            let since = Calendar(identifier: .gregorian).date(
                byAdding: .minute,
                value: -lookbackMinutes,
                to: now
            ) ?? now

            let recentNews = try await newsStore.listRecent(limit: 300, since: since)
            let snapshot = await store.snapshot()
            let generated = scoringEngine.generateSignals(
                input: SignalScoringInput(
                    recentNews: recentNews,
                    snapshot: snapshot,
                    now: now,
                    sourceJobId: sourceJobID,
                    scoringVersion: analystScoringVersion,
                    draftThreshold: minScoreThreshold
                )
            ).filter { $0.score >= minScoreThreshold }

            var generatedCount = 0
            for var signal in generated {
                generatedCount += 1
                let existing = try await signalStore.get(id: signal.signalId)
                if mode == .draftProposals,
                   signal.recommendedAction == .draftProposal {
                    let proposalID = try await draftProposalFromSignal(
                        signal: signal,
                        strategyID: strategyIDForDrafts,
                        sourceJobID: sourceJobID,
                        source: .engine
                    )
                    signal.draftedProposalId = proposalID
                    signal.linkedProposalId = proposalID
                    if existing?.draftedProposalId != proposalID {
                        draftedProposals += 1
                    }
                }

                _ = try await signalStore.upsert(signal)
                if existing == nil {
                    insertedSignals += 1
                } else {
                    updatedSignals += 1
                }
            }

            await refreshSignalsSnapshot()
            if mode == .draftProposals, generatedCount > 0 {
                await refreshProposalsSnapshot()
            }

            await store.publishDiagnostic(
                "analyst signals tick id=\(shortOrderID(job.jobId)) generated=\(generatedCount) inserted=\(insertedSignals) updated=\(updatedSignals) drafted=\(draftedProposals)",
                source: .engine,
                action: "analyst_signals"
            )

            ticks += 1
            if let maxTicks {
                await updateProgress(
                    Double(ticks) / Double(maxTicks),
                    "Analyst signals tick \(ticks)/\(maxTicks)"
                )
                if ticks >= maxTicks {
                    break
                }
            } else {
                await updateProgress(nil, "Analyst signals tick \(ticks)")
            }

            await replaySleep(intervalSec)
        }

        if Task.isCancelled {
            throw CancellationError()
        }

        return JobExecutionReport(
            result: .object([
                "jobType": .string(JobType.analystSignals.rawValue),
                "ticks": .number(Double(ticks)),
                "insertedSignals": .number(Double(insertedSignals)),
                "updatedSignals": .number(Double(updatedSignals)),
                "draftedProposals": .number(Double(draftedProposals)),
                "mode": .string(mode.rawValue),
                "minScoreThreshold": .number(minScoreThreshold),
                "lookbackMinutes": .number(Double(lookbackMinutes))
            ])
        )
    }

    private func executeStandingAnalystReportJob(
        job: JobRecord,
        updateProgress: JobRunner.JobProgressUpdater
    ) async throws -> JobExecutionReport {
        let now = nowDate()
        let scheduleID = try requiredStandingReportString(job.parameters["_scheduleId"], field: "_scheduleId")
        let charterID = try requiredStandingReportString(job.parameters["charterId"], field: "charterId")
        let analystID = try requiredStandingReportString(job.parameters["analystId"], field: "analystId")

        guard let schedule = try await scheduler.getSchedule(id: scheduleID) else {
            throw ScheduleStoreError.scheduleNotFound(id: scheduleID)
        }

        try await ensureStandingAnalystBenchSeeded()
        let charter = try await getAnalystCharter(id: charterID)
        guard charter.analystId == analystID else {
            throw JobRunnerError.invalidParameters(
                message: "Standing report schedule analyst mismatch for charter \(charterID)."
            )
        }

        await updateProgress(0, "Preparing standing analyst report")
        let strategyBrief = try await getPortfolioStrategyBrief()
        let snapshot = await store.snapshot()
        if let suppressedSummary = standingAnalystReportSuppressionSummary(
            charter: charter,
            positions: snapshot.positions
        ) {
            await updateProgress(1, suppressedSummary)
            await store.publishDiagnostic(
                "standing analyst report skipped schedule=\(shortOrderID(schedule.scheduleId)) reason=no_portfolio_for_risk_report",
                source: .engine,
                action: "standing_analyst_report"
            )
            return JobExecutionReport(
                result: .object([
                    "jobType": .string(JobType.standingAnalystReport.rawValue),
                    "scheduleId": .string(schedule.scheduleId),
                    "charterId": .string(charter.charterId),
                    "analystId": .string(charter.analystId),
                    "reportCreated": .bool(false),
                    "summary": .string(suppressedSummary)
                ])
            )
        }
        let reportingWindowStart = Calendar(identifier: .gregorian).date(
            byAdding: .second,
            value: -max(3_600, schedule.trigger.intervalSec),
            to: now
        ) ?? now
        let recentNews = try await newsStore.listRecent(limit: 180, since: reportingWindowStart)
        let scopedRecentNews = standingAnalystScopedRecentNews(
            charter: charter,
            positions: snapshot.positions,
            reportingWindowNews: recentNews
        )
        let runtimePolicy = try await standingBenchRuntimePolicyForExecution(
            charter: charter,
            now: now
        )
        let contextPack = try await buildAnalystContextPack(
            charter: charter,
            pmID: nil,
            snapshot: snapshot,
            recentNews: scopedRecentNews,
            strategyBrief: strategyBrief,
            assembledAt: now
        )
        let task = try await upsertAnalystTask(
            makeStandingAnalystReportTask(
                schedule: schedule,
                charter: charter,
                reportingWindowStart: reportingWindowStart,
                reportingWindowNewsCount: recentNews.count,
                scopedRecentNewsCount: scopedRecentNews.count,
                contextPack: contextPack,
                now: now
            ),
            source: .engine
        )
        await updateProgress(0.45, "Standing analyst launching worker")
        let launchResult = try await launchAnalystWorkerOnce(
            charterID: charter.charterId,
            taskID: task.taskId,
            intendedRuntimePolicy: runtimePolicy,
            source: .engine
        )
        guard let memoID = launchResult.memoId else {
            throw AnalystWorkerLaunchError.workerLaunchFailed(
                reason: standingReportRequiredMemoArtifactFailureReason(
                    charter: charter,
                    schedule: schedule,
                    task: task,
                    launchResult: launchResult,
                    returnedMemoID: nil
                )
            )
        }
        guard let memo = try? await getAnalystMemo(id: memoID) else {
            throw AnalystWorkerLaunchError.workerLaunchFailed(
                reason: standingReportRequiredMemoArtifactFailureReason(
                    charter: charter,
                    schedule: schedule,
                    task: task,
                    launchResult: launchResult,
                    returnedMemoID: memoID
                )
            )
        }
        let refreshedTask: AnalystTask
        if let launchedTaskID = launchResult.taskId,
           let loadedTask = try? await getAnalystTask(id: launchedTaskID) {
            refreshedTask = loadedTask
        } else {
            refreshedTask = task
        }
        let evidenceBundle: AnalystEvidenceBundle?
        if let bundleID = memo.evidenceBundleId {
            evidenceBundle = try? await getAnalystEvidenceBundle(id: bundleID)
        } else {
            evidenceBundle = nil
        }
        let draft = makeStandingAnalystReportDraft(
            schedule: schedule,
            charter: charter,
            strategyBrief: strategyBrief,
            positions: snapshot.positions,
            watchlistSymbols: snapshot.watchlistSymbols,
            recentNews: scopedRecentNews,
            externalEvidence: standingAnalystExternalEvidenceDocuments(from: evidenceBundle),
            externalIssues: standingAnalystExternalEvidenceIssues(from: launchResult),
            reportingWindowStart: reportingWindowStart,
            now: now
        )

        let report = try await upsertAnalystStandingReport(
            makeStandingAnalystReportFromWorkerArtifacts(
                schedule: schedule,
                charter: charter,
                memo: memo,
                draft: draft,
                task: refreshedTask,
                evidenceBundle: evidenceBundle,
                now: now
            ),
            source: .engine
        )

        let summary = "standing_analyst_report: delivered \(charter.title) to PM Inbox"
        await updateProgress(1, summary)
        await store.publishDiagnostic(
            "standing analyst report delivered schedule=\(shortOrderID(schedule.scheduleId)) report=\(shortOrderID(report.reportId)) memo=\(shortOrderID(memo.memoId))",
            source: .engine,
            action: "standing_analyst_report"
        )

        let resultPayload: [String: JSONValue] = [
            "jobType": .string(JobType.standingAnalystReport.rawValue),
            "scheduleId": .string(schedule.scheduleId),
            "charterId": .string(charter.charterId),
            "analystId": .string(charter.analystId),
            "memoId": .string(memo.memoId),
            "reportId": .string(report.reportId),
            "actualRuntimeIdentifier": .string(launchResult.runtimeProvenance?.actualRuntimeIdentifier ?? ""),
            "actualReasoningMode": .string(launchResult.runtimeProvenance?.actualReasoningMode?.rawValue ?? ""),
            "intendedProviderKind": .string(launchResult.runtimeProvenance?.intendedPolicy?.providerKind.rawValue ?? ""),
            "intendedRuntimeIdentifier": .string(launchResult.runtimeProvenance?.intendedPolicy?.runtimeIdentifier ?? ""),
            "synthesisStatus": .string(launchResult.synthesisStatus ?? ""),
            "synthesisIssueSummary": .string(
                launchResult.synthesisIssueSummary.map(boundedArtifactFailureDetail) ?? ""
            ),
            "externalEvidenceStatus": .string(launchResult.externalEvidenceStatus ?? ""),
            "externalEvidenceIssueSummary": .string(
                launchResult.externalEvidenceIssueSummary.map(boundedArtifactFailureDetail) ?? ""
            ),
            "summary": .string(summary)
        ]

        return JobExecutionReport(result: .object(resultPayload))
    }

    private func standingReportRequiredMemoArtifactFailureReason(
        charter: AnalystCharter,
        schedule: ScheduledJob,
        task: AnalystTask,
        launchResult: AnalystWorkerLaunchResult,
        returnedMemoID: String?
    ) -> String {
        let reportKind = charter.charterId == recentNewsStandingAnalystCharterID
            ? "Recent News Analyst standing report"
            : "standing analyst report"
        let memoDetail: String
        if let returnedMemoID {
            memoDetail = "worker returned memoId \(shortOrderID(returnedMemoID)), but the app could not load that AnalystMemo from the durable memo store"
        } else {
            memoDetail = "worker returned no memoId"
        }
        var provenance: [String] = []
        if let keyConfigured = launchResult.openAIKeyConfigured {
            provenance.append("openAIKeyConfigured=\(keyConfigured)")
        }
        if let usedOpenAI = launchResult.usedOpenAI {
            provenance.append("usedOpenAI=\(usedOpenAI)")
        }
        if let synthesisStatus = launchResult.synthesisStatus?.trimmingCharacters(in: .whitespacesAndNewlines),
           synthesisStatus.isEmpty == false {
            provenance.append("synthesisStatus=\(boundedArtifactFailureDetail(synthesisStatus))")
        }
        if let synthesisIssue = launchResult.synthesisIssueSummary?.trimmingCharacters(in: .whitespacesAndNewlines),
           synthesisIssue.isEmpty == false {
            provenance.append("synthesisIssue=\(boundedArtifactFailureDetail(synthesisIssue))")
        }
        let provenanceSummary = provenance.isEmpty ? "" : " (\(provenance.joined(separator: ", ")))"
        return "\(reportKind) requires a readable AnalystMemo before PM Inbox delivery; \(memoDetail) for charter \(shortOrderID(charter.charterId)), schedule \(shortOrderID(schedule.scheduleId)), task \(shortOrderID(task.taskId)). No standing report was created.\(provenanceSummary)"
    }

    private func boundedArtifactFailureDetail(_ value: String) -> String {
        let trimmed = value.trimmingCharacters(in: .whitespacesAndNewlines)
        guard trimmed.count > 120 else { return trimmed }
        return String(trimmed.prefix(117)) + "..."
    }

    private struct StandingAnalystDraftSynthesisResult {
        let draft: StandingAnalystReportDraft
        let runtimeProvenance: AnalystRuntimeProvenance?
    }

    private func standingAnalystScopedRecentNews(
        charter: AnalystCharter,
        positions: [PositionRow],
        reportingWindowNews: [NewsEvent]
    ) -> [NewsEvent] {
        let scoped: [NewsEvent]
        switch standingReportContractProfile(for: charter) {
        case .framework, .recentNews:
            scoped = Array(reportingWindowNews.prefix(18))
        case .sector:
            if let profile = standingSectorResearchProfile(for: charter.analystId) {
                scoped = Array(
                    reportingWindowNews
                        .filter { isStandingSectorNewsRelevant($0, profile: profile) }
                        .prefix(18)
                )
            } else {
                scoped = Array(reportingWindowNews.prefix(18))
            }
        case .macroInternational:
            if let profile = standingMacroResearchProfile(for: charter.analystId) {
                scoped = Array(
                    reportingWindowNews
                        .filter { isStandingMacroNewsRelevant($0, profile: profile) }
                        .prefix(18)
                )
            } else {
                scoped = Array(reportingWindowNews.prefix(18))
            }
        case .portfolioRisk:
            let heldSymbols = Set(positions.map { $0.symbol.uppercased() })
            scoped = Array(
                reportingWindowNews
                    .filter { isStandingPortfolioRiskNewsRelevant($0, heldSymbols: heldSymbols) }
                    .prefix(18)
            )
        }
        return scoped
    }

    private func makeStandingAnalystReportTask(
        schedule: ScheduledJob,
        charter: AnalystCharter,
        reportingWindowStart: Date,
        reportingWindowNewsCount: Int,
        scopedRecentNewsCount: Int,
        contextPack: AnalystContextPack,
        now: Date
    ) -> AnalystTask {
        var tags = ["standing_report", "app_news_first", "task-synthesis"]
        if reportingWindowNewsCount > 0, scopedRecentNewsCount == 0 {
            tags.append("app_news_scope_empty")
        }

        let baselineSummary: String
        if scopedRecentNewsCount > 0 {
            baselineSummary = "Start with the scoped app-owned news baseline for this reporting window (\(scopedRecentNewsCount) relevant item(s))."
        } else if reportingWindowNewsCount > 0 {
            baselineSummary = "Start with app-owned recent news, but note explicitly that the current reporting-window feed was noisy or off-scope for this analyst and yielded no materially relevant baseline item."
        } else {
            baselineSummary = "Start with app-owned recent news and state clearly if the current reporting window produced no baseline headlines."
        }

        return AnalystTask(
            taskId: "standing-report-task-\(schedule.scheduleId)",
            analystId: charter.analystId,
            charterId: charter.charterId,
            title: "\(charter.title) standing report refresh",
            description: "\(baselineSummary) Then perform current public-web research unless the charter source policy, selected skills, task wording, or hard app governance expressly restricts it; use the public research to confirm, qualify, or challenge the app-owned baseline. Reporting window begins at \(DateCodec.formatISO8601(reportingWindowStart)). Produce a short recurring analyst report for PM review without PM triage or owner-action language.",
            status: .queued,
            createdAt: now,
            updatedAt: now,
            tags: Array(Set(tags)).sorted(),
            contextPack: contextPack,
            linkedFindingIDs: [],
            linkedProposalIDs: []
        )
    }

    private func standingAnalystExternalEvidenceDocuments(
        from bundle: AnalystEvidenceBundle?
    ) -> [ExternalAnalystEvidenceDocument] {
        guard let bundle else { return [] }
        return bundle.refs.compactMap { ref in
            guard ref.sourceKind == .web,
                  let url = ref.url,
                  url.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty == false else {
                return nil
            }
            return ExternalAnalystEvidenceDocument(
                sourceID: ref.sourceIdentifier ?? "worker_recorded_external_evidence",
                url: url,
                title: ref.title,
                observedAt: ref.observedAt,
                summary: ref.summary ?? "",
                snippet: ref.summary ?? "",
                provenanceNote: ref.freshnessNote ?? "worker_recorded_external_evidence",
                sourceTier: sourceTierForStandingEvidenceRef(ref)
            )
        }
    }

    private func sourceTierForStandingEvidenceRef(_ ref: AnalystEvidenceRef) -> AnalystResearchSourceTier {
        let note = ref.freshnessNote?.lowercased() ?? ""
        let url = ref.url.flatMap(URL.init(string:))
        if note.contains("source_tier=app_owned_truth") {
            return .appOwnedTruth
        }
        if note.contains("source_tier=official_primary") {
            return .officialPrimary
        }
        if note.contains("source_tier=reputable_secondary") {
            return .reputableSecondary
        }
        if note.contains("source_tier=missing_or_restricted") {
            return .missingOrRestricted
        }
        if note.contains("official")
            || note.contains("regulator")
            || note.contains("sec")
            || url?.host?.lowercased().hasSuffix(".gov") == true {
            return .officialPrimary
        }
        if note.contains("restricted") || note.contains("unsupported") || note.contains("missing") {
            return .missingOrRestricted
        }
        return .reputableSecondary
    }

    private func standingAnalystExternalEvidenceIssues(
        from launchResult: AnalystWorkerLaunchResult
    ) -> [AnalystExternalEvidenceIssue] {
        guard let summary = launchResult.externalEvidenceIssueSummary,
              summary.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty == false else {
            return []
        }
        return [
            AnalystExternalEvidenceIssue(
                category: .unexpected,
                detail: summary
            )
        ]
    }

    private func standingAnalystEvidenceReferenceSummary(
        bundle: AnalystEvidenceBundle?,
        fallback: [String]
    ) -> [String] {
        guard let bundle else { return fallback }

        var references: [String] = []
        let appNewsRefs = bundle.refs.filter { $0.sourceKind == .appNews }
        if appNewsRefs.isEmpty == false {
            references.append(
                "App-owned recent news: \(appNewsRefs.prefix(3).map(\.title).joined(separator: " | "))"
            )
        }
        let webRefs = bundle.refs.filter { $0.sourceKind == .web }
        let materialWebRefs = webRefs.filter { standingReportWebRefIsMaterialSupport($0) }
        if materialWebRefs.isEmpty == false {
            references.append(
                "Supplemental outside research: \(materialWebRefs.prefix(3).map(\.title).joined(separator: " | "))"
            )
        }
        return references.isEmpty ? fallback : references
    }

    private func standingReportWebRefIsMaterialSupport(_ ref: AnalystEvidenceRef) -> Bool {
        let title = ref.title.lowercased()
        let summary = ref.summary?.lowercased() ?? ""

        if summary.contains("compacted into corroboration")
            || summary.contains("mostly repeats the app-news fact pattern")
            || summary.contains("mostly repeated the same fact pattern") {
            return false
        }

        if summary.contains("adds incremental timing, background, or strategic/risk context")
            || summary.contains("provided stronger confirmation")
            || summary.contains("stronger or more primary sourcing")
            || summary.contains("qualifies or challenges the app-news baseline")
            || summary.contains("introduced disconfirming or qualifying context") {
            return true
        }

        let genericHints = [
            "stanford ai index",
            "macro seminar",
            "cepr seminar",
            "cepr workshop",
            "benchmark overview"
        ]
        if genericHints.contains(where: { title.contains($0) }) {
            return false
        }

        return true
    }

    private func makeStandingAnalystReportFromWorkerArtifacts(
        schedule: ScheduledJob,
        charter: AnalystCharter,
        memo: AnalystMemo,
        draft: StandingAnalystReportDraft,
        task: AnalystTask,
        evidenceBundle: AnalystEvidenceBundle?,
        now: Date
    ) -> AnalystStandingReport {
        AnalystStandingReport(
            reportId: "standing-report-\(schedule.scheduleId)-\(Int(now.timeIntervalSince1970))",
            analystId: charter.analystId,
            charterId: charter.charterId,
            scheduleId: schedule.scheduleId,
            memoId: memo.memoId,
            runtimeProvenance: memo.runtimeProvenance,
            title: memo.title,
            summary: memo.executiveSummary,
            cadenceIntervalSec: schedule.trigger.intervalSec,
            reportingWindowSummary: draft.reportingWindowSummary,
            portfolioScopeSummary: draft.portfolioScopeSummary,
            coveredSymbols: draft.coveredSymbols,
            headlineView: memo.currentView,
            portfolioRelevanceSummary: draft.portfolioRelevanceSummary,
            openQuestions: task.checkpoint?.openQuestions.isEmpty == false
                ? task.checkpoint?.openQuestions ?? []
                : draft.openQuestions,
            evidenceReferenceSummary: standingAnalystEvidenceReferenceSummary(
                bundle: evidenceBundle,
                fallback: draft.evidenceReferenceSummary
            ),
            sections: draft.sections,
            skillUsageSummaries: memo.skillUsageSummaries,
            deliveredToPMInboxAt: now,
            createdAt: now,
            updatedAt: now
        )
    }

    private func synthesizeStandingAnalystReportDraftIfPossible(
        schedule: ScheduledJob,
        charter: AnalystCharter,
        runtimePolicy: AnalystRuntimePolicy?,
        strategyBrief: PortfolioStrategyBrief,
        positions: [PositionRow],
        watchlistSymbols: [String],
        recentNews: [NewsEvent],
        externalEvidence: [ExternalAnalystEvidenceDocument],
        externalIssues: [AnalystExternalEvidenceIssue],
        reportingWindowStart: Date,
        now: Date
    ) async throws -> StandingAnalystDraftSynthesisResult {
        let deterministicDraft = makeStandingAnalystReportDraft(
            schedule: schedule,
            charter: charter,
            strategyBrief: strategyBrief,
            positions: positions,
            watchlistSymbols: watchlistSymbols,
            recentNews: recentNews,
            externalEvidence: externalEvidence,
            externalIssues: externalIssues,
            reportingWindowStart: reportingWindowStart,
            now: now
        )
        guard let runtimePolicy else {
            return StandingAnalystDraftSynthesisResult(
                draft: deterministicDraft,
                runtimeProvenance: nil
            )
        }

        let launchedAt = now
        let credentialResolution = openAICredentialResolution(for: runtimePolicy)
        let fallbackRuntime = AnalystRuntimeProvenance(
            intendedPolicy: runtimePolicy,
            actualRuntimeIdentifier: "deterministic_local_fallback[\(runtimePolicy.runtimeIdentifier)]",
            actualReasoningMode: runtimePolicy.reasoningMode,
            launchedAt: launchedAt
        )
        guard let apiKey = credentialResolution.apiKey else {
            return StandingAnalystDraftSynthesisResult(
                draft: deterministicDraft,
                runtimeProvenance: fallbackRuntime
            )
        }

        let request = try await makeStandingAnalystOpenAISynthesisRequest(
            cadenceIntervalSec: schedule.trigger.intervalSec,
            charter: charter,
            strategyBrief: strategyBrief,
            positions: positions,
            watchlistSymbols: watchlistSymbols,
            recentNews: recentNews,
            externalEvidence: externalEvidence,
            externalIssues: externalIssues,
            reportingWindowStart: reportingWindowStart,
            now: now,
            runtimePolicy: runtimePolicy
        )

        do {
            let output = try await standingAnalystOpenAISynthesisProvider.synthesize(
                request: request,
                apiKey: apiKey
            )
            return StandingAnalystDraftSynthesisResult(
                draft: makeStandingAnalystReportDraft(
                    reportingWindowSummary: request.reportingWindowSummary,
                    output: output
                ),
                runtimeProvenance: AnalystRuntimeProvenance(
                    intendedPolicy: runtimePolicy,
                    actualRuntimeIdentifier: "openai_responses[\(runtimePolicy.runtimeIdentifier)]",
                    actualReasoningMode: runtimePolicy.reasoningMode,
                    launchedAt: launchedAt
                )
            )
        } catch {
            return StandingAnalystDraftSynthesisResult(
                draft: deterministicDraft,
                runtimeProvenance: fallbackRuntime
            )
        }
    }

    private struct StandingAnalystReportDraft {
        let executiveSummary: String
        let currentView: String
        let evidenceSummary: String
        let uncertaintySummary: String
        let recommendedNextStep: String
        let confidence: Double
        let reportingWindowSummary: String
        let portfolioScopeSummary: String
        let coveredSymbols: [String]
        let headlineView: String
        let portfolioRelevanceSummary: String
        let openQuestions: [String]
        let evidenceReferenceSummary: [String]
        let sections: [AnalystStandingReportSection]
        let skillUsageSummaries: [AgentSkillUsageSummary]
    }

    private func makeStandingAnalystOpenAISynthesisRequest(
        cadenceIntervalSec: Int,
        charter: AnalystCharter,
        strategyBrief: PortfolioStrategyBrief,
        positions: [PositionRow],
        watchlistSymbols: [String],
        recentNews: [NewsEvent],
        externalEvidence: [ExternalAnalystEvidenceDocument],
        externalIssues: [AnalystExternalEvidenceIssue],
        reportingWindowStart: Date,
        now: Date,
        runtimePolicy: AnalystRuntimePolicy
    ) async throws -> StandingAnalystOpenAISynthesisRequest {
        let reportingWindowSummary = "\(standingAnalystReportCadenceSummary(intervalSec: cadenceIntervalSec)) recurring review covering \(DateCodec.formatISO8601(reportingWindowStart)) through \(DateCodec.formatISO8601(now))."
        let selectedSkills = try await analystSkillContextItems(for: charter, assembledAt: now)
        return StandingAnalystOpenAISynthesisRequest(
            runtimeIdentifier: runtimePolicy.runtimeIdentifier,
            reasoningMode: runtimePolicy.reasoningMode,
            charterTitle: charter.title,
            charterSummary: charter.summary,
            charterDocumentBodyExcerpt: charter.documentBody,
            strategyObjective: emptyToNil(strategyBrief.objectiveSummary),
            strategyThemes: strategyBrief.keyThemes,
            currentRiskPosture: emptyToNil(strategyBrief.currentRiskPosture),
            reviewEscalationPosture: emptyToNil(strategyBrief.reviewEscalationPosture),
            reportingWindowSummary: reportingWindowSummary,
            positionItems: positions.map { position in
                StandingAnalystOpenAISynthesisRequest.PositionItem(
                    symbol: position.symbol,
                    quantity: Decimal(string: position.qty, locale: Locale(identifier: "en_US_POSIX")) ?? 0,
                    marketValue: Decimal(string: position.marketValue, locale: Locale(identifier: "en_US_POSIX")) ?? 0,
                    allocationFraction: nil
                )
            },
            watchlistSymbols: watchlistSymbols,
            newsItems: recentNews.prefix(14).map { item in
                StandingAnalystOpenAISynthesisRequest.NewsItem(
                    source: item.source,
                    title: item.title,
                    summary: item.summary,
                    symbols: item.rawSymbolHints,
                    tags: item.tags,
                    publishedAt: item.publishedAt
                )
            },
            externalEvidenceItems: externalEvidence.prefix(6).map { item in
                StandingAnalystOpenAISynthesisRequest.EvidenceItem(
                    sourceID: item.sourceID,
                    title: item.title,
                    summary: item.summary,
                    snippet: item.snippet,
                    url: item.url,
                    observedAt: item.observedAt,
                    provenanceNote: item.provenanceNote,
                    sourceTier: item.sourceTier
                )
            },
            externalEvidenceIssues: externalIssues.map(\.boundedSummary),
            selectedSkills: selectedSkills,
            publicWebSearchEnabled: charter.sourcePolicy.reputableWebResearchAllowed
                && charter.allowedSources.contains("no_external_evidence_required") == false
        )
    }

    private func makeStandingAnalystReportDraft(
        reportingWindowSummary: String,
        output: StandingAnalystOpenAISynthesisOutput
    ) -> StandingAnalystReportDraft {
        StandingAnalystReportDraft(
            executiveSummary: output.executiveSummary,
            currentView: output.currentView,
            evidenceSummary: output.evidenceSummary,
            uncertaintySummary: output.uncertaintySummary,
            recommendedNextStep: output.recommendedNextStep,
            confidence: output.confidence,
            reportingWindowSummary: reportingWindowSummary,
            portfolioScopeSummary: output.portfolioScopeSummary,
            coveredSymbols: output.coveredSymbols,
            headlineView: output.headlineView,
            portfolioRelevanceSummary: output.portfolioRelevanceSummary,
            openQuestions: output.openQuestions,
            evidenceReferenceSummary: output.evidenceReferenceSummary,
            sections: output.sections.enumerated().map { index, section in
                AnalystStandingReportSection(
                    sectionId: "model-\(section.kind.rawValue)-\(index)",
                    kind: section.kind,
                    title: section.title,
                    summary: section.summary,
                    items: section.items.enumerated().map { itemIndex, item in
                        AnalystStandingReportItem(
                            itemId: "model-\(section.kind.rawValue)-\(itemIndex)",
                            headline: item.headline,
                            detail: item.detail,
                            symbol: item.symbol,
                            stance: item.stance,
                            conviction: item.conviction,
                            priority: item.priority
                        )
                    }
                )
            },
            skillUsageSummaries: output.skillUsageSummaries
        )
    }

