    private func makeFrameworkStandingAnalystReportDraft(
        schedule: ScheduledJob,
        charter: AnalystCharter,
        strategyBrief: PortfolioStrategyBrief?,
        positions: [PositionRow],
        recentNews: [NewsEvent],
        externalEvidence: [ExternalAnalystEvidenceDocument],
        externalIssues: [AnalystExternalEvidenceIssue],
        reportingWindowStart: Date,
        now: Date
    ) -> StandingAnalystReportDraft {
        let cadenceSummary = standingAnalystReportCadenceSummary(intervalSec: schedule.trigger.intervalSec)
        let coveredSymbols = positions.map(\.symbol)
        let reportingWindowSummary = "\(cadenceSummary) recurring review covering \(DateCodec.formatISO8601(reportingWindowStart)) through \(DateCodec.formatISO8601(now))."
        let portfolioScopeSummary: String
        if coveredSymbols.isEmpty {
            portfolioScopeSummary = "No current portfolio positions were attached to this recurring report. The contract remains ready for later candidate-driven sector or overlay coverage."
        } else {
            portfolioScopeSummary = "Covered current portfolio names: \(coveredSymbols.joined(separator: ", "))."
        }
        let portfolioRelevanceSummary = makeFrameworkStandingReportPortfolioRelevanceSummary(
            charter: charter,
            strategyBrief: strategyBrief,
            coveredSymbols: coveredSymbols
        )
        let openQuestions = makeFrameworkStandingReportOpenQuestions(charter: charter, coveredSymbols: coveredSymbols)
        let evidenceReferenceSummary = makeFrameworkStandingReportEvidenceReferenceSummary(
            charter: charter,
            strategyBrief: strategyBrief,
            positions: positions,
            recentNews: recentNews,
            externalEvidence: externalEvidence,
            cadenceSummary: cadenceSummary
        )
        let sections = makeFrameworkStandingAnalystReportSections(
            charter: charter,
            reportingWindowSummary: reportingWindowSummary,
            portfolioScopeSummary: portfolioScopeSummary,
            portfolioRelevanceSummary: portfolioRelevanceSummary,
            openQuestions: openQuestions,
            evidenceReferenceSummary: evidenceReferenceSummary,
            positions: positions
        )
        let issueSuffix = standingExternalEvidenceIssueSummary(externalIssues).map { " External evidence degraded: \($0)." } ?? ""
        let strategyBriefSummary = strategyBrief?.title.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty == false
            ? "Grounded on the current Portfolio Strategy Brief."
            : "No Portfolio Strategy Brief was available at generation time."
        let placeholderSummary = "This recurring report now lands as a structured PM-review artifact. Richer analyst-specific intelligence can populate the same contract without creating a second report model."

        return StandingAnalystReportDraft(
            executiveSummary: "\(cadenceSummary) standing report delivered for \(charter.title).",
            currentView: placeholderSummary,
            evidenceSummary: "\(strategyBriefSummary) The durable analyst charter remains the standing operating document for this analyst, and this recurring artifact now preserves explicit review sections for PM triage.",
            uncertaintySummary: "This report remains a bounded framework placeholder. It confirms recurring report structure, persistence, and PM Inbox review presentation rather than full analyst research depth.\(issueSuffix)",
            recommendedNextStep: "PM can review the structured standing report in PM Inbox, decide whether the cadence still fits, and use the contract sections to guide later richer analyst reporting.",
            confidence: 0.25,
            reportingWindowSummary: reportingWindowSummary,
            portfolioScopeSummary: portfolioScopeSummary,
            coveredSymbols: coveredSymbols,
            headlineView: placeholderSummary,
            portfolioRelevanceSummary: portfolioRelevanceSummary,
            openQuestions: openQuestions,
            evidenceReferenceSummary: evidenceReferenceSummary,
            sections: sections,
            skillUsageSummaries: []
        )
    }

    private func makeMacroStandingAnalystReportDraft(
        schedule: ScheduledJob,
        charter: AnalystCharter,
        strategyBrief: PortfolioStrategyBrief?,
        positions: [PositionRow],
        watchlistSymbols: [String],
        recentNews: [NewsEvent],
        externalEvidence: [ExternalAnalystEvidenceDocument],
        externalIssues: [AnalystExternalEvidenceIssue],
        reportingWindowStart: Date,
        now: Date,
        profile: MacroStandingResearchProfile
    ) -> StandingAnalystReportDraft {
        let cadenceSummary = standingAnalystReportCadenceSummary(intervalSec: schedule.trigger.intervalSec)
        let normalizedWatchlist = Set(watchlistSymbols.map { $0.uppercased() })
        let heldSymbols = Set(positions.map { $0.symbol.uppercased() })
        let currentSectors = standingMacroPortfolioSectorNames(positions: positions)
        let relevantNews = recentNews.filter { isStandingMacroNewsRelevant($0, profile: profile) }
        let materialNews = Array(relevantNews.prefix(3))
        let nonMaterialNews = Array(relevantNews.dropFirst(3).prefix(2))
        let longIdeas = makeStandingMacroIdeas(
            seeds: profile.longExpressions,
            stance: .long,
            strategyBrief: strategyBrief,
            currentSectors: currentSectors,
            heldSymbols: heldSymbols,
            watchlistSymbols: normalizedWatchlist,
            relevantNews: relevantNews,
            externalEvidence: externalEvidence
        )
        let shortIdeas = makeStandingMacroIdeas(
            seeds: profile.shortExpressions,
            stance: .short,
            strategyBrief: strategyBrief,
            currentSectors: currentSectors,
            heldSymbols: heldSymbols,
            watchlistSymbols: normalizedWatchlist,
            relevantNews: relevantNews,
            externalEvidence: externalEvidence
        )
        let etfIdeas = makeStandingMacroIdeas(
            seeds: profile.etfExpressions,
            stance: .etf,
            strategyBrief: strategyBrief,
            currentSectors: currentSectors,
            heldSymbols: heldSymbols,
            watchlistSymbols: normalizedWatchlist,
            relevantNews: relevantNews,
            externalEvidence: externalEvidence
        )
        let strategyObjective = standingStrategyBriefObjective(strategyBrief)
        let strategyThemes = standingStrategyBriefThemes(strategyBrief)
        let reportingWindowSummary = "\(cadenceSummary) macro and international review covering \(DateCodec.formatISO8601(reportingWindowStart)) through \(DateCodec.formatISO8601(now)) with \(relevantNews.count) relevant news item(s) and \(externalEvidence.count) charter-governed web source(s)."
        let portfolioScopeSummary = makeMacroStandingPortfolioScopeSummary(
            positions: positions,
            currentSectors: currentSectors,
            watchlistSymbols: normalizedWatchlist,
            profile: profile
        )
        let headlineView = makeMacroStandingHeadlineView(
            currentSectors: currentSectors,
            materialNews: materialNews,
            longIdeas: longIdeas,
            shortIdeas: shortIdeas,
            etfIdeas: etfIdeas
        )
        let portfolioRelevanceSummary = makeMacroStandingPortfolioRelevanceSummary(
            strategyObjective: strategyObjective,
            strategyThemes: strategyThemes,
            currentSectors: currentSectors,
            positions: positions
        )
        let openQuestions = makeMacroStandingOpenQuestions(
            currentSectors: currentSectors,
            positions: positions,
            longIdeas: longIdeas,
            shortIdeas: shortIdeas,
            etfIdeas: etfIdeas
        )
        let evidenceReferenceSummary = makeMacroStandingEvidenceReferences(
            charter: charter,
            strategyBrief: strategyBrief,
            positions: positions,
            currentSectors: currentSectors,
            materialNews: materialNews,
            externalEvidence: externalEvidence
        )
        let sections = makeMacroStandingAnalystReportSections(
            profile: profile,
            reportingWindowSummary: reportingWindowSummary,
            portfolioScopeSummary: portfolioScopeSummary,
            portfolioRelevanceSummary: portfolioRelevanceSummary,
            openQuestions: openQuestions,
            evidenceReferenceSummary: evidenceReferenceSummary,
            positions: positions,
            currentSectors: currentSectors,
            materialNews: materialNews,
            nonMaterialNews: nonMaterialNews,
            longIdeas: longIdeas,
            shortIdeas: shortIdeas,
            etfIdeas: etfIdeas
        )
        let topLong = longIdeas.first?.seed.symbol ?? "TLT"
        let topShort = shortIdeas.first?.seed.symbol ?? "EEM"
        let topETF = etfIdeas.first?.seed.symbol ?? "TLT"
        let issueSuffix = standingExternalEvidenceIssueSummary(externalIssues).map { " External evidence degraded: \($0)." } ?? ""
        let externalAnchorLine = standingExternalEvidenceLead(externalEvidence.first)
        let charterGuidance = charter.expectedOutputs.first ?? charter.summary
        let materialLead = materialNews.isEmpty
            ? "No reporting-window macro headline cleared the bounded relevance filter, so the overlay stayed anchored on portfolio posture and expression selection."
            : "Material macro developments led by \(materialNews.prefix(2).map(\.title).joined(separator: " | "))."

        return StandingAnalystReportDraft(
            executiveSummary: "\(cadenceSummary) macro and international standing review tied current portfolio posture to expressions \(topLong), \(topShort), and \(topETF). \(materialLead)",
            currentView: headlineView,
            evidenceSummary: "Grounded on the analyst charter, Portfolio Strategy Brief, current portfolio construction, reporting-window macro and international news, and bounded charter-governed reputable-web evidence. Strategy objective: \(strategyObjective).\(strategyThemes.isEmpty ? "" : " Key themes: \(strategyThemes.joined(separator: "; ")).")\(externalAnchorLine)",
            uncertaintySummary: "This macro overlay uses a bounded theme map for rates, FX, commodities, and international breadth rather than a broad macro platform. Charter guidance remains: \(charterGuidance).\(issueSuffix)",
            recommendedNextStep: "PM should review whether \(topETF) is the cleanest overlay expression for the current macro setup, whether \(topLong) belongs in the long-expression queue, and whether \(topShort) is a live hedge or only a monitoring pressure test before the next standing cycle.",
            confidence: Double(max(longIdeas.first?.conviction ?? 6, max(shortIdeas.first?.conviction ?? 5, etfIdeas.first?.conviction ?? 6))) / 10.0,
            reportingWindowSummary: reportingWindowSummary,
            portfolioScopeSummary: portfolioScopeSummary,
            coveredSymbols: positions.map(\.symbol),
            headlineView: headlineView,
            portfolioRelevanceSummary: portfolioRelevanceSummary,
            openQuestions: openQuestions,
            evidenceReferenceSummary: evidenceReferenceSummary,
            sections: sections,
            skillUsageSummaries: []
        )
    }

    private func makeMacroStandingPortfolioScopeSummary(
        positions: [PositionRow],
        currentSectors: [String],
        watchlistSymbols: Set<String>,
        profile: MacroStandingResearchProfile
    ) -> String {
        let watchlistBenchmarks = Array(watchlistSymbols.intersection(profile.coverageSymbols)).sorted()
        let heldSymbols = positions.map(\.symbol)
        if heldSymbols.isEmpty {
            if watchlistBenchmarks.isEmpty {
                return "No current portfolio positions were attached. This overlay cycle leans on the opportunity set and bounded macro benchmarks instead of live exposure review."
            }
            return "No current portfolio positions were attached. Opportunity-set watchlist expressions already in scope: \(watchlistBenchmarks.joined(separator: ", "))."
        }
        let sectorLead = currentSectors.isEmpty
            ? "Current holdings are outside the bounded sector map, so macro review leans on symbol-level posture."
            : "Current holdings span sectors: \(currentSectors.joined(separator: ", "))."
        if watchlistBenchmarks.isEmpty {
            return "Current portfolio names in scope: \(heldSymbols.joined(separator: ", ")). \(sectorLead)"
        }
        return "Current portfolio names in scope: \(heldSymbols.joined(separator: ", ")). \(sectorLead) Watchlist macro expressions already in scope: \(watchlistBenchmarks.joined(separator: ", "))."
    }

    private func makeMacroStandingHeadlineView(
        currentSectors: [String],
        materialNews: [NewsEvent],
        longIdeas: [MacroStandingIdea],
        shortIdeas: [MacroStandingIdea],
        etfIdeas: [MacroStandingIdea]
    ) -> String {
        let sectorLead = currentSectors.isEmpty
            ? "The current portfolio is being treated as a broad opportunity set rather than a single-sector posture."
            : "Current exposure in \(currentSectors.joined(separator: ", ")) makes macro transmission more important than a broad market narrative."
        let materialLead = materialNews.isEmpty
            ? "No fresh macro headline dominated the window, so the overlay stayed focused on transmission mechanisms and expression choice."
            : "Reporting-window macro developments were led by \(materialNews.prefix(2).map(\.title).joined(separator: " | "))."
        let expressions = [
            longIdeas.first?.seed.symbol,
            shortIdeas.first?.seed.symbol,
            etfIdeas.first?.seed.symbol
        ]
        .compactMap { $0 }
        .joined(separator: ", ")
        return "\(sectorLead) \(materialLead) The current bounded overlay expressions are \(expressions)."
    }

    private func makeMacroStandingPortfolioRelevanceSummary(
        strategyObjective: String,
        strategyThemes: [String],
        currentSectors: [String],
        positions: [PositionRow]
    ) -> String {
        let themeLead = strategyThemes.isEmpty
            ? "No explicit key themes were parsed from the current brief."
            : "Key themes in scope: \(strategyThemes.prefix(3).joined(separator: ", "))."
        if positions.isEmpty {
            return "Grounded on the current strategy objective (\(strategyObjective)). \(themeLead) With no current portfolio positions attached, this overlay stays focused on opportunity-set expressions rather than forcing a portfolio posture."
        }
        let sectorLead = currentSectors.isEmpty
            ? "Holdings did not map cleanly into the bounded sector taxonomy."
            : "Holdings map into \(currentSectors.joined(separator: ", ")), so macro transmission is tied back to those sector exposures."
        return "Grounded on the current strategy objective (\(strategyObjective)). \(themeLead) \(sectorLead) The report separates what changes current portfolio posture from background macro commentary."
    }

    private func makeMacroStandingOpenQuestions(
        currentSectors: [String],
        positions: [PositionRow],
        longIdeas: [MacroStandingIdea],
        shortIdeas: [MacroStandingIdea],
        etfIdeas: [MacroStandingIdea]
    ) -> [String] {
        let topLong = longIdeas.first?.seed.symbol ?? "the top long expression"
        let topShort = shortIdeas.first?.seed.symbol ?? "the top short expression"
        let topETF = etfIdeas.first?.seed.symbol ?? "the top ETF expression"
        if positions.isEmpty {
            return [
                "Does \(topETF) belong on the active opportunity-set watchlist as the cleanest macro expression before single-name work?",
                "What evidence would move \(topLong) from macro expression to stronger PM priority?",
                "What would invalidate the short-side overlay on \(topShort)?"
            ]
        }
        let sectorLead = currentSectors.isEmpty ? "current holdings" : currentSectors.joined(separator: ", ")
        return [
            "Which current exposure in \(sectorLead) is most sensitive to the macro setup driving \(topLong) and \(topShort)?",
            "Is \(topETF) the cleaner expression than adding or trimming a single-name position?",
            "What portfolio condition would convert \(topShort) from hedge candidate to active PM follow-up?"
        ]
    }

    private func makeMacroStandingEvidenceReferences(
        charter: AnalystCharter,
        strategyBrief: PortfolioStrategyBrief?,
        positions: [PositionRow],
        currentSectors: [String],
        materialNews: [NewsEvent],
        externalEvidence: [ExternalAnalystEvidenceDocument]
    ) -> [String] {
        var references: [String] = ["Standing analyst charter: \(charter.title)"]
        if let strategyBrief,
           strategyBrief.title.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty == false {
            references.append("Portfolio Strategy Brief: \(strategyBrief.title)")
        } else {
            references.append("Portfolio Strategy Brief unavailable at generation time")
        }
        if positions.isEmpty {
            references.append("Current holdings snapshot: no positions attached")
        } else {
            references.append("Current holdings snapshot: \(positions.map(\.symbol).joined(separator: ", "))")
        }
        if currentSectors.isEmpty == false {
            references.append("Bounded sector exposure map: \(currentSectors.joined(separator: ", "))")
        }
        references.append(contentsOf: materialNews.prefix(3).map { "Recent news: \($0.title)" })
        references.append(contentsOf: externalEvidence.prefix(2).map(standingExternalEvidenceReference))
        return references
    }

    private func makeMacroStandingAnalystReportSections(
        profile: MacroStandingResearchProfile,
        reportingWindowSummary: String,
        portfolioScopeSummary: String,
        portfolioRelevanceSummary: String,
        openQuestions: [String],
        evidenceReferenceSummary: [String],
        positions: [PositionRow],
        currentSectors: [String],
        materialNews: [NewsEvent],
        nonMaterialNews: [NewsEvent],
        longIdeas: [MacroStandingIdea],
        shortIdeas: [MacroStandingIdea],
        etfIdeas: [MacroStandingIdea]
    ) -> [AnalystStandingReportSection] {
        [
            AnalystStandingReportSection(
                sectionId: "reporting-window",
                kind: .reportingWindow,
                summary: reportingWindowSummary,
                items: [
                    AnalystStandingReportItem(
                        itemId: "reporting-window-item",
                        headline: "Macro and international standing cycle",
                        detail: "This recurring overlay is grounded on current portfolio posture, reporting-window macro developments, and the standing analyst charter rather than a generic market recap.",
                        stance: .neutral,
                        priority: 7
                    )
                ]
            ),
            AnalystStandingReportSection(
                sectionId: "portfolio-scope",
                kind: .portfolioScope,
                summary: portfolioScopeSummary,
                items: makeMacroStandingPortfolioScopeItems(
                    positions: positions,
                    currentSectors: currentSectors
                )
            ),
            AnalystStandingReportSection(
                sectionId: "material-developments",
                kind: .materialDevelopments,
                summary: materialNews.isEmpty
                    ? "No fresh reporting-window macro item displaced the current portfolio posture work."
                    : "Material macro and international developments are separated from broad background noise.",
                items: makeMacroStandingMaterialItems(materialNews: materialNews)
            ),
            AnalystStandingReportSection(
                sectionId: "important-items",
                kind: .importantItems,
                summary: "What matters now is tied to transmission into the current portfolio and opportunity set, not generic commentary.",
                items: makeMacroStandingImportantItems(
                    profile: profile,
                    currentSectors: currentSectors,
                    longIdeas: longIdeas,
                    shortIdeas: shortIdeas,
                    etfIdeas: etfIdeas
                )
            ),
            AnalystStandingReportSection(
                sectionId: "non-material-items",
                kind: .nonMaterialItems,
                summary: "Lower-signal macro commentary stays separate from the active overlay view.",
                items: makeMacroStandingNonMaterialItems(nonMaterialNews: nonMaterialNews)
            ),
            AnalystStandingReportSection(
                sectionId: "macro-views",
                kind: .macroViews,
                summary: "The overlay separates transmission mechanisms that matter to this portfolio from background macro narration.",
                items: makeMacroStandingViewItems(
                    profile: profile,
                    currentSectors: currentSectors,
                    materialNews: materialNews
                )
            ),
            AnalystStandingReportSection(
                sectionId: "long-ideas",
                kind: .longIdeas,
                summary: "Best current long-side macro or international expressions with bounded conviction.",
                items: longIdeas.map { idea in
                    AnalystStandingReportItem(
                        itemId: "long-\(idea.seed.symbol.lowercased())",
                        headline: idea.seed.headline,
                        detail: idea.detail,
                        symbol: idea.seed.symbol,
                        stance: .long,
                        conviction: idea.conviction
                    )
                }
            ),
            AnalystStandingReportSection(
                sectionId: "short-ideas",
                kind: .shortIdeas,
                summary: "Best current short-side or hedge expressions with bounded conviction.",
                items: shortIdeas.map { idea in
                    AnalystStandingReportItem(
                        itemId: "short-\(idea.seed.symbol.lowercased())",
                        headline: idea.seed.headline,
                        detail: idea.detail,
                        symbol: idea.seed.symbol,
                        stance: .short,
                        conviction: idea.conviction
                    )
                }
            ),
            AnalystStandingReportSection(
                sectionId: "etf-ideas",
                kind: .etfIdeas,
                summary: "ETF or cross-asset expressions appear only when they isolate the macro view better than a single-name follow-up.",
                items: etfIdeas.map { idea in
                    AnalystStandingReportItem(
                        itemId: "etf-\(idea.seed.symbol.lowercased())",
                        headline: idea.seed.headline,
                        detail: idea.detail,
                        symbol: idea.seed.symbol,
                        stance: .etf,
                        conviction: idea.conviction
                    )
                }
            ),
            AnalystStandingReportSection(
                sectionId: "portfolio-relevance",
                kind: .portfolioRelevance,
                summary: portfolioRelevanceSummary,
                items: [
                    AnalystStandingReportItem(
                        itemId: "portfolio-relevance-item",
                        headline: "The overlay stays tied to current portfolio construction",
                        detail: "Macro and international analysis only matters here when it changes the posture, hedge needs, or opportunity set for current holdings and active watch coverage.",
                        stance: .macro,
                        priority: 7
                    )
                ]
            ),
            AnalystStandingReportSection(
                sectionId: "follow-up",
                kind: .followUp,
                summary: "Open PM follow-up questions remain explicit and separate from later ad hoc analyst tasking.",
                items: openQuestions.enumerated().map { index, question in
                    AnalystStandingReportItem(
                        itemId: "follow-up-\(index)",
                        headline: "Open question \(index + 1)",
                        detail: question,
                        stance: .neutral,
                        priority: 5
                    )
                }
            ),
            AnalystStandingReportSection(
                sectionId: "evidence",
                kind: .evidence,
                summary: "Grounding references remain explicit so PM review can trace strategy, portfolio, news, and charter-governed web sources.",
                items: evidenceReferenceSummary.enumerated().map { index, reference in
                    AnalystStandingReportItem(
                        itemId: "evidence-\(index)",
                        headline: "Grounding reference \(index + 1)",
                        detail: reference,
                        stance: .neutral,
                        priority: 4
                    )
                }
            )
        ]
    }

    private func makeMacroStandingPortfolioScopeItems(
        positions: [PositionRow],
        currentSectors: [String]
    ) -> [AnalystStandingReportItem] {
        if positions.isEmpty {
            return [
                AnalystStandingReportItem(
                    itemId: "portfolio-scope-empty",
                    headline: "No current positions were attached",
                    detail: "The macro overlay stayed focused on opportunity-set expressions rather than claiming a live portfolio posture.",
                    stance: .neutral,
                    priority: 4
                )
            ]
        }
        let sectorDetail = currentSectors.isEmpty
            ? "Current positions did not map into the bounded sector taxonomy."
            : "Mapped sector exposure: \(currentSectors.joined(separator: ", "))."
        return positions.prefix(5).map { position in
            AnalystStandingReportItem(
                itemId: "portfolio-scope-\(position.symbol.lowercased())",
                headline: "\(position.symbol) (\(position.directionLabel))",
                detail: "Current holding in macro scope. Quantity \(position.qty) • Market value \(position.marketValue). \(sectorDetail)",
                symbol: position.symbol,
                stance: .neutral,
                priority: 6
            )
        }
    }

    private func makeMacroStandingMaterialItems(
        materialNews: [NewsEvent]
    ) -> [AnalystStandingReportItem] {
        if materialNews.isEmpty {
            return [
                AnalystStandingReportItem(
                    itemId: "material-none",
                    headline: "No fresh macro headline displaced the current posture work",
                    detail: "The standing overlay still records the reporting window explicitly, but no recent macro item was strong enough to replace portfolio transmission and expression selection as the main output.",
                    stance: .neutral,
                    priority: 4
                )
            ]
        }
        return materialNews.enumerated().map { index, event in
            let detailParts = [
                event.summary?.trimmingCharacters(in: .whitespacesAndNewlines),
                "Published \(DateCodec.formatISO8601(event.publishedAt))"
            ].compactMap { $0 }
            return AnalystStandingReportItem(
                itemId: "material-\(event.eventId)",
                headline: event.title,
                detail: detailParts.joined(separator: " • "),
                stance: .macro,
                priority: max(6, 9 - index)
            )
        }
    }

    private func makeMacroStandingImportantItems(
        profile: MacroStandingResearchProfile,
        currentSectors: [String],
        longIdeas: [MacroStandingIdea],
        shortIdeas: [MacroStandingIdea],
        etfIdeas: [MacroStandingIdea]
    ) -> [AnalystStandingReportItem] {
        var items: [AnalystStandingReportItem] = []
        if let topLong = longIdeas.first {
            items.append(
                AnalystStandingReportItem(
                    itemId: "important-long-\(topLong.seed.symbol.lowercased())",
                    headline: "Most actionable long-side macro expression: \(topLong.seed.symbol)",
                    detail: topLong.detail,
                    symbol: topLong.seed.symbol,
                    stance: .long,
                    conviction: topLong.conviction
                )
            )
        }
        if let topShort = shortIdeas.first {
            items.append(
                AnalystStandingReportItem(
                    itemId: "important-short-\(topShort.seed.symbol.lowercased())",
                    headline: "Most actionable hedge or short-side expression: \(topShort.seed.symbol)",
                    detail: topShort.detail,
                    symbol: topShort.seed.symbol,
                    stance: .short,
                    conviction: topShort.conviction
                )
            )
        }
        if let topETF = etfIdeas.first {
            items.append(
                AnalystStandingReportItem(
                    itemId: "important-etf-\(topETF.seed.symbol.lowercased())",
                    headline: "ETF expression with the clearest transmission: \(topETF.seed.symbol)",
                    detail: topETF.detail,
                    symbol: topETF.seed.symbol,
                    stance: .etf,
                    conviction: topETF.conviction
                )
            )
        }
        if items.isEmpty {
            items.append(
                AnalystStandingReportItem(
                    itemId: "important-fallback",
                    headline: "Macro overlay remains focused on transmission rather than recap",
                    detail: "The bounded overlay did not find a higher-signal expression, so the report remains anchored on how macro conditions would affect \(currentSectors.joined(separator: ", ")).",
                    stance: .macro,
                    priority: 5
                )
            )
        }
        return items
    }

    private func makeMacroStandingNonMaterialItems(
        nonMaterialNews: [NewsEvent]
    ) -> [AnalystStandingReportItem] {
        if nonMaterialNews.isEmpty {
            return [
                AnalystStandingReportItem(
                    itemId: "non-material-none",
                    headline: "No additional low-signal macro items need PM attention",
                    detail: "Lower-signal market commentary did not outrank the current transmission and expression work for this cycle.",
                    stance: .neutral,
                    priority: 3
                )
            ]
        }
        return nonMaterialNews.enumerated().map { index, event in
            AnalystStandingReportItem(
                itemId: "non-material-\(event.eventId)",
                headline: event.title,
                detail: event.summary?.trimmingCharacters(in: .whitespacesAndNewlines) ?? "Lower-signal macro commentary parked here so it does not crowd out what matters now.",
                stance: .neutral,
                priority: max(2, 4 - index)
            )
        }
    }

    private func makeMacroStandingViewItems(
        profile: MacroStandingResearchProfile,
        currentSectors: [String],
        materialNews: [NewsEvent]
    ) -> [AnalystStandingReportItem] {
        profile.viewThemes.map { theme in
            let matchedNews = materialNews.filter { event in
                let body = "\(event.title) \(event.summary ?? "")".lowercased()
                return theme.keywords.contains(where: { body.contains($0.lowercased()) })
            }
            let matchedSectors = currentSectors.filter { sector in
                theme.portfolioHooks.contains(where: { hook in
                    sector.localizedCaseInsensitiveContains(hook)
                })
            }
            let sectorHook = currentSectors.isEmpty
                ? "No current sector map was available, so the theme is framed against the opportunity set."
                : "Most relevant current sectors: \(matchedSectors.isEmpty ? currentSectors.joined(separator: ", ") : matchedSectors.joined(separator: ", "))."
            let newsLead = matchedNews.isEmpty
                ? "No reporting-window headline directly dominated this theme."
                : "Relevant developments: \(matchedNews.prefix(2).map(\.title).joined(separator: " | "))."
            return AnalystStandingReportItem(
                itemId: "macro-view-\(theme.themeID)",
                headline: theme.headline,
                detail: "\(theme.whyItMatters) \(newsLead) \(sectorHook) Noise boundary: \(theme.noiseBoundary)",
                stance: .macro,
                priority: matchedNews.isEmpty ? 5 : 7
            )
        }
    }

    private func makeStandingMacroIdeas(
        seeds: [MacroStandingExpressionSeed],
        stance: AnalystStandingReportItemStance,
        strategyBrief: PortfolioStrategyBrief?,
        currentSectors: [String],
        heldSymbols: Set<String>,
        watchlistSymbols: Set<String>,
        relevantNews: [NewsEvent],
        externalEvidence: [ExternalAnalystEvidenceDocument]
    ) -> [MacroStandingIdea] {
        let strategyThemes = standingStrategyBriefThemes(strategyBrief)
        let strategyObjective = standingStrategyBriefObjective(strategyBrief)
        let externalAnchor = externalEvidence.first?.title

        return seeds.enumerated().map { index, seed in
            let normalizedSymbol = seed.symbol.uppercased()
            let matchedNews = relevantNews.filter { event in
                let hintSymbols = Set(event.rawSymbolHints.map { $0.uppercased() })
                if hintSymbols.contains(normalizedSymbol) {
                    return true
                }
                let body = "\(event.title) \(event.summary ?? "")".lowercased()
                return seed.keywords.contains(where: { body.contains($0.lowercased()) })
            }
            let sectorMatches = currentSectors.filter { sector in
                seed.portfolioHooks.contains(where: { hook in
                    sector.localizedCaseInsensitiveContains(hook)
                })
            }
            let isHeld = heldSymbols.contains(normalizedSymbol)
            let isWatchlist = watchlistSymbols.contains(normalizedSymbol)
            var conviction = stance == .short ? 5 : 6
            conviction += min(2, matchedNews.count)
            conviction += min(1, sectorMatches.count)
            if isHeld {
                conviction += 1
            }
            if isWatchlist {
                conviction += 1
            }
            if strategyThemes.isEmpty == false,
               seed.keywords.contains(where: { keyword in
                   strategyThemes.contains(where: { $0.localizedCaseInsensitiveContains(keyword) })
               }) {
                conviction += 1
            }
            conviction = min(10, max(4, conviction))

            let newsLead = matchedNews.isEmpty
                ? "No reporting-window headline directly referenced \(seed.symbol), so this remains a bounded expression built from portfolio posture, charter guidance, and macro transmission."
                : "Recent developments: \(matchedNews.prefix(2).map(\.title).joined(separator: " | "))."
            let portfolioLead: String
            if sectorMatches.isEmpty {
                portfolioLead = "This expression is framed against the current opportunity set rather than one specific sector holding."
            } else {
                portfolioLead = "Most relevant current sectors: \(sectorMatches.joined(separator: ", "))."
            }
            let watchlistLead: String
            if isHeld {
                watchlistLead = "\(seed.symbol) is already held, so the overlay treats it as a live position review."
            } else if isWatchlist {
                watchlistLead = "\(seed.symbol) is already on the watchlist, so it can be escalated without rebuilding coverage."
            } else {
                watchlistLead = "\(seed.symbol) is not currently held, so it remains an overlay expression rather than an implied action."
            }
            let strategyLead = strategyThemes.isEmpty
                ? "Current objective anchor: \(strategyObjective)."
                : "Best fit with current strategy themes: \(strategyThemes.prefix(2).joined(separator: ", "))."
            let etfLead = seed.etfAdvantage.map { "ETF rationale: \($0)." } ?? ""
            let externalLead = standingExternalEvidenceReviewedLead(externalAnchor)
            let detail = "\(seed.rationale) \(newsLead) \(portfolioLead) \(watchlistLead) \(strategyLead) \(etfLead) \(externalLead)".trimmingCharacters(in: .whitespacesAndNewlines)

            return MacroStandingIdea(
                seed: seed,
                conviction: conviction,
                detail: detail,
                newsMatches: matchedNews,
                sectorMatches: sectorMatches,
                isWatchlist: isWatchlist,
                isHeld: isHeld
            )
        }
        .enumerated()
        .sorted { lhs, rhs in
            if lhs.element.conviction == rhs.element.conviction {
                return lhs.offset < rhs.offset
            }
            return lhs.element.conviction > rhs.element.conviction
        }
        .prefix(3)
        .map(\.element)
    }

    private func isStandingMacroNewsRelevant(
        _ event: NewsEvent,
        profile: MacroStandingResearchProfile
    ) -> Bool {
        let hintSymbols = Set(event.rawSymbolHints.map { $0.uppercased() })
        if hintSymbols.intersection(profile.coverageSymbols).isEmpty == false {
            return true
        }
        let body = "\(event.title) \(event.summary ?? "")".lowercased()
        return profile.keywords.contains(where: { body.contains($0.lowercased()) })
    }

    private func standingAnalystReportSuppressionSummary(
        charter: AnalystCharter,
        positions: [PositionRow]
    ) -> String? {
        guard standingReportContractProfile(for: charter) == .portfolioRisk,
              positions.isEmpty else {
            return nil
        }
        return "standing_analyst_report: skipped \(charter.title) because no current portfolio positions were available."
    }

    private func makePortfolioRiskStandingAnalystReportDraft(
        schedule: ScheduledJob,
        charter: AnalystCharter,
        strategyBrief: PortfolioStrategyBrief?,
        positions: [PositionRow],
        watchlistSymbols: [String],
        recentNews: [NewsEvent],
        externalEvidence: [ExternalAnalystEvidenceDocument],
        externalIssues: [AnalystExternalEvidenceIssue],
        reportingWindowStart: Date,
        now: Date
    ) -> StandingAnalystReportDraft {
        let cadenceSummary = standingAnalystReportCadenceSummary(intervalSec: schedule.trigger.intervalSec)
        let exposures = makeStandingRiskExposures(positions: positions)
        let heldSymbols = Set(exposures.map(\.symbol))
        let sectorWeights = Dictionary(grouping: exposures, by: { $0.sectorName ?? "Other" })
            .mapValues { group in group.reduce(0.0) { $0 + $1.weight } }
        let relevantNews = recentNews.filter { isStandingPortfolioRiskNewsRelevant($0, heldSymbols: heldSymbols) }
        let materialNews = Array(relevantNews.prefix(3))
        let nonMaterialNews = Array(relevantNews.dropFirst(3).prefix(2))
        let triggerEvaluation = PortfolioRiskTriggerEvaluator.evaluate(
            snapshot: makeStandingRiskSnapshot(
                positions: positions,
                watchlistSymbols: watchlistSymbols
            ),
            strategyBrief: strategyBrief,
            previousObservedPricesBySymbol: [:],
            previousObservedWeightsBySymbol: [:],
            recentNews: recentNews,
            now: now
        )
        let concentrationIssues = makeStandingRiskConcentrationIssues(exposures: exposures)
        let clusteringIssues = makeStandingRiskClusteringIssues(
            sectorWeights: sectorWeights,
            strategyBrief: strategyBrief
        )
        let vulnerabilityIssues = makeStandingRiskVulnerabilityIssues(
            exposures: exposures,
            materialNews: materialNews,
            triggerEvaluation: triggerEvaluation
        )
        let downsideIssues = makeStandingRiskDownsideIssues(
            exposures: exposures,
            sectorWeights: sectorWeights,
            strategyBrief: strategyBrief
        )
        let allRiskIssues = Array(
            (concentrationIssues + clusteringIssues + vulnerabilityIssues + downsideIssues)
                .sorted { lhs, rhs in
                    if lhs.priority == rhs.priority {
                        return lhs.issueID < rhs.issueID
                    }
                    return lhs.priority > rhs.priority
                }
                .prefix(8)
        )
        let strategyObjective = standingStrategyBriefObjective(strategyBrief)
        let strategyThemes = standingStrategyBriefThemes(strategyBrief)
        let reportingWindowSummary = "\(cadenceSummary) portfolio-risk review covering \(DateCodec.formatISO8601(reportingWindowStart)) through \(DateCodec.formatISO8601(now)) with \(materialNews.count) materially relevant news item(s) and \(externalEvidence.count) charter-governed web source(s)."
        let portfolioScopeSummary = makeStandingRiskPortfolioScopeSummary(
            exposures: exposures,
            sectorWeights: sectorWeights
        )
        let headlineView = makeStandingRiskHeadlineView(
            exposures: exposures,
            allRiskIssues: allRiskIssues,
            materialNews: materialNews
        )
        let portfolioRelevanceSummary = makeStandingRiskPortfolioRelevanceSummary(
            strategyObjective: strategyObjective,
            strategyThemes: strategyThemes,
            exposures: exposures,
            sectorWeights: sectorWeights
        )
        let openQuestions = makeStandingRiskOpenQuestions(
            allRiskIssues: allRiskIssues,
            exposures: exposures,
            sectorWeights: sectorWeights
        )
        let evidenceReferenceSummary = makeStandingRiskEvidenceReferences(
            charter: charter,
            strategyBrief: strategyBrief,
            exposures: exposures,
            materialNews: materialNews,
            externalEvidence: externalEvidence
        )
        let sections = makePortfolioRiskStandingAnalystReportSections(
            reportingWindowSummary: reportingWindowSummary,
            portfolioScopeSummary: portfolioScopeSummary,
            portfolioRelevanceSummary: portfolioRelevanceSummary,
            openQuestions: openQuestions,
            evidenceReferenceSummary: evidenceReferenceSummary,
            exposures: exposures,
            materialNews: materialNews,
            nonMaterialNews: nonMaterialNews,
            allRiskIssues: allRiskIssues
        )
        let issueSuffix = standingExternalEvidenceIssueSummary(externalIssues).map { " External evidence degraded: \($0)." } ?? ""
        let externalAnchorLine = standingExternalEvidenceLead(externalEvidence.first)
        let charterGuidance = charter.expectedOutputs.first ?? charter.summary
        let topIssues = allRiskIssues.prefix(2).map(\.headline).joined(separator: " | ")
        let materialLead = materialNews.isEmpty
            ? "No reporting-window headline materially changed the risk posture beyond current portfolio construction."
            : "Material risk developments led by \(materialNews.prefix(2).map(\.title).joined(separator: " | "))."

        return StandingAnalystReportDraft(
            executiveSummary: "\(cadenceSummary) portfolio-risk standing review surfaced \(topIssues). \(materialLead)",
            currentView: headlineView,
            evidenceSummary: "Grounded on the analyst charter, Portfolio Strategy Brief, current portfolio construction, materially relevant reporting-window news, and bounded charter-governed reputable-web evidence. Strategy objective: \(strategyObjective).\(strategyThemes.isEmpty ? "" : " Key themes: \(strategyThemes.joined(separator: "; ")).")\(externalAnchorLine)",
            uncertaintySummary: "This risk overlay remains bounded to current concentration, sector clustering, vulnerability, and downside-scenario analysis rather than a full risk engine. Charter guidance remains: \(charterGuidance).\(issueSuffix)",
            recommendedNextStep: "PM should review whether the top concentration or clustering issue changes current sizing, hedge posture, or monitoring priority before the next standing cycle.",
            confidence: Double(max(6, allRiskIssues.first?.priority ?? 6)) / 10.0,
            reportingWindowSummary: reportingWindowSummary,
            portfolioScopeSummary: portfolioScopeSummary,
            coveredSymbols: exposures.map(\.symbol),
            headlineView: headlineView,
            portfolioRelevanceSummary: portfolioRelevanceSummary,
            openQuestions: openQuestions,
            evidenceReferenceSummary: evidenceReferenceSummary,
            sections: sections,
            skillUsageSummaries: []
        )
    }

    private func makeStandingRiskExposures(
        positions: [PositionRow]
    ) -> [RiskStandingExposure] {
        let totalAbsoluteExposure = positions.reduce(0.0) { partial, row in
            partial + abs(standingRiskDoubleValue(row.marketValue) ?? 0)
        }
        guard totalAbsoluteExposure > 0 else {
            return []
        }
        return positions.compactMap { row in
            let marketValue = abs(standingRiskDoubleValue(row.marketValue) ?? 0)
            guard marketValue > 0 else {
                return nil
            }
            return RiskStandingExposure(
                symbol: row.symbol.uppercased(),
                weight: marketValue / totalAbsoluteExposure,
                marketValue: marketValue,
                directionLabel: row.directionLabel,
                sectorName: standingSectorName(for: row.symbol)
            )
        }
        .sorted { lhs, rhs in
            if lhs.weight == rhs.weight {
                return lhs.symbol < rhs.symbol
            }
            return lhs.weight > rhs.weight
        }
    }

    private func makeStandingRiskSnapshot(
        positions: [PositionRow],
        watchlistSymbols: [String]
    ) -> StoreSnapshot {
        StoreSnapshot(
            build: "standing-risk-snapshot",
            positions: positions,
            watchlistSymbols: watchlistSymbols
        )
    }

    private func standingRiskDoubleValue(_ raw: String?) -> Double? {
        guard let raw else {
            return nil
        }
        return Double(raw.trimmingCharacters(in: .whitespacesAndNewlines))
    }

    private func standingRiskPercentText(_ value: Double) -> String {
        let formatter = NumberFormatter()
        formatter.locale = Locale(identifier: "en_US_POSIX")
        formatter.numberStyle = .percent
        formatter.maximumFractionDigits = value < 0.1 ? 1 : 0
        formatter.minimumFractionDigits = 0
        return formatter.string(from: NSNumber(value: value)) ?? "\(Int((value * 100).rounded()))%"
    }

    private func isStandingPortfolioRiskNewsRelevant(
        _ event: NewsEvent,
        heldSymbols: Set<String>
    ) -> Bool {
        let hintSymbols = Set(event.rawSymbolHints.map { $0.uppercased() })
        if hintSymbols.intersection(heldSymbols).isEmpty == false {
            return true
        }
        let body = "\(event.title) \(event.summary ?? "")".lowercased()
        return ["earnings", "guidance", "downgrade", "warning", "funding", "liquidity", "credit", "reserve", "investigation", "regulator", "default"].contains(where: { body.contains($0) })
    }

    private func makeStandingRiskPortfolioScopeSummary(
        exposures: [RiskStandingExposure],
        sectorWeights: [String: Double]
    ) -> String {
        let topHoldings = exposures.prefix(3).map {
            "\($0.symbol) \(standingRiskPercentText($0.weight))"
        }.joined(separator: ", ")
        let topSectors = sectorWeights
            .sorted { lhs, rhs in
                if lhs.value == rhs.value {
                    return lhs.key < rhs.key
                }
                return lhs.value > rhs.value
            }
            .prefix(3)
            .map { "\($0.key) \(standingRiskPercentText($0.value))" }
            .joined(separator: ", ")
        return "Current portfolio risk scope is anchored on holdings \(topHoldings). Sector clustering in scope: \(topSectors)."
    }

    private func makeStandingRiskHeadlineView(
        exposures: [RiskStandingExposure],
        allRiskIssues: [RiskStandingIssue],
        materialNews: [NewsEvent]
    ) -> String {
        let topHolding = exposures.first?.symbol ?? "the top holding"
        let topIssue = allRiskIssues.first?.headline ?? "current portfolio risk posture"
        let newsLead = materialNews.isEmpty
            ? "No new reporting-window headline displaced current construction as the main risk driver."
            : "Material risk developments were led by \(materialNews.prefix(2).map(\.title).joined(separator: " | "))."
        return "\(topIssue) currently matters most, with \(topHolding) anchoring the highest current single-name exposure. \(newsLead)"
    }

    private func makeStandingRiskPortfolioRelevanceSummary(
        strategyObjective: String,
        strategyThemes: [String],
        exposures: [RiskStandingExposure],
        sectorWeights: [String: Double]
    ) -> String {
        let themeLead = strategyThemes.isEmpty
            ? "No explicit key themes were parsed from the current brief."
            : "Key themes in scope: \(strategyThemes.prefix(3).joined(separator: ", "))."
        let concentrationLead = exposures.first.map {
            "Largest single-name exposure is \($0.symbol) at \(standingRiskPercentText($0.weight))."
        } ?? "No exposures were available."
        let sectorLead = sectorWeights.max(by: { $0.value < $1.value }).map {
            "Largest sector cluster is \($0.key) at \(standingRiskPercentText($0.value))."
        } ?? "No sector clustering was derived from the current holdings."
        return "Grounded on the current strategy objective (\(strategyObjective)). \(themeLead) \(concentrationLead) \(sectorLead) The report surfaces only risk issues that could change PM attention, monitoring posture, or sizing judgment."
    }

    private func makeStandingRiskOpenQuestions(
        allRiskIssues: [RiskStandingIssue],
        exposures: [RiskStandingExposure],
        sectorWeights: [String: Double]
    ) -> [String] {
        let topIssue = allRiskIssues.first?.headline ?? "the top current risk issue"
        let topHolding = exposures.first?.symbol ?? "the largest holding"
        let topSector = sectorWeights.max(by: { $0.value < $1.value })?.key ?? "the dominant sector cluster"
        return [
            "Does \(topIssue.lowercased()) warrant a PM change to monitoring posture before the next standing cycle?",
            "Is \(topHolding) sized appropriately given the current concentration and single-name vulnerability profile?",
            "Should the PM treat \(topSector) as a cluster that needs explicit hedge or de-crowding review?"
        ]
    }

    private func makeStandingRiskEvidenceReferences(
        charter: AnalystCharter,
        strategyBrief: PortfolioStrategyBrief?,
        exposures: [RiskStandingExposure],
        materialNews: [NewsEvent],
        externalEvidence: [ExternalAnalystEvidenceDocument]
    ) -> [String] {
        var references: [String] = ["Standing analyst charter: \(charter.title)"]
        if let strategyBrief,
           strategyBrief.title.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty == false {
            references.append("Portfolio Strategy Brief: \(strategyBrief.title)")
        } else {
            references.append("Portfolio Strategy Brief unavailable at generation time")
        }
        references.append("Current holdings snapshot: \(exposures.prefix(5).map { "\($0.symbol) \(standingRiskPercentText($0.weight))" }.joined(separator: ", "))")
        references.append(contentsOf: materialNews.prefix(3).map { "Recent news: \($0.title)" })
        references.append(contentsOf: externalEvidence.prefix(2).map(standingExternalEvidenceReference))
        return references
    }

    private func makeStandingRiskConcentrationIssues(
        exposures: [RiskStandingExposure]
    ) -> [RiskStandingIssue] {
        exposures.prefix(3).enumerated().map { index, exposure in
            RiskStandingIssue(
                issueID: "concentration-\(exposure.symbol.lowercased())",
                headline: "Single-name concentration: \(exposure.symbol)",
                detail: "\(exposure.symbol) represents \(standingRiskPercentText(exposure.weight)) of current portfolio exposure, making it a first-order PM risk review item rather than a background holding.",
                symbol: exposure.symbol,
                priority: max(6, 9 - index)
            )
        }
    }

    private func makeStandingRiskClusteringIssues(
        sectorWeights: [String: Double],
        strategyBrief: PortfolioStrategyBrief?
    ) -> [RiskStandingIssue] {
        let threshold: Double
        let posture = strategyBrief?.currentRiskPosture.lowercased() ?? ""
        if posture.contains("aggressive") || posture.contains("concentrated") {
            threshold = 0.45
        } else if posture.contains("conservative") || posture.contains("defensive") {
            threshold = 0.28
        } else {
            threshold = 0.35
        }
        return sectorWeights
            .filter { $0.value >= threshold }
            .sorted { lhs, rhs in
                if lhs.value == rhs.value { return lhs.key < rhs.key }
                return lhs.value > rhs.value
            }
            .map { sector, weight in
                RiskStandingIssue(
                    issueID: "cluster-\(sector.lowercased().replacingOccurrences(of: "/", with: "-"))",
                    headline: "Sector clustering: \(sector)",
                    detail: "\(sector) accounts for \(standingRiskPercentText(weight)) of current portfolio exposure, so correlated downside could matter more than any single headline in that sleeve.",
                    symbol: nil,
                    priority: 8
                )
            }
    }

    private func makeStandingRiskVulnerabilityIssues(
        exposures: [RiskStandingExposure],
        materialNews: [NewsEvent],
        triggerEvaluation: PortfolioRiskTriggerEvaluation
    ) -> [RiskStandingIssue] {
        var issues: [RiskStandingIssue] = triggerEvaluation.matches.map { match in
            RiskStandingIssue(
                issueID: "trigger-\(match.kind.rawValue)-\(match.symbol.lowercased())",
                headline: match.summary,
                detail: "\(match.detail) What changed: \(match.whatChanged)",
                symbol: match.symbol,
                priority: 9
            )
        }
        let symbolsWithNews = Set(materialNews.flatMap { $0.rawSymbolHints.map { $0.uppercased() } })
        for exposure in exposures where symbolsWithNews.contains(exposure.symbol) {
            issues.append(
                RiskStandingIssue(
                    issueID: "news-vulnerability-\(exposure.symbol.lowercased())",
                    headline: "Single-name vulnerability check: \(exposure.symbol)",
                    detail: "\(exposure.symbol) is both a current holding and part of the materially relevant news set, so PM should treat it as a live vulnerability review rather than passive monitoring.",
                    symbol: exposure.symbol,
                    priority: 8
                )
            )
        }
        return Array(
            Dictionary(uniqueKeysWithValues: issues.map { ($0.issueID, $0) }).values
        )
    }

    private func makeStandingRiskDownsideIssues(
        exposures: [RiskStandingExposure],
        sectorWeights: [String: Double],
        strategyBrief: PortfolioStrategyBrief?
    ) -> [RiskStandingIssue] {
        var issues: [RiskStandingIssue] = []
        if let topExposure = exposures.first {
            issues.append(
                RiskStandingIssue(
                    issueID: "downside-\(topExposure.symbol.lowercased())",
                    headline: "Downside scenario: \(topExposure.symbol) gap or de-rating",
                    detail: "If \(topExposure.symbol) gaps lower or loses multiple support, the current concentration means the drawdown would be portfolio-shaping rather than name-level noise.",
                    symbol: topExposure.symbol,
                    priority: 7
                )
            )
        }
        if let topCluster = sectorWeights.max(by: { $0.value < $1.value }) {
            issues.append(
                RiskStandingIssue(
                    issueID: "cluster-downside-\(topCluster.key.lowercased().replacingOccurrences(of: "/", with: "-"))",
                    headline: "Downside scenario: correlated stress in \(topCluster.key)",
                    detail: "A correlated drawdown across \(topCluster.key) would pressure multiple positions simultaneously because the cluster represents \(standingRiskPercentText(topCluster.value)) of current exposure.",
                    symbol: nil,
                    priority: 6
                )
            )
        }
        if let reviewPosture = strategyBrief?.reviewEscalationPosture,
           reviewPosture.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty == false {
            issues.append(
                RiskStandingIssue(
                    issueID: "review-posture",
                    headline: "Review posture anchor",
                    detail: "Current strategy review posture says: \(reviewPosture). The risk overlay keeps downside scenarios aligned with that PM escalation posture.",
                    symbol: nil,
                    priority: 5
                )
            )
        }
        return issues
    }

