    private func makeFrameworkStandingReportPortfolioRelevanceSummary(
        charter: AnalystCharter,
        strategyBrief: PortfolioStrategyBrief?,
        coveredSymbols: [String]
    ) -> String {
        let analystFocus = standingReportContractProfile(for: charter)
        let strategyGrounding = strategyBrief?.objectiveSummary.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty == false
            ? "Grounded on the current Portfolio Strategy Brief."
            : "No Portfolio Strategy Brief was available, so this placeholder uses only durable charter and portfolio scope truth."

        switch analystFocus {
        case .framework:
            return "\(strategyGrounding) This standing report contract is ready for later analyst-specific population without changing the PM review surface."
        case .sector:
            if coveredSymbols.isEmpty {
                return "\(strategyGrounding) No current in-sector holdings were attached, so later richer slices can populate candidate additions and watch names without changing the contract."
            }
            return "\(strategyGrounding) This sector report contract is ready to compare current names with later ranked long and short candidates."
        case .recentNews:
            if coveredSymbols.isEmpty {
                return "\(strategyGrounding) No current positions were attached, so this recent-news overlay stays focused on watchlist and strategy-theme materiality rather than forcing a fake escalation."
            }
            return "\(strategyGrounding) This recent-news overlay contract is ready to separate PM-attention-worthy developments from watch-only or non-material headlines tied to the covered book."
        case .macroInternational:
            return "\(strategyGrounding) This overlay contract is ready for later macro, international, and ETF expressions that affect portfolio posture across the covered book."
        case .portfolioRisk:
            if coveredSymbols.isEmpty {
                return "\(strategyGrounding) With no current positions attached, the risk overlay remains a framework artifact and should not yet emit a substantive standing risk review."
            }
            return "\(strategyGrounding) This risk contract is ready for later vulnerability, concentration, and downside-scenario population tied to current holdings."
        }
    }

    private func makeFrameworkStandingReportOpenQuestions(
        charter: AnalystCharter,
        coveredSymbols: [String]
    ) -> [String] {
        switch standingReportContractProfile(for: charter) {
        case .framework:
            return [
                "Which developments should this analyst elevate before the next recurring review?",
                "What follow-up or contract refinement would make the next standing report more decision-useful for the PM?"
            ]
        case .sector:
            return [
                coveredSymbols.isEmpty
                    ? "Which names should this sector analyst elevate for inclusion or watchlist monitoring when the sector is not yet represented in the portfolio?"
                    : "Which covered sector names deserve the highest PM attention before the next recurring report?",
                "What long and short candidate ranking should this analyst surface once richer research behavior is enabled?"
            ]
        case .recentNews:
            return [
                "Which reporting-window developments are genuinely worthy of PM attention now versus simply worth monitoring?",
                "Which names, themes, or exposures should the Recent News Analyst keep under tighter watch before the next recurring review?"
            ]
        case .macroInternational:
            return [
                "Which macro or international developments are actually portfolio-relevant rather than background noise?",
                "When should this overlay prefer an ETF or cross-asset expression over single-name follow-up?"
            ]
        case .portfolioRisk:
            return [
                coveredSymbols.isEmpty
                    ? "Should this standing risk review stay quiet until the portfolio carries current positions?"
                    : "Which current exposures or clusters should the PM stress first when richer risk reporting lands?",
                "What downside scenarios or concentration changes should cause follow-up before the next standing review?"
            ]
        }
    }

    private func makeFrameworkStandingReportEvidenceReferenceSummary(
        charter: AnalystCharter,
        strategyBrief: PortfolioStrategyBrief?,
        positions: [PositionRow],
        recentNews: [NewsEvent],
        externalEvidence: [ExternalAnalystEvidenceDocument],
        cadenceSummary: String
    ) -> [String] {
        var references: [String] = []
        references.append("Standing analyst charter: \(charter.title)")
        references.append("Recurring cadence: \(cadenceSummary)")
        if let strategyBrief,
           strategyBrief.title.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty == false {
            references.append("Portfolio Strategy Brief: \(strategyBrief.title)")
        } else {
            references.append("Portfolio Strategy Brief unavailable at generation time")
        }
        if positions.isEmpty {
            references.append("Portfolio scope snapshot: no current positions attached")
        } else {
            references.append("Portfolio scope snapshot: \(positions.map(\.symbol).joined(separator: ", "))")
        }
        if let event = recentNews.first {
            references.append("Latest reporting-window news: \(event.title)")
        }
        if let external = externalEvidence.first {
            references.append(standingExternalEvidenceReference(external))
        }
        return references
    }

