    private func makeSectorStandingAnalystReportDraft(
        schedule: ScheduledJob,
        charter: AnalystCharter,
        strategyBrief: PortfolioStrategyBrief?,
        positions: [PositionRow],
        watchlistSymbols: [String],
        recentNews: [NewsEvent],
        externalEvidence: [ExternalAnalystEvidenceDocument],
        externalIssues: [AnalystExternalEvidenceIssue],
        reportingWindowStart: Date,
        now: Date,
        profile: SectorStandingResearchProfile
    ) -> StandingAnalystReportDraft {
        let cadenceSummary = standingAnalystReportCadenceSummary(intervalSec: schedule.trigger.intervalSec)
        let normalizedWatchlist = Set(watchlistSymbols.map { $0.uppercased() })
        let sectorPositions = positions.filter { profile.coverageSymbols.contains($0.symbol.uppercased()) }
        let coveredSymbols = sectorPositions.map(\.symbol)
        let sectorWatchlistOnly = normalizedWatchlist
            .intersection(profile.coverageSymbols)
            .subtracting(Set(coveredSymbols.map { $0.uppercased() }))
            .sorted()
        let relevantNews = recentNews.filter { isStandingSectorNewsRelevant($0, profile: profile) }
        let materialNews = Array(relevantNews.prefix(3))
        let nonMaterialNews = Array(relevantNews.dropFirst(3).prefix(2))
        let longIdeas = makeStandingSectorIdeas(
            seeds: profile.longCandidates,
            stance: .long,
            sectorName: profile.sectorName,
            strategyBrief: strategyBrief,
            heldSymbols: Set(coveredSymbols.map { $0.uppercased() }),
            watchlistSymbols: normalizedWatchlist,
            relevantNews: relevantNews,
            externalEvidence: externalEvidence
        )
        let shortIdeas = makeStandingSectorIdeas(
            seeds: profile.shortCandidates,
            stance: .short,
            sectorName: profile.sectorName,
            strategyBrief: strategyBrief,
            heldSymbols: Set(coveredSymbols.map { $0.uppercased() }),
            watchlistSymbols: normalizedWatchlist,
            relevantNews: relevantNews,
            externalEvidence: externalEvidence
        )

        let strategyObjective = standingStrategyBriefObjective(strategyBrief)
        let strategyThemes = standingStrategyBriefThemes(strategyBrief)
        let reportingWindowSummary = "\(cadenceSummary) \(profile.sectorName.lowercased()) review covering \(DateCodec.formatISO8601(reportingWindowStart)) through \(DateCodec.formatISO8601(now)) with \(relevantNews.count) relevant news item(s) and \(externalEvidence.count) charter-governed web source(s)."

        let portfolioScopeSummary: String
        if coveredSymbols.isEmpty {
            if sectorWatchlistOnly.isEmpty {
                portfolioScopeSummary = "No current \(profile.sectorName.lowercased()) holdings were attached. This standing cycle shifts to candidate-inclusion work for \(profile.sectorName.lowercased()) exposure."
            } else {
                portfolioScopeSummary = "No current \(profile.sectorName.lowercased()) holdings were attached. Watchlist names already in scope: \(sectorWatchlistOnly.joined(separator: ", "))."
            }
        } else {
            portfolioScopeSummary = "Current \(profile.sectorName.lowercased()) holdings in scope: \(coveredSymbols.joined(separator: ", "))."
        }

        let topLongSymbols = longIdeas.prefix(2).map { $0.seed.symbol }
        let topShortSymbols = shortIdeas.prefix(2).map { $0.seed.symbol }
        let headlineView: String
        if coveredSymbols.isEmpty {
            headlineView = "No current \(profile.sectorName.lowercased()) holdings were attached, so the analyst is using the reporting window to elevate inclusion candidates \(topLongSymbols.joined(separator: ", ")) and short-side pressure-test names \(topShortSymbols.joined(separator: ", "))."
        } else {
            headlineView = "Current \(profile.sectorName.lowercased()) exposure (\(coveredSymbols.joined(separator: ", "))) stays central, with candidate refresh work around \(topLongSymbols.joined(separator: ", ")) on the long side and \(topShortSymbols.joined(separator: ", ")) on the short side."
        }

        let portfolioRelevanceSummary = makeSectorStandingPortfolioRelevanceSummary(
            profile: profile,
            strategyObjective: strategyObjective,
            strategyThemes: strategyThemes,
            coveredSymbols: coveredSymbols,
            sectorWatchlistOnly: sectorWatchlistOnly,
            charter: charter
        )
        let openQuestions = makeSectorStandingOpenQuestions(
            profile: profile,
            coveredSymbols: coveredSymbols,
            sectorWatchlistOnly: sectorWatchlistOnly,
            longIdeas: longIdeas,
            shortIdeas: shortIdeas
        )
        let evidenceReferenceSummary = makeSectorStandingEvidenceReferences(
            profile: profile,
            charter: charter,
            strategyBrief: strategyBrief,
            coveredSymbols: coveredSymbols,
            sectorWatchlistOnly: sectorWatchlistOnly,
            materialNews: materialNews,
            externalEvidence: externalEvidence
        )
        let sections = makeSectorStandingAnalystReportSections(
            profile: profile,
            reportingWindowSummary: reportingWindowSummary,
            portfolioScopeSummary: portfolioScopeSummary,
            portfolioRelevanceSummary: portfolioRelevanceSummary,
            openQuestions: openQuestions,
            evidenceReferenceSummary: evidenceReferenceSummary,
            sectorPositions: sectorPositions,
            sectorWatchlistOnly: sectorWatchlistOnly,
            materialNews: materialNews,
            nonMaterialNews: nonMaterialNews,
            longIdeas: longIdeas,
            shortIdeas: shortIdeas
        )

        let issueSuffix = standingExternalEvidenceIssueSummary(externalIssues).map { " External evidence degraded: \($0)." } ?? ""
        let summaryLead: String
        if coveredSymbols.isEmpty {
            summaryLead = "\(cadenceSummary) \(profile.sectorName.lowercased()) standing review surfaced inclusion candidates \(topLongSymbols.joined(separator: ", ")) and short-side pressure tests \(topShortSymbols.joined(separator: ", "))."
        } else {
            summaryLead = "\(cadenceSummary) \(profile.sectorName.lowercased()) standing review covered current holdings \(coveredSymbols.joined(separator: ", ")) plus candidate refresh work around \(topLongSymbols.joined(separator: ", ")) and \(topShortSymbols.joined(separator: ", "))."
        }
        let newsSummary = materialNews.isEmpty
            ? "No fresh reporting-window headlines cleared the current bounded relevance filter."
            : "Material developments led by \(materialNews.prefix(2).map(\.title).joined(separator: " | "))."
        let charterGuidance = charter.expectedOutputs.first ?? charter.summary
        let externalAnchorLine = standingExternalEvidenceLead(externalEvidence.first)

        return StandingAnalystReportDraft(
            executiveSummary: "\(summaryLead) \(newsSummary)",
            currentView: headlineView,
            evidenceSummary: "Grounded on the analyst charter, Portfolio Strategy Brief, current portfolio construction, and reporting-window news for \(profile.sectorName.lowercased()). Strategy objective: \(strategyObjective).\(strategyThemes.isEmpty ? "" : " Key themes: \(strategyThemes.joined(separator: "; ")).")\(externalAnchorLine)",
            uncertaintySummary: "This sector pass uses bounded symbol coverage plus charter-governed web sources, so holdings outside the current sector seed map may still need explicit watchlist or charter follow-up for fuller coverage. Charter guidance remains: \(charterGuidance).\(issueSuffix)",
            recommendedNextStep: coveredSymbols.isEmpty
                ? "PM should review whether \(topLongSymbols.joined(separator: ", ")) belong on the active sector watchlist before the next standing cycle and whether \(topShortSymbols.first ?? "the short basket") warrants a deeper ad hoc follow-up."
                : "PM should review whether \(coveredSymbols.first ?? profile.sectorName) deserves the next sector follow-up, and whether \(topLongSymbols.joined(separator: ", ")) or \(topShortSymbols.joined(separator: ", ")) should graduate into deeper analyst work before the next standing cycle.",
            confidence: Double(max(longIdeas.first?.conviction ?? 6, shortIdeas.first?.conviction ?? 5)) / 10.0,
            reportingWindowSummary: reportingWindowSummary,
            portfolioScopeSummary: portfolioScopeSummary,
            coveredSymbols: coveredSymbols,
            headlineView: headlineView,
            portfolioRelevanceSummary: portfolioRelevanceSummary,
            openQuestions: openQuestions,
            evidenceReferenceSummary: evidenceReferenceSummary,
            sections: sections,
            skillUsageSummaries: []
        )
    }

    private func makeSectorStandingPortfolioRelevanceSummary(
        profile: SectorStandingResearchProfile,
        strategyObjective: String,
        strategyThemes: [String],
        coveredSymbols: [String],
        sectorWatchlistOnly: [String],
        charter: AnalystCharter
    ) -> String {
        let themeLead = strategyThemes.isEmpty
            ? "No explicit key themes were parsed from the current brief."
            : "Key themes in scope: \(strategyThemes.prefix(3).joined(separator: ", "))."
        if coveredSymbols.isEmpty {
            if sectorWatchlistOnly.isEmpty {
                return "Grounded on the current strategy objective (\(strategyObjective)). \(themeLead) No current \(profile.sectorName.lowercased()) holdings were attached, so this report emphasizes candidate inclusion ideas consistent with \(charter.title)'s standing mandate."
            }
            return "Grounded on the current strategy objective (\(strategyObjective)). \(themeLead) No current \(profile.sectorName.lowercased()) holdings were attached, so this report leans on watchlist names \(sectorWatchlistOnly.joined(separator: ", ")) plus candidate inclusion work."
        }
        return "Grounded on the current strategy objective (\(strategyObjective)). \(themeLead) Current \(profile.sectorName.lowercased()) exposure includes \(coveredSymbols.joined(separator: ", ")), so the report separates holding-specific review from next candidate additions or hedges."
    }

    private func makeSectorStandingOpenQuestions(
        profile: SectorStandingResearchProfile,
        coveredSymbols: [String],
        sectorWatchlistOnly: [String],
        longIdeas: [SectorStandingIdea],
        shortIdeas: [SectorStandingIdea]
    ) -> [String] {
        let topLong = longIdeas.first?.seed.symbol ?? "the top long candidate"
        let topShort = shortIdeas.first?.seed.symbol ?? "the top short candidate"
        if coveredSymbols.isEmpty {
            return [
                sectorWatchlistOnly.isEmpty
                    ? "Which \(profile.sectorName.lowercased()) names should the PM add to active watch coverage first, starting with \(topLong)?"
                    : "Should the PM convert any current watchlist name (\(sectorWatchlistOnly.joined(separator: ", "))) into active sector follow-up before the next standing cycle?",
                "What evidence would move \(topLong) from inclusion candidate to stronger PM priority?",
                "What would invalidate the short-side pressure test on \(topShort)?"
            ]
        }
        return [
            "Which current \(profile.sectorName.lowercased()) holding deserves the highest PM attention before the next standing cycle: \(coveredSymbols.joined(separator: ", "))?",
            "Does \(topLong) add to current \(profile.sectorName.lowercased()) exposure, or should the PM prefer it as a replacement candidate?",
            "Does \(topShort) conflict with the current construction strongly enough to justify deeper short-side work?"
        ]
    }

    private func makeSectorStandingEvidenceReferences(
        profile: SectorStandingResearchProfile,
        charter: AnalystCharter,
        strategyBrief: PortfolioStrategyBrief?,
        coveredSymbols: [String],
        sectorWatchlistOnly: [String],
        materialNews: [NewsEvent],
        externalEvidence: [ExternalAnalystEvidenceDocument]
    ) -> [String] {
        var references: [String] = ["Standing analyst charter: \(charter.title)"]
        if let strategyBrief,
           strategyBrief.title.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty == false {
            references.append("Portfolio Strategy Brief: \(strategyBrief.title)")
        } else {
            references.append("Portfolio Strategy Brief unavailable at generation time")
        }
        if coveredSymbols.isEmpty {
            references.append("Current \(profile.sectorName.lowercased()) holdings: none attached")
        } else {
            references.append("Current \(profile.sectorName.lowercased()) holdings: \(coveredSymbols.joined(separator: ", "))")
        }
        if sectorWatchlistOnly.isEmpty == false {
            references.append("Watchlist names in \(profile.sectorName.lowercased()) scope: \(sectorWatchlistOnly.joined(separator: ", "))")
        }
        references.append(contentsOf: materialNews.prefix(3).map { "Recent news: \($0.title)" })
        references.append(contentsOf: externalEvidence.prefix(2).map(standingExternalEvidenceReference))
        return references
    }

    private func makeSectorStandingAnalystReportSections(
        profile: SectorStandingResearchProfile,
        reportingWindowSummary: String,
        portfolioScopeSummary: String,
        portfolioRelevanceSummary: String,
        openQuestions: [String],
        evidenceReferenceSummary: [String],
        sectorPositions: [PositionRow],
        sectorWatchlistOnly: [String],
        materialNews: [NewsEvent],
        nonMaterialNews: [NewsEvent],
        longIdeas: [SectorStandingIdea],
        shortIdeas: [SectorStandingIdea]
    ) -> [AnalystStandingReportSection] {
        let sections: [AnalystStandingReportSection] = [
            AnalystStandingReportSection(
                sectionId: "reporting-window",
                kind: .reportingWindow,
                summary: reportingWindowSummary,
                items: [
                    AnalystStandingReportItem(
                        itemId: "reporting-window-item",
                        headline: "\(profile.sectorName) standing cycle",
                        detail: "This standing report is grounded on the reporting window, current portfolio construction, and the analyst charter rather than ad hoc delegation residue.",
                        stance: .neutral,
                        priority: 7
                    )
                ]
            ),
            AnalystStandingReportSection(
                sectionId: "portfolio-scope",
                kind: .portfolioScope,
                summary: portfolioScopeSummary,
                items: makeSectorStandingPortfolioScopeItems(
                    profile: profile,
                    sectorPositions: sectorPositions,
                    sectorWatchlistOnly: sectorWatchlistOnly
                )
            ),
            AnalystStandingReportSection(
                sectionId: "material-developments",
                kind: .materialDevelopments,
                summary: materialNews.isEmpty
                    ? "No fresh reporting-window headlines cleared the current bounded \(profile.sectorName.lowercased()) relevance filter."
                    : "Material \(profile.sectorName.lowercased()) developments are separated from lower-signal flow for PM triage.",
                items: makeSectorStandingMaterialItems(
                    materialNews: materialNews,
                    profile: profile
                )
            ),
            AnalystStandingReportSection(
                sectionId: "important-items",
                kind: .importantItems,
                summary: "What matters now is separated from lower-signal commentary and tied back to PM-useful portfolio decisions.",
                items: makeSectorStandingImportantItems(
                    profile: profile,
                    sectorPositions: sectorPositions,
                    longIdeas: longIdeas,
                    shortIdeas: shortIdeas
                )
            ),
            AnalystStandingReportSection(
                sectionId: "non-material-items",
                kind: .nonMaterialItems,
                summary: "Lower-signal or not-yet-actionable items stay distinct from the core sector view.",
                items: makeSectorStandingNonMaterialItems(
                    profile: profile,
                    nonMaterialNews: nonMaterialNews
                )
            ),
            AnalystStandingReportSection(
                sectionId: "long-ideas",
                kind: .longIdeas,
                summary: "Best current long-side candidates in \(profile.sectorName.lowercased()) with bounded conviction scores tied to the current brief and construction.",
                items: longIdeas.map { idea in
                    AnalystStandingReportItem(
                        itemId: "long-\(idea.seed.symbol.lowercased())",
                        headline: idea.seed.headline,
                        detail: idea.detail,
                        symbol: idea.seed.symbol,
                        stance: .long,
                        conviction: idea.conviction
                    )
                }
            ),
            AnalystStandingReportSection(
                sectionId: "short-ideas",
                kind: .shortIdeas,
                summary: "Best current short-side pressure-test candidates in \(profile.sectorName.lowercased()) with bounded conviction scores.",
                items: shortIdeas.map { idea in
                    AnalystStandingReportItem(
                        itemId: "short-\(idea.seed.symbol.lowercased())",
                        headline: idea.seed.headline,
                        detail: idea.detail,
                        symbol: idea.seed.symbol,
                        stance: .short,
                        conviction: idea.conviction
                    )
                }
            ),
            AnalystStandingReportSection(
                sectionId: "portfolio-relevance",
                kind: .portfolioRelevance,
                summary: portfolioRelevanceSummary,
                items: [
                    AnalystStandingReportItem(
                        itemId: "portfolio-relevance-item",
                        headline: "\(profile.sectorName) conclusions remain tied to portfolio construction",
                        detail: "The standing sector analyst is expected to connect company and sector research back to current portfolio posture instead of producing generic market commentary.",
                        stance: .neutral,
                        priority: 7
                    )
                ]
            ),
            AnalystStandingReportSection(
                sectionId: "follow-up",
                kind: .followUp,
                summary: "Open PM follow-up questions remain explicit and separate from any future ad hoc analyst tasking.",
                items: openQuestions.enumerated().map { index, question in
                    AnalystStandingReportItem(
                        itemId: "follow-up-\(index)",
                        headline: "Open question \(index + 1)",
                        detail: question,
                        stance: .neutral,
                        priority: 5
                    )
                }
            ),
            AnalystStandingReportSection(
                sectionId: "evidence",
                kind: .evidence,
                summary: "Grounding references remain explicit so PM review can trace strategy, portfolio, news, and charter-governed web sources.",
                items: evidenceReferenceSummary.enumerated().map { index, reference in
                    AnalystStandingReportItem(
                        itemId: "evidence-\(index)",
                        headline: "Grounding reference \(index + 1)",
                        detail: reference,
                        stance: .neutral,
                        priority: 4
                    )
                }
            )
        ]

        return sections
    }

    private func makeSectorStandingPortfolioScopeItems(
        profile: SectorStandingResearchProfile,
        sectorPositions: [PositionRow],
        sectorWatchlistOnly: [String]
    ) -> [AnalystStandingReportItem] {
        if sectorPositions.isEmpty {
            let watchlistDetail = sectorWatchlistOnly.isEmpty
                ? "No current \(profile.sectorName.lowercased()) holdings or matching watchlist names were attached to this cycle."
                : "Watchlist names already in scope: \(sectorWatchlistOnly.joined(separator: ", "))."
            return [
                AnalystStandingReportItem(
                    itemId: "portfolio-scope-empty",
                    headline: "No current \(profile.sectorName.lowercased()) holdings were attached",
                    detail: "The report shifts to inclusion-candidate work for this sector. \(watchlistDetail)",
                    stance: .neutral,
                    priority: 4
                )
            ]
        }
        return sectorPositions.map { position in
            AnalystStandingReportItem(
                itemId: "portfolio-scope-\(position.symbol.lowercased())",
                headline: "\(position.symbol) (\(position.directionLabel))",
                detail: "Current \(profile.sectorName.lowercased()) holding in scope. Quantity \(position.qty) • Market value \(position.marketValue)",
                symbol: position.symbol,
                stance: .neutral,
                priority: 6
            )
        }
    }

    private func makeSectorStandingMaterialItems(
        materialNews: [NewsEvent],
        profile: SectorStandingResearchProfile
    ) -> [AnalystStandingReportItem] {
        if materialNews.isEmpty {
            return [
                AnalystStandingReportItem(
                    itemId: "material-none",
                    headline: "No fresh \(profile.sectorName.lowercased()) headline cleared the bounded filter",
                    detail: "The standing report still records the reporting window explicitly, but nothing new was strong enough to displace candidate review and current construction work.",
                    stance: .neutral,
                    priority: 4
                )
            ]
        }
        return materialNews.enumerated().map { index, event in
            let symbols = Array(Set(event.rawSymbolHints.map { $0.uppercased() })).sorted()
            let detailParts = [
                event.summary?.trimmingCharacters(in: .whitespacesAndNewlines),
                symbols.isEmpty ? nil : "Symbols: \(symbols.joined(separator: ", "))",
                "Published \(DateCodec.formatISO8601(event.publishedAt))"
            ].compactMap { $0 }
            return AnalystStandingReportItem(
                itemId: "material-\(event.eventId)",
                headline: event.title,
                detail: detailParts.joined(separator: " • "),
                symbol: symbols.first,
                stance: .neutral,
                priority: max(6, 9 - index)
            )
        }
    }

    private func makeSectorStandingImportantItems(
        profile: SectorStandingResearchProfile,
        sectorPositions: [PositionRow],
        longIdeas: [SectorStandingIdea],
        shortIdeas: [SectorStandingIdea]
    ) -> [AnalystStandingReportItem] {
        var items: [AnalystStandingReportItem] = []
        if let position = sectorPositions.first {
            items.append(
                AnalystStandingReportItem(
                    itemId: "important-held-\(position.symbol.lowercased())",
                    headline: "Current holding to keep in PM focus: \(position.symbol)",
                    detail: "This holding is already in the portfolio, so the standing report treats it as the first place where sector developments can change current construction.",
                    symbol: position.symbol,
                    stance: position.isShort ? .short : .long,
                    priority: 8
                )
            )
        }
        if let topLong = longIdeas.first {
            items.append(
                AnalystStandingReportItem(
                    itemId: "important-long-\(topLong.seed.symbol.lowercased())",
                    headline: "Most actionable long-side inclusion candidate: \(topLong.seed.symbol)",
                    detail: topLong.detail,
                    symbol: topLong.seed.symbol,
                    stance: .long,
                    conviction: topLong.conviction
                )
            )
        }
        if let topShort = shortIdeas.first {
            items.append(
                AnalystStandingReportItem(
                    itemId: "important-short-\(topShort.seed.symbol.lowercased())",
                    headline: "Most actionable short-side pressure test: \(topShort.seed.symbol)",
                    detail: topShort.detail,
                    symbol: topShort.seed.symbol,
                    stance: .short,
                    conviction: topShort.conviction
                )
            )
        }
        if items.isEmpty {
            items.append(
                AnalystStandingReportItem(
                    itemId: "important-fallback",
                    headline: "Candidate review remains the main PM-useful output",
                    detail: "Even without a current holding in scope, the standing sector report keeps the long/short candidate list explicit so PM can decide what deserves deeper work next.",
                    stance: .neutral,
                    priority: 6
                )
            )
        }
        return items
    }

    private func makeSectorStandingNonMaterialItems(
        profile: SectorStandingResearchProfile,
        nonMaterialNews: [NewsEvent]
    ) -> [AnalystStandingReportItem] {
        if nonMaterialNews.isEmpty {
            return [
                AnalystStandingReportItem(
                    itemId: "non-material-none",
                    headline: "No additional low-signal \(profile.sectorName.lowercased()) items need PM attention",
                    detail: "The bounded review did not find extra reporting-window headlines that were worth elevating beyond the material list and candidate work.",
                    stance: .neutral,
                    priority: 3
                )
            ]
        }
        return nonMaterialNews.enumerated().map { index, event in
            AnalystStandingReportItem(
                itemId: "non-material-\(event.eventId)",
                headline: event.title,
                detail: event.summary?.trimmingCharacters(in: .whitespacesAndNewlines) ?? "Lower-signal sector flow parked here so it does not crowd out what matters now.",
                stance: .neutral,
                priority: max(2, 4 - index)
            )
        }
    }

    private func makeStandingSectorIdeas(
        seeds: [SectorStandingCandidateSeed],
        stance: AnalystStandingReportItemStance,
        sectorName: String,
        strategyBrief: PortfolioStrategyBrief?,
        heldSymbols: Set<String>,
        watchlistSymbols: Set<String>,
        relevantNews: [NewsEvent],
        externalEvidence: [ExternalAnalystEvidenceDocument]
    ) -> [SectorStandingIdea] {
        let strategyThemes = standingStrategyBriefThemes(strategyBrief)
        let strategyObjective = standingStrategyBriefObjective(strategyBrief)
        let externalAnchor = externalEvidence.first?.title

        return seeds.map { seed in
            let normalizedSymbol = seed.symbol.uppercased()
            let matchedNews = relevantNews.filter { event in
                let hintSymbols = Set(event.rawSymbolHints.map { $0.uppercased() })
                if hintSymbols.contains(normalizedSymbol) {
                    return true
                }
                let body = "\(event.title) \(event.summary ?? "")".lowercased()
                return seed.keywords.contains(where: { body.contains($0.lowercased()) })
            }
            let isHeld = heldSymbols.contains(normalizedSymbol)
            let isWatchlist = watchlistSymbols.contains(normalizedSymbol)
            var conviction = stance == .long ? 6 : 5
            conviction += min(2, matchedNews.count)
            if isHeld {
                conviction += 1
            }
            if isWatchlist {
                conviction += 1
            }
            if strategyThemes.isEmpty == false,
               seed.keywords.contains(where: { keyword in
                   strategyThemes.contains(where: { $0.localizedCaseInsensitiveContains(keyword) })
               }) {
                conviction += 1
            }
            conviction = min(10, max(4, conviction))

            let stanceRationale = stance == .long ? seed.longRationale : seed.shortRationale
            let newsLead = matchedNews.isEmpty
                ? "No reporting-window headline directly referenced \(seed.symbol), so this remains a candidate built from sector posture, charter guidance, and portfolio fit."
                : "Recent developments: \(matchedNews.prefix(2).map(\.title).joined(separator: " | "))."
            let portfolioContext: String
            if isHeld {
                portfolioContext = "\(seed.symbol) is already in the current portfolio, so the PM should treat this as a live exposure review rather than a greenfield idea."
            } else if isWatchlist {
                portfolioContext = "\(seed.symbol) is already on the watchlist, so it can be escalated without first rebuilding coverage from scratch."
            } else {
                portfolioContext = "\(seed.symbol) is not currently held, so it belongs in inclusion or hedge-candidate work rather than immediate action."
            }
            let strategyContext = strategyThemes.isEmpty
                ? "Current objective anchor: \(strategyObjective)."
                : "Best fit with current strategy themes: \(strategyThemes.prefix(2).joined(separator: ", "))."
            let externalContext = standingExternalEvidenceReviewedLead(externalAnchor)
            let detail = "\(stanceRationale) \(newsLead) \(portfolioContext) \(strategyContext) \(externalContext)".trimmingCharacters(in: .whitespacesAndNewlines)

            return SectorStandingIdea(
                seed: seed,
                conviction: conviction,
                detail: detail,
                newsMatches: matchedNews,
                isHeld: isHeld,
                isWatchlist: isWatchlist
            )
        }
        .sorted { lhs, rhs in
            if lhs.conviction == rhs.conviction {
                return lhs.seed.symbol < rhs.seed.symbol
            }
            return lhs.conviction > rhs.conviction
        }
        .prefix(3)
        .map { $0 }
    }

    private func isStandingSectorNewsRelevant(
        _ event: NewsEvent,
        profile: SectorStandingResearchProfile
    ) -> Bool {
        let hintSymbols = Set(event.rawSymbolHints.map { $0.uppercased() })
        if hintSymbols.intersection(profile.coverageSymbols).isEmpty == false {
            return true
        }
        let body = "\(event.title) \(event.summary ?? "")".lowercased()
        return profile.keywords.contains(where: { body.contains($0.lowercased()) })
    }

    private func standingStrategyBriefObjective(_ strategyBrief: PortfolioStrategyBrief?) -> String {
        let objective = strategyBrief?.objectiveSummary.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        return objective.isEmpty ? "No explicit Portfolio Strategy Brief objective was available." : objective
    }

    private func standingStrategyBriefThemes(_ strategyBrief: PortfolioStrategyBrief?) -> [String] {
        strategyBrief?.keyThemes
            .map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
            .filter { $0.isEmpty == false } ?? []
    }

    private func standingExternalEvidenceIssueSummary(
        _ issues: [AnalystExternalEvidenceIssue]
    ) -> String? {
        let details = issues
            .map { $0.detail.trimmingCharacters(in: .whitespacesAndNewlines) }
            .filter { $0.isEmpty == false }
        guard details.isEmpty == false else {
            return nil
        }
        return Array(details.prefix(2)).joined(separator: " | ")
    }

    private func standingExternalEvidenceReference(
        _ external: ExternalAnalystEvidenceDocument
    ) -> String {
        "Charter-governed web source (\(external.sourceTier.displayTitle)): \(external.title)"
    }

    private func standingExternalEvidenceLead(
        _ external: ExternalAnalystEvidenceDocument?
    ) -> String {
        external.map { " Charter-governed web source (\($0.sourceTier.displayTitle)): \($0.title)." } ?? ""
    }

    private func standingExternalEvidenceReviewedLead(
        _ externalTitle: String?
    ) -> String {
        externalTitle.map { "Charter-governed web source reviewed: \($0)." } ?? ""
    }

    private func standingMacroPortfolioSectorNames(
        positions: [PositionRow]
    ) -> [String] {
        Array(
            Set(
                positions.compactMap { standingSectorName(for: $0.symbol) }
            )
        )
        .sorted()
    }

    private func standingSectorName(for symbol: String) -> String? {
        let normalizedSymbol = symbol.uppercased()
        let profiles = [
            standingSectorResearchProfile(for: "bench-sector-technology-analyst"),
            standingSectorResearchProfile(for: "bench-sector-healthcare-biotech-analyst"),
            standingSectorResearchProfile(for: "bench-sector-consumer-analyst"),
            standingSectorResearchProfile(for: "bench-sector-industrials-analyst"),
            standingSectorResearchProfile(for: "bench-sector-financials-analyst"),
            standingSectorResearchProfile(for: "bench-sector-energy-materials-analyst")
        ]
        .compactMap { $0 }
        return profiles.first(where: { $0.coverageSymbols.contains(normalizedSymbol) })?.sectorName
    }

