    private func makeStandingReportPortfolioScopeItems(
        positions: [PositionRow]
    ) -> [AnalystStandingReportItem] {
        if positions.isEmpty {
            return [
                AnalystStandingReportItem(
                    itemId: "portfolio-scope-empty",
                    headline: "No current positions were attached",
                    detail: "The recurring report contract still records scope explicitly so sector candidate generation or risk quiet-state behavior can be added later without changing the artifact shape.",
                    stance: .neutral,
                    priority: 3
                )
            ]
        }

        return positions.map { position in
            AnalystStandingReportItem(
                itemId: "portfolio-scope-\(position.symbol.lowercased())",
                headline: "\(position.symbol) (\(position.directionLabel))",
                detail: "Quantity \(position.qty) • Market value \(position.marketValue)",
                symbol: position.symbol,
                stance: .neutral,
                priority: 5
            )
        }
    }

    private enum StandingReportContractProfile {
        case framework
        case sector
        case recentNews
        case macroInternational
        case portfolioRisk
    }

    private func standingReportContractProfile(for charter: AnalystCharter) -> StandingReportContractProfile {
        switch charter.analystId {
        case recentNewsStandingAnalystID:
            return .recentNews
        case "bench-overlay-macro-international-analyst":
            return .macroInternational
        case "bench-overlay-portfolio-risk-analyst":
            return .portfolioRisk
        default:
            return charter.benchRole == .sector ? .sector : .framework
        }
    }

    private func requiredStandingReportString(
        _ value: JSONValue?,
        field: String
    ) throws -> String {
        guard let raw = value?.stringValue?.trimmingCharacters(in: .whitespacesAndNewlines),
              raw.isEmpty == false else {
            throw JobRunnerError.invalidParameters(message: "Missing \(field) for standing analyst report job.")
        }
        return raw
    }

    private func executeRecentNewsAnalystJob(
        job: JobRecord,
        updateProgress: JobRunner.JobProgressUpdater
    ) async throws -> JobExecutionReport {
        let lookbackMinutes = try replayPositiveIntParam(
            job.parameters["lookbackMinutes"],
            defaultValue: 180,
            field: "lookbackMinutes"
        )
        let now = nowDate()
        let bootstrapSince = Calendar(identifier: .gregorian).date(
            byAdding: .minute,
            value: -lookbackMinutes,
            to: now
        ) ?? now
        let existingReviewState = await recentNewsReviewStateStore.load()
        let recentNews = try await recentNewsEventsForAnalystReview(
            reviewState: existingReviewState,
            bootstrapSince: bootstrapSince
        )

        await updateProgress(0, "Recent news analyst evaluating normalized news")
        let snapshot = await store.snapshot()
        let strategyBrief = try await getPortfolioStrategyBrief()
        let updatedReviewState = makeRecentNewsReviewState(
            previous: existingReviewState,
            reviewedNews: recentNews,
            now: now
        )

        guard recentNews.isEmpty == false else {
            try await recentNewsReviewStateStore.save(updatedReviewState)
            let summary = existingReviewState?.lastReviewedReceivedAt == nil
                ? "recent_news_analyst: bootstrap window quiet no_new_news"
                : "recent_news_analyst: no_new_news_since_review_watermark"
            await updateProgress(1, summary)
            await store.publishDiagnostic(
                "recent news analyst quiet id=\(shortOrderID(job.jobId)) \(summary)",
                source: .engine,
                action: "recent_news_analyst"
            )
            return JobExecutionReport(
                result: .object([
                    "jobType": .string(JobType.recentNewsAnalyst.rawValue),
                    "materialImpact": .bool(false),
                    "lookbackMinutes": .number(Double(lookbackMinutes)),
                    "incrementalReview": .bool(existingReviewState?.lastReviewedReceivedAt != nil),
                    "newNewsCount": .number(0),
                    "consideredNewsCount": .number(0),
                    "candidateCount": .number(0),
                    "summary": .string(summary)
                ])
            )
        }

        let evaluation = RecentNewsMaterialityEvaluator.evaluate(
            recentNews: recentNews,
            positions: snapshot.positions,
            watchlistSymbols: snapshot.watchlistSymbols,
            strategyBrief: strategyBrief
        )

        guard evaluation.isMaterial else {
            try await recentNewsReviewStateStore.save(updatedReviewState)
            await updateProgress(1, evaluation.summary)
            await store.publishDiagnostic(
                "recent news analyst quiet id=\(shortOrderID(job.jobId)) \(evaluation.summary)",
                source: .engine,
                action: "recent_news_analyst"
            )
            return JobExecutionReport(
                result: .object([
                    "jobType": .string(JobType.recentNewsAnalyst.rawValue),
                    "materialImpact": .bool(false),
                    "lookbackMinutes": .number(Double(lookbackMinutes)),
                    "incrementalReview": .bool(existingReviewState?.lastReviewedReceivedAt != nil),
                    "newNewsCount": .number(Double(recentNews.count)),
                    "consideredNewsCount": .number(Double(evaluation.consideredNewsCount)),
                    "candidateCount": .number(0),
                    "summary": .string(evaluation.summary)
                ])
            )
        }

        let pmProfile = try await resolveRecentNewsAnalystPMProfile(job.parameters["pmId"])
        let charter = try await ensureRecentNewsAnalystCharter(now: now)
        let plan = RecentNewsEscalationPlanner.makePlan(
            evaluation: evaluation,
            positions: snapshot.positions,
            watchlistSymbols: snapshot.watchlistSymbols,
            strategyBrief: strategyBrief
        )
        let contextPack = try await buildAnalystContextPack(
            charter: charter,
            pmID: pmProfile.pmId,
            snapshot: snapshot,
            recentNews: recentNews,
            strategyBrief: strategyBrief,
            assembledAt: now
        )

        let existingMemos = try await listAnalystMemos()
        if existingMemos.contains(where: { $0.delegationId == plan.delegationId }) {
            try await recentNewsReviewStateStore.save(updatedReviewState)
            let summary = "recent_news_analyst: material cluster already escalated"
            await updateProgress(1, summary)
            await store.publishDiagnostic(
                "recent news analyst skipped duplicate id=\(shortOrderID(job.jobId)) delegation=\(shortOrderID(plan.delegationId))",
                source: .engine,
                action: "recent_news_analyst"
            )
            return JobExecutionReport(
                result: .object([
                    "jobType": .string(JobType.recentNewsAnalyst.rawValue),
                    "materialImpact": .bool(true),
                    "incrementalReview": .bool(existingReviewState?.lastReviewedReceivedAt != nil),
                    "newNewsCount": .number(Double(recentNews.count)),
                    "candidateCount": .number(Double(evaluation.candidateMatches.count)),
                    "delegationId": .string(plan.delegationId),
                    "decisionId": .string(plan.decisionId),
                    "summary": .string(summary)
                ])
            )
        }

        let runtimePolicy = try await recentNewsAnalystRuntimePolicy(now: now)
        let task = try await upsertAnalystTask(
            makeRecentNewsAnalystTask(
                plan: plan,
                charter: charter,
                contextPack: contextPack,
                now: now
            ),
            source: .engine
        )
        let delegation = try await upsertPMDelegation(
            makeRecentNewsAnalystDelegation(
                plan: plan,
                pmProfile: pmProfile,
                charter: charter,
                task: task,
                runtimePolicy: runtimePolicy,
                now: now
            ),
            source: .engine
        )

        await updateProgress(0.45, "Recent news analyst launching worker")
        let launchResult = try await launchAnalystWorkerForPMDelegation(
            delegationID: delegation.delegationId,
            source: .engine
        )
        let memo: AnalystMemo?
        if let memoID = launchResult.memoId {
            memo = try? await getAnalystMemo(id: memoID)
        } else {
            memo = nil
        }
        let decision = try await upsertPMDecision(
            makeRecentNewsEscalationDecision(
                plan: plan,
                pmProfile: pmProfile,
                charter: charter,
                launchResult: launchResult,
                memo: memo,
                now: now
            ),
            source: .engine
        )

        let impactedSymbols = plan.impactedSymbols.map { JSONValue.string($0) }
        let summary = "recent_news_analyst: material=\(evaluation.candidateMatches.count) escalated=\(plan.impactedSymbols.joined(separator: ", "))"
        try await recentNewsReviewStateStore.save(updatedReviewState)
        await updateProgress(1, summary)
        await store.publishDiagnostic(
            "recent news analyst escalated id=\(shortOrderID(job.jobId)) delegation=\(shortOrderID(delegation.delegationId)) memo=\(launchResult.memoId.map(shortOrderID) ?? "-") decision=\(shortOrderID(decision.decisionId))",
            source: .engine,
            action: "recent_news_analyst"
        )

        return JobExecutionReport(
            result: .object([
                "jobType": .string(JobType.recentNewsAnalyst.rawValue),
                "materialImpact": .bool(true),
                "lookbackMinutes": .number(Double(lookbackMinutes)),
                "incrementalReview": .bool(existingReviewState?.lastReviewedReceivedAt != nil),
                "newNewsCount": .number(Double(recentNews.count)),
                "consideredNewsCount": .number(Double(evaluation.consideredNewsCount)),
                "candidateCount": .number(Double(evaluation.candidateMatches.count)),
                "impactedSymbols": .array(impactedSymbols),
                "delegationId": .string(delegation.delegationId),
                "memoId": launchResult.memoId.map(JSONValue.string) ?? .null,
                "decisionId": .string(decision.decisionId),
                "summary": .string(summary)
            ])
        )
    }

    private func executePortfolioRiskAnalystJob(
        job: JobRecord,
        updateProgress: JobRunner.JobProgressUpdater
    ) async throws -> JobExecutionReport {
        let now = nowDate()
        await updateProgress(0, "Portfolio Risk analyst evaluating bounded triggers")

        let existingReviewState = await portfolioRiskTriggerReviewStateStore.load()
        let (snapshot, strategyBrief, evaluation) = try await currentPortfolioRiskEvaluation(
            existingReviewState: existingReviewState,
            now: now
        )

        guard evaluation.isMaterial else {
            let updatedState = makePortfolioRiskTriggerReviewState(
                previous: existingReviewState,
                evaluation: evaluation,
                now: now,
                reviewSource: .automaticTrigger,
                reviewSummary: evaluation.summary,
                activeTriggerFingerprint: nil
            )
            try await portfolioRiskTriggerReviewStateStore.save(updatedState)
            await updateProgress(1, evaluation.summary)
            await store.publishDiagnostic(
                "portfolio risk analyst quiet id=\(shortOrderID(job.jobId)) \(evaluation.summary)",
                source: .engine,
                action: "portfolio_risk_analyst"
            )
            return JobExecutionReport(
                result: .object([
                    "jobType": .string(JobType.portfolioRiskAnalyst.rawValue),
                    "materialImpact": .bool(false),
                    "candidateCount": .number(0),
                    "summary": .string(evaluation.summary),
                    "rationale": .string(evaluation.rationale)
                ])
            )
        }

        let fingerprint = evaluation.triggerFingerprint ?? "portfolio-risk-trigger"
        if existingReviewState?.activeTriggerFingerprint == fingerprint {
            let updatedState = makePortfolioRiskTriggerReviewState(
                previous: existingReviewState,
                evaluation: evaluation,
                now: now,
                reviewSource: .automaticTrigger,
                reviewSummary: evaluation.summary,
                activeTriggerFingerprint: fingerprint
            )
            try await portfolioRiskTriggerReviewStateStore.save(updatedState)
            let summary = "portfolio_risk_analyst: material trigger already escalated"
            await updateProgress(1, summary)
            await store.publishDiagnostic(
                "portfolio risk analyst skipped duplicate id=\(shortOrderID(job.jobId)) fingerprint=\(shortOrderID(fingerprint))",
                source: .engine,
                action: "portfolio_risk_analyst"
            )
            return JobExecutionReport(
                result: .object([
                    "jobType": .string(JobType.portfolioRiskAnalyst.rawValue),
                    "materialImpact": .bool(true),
                    "escalated": .bool(false),
                    "duplicateSuppressed": .bool(true),
                    "candidateCount": .number(Double(evaluation.matches.count)),
                    "impactedSymbols": .array(evaluation.impactedSymbols.map(JSONValue.string)),
                    "summary": .string(summary),
                    "rationale": .string(evaluation.rationale)
                ])
            )
        }

        let pmProfile = try await resolvePortfolioRiskAnalystPMProfile(job.parameters["pmId"])
        try await ensureStandingAnalystBenchSeeded()
        let charter = try await getAnalystCharter(id: "bench-overlay-portfolio-risk")
        let contextPack = try await buildBenchAnalystContextPack(
            charterID: charter.charterId,
            pmID: pmProfile.pmId
        )
        let plan = makePortfolioRiskEscalationPlan(
            evaluation: evaluation,
            charter: charter,
            strategyBrief: strategyBrief,
            snapshot: snapshot,
            existingReviewState: existingReviewState
        )

        let existingMemos = try await listAnalystMemos()
        if existingMemos.contains(where: { $0.delegationId == plan.delegationId }) {
            let updatedState = makePortfolioRiskTriggerReviewState(
                previous: existingReviewState,
                evaluation: evaluation,
                now: now,
                reviewSource: .automaticTrigger,
                reviewSummary: evaluation.summary,
                activeTriggerFingerprint: fingerprint
            )
            try await portfolioRiskTriggerReviewStateStore.save(updatedState)
            let summary = "portfolio_risk_analyst: material trigger already has memo"
            await updateProgress(1, summary)
            await store.publishDiagnostic(
                "portfolio risk analyst skipped existing memo id=\(shortOrderID(job.jobId)) delegation=\(shortOrderID(plan.delegationId))",
                source: .engine,
                action: "portfolio_risk_analyst"
            )
            return JobExecutionReport(
                result: .object([
                    "jobType": .string(JobType.portfolioRiskAnalyst.rawValue),
                    "materialImpact": .bool(true),
                    "escalated": .bool(false),
                    "duplicateSuppressed": .bool(true),
                    "candidateCount": .number(Double(evaluation.matches.count)),
                    "impactedSymbols": .array(evaluation.impactedSymbols.map(JSONValue.string)),
                    "delegationId": .string(plan.delegationId),
                    "decisionId": .string(plan.decisionId),
                    "summary": .string(summary),
                    "rationale": .string(evaluation.rationale)
                ])
            )
        }

        let task = try await upsertAnalystTask(
            makePortfolioRiskAnalystTask(
                plan: plan,
                charter: charter,
                contextPack: contextPack,
                now: now
            ),
            source: .engine
        )
        let delegation = try await upsertPMDelegation(
            makePortfolioRiskAnalystDelegation(
                plan: plan,
                pmProfile: pmProfile,
                charter: charter,
                task: task,
                runtimePolicy: portfolioRiskAnalystRuntimePolicy(charter: charter, now: now),
                now: now
            ),
            source: .engine
        )

        await updateProgress(0.45, "Portfolio Risk analyst launching worker")
        let launchResult = try await launchAnalystWorkerForPMDelegation(
            delegationID: delegation.delegationId,
            source: .engine
        )
        let memo: AnalystMemo?
        if let memoID = launchResult.memoId {
            memo = try? await getAnalystMemo(id: memoID)
        } else {
            memo = nil
        }
        let decision = try await upsertPMDecision(
            makePortfolioRiskEscalationDecision(
                plan: plan,
                pmProfile: pmProfile,
                charter: charter,
                launchResult: launchResult,
                memo: memo,
                now: now
            ),
            source: .engine
        )

        let updatedState = makePortfolioRiskTriggerReviewState(
            previous: existingReviewState,
            evaluation: evaluation,
            now: now,
            reviewSource: .automaticTrigger,
            reviewSummary: evaluation.summary,
            activeTriggerFingerprint: fingerprint
        )
        try await portfolioRiskTriggerReviewStateStore.save(updatedState)
        let summary = "portfolio_risk_analyst: material=\(evaluation.matches.count) escalated=\(evaluation.impactedSymbols.joined(separator: ", "))"
        await updateProgress(1, summary)
        await store.publishDiagnostic(
            "portfolio risk analyst escalated id=\(shortOrderID(job.jobId)) delegation=\(shortOrderID(delegation.delegationId)) memo=\(launchResult.memoId.map(shortOrderID) ?? "-") decision=\(shortOrderID(decision.decisionId))",
            source: .engine,
            action: "portfolio_risk_analyst"
        )

        return JobExecutionReport(
            result: .object([
                "jobType": .string(JobType.portfolioRiskAnalyst.rawValue),
                "materialImpact": .bool(true),
                "escalated": .bool(true),
                "candidateCount": .number(Double(evaluation.matches.count)),
                "impactedSymbols": .array(evaluation.impactedSymbols.map(JSONValue.string)),
                "delegationId": .string(delegation.delegationId),
                "memoId": launchResult.memoId.map(JSONValue.string) ?? .null,
                "decisionId": .string(decision.decisionId),
                "summary": .string(summary),
                "rationale": .string(evaluation.rationale)
            ])
        )
    }

    private func currentPortfolioRiskEvaluation(
        existingReviewState: PortfolioRiskTriggerReviewState?,
        now: Date
    ) async throws -> (
        snapshot: StoreSnapshot,
        strategyBrief: PortfolioStrategyBrief?,
        evaluation: PortfolioRiskTriggerEvaluation
    ) {
        let snapshot = await store.snapshot()
        let strategyBrief = try await getPortfolioStrategyBrief()
        let recentNews = try await newsStore.listRecent(
            limit: 150,
            since: Calendar(identifier: .gregorian).date(byAdding: .day, value: -14, to: now)
        )
        let evaluation = PortfolioRiskTriggerEvaluator.evaluate(
            snapshot: snapshot,
            strategyBrief: strategyBrief,
            previousObservedPricesBySymbol: existingReviewState?.lastObservedPricesBySymbol ?? [:],
            previousObservedWeightsBySymbol: existingReviewState?.lastObservedWeightsBySymbol ?? [:],
            recentNews: recentNews,
            now: now
        )
        return (snapshot, strategyBrief, evaluation)
    }

    private func recentNewsEventsForAnalystReview(
        reviewState: RecentNewsAnalystReviewState?,
        bootstrapSince: Date
    ) async throws -> [NewsEvent] {
        if let watermark = reviewState?.lastReviewedReceivedAt {
            let alreadyReviewedAtWatermark = Set(reviewState?.lastReviewedEventIDsAtWatermark ?? [])
            return try await newsStore.listRecentByReceivedAt(limit: 300, receivedSince: watermark)
                .filter { event in
                    if event.receivedAt > watermark {
                        return true
                    }
                    return alreadyReviewedAtWatermark.contains(event.eventId) == false
                }
        }

        return try await newsStore.listRecentByReceivedAt(limit: 300, receivedSince: bootstrapSince)
    }

    private func makeRecentNewsReviewState(
        previous: RecentNewsAnalystReviewState?,
        reviewedNews: [NewsEvent],
        now: Date
    ) -> RecentNewsAnalystReviewState {
        guard let watermark = reviewedNews.map(\.receivedAt).max() else {
            if var previous {
                previous.lastRunAt = now
                previous.updatedAt = now
                return previous
            }
            return RecentNewsAnalystReviewState(
                lastReviewedReceivedAt: now,
                lastReviewedEventIDsAtWatermark: [],
                lastRunAt: now,
                updatedAt: now
            )
        }

        return RecentNewsAnalystReviewState(
            stateId: previous?.stateId ?? RecentNewsAnalystReviewState.stateID,
            lastReviewedReceivedAt: watermark,
            lastReviewedEventIDsAtWatermark: reviewedNews
                .filter { $0.receivedAt == watermark }
                .map(\.eventId)
                .sorted(),
            lastRunAt: now,
            updatedAt: now
        )
    }

    private func makePortfolioRiskTriggerReviewState(
        previous: PortfolioRiskTriggerReviewState?,
        evaluation: PortfolioRiskTriggerEvaluation,
        now: Date,
        reviewSource: PortfolioRiskTriggerReviewSource,
        reviewSummary: String,
        activeTriggerFingerprint: String?
    ) -> PortfolioRiskTriggerReviewState {
        PortfolioRiskTriggerReviewState(
            stateId: previous?.stateId ?? PortfolioRiskTriggerReviewState.stateID,
            lastObservedPricesBySymbol: evaluation.observedPricesBySymbol,
            lastObservedWeightsBySymbol: evaluation.observedWeightsBySymbol,
            activeTriggerFingerprint: activeTriggerFingerprint,
            lastReviewedAt: now,
            lastReviewSource: reviewSource,
            lastReviewSummary: reviewSummary,
            lastRunAt: now,
            updatedAt: now
        )
    }

    private func resolveRecentNewsAnalystPMProfile(_ value: JSONValue?) async throws -> PMProfile {
        if let requestedID = value?.stringValue?.trimmingCharacters(in: .whitespacesAndNewlines),
           requestedID.isEmpty == false {
            return try await getPMProfile(id: requestedID)
        }

        let profiles = try await listPMProfiles()
        if profiles.count == 1, let only = profiles.first {
            return only
        }

        throw JobRunnerError.invalidParameters(
            message: "recent_news_analyst requires pmId when multiple PM profiles exist."
        )
    }

    private func resolvePortfolioRiskAnalystPMProfile(_ value: JSONValue?) async throws -> PMProfile {
        if let requestedID = value?.stringValue?.trimmingCharacters(in: .whitespacesAndNewlines),
           requestedID.isEmpty == false {
            return try await getPMProfile(id: requestedID)
        }

        let profiles = try await listPMProfiles()
        if profiles.count == 1, let only = profiles.first {
            return only
        }

        throw JobRunnerError.invalidParameters(
            message: "portfolio_risk_analyst requires pmId when multiple PM profiles exist."
        )
    }

    private func ensureRecentNewsAnalystCharter(now _: Date) async throws -> AnalystCharter {
        try await ensureStandingAnalystBenchSeeded()
        return try await getAnalystCharter(id: recentNewsStandingAnalystCharterID)
    }

    @discardableResult
    private func ensureAgentSkillsSeeded(source: AuditEventSource) async throws -> [AgentSkillRecord] {
        let seeded = try await agentSkillStore.seedMissingDefaultSkills()
        await publishAgentSkillPersistenceDiagnostics()
        guard seeded.isEmpty == false else {
            return seeded
        }
        await store.publishDiagnostic(
            "agent skills seeded ids=\(seeded.map(\.skillId).joined(separator: ","))",
            source: source,
            action: "agent_skill_seed"
        )
        await store.publish(StoreEvent(name: "agent_skill_updated"))
        return seeded
    }

    private func ensureStandingAnalystBenchSeeded() async throws {
        let existing = try await analystCharterStore.loadAll()
        let removedLegacyIDs = try await removeLegacyDuplicateAnalystCharters(from: existing)
        let current = try await analystCharterStore.loadAll()
        let currentByID = Dictionary(uniqueKeysWithValues: current.map { ($0.charterId, $0) })
        let timestamp = nowDate()
        let seed = StandingAnalystBenchSeed()
        var seededIDs: [String] = []
        var refreshedIDs: [String] = []

        for charter in seed.seededCharters(now: timestamp) {
            if let existing = currentByID[charter.charterId] {
                guard let refreshed = refreshedSeededAnalystCharter(existing, seeded: charter) else { continue }
                let updated = try await analystCharterStore.upsert(try validatedAnalystCharter(refreshed))
                refreshedIDs.append(updated.charterId)
                continue
            }

            let updated = try await analystCharterStore.upsert(try validatedAnalystCharter(charter))
            seededIDs.append(updated.charterId)
        }

        guard seededIDs.isEmpty == false || refreshedIDs.isEmpty == false || removedLegacyIDs.isEmpty == false else { return }
        await publishAnalystPersistenceDiagnostics()
        await store.publishDiagnostic(
            [
                seededIDs.isEmpty ? nil : "standing analyst bench seeded ids=\(seededIDs.joined(separator: ","))",
                refreshedIDs.isEmpty ? nil : "standing analyst bench refreshed ids=\(refreshedIDs.joined(separator: ","))",
                removedLegacyIDs.isEmpty ? nil : "removed legacy analyst charters ids=\(removedLegacyIDs.joined(separator: ","))"
            ]
            .compactMap { $0 }
            .joined(separator: " | "),
            source: .engine,
            action: "analyst_bench_seed"
        )
    }

    private func removeLegacyDuplicateAnalystCharters(
        from existing: [AnalystCharter]
    ) async throws -> [String] {
        var removedIDs: [String] = []
        for charter in existing where isLegacyDuplicateAnalystCharter(charter) {
            if try await analystCharterStore.remove(id: charter.charterId) {
                removedIDs.append(charter.charterId)
            }
        }
        return removedIDs
    }

    private func makePortfolioRiskEscalationPlan(
        evaluation: PortfolioRiskTriggerEvaluation,
        charter: AnalystCharter,
        strategyBrief: PortfolioStrategyBrief?,
        snapshot: StoreSnapshot,
        existingReviewState: PortfolioRiskTriggerReviewState?
    ) -> (
        taskId: String,
        delegationId: String,
        decisionId: String,
        taskTitle: String,
        taskDescription: String,
        impactedSymbols: [String]
    ) {
        let fingerprint = evaluation.triggerFingerprint ?? "portfolio-risk-trigger"
        let impactedSymbols = evaluation.impactedSymbols
        let inScopePositions = snapshot.positions
            .filter { impactedSymbols.contains($0.symbol.uppercased()) }
            .map { "\($0.symbol) \($0.directionLabel) qty \($0.qty) market value \($0.marketValue)" }
        let triggerLines = evaluation.matches.map { match in
            "\(match.symbol): \(match.summary) \(match.detail)"
        }
        let previousReviewAnchor = existingReviewState?.lastReviewedAt.map {
            "Prior portfolio-risk review anchor: \(DateCodec.formatISO8601($0))."
        }
        let previousReviewSource = existingReviewState?.lastReviewSource.map { source in
            switch source {
            case .automaticTrigger:
                return "The last review anchor came from an automatic bounded trigger review."
            case .pmInvocation:
                return "The last review anchor came from an ad hoc PM-invoked Portfolio Risk review."
            }
        }
        let strategyPriorities = strategyBrief.map(analystStrategyBriefPriorities(from:))
        let riskFrameworkGuidance = StandingAnalystBenchSeed.portfolioRiskMetricsAndCalculationGuidanceSummary(
            from: charter.primaryDocumentBody
        )

        let description = [
            "Review bounded portfolio-risk trigger conditions for potential PM escalation.",
            inScopePositions.isEmpty ? nil : "Held positions in scope: \(inScopePositions.joined(separator: "; ")).",
            snapshot.watchlistSymbols.isEmpty ? nil : "Watchlist context: \(snapshot.watchlistSymbols.map { $0.uppercased() }.joined(separator: ", ")).",
            strategyBrief.map { "Portfolio strategy brief objective: \($0.objectiveSummary)" },
            strategyBrief.flatMap { $0.currentRiskPosture.isEmpty ? nil : "Current risk posture: \($0.currentRiskPosture)" },
            strategyBrief.flatMap { $0.keyThemes.isEmpty ? nil : "Strategy themes: \($0.keyThemes.joined(separator: "; "))." },
            strategyPriorities.flatMap { $0.isEmpty ? nil : "Strategy priorities: \($0.joined(separator: " | "))." },
            strategyBrief.flatMap { $0.reviewEscalationPosture.isEmpty ? nil : "Review posture: \($0.reviewEscalationPosture)" },
            riskFrameworkGuidance.map { "Risk framework guidance: \($0)." },
            strategyBrief.flatMap { brief in
                guard let revisionSummary = brief.revisionSummary?.trimmingCharacters(in: .whitespacesAndNewlines),
                      revisionSummary.isEmpty == false else {
                    return nil
                }
                return "Latest strategy revision: \(revisionSummary)."
            },
            "Coverage posture: \(evaluation.coverageSummary)",
            "Concentration posture: \(evaluation.concentrationSummary)",
            "Clustered risk view: \(evaluation.clusteredRiskSummary)",
            "Long-vs-short posture: \(evaluation.longShortSummary)",
            "Escalation posture: \(evaluation.escalationDisposition.summaryText).",
            "Why now: \(evaluation.whyNowSummary)",
            "Current book posture: \(evaluation.bookPostureSummary)",
            "Risk trigger: \(evaluation.rationale)",
            "What changed since prior review: \(evaluation.whatChangedSinceReview)",
            "Triggering conditions: \(triggerLines.joined(separator: " | "))",
            previousReviewAnchor,
            previousReviewSource,
            "This is a bounded Portfolio Risk overlay review. Do not approve trading, proposals, or safety-state changes."
        ]
        .compactMap { $0 }
        .joined(separator: " ")

        return (
            taskId: "portfolio-risk-task-\(fingerprint)",
            delegationId: "portfolio-risk-delegation-\(fingerprint)",
            decisionId: "portfolio-risk-decision-\(fingerprint)",
            taskTitle: "Portfolio risk review: \(impactedSymbols.joined(separator: ", "))",
            taskDescription: description,
            impactedSymbols: impactedSymbols
        )
    }

