    private func portfolioRiskAnalystRuntimePolicy(
        charter: AnalystCharter,
        now: Date
    ) -> AnalystRuntimePolicy? {
        guard var policy = charter.defaultRuntimePolicy else {
            return nil
        }
        policy.policySource = .charterDefault
        policy.createdAt = now
        policy.updatedAt = now
        return policy
    }

    private func standingBenchRuntimePolicyForExecution(
        charter: AnalystCharter,
        now: Date
    ) async throws -> AnalystRuntimePolicy? {
        if charter.charterId == recentNewsStandingAnalystCharterID {
            let (_, resolution) = try await resolvedRecentNewsAnalystRuntimeSettingsForExecution(now: now)
            return AnalystRuntimePolicy(
                providerKind: resolution.effectiveProviderKind,
                credentialProfileId: resolution.effectiveCredentialProfileId,
                runtimeIdentifier: resolution.effectiveRuntimeIdentifier,
                reasoningMode: resolution.effectiveReasoningMode,
                policySource: .specializationDefault,
                createdAt: now,
                updatedAt: now
            )
        }

        if isSeededStandingAnalystCharterID(charter.charterId) {
            let (_, resolution) = try await resolvedStandingBenchAnalystRuntimeSettingsForExecution(now: now)
            return AnalystRuntimePolicy(
                providerKind: resolution.effectiveProviderKind,
                credentialProfileId: resolution.effectiveCredentialProfileId,
                runtimeIdentifier: resolution.effectiveRuntimeIdentifier,
                reasoningMode: resolution.effectiveReasoningMode,
                policySource: .standingBenchDefault,
                createdAt: now,
                updatedAt: now
            )
        }

        guard var policy = charter.defaultRuntimePolicy else {
            return nil
        }
        policy.policySource = .charterDefault
        policy.createdAt = now
        policy.updatedAt = now
        return policy
    }

    private func isCoveredStandingDefaultCharter(_ charter: AnalystCharter) -> Bool {
        charter.charterId == recentNewsStandingAnalystCharterID
            || isSeededStandingAnalystCharterID(charter.charterId)
    }

