    private func refreshPortfolioRiskReviewAnchorIfNeeded(
        delegation: PMDelegationRecord,
        charter: AnalystCharter,
        source: AuditEventSource
    ) async {
        guard charter.charterId == "bench-overlay-portfolio-risk",
              delegation.delegationId.hasPrefix("portfolio-risk-delegation-") == false
        else {
            return
        }

        do {
            let now = nowDate()
            let existingReviewState = await portfolioRiskTriggerReviewStateStore.load()
            let (_, _, evaluation) = try await currentPortfolioRiskEvaluation(
                existingReviewState: existingReviewState,
                now: now
            )
            let updatedState = makePortfolioRiskTriggerReviewState(
                previous: existingReviewState,
                evaluation: evaluation,
                now: now,
                reviewSource: .pmInvocation,
                reviewSummary: "ad hoc PM-invoked Portfolio Risk review refreshed the trigger baseline",
                activeTriggerFingerprint: evaluation.triggerFingerprint
            )
            try await portfolioRiskTriggerReviewStateStore.save(updatedState)
            await store.publishDiagnostic(
                "portfolio risk review anchor refreshed delegation=\(shortOrderID(delegation.delegationId)) source=pm_invocation fingerprint=\(updatedState.activeTriggerFingerprint.map(shortOrderID) ?? "-")",
                source: source,
                action: "portfolio_risk_review_anchor_refresh"
            )
        } catch {
            await store.publishDiagnostic(
                "portfolio risk review anchor refresh degraded delegation=\(shortOrderID(delegation.delegationId)) reason=\(error.localizedDescription)",
                source: source,
                action: "portfolio_risk_review_anchor_refresh_failed"
            )
        }
    }

