    private func resolvedRecentNewsAnalystRuntimeSettingsForExecution(
        now: Date
    ) async throws -> (RecentNewsAnalystRuntimeSettings, ResolvedRuntimeSelection) {
        let settings = try await getRecentNewsAnalystRuntimeSettings()
        let resolution = resolveRuntimeSelection(
            configuredRuntimeIdentifier: settings.runtimeIdentifier,
            configuredReasoningMode: settings.reasoningMode,
            configuredProviderKind: settings.providerKind,
            configuredCredentialProfileId: settings.credentialProfileId,
            lastKnownGoodRuntime: settings.lastKnownGoodRuntime,
            checkedBy: settings.updatedBy,
            now: now,
            anthropicExecutionSupported: true
        )
        let updated = applyingRuntimeResolution(
            resolution,
            to: settings,
            updateSource: settings.updateSource,
            updatedBy: settings.updatedBy,
            now: now
        )
        if updated != settings {
            _ = try await recentNewsAnalystRuntimeSettingsStore.upsert(updated)
            await publishAnalystPersistenceDiagnostics()
            await store.publishDiagnostic(
                "recent news runtime selection resolved configured=\(settings.runtimeIdentifier) effective=\(resolution.effectiveRuntimeIdentifier) fallback=\(resolution.fallbackApplied)",
                source: .engine,
                action: "recent_news_runtime_resolution"
            )
        }
        if resolution.validation.status == .invalid, resolution.fallbackApplied == false {
            throw RuntimeSelectionResolutionError.configuredRuntimeInvalid(
                summary: "Recent News Analyst runtime is invalid and no last-known-good fallback is available. \(resolution.validation.summary)"
            )
        }
        return (updated, resolution)
    }

    private func resolvedStandingBenchAnalystRuntimeSettingsForExecution(
        now: Date
    ) async throws -> (StandingBenchAnalystRuntimeSettings, ResolvedRuntimeSelection) {
        let settings = try await getStandingBenchAnalystRuntimeSettings()
        let resolution = resolveRuntimeSelection(
            configuredRuntimeIdentifier: settings.runtimeIdentifier,
            configuredReasoningMode: settings.reasoningMode,
            configuredProviderKind: settings.providerKind,
            configuredCredentialProfileId: settings.credentialProfileId,
            lastKnownGoodRuntime: settings.lastKnownGoodRuntime,
            checkedBy: settings.updatedBy,
            now: now,
            anthropicExecutionSupported: true
        )
        let updated = applyingRuntimeResolution(
            resolution,
            to: settings,
            updateSource: settings.updateSource,
            updatedBy: settings.updatedBy,
            now: now
        )
        if updated != settings {
            _ = try await standingBenchAnalystRuntimeSettingsStore.upsert(updated)
            await publishAnalystPersistenceDiagnostics()
            await store.publishDiagnostic(
                "standing bench runtime selection resolved configured=\(settings.runtimeIdentifier) effective=\(resolution.effectiveRuntimeIdentifier) fallback=\(resolution.fallbackApplied)",
                source: .engine,
                action: "standing_bench_runtime_resolution"
            )
        }
        if resolution.validation.status == .invalid, resolution.fallbackApplied == false {
            if standingBenchRuntimeCanProceedWithDeterministicFallback(resolution) {
                await store.publishDiagnostic(
                    "standing bench runtime unavailable; proceeding with deterministic standing-report fallback configured=\(settings.runtimeIdentifier)",
                    source: .engine,
                    action: "standing_bench_runtime_resolution"
                )
                return (updated, resolution)
            }
            throw RuntimeSelectionResolutionError.configuredRuntimeInvalid(
                summary: "Standing bench runtime is invalid and no last-known-good fallback is available. \(resolution.validation.summary)"
            )
        }
        return (updated, resolution)
    }

    private func standingBenchRuntimeCanProceedWithDeterministicFallback(
        _ resolution: ResolvedRuntimeSelection
    ) -> Bool {
        resolution.configuredProviderKind == .openAI
            && resolution.effectiveProviderKind == .openAI
            && resolution.validation.status == .invalid
            && resolution.validation.category == .unavailable
    }

    @discardableResult
    private func draftProposalFromSignal(
        signal: Signal,
        strategyID: String,
        sourceJobID: String,
        source: AuditEventSource
    ) async throws -> String {
        let proposalID = "signal-\(signal.signalId)"
        let now = nowDate()
        let existing = try await proposalStore.getProposal(id: proposalID)

        let evidenceTitles = signal.evidence
            .prefix(3)
            .map(\.title)
            .joined(separator: " | ")
        let rationale = """
        Signal thesis: \(signal.positionStatement)
        Evidence: \(evidenceTitles)
        """

        let metadata: [String: JSONValue] = [
            "draftedFromSignalId": .string(signal.signalId),
            "sourceJobId": .string(sourceJobID),
            "confidence": .number(signal.confidence),
            "score": .number(signal.score),
            "direction": .string(signal.direction.rawValue),
            "horizon": .string(signal.horizon.rawValue),
            "evidenceIds": .array(
                signal.evidence.compactMap { evidence in
                    evidence.id.map(JSONValue.string)
                }
            )
        ]
        let analystLineage = analystProposalLineage(from: signal)

        var proposal = StrategyProposal(
            proposalId: proposalID,
            createdAt: existing?.createdAt ?? now,
            updatedAt: now,
            createdBy: "analyst-job",
            title: "Signal Draft \(signal.symbols.joined(separator: ","))",
            summary: signal.positionStatement,
            strategyId: strategyID,
            parameters: existing?.parameters ?? ["intervalSec": .number(2)],
            scope: StrategyProposalScope(symbols: signal.symbols, watchlistReference: nil),
            intendedEnvironmentPaperOnly: true,
            constraints: existing?.constraints ?? StrategyProposalConstraints(
                maxOrdersPerMinute: 5,
                maxNotionalPerOrder: Decimal(1_000)
            ),
            testPlan: existing?.testPlan ?? StrategyProposalTestPlan(
                durationMinutes: 60,
                successMetrics: ["no_errors", "signal_alignment"],
                stopConditions: ["manual_stop", "risk_blocks_gt_0"]
            ),
            rationale: rationale,
            metadata: metadata,
            originatingSignalId: signal.signalId,
            analystLineage: existing?.analystLineage ?? analystLineage,
            approval: existing?.approval ?? StrategyProposalApproval(status: .draft),
            runResult: existing?.runResult
        )
        proposal.metadata.merge(existing?.metadata ?? [:]) { _, incoming in incoming }
        proposal.metadata["draftedFromSignalId"] = .string(signal.signalId)
        proposal.metadata["sourceJobId"] = .string(sourceJobID)
        proposal.metadata["confidence"] = .number(signal.confidence)
        proposal.metadata["score"] = .number(signal.score)
        proposal.originatingSignalId = signal.signalId
        proposal.analystLineage = analystLineage ?? existing?.analystLineage

        let updated = try await proposalStore.upsertProposal(proposal)
        await store.publishDiagnostic(
            "proposal drafted from signal proposal_id=\(updated.proposalId) signal_id=\(signal.signalId)",
            source: source,
            action: "signal_draft_proposal"
        )
        return updated.proposalId
    }

    private func validatedAnalystCharter(_ charter: AnalystCharter) throws -> AnalystCharter {
        var updated = charter
        let trimmedTitle = updated.title.trimmingCharacters(in: .whitespacesAndNewlines)
        updated.title = trimmedTitle.isEmpty ? "Untitled Analyst Charter" : trimmedTitle
        updated.analystId = updated.analystId.trimmingCharacters(in: .whitespacesAndNewlines)
        updated.coverageScope = updated.coverageScope.trimmingCharacters(in: .whitespacesAndNewlines)
        updated.strategyFamily = updated.strategyFamily.trimmingCharacters(in: .whitespacesAndNewlines)
        updated.summary = updated.summary.trimmingCharacters(in: .whitespacesAndNewlines)
        updated.documentBody = updated.documentBody?.trimmingCharacters(in: .whitespacesAndNewlines)
        updated.revisionSummary = updated.revisionSummary?.trimmingCharacters(in: .whitespacesAndNewlines)
        updated.sourcePolicy.preferredSources = trimmedNonEmptyEntries(updated.sourcePolicy.preferredSources)
        updated.sourcePolicy.restrictedSources = trimmedNonEmptyEntries(updated.sourcePolicy.restrictedSources)
        updated.sourcePolicy.sourceCategories = trimmedNonEmptyEntries(updated.sourcePolicy.sourceCategories)
        updated.sourcePolicy.guidanceNotes = trimmedNonEmptyEntries(updated.sourcePolicy.guidanceNotes)
        updated.skillReferences = normalizedAgentSkillReferences(updated.skillReferences)
        let trimmedUpdatedBy = updated.updatedBy.trimmingCharacters(in: .whitespacesAndNewlines)
        updated.updatedBy = trimmedUpdatedBy.isEmpty ? "unknown" : trimmedUpdatedBy
        if isCoveredStandingDefaultCharter(updated) {
            updated.defaultRuntimePolicy = nil
        } else {
            updated.defaultRuntimePolicy = try validatedAnalystRuntimePolicy(
                charter.defaultRuntimePolicy,
                expectedSource: .charterDefault
            )
        }
        return updated
    }

    private func normalizedAgentSkillReferences(
        _ references: [AgentSkillReference]
    ) -> [AgentSkillReference] {
        var seen = Set<String>()
        var normalized: [AgentSkillReference] = []
        for reference in references {
            let skillId = reference.skillId.trimmingCharacters(in: .whitespacesAndNewlines)
            guard skillId.isEmpty == false else { continue }
            let key = skillId.lowercased()
            guard seen.insert(key).inserted else { continue }
            var updated = reference
            updated.skillId = skillId
            updated.rationale = trimmedOptional(reference.rationale)
            let actor = reference.updatedBy.trimmingCharacters(in: .whitespacesAndNewlines)
            updated.updatedBy = actor.isEmpty ? "unknown" : actor
            normalized.append(updated)
        }
        return normalized
    }

    private func refreshedSeededAnalystCharter(
        _ charter: AnalystCharter,
        seeded: AnalystCharter
    ) -> AnalystCharter? {
        let persistedBody = charter.documentBody?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        let missingSeededBody = persistedBody.isEmpty
        let missingSourcePolicySection = standingBenchSourcePolicySectionMissing(charter)
        let missingPortfolioRiskGuidanceSection = portfolioRiskGuidanceSectionMissing(charter)
        let missingPolicyValues = charter.sourcePolicy.reputableWebResearchAllowed == false
            && charter.sourcePolicy.preferredSources.isEmpty
            && charter.sourcePolicy.restrictedSources.isEmpty
            && charter.sourcePolicy.guidanceNotes.isEmpty
        let staleCoveredRuntimeDefault = isCoveredStandingDefaultCharter(charter)
            && charter.defaultRuntimePolicy != nil

        guard missingSeededBody || missingSourcePolicySection || missingPortfolioRiskGuidanceSection || missingPolicyValues || staleCoveredRuntimeDefault else {
            return nil
        }

        var refreshed = charter
        refreshed.createdAt = charter.createdAt
        refreshed.defaultRuntimePolicy = nil

        if missingSeededBody, charter.updateSource != .userEdited {
            refreshed.documentBody = seeded.documentBody
        } else {
            var updatedBody = charter.primaryDocumentBody
            if missingPortfolioRiskGuidanceSection, charter.updateSource != .userEdited {
                updatedBody += "\n\n" + StandingAnalystBenchSeed.portfolioRiskMetricsAndCalculationGuidanceSection()
            }
            if missingSourcePolicySection {
                updatedBody += "\n\n" + StandingAnalystBenchSeed.sourcePolicyAndResearchConductSection()
            }
            if updatedBody != charter.primaryDocumentBody {
                refreshed.documentBody = updatedBody
            }
        }

        if missingPolicyValues {
            refreshed.sourcePolicy = seeded.sourcePolicy
        } else {
            refreshed.sourcePolicy.reputableWebResearchAllowed = charter.sourcePolicy.reputableWebResearchAllowed || seeded.sourcePolicy.reputableWebResearchAllowed
            if refreshed.sourcePolicy.preferredSources.isEmpty {
                refreshed.sourcePolicy.preferredSources = seeded.sourcePolicy.preferredSources
            }
            if refreshed.sourcePolicy.guidanceNotes.isEmpty {
                refreshed.sourcePolicy.guidanceNotes = seeded.sourcePolicy.guidanceNotes
            }
            if refreshed.sourcePolicy.sourceCategories.isEmpty {
                refreshed.sourcePolicy.sourceCategories = seeded.sourcePolicy.sourceCategories
            }
        }

        return refreshed.analystId == seeded.analystId ? refreshed : nil
    }

    private func validatedAnalystRuntimePolicy(
        _ policy: AnalystRuntimePolicy?,
        expectedSource: AnalystRuntimePolicySource? = nil
    ) throws -> AnalystRuntimePolicy? {
        guard var policy else { return nil }
        let runtimeIdentifier = policy.runtimeIdentifier.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !runtimeIdentifier.isEmpty else {
            throw AnalystRuntimePolicyValidationError.runtimeIdentifierRequired
        }
        policy.runtimeIdentifier = runtimeIdentifier
        if let expectedSource {
            policy.policySource = expectedSource
        }
        return policy
    }

    private func validatedAnalystSourceAccessSuggestion(
        _ suggestion: AnalystSourceAccessSuggestionRecord
    ) throws -> AnalystSourceAccessSuggestionRecord {
        var updated = suggestion
        updated.suggestionId = updated.suggestionId.trimmingCharacters(in: .whitespacesAndNewlines)
        if updated.suggestionId.isEmpty {
            updated.suggestionId = UUID().uuidString
        }
        updated.analystId = updated.analystId.trimmingCharacters(in: .whitespacesAndNewlines)
        guard updated.analystId.isEmpty == false else {
            throw AnalystSourceAccessSuggestionStoreError.suggestionNotFound(id: "missing_analyst_id")
        }
        updated.charterId = trimmedOptional(updated.charterId)
        updated.taskId = trimmedOptional(updated.taskId)
        updated.memoId = trimmedOptional(updated.memoId)
        updated.findingId = trimmedOptional(updated.findingId)
        updated.evidenceBundleId = trimmedOptional(updated.evidenceBundleId)
        updated.delegationId = trimmedOptional(updated.delegationId)
        updated.requestedSource = updated.requestedSource.trimmingCharacters(in: .whitespacesAndNewlines)
        updated.requestedDomain = trimmedOptional(updated.requestedDomain)
        updated.siteName = trimmedOptional(updated.siteName)
        updated.whyItMatters = updated.whyItMatters.trimmingCharacters(in: .whitespacesAndNewlines)
        updated.affectedTaskSummary = trimmedOptional(updated.affectedTaskSummary)
        updated.resolvedBy = trimmedOptional(updated.resolvedBy)
        updated.resolvedCharterId = trimmedOptional(updated.resolvedCharterId)
        updated.appliedPolicyEntry = trimmedOptional(updated.appliedPolicyEntry)
        updated.resolutionSummary = trimmedOptional(updated.resolutionSummary)

        switch updated.status {
        case .open:
            updated.resolvedBy = nil
            updated.resolvedCharterId = nil
            updated.appliedPolicyEntry = nil
            updated.resolutionSummary = nil
            updated.closedAt = nil
        case .addedToPreferredSources, .addedToRestrictedSources, .dismissed, .reviewed, .closed:
            updated.closedAt = updated.closedAt ?? nowDate()
        }
        return updated
    }

    private func trimmedNonEmptyEntries(_ values: [String]) -> [String] {
        var seen = Set<String>()
        var normalized: [String] = []

        for value in values {
            let trimmed = value.trimmingCharacters(in: .whitespacesAndNewlines)
            guard trimmed.isEmpty == false else { continue }
            let fingerprint = trimmed.lowercased()
            guard seen.insert(fingerprint).inserted else { continue }
            normalized.append(trimmed)
        }

        return normalized
    }

    private func trimmedOptional(_ value: String?) -> String? {
        guard let value else { return nil }
        let trimmed = value.trimmingCharacters(in: .whitespacesAndNewlines)
        return trimmed.isEmpty ? nil : trimmed
    }

    private func preferredPolicyEntry(for suggestion: AnalystSourceAccessSuggestionRecord) -> String {
        if let requestedDomain = trimmedOptional(suggestion.requestedDomain) {
            return requestedDomain.lowercased()
        }
        return suggestion.requestedSource.trimmingCharacters(in: .whitespacesAndNewlines)
    }

    private func mergedPolicyEntries(_ existing: [String], appending value: String) -> [String] {
        trimmedNonEmptyEntries(existing + [value])
    }

    private func removingPolicyEntry(_ value: String, from existing: [String]) -> [String] {
        let fingerprint = value.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
        return trimmedNonEmptyEntries(existing).filter {
            $0.trimmingCharacters(in: .whitespacesAndNewlines).lowercased() != fingerprint
        }
    }

    private func resolvedAnalystCharter(
        for suggestion: AnalystSourceAccessSuggestionRecord
    ) async throws -> AnalystCharter {
        if let charterID = trimmedOptional(suggestion.charterId) {
            return try await getAnalystCharter(id: charterID)
        }

        let matchingCharters = try await listAnalystCharters().filter {
            $0.analystId == suggestion.analystId
        }
        if matchingCharters.count == 1, let charter = matchingCharters.first {
            return charter
        }
        throw AnalystSourceAccessSuggestionActionValidationError.charterLinkMissing(id: suggestion.suggestionId)
    }

    private func standingBenchSourcePolicySectionMissing(_ charter: AnalystCharter) -> Bool {
        guard StandingAnalystBenchSeed.definitions.contains(where: { $0.charterId == charter.charterId }) else {
            return false
        }
        return charter.primaryDocumentBody.contains("### Source Policy And Research Conduct") == false
    }

    private func portfolioRiskGuidanceSectionMissing(_ charter: AnalystCharter) -> Bool {
        guard charter.charterId == "bench-overlay-portfolio-risk" else {
            return false
        }
        return charter.primaryDocumentBody.contains("### Risk Metrics And Calculation Guidance") == false
    }

    private func validatedAnalystStrategyImplication(
        _ implication: AnalystStrategyImplicationRecord
    ) throws -> AnalystStrategyImplicationRecord {
        let implicationID = implication.implicationId.trimmingCharacters(in: .whitespacesAndNewlines)
        guard implicationID.isEmpty == false else {
            throw AnalystStrategyImplicationValidationError.implicationIdRequired
        }

        let pmID = implication.pmId.trimmingCharacters(in: .whitespacesAndNewlines)
        guard pmID.isEmpty == false else {
            throw AnalystStrategyImplicationValidationError.pmIdRequired
        }

        let implicationSummary = implication.implicationSummary.trimmingCharacters(in: .whitespacesAndNewlines)
        guard implicationSummary.isEmpty == false else {
            throw AnalystStrategyImplicationValidationError.implicationSummaryRequired
        }

        let whyItMatters = implication.whyItMatters.trimmingCharacters(in: .whitespacesAndNewlines)
        guard whyItMatters.isEmpty == false else {
            throw AnalystStrategyImplicationValidationError.whyItMattersRequired
        }

        let memoID = trimmedOptionalDecisionText(implication.memoId)
        let findingID = trimmedOptionalDecisionText(implication.findingId)
        let evidenceBundleID = trimmedOptionalDecisionText(implication.evidenceBundleId)
        let delegationID = trimmedOptionalDecisionText(implication.delegationId)
        guard memoID != nil || findingID != nil || evidenceBundleID != nil || delegationID != nil else {
            throw AnalystStrategyImplicationValidationError.linkedAnalystArtifactRequired
        }

        var updated = implication
        updated.implicationId = implicationID
        updated.pmId = pmID
        updated.implicationSummary = implicationSummary
        updated.whyItMatters = whyItMatters
        updated.candidateStrategyBriefRevisionNote = trimmedOptionalDecisionText(
            implication.candidateStrategyBriefRevisionNote
        )
        updated.candidatePMFollowUpSummary = trimmedOptionalDecisionText(
            implication.candidatePMFollowUpSummary
        )
        updated.memoId = memoID
        updated.findingId = findingID
        updated.evidenceBundleId = evidenceBundleID
        updated.delegationId = delegationID
        return updated
    }

    private func validatedAnalystStrategyFollowUpCandidate(
        _ candidate: AnalystStrategyFollowUpCandidateRecord
    ) async throws -> AnalystStrategyFollowUpCandidateRecord {
        let candidateID = candidate.candidateId.trimmingCharacters(in: .whitespacesAndNewlines)
        guard candidateID.isEmpty == false else {
            throw AnalystStrategyFollowUpCandidateValidationError.candidateIdRequired
        }

        let implicationID = candidate.implicationId.trimmingCharacters(in: .whitespacesAndNewlines)
        guard implicationID.isEmpty == false else {
            throw AnalystStrategyFollowUpCandidateValidationError.implicationIdRequired
        }

        guard let implication = try await analystStrategyImplicationStore.get(id: implicationID) else {
            throw AnalystStrategyFollowUpCandidateValidationError.implicationNotFound(id: implicationID)
        }

        let pmID = candidate.pmId.trimmingCharacters(in: .whitespacesAndNewlines)
        guard pmID.isEmpty == false else {
            throw AnalystStrategyFollowUpCandidateValidationError.pmIdRequired
        }

        let candidateSummary = candidate.candidateSummary.trimmingCharacters(in: .whitespacesAndNewlines)
        guard candidateSummary.isEmpty == false else {
            throw AnalystStrategyFollowUpCandidateValidationError.candidateSummaryRequired
        }

        let candidateDetail = candidate.candidateDetail.trimmingCharacters(in: .whitespacesAndNewlines)
        guard candidateDetail.isEmpty == false else {
            throw AnalystStrategyFollowUpCandidateValidationError.candidateDetailRequired
        }

        var updated = candidate
        updated.candidateId = candidateID
        updated.implicationId = implicationID
        updated.pmId = pmID
        updated.candidateSummary = candidateSummary
        updated.candidateDetail = candidateDetail
        updated.memoId = trimmedOptionalDecisionText(candidate.memoId) ?? implication.memoId
        updated.findingId = trimmedOptionalDecisionText(candidate.findingId) ?? implication.findingId
        updated.evidenceBundleId = trimmedOptionalDecisionText(candidate.evidenceBundleId) ?? implication.evidenceBundleId
        updated.delegationId = trimmedOptionalDecisionText(candidate.delegationId) ?? implication.delegationId
        updated.appliedStrategyBriefId = trimmedOptionalDecisionText(candidate.appliedStrategyBriefId)
        updated.convertedInstructionId = trimmedOptionalDecisionText(candidate.convertedInstructionId)
        updated.convertedMandateId = trimmedOptionalDecisionText(candidate.convertedMandateId)

        switch updated.status {
        case .open, .monitoring:
            updated.closedAt = nil
            updated.appliedStrategyBriefId = nil
            updated.convertedInstructionId = nil
            updated.convertedMandateId = nil
        case .appliedToStrategyBrief, .convertedToInstruction, .convertedToMandate, .dismissed:
            updated.closedAt = updated.closedAt ?? nowDate()
        }

        return updated
    }

    private func makePortfolioStrategyBriefApplyingStrategyFollowUpCandidate(
        candidate: AnalystStrategyFollowUpCandidateRecord,
        implication: AnalystStrategyImplicationRecord,
        existing: PortfolioStrategyBrief,
        updatedBy: String,
        now: Date
    ) -> PortfolioStrategyBrief {
        let existingBody = existing.primaryDocumentBody.trimmingCharacters(in: .whitespacesAndNewlines)
        let appliedSection = [
            "## Applied Strategy Follow-Up",
            "- Candidate: \(candidate.candidateSummary)",
            "- Strategic implication: \(implication.implicationSummary)",
            "- Why it matters: \(implication.whyItMatters)",
            "",
            candidate.candidateDetail
        ]
            .joined(separator: "\n")
            .trimmingCharacters(in: .whitespacesAndNewlines)

        let updatedDocumentBody = existingBody.isEmpty
            ? appliedSection
            : "\(existingBody)\n\n\(appliedSection)"

        return PortfolioStrategyBrief(
            briefId: existing.briefId,
            title: existing.title,
            documentBody: updatedDocumentBody,
            objectiveSummary: existing.objectiveSummary,
            keyThemes: existing.keyThemes,
            currentRiskPosture: existing.currentRiskPosture,
            materialDevelopments: existing.materialDevelopments,
            nonMaterialDevelopments: existing.nonMaterialDevelopments,
            reviewEscalationPosture: existing.reviewEscalationPosture,
            revisionSummary: "Applied owner-approved strategy change: \(candidate.candidateSummary)",
            sourceCommunicationMessageId: existing.sourceCommunicationMessageId,
            sourceAnalystStrategyFollowUpCandidateId: candidate.candidateId,
            sourceAnalystStrategyImplicationId: implication.implicationId,
            sourceAnalystMemoId: candidate.memoId,
            sourceAnalystFindingId: candidate.findingId,
            sourceAnalystEvidenceBundleId: candidate.evidenceBundleId,
            updatedBy: updatedBy.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty ? candidate.pmId : updatedBy,
            updateSource: .strategyFollowUpCandidateApplied,
            createdAt: existing.createdAt,
            updatedAt: now
        )
    }

    private func makeStrategyFollowUpInstructionBody(
        candidate: AnalystStrategyFollowUpCandidateRecord,
        implication: AnalystStrategyImplicationRecord
    ) -> String {
        [
            "Follow-up candidate summary: \(candidate.candidateSummary)",
            "",
            "Strategic implication: \(implication.implicationSummary)",
            "",
            "Why it matters: \(implication.whyItMatters)",
            "",
            "Bounded PM instruction detail:",
            candidate.candidateDetail
        ]
        .joined(separator: "\n")
    }

    private func validatedPMDecision(_ decision: PMDecisionRecord) throws -> PMDecisionRecord {
        func trimmedUniqueDecisionLines(_ values: [String]?) -> [String]? {
            guard let values else { return nil }
            let trimmed = orderedUniqueStrings(values)
            return trimmed.isEmpty ? nil : trimmed
        }

        let pmID = decision.pmId.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !pmID.isEmpty else {
            throw PMDecisionValidationError.pmIdRequired
        }

        let title = decision.title.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !title.isEmpty else {
            throw PMDecisionValidationError.titleRequired
        }

        let summary = decision.summary.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !summary.isEmpty else {
            throw PMDecisionValidationError.summaryRequired
        }

        var updated = decision
        updated.pmId = pmID
        updated.title = title
        updated.summary = summary
        updated.recommendedAction = trimmedOptionalDecisionText(updated.recommendedAction)
        updated.evidenceSummary = trimmedOptionalDecisionText(updated.evidenceSummary)
        updated.ownerAsk = trimmedOptionalDecisionText(updated.ownerAsk)
        updated.approvedNextStepSummary = trimmedOptionalDecisionText(updated.approvedNextStepSummary)
        updated.sourceCommunicationMessageId = trimmedOptionalDecisionText(updated.sourceCommunicationMessageId)
        updated.standingReviewDisposition = trimmedOptionalDecisionText(updated.standingReviewDisposition)
        updated.standingReviewAnalystTitles = trimmedUniqueDecisionLines(updated.standingReviewAnalystTitles)
        updated.standingReviewAttentionItems = trimmedUniqueDecisionLines(updated.standingReviewAttentionItems)
        updated.standingReviewCandidateLongs = trimmedUniqueDecisionLines(updated.standingReviewCandidateLongs)
        updated.standingReviewCandidateShorts = trimmedUniqueDecisionLines(updated.standingReviewCandidateShorts)
        updated.standingReviewCandidateThemes = trimmedUniqueDecisionLines(updated.standingReviewCandidateThemes)
        updated.standingReviewFollowUpItems = trimmedUniqueDecisionLines(updated.standingReviewFollowUpItems)
        return updated
    }

    private func validatedPortfolioStrategyBrief(_ brief: PortfolioStrategyBrief) -> PortfolioStrategyBrief {
        func trimmedLines(_ values: [String]) -> [String] {
            values
                .map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
                .filter { !$0.isEmpty }
        }

        var updated = brief
        updated.briefId = PortfolioStrategyBrief.singletonID
        let trimmedTitle = updated.title.trimmingCharacters(in: .whitespacesAndNewlines)
        updated.title = trimmedTitle.isEmpty ? "Current Portfolio Strategy Brief" : trimmedTitle
        updated.documentBody = updated.documentBody?.trimmingCharacters(in: .whitespacesAndNewlines)
        updated.objectiveSummary = updated.objectiveSummary.trimmingCharacters(in: .whitespacesAndNewlines)
        updated.keyThemes = trimmedLines(updated.keyThemes)
        updated.currentRiskPosture = updated.currentRiskPosture.trimmingCharacters(in: .whitespacesAndNewlines)
        updated.materialDevelopments = trimmedLines(updated.materialDevelopments)
        updated.nonMaterialDevelopments = trimmedLines(updated.nonMaterialDevelopments)
        updated.reviewEscalationPosture = updated.reviewEscalationPosture.trimmingCharacters(in: .whitespacesAndNewlines)
        updated.revisionSummary = updated.revisionSummary?.trimmingCharacters(in: .whitespacesAndNewlines)
        updated.sourceCommunicationMessageId = updated.sourceCommunicationMessageId?
            .trimmingCharacters(in: .whitespacesAndNewlines)
        updated.sourceAnalystStrategyFollowUpCandidateId = trimmedOptionalDecisionText(updated.sourceAnalystStrategyFollowUpCandidateId)
        updated.sourceAnalystStrategyImplicationId = trimmedOptionalDecisionText(updated.sourceAnalystStrategyImplicationId)
        updated.sourceAnalystMemoId = trimmedOptionalDecisionText(updated.sourceAnalystMemoId)
        updated.sourceAnalystFindingId = trimmedOptionalDecisionText(updated.sourceAnalystFindingId)
        updated.sourceAnalystEvidenceBundleId = trimmedOptionalDecisionText(updated.sourceAnalystEvidenceBundleId)
        let trimmedUpdatedBy = updated.updatedBy.trimmingCharacters(in: .whitespacesAndNewlines)
        updated.updatedBy = trimmedUpdatedBy.isEmpty ? "unknown" : trimmedUpdatedBy
        return updated
    }

    private func validatedPMInteractionMemory(_ memory: PMInteractionMemoryRecord) throws -> PMInteractionMemoryRecord {
        func trimmedUniqueLines(_ values: [String], uppercase: Bool = false) -> [String] {
            var seen: Set<String> = []
            var result: [String] = []

            for value in values {
                let trimmed = value.trimmingCharacters(in: .whitespacesAndNewlines)
                guard trimmed.isEmpty == false else { continue }
                let normalized = uppercase ? trimmed.uppercased() : trimmed
                let key = normalized.lowercased()
                guard seen.insert(key).inserted else { continue }
                result.append(normalized)
            }

            return result
        }

        let pmID = memory.pmId.trimmingCharacters(in: .whitespacesAndNewlines)
        guard pmID.isEmpty == false else {
            throw PMInteractionMemoryValidationError.pmIdRequired
        }

        let title = memory.title.trimmingCharacters(in: .whitespacesAndNewlines)
        guard title.isEmpty == false else {
            throw PMInteractionMemoryValidationError.titleRequired
        }

        let summary = memory.summary.trimmingCharacters(in: .whitespacesAndNewlines)
        guard summary.isEmpty == false else {
            throw PMInteractionMemoryValidationError.summaryRequired
        }

        var updated = memory
        updated.pmId = pmID
        updated.title = title
        updated.summary = summary
        updated.symbols = trimmedUniqueLines(updated.symbols, uppercase: true)
        updated.themes = trimmedUniqueLines(updated.themes)
        updated.riskPostures = trimmedUniqueLines(updated.riskPostures)
        updated.recommendationTypes = trimmedUniqueLines(updated.recommendationTypes)
        updated.sourceCommunicationMessageId = trimmedOptionalDecisionText(updated.sourceCommunicationMessageId)
        updated.sourceDecisionId = trimmedOptionalDecisionText(updated.sourceDecisionId)
        updated.sourceApprovalRequestId = trimmedOptionalDecisionText(updated.sourceApprovalRequestId)
        updated.sourceStrategyBriefId = trimmedOptionalDecisionText(updated.sourceStrategyBriefId)
        updated.sourceAnalystMemoId = trimmedOptionalDecisionText(updated.sourceAnalystMemoId)
        return updated
    }

    private func validatedPortfolioWatchChartWallConfiguration(
        _ configuration: PortfolioWatchChartWallConfiguration,
