    private func normalizedPMRuntimeSettings(
        _ settings: PMRuntimeSettings,
        previous: PMRuntimeSettings?,
        now: Date
    ) -> PMRuntimeSettings {
        let checkedBy = normalizedRuntimeUpdatedBy(settings.updatedBy)
        let normalizedProvider = settings.providerKind
        let normalizedCredentialProfileId = normalizedCredentialProfileId(
            settings.credentialProfileId,
            providerKind: normalizedProvider
        )
        let validation = validateRuntimeConfiguration(
            settings.runtimeIdentifier,
            providerKind: normalizedProvider,
            credentialProfileId: normalizedCredentialProfileId,
            checkedBy: checkedBy,
            now: now,
            anthropicExecutionSupported: true
        )

        var updated = settings
        updated.settingsId = PMRuntimeSettings.singletonID
        updated.providerKind = normalizedProvider
        updated.credentialProfileId = normalizedCredentialProfileId
        updated.runtimeIdentifier = normalizedRuntimeIdentifier(settings.runtimeIdentifier)
        updated.updatedBy = checkedBy
        updated.validationStatus = validation
        let configurationChanged = previous.map {
            normalizedRuntimeIdentifier($0.runtimeIdentifier) != updated.runtimeIdentifier
                || $0.reasoningMode != updated.reasoningMode
                || $0.providerKind != updated.providerKind
                || $0.credentialProfileId != updated.credentialProfileId
        } ?? false
        updated.executionStatus = configurationChanged ? nil : (previous?.executionStatus ?? settings.executionStatus)
        if validation.status == .valid {
            updated.lastKnownGoodRuntime = LastKnownGoodRuntimeRecord(
                providerKind: updated.providerKind,
                credentialProfileId: updated.credentialProfileId,
                runtimeIdentifier: updated.runtimeIdentifier,
                reasoningMode: updated.reasoningMode,
                verifiedAt: now,
                summary: "Accepted by the app's bounded local runtime validation policy."
            )
            updated.lastFallback = nil
        } else {
            updated.lastKnownGoodRuntime = previous?.lastKnownGoodRuntime ?? settings.lastKnownGoodRuntime
            updated.lastFallback = validation.status == .warning ? nil : previous?.lastFallback
        }
        return updated
    }

    private func validateRuntimeIdentifier(
        _ runtimeIdentifier: String,
        checkedBy: String,
        now: Date
    ) -> RuntimeValidationRecord {
        let trimmed = normalizedRuntimeIdentifier(runtimeIdentifier)
        guard trimmed.isEmpty == false else {
            return RuntimeValidationRecord(
                status: .invalid,
                category: .invalidFormat,
                summary: "Runtime identifier is required before the app can rely on this setting.",
                checkedAt: now,
                checkedBy: checkedBy
            )
        }
        guard trimmed.count <= 128 else {
            return RuntimeValidationRecord(
                status: .invalid,
                category: .invalidFormat,
                summary: "Runtime identifier is too long. Keep it to 128 characters or fewer.",
                checkedAt: now,
                checkedBy: checkedBy
            )
        }

        let allowedScalars = CharacterSet(charactersIn: "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789-._:")
        let invalidCharacterFound = trimmed.unicodeScalars.contains { allowedScalars.contains($0) == false }
        guard invalidCharacterFound == false else {
            return RuntimeValidationRecord(
                status: .invalid,
                category: .invalidFormat,
                summary: "Runtime identifier can use letters, numbers, hyphen, underscore, period, and colon only.",
                checkedAt: now,
                checkedBy: checkedBy
            )
        }

        let knownFamilies = ["gpt-", "o", "omni-", "chatgpt-", "claude-"]
        let lowercased = trimmed.lowercased()
        if knownFamilies.contains(where: { lowercased.hasPrefix($0) }) {
            return RuntimeValidationRecord(
                status: .valid,
                category: .accepted,
                summary: "Runtime identifier passed the app's bounded local validation policy.",
                checkedAt: now,
                checkedBy: checkedBy
            )
        }

        return RuntimeValidationRecord(
            status: .warning,
            category: .unknownRuntimeFamily,
            summary: "Runtime identifier is syntactically acceptable but outside the app's known runtime families. Save is allowed, but review it before relying on it.",
            checkedAt: now,
            checkedBy: checkedBy
        )
    }

    private func validateAnthropicRuntimeIdentifier(
        _ runtimeIdentifier: String,
        baseValidation: RuntimeValidationRecord,
        checkedBy: String,
        now: Date
    ) -> RuntimeValidationRecord {
        guard baseValidation.status != .invalid else { return baseValidation }

        let normalized = normalizedRuntimeIdentifier(runtimeIdentifier).lowercased()
        let currentFamilyPattern = #"^claude-(opus|sonnet|haiku)-[0-9]+(-[0-9]+)*(-[0-9]{8})?$"#
        let legacyFamilyPattern = #"^claude-[0-9]+(-[0-9]+)*-(opus|sonnet|haiku)(-[0-9]{8})?$"#
        let matchesCurrentFamily = normalized.range(
            of: currentFamilyPattern,
            options: .regularExpression
        ) != nil
        let matchesLegacyFamily = normalized.range(
            of: legacyFamilyPattern,
            options: .regularExpression
        ) != nil

        guard matchesCurrentFamily || matchesLegacyFamily else {
            return RuntimeValidationRecord(
                status: .invalid,
                category: .invalidFormat,
                summary: "Anthropic runtime identifier is not a recognized Claude API model id or alias. Use a Claude API id or alias such as claude-sonnet-4-6, claude-opus-4-7, claude-haiku-4-5, or a dated Claude snapshot id.",
                checkedAt: now,
                checkedBy: checkedBy
            )
        }

        return RuntimeValidationRecord(
            status: .valid,
            category: .accepted,
            summary: "Anthropic runtime identifier passed the app's bounded Claude API model-id validation policy.",
            checkedAt: now,
            checkedBy: checkedBy
        )
    }

    private func validateRuntimeConfiguration(
        _ runtimeIdentifier: String,
        providerKind: LLMProviderKind,
        credentialProfileId: String,
        checkedBy: String,
        now: Date,
        anthropicExecutionSupported: Bool = false
    ) -> RuntimeValidationRecord {
        let baseValidation = validateRuntimeIdentifier(
            runtimeIdentifier,
            checkedBy: checkedBy,
            now: now
        )
        guard baseValidation.status != .invalid else {
            return baseValidation
        }

        let providerRuntimeValidation: RuntimeValidationRecord
        switch providerKind {
        case .openAI:
            providerRuntimeValidation = baseValidation
        case .anthropic:
            providerRuntimeValidation = validateAnthropicRuntimeIdentifier(
                runtimeIdentifier,
                baseValidation: baseValidation,
                checkedBy: checkedBy,
                now: now
            )
        }
        guard providerRuntimeValidation.status != .invalid else {
            return providerRuntimeValidation
        }

        let credentialResolution = llmCredentialResolution(
            providerKind: providerKind,
            credentialProfileId: credentialProfileId
        )

        switch providerKind {
        case .openAI:
            return makeOpenAIProviderValidationRecord(
                checkedBy: checkedBy,
                now: now,
                baseValidation: baseValidation,
                credentialResolution: openAICredentialResolution(from: credentialResolution)
            )
        case .anthropic:
            switch credentialResolution.status {
            case .ready:
                guard anthropicExecutionSupported else {
                    return RuntimeValidationRecord(
                        status: .invalid,
                        category: .unavailable,
                        summary: "\(providerRuntimeValidation.summary) \(credentialResolution.summary) Anthropic is configurable for this runtime setting, but live Anthropic analyst execution is not implemented yet for this path. PM conversation execution is the first supported Anthropic path.",
                        checkedAt: now,
                        checkedBy: checkedBy
                    )
                }
                return RuntimeValidationRecord(
                    status: providerRuntimeValidation.status,
                    category: providerRuntimeValidation.category,
                    summary: "\(providerRuntimeValidation.summary) \(credentialResolution.summary) The app can attempt live Anthropic Messages API execution for this configured runtime path, but this check does not prove that a live provider request has already succeeded.",
                    checkedAt: now,
                    checkedBy: checkedBy
                )
            case .missingKey, .emptyKey, .disabled, .unsupportedAuth:
                return RuntimeValidationRecord(
                    status: .invalid,
                    category: .unavailable,
                    summary: "\(providerRuntimeValidation.summary) \(credentialResolution.summary)",
                    checkedAt: now,
                    checkedBy: checkedBy
                )
            }
        }
    }

    private func llmCredentialResolution(
        providerKind: LLMProviderKind,
        credentialProfileId: String
    ) -> LLMCredentialResolution {
        if providerKind == .openAI, preferConfiguredLLMProviderCredentials == false {
            return llmCredentialResolution(
                from: openAIKeyStatusProvider.credentialResolution(),
                profileId: credentialProfileId
            )
        }
        let settings = (try? llmProviderSettingsStore.loadOrDefault()) ?? .default(now: nowDate())
        let normalizedProfileId = normalizedCredentialProfileId(
            credentialProfileId,
            providerKind: providerKind
        )
        let profile = settings.profile(id: normalizedProfileId)
            ?? settings.profiles(for: providerKind).first
            ?? (providerKind == .openAI
                ? LLMCredentialProfile.defaultOpenAI(now: nowDate())
                : LLMCredentialProfile.defaultAnthropic(now: nowDate()))
        let resolution = llmCredentialResolver.resolve(profile: profile)
        if providerKind == .openAI, resolution.status != .ready, settings.updateSource == .migration || settings.updateSource == .systemDefault {
            let fallback = openAIKeyStatusProvider.credentialResolution()
            if fallback.isReady {
                return LLMCredentialResolution(
                    status: .ready,
                    apiKey: fallback.apiKey,
                    profileId: profile.profileId,
                    providerKind: .openAI,
                    matchedServiceOrLabel: fallback.matchedServiceOrLabel,
                    account: fallback.account,
                    summary: fallback.summary
                )
            }
        }
        return resolution
    }

    private func llmCredentialResolution(
        from resolution: OpenAICredentialResolution,
        profileId: String
    ) -> LLMCredentialResolution {
        let status: LLMCredentialResolutionStatus
        switch resolution.status {
        case .ready:
            status = .ready
        case .missingKey:
            status = .missingKey
        case .emptyKey:
            status = .emptyKey
        }
        return LLMCredentialResolution(
            status: status,
            apiKey: resolution.apiKey,
            profileId: profileId,
            providerKind: .openAI,
            matchedServiceOrLabel: resolution.matchedServiceOrLabel,
            account: resolution.account,
            summary: resolution.summary
        )
    }

    private func openAICredentialResolution(
        from resolution: LLMCredentialResolution
    ) -> OpenAICredentialResolution {
        let status: OpenAICredentialResolutionStatus
        switch resolution.status {
        case .ready:
            status = .ready
        case .emptyKey:
            status = .emptyKey
        case .missingKey, .disabled, .unsupportedAuth:
            status = .missingKey
        }
        let source: OpenAICredentialResolutionSource?
        switch resolution.source {
        case .configuredServiceAccount:
            source = .configuredProfileServiceAccount
        case .configuredLabelAccount:
            source = .configuredProfileLabelAccount
        case .legacyServiceAccount:
            source = .legacyServiceAccount
        case .legacyLabelAccount:
            source = .legacyLabelAccount
        case nil:
            source = nil
        }
        return OpenAICredentialResolution(
            status: status,
            apiKey: resolution.apiKey,
            source: source,
            matchedServiceOrLabel: resolution.matchedServiceOrLabel,
            account: resolution.account,
            summary: resolution.summary
        )
    }

    private func openAICredentialResolution(
        for runtimeSelection: ResolvedRuntimeSelection
    ) -> OpenAICredentialResolution {
        guard runtimeSelection.effectiveProviderKind == .openAI else {
            return OpenAICredentialResolution(
                status: .missingKey,
                account: runtimeSelection.effectiveCredentialProfileId,
                summary: "\(runtimeSelection.effectiveProviderKind.displayName) execution is not available through the OpenAI Responses path."
            )
        }
        return openAICredentialResolution(
            from: llmCredentialResolution(
                providerKind: .openAI,
                credentialProfileId: runtimeSelection.effectiveCredentialProfileId
            )
        )
    }

    private func openAICredentialResolution(
        for runtimePolicy: AnalystRuntimePolicy
    ) -> OpenAICredentialResolution {
        guard runtimePolicy.providerKind == .openAI else {
            return OpenAICredentialResolution(
                status: .missingKey,
                account: runtimePolicy.credentialProfileId,
                summary: "\(runtimePolicy.providerKind.displayName) execution is not available through the OpenAI Responses path."
            )
        }
        return openAICredentialResolution(
            from: llmCredentialResolution(
                providerKind: .openAI,
                credentialProfileId: runtimePolicy.credentialProfileId
            )
        )
    }

    private func resolveRuntimeSelection(
        configuredRuntimeIdentifier: String,
        configuredReasoningMode: AnalystRuntimeReasoningMode?,
        configuredProviderKind: LLMProviderKind,
        configuredCredentialProfileId: String,
        lastKnownGoodRuntime: LastKnownGoodRuntimeRecord?,
        checkedBy: String,
        now: Date,
        anthropicExecutionSupported: Bool = false
    ) -> ResolvedRuntimeSelection {
        let normalizedConfiguredProfileId = normalizedCredentialProfileId(
            configuredCredentialProfileId,
            providerKind: configuredProviderKind
        )
        let validation = validateRuntimeConfiguration(
            configuredRuntimeIdentifier,
            providerKind: configuredProviderKind,
            credentialProfileId: normalizedConfiguredProfileId,
            checkedBy: checkedBy,
            now: now,
            anthropicExecutionSupported: anthropicExecutionSupported
        )
        let normalizedConfiguredRuntime = normalizedRuntimeIdentifier(configuredRuntimeIdentifier)
        if validation.status != .invalid {
            return ResolvedRuntimeSelection(
                configuredProviderKind: configuredProviderKind,
                configuredCredentialProfileId: normalizedConfiguredProfileId,
                configuredRuntimeIdentifier: normalizedConfiguredRuntime,
                configuredReasoningMode: configuredReasoningMode,
                effectiveProviderKind: configuredProviderKind,
                effectiveCredentialProfileId: normalizedConfiguredProfileId,
                effectiveRuntimeIdentifier: normalizedConfiguredRuntime,
                effectiveReasoningMode: configuredReasoningMode,
                validation: validation,
                fallbackApplied: false
            )
        }

        if let lastKnownGoodRuntime,
           (lastKnownGoodRuntime.providerKind ?? .openAI) == configuredProviderKind {
            let fallbackProviderKind = lastKnownGoodRuntime.providerKind ?? .openAI
            let fallbackCredentialProfileId = lastKnownGoodRuntime.credentialProfileId
                ?? fallbackProviderKind.defaultCredentialProfileId
            let fallback = RuntimeFallbackRecord(
                configuredProviderKind: configuredProviderKind,
                configuredCredentialProfileId: normalizedConfiguredProfileId,
                configuredRuntimeIdentifier: normalizedConfiguredRuntime,
                configuredReasoningMode: configuredReasoningMode,
                fallbackProviderKind: fallbackProviderKind,
                fallbackCredentialProfileId: fallbackCredentialProfileId,
                fallbackRuntimeIdentifier: lastKnownGoodRuntime.runtimeIdentifier,
                fallbackReasoningMode: lastKnownGoodRuntime.reasoningMode,
                reasonCategory: validation.category,
                reasonSummary: validation.summary,
                occurredAt: now
            )
            return ResolvedRuntimeSelection(
                configuredProviderKind: configuredProviderKind,
                configuredCredentialProfileId: normalizedConfiguredProfileId,
                configuredRuntimeIdentifier: normalizedConfiguredRuntime,
                configuredReasoningMode: configuredReasoningMode,
                effectiveProviderKind: fallbackProviderKind,
                effectiveCredentialProfileId: fallbackCredentialProfileId,
                effectiveRuntimeIdentifier: lastKnownGoodRuntime.runtimeIdentifier,
                effectiveReasoningMode: lastKnownGoodRuntime.reasoningMode,
                validation: validation,
                fallbackApplied: true,
                fallback: fallback
            )
        }

        return ResolvedRuntimeSelection(
            configuredProviderKind: configuredProviderKind,
            configuredCredentialProfileId: normalizedConfiguredProfileId,
            configuredRuntimeIdentifier: normalizedConfiguredRuntime,
            configuredReasoningMode: configuredReasoningMode,
            effectiveProviderKind: configuredProviderKind,
            effectiveCredentialProfileId: normalizedConfiguredProfileId,
            effectiveRuntimeIdentifier: normalizedConfiguredRuntime,
            effectiveReasoningMode: configuredReasoningMode,
            validation: validation,
            fallbackApplied: false
        )
    }

    private func applyingRuntimeResolution(
        _ resolution: ResolvedRuntimeSelection,
        to settings: PMRuntimeSettings,
        updateSource: PMRuntimeSettingsUpdateSource,
        updatedBy: String,
        now: Date
    ) -> PMRuntimeSettings {
        var updated = settings
        updated.settingsId = PMRuntimeSettings.singletonID
        updated.providerKind = resolution.configuredProviderKind
        updated.credentialProfileId = resolution.configuredCredentialProfileId
        updated.runtimeIdentifier = normalizedRuntimeIdentifier(settings.runtimeIdentifier)
        updated.updatedBy = normalizedRuntimeUpdatedBy(updatedBy)
        updated.validationStatus = resolution.validation
        if resolution.fallbackApplied {
            updated.lastFallback = resolution.fallback
        } else {
            updated.lastFallback = nil
            if resolution.validation.status == .valid {
                updated.lastKnownGoodRuntime = LastKnownGoodRuntimeRecord(
                    providerKind: resolution.effectiveProviderKind,
                    credentialProfileId: resolution.effectiveCredentialProfileId,
                    runtimeIdentifier: resolution.effectiveRuntimeIdentifier,
                    reasoningMode: resolution.effectiveReasoningMode,
                    verifiedAt: now,
                    summary: "Resolved successfully for PM runtime execution."
                )
            }
        }
        updated.updateSource = updateSource
        return updated
    }

