    private func makeStrategyChangePortfolioContextSnapshot(
        now: Date
    ) async -> PMStrategyChangePortfolioContextSnapshot {
        let snapshot = await store.snapshot()
        let exposures = snapshot.positions.compactMap { row -> (symbol: String, marketValue: Double, isShort: Bool)? in
            let marketValue = abs(strategyChangeDoubleValue(row.marketValue) ?? 0)
            guard marketValue > 0 else {
                return nil
            }
            return (
                symbol: row.symbol.trimmingCharacters(in: .whitespacesAndNewlines),
                marketValue: marketValue,
                isShort: row.isShort
            )
        }

        let grossExposure = exposures.reduce(0) { partial, exposure in
            partial + exposure.marketValue
        }
        let longExposure = exposures.reduce(0) { partial, exposure in
            partial + (exposure.isShort ? 0 : exposure.marketValue)
        }
        let shortExposure = exposures.reduce(0) { partial, exposure in
            partial + (exposure.isShort ? exposure.marketValue : 0)
        }
        let netExposure = longExposure - shortExposure
        let longWeight = grossExposure > 0 ? longExposure / grossExposure : 0
        let shortWeight = grossExposure > 0 ? shortExposure / grossExposure : 0
        let netWeight = grossExposure > 0 ? netExposure / grossExposure : 0
        let largestExposure = exposures.max { lhs, rhs in
            if lhs.marketValue == rhs.marketValue {
                return lhs.symbol < rhs.symbol
            }
            return lhs.marketValue < rhs.marketValue
        }

        return PMStrategyChangePortfolioContextSnapshot(
            positionCount: snapshot.positions.count,
            grossExposure: grossExposure,
            netExposure: netExposure,
            longExposure: longExposure,
            shortExposure: shortExposure,
            longWeight: longWeight,
            shortWeight: shortWeight,
            netWeight: netWeight,
            largestPositionSymbol: largestExposure?.symbol.isEmpty == false ? largestExposure?.symbol : nil,
            largestPositionWeight: largestExposure.map { grossExposure > 0 ? $0.marketValue / grossExposure : 0 },
            capturedAt: now
        )
    }

