        let now = nowDate()
        let updatedCandidate = AnalystStrategyFollowUpCandidateRecord(
            candidateId: candidate.candidateId,
            implicationId: candidate.implicationId,
            pmId: candidate.pmId,
            followUpKind: candidate.followUpKind,
