    private func strategyChangeDoubleValue(_ raw: String?) -> Double? {
        guard let trimmed = raw?.trimmingCharacters(in: .whitespacesAndNewlines),
              trimmed.isEmpty == false else {
            return nil
        }
        return Double(trimmed)
    }

    private func validatedPMApprovalRequest(_ approvalRequest: PMApprovalRequest) throws -> PMApprovalRequest {
        let pmID = approvalRequest.pmId.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !pmID.isEmpty else {
            throw PMApprovalRequestValidationError.pmIdRequired
        }

        let subject = approvalRequest.subject.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !subject.isEmpty else {
            throw PMApprovalRequestValidationError.subjectRequired
        }

        let rationale = approvalRequest.rationale.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !rationale.isEmpty else {
            throw PMApprovalRequestValidationError.rationaleRequired
        }

        var updated = approvalRequest
        updated.pmId = pmID
        updated.subject = subject
        updated.rationale = rationale
        updated.requestedActionSummary = trimmedOptionalDecisionText(updated.requestedActionSummary)
        updated.approvedNextStepSummary = trimmedOptionalDecisionText(updated.approvedNextStepSummary)
        updated.rejectedNextStepSummary = trimmedOptionalDecisionText(updated.rejectedNextStepSummary)
        updated.reviewedNextStepSummary = trimmedOptionalDecisionText(updated.reviewedNextStepSummary)
        updated.sourceCommunicationMessageId = trimmedOptionalDecisionText(updated.sourceCommunicationMessageId)
        updated.sourceAnalystStrategyFollowUpCandidateId = trimmedOptionalDecisionText(updated.sourceAnalystStrategyFollowUpCandidateId)
        updated.sourceAnalystStrategyImplicationId = trimmedOptionalDecisionText(updated.sourceAnalystStrategyImplicationId)
        updated.sourceAnalystMemoId = trimmedOptionalDecisionText(updated.sourceAnalystMemoId)
        updated.sourceAnalystEvidenceBundleId = trimmedOptionalDecisionText(updated.sourceAnalystEvidenceBundleId)
        updated.resultingStrategyBriefId = trimmedOptionalDecisionText(updated.resultingStrategyBriefId)
        updated.liveOrderReview = normalizedLiveOrderReviewPayload(updated.liveOrderReview)
        if updated.requestType != .liveOrderReview {
            updated.liveOrderReview = nil
            updated.liveOrderExecutionLifecycleState = nil
        }
        updated.ownerAcknowledgedBy = trimmedOptionalDecisionText(updated.ownerAcknowledgedBy)
        if updated.ownerResponse == nil {
            updated.ownerRespondedAt = nil
        } else if updated.status == .pending {
            updated.status = .resolved
        }
        if updated.status != .resolved || updated.ownerResponse != .approved {
            if updated.ownerResponse == .rejected
                || updated.ownerResponse == .reviewed
                || updated.status == .withdrawn
                || updated.status == .stale {
                updated.lastExecutionRoutingAssessment = nil
            }
            updated.liveOrderExecutionLifecycleState = nil
            updated.paperPortfolioExecutionPendingState = nil
            updated.paperPortfolioExecutionLifecycleState = nil
        } else if var pendingState = updated.paperPortfolioExecutionPendingState {
            pendingState.missingPriceSymbols = Array(
                MarketDataSubscriptionSet.normalized(pendingState.missingPriceSymbols)
            ).sorted()
            pendingState.marketDataSubscriptionSymbols = Array(
                MarketDataSubscriptionSet.normalized(pendingState.marketDataSubscriptionSymbols)
            ).sorted()
            pendingState.lastBlockerSummary = pendingState.lastBlockerSummary
                .trimmingCharacters(in: .whitespacesAndNewlines)
            pendingState.lastBlockerDetail = pendingState.lastBlockerDetail
                .trimmingCharacters(in: .whitespacesAndNewlines)
            if pendingState.missingPriceSymbols.isEmpty
                || pendingState.lastBlockerSummary.isEmpty
                || pendingState.lastBlockerDetail.isEmpty {
                updated.paperPortfolioExecutionPendingState = nil
            } else {
                updated.paperPortfolioExecutionPendingState = pendingState
            }
        }
        if var lifecycleState = updated.paperPortfolioExecutionLifecycleState {
            lifecycleState.summary = lifecycleState.summary
                .trimmingCharacters(in: .whitespacesAndNewlines)
            lifecycleState.detail = lifecycleState.detail
                .trimmingCharacters(in: .whitespacesAndNewlines)
            lifecycleState.targetSymbols = Array(
                MarketDataSubscriptionSet.normalized(lifecycleState.targetSymbols)
            ).sorted()
            lifecycleState.missingPriceSymbols = Array(
                MarketDataSubscriptionSet.normalized(lifecycleState.missingPriceSymbols)
            ).sorted()
            lifecycleState.orderAttemptCount = max(0, lifecycleState.orderAttemptCount)
            lifecycleState.acceptedOrderAttemptCount = max(0, lifecycleState.acceptedOrderAttemptCount)
            lifecycleState.failedOrderAttemptCount = max(0, lifecycleState.failedOrderAttemptCount)
            if lifecycleState.summary.isEmpty {
                updated.paperPortfolioExecutionLifecycleState = nil
            } else {
                updated.paperPortfolioExecutionLifecycleState = lifecycleState
            }
        }
        if var liveState = updated.liveOrderExecutionLifecycleState {
            liveState.summary = liveState.summary.trimmingCharacters(in: .whitespacesAndNewlines)
            liveState.detail = liveState.detail.trimmingCharacters(in: .whitespacesAndNewlines)
            liveState.orderId = trimmedOptionalDecisionText(liveState.orderId)
            liveState.symbol = liveState.symbol.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
            liveState.quantity = liveState.quantity.flatMap { $0 > 0 ? $0 : nil }
            liveState.filledQuantity = trimmedOptionalDecisionText(liveState.filledQuantity)
            liveState.averageFillPrice = trimmedOptionalDecisionText(liveState.averageFillPrice)
            liveState.positionQuantity = trimmedOptionalDecisionText(liveState.positionQuantity)
            liveState.openOrderStatus = trimmedOptionalDecisionText(liveState.openOrderStatus)
            liveState.completionFollowThroughMessageId = trimmedOptionalDecisionText(liveState.completionFollowThroughMessageId)
            if liveState.summary.isEmpty || liveState.symbol.isEmpty {
                updated.liveOrderExecutionLifecycleState = nil
            } else {
                updated.liveOrderExecutionLifecycleState = liveState
            }
        }
        return updated
    }

    private func normalizedLiveOrderReviewPayload(
        _ payload: PMLiveOrderReviewPayload?
    ) -> PMLiveOrderReviewPayload? {
        guard var payload else {
            return nil
        }
        let symbol = payload.symbol
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .uppercased()
        guard symbol.isEmpty == false else {
            return nil
        }
        payload.symbol = symbol
        payload.quantity = payload.quantity.flatMap { $0 > 0 ? $0 : nil }
        payload.notionalAmount = payload.notionalAmount.flatMap { $0 > 0 ? $0 : nil }
        payload.limitPrice = payload.limitPrice.flatMap { $0 > 0 ? $0 : nil }
        payload.instructionSummary = trimmedOptionalDecisionText(payload.instructionSummary)
        return payload
    }

    private func ensureTelegramPMUserCommunicationSession(
        chatId: String,
        participantId: String?,
        participantDisplayName: String?,
        pmId: String?,
        updatedAt: Date,
        source: AuditEventSource
    ) async throws -> PMCommunicationSession {
        let sessionID = telegramSessionID(chatId: chatId)
        let resolvedPMID = try await resolvedConversationPMID(
            requestedPMID: pmId,
            source: source
        )
        let resolvedParticipantDisplayName = participantDisplayName?
            .trimmingCharacters(in: .whitespacesAndNewlines)
        let resolvedParticipantId = participantId?.trimmingCharacters(in: .whitespacesAndNewlines)

        if let existing = try await pmCommunicationSessionStore.get(id: sessionID) {
            let refreshed = PMCommunicationSession(
                sessionId: existing.sessionId,
                channel: .telegram,
                externalConversationId: chatId,
                pmId: existing.pmId ?? resolvedPMID,
                participantId: resolvedParticipantId ?? existing.participantId,
                participantDisplayName: resolvedParticipantDisplayName?.isEmpty == false
                    ? resolvedParticipantDisplayName
                    : existing.participantDisplayName,
                status: .active,
                createdAt: existing.createdAt,
                updatedAt: max(existing.updatedAt, updatedAt)
            )
            return try await upsertPMCommunicationSession(refreshed, source: source)
        }

        let session = PMCommunicationSession(
            sessionId: sessionID,
            channel: .telegram,
            externalConversationId: chatId,
            pmId: resolvedPMID,
            participantId: resolvedParticipantId,
            participantDisplayName: resolvedParticipantDisplayName?.isEmpty == false
                ? resolvedParticipantDisplayName
                : "Telegram User",
            status: .active,
            createdAt: updatedAt,
            updatedAt: updatedAt
        )
        return try await upsertPMCommunicationSession(session, source: source)
    }

    private struct TelegramPMConversationResolution {
        let request: PMApprovalRequest?
        let requestMemo: PMApprovalRequestMemoPresentation?
        let decision: PMDecisionRecord?
        let decisionMemo: PMDecisionMemoPresentation?
        let ambiguousApprovalRequest: Bool
    }

    private struct TelegramDecisionTransportContext {
        let memo: PMDecisionMemoPresentation
        let recentNewsWakeUp: RecentNewsWakeUpPresentation
        let portfolioRiskWakeUp: PortfolioRiskWakeUpPresentation
    }

    private struct TelegramInboundIntentOutcome {
        let recordedApprovalResponse: Bool
        let sentClarificationReply: Bool
    }

    private func handleTelegramInboundIntent(
        session: PMCommunicationSession,
        message: PMCommunicationMessage,
        source: AuditEventSource
    ) async throws -> TelegramInboundIntentOutcome? {
        guard let intent = parseTelegramPMInboundIntent(message.body) else {
            return nil
        }

        let resolution = try await resolveTelegramPMConversation(
            session: session,
            sourceMessage: message
        )

        switch intent {
        case .ownerApprovalResponse(let response):
            guard resolution.ambiguousApprovalRequest == false else {
                _ = try await createPMCommunicationMessage(
                    sessionId: session.sessionId,
                    senderRole: .pm,
                    senderId: session.pmId,
                    body: makeTelegramAmbiguousApprovalGuidance(),
                    replyToMessageId: message.messageId,
                    source: source
                )
                return TelegramInboundIntentOutcome(
                    recordedApprovalResponse: false,
                    sentClarificationReply: true
                )
            }
            guard let request = resolution.request,
                  request.status == .pending else {
                // Without a resolvable pending approval, even an exact approval word is normal PM/User
                // conversation. Let model-backed synthesis interpret the owner turn with full context.
                return nil
            }
            if shouldBlockTelegramLiveExecutionApproval(response: response, request: request, session: session) {
                _ = try await createPMCommunicationMessage(
                    sessionId: session.sessionId,
                    senderRole: .pm,
                    senderId: request.pmId,
                    body: makeTelegramLiveOrderReviewApprovalBlockedAcknowledgement(),
                    replyToMessageId: message.messageId,
                    source: source
                )
                await store.publishDiagnostic(
                    "telegram live-order approval blocked approval_request=\(shortOrderID(request.approvalRequestId))",
                    source: source,
                    action: "telegram_live_order_approval_blocked"
                )
                return TelegramInboundIntentOutcome(
                    recordedApprovalResponse: false,
                    sentClarificationReply: true
                )
            }

            let updatedRequest = try await respondToPMApprovalRequest(
                requestId: request.approvalRequestId,
                response: response,
                source: source
            )
            let acknowledgement = makeTelegramApprovalResponseAcknowledgement(
                response: response,
                request: updatedRequest,
                approvalMemo: resolution.requestMemo
            )
            _ = try await createPMCommunicationMessage(
                sessionId: session.sessionId,
                senderRole: .pm,
                senderId: updatedRequest.pmId,
                body: acknowledgement,
                replyToMessageId: message.messageId,
                source: source
            )
            return TelegramInboundIntentOutcome(
                recordedApprovalResponse: true,
                sentClarificationReply: true
            )
        }
    }

    private func shouldBlockTelegramLiveExecutionApproval(
        response: PMApprovalRequestOwnerResponse,
        request: PMApprovalRequest,
        session: PMCommunicationSession
    ) -> Bool {
        guard response == .approved,
              request.requestType == .liveOrderReview else {
            return false
        }
        return session.channel == .telegram || session.channel == .mockTelegram
    }

    private func resolveTelegramPMConversation(
        session: PMCommunicationSession,
        sourceMessage _: PMCommunicationMessage
    ) async throws -> TelegramPMConversationResolution {
        let messages = try await listPMCommunicationMessages()
        let requests = try await listPMApprovalRequests()
            .filter { $0.status == .pending && isExercisePMApprovalRequest($0) == false }
        let decisions = try await listPMDecisions()
            .filter { $0.status == .active && isExercisePMDecision($0) == false }
        let delegations = try await listPMDelegations()
        let tasks = try await listAnalystTasks()
        let findings = try await listAnalystFindings()
        let memos = try await listAnalystMemos()
        let strategyBrief = try await getPortfolioStrategyBrief()

        let decisionsByID = Dictionary(uniqueKeysWithValues: decisions.map { ($0.decisionId, $0) })
        let delegationsByID = Dictionary(uniqueKeysWithValues: delegations.map { ($0.delegationId, $0) })
        let tasksByID = Dictionary(uniqueKeysWithValues: tasks.map { ($0.taskId, $0) })
        let findingsByID = Dictionary(uniqueKeysWithValues: findings.map { ($0.findingId, $0) })

        let requestMatches = requests.map { request -> (PMApprovalRequest, Int) in
            (request, telegramApprovalRequestMatchScore(request, sessionId: session.sessionId, messages: messages, decisionsByID: decisionsByID))
        }
        let positiveMatches = requestMatches
            .filter { $0.1 > 0 }
            .sorted { lhs, rhs in
                if lhs.1 == rhs.1 {
                    if lhs.0.updatedAt == rhs.0.updatedAt {
                        return lhs.0.approvalRequestId < rhs.0.approvalRequestId
                    }
                    return lhs.0.updatedAt > rhs.0.updatedAt
                }
                return lhs.1 > rhs.1
            }

        let resolvedRequest: PMApprovalRequest?
        let ambiguousApprovalRequest: Bool
        if let first = positiveMatches.first {
            if positiveMatches.count > 1, positiveMatches[1].1 == first.1 {
                resolvedRequest = nil
                ambiguousApprovalRequest = true
            } else {
                resolvedRequest = first.0
                ambiguousApprovalRequest = false
            }
        } else if requests.count == 1 {
            resolvedRequest = requests.first
            ambiguousApprovalRequest = false
        } else {
            resolvedRequest = nil
            ambiguousApprovalRequest = requests.count > 1
        }

        let resolvedDecision: PMDecisionRecord?
        if let resolvedRequest {
            resolvedDecision = resolvedRequest.decisionId.flatMap { decisionsByID[$0] }
        } else {
            let decisionMatches = decisions.map { decision -> (PMDecisionRecord, Int) in
                (decision, telegramDecisionMatchScore(decision, sessionId: session.sessionId, messages: messages))
            }
            let positiveDecisionMatches = decisionMatches
                .filter { $0.1 > 0 }
                .sorted { lhs, rhs in
                    if lhs.1 == rhs.1 {
                        if lhs.0.updatedAt == rhs.0.updatedAt {
                            return lhs.0.decisionId < rhs.0.decisionId
                        }
                        return lhs.0.updatedAt > rhs.0.updatedAt
                    }
                    return lhs.1 > rhs.1
                }
            if let first = positiveDecisionMatches.first {
                resolvedDecision = first.0
            } else if decisions.count == 1 {
                resolvedDecision = decisions.first
            } else {
                resolvedDecision = nil
            }
        }

        let linkedDelegation = (resolvedRequest?.delegationId ?? resolvedDecision?.delegationId)
            .flatMap { delegationsByID[$0] }
        let linkedTask = (linkedDelegation?.taskId ?? resolvedDecision?.taskId).flatMap { tasksByID[$0] }
        let linkedFinding = (resolvedRequest?.findingId
            ?? linkedDelegation?.linkedFindingIDs.last
            ?? resolvedDecision?.findingId)
            .flatMap { findingsByID[$0] }
        let linkedMemo = memos
            .filter { memo in
                if let delegationID = linkedDelegation?.delegationId, memo.delegationId == delegationID {
                    return true
                }
                if let taskID = linkedTask?.taskId, memo.taskId == taskID {
                    return true
                }
                if let findingID = linkedFinding?.findingId, memo.findingId == findingID {
                    return true
                }
                return false
            }
            .sorted { lhs, rhs in
                if lhs.updatedAt == rhs.updatedAt {
                    return lhs.memoId < rhs.memoId
                }
                return lhs.updatedAt > rhs.updatedAt
            }
            .first

        let resolvedLinkedCommunicationMessage: PMCommunicationMessage?
        if let request = resolvedRequest {
            resolvedLinkedCommunicationMessage = linkedCommunicationMessage(
                for: request,
                messages: messages
            )
        } else if let decision = resolvedDecision {
            resolvedLinkedCommunicationMessage = linkedCommunicationMessage(
                for: decision,
                messages: messages
            )
        } else {
            resolvedLinkedCommunicationMessage = nil
        }

        let linkedDelegationObservability = linkedDelegation.map { delegation in
            makePMDelegationObservabilitySummary(
                delegation: delegation,
                charterDefaultRuntimePolicy: nil,
                task: linkedTask
            )
        }

        let requestMemo = resolvedRequest.map {
            makePMApprovalRequestMemoPresentation(
                request: $0,
                linkedDecision: resolvedDecision,
                linkedDelegation: linkedDelegation,
                linkedDelegationObservability: linkedDelegationObservability,
                linkedTask: linkedTask,
                linkedFinding: linkedFinding,
                linkedCommunicationMessage: resolvedLinkedCommunicationMessage,
                linkedMemo: linkedMemo,
                strategyBrief: strategyBrief
            )
        }

        let decisionMemo = resolvedDecision.map {
            makePMDecisionMemoPresentation(
                decision: $0,
                linkedApprovalRequest: resolvedRequest,
                linkedDelegation: linkedDelegation,
                linkedDelegationObservability: linkedDelegationObservability,
                linkedTask: linkedTask,
                linkedFinding: linkedFinding,
                linkedCommunicationMessage: resolvedLinkedCommunicationMessage,
                linkedMemo: linkedMemo,
                strategyBrief: strategyBrief
            )
        }

        return TelegramPMConversationResolution(
            request: resolvedRequest,
            requestMemo: requestMemo,
            decision: resolvedDecision,
            decisionMemo: decisionMemo,
            ambiguousApprovalRequest: ambiguousApprovalRequest
        )
    }

    private func loadTelegramApprovalMemoPresentation(
        request: PMApprovalRequest
    ) async throws -> PMApprovalRequestMemoPresentation {
        let decisions = try await listPMDecisions()
        let delegations = try await listPMDelegations()
        let tasks = try await listAnalystTasks()
        let findings = try await listAnalystFindings()
        let memos = try await listAnalystMemos()
        let messages = try await listPMCommunicationMessages()
        let strategyBrief = try await getPortfolioStrategyBrief()

        let decisionsByID = Dictionary(uniqueKeysWithValues: decisions.map { ($0.decisionId, $0) })
        let delegationsByID = Dictionary(uniqueKeysWithValues: delegations.map { ($0.delegationId, $0) })
        let tasksByID = Dictionary(uniqueKeysWithValues: tasks.map { ($0.taskId, $0) })
        let findingsByID = Dictionary(uniqueKeysWithValues: findings.map { ($0.findingId, $0) })

        let linkedDecision = request.decisionId.flatMap { decisionsByID[$0] }
        let linkedDelegation = request.delegationId.flatMap { delegationsByID[$0] }
        let linkedTask = linkedDelegation?.taskId.flatMap { tasksByID[$0] }
        let linkedFinding = request.findingId.flatMap { findingsByID[$0] }
            ?? linkedDelegation?.linkedFindingIDs.last.flatMap { findingsByID[$0] }
        let linkedMemo = memos
            .filter { memo in
                if let delegationID = linkedDelegation?.delegationId, memo.delegationId == delegationID {
                    return true
                }
                if let taskID = linkedTask?.taskId, memo.taskId == taskID {
                    return true
                }
                if let findingID = linkedFinding?.findingId, memo.findingId == findingID {
                    return true
                }
                return false
            }
            .sorted { lhs, rhs in
                if lhs.updatedAt == rhs.updatedAt {
                    return lhs.memoId < rhs.memoId
                }
                return lhs.updatedAt > rhs.updatedAt
            }
            .first
        let linkedCommunication = linkedCommunicationMessage(for: request, messages: messages)
        let linkedDelegationObservability = linkedDelegation.map { delegation in
            makePMDelegationObservabilitySummary(
                delegation: delegation,
                charterDefaultRuntimePolicy: nil,
                task: linkedTask
            )
        }

        return makePMApprovalRequestMemoPresentation(
            request: request,
            linkedDecision: linkedDecision,
            linkedDelegation: linkedDelegation,
            linkedDelegationObservability: linkedDelegationObservability,
            linkedTask: linkedTask,
            linkedFinding: linkedFinding,
            linkedCommunicationMessage: linkedCommunication,
            linkedMemo: linkedMemo,
            strategyBrief: strategyBrief
        )
    }

    private func loadTelegramDecisionTransportContext(
        decision: PMDecisionRecord
    ) async throws -> TelegramDecisionTransportContext {
        let delegations = try await listPMDelegations()
        let tasks = try await listAnalystTasks()
        let findings = try await listAnalystFindings()
        let memos = try await listAnalystMemos()
        let messages = try await listPMCommunicationMessages()
        let strategyBrief = try await getPortfolioStrategyBrief()
        let snapshot = await store.snapshot()

        let delegationsByID = Dictionary(uniqueKeysWithValues: delegations.map { ($0.delegationId, $0) })
        let tasksByID = Dictionary(uniqueKeysWithValues: tasks.map { ($0.taskId, $0) })
        let findingsByID = Dictionary(uniqueKeysWithValues: findings.map { ($0.findingId, $0) })

        let linkedDelegation = decision.delegationId.flatMap { delegationsByID[$0] }
        let linkedTask = linkedDelegation?.taskId.flatMap { tasksByID[$0] }
            ?? decision.taskId.flatMap { tasksByID[$0] }
        let linkedFinding = decision.findingId.flatMap { findingsByID[$0] }
            ?? linkedDelegation?.linkedFindingIDs.last.flatMap { findingsByID[$0] }
        let linkedMemo = memos
            .filter { memo in
                if let delegationID = linkedDelegation?.delegationId, memo.delegationId == delegationID {
                    return true
                }
                if let taskID = linkedTask?.taskId, memo.taskId == taskID {
                    return true
                }
                if let findingID = linkedFinding?.findingId, memo.findingId == findingID {
                    return true
                }
                return false
            }
            .sorted { lhs, rhs in
                if lhs.updatedAt == rhs.updatedAt {
                    return lhs.memoId < rhs.memoId
                }
                return lhs.updatedAt > rhs.updatedAt
            }
            .first
        let linkedCommunication = linkedCommunicationMessage(for: decision, messages: messages)
        let linkedDelegationObservability = linkedDelegation.map { delegation in
            makePMDelegationObservabilitySummary(
                delegation: delegation,
                charterDefaultRuntimePolicy: nil,
                task: linkedTask
            )
        }

        let memo = makePMDecisionMemoPresentation(
            decision: decision,
            linkedApprovalRequest: nil,
            linkedDelegation: linkedDelegation,
            linkedDelegationObservability: linkedDelegationObservability,
            linkedTask: linkedTask,
            linkedFinding: linkedFinding,
            linkedCommunicationMessage: linkedCommunication,
            linkedMemo: linkedMemo,
            strategyBrief: strategyBrief
        )
        let recentNewsWakeUp = makeRecentNewsWakeUpPresentation(
            decision: decision,
            linkedTask: linkedTask,
            linkedMemo: linkedMemo,
            positions: snapshot.positions,
            watchlistSymbols: snapshot.watchlistSymbols,
            strategyBrief: strategyBrief
        )
        let portfolioRiskWakeUp = makePortfolioRiskWakeUpPresentation(
            decision: decision,
            linkedTask: linkedTask,
            linkedMemo: linkedMemo,
            positions: snapshot.positions,
            watchlistSymbols: snapshot.watchlistSymbols,
            strategyBrief: strategyBrief
        )

        return TelegramDecisionTransportContext(
            memo: memo,
            recentNewsWakeUp: recentNewsWakeUp,
            portfolioRiskWakeUp: portfolioRiskWakeUp
        )
    }

    private func telegramApprovalRequestMatchScore(
        _ request: PMApprovalRequest,
        sessionId: String,
        messages: [PMCommunicationMessage],
        decisionsByID: [String: PMDecisionRecord]
    ) -> Int {
        if let messageID = request.sourceCommunicationMessageId,
           messages.contains(where: { $0.messageId == messageID && $0.sessionId == sessionId }) {
            return 3
        }
        if messages.contains(where: {
            $0.sessionId == sessionId
                && $0.promotion?.targetType == .approvalRequest
                && $0.promotion?.targetId == request.approvalRequestId
        }) {
            return 3
        }
        if let decisionID = request.decisionId,
           let decision = decisionsByID[decisionID],
           telegramDecisionMatchScore(decision, sessionId: sessionId, messages: messages) > 0 {
            return 2
        }
        return 0
    }

    private func telegramDecisionMatchScore(
        _ decision: PMDecisionRecord,
        sessionId: String,
        messages: [PMCommunicationMessage]
    ) -> Int {
        if let messageID = decision.sourceCommunicationMessageId,
           messages.contains(where: { $0.messageId == messageID && $0.sessionId == sessionId }) {
            return 3
        }
        if messages.contains(where: {
            $0.sessionId == sessionId
                && $0.promotion?.targetType == .decision
                && $0.promotion?.targetId == decision.decisionId
        }) {
            return 3
        }
        return 0
    }

    private func linkedCommunicationMessage(
        for request: PMApprovalRequest,
        messages: [PMCommunicationMessage]
    ) -> PMCommunicationMessage? {
        if let messageID = request.sourceCommunicationMessageId {
            return messages.first(where: { $0.messageId == messageID })
        }
        return messages.first(where: {
            $0.promotion?.targetType == .approvalRequest && $0.promotion?.targetId == request.approvalRequestId
        })
    }

    private func linkedCommunicationMessage(
        for decision: PMDecisionRecord,
        messages: [PMCommunicationMessage]
    ) -> PMCommunicationMessage? {
        if let messageID = decision.sourceCommunicationMessageId {
            return messages.first(where: { $0.messageId == messageID })
        }
        return messages.first(where: {
            $0.promotion?.targetType == .decision && $0.promotion?.targetId == decision.decisionId
        })
    }

    private func sendTelegramMessageForPMCommunication(
        session: PMCommunicationSession,
        message: PMCommunicationMessage,
        delivery: TelegramPMDeliveryBehavior,
        source: AuditEventSource
    ) async throws -> TelegramBotSentMessage {
        guard let chatId = session.externalConversationId?.trimmingCharacters(in: .whitespacesAndNewlines),
              chatId.isEmpty == false else {
            throw TelegramBridgeError.telegramSessionNotBound(sessionId: session.sessionId)
        }
        guard let botToken = telegramBotToken(for: .outbound, throttleMissingForPolling: false) else {
            throw TelegramBridgeError.missingBotToken
        }
        let existingState = await bootstrappedTelegramOwnerRouteAllowlist(await telegramBridgeStateStore.load())
        if let allowlistedOwnerChatId = resolvedTelegramOwnerAllowlistedChatId(existingState),
           allowlistedOwnerChatId != chatId {
            throw TelegramBridgeError.proactiveSendSuppressed(
                reason: "Telegram send blocked because this chat is not the allowlisted owner route."
            )
        }

        let telegramText = telegramTransportSafePMMessageBody(message.body)
        let sentMessage = try await telegramBotService.sendMessage(
            botToken: botToken,
            chatID: chatId,
            text: telegramText,
            replyToMessageID: telegramReplyMessageId(
                for: message.replyToMessageId,
                session: session
            ),
            disableNotification: delivery.disableNotification
        )

        var state = await telegramBridgeStateStore.load()
        state.lastBoundChatId = chatId
        state.lastBoundSessionId = session.sessionId
        state.lastBoundParticipantLabel = session.participantDisplayName
        state.lastOutboundAt = sentMessage.sentAt
        state.lastOutboundWakeUpClass = delivery.wakeUpClass
        state.lastOutboundSilent = delivery.disableNotification
        state.lastOutboundReason = delivery.reason
        state.lastOutboundSummary = makeTelegramOutboundSummary(
            participantLabel: session.participantDisplayName,
            delivery: delivery
        )
        _ = try await telegramBridgeStateStore.save(state)
        await publishPMPersistenceDiagnostics()
        await store.publishDiagnostic(
            "telegram bridge sent outbound message session=\(shortOrderID(session.sessionId)) channel=telegram wake_up=\(delivery.wakeUpClass.rawValue) silent=\(delivery.disableNotification)",
            source: source,
            action: "telegram_bridge_send"
        )
        return sentMessage
    }

    private func telegramTransportSafePMMessageBody(_ body: String) -> String {
        let sanitized = sanitizedOwnerFacingPMFollowThroughBody(body)
        let base = sanitized.isEmpty
            ? "I have an app-owned PM update, but the transport-safe summary was empty. Please open Command Center or PM Inbox for the full detail."
            : sanitized
        let limit = 3_500
        guard base.count > limit else {
            return base
        }
        let prefix = boundedConversationText(base, limit: limit - 96)
        return "\(prefix)\n\nFull detail is available in Command Center / PM Inbox."
            .trimmingCharacters(in: .whitespacesAndNewlines)
    }

    private func makeTelegramOutboundSummary(
        participantLabel: String?,
        delivery: TelegramPMDeliveryBehavior
    ) -> String {
        let participant = participantLabel ?? "Telegram chat"
        let mode: String
        switch delivery.wakeUpClass {
        case .approvalRequired:
            mode = "Sent approval-required Telegram wake-up"
        case .importantWakeUp:
            mode = "Sent important Telegram wake-up"
        case .quietInfo:
            mode = "Sent quiet Telegram informational update"
        case .conversationReply:
            mode = "Sent Telegram conversation reply"
        case .doNotSendProactively:
            mode = "Suppressed proactive Telegram send"
        }

        var parts = ["\(mode) to \(participant)"]
        parts.append(delivery.disableNotification ? "silent" : "normal alert")
        if let reason = delivery.reason, reason.isEmpty == false {
            parts.append(reason)
        }
        return parts.joined(separator: " · ")
    }

    private func telegramReplyMessageId(
        for replyToMessageId: String?,
        session: PMCommunicationSession
    ) -> Int? {
        guard session.channel == .telegram || session.channel == .mockTelegram else {
            return nil
        }
        guard let replyToMessageId else { return nil }
        let components = replyToMessageId.split(separator: "-")
        guard let suffix = components.last, let value = Int(suffix) else {
            return nil
        }
        return value
    }

    private func telegramSessionID(chatId: String) -> String {
        "pm-user-telegram-chat-\(telegramIdentifierComponent(chatId))"
    }

    private func telegramInboundMessageID(chatId: String, telegramMessageId: Int) -> String {
        "pm-telegram-message-\(telegramIdentifierComponent(chatId))-\(telegramMessageId)"
    }

    private func bootstrappedTelegramOwnerRouteAllowlist(_ state: TelegramBridgeState) async -> TelegramBridgeState {
        var updated = state
        if resolvedTelegramOwnerAllowlistedChatId(state) == nil,
           let lastBoundChatId = state.lastBoundChatId?.trimmingCharacters(in: .whitespacesAndNewlines),
           lastBoundChatId.isEmpty == false {
            updated.allowlistedOwnerChatId = lastBoundChatId
            updated.allowlistedOwnerSessionId = state.lastBoundSessionId ?? telegramSessionID(chatId: lastBoundChatId)
            updated.allowlistedOwnerParticipantLabel = state.lastBoundParticipantLabel
        } else if resolvedTelegramOwnerAllowlistedChatId(state) == nil,
                  let recovered = try? await recoverTelegramOwnerRouteFromCommunicationSessions() {
            updated.allowlistedOwnerChatId = recovered.chatId
            updated.allowlistedOwnerSessionId = recovered.sessionId
            updated.allowlistedOwnerParticipantLabel = recovered.participantLabel
        } else if let allowlistedOwnerChatId = resolvedTelegramOwnerAllowlistedChatId(state),
                  (state.allowlistedOwnerSessionId?.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty ?? true) {
            updated.allowlistedOwnerSessionId = telegramSessionID(chatId: allowlistedOwnerChatId)
        }
        return updated
    }

    private func recoverTelegramOwnerRouteFromCommunicationSessions() async throws -> (
        chatId: String,
        sessionId: String,
        participantLabel: String?
    )? {
        let sessions = try await pmCommunicationSessionStore.loadAll()
        let telegramSessions = sessions
            .filter { $0.channel == .telegram }
            .compactMap { session -> (chatId: String, sessionId: String, participantLabel: String?, updatedAt: Date)? in
                guard let chatId = session.externalConversationId?.trimmingCharacters(in: .whitespacesAndNewlines),
                      chatId.isEmpty == false else {
                    return nil
                }
                return (chatId, session.sessionId, session.participantDisplayName, session.updatedAt)
            }
            .sorted { lhs, rhs in
                if lhs.updatedAt == rhs.updatedAt {
                    return lhs.sessionId < rhs.sessionId
                }
                return lhs.updatedAt > rhs.updatedAt
            }

        guard telegramSessions.count == 1, let session = telegramSessions.first else {
            return nil
        }
        return (session.chatId, session.sessionId, session.participantLabel)
    }

    private func resolvedTelegramOwnerAllowlistedChatId(_ state: TelegramBridgeState) -> String? {
        let allowlisted = state.allowlistedOwnerChatId?
            .trimmingCharacters(in: .whitespacesAndNewlines)
        if let allowlisted, allowlisted.isEmpty == false {
            return allowlisted
        }
        let lastBound = state.lastBoundChatId?
            .trimmingCharacters(in: .whitespacesAndNewlines)
        if let lastBound, lastBound.isEmpty == false {
            return lastBound
        }
        return nil
    }

    private func telegramIdentifierComponent(_ raw: String) -> String {
        raw
            .trimmingCharacters(in: .whitespacesAndNewlines)
            .replacingOccurrences(of: "-", with: "neg-")
            .replacingOccurrences(of: " ", with: "-")
            .lowercased()
    }

    private func telegramRecoveryOffset(
        existingState: TelegramBridgeState,
        primaryUpdates: [TelegramBotUpdate]
    ) -> Int? {
        guard primaryUpdates.isEmpty else { return nil }
        guard existingState.lastBoundChatId == nil,
              existingState.lastBoundSessionId == nil else {
            return nil
        }
        return -5
    }

    private func mergeTelegramUpdates(
        primary: [TelegramBotUpdate],
        recovery: [TelegramBotUpdate]
    ) -> [TelegramBotUpdate] {
        var updatesByID: [Int: TelegramBotUpdate] = [:]
        for update in primary {
            updatesByID[update.updateId] = update
        }
        for update in recovery {
            updatesByID[update.updateId] = update
        }
        return updatesByID.values.sorted { $0.updateId < $1.updateId }
    }

    private func makeTelegramPollSummary(
        fetchedUpdateCount: Int,
        ingestedMessageCount: Int,
        duplicateUpdateCount: Int,
        skippedUnsupportedCount: Int,
        unauthorizedIgnoredCount: Int,
        approvalResponseCount: Int,
        clarificationReplyCount: Int,
        requestedOffset: Int?,
        highestFetchedUpdateId: Int?,
        webhookPresent: Bool,
        webhookCleared: Bool,
        webhookPendingUpdateCount: Int?,
        recoveryTriggered: Bool,
        recoveryOffset: Int?,
        ownerRouteAllowlisted: Bool,
        learnedChatBound: Bool
    ) -> String {
        var parts: [String] = []
        parts.append(ownerRouteAllowlisted
            ? "Telegram owner route allowlisted"
            : "Telegram owner route not allowlisted")
        if webhookPresent {
            parts.append(webhookCleared
                ? "Cleared Telegram webhook for polling mode"
                : "Telegram webhook still present during polling")
        } else {
            parts.append("Telegram webhook absent")
        }
        if let webhookPendingUpdateCount {
            parts.append("pending \(webhookPendingUpdateCount) Telegram update\(webhookPendingUpdateCount == 1 ? "" : "s")")
        }
        if let requestedOffset {
            parts.append("requested offset \(requestedOffset)")
        } else {
            parts.append("requested unbounded offset")
        }
        parts.append("Fetched \(fetchedUpdateCount) Telegram update\(fetchedUpdateCount == 1 ? "" : "s")")
        if let highestFetchedUpdateId {
            parts.append("highest update \(highestFetchedUpdateId)")
        }
        if ingestedMessageCount > 0 {
            parts.append("ingested \(ingestedMessageCount) new message\(ingestedMessageCount == 1 ? "" : "s")")
        }
        if duplicateUpdateCount > 0 {
            parts.append("ignored \(duplicateUpdateCount) duplicate update\(duplicateUpdateCount == 1 ? "" : "s")")
        }
        if skippedUnsupportedCount > 0 {
            parts.append("skipped \(skippedUnsupportedCount) non-text update\(skippedUnsupportedCount == 1 ? "" : "s")")
        }
        if unauthorizedIgnoredCount > 0 {
            parts.append("ignored \(unauthorizedIgnoredCount) unauthorized inbound message\(unauthorizedIgnoredCount == 1 ? "" : "s")")
        }
        if approvalResponseCount > 0 {
            parts.append("recorded \(approvalResponseCount) explicit approval response\(approvalResponseCount == 1 ? "" : "s")")
        }
        if clarificationReplyCount > 0 {
            parts.append("sent \(clarificationReplyCount) bounded PM reply\(clarificationReplyCount == 1 ? "" : "s")")
        }
        if recoveryTriggered, let recoveryOffset {
            parts.append("recovery poll used offset \(recoveryOffset)")
        }
        if learnedChatBound {
            parts.append("learned Telegram chat route")
        } else if fetchedUpdateCount == 0 {
            parts.append("no Telegram chat route learned yet")
        }
        return parts.joined(separator: "; ")
    }

    private func validatedPMCommunicationSession(_ session: PMCommunicationSession) throws -> PMCommunicationSession {
        let sessionID = session.sessionId.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !sessionID.isEmpty else {
            throw PMCommunicationSessionValidationError.sessionIdRequired
        }

        var updated = session
        updated.sessionId = sessionID
        updated.externalConversationId = session.externalConversationId?.trimmingCharacters(in: .whitespacesAndNewlines)
        updated.pmId = session.pmId?.trimmingCharacters(in: .whitespacesAndNewlines)
        updated.participantId = session.participantId?.trimmingCharacters(in: .whitespacesAndNewlines)
        updated.participantDisplayName = session.participantDisplayName?.trimmingCharacters(in: .whitespacesAndNewlines)
        if updated.externalConversationId?.isEmpty == true { updated.externalConversationId = nil }
        if updated.pmId?.isEmpty == true { updated.pmId = nil }
        if updated.participantId?.isEmpty == true { updated.participantId = nil }
        if updated.participantDisplayName?.isEmpty == true { updated.participantDisplayName = nil }
        return updated
    }

    private func trimmedOptionalDecisionText(_ value: String?) -> String? {
        guard let value else { return nil }
        let trimmed = value.trimmingCharacters(in: .whitespacesAndNewlines)
        return trimmed.isEmpty ? nil : trimmed
    }

    private func validatedPMConversationResolution(
        _ resolution: PMConversationResolutionState?
    ) -> PMConversationResolutionState? {
        guard var resolution else { return nil }

        resolution.workingUnderstandingSummary = trimmedOptionalDecisionText(resolution.workingUnderstandingSummary)
        resolution.ambiguitySummary = trimmedOptionalDecisionText(resolution.ambiguitySummary)
        resolution.operatingTruthSummary = trimmedOptionalDecisionText(resolution.operatingTruthSummary)
        resolution.operatingTruthBody = trimmedOptionalDecisionText(resolution.operatingTruthBody)
        resolution.durableTitle = trimmedOptionalDecisionText(resolution.durableTitle)
        resolution.durableBody = trimmedOptionalDecisionText(resolution.durableBody)
        resolution.durableTargetId = trimmedOptionalDecisionText(resolution.durableTargetId)
        resolution.sourceMessageIds = orderedUniqueStrings(resolution.sourceMessageIds)
        if resolution.operatingTruthKind == nil {
            resolution.operatingTruthKind = pmConversationOperatingTruthKind(from: resolution.instructionTargetKind)
        }
        if resolution.operatingTruthSummary == nil {
            resolution.operatingTruthSummary = resolution.workingUnderstandingSummary
        }
        if resolution.operatingTruthBody == nil {
            resolution.operatingTruthBody = resolution.operatingTruthSummary ?? resolution.durableBody
        }

        if var pendingAsk = resolution.pendingAsk {
            pendingAsk.promptSummary = trimmedOptionalDecisionText(pendingAsk.promptSummary) ?? "Clarify the latest PM ask."
            pendingAsk.workingUnderstandingSummary = trimmedOptionalDecisionText(pendingAsk.workingUnderstandingSummary)
            pendingAsk.operatingTruthSummary = trimmedOptionalDecisionText(pendingAsk.operatingTruthSummary)
            pendingAsk.durableTitle = trimmedOptionalDecisionText(pendingAsk.durableTitle)
            pendingAsk.durableBody = trimmedOptionalDecisionText(pendingAsk.durableBody)
            if pendingAsk.operatingTruthKind == nil {
                pendingAsk.operatingTruthKind = pmConversationOperatingTruthKind(from: pendingAsk.instructionTargetKind)
            }
            if pendingAsk.operatingTruthSummary == nil {
                pendingAsk.operatingTruthSummary = pendingAsk.workingUnderstandingSummary
            }
            if pendingAsk.durableTargetType != .pmInstruction {
                pendingAsk.instructionTargetKind = nil
                pendingAsk.durableTitle = nil
                pendingAsk.durableBody = nil
            }
            resolution.pendingAsk = pendingAsk
        }

        if resolution.durableTargetType != .pmInstruction {
            resolution.instructionTargetKind = nil
            resolution.durableTitle = nil
            resolution.durableBody = nil
            resolution.durableTargetId = nil
        }

        return resolution
    }

    private func validatedPMConversationActionPlan(
        _ actionPlan: PMConversationActionPlan?
    ) -> PMConversationActionPlan? {
        guard var actionPlan else { return nil }
        let summary = trimmedOptionalDecisionText(actionPlan.summary)
        let actions = actionPlan.actions.compactMap(validatedPMConversationActionIntent)
        guard let summary, actions.isEmpty == false else { return nil }
        actionPlan.summary = summary
        actionPlan.actions = actions
        return actionPlan
    }

    private func validatedPMConversationActionIntent(
        _ action: PMConversationActionIntent
    ) -> PMConversationActionIntent? {
        guard let summary = trimmedOptionalDecisionText(action.summary) else { return nil }
        var updated = action
        updated.summary = summary
        updated.title = trimmedOptionalDecisionText(action.title)
        updated.body = trimmedOptionalDecisionText(action.body)
        updated.detail = trimmedOptionalDecisionText(action.detail)
        updated.targetId = trimmedOptionalDecisionText(action.targetId)
        updated.charterId = trimmedOptionalDecisionText(action.charterId)
        updated.proposalSymbol = normalizedPMConversationProposalSymbol(action.proposalSymbol)
        if let quantity = action.proposalQuantity, quantity > 0 {
            updated.proposalQuantity = quantity
        } else {
            updated.proposalQuantity = nil
        }
        updated.liveOrderSymbol = normalizedPMConversationProposalSymbol(action.liveOrderSymbol)
        if let quantity = action.liveOrderQuantity, quantity > 0 {
            updated.liveOrderQuantity = quantity
        } else {
            updated.liveOrderQuantity = nil
        }
        if let notional = action.liveOrderNotionalAmount, notional > 0 {
            updated.liveOrderNotionalAmount = notional
        } else {
            updated.liveOrderNotionalAmount = nil
        }
        if let limitPrice = action.liveOrderLimitPrice, limitPrice > 0 {
            updated.liveOrderLimitPrice = limitPrice
        } else {
            updated.liveOrderLimitPrice = nil
        }
        updated.runtimeIdentifier = trimmedOptionalDecisionText(action.runtimeIdentifier)
        updated.watchlistSymbols = normalizedPMConversationWatchlistSymbolHints(action.watchlistSymbols)
        updated.selectedSkillReferences = normalizedPMConversationAgentSkillReferenceIntents(
            action.selectedSkillReferences
        )
        updated.sourceMessageIds = orderedUniqueStrings(action.sourceMessageIds)
        return updated
    }

    private func normalizedPMConversationAgentSkillReferenceIntents(
        _ references: [PMConversationAgentSkillReferenceIntent]
    ) -> [PMConversationAgentSkillReferenceIntent] {
        var orderedKeys: [String] = []
        var normalizedByKey: [String: PMConversationAgentSkillReferenceIntent] = [:]
        for reference in references {
            let skillId = reference.skillId.trimmingCharacters(in: .whitespacesAndNewlines)
            guard skillId.isEmpty == false else { continue }
            let key = skillId.lowercased()
            if normalizedByKey[key] == nil {
                orderedKeys.append(key)
                normalizedByKey[key] = PMConversationAgentSkillReferenceIntent(
                    skillId: skillId,
                    requirement: reference.requirement,
                    rationale: trimmedOptionalDecisionText(reference.rationale)
                )
                continue
            }
            guard var existing = normalizedByKey[key] else { continue }
            existing.requirement = strongestAgentSkillRequirement(existing.requirement, reference.requirement)
            if let rationale = trimmedOptionalDecisionText(reference.rationale),
               existing.rationale?.contains(rationale) != true {
                let existingRationale = existing.rationale ?? ""
                existing.rationale = existingRationale.isEmpty
                    ? rationale
                    : "\(existingRationale) | \(rationale)"
            }
            normalizedByKey[key] = existing
        }
        return orderedKeys
            .compactMap { normalizedByKey[$0] }
            .prefix(8)
            .map { reference in
                PMConversationAgentSkillReferenceIntent(
                    skillId: reference.skillId,
                    requirement: reference.requirement,
                    rationale: trimmedOptionalDecisionText(reference.rationale)
                )
            }
    }

    private struct PMConversationSelectedSkillReferenceResolution: Sendable, Equatable {
        var references: [AgentSkillTaskReference]
        var blocker: String?
    }

    private func resolvePMConversationSelectedSkillReferences(
        _ references: [PMConversationAgentSkillReferenceIntent],
        actor: String,
        now: Date
    ) async -> PMConversationSelectedSkillReferenceResolution {
        let normalized = normalizedPMConversationAgentSkillReferenceIntents(references)
        guard normalized.isEmpty == false else {
            return PMConversationSelectedSkillReferenceResolution(references: [], blocker: nil)
        }
        do {
            let skills = try await listAgentSkills(includeArchived: true)
            let skillsByID = Dictionary(uniqueKeysWithValues: skills.map { ($0.skillId.lowercased(), $0) })
            var taskReferences: [AgentSkillTaskReference] = []
            for reference in normalized {
                let key = reference.skillId.lowercased()
                guard let skill = skillsByID[key] else {
                    return PMConversationSelectedSkillReferenceResolution(
                        references: [],
                        blocker: "The PM selected Agent Skill id \(reference.skillId), but that skill is not in the app-owned Skills Library. No analyst delegation was launched with an invented skill."
                    )
                }
                guard skill.status == .active else {
                    return PMConversationSelectedSkillReferenceResolution(
                        references: [],
                        blocker: "The PM selected Agent Skill \(skill.title), but that skill is archived/inactive. No analyst delegation was launched with an unavailable skill."
                    )
                }
                taskReferences.append(
                    AgentSkillTaskReference(
                        skillId: skill.skillId,
                        skillTitle: skill.title,
                        requirement: reference.requirement,
                        source: .pmConversation,
                        rationale: trimmedOptionalDecisionText(reference.rationale),
                        updatedBy: actor,
                        createdAt: now,
                        updatedAt: now
                    )
                )
            }
            return PMConversationSelectedSkillReferenceResolution(
                references: normalizedAgentSkillTaskReferences(taskReferences),
                blocker: nil
            )
        } catch {
            return PMConversationSelectedSkillReferenceResolution(
                references: [],
                blocker: "The app-owned Agent Skills Library could not be read, so the PM could not validate selected skill ids. No analyst delegation was launched with unvalidated skills."
            )
        }
    }

    private func currentLiveReadinessBlockReasons() -> [PMExecutionRoutingBlockReason] {
        guard configuration.environment == .live else {
            return []
        }

        var reasons: [PMExecutionRoutingBlockReason] = []
        if killSwitchEnabled {
            reasons.append(.killSwitchEnabled)
        }
        if !isArmedForLiveTrading {
            reasons.append(.liveNotArmed)
        }
        return reasons
    }

    private func makePMExecutionRoutingAssessment(
        request: PMApprovalRequest,
        proposal: StrategyProposal?,
        status: PMExecutionRoutingStatus,
        action: PMExecutionRoutingAction,
        summary: String,
        detail: String,
        blockedReasons: [PMExecutionRoutingBlockReason]
    ) -> PMExecutionRoutingAssessment {
        PMExecutionRoutingAssessment(
            approvalRequestId: request.approvalRequestId,
            decisionId: request.decisionId,
            proposalId: proposal?.proposalId ?? request.proposalId,
            proposalTitle: proposal?.title,
            proposalStatus: proposal?.approval.status,
            environment: configuration.environment,
            isLiveArmed: isArmedForLiveTrading,
            killSwitchEnabled: killSwitchEnabled,
            status: status,
            action: action,
            summary: summary,
            detail: detail,
            blockedReasons: blockedReasons
        )
    }

    private func defaultPMApprovedNextStepSummary(decision: PMDecisionRecord) -> String {
        if let proposalId = trimmedOptionalDecisionText(decision.proposalId) {
            return "If you approve this PM request, the next step is a separate paper-safe proposal review for \(proposalId). This PM-layer approval still does not approve the proposal or authorize trading."
        }
        if let delegationId = trimmedOptionalDecisionText(decision.delegationId) {
            return "If you approve this PM request, the PM can continue with the linked analyst/proposal follow-up from delegation \(delegationId) while keeping any proposal approval or trade decision behind existing gates."
        }
        return "If you approve this PM request, the PM can continue with the bounded next paper-safe step while keeping proposal approval and trading behind the existing safety gates."
    }

    private func defaultPMRejectedNextStepSummary(decision: PMDecisionRecord) -> String {
        if decision.delegationId != nil || decision.findingId != nil {
            return "If you reject this PM request, the PM should leave the current recommendation unapproved and either request more analysis or keep the issue in monitor-only state."
        }
        return "If you reject this PM request, the PM should leave the current recommendation unapproved and avoid any paper-action escalation unless a new bounded review justifies it."
    }

    private func defaultPMReviewedNextStepSummary(decision: PMDecisionRecord) -> String {
        if decision.proposalId != nil {
            return "If you ask for more work, the PM should refine the recommendation while the linked proposal path remains behind its existing separate approval workflow."
        }
        return "If you ask for more work, the PM should revisit the recommendation without granting further authority or changing the current execution posture."
    }

