    @discardableResult
    private func upsertPMCommunicationPromotion(
        message: PMCommunicationMessage,
        targetType: PMCommunicationPromotionTargetType,
        targetId: String,
        source: AuditEventSource
    ) async throws -> PMCommunicationMessage {
        var updatedMessage = message
        updatedMessage.promotion = PMCommunicationPromotion(
            targetType: targetType,
            targetId: targetId,
            promotedAt: nowDate()
        )
        updatedMessage.updatedAt = nowDate()
        return try await upsertPMCommunicationMessage(updatedMessage, source: source)
    }

    private func validatedPMCommunicationMessage(_ message: PMCommunicationMessage) async throws -> PMCommunicationMessage {
        let sessionID = message.sessionId.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !sessionID.isEmpty else {
            throw PMCommunicationMessageValidationError.sessionIdRequired
        }
        guard try await pmCommunicationSessionStore.get(id: sessionID) != nil else {
            throw PMCommunicationMessageValidationError.sessionNotFound(id: sessionID)
        }

        let body = message.body.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !body.isEmpty else {
            throw PMCommunicationMessageValidationError.bodyRequired
        }

        var updated = message
        updated.sessionId = sessionID
        updated.body = body
        updated.senderId = message.senderId?.trimmingCharacters(in: .whitespacesAndNewlines)
        updated.replyToMessageId = message.replyToMessageId?.trimmingCharacters(in: .whitespacesAndNewlines)
        if updated.senderId?.isEmpty == true { updated.senderId = nil }
        if updated.replyToMessageId?.isEmpty == true { updated.replyToMessageId = nil }

        if var promotion = message.promotion {
            let targetID = promotion.targetId.trimmingCharacters(in: .whitespacesAndNewlines)
            guard !targetID.isEmpty else {
                throw PMCommunicationMessageValidationError.promotionTargetIdRequired
            }
            promotion.targetId = targetID
            updated.promotion = promotion
        }

        updated.conversationResolution = validatedPMConversationResolution(updated.conversationResolution)
        updated.conversationActionPlan = validatedPMConversationActionPlan(updated.conversationActionPlan)

        return updated
    }

    private func validatedPMDelegation(_ delegation: PMDelegationRecord) async throws -> PMDelegationRecord {
        let pmID = delegation.pmId.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !pmID.isEmpty else {
            throw PMDelegationValidationError.pmIdRequired
        }

        let charterID = delegation.charterId.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !charterID.isEmpty else {
            throw PMDelegationValidationError.charterIdRequired
        }

        let title = delegation.title.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !title.isEmpty else {
            throw PMDelegationValidationError.titleRequired
        }

        let rationale = delegation.rationale.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !rationale.isEmpty else {
            throw PMDelegationValidationError.rationaleRequired
        }

        guard !delegation.requestedOutputs.isEmpty else {
            throw PMDelegationValidationError.requestedOutputsRequired
        }

        let charter = try await getAnalystCharter(id: charterID)
        var updated = delegation
        updated.pmId = pmID
        updated.charterId = charterID
        updated.analystId = charter.analystId
        updated.title = title
        updated.rationale = rationale
        updated.parentDelegationId = delegation.parentDelegationId?.trimmingCharacters(in: .whitespacesAndNewlines)
        if updated.parentDelegationId?.isEmpty == true {
            updated.parentDelegationId = nil
        }
        updated.sourceFollowUpActionId = delegation.sourceFollowUpActionId?.trimmingCharacters(in: .whitespacesAndNewlines)
        if updated.sourceFollowUpActionId?.isEmpty == true {
            updated.sourceFollowUpActionId = nil
        }
        updated.sourceCommunicationSessionId = delegation.sourceCommunicationSessionId?.trimmingCharacters(in: .whitespacesAndNewlines)
        if updated.sourceCommunicationSessionId?.isEmpty == true {
            updated.sourceCommunicationSessionId = nil
        }
        updated.sourceCommunicationMessageId = delegation.sourceCommunicationMessageId?.trimmingCharacters(in: .whitespacesAndNewlines)
        if updated.sourceCommunicationMessageId?.isEmpty == true {
            updated.sourceCommunicationMessageId = nil
        }
        updated.taskingBrief = normalizedPMTaskingBrief(delegation.taskingBrief)
        let delegationRuntimeSource: AnalystRuntimePolicySource? = switch delegation.runtimePolicyOverride?.policySource {
        case .specializationDefault:
            .specializationDefault
        case .standingBenchDefault:
            .standingBenchDefault
        default:
            .pmDelegationOverride
        }
        updated.runtimePolicyOverride = try validatedAnalystRuntimePolicy(
            delegation.runtimePolicyOverride,
            expectedSource: delegationRuntimeSource
        )
        if var resolution = delegation.issueResolution {
            let resolvedBy = resolution.resolvedBy.trimmingCharacters(in: .whitespacesAndNewlines)
            let summary = resolution.summary.trimmingCharacters(in: .whitespacesAndNewlines)
            let supersededBy = resolution.supersededByDelegationId?.trimmingCharacters(in: .whitespacesAndNewlines)
            resolution.resolvedBy = resolvedBy.isEmpty ? "owner" : resolvedBy
            resolution.summary = summary.isEmpty
                ? "Worker issue resolved from active owner surfaces; durable history remains traceable."
                : summary
            resolution.supersededByDelegationId = supersededBy?.isEmpty == true ? nil : supersededBy
            updated.issueResolution = resolution
        } else {
            updated.issueResolution = nil
        }

        if let rawTaskID = delegation.taskId?.trimmingCharacters(in: .whitespacesAndNewlines), !rawTaskID.isEmpty {
            let task = try await getAnalystTask(id: rawTaskID)
            guard task.analystId == charter.analystId else {
                throw PMDelegationValidationError.analystTaskMismatch(taskId: rawTaskID)
            }
            if let taskCharterID = task.charterId, taskCharterID != charterID {
                throw PMDelegationValidationError.analystCharterMismatch(
                    expected: charterID,
                    actual: taskCharterID
                )
            }
            updated.taskId = rawTaskID
        } else {
            updated.taskId = nil
        }

        updated.followUpActions = try delegation.followUpActions.map { try normalizedPMAnalystFollowUpAction($0) }

        return updated
    }

    private func normalizedPMTaskingBrief(_ brief: PMTaskingBrief?) -> PMTaskingBrief? {
        guard var brief else { return nil }
        brief.taskObjective = brief.taskObjective?.trimmingCharacters(in: .whitespacesAndNewlines)
        brief.whyNow = brief.whyNow?.trimmingCharacters(in: .whitespacesAndNewlines)
        brief.reviewLens = brief.reviewLens?.trimmingCharacters(in: .whitespacesAndNewlines)
        brief.challengeInstruction = brief.challengeInstruction?.trimmingCharacters(in: .whitespacesAndNewlines)
        brief.evidenceExpectation = brief.evidenceExpectation?.trimmingCharacters(in: .whitespacesAndNewlines)
        brief.disconfirmingEvidenceExpectation = brief.disconfirmingEvidenceExpectation?.trimmingCharacters(in: .whitespacesAndNewlines)
        brief.researchQuestions = AnalystTaskQuestionChecklist.normalizedQuestions(brief.researchQuestions)
        if brief.researchQuestions.isEmpty == false {
            brief.coverageRequired = true
        }
        brief.expectedOutputs = brief.expectedOutputs
            .map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
            .filter { !$0.isEmpty }
        brief.revisionReason = brief.revisionReason?.trimmingCharacters(in: .whitespacesAndNewlines)
        brief.selectedSkillReferences = normalizedAgentSkillTaskReferences(brief.selectedSkillReferences)
        return pmTaskingBriefHasContent(brief) ? brief : nil
    }

    private func normalizedAgentSkillTaskReferences(
        _ references: [AgentSkillTaskReference]
    ) -> [AgentSkillTaskReference] {
        var seen = Set<String>()
        var normalized: [AgentSkillTaskReference] = []
        for reference in references {
            let skillId = reference.skillId.trimmingCharacters(in: .whitespacesAndNewlines)
            guard skillId.isEmpty == false else { continue }
            let key = skillId.lowercased()
            guard seen.insert(key).inserted else { continue }
            let title = reference.skillTitle.trimmingCharacters(in: .whitespacesAndNewlines)
            let actor = reference.updatedBy.trimmingCharacters(in: .whitespacesAndNewlines)
            normalized.append(
                AgentSkillTaskReference(
                    skillId: skillId,
                    skillTitle: title.isEmpty ? skillId : title,
                    requirement: reference.requirement,
                    source: reference.source,
                    rationale: trimmedOptionalDecisionText(reference.rationale),
                    updatedBy: actor.isEmpty ? "unknown" : actor,
                    createdAt: reference.createdAt,
                    updatedAt: reference.updatedAt
                )
            )
        }
        return Array(normalized.prefix(8))
    }

    private func normalizedPMAnalystFollowUpAction(
        _ action: PMAnalystFollowUpAction
    ) throws -> PMAnalystFollowUpAction {
        var updated = action
        updated.summary = action.summary.trimmingCharacters(in: .whitespacesAndNewlines)
        updated.requestedCharterId = action.requestedCharterId?.trimmingCharacters(in: .whitespacesAndNewlines)
        if updated.requestedCharterId?.isEmpty == true {
            updated.requestedCharterId = nil
        }
        updated.taskingBrief = normalizedPMTaskingBrief(action.taskingBrief)
        updated.requestedRuntimePolicy = try validatedAnalystRuntimePolicy(
            action.requestedRuntimePolicy,
            expectedSource: action.requestedRuntimePolicy == nil ? nil : .pmDelegationOverride
        )
        return updated
    }

    private func validatePMDelegationFollowUpRequest(
        _ request: PMDelegationFollowUpRequest
    ) throws -> PMDelegationFollowUpRequest {
        let sourceDelegationId = request.sourceDelegationId.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !sourceDelegationId.isEmpty else {
            throw PMDelegationFollowUpValidationError.sourceDelegationIdRequired
        }
        let summary = request.summary.trimmingCharacters(in: .whitespacesAndNewlines)
        if request.actionType != .accept && summary.isEmpty {
            throw PMDelegationFollowUpValidationError.summaryRequired
        }
        let requestedCharterId = request.requestedCharterId?.trimmingCharacters(in: .whitespacesAndNewlines)
        if request.actionType == .rerouteToAnalyst,
           requestedCharterId == nil || requestedCharterId?.isEmpty == true {
            throw PMDelegationFollowUpValidationError.requestedCharterIdRequired
        }
        if request.actionType == .rerunWithRuntime,
           request.requestedRuntimePolicy == nil {
            throw PMDelegationFollowUpValidationError.requestedRuntimeRequired
        }
        return PMDelegationFollowUpRequest(
            sourceDelegationId: sourceDelegationId,
            actionType: request.actionType,
            summary: summary.isEmpty ? "PM accepted current analyst output as sufficient." : summary,
            requestedCharterId: requestedCharterId?.isEmpty == true ? nil : requestedCharterId,
            requestedRuntimePolicy: request.requestedRuntimePolicy,
            taskingBrief: normalizedPMTaskingBrief(request.taskingBrief)
        )
    }

    private func resolveFollowUpRuntimePolicy(
        request: PMDelegationFollowUpRequest,
        sourceDelegation: PMDelegationRecord,
        targetCharter: AnalystCharter,
        now: Date
    ) async throws -> AnalystRuntimePolicy? {
        if var requested = request.requestedRuntimePolicy {
            requested.policySource = .pmDelegationOverride
            requested.createdAt = now
            requested.updatedAt = now
            return requested
        }
        if var existing = sourceDelegation.runtimePolicyOverride {
            existing.policySource = .pmDelegationOverride
            existing.createdAt = now
            existing.updatedAt = now
            return existing
        }
        if targetCharter.charterId == recentNewsStandingAnalystCharterID {
            return try await recentNewsAnalystRuntimePolicy(now: now)
        }
        if isSeededStandingAnalystCharterID(targetCharter.charterId) {
            return try await standingBenchAnalystRuntimePolicy(now: now)
        }
        if var charterDefault = targetCharter.defaultRuntimePolicy {
            charterDefault.policySource = .charterDefault
            charterDefault.createdAt = now
            charterDefault.updatedAt = now
            return charterDefault
        }
        return nil
    }

    private func makePMConversationAnalystTask(
        action: PMConversationActionIntent,
        charter: AnalystCharter,
        delegation: PMDelegationRecord,
        taskingBrief: PMTaskingBrief?,
        taskId: String,
        pmId: String,
        now: Date
    ) async throws -> AnalystTask {
        let contextPack = try await buildBenchAnalystContextPack(
            charterID: charter.charterId,
            pmID: pmId,
            taskSkillReferences: taskingBrief?.selectedSkillReferences ?? []
        )
        let symbolHints = normalizedPMConversationAnalystSymbolHints(
            inferredPMConversationAnalystSymbols(
                action: action,
                title: delegation.title,
                rationale: delegation.rationale,
                brief: taskingBrief
            )
        )
        return AnalystTask(
            taskId: taskId,
            analystId: charter.analystId,
            charterId: charter.charterId,
            parentTaskId: nil,
            title: delegation.title,
            description: makePMTaskDescription(
                baseDescription: delegation.rationale,
                brief: taskingBrief
            ),
            pmTaskingBrief: taskingBrief,
            status: .queued,
            createdAt: now,
            updatedAt: now,
            dueAt: nil,
            symbols: symbolHints,
            tags: ["pm-conversation-delegation", "pm-skill-tasking"],
            contextPack: contextPack,
            lastCheckpointSummary: nil,
            checkpoint: nil,
            linkedFindingIDs: [],
            linkedProposalIDs: []
        )
    }

    private func shouldLaunchPMConversationDelegation(_ delegation: PMDelegationRecord) -> Bool {
        guard let lastLaunch = delegation.lastLaunch else {
            return true
        }
        switch lastLaunch.status {
        case .failed:
            return true
        case .running, .progressing, .healthy, .degradedExternalEvidence:
            return false
        }
    }

    private func makeFollowUpAnalystTask(
        sourceDelegation: PMDelegationRecord,
        sourceTask: AnalystTask?,
        targetCharter: AnalystCharter,
        followUpAction: PMAnalystFollowUpAction,
        taskingBrief: PMTaskingBrief?,
        taskId: String,
        now: Date
    ) async throws -> AnalystTask {
        let contextPack = try await buildBenchAnalystContextPack(
            charterID: targetCharter.charterId,
            pmID: sourceDelegation.pmId,
            taskSkillReferences: taskingBrief?.selectedSkillReferences ?? []
        )
        let baseTags = Set((sourceTask?.tags ?? []) + ["pm-follow-up", "pm-\(followUpAction.actionType.rawValue)"])
        let baseDescription = sourceTask?.description
            ?? sourceDelegation.rationale
        return AnalystTask(
            taskId: taskId,
            analystId: targetCharter.analystId,
            charterId: targetCharter.charterId,
            parentTaskId: sourceTask?.taskId,
            title: makeFollowUpTaskTitle(sourceDelegation.title, action: followUpAction.actionType),
            description: makePMTaskDescription(
                baseDescription: baseDescription,
                brief: taskingBrief,
                action: followUpAction,
                sourceDelegationTitle: sourceDelegation.title
            ),
            pmTaskingBrief: taskingBrief,
            status: .queued,
            createdAt: now,
            updatedAt: now,
            dueAt: sourceTask?.dueAt,
            symbols: sourceTask?.symbols ?? [],
            tags: Array(baseTags).sorted(),
            contextPack: contextPack,
            lastCheckpointSummary: nil,
            checkpoint: nil,
            linkedFindingIDs: [],
            linkedProposalIDs: []
        )
    }

    private func makeFollowUpTaskTitle(
        _ sourceTitle: String,
        action: PMAnalystFollowUpActionType
    ) -> String {
        switch action {
        case .accept:
            return sourceTitle
        case .requestRevision:
            return "Revise and tighten: \(sourceTitle)"
        case .requestStrongerEvidence:
            return "Deepen evidence: \(sourceTitle)"
        case .rerouteToAnalyst:
            return "Cross-check with better-fit analyst: \(sourceTitle)"
        case .rerunWithRuntime:
            return "Re-run under stronger runtime: \(sourceTitle)"
        }
    }

    private func makeFollowUpDelegationRationale(
        sourceDelegation: PMDelegationRecord,
        followUpAction: PMAnalystFollowUpAction
    ) -> String {
        let trimmedSummary = followUpAction.summary.trimmingCharacters(in: .whitespacesAndNewlines)
        let guidance = makePMAnalystFollowUpGuidance(followUpAction.actionType)
        var sentences = [
            "PM follow-up on prior analyst output for \(sourceDelegation.title).",
            guidance.managerialIntent
        ]
        if !trimmedSummary.isEmpty {
            sentences.append("PM rationale: \(trimmedSummary).")
        }
        if let requestedCharterID = followUpAction.requestedCharterId,
           !requestedCharterID.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
            sentences.append("Requested specialist: \(requestedCharterID).")
        }
        if let runtime = followUpAction.requestedRuntimePolicy {
            sentences.append("Requested runtime: \(analystRequestedRuntimeText(runtime)).")
        }
        sentences.append(guidance.nextStepMeaning)
        sentences.append("This remains bounded analyst work under existing approval and trading guardrails.")
        return sentences.joined(separator: " ")
    }

    private func resolvedRuntimePolicy(
        delegationRuntimeOverride: AnalystRuntimePolicy?,
        charter: AnalystCharter,
        now: Date
    ) async throws -> AnalystRuntimePolicy? {
        if let delegationRuntimeOverride {
            return delegationRuntimeOverride
        }
        if charter.charterId == recentNewsStandingAnalystCharterID {
            return try await recentNewsAnalystRuntimePolicy(now: now)
        }
        if isSeededStandingAnalystCharterID(charter.charterId) {
            return try await standingBenchAnalystRuntimePolicy(now: now)
        }
        return charter.defaultRuntimePolicy
    }

    private func appendUnique(_ id: String, to existing: [String]) -> [String] {
        if existing.contains(id) {
            return existing
        }
        return existing + [id]
    }

    private func makeSignalFromAnalystFinding(
        finding: AnalystFinding,
        bundle: AnalystEvidenceBundle
    ) async throws -> Signal {
        guard !finding.symbols.isEmpty else {
            throw AnalystFindingSignalDraftError.ineligibleFinding(
                id: finding.findingId,
                reason: "finding has no linked symbols"
            )
        }
        guard !bundle.refs.isEmpty else {
            throw AnalystFindingSignalDraftError.ineligibleFinding(
                id: finding.findingId,
                reason: "linked evidence bundle is empty"
            )
        }

        let direction = findingSignalDirection(for: finding) ?? .neutral

        let signalID = finding.linkedSignalId ?? "sig-\(finding.findingId)"
        let effectiveTaskID = finding.taskId ?? bundle.taskId
        let effectiveCharterID = try await resolveAnalystCharterID(
            finding: finding,
            bundle: bundle,
            taskID: effectiveTaskID
        )
        let evidence = makeSignalEvidenceFromFinding(finding: finding, bundle: bundle)

        return Signal(
            signalId: signalID,
            createdAt: finding.createdAt,
            updatedAt: finding.updatedAt,
            status: .new,
            symbols: finding.symbols,
            direction: direction,
            horizon: findingSignalHorizon(for: finding),
            confidence: finding.confidence,
            score: finding.confidence,
            positionStatement: finding.thesis,
            recommendedAction: .notifyOnly,
            evidence: evidence,
            provenance: SignalProvenance(
                sourceJobId: "analyst.finding_draft",
                scoringVersion: "analyst-finding-v1",
                analystId: finding.analystId,
                charterId: effectiveCharterID,
                taskId: effectiveTaskID,
                sourceFindingId: finding.findingId,
                sourceEvidenceBundleId: bundle.bundleId
            ),
            originatingFindingId: finding.findingId
        )
    }

    private func resolveAnalystCharterID(
        finding: AnalystFinding,
        bundle: AnalystEvidenceBundle,
        taskID: String?
    ) async throws -> String? {
        if let charterID = finding.charterId {
            return charterID
        }
        if let charterID = bundle.charterId {
            return charterID
        }
        guard let taskID else {
            return nil
        }
        return try await analystTaskStore.get(id: taskID)?.charterId
    }

    private func findingSignalDirection(for finding: AnalystFinding) -> SignalDirection? {
        let directionTerms = "\(finding.title) \(finding.summary) \(finding.thesis) \(finding.tags.joined(separator: " "))".lowercased()
        let bullishKeywords = ["bullish", "long", "upside", "outperform", "acceleration", "benefit", "positive"]
        let bearishKeywords = ["bearish", "short", "downside", "underperform", "deterioration", "headwind", "negative"]

        let bullishHits = bullishKeywords.reduce(into: 0) { partial, keyword in
            if directionTerms.contains(keyword) {
                partial += 1
            }
        }
        let bearishHits = bearishKeywords.reduce(into: 0) { partial, keyword in
            if directionTerms.contains(keyword) {
                partial += 1
            }
        }

        if bullishHits > bearishHits {
            return .bullish
        }
        if bearishHits > bullishHits {
            return .bearish
        }
        return nil
    }

    private func findingSignalHorizon(for finding: AnalystFinding) -> SignalHorizon {
        let raw = finding.timeHorizon?.lowercased() ?? ""
        if raw.contains("intra") || raw.contains("day") {
            return .intraday
        }
        if raw.contains("long") || raw.contains("quarter") || raw.contains("year") {
            return .longTerm
        }
        return .swing
    }

    private func makeSignalEvidenceFromFinding(
        finding: AnalystFinding,
        bundle: AnalystEvidenceBundle
    ) -> [SignalEvidenceRef] {
        var evidence: [SignalEvidenceRef] = [
            SignalEvidenceRef(
                type: .finding,
                id: finding.findingId,
                url: nil,
                title: finding.title,
                summary: finding.summary,
                timestamp: finding.updatedAt
            )
        ]

        evidence.append(contentsOf: bundle.refs.prefix(4).map { ref in
            let type: SignalEvidenceType
            switch ref.sourceKind {
            case .market:
                type = .market
            case .appNews:
                type = .news
            default:
                type = .external
            }

            return SignalEvidenceRef(
                type: type,
                id: ref.appEntityID ?? ref.sourceIdentifier ?? ref.refId,
                url: ref.url,
                title: ref.title,
                summary: ref.summary,
                timestamp: ref.observedAt ?? finding.updatedAt
            )
        })

        return evidence
    }

    private func validateAnalystSignalEligibleForProposal(_ signal: Signal) throws {
        guard signal.analystLineage != nil else {
            throw AnalystSignalProposalDraftError.ineligibleSignal(
                id: signal.signalId,
                reason: "signal is missing analyst provenance"
            )
        }
        guard !signal.symbols.isEmpty else {
            throw AnalystSignalProposalDraftError.ineligibleSignal(
                id: signal.signalId,
                reason: "signal has no linked symbols"
            )
        }
        guard signal.direction != .neutral else {
            throw AnalystSignalProposalDraftError.ineligibleSignal(
                id: signal.signalId,
                reason: "signal direction is neutral"
            )
        }

        let positionStatement = signal.positionStatement.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !positionStatement.isEmpty else {
            throw AnalystSignalProposalDraftError.ineligibleSignal(
                id: signal.signalId,
                reason: "signal is missing directional rationale"
            )
        }
    }

    private func analystProposalLineage(from signal: Signal) -> AnalystProposalLineage? {
        guard let lineage = signal.analystLineage else {
            return nil
        }

        return AnalystProposalLineage(
            analystId: lineage.analystId,
            charterId: lineage.charterId,
            taskId: lineage.taskId,
            originatingFindingId: lineage.findingId,
            sourceEvidenceBundleId: lineage.evidenceBundleId
        )
    }

    private struct RSSPollFeedResult: Sendable {
        let inserted: Int
        let duplicates: Int
        let itemsParsed: Int
    }

    private func pollRSSFeed(
        feed: RSSFeed,
        maxItemsPerFeed: Int,
        now: Date
    ) async throws -> RSSPollFeedResult {
        guard let url = URL(string: feed.url) else {
            throw RSSFeedFetchError.invalidURL(feedName: feed.name)
        }

        let response = try await rssFetcher.fetch(
            url: url,
            userAgent: "AlgoTradingMac/1.0 (TradingKit RSS Poller)"
        )
        guard (200...299).contains(response.statusCode) else {
            throw RSSFeedFetchError.httpStatus(host: url.host, statusCode: response.statusCode)
        }

        let parsed = RSSParser.parseWithDiagnostics(data: response.data)
        if let fatalError = parsed.fatalError {
            throw RSSFeedFetchError.parsing(host: url.host, message: fatalError)
        }
        let items = Array(parsed.items.prefix(maxItemsPerFeed))
        let source = normalizedRSSSourceName(for: feed)
        let events = items.map { item in
            NewsEventFactory.makeFromRSS(
                source: source,
                feedTags: feed.tags,
                item: item,
                now: now
            )
        }
        let appended = try await newsStore.append(events)
        await store.publishDiagnostic(
            "rss poll feed=\(feed.name) fetched=\(items.count) skipped_invalid_pub_date=\(parsed.diagnostics.count) new=\(appended.inserted) dup=\(appended.duplicates)",
            source: .engine,
            action: "rss_poll"
        )
        return RSSPollFeedResult(
            inserted: appended.inserted,
            duplicates: appended.duplicates,
            itemsParsed: items.count
        )
    }

    private func normalizedRSSSourceName(for feed: RSSFeed) -> String {
        let lower = feed.name.lowercased()
        let scalars = lower.unicodeScalars.map { scalar -> Character in
            let allowed = CharacterSet.alphanumerics.contains(scalar)
            return allowed ? Character(scalar) : "_"
        }
        let collapsed = String(scalars)
            .replacingOccurrences(of: "__", with: "_")
            .trimmingCharacters(in: CharacterSet(charactersIn: "_"))
        if collapsed.isEmpty {
            return "rss_custom"
        }
        return "rss_\(collapsed)"
    }

    private func resolveAlpacaNewsClient() -> any AlpacaNewsProviding {
        if let alpacaNewsClient {
            return alpacaNewsClient
        }
        let created = alpacaNewsClientFactory(configuration.environment)
        alpacaNewsClient = created
        return created
    }

    private func executeReplayBatchJob(
        job: JobRecord,
        updateProgress: JobRunner.JobProgressUpdater
    ) async throws -> JobExecutionReport {
        let proposalID = try requiredJobString(
            key: "proposalId",
            params: job.parameters
        )
        let rawSymbols = try monitorSymbolsParam(job.parameters["symbols"])
        guard !rawSymbols.isEmpty else {
            throw JobRunnerError.invalidParameters(message: "replay_batch requires symbols.")
        }
        let symbols = Array(MarketDataSubscriptionSet.normalized(rawSymbols)).sorted()
        guard !symbols.isEmpty else {
            throw JobRunnerError.invalidParameters(message: "replay_batch requires at least one valid symbol.")
        }

        let timeframe = try replayTimeframeParam(job.parameters["timeframe"])
        let speed = try replaySpeedParam(job.parameters["speed"])
        let feed = try replayFeedParam(
            job.parameters["feed"],
            defaultFeed: ReplayFeed(marketDataFeed: configuration.marketDataFeed)
        )
        let autoIngest = replayBoolParam(
            job.parameters["autoIngest"],
            defaultValue: true
        )
        let repeats = try replayRepeatsParam(job.parameters["repeats"])
        let simulateTrades = replayBoolParam(
            job.parameters["simulateTrades"],
            defaultValue: false
        )
        let allowTradingInReplay = replayBoolParam(
            job.parameters["allowTradingInReplay"],
            defaultValue: simulateTrades
        )
        let fillPolicy = try replayFillPolicyParam(job.parameters["fillPolicy"])
        let slippageBps = try replaySlippageParam(job.parameters)
        let window = try replayWindowParams(job.parameters)

        let totalRuns = repeats * symbols.count
        var completedRuns = 0
        var runIDs: [String] = []
        var failures: [[String: JSONValue]] = []
        var successfulRuns: [[String: JSONValue]] = []
        var netPnLs: [Double] = []

        await updateProgress(0, "Replay batch queued")

        for repeatIndex in 0..<repeats {
            for symbol in symbols {
                try Task.checkCancellation()
                do {
                    let result = try await replayRun(
                        proposalID: proposalID,
                        symbols: [symbol],
                        timeframe: timeframe,
                        start: window.start,
                        end: window.end,
                        speed: speed,
                        autoIngest: autoIngest,
                        feed: feed,
                        simulateTrades: simulateTrades,
                        allowTradingInReplay: allowTradingInReplay,
                        fillPolicy: fillPolicy,
                        slippageBps: slippageBps,
                        source: .engine
                    )
                    runIDs.append(result.runID)

                    var row: [String: JSONValue] = [
                        "symbol": .string(symbol),
                        "repeat": .number(Double(repeatIndex + 1)),
                        "runId": .string(result.runID),
                        "barsProcessed": .number(Double(result.barsProcessed))
                    ]
                    if let record = try? await getRun(runID: result.runID),
                       let netPnL = record.metrics.netPnL {
                        let pnlValue = NSDecimalNumber(decimal: netPnL).doubleValue
                        netPnLs.append(pnlValue)
                        row["netPnL"] = .number(pnlValue)
                    } else {
                        row["netPnL"] = .null
                    }
                    successfulRuns.append(row)
                } catch let controlError as AgentControlError {
                    failures.append([
                        "symbol": .string(symbol),
                        "repeat": .number(Double(repeatIndex + 1)),
                        "code": .string(controlError.code),
                        "message": .string(controlError.message)
                    ])
                    await store.publishDiagnostic(
                        "replay batch run failed symbol=\(symbol) repeat=\(repeatIndex + 1) code=\(controlError.code)",
                        source: .engine,
                        level: .warning,
                        action: "job_replay_batch"
                    )
                } catch {
                    failures.append([
                        "symbol": .string(symbol),
                        "repeat": .number(Double(repeatIndex + 1)),
                        "code": .string("job_replay_batch_failed"),
                        "message": .string(error.localizedDescription)
                    ])
                    await store.publishDiagnostic(
                        "replay batch run failed symbol=\(symbol) repeat=\(repeatIndex + 1)",
                        source: .engine,
                        level: .warning,
                        action: "job_replay_batch"
                    )
                }

                completedRuns += 1
                await updateProgress(
                    Double(completedRuns) / Double(totalRuns),
                    "Replay batch \(completedRuns)/\(totalRuns)"
                )
            }
        }

        if Task.isCancelled {
            throw CancellationError()
        }

        let averagePnL: JSONValue
        if netPnLs.isEmpty {
            averagePnL = .null
        } else {
            averagePnL = .number(netPnLs.reduce(0, +) / Double(netPnLs.count))
        }
        let bestPnL = netPnLs.max().map(JSONValue.number) ?? .null
        let worstPnL = netPnLs.min().map(JSONValue.number) ?? .null

        let result: JSONValue = .object([
            "jobType": .string(JobType.replayBatch.rawValue),
            "proposalId": .string(proposalID),
            "timeframe": .string(timeframe.rawValue),
            "start": .string(iso8601Timestamp(window.start)),
            "end": .string(iso8601Timestamp(window.end)),
            "symbols": .array(symbols.map(JSONValue.string)),
            "repeats": .number(Double(repeats)),
            "totalRequestedRuns": .number(Double(totalRuns)),
            "succeededRuns": .number(Double(successfulRuns.count)),
            "failedRuns": .number(Double(failures.count)),
            "runsCreated": .array(runIDs.map(JSONValue.string)),
            "successes": .array(successfulRuns.map(JSONValue.object)),
            "failures": .array(failures.map(JSONValue.object)),
            "avgNetPnL": averagePnL,
            "bestNetPnL": bestPnL,
            "worstNetPnL": worstPnL
        ])

        return JobExecutionReport(
            result: result,
            proposalId: proposalID,
            runId: runIDs.first
        )
    }

