    private func reconcilePersistedRSSNewsSources(
        changedFeedName: String? = nil,
        trigger: String,
        force: Bool = false
    ) async {
        rssNewsCleanupRequestCount += 1
        do {
            let feeds = try await rssFeedStore.listFeeds()
            let activeSources = Set(feeds.map(normalizedRSSSourceName(for:)))
            if !force,
               let lastRSSNewsReconciliationActiveSources,
               lastRSSNewsReconciliationActiveSources == activeSources {
                rssNewsCleanupSkippedNoSourceChangeCount += 1
                return
            }

            rssNewsCleanupFullScanCount += 1
            let cleanup = try await newsStore.purgeRSSSources(notIn: activeSources)
            lastRSSNewsReconciliationActiveSources = activeSources
            rssNewsCleanupRemovedEventCount += cleanup.removedEvents
            rssNewsCleanupAffectedFileCount += cleanup.affectedFiles
            guard cleanup.removedEvents > 0 else {
                return
            }

            let changedFeedSegment = changedFeedName.map { " changed_feed=\($0)" } ?? ""
            await store.publishDiagnostic(
                "rss news cleanup removed_events=\(cleanup.removedEvents) affected_files=\(cleanup.affectedFiles) trigger=\(trigger)\(changedFeedSegment)",
                source: .engine,
                action: "rss_news_cleanup"
            )
        } catch {
            await store.publishDiagnostic(
                "rss news cleanup degraded trigger=\(trigger) reason=\(error.localizedDescription)",
                source: .engine,
                level: .warning,
                action: "rss_news_cleanup"
            )
        }
    }

