    private func monitorStrategyRuns() async {
        while !Task.isCancelled {
            try? await Task.sleep(nanoseconds: UInt64(max(0.2, strategySnapshotIntervalSec) * 1_000_000_000))
            guard !Task.isCancelled else {
                return
            }
            await reconcileActivePaperRunsWithStrategyStates()
        }
    }

    private func reconcileActivePaperRunsWithStrategyStates() async {
        guard !activeRunIDByStrategyID.isEmpty else {
            return
        }
        let statuses = await strategyRunner.statuses()
        let statusesByID = Dictionary(uniqueKeysWithValues: statuses.map { ($0.id, $0) })

        for (strategyID, _) in activeRunIDByStrategyID {
            guard let status = statusesByID[strategyID] else {
                continue
            }
            guard status.state != .running else {
                continue
            }

            let resolvedStatus: PaperRunStatus = (status.state == .error) ? .error : .stopped
            let reason = (status.state == .error)
                ? (status.lastMessage ?? "error")
                : "completed"
            await finalizePaperRunIfActive(
                strategyID: strategyID,
                status: resolvedStatus,
                stopReason: reason,
                source: .engine
            )
        }
    }

    private func finalizeAllActivePaperRuns(
        status: PaperRunStatus,
        stopReason: String,
        source: AuditEventSource
    ) async {
        let strategyIDs = Array(activeRunIDByStrategyID.keys)
        for strategyID in strategyIDs {
            await finalizePaperRunIfActive(
                strategyID: strategyID,
                status: status,
                stopReason: stopReason,
                source: source
            )
        }
    }

    private func finalizePaperRunIfActive(
        strategyID: String,
        status: PaperRunStatus,
        stopReason: String,
        source: AuditEventSource
    ) async {
        guard let runID = activeRunIDByStrategyID[strategyID],
              var run = activePaperRunsByRunID[runID]
        else {
            return
        }

        let replayEndedAt = replayCurrentTimeByStrategyID[strategyID] ?? run.startedAt
        let endedAt = (run.runType == .replay) ? replayEndedAt : nowDate()
        run.endedAt = endedAt
        run.status = status
        run.stopReason = stopReason
        run.metrics.lastUpdatedAt = endedAt
        if run.runType == .replay {
            run.metrics.endingCash = run.metrics.endingCash ?? run.metrics.startingCash
            run.metrics.endingEquity = run.metrics.endingEquity ?? run.metrics.startingEquity
        } else {
            run.metrics.endingEquity = await currentAccountEquity()
        }
        if let realized = run.metrics.realizedPnL,
           let unrealized = run.metrics.unrealizedPnL {
            run.metrics.netPnL = realized + unrealized
        } else {
            run.metrics.netPnL = nil
        }

        activePaperRunsByRunID[runID] = nil
        activeRunIDByStrategyID[strategyID] = nil
        activeReplayRunIDByStrategyID[strategyID] = nil
        replaySimBrokerByStrategyID[strategyID] = nil
        replayCurrentTimeByStrategyID[strategyID] = nil
        dirtyRunIDs.remove(runID)
        runIDByOrderID = runIDByOrderID.filter { $0.value != runID }

        do {
            try await paperRunStore.updateRun(runId: runID, record: run)
        } catch {
            await store.publishDiagnostic(
                "paper run finalize persist failed run_id=\(shortOrderID(runID)) reason=\(error.localizedDescription)",
                source: .system,
                level: .warning,
                strategyID: strategyID,
                action: "paper_run_finalize"
            )
        }
        _ = try? await proposalStore.recordPaperRunResult(
            proposalID: run.proposalId,
            status: status.rawValue
        )
        await refreshProposalsSnapshot()
        await refreshProposalRunsSnapshot(proposalID: run.proposalId)
        await store.publishDiagnostic(
            "paper run stopped proposal_id=\(run.proposalId) run_id=\(shortOrderID(runID)) reason=\(stopReason)",
            source: source,
            strategyID: strategyID,
            action: "paper_run_stopped"
        )
    }

    private func schedulePaperRunPersistence() async {
        guard !dirtyRunIDs.isEmpty else {
            return
        }
        guard isStarted else {
            await flushDirtyPaperRuns()
            return
        }
        await paperRunPersistenceRefresher.trigger { [weak self] in
            await self?.flushDirtyPaperRuns()
        }
    }

    private func flushDirtyPaperRuns() async {
        let runIDs = Array(dirtyRunIDs)
        guard !runIDs.isEmpty else {
            return
        }
        dirtyRunIDs.removeAll()
        for runID in runIDs {
            guard let run = activePaperRunsByRunID[runID] else {
                continue
            }
            do {
                try await paperRunStore.updateRun(runId: runID, record: run)
            } catch {
                await store.publishDiagnostic(
                    "paper run persist failed run_id=\(shortOrderID(runID)) reason=\(error.localizedDescription)",
                    source: .system,
                    level: .warning,
                    strategyID: run.strategyId,
                    action: "paper_run_persist"
                )
            }
        }
    }

    private func markRunDirty(_ runID: String) async {
        dirtyRunIDs.insert(runID)
        await schedulePaperRunPersistence()
    }

    private func recordRunIntentSubmission(
        strategyID: String,
        intent: OrderIntent
    ) async {
        guard let runID = activeRunIDByStrategyID[strategyID],
              var run = activePaperRunsByRunID[runID]
        else {
            return
        }

        run.metrics.orderIntentsSubmitted += 1
        run.metrics.lastUpdatedAt = nowDate()
        switch intent {
        case .place(let place):
            let symbol = place.symbol.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
            if !symbol.isEmpty, !run.metrics.symbolsTraded.contains(symbol) {
                run.metrics.symbolsTraded.append(symbol)
                run.metrics.symbolsTraded.sort()
            }
        case .replace:
            run.metrics.replacesSubmitted += 1
        case .cancel:
            run.metrics.cancelsSubmitted += 1
        }

        activePaperRunsByRunID[runID] = run
        await markRunDirty(runID)
    }

    private func recordRunIntentOutcome(
        strategyID: String,
        intent: OrderIntent,
        result: OrderIntentSubmissionResult
    ) async {
        guard let runID = activeRunIDByStrategyID[strategyID],
              var run = activePaperRunsByRunID[runID]
        else {
            return
        }

        if result.accepted {
            run.metrics.ordersAccepted += 1
            if let orderID = result.orderID {
                runIDByOrderID[orderID] = runID
            }
        } else {
            run.metrics.ordersRejected += 1
            if let code = result.errorCode,
               strategySafetyBlockCodes.contains(code) || code.hasPrefix("proposal_") {
                run.metrics.riskBlocks += 1
            }
        }
        run.metrics.lastUpdatedAt = nowDate()

        if case .place(let place) = intent {
            let symbol = place.symbol.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
            if !symbol.isEmpty, !run.metrics.symbolsTraded.contains(symbol) {
                run.metrics.symbolsTraded.append(symbol)
                run.metrics.symbolsTraded.sort()
            }
        }

        activePaperRunsByRunID[runID] = run
        await markRunDirty(runID)
    }

    private func recordBlockedProposalIntentForRun(
        strategyID: String,
        symbol: String?,
        errorCode: String
    ) async {
        guard let runID = activeRunIDByStrategyID[strategyID],
              var run = activePaperRunsByRunID[runID]
        else {
            return
        }

        run.metrics.orderIntentsSubmitted += 1
        run.metrics.ordersRejected += 1
        run.metrics.riskBlocks += 1
        run.metrics.lastUpdatedAt = nowDate()
        if let symbol {
            let normalized = symbol.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
            if !normalized.isEmpty, !run.metrics.symbolsTraded.contains(normalized) {
                run.metrics.symbolsTraded.append(normalized)
                run.metrics.symbolsTraded.sort()
            }
        }
        activePaperRunsByRunID[runID] = run
        await markRunDirty(runID)

        await store.publishDiagnostic(
            "paper run risk block strategy_id=\(strategyID) code=\(errorCode)",
            source: .strategy,
            level: .warning,
            strategyID: strategyID,
            symbol: symbol,
            action: "paper_run_risk_block",
            errorCode: errorCode
        )
    }

    private func recordTradeUpdateForRuns(_ update: TradeUpdateEvent) async {
        guard let runID = runIDByOrderID[update.orderID],
              var run = activePaperRunsByRunID[runID]
        else {
            return
        }

        let normalizedEvent = update.event.lowercased()
        if normalizedEvent == "fill" {
            run.metrics.fillsCount += 1
        } else if normalizedEvent == "partial_fill" || normalizedEvent == "partial-fill" {
            run.metrics.partialFillsCount += 1
        }
        if let filledQty = decimalValue(update.filledQty) {
            run.metrics.totalFilledQty += filledQty
        }
        if let symbol = update.symbol {
            let normalized = symbol.trimmingCharacters(in: .whitespacesAndNewlines).uppercased()
            if !normalized.isEmpty, !run.metrics.symbolsTraded.contains(normalized) {
                run.metrics.symbolsTraded.append(normalized)
                run.metrics.symbolsTraded.sort()
            }
        }
        if run.runType == .replay {
            run.metrics.lastUpdatedAt = replayTimestampForRunUpdate(
                strategyID: run.strategyId,
                fallback: run.metrics.lastUpdatedAt,
                tradeUpdateTimestamp: update.timestamp
            )
        } else {
            run.metrics.lastUpdatedAt = nowDate()
        }
        activePaperRunsByRunID[runID] = run
        await markRunDirty(runID)
    }

    private func processReplayBar(
        strategyID: String,
        runID: String,
        bar: Bar
    ) async {
        replayCurrentTimeByStrategyID[strategyID] = bar.timestamp
        await publishReplayBar(bar)

        guard let simBroker = replaySimBrokerByStrategyID[strategyID] else {
            return
        }

        let tick = await simBroker.processBar(bar)
        for event in tick.events {
            await processTradeUpdate(event, allowRESTRepairs: false)
        }
        await applyReplayAccountSnapshot(
            runID: runID,
            snapshot: tick.accountSnapshot,
            at: bar.timestamp
        )
    }

    private func publishReplayBar(_ bar: Bar) async {
        await store.publishMarketBar(
            MarketDataBarEvent(
                symbol: bar.symbol,
                instrumentType: .equity,
                open: bar.open,
                high: bar.high,
                low: bar.low,
                close: bar.close,
                volume: bar.volume,
                timestamp: DateCodec.formatISO8601(bar.timestamp)
            )
        )
    }

    private func applyReplayProgress(
        runID: String,
        barsProcessed: Int,
        symbolsSeen: Set<String>,
        at timestamp: Date
    ) async {
        guard var run = activePaperRunsByRunID[runID] else {
            return
        }
        run.metrics.barsProcessed += barsProcessed
        for symbol in symbolsSeen.sorted() where !run.metrics.symbolsTraded.contains(symbol) {
            run.metrics.symbolsTraded.append(symbol)
        }
        run.metrics.symbolsTraded.sort()
        run.metrics.lastUpdatedAt = timestamp
        activePaperRunsByRunID[runID] = run
        await markRunDirty(runID)
    }

    private func applyReplayAccountSnapshot(
        runID: String,
        snapshot: SimBrokerAccountSnapshot,
        at timestamp: Date
    ) async {
        guard var run = activePaperRunsByRunID[runID] else {
            return
        }
        run.metrics.startingCash = run.metrics.startingCash ?? snapshot.cash
        run.metrics.endingCash = snapshot.cash
        run.metrics.startingEquity = run.metrics.startingEquity ?? snapshot.equity
        run.metrics.endingEquity = snapshot.equity
        run.metrics.realizedPnL = snapshot.realizedPnL
        run.metrics.unrealizedPnL = snapshot.unrealizedPnL
        run.metrics.netPnL = snapshot.netPnL
        run.metrics.lastUpdatedAt = timestamp
        activePaperRunsByRunID[runID] = run
        await markRunDirty(runID)
    }

    private func replayTimestampForRunUpdate(
        strategyID: String,
        fallback: Date,
        tradeUpdateTimestamp: String?
    ) -> Date {
        if let parsed = parseISO8601(tradeUpdateTimestamp) {
            return parsed
        }
        return replayCurrentTimeByStrategyID[strategyID] ?? fallback
    }

    private func parseISO8601(_ raw: String?) -> Date? {
        guard let raw else { return nil }
        return DateCodec.parseISO8601(raw)
    }

    private func replayRunIDForStrategy(_ strategyID: String) -> String? {
        guard let runID = activeReplayRunIDByStrategyID[strategyID],
              activePaperRunsByRunID[runID]?.runType == .replay
        else {
            return nil
        }
        return runID
    }

    private func currentAccountEquity() async -> Decimal? {
        if let equity = decimalValue(lastKnownAccount?.equity) {
            return equity
        }
        let snapshot = await store.snapshot()
        return decimalValue(snapshot.accountSummary?.equity)
    }

    private func requiredJobString(
        key: String,
        params: [String: JSONValue]
    ) throws -> String {
        guard let value = params[key]?.stringValue?
            .trimmingCharacters(in: .whitespacesAndNewlines),
              !value.isEmpty
        else {
            throw JobRunnerError.invalidParameters(message: "Missing required field: \(key)")
        }
        return value
    }

    private func replayWindowParams(_ params: [String: JSONValue]) throws -> ReplayQuickWindow {
        if let startRaw = params["start"]?.stringValue,
           let endRaw = params["end"]?.stringValue {
            guard let start = parseISO8601(startRaw),
                  let end = parseISO8601(endRaw)
            else {
                throw JobRunnerError.invalidParameters(message: "Invalid start/end ISO8601 timestamps.")
            }
            guard start < end else {
                throw JobRunnerError.invalidParameters(message: "Replay start must be before end.")
            }
            return ReplayQuickWindow(start: start, end: end)
        }

        let days = try replayPositiveIntParam(
            params["days"],
            defaultValue: 1,
            field: "days"
        )
        let explicitEnd: Date?
        if let endRaw = params["end"]?.stringValue {
            guard let parsed = parseISO8601(endRaw) else {
                throw JobRunnerError.invalidParameters(message: "Invalid end ISO8601 timestamp.")
            }
            explicitEnd = parsed
        } else {
            explicitEnd = nil
        }
        return try ReplayWindow.resolve(days: days, end: explicitEnd, now: nowDate)
    }

