    private func resolvedMonitorSymbols(
        configuredSymbols: [String],
        snapshot: StoreSnapshot
    ) -> [String] {
        if !configuredSymbols.isEmpty {
            return configuredSymbols
        }
        if !snapshot.watchlistSymbols.isEmpty {
            return Array(MarketDataSubscriptionSet.normalized(snapshot.watchlistSymbols)).sorted()
        }
        let symbols = Set(snapshot.quotesBySymbol.keys).union(snapshot.optionQuotesBySymbol.keys)
        return symbols.sorted()
    }

    private func resolvedMonitorObservedSymbols(
        baselines: [String: Double]
    ) -> [String] {
        baselines.keys.sorted()
    }

    private func monitorPrice(
        for symbol: String,
        snapshot: StoreSnapshot
    ) -> Double? {
        if let quote = snapshot.quotesBySymbol[symbol] ?? snapshot.optionQuotesBySymbol[symbol] {
            if let last = quote.lastPrice {
                return last
            }
            if let bid = quote.bidPrice, let ask = quote.askPrice {
                return (bid + ask) / 2.0
            }
            return quote.bidPrice ?? quote.askPrice
        }
        return nil
    }

    private func roundedScoreValue(_ value: Double) -> String {
        String(format: "%.4f", value)
    }

    private func iso8601Timestamp(_ date: Date) -> String {
        DateCodec.formatISO8601(date)
    }

    private func enforceTradingSafetyForSubmission(
        source: String,
        providedArmingSessionID: String?
    ) async throws {
        guard configuration.environment == .live else {
            return
        }

        if killSwitchEnabled {
            await throttledBlockedSubmissionAudit(
                reason: "kill_switch_enabled",
                source: source
            )
            throw ManualOrderValidationError.tradingDisabledByKillSwitch
        }

        guard isArmedForLiveTrading else {
            await throttledBlockedSubmissionAudit(
                reason: "live_not_armed",
                source: source
            )
            throw ManualOrderValidationError.liveTradingNotArmed
        }

        if let expectedSessionID = armingSessionID,
           providedArmingSessionID != expectedSessionID {
            await throttledBlockedSubmissionAudit(
                reason: "stale_arming_session",
                source: source
            )
            throw ManualOrderValidationError.staleArmingSession
        }
    }

    private func requireLocalUserPresenceForLiveOrderIfNeeded(
        challenge: LocalUserPresenceChallenge,
        source: String,
        symbol: String?,
        orderID: String?,
        action: String
    ) async throws {
        guard configuration.environment == .live else {
            return
        }
        let settings = await getLiveExecutionProtectionSettings()
        guard settings.localUserPresenceRequiredForLiveOrders else {
            return
        }

        let result = await localUserPresenceAuthorizer.authorize(challenge: challenge)
        lastLocalUserPresenceAuthorizationResult = result

        if result.authorized {
            await store.publishDiagnostic(
                "live local user-presence authorization succeeded \(challenge.safeContextSummary)",
                source: auditSource(from: source),
                orderID: orderID,
                symbol: symbol,
                action: action
            )
            return
        }

        let validationError = manualOrderError(for: result.status)
        await store.publishDiagnostic(
            "live order blocked by local user-presence gate status=\(result.status.rawValue) \(challenge.safeContextSummary)",
            source: auditSource(from: source),
            level: .warning,
            orderID: orderID,
            symbol: symbol,
            action: action,
            errorCode: validationError.errorCode
        )
        throw validationError
    }

    private func manualOrderError(
        for status: LocalUserPresenceAuthorizationStatus
    ) -> ManualOrderValidationError {
        switch status {
        case .success:
            return .localUserPresenceSystemError
        case .canceled:
            return .localUserPresenceCanceled
        case .failed:
            return .localUserPresenceFailed
        case .unavailable:
            return .localUserPresenceUnavailable
        case .systemError:
            return .localUserPresenceSystemError
        }
    }

    private func throttledBlockedSubmissionAudit(
        reason: String,
        source: String
    ) async {
        let key = "\(reason)|\(source)"
        let currentTime = now()

        if var state = blockedActionAuditStateByKey[key] {
            let elapsed = currentTime - state.lastLoggedAt
            if elapsed < blockedAuditWindow {
                state.suppressedCount += 1
                blockedActionAuditStateByKey[key] = state
                return
            }

            let suppressedCount = state.suppressedCount
            state.lastLoggedAt = currentTime
            state.suppressedCount = 0
            blockedActionAuditStateByKey[key] = state

            if suppressedCount > 0 {
                await store.publishDiagnostic(
                    "order blocked reason=\(reason) source=\(source) suppressed=\(suppressedCount)",
                    source: auditSource(from: source),
                    level: .warning,
                    action: "order_blocked",
                    errorCode: reason
                )
            } else {
                await store.publishDiagnostic(
                    "order blocked reason=\(reason) source=\(source)",
                    source: auditSource(from: source),
                    level: .warning,
                    action: "order_blocked",
                    errorCode: reason
                )
            }
            return
        }

        blockedActionAuditStateByKey[key] = BlockedActionAuditState(
            lastLoggedAt: currentTime,
            suppressedCount: 0
        )
        await store.publishDiagnostic(
            "order blocked reason=\(reason) source=\(source)",
            source: auditSource(from: source),
            level: .warning,
            action: "order_blocked",
            errorCode: reason
        )
    }

    private func throttledBlockedProposalStartAudit(
        proposalID: String,
        source: AuditEventSource
    ) async {
        let reason = "strategy_not_approved_for_paper"
        let key = "\(reason)|\(proposalID)"
        let currentTime = now()

        if var state = blockedActionAuditStateByKey[key] {
            let elapsed = currentTime - state.lastLoggedAt
            if elapsed < blockedAuditWindow {
                state.suppressedCount += 1
                blockedActionAuditStateByKey[key] = state
                return
            }

            let suppressedCount = state.suppressedCount
            state.lastLoggedAt = currentTime
            state.suppressedCount = 0
            blockedActionAuditStateByKey[key] = state

            await store.publishDiagnostic(
                "proposal run blocked reason=\(reason) proposal_id=\(proposalID) suppressed=\(suppressedCount)",
                source: source,
                level: .warning,
                action: "paper_run_blocked",
                errorCode: reason
            )
            return
        }

        blockedActionAuditStateByKey[key] = BlockedActionAuditState(
            lastLoggedAt: currentTime,
            suppressedCount: 0
        )
        await store.publishDiagnostic(
            "proposal run blocked reason=\(reason) proposal_id=\(proposalID)",
            source: source,
            level: .warning,
            action: "paper_run_blocked",
            errorCode: reason
        )
    }

    private func maintenanceRunSummaryJSON(_ summary: MaintenanceRunSummary) -> JSONValue {
        .object([
            "jobType": .string(JobType.maintenanceRetention.rawValue),
            "dryRun": .bool(summary.dryRun),
            "startedAt": .string(iso8601Timestamp(summary.startedAt)),
            "finishedAt": .string(iso8601Timestamp(summary.finishedAt)),
            "totalBytesFreed": .number(Double(summary.totalBytesFreed)),
            "hasErrors": .bool(summary.hasErrors),
            "policy": .object([
                "audit": .object([
                    "rotateWhenMB": .number(Double(summary.policy.audit.rotateWhenMB)),
                    "keepDays": .number(Double(summary.policy.audit.keepDays))
                ]),
                "news": .object([
                    "keepDays": .number(Double(summary.policy.news.keepDays))
                ]),
                "jobs": .object([
                    "keepDaysCompleted": .number(Double(summary.policy.jobs.keepDaysCompleted)),
                    "keepMaxCompletedCount": summary.policy.jobs.keepMaxCompletedCount.map { .number(Double($0)) } ?? .null
                ]),
                "runs": .object([
                    "enabled": .bool(summary.policy.runs.enabled),
                    "keepDays": .number(Double(summary.policy.runs.keepDays))
                ]),
                "barsCache": .object([
                    "enabled": .bool(summary.policy.barsCache.enabled),
                    "maxDBMB": summary.policy.barsCache.maxDBMB.map { .number(Double($0)) } ?? .null
                ])
            ]),
            "areas": .array(
                summary.areas.map { area in
                    .object([
                        "area": .string(area.area),
                        "scannedCount": .number(Double(area.scannedCount)),
                        "deletedCount": .number(Double(area.deletedCount)),
                        "bytesFreed": .number(Double(area.bytesFreed)),
                        "dryRun": .bool(area.dryRun),
                        "errors": .array(area.errors.map(JSONValue.string)),
                        "details": area.details ?? .null
                    ])
                }
            )
        ])
    }

    private func shortOrderID(_ orderID: String) -> String {
        String(orderID.prefix(8))
    }

    private func shortSessionID(_ sessionID: String?) -> String {
        guard let sessionID, !sessionID.isEmpty else {
            return "-"
        }
        return String(sessionID.prefix(8))
    }

    private func strategyID(fromSource source: String) -> String? {
        let normalized = source.trimmingCharacters(in: .whitespacesAndNewlines)
        guard normalized.hasPrefix("strategy.") else {
            return nil
        }
        let parts = normalized.split(separator: ".", maxSplits: 1, omittingEmptySubsequences: false)
        guard parts.count == 2 else {
            return nil
        }
        let id = String(parts[1]).trimmingCharacters(in: .whitespacesAndNewlines)
        return id.isEmpty ? nil : id
    }

    private func strategyArmingSessionID() -> String? {
        guard configuration.environment == .live else {
            return nil
        }
        return armingSessionID
    }

    private func auditSource(from source: String) -> AuditEventSource {
        let normalized = source.lowercased()
        if normalized.hasPrefix("ui") {
            return .ui
        }
        if normalized.hasPrefix("strategy") {
            return .strategy
        }
        if normalized.hasPrefix("ipc") {
            return .ipc
        }
        if normalized.hasPrefix("cli") {
            return .cli
        }
        return .engine
    }

    private func jsonValue(strategyStatus: StrategyStatusSnapshot) -> JSONValue {
        var object: [String: JSONValue] = [
            "id": .string(strategyStatus.id),
            "name": .string(strategyStatus.name),
            "state": .string(strategyStatus.state.rawValue),
            "parameters": .object(strategyStatus.parameters)
        ]
        object["lastMessage"] = strategyStatus.lastMessage.map(JSONValue.string) ?? .null
        object["startTime"] = strategyStatus.startTime.map(JSONValue.string) ?? .null
        object["proposalId"] = strategyStatus.proposalId.map(JSONValue.string) ?? .null
        if let constraints = strategyStatus.proposalConstraints {
            object["proposalConstraints"] = .object([
                "maxOrdersPerMinute": .number(Double(constraints.maxOrdersPerMinute)),
                "maxNotionalPerOrder": .string(NSDecimalNumber(decimal: constraints.maxNotionalPerOrder).stringValue),
                "maxDailyNotional": constraints.maxDailyNotional.map {
                    .string(NSDecimalNumber(decimal: $0).stringValue)
                } ?? .null,
                "allowShort": constraints.allowShort.map(JSONValue.bool) ?? .null,
                "allowOptions": constraints.allowOptions.map(JSONValue.bool) ?? .null
            ])
        } else {
            object["proposalConstraints"] = .null
        }
        return .object(object)
    }

    private func jsonValue(marketDataSubscriptions subscriptions: MarketDataSubscriptionSet) -> JSONValue {
        .object([
            "quotes": .array(subscriptions.quotes.sorted().map(JSONValue.string)),
            "trades": .array(subscriptions.trades.sorted().map(JSONValue.string)),
            "bars": .array(subscriptions.bars.sorted().map(JSONValue.string)),
            "optionQuotes": .array(subscriptions.optionQuotes.sorted().map(JSONValue.string)),
            "optionTrades": .array(subscriptions.optionTrades.sorted().map(JSONValue.string)),
            "optionBars": .array(subscriptions.optionBars.sorted().map(JSONValue.string))
        ])
    }

    private func isOpeningOrIncreasingShort(
        symbol: String,
        side: OrderSide
    ) async -> Bool {
        guard side == .sell else {
            return false
        }
        let currentQty = await currentPositionQuantity(for: symbol)
        return currentQty <= 0
    }

    private func currentPositionQuantity(for symbol: String) async -> Decimal {
        let snapshot = await store.snapshot()
        guard let row = snapshot.positions.first(where: { $0.symbol == symbol }) else {
            return 0
        }

        let raw = Decimal(string: row.qty, locale: Locale(identifier: "en_US_POSIX")) ?? 0
        if row.side.lowercased() == "short", raw > 0 {
            return -raw
        }
        return raw
    }

    private func runShortPreflight(symbol: String) async throws {
        let currentPosition = await currentPositionQuantity(for: symbol)
        await store.publishDiagnostic("short preflight intent symbol=\(symbol) current_position=\(NSDecimalNumber(decimal: currentPosition).stringValue)")

        let account = await resolveAccountForPreflight()
        if let account, !account.canShortSellEquities {
            await store.publishDiagnostic("short preflight blocked symbol=\(symbol) reason=account_capability")
            throw ManualOrderValidationError.shortNotAllowedByAccount
        }

        do {
            let asset = try await resolveAsset(symbol: symbol)
            if asset.shortable == false {
                await store.publishDiagnostic("short preflight blocked symbol=\(symbol) reason=asset_not_shortable")
                throw ManualOrderValidationError.symbolNotShortable
            }
        } catch let validationError as ManualOrderValidationError {
            throw validationError
        } catch {
            await store.publishDiagnostic("short preflight inconclusive symbol=\(symbol) reason=asset_lookup_failed")
        }
    }

    private func resolveAccountForPreflight() async -> Account? {
        if let lastKnownAccount {
            return lastKnownAccount
        }

        do {
            let account = try await restClient.fetchAccount()
            lastKnownAccount = account
            return account
        } catch {
            await store.publishDiagnostic("short preflight inconclusive reason=account_lookup_failed")
            return nil
        }
    }

    private func resolveAsset(symbol: String) async throws -> Asset {
        if let cached = assetCache[symbol] {
            return cached
        }
        let asset = try await restClient.fetchAsset(symbol: symbol)
        assetCache[symbol] = asset
        return asset
    }

    private func isLikelyShortRejection(_ error: Error) -> Bool {
        if let apiError = error as? AlpacaAPIError {
            let raw = (apiError.alpacaMessage ?? error.localizedDescription).lowercased()
            return raw.contains("short") ||
                raw.contains("borrow") ||
                raw.contains("margin") ||
                raw.contains("equity")
        }
        return false
    }

    private func positiveDecimalString(
        _ value: Decimal,
        error: ManualOrderValidationError
    ) throws -> String {
        let number = NSDecimalNumber(decimal: value)
        guard number.compare(NSDecimalNumber.zero) == .orderedDescending else {
            throw error
        }
        return number.stringValue
    }

    private func decimalValue(_ raw: String?) -> Decimal? {
        guard let raw else {
            return nil
        }
        return Decimal(string: raw, locale: Locale(identifier: "en_US_POSIX"))
    }

    private func validateBracketRelation(
        side: OrderSide,
        entryPrice: Decimal,
        takeProfitPrice: Decimal,
        stopLossPrice: Decimal
    ) throws {
        let entry = NSDecimalNumber(decimal: entryPrice)
        let takeProfit = NSDecimalNumber(decimal: takeProfitPrice)
        let stopLoss = NSDecimalNumber(decimal: stopLossPrice)

        switch side {
        case .buy:
            guard takeProfit.compare(entry) == .orderedDescending,
                  stopLoss.compare(entry) == .orderedAscending
            else {
                throw ManualOrderValidationError.invalidBracketRelation
            }
        case .sell:
            guard takeProfit.compare(entry) == .orderedAscending,
                  stopLoss.compare(entry) == .orderedDescending
            else {
                throw ManualOrderValidationError.invalidBracketRelation
            }
        }
    }
}
